# ═══════════════════════════════════════════════════════════════════════════════════════
# SISTEMA DE AUDITORIA GLOBAL - INICIALIZADO ANTES DE QUALQUER PROCESSO
# ═══════════════════════════════════════════════════════════════════════════════════════
# Este módulo cria a pasta 'auditoria' e um arquivo de log único por execução
# ANTES de qualquer outro trâmite do sistema. Registra TUDO: processos, erros,
# ações de usuários, operações do sistema, com data/hora e identificação.
# A cada execução do sistema, um NOVO arquivo é criado automaticamente.
# ═══════════════════════════════════════════════════════════════════════════════════════

class _SistemaAuditoriaGlobal:
    """
    Sistema de Auditoria Global do PDV Quantum.
    
    Responsabilidades:
    - Criar pasta 'auditoria' na mesma pasta do sistema (se não existir)
    - Criar arquivo auditoria_DATA_HORA.txt único por execução
    - Registrar TODAS as ações, processos, erros e operações
    - Registrar com data/hora, nome do usuário ou 'SISTEMA'
    - Thread-safe para uso em múltiplas threads
    - Nunca perder nenhum registro
    """
    
    _instance = None
    _lock = _threading_auditoria.Lock()
    
    def __new__(cls):
        if cls._instance is None:
            with cls._lock:
                if cls._instance is None:
                    cls._instance = super().__new__(cls)
                    cls._instance._inicializado = False
        return cls._instance
    
    def __init__(self):
        if self._inicializado:
            return
        
        self._inicializado = True
        self._write_lock = _threading_auditoria.Lock()
        self._buffer = []
        self._buffer_lock = _threading_auditoria.Lock()
        self._usuario_logado = None
        
        # Determina o diretório do sistema
        if getattr(sys, 'frozen', False):
            self._dir_sistema = os.path.dirname(sys.executable)
        else:
            self._dir_sistema = os.path.dirname(os.path.abspath(__file__))
        
        # Cria pasta auditoria se não existir
        self._dir_auditoria = os.path.join(self._dir_sistema, "auditoria")
        try:
            if not os.path.exists(self._dir_auditoria):
                os.makedirs(self._dir_auditoria)
        except Exception as e:
            # Fallback: tenta criar no diretório atual
            self._dir_auditoria = os.path.join(os.getcwd(), "auditoria")
            try:
                if not os.path.exists(self._dir_auditoria):
                    os.makedirs(self._dir_auditoria)
            except Exception:
                self._dir_auditoria = os.getcwd()
        
        # Cria arquivo de auditoria único para esta execução
        agora = _dt_auditoria.datetime.now()
        nome_arquivo = agora.strftime("auditoria_%d%m%Y_%H%M%S.txt")
        self._arquivo_auditoria = os.path.join(self._dir_auditoria, nome_arquivo)
        
        # Escreve cabeçalho do arquivo
        try:
            with open(self._arquivo_auditoria, 'w', encoding='utf-8') as f:
                f.write("=" * 100 + "\n")
                f.write("  REGISTRO DE AUDITORIA - PDV QUANTUM SUPREME ULTRA PROFESSIONAL\n")
                f.write("=" * 100 + "\n")
                f.write(f"  Arquivo criado em: {agora.strftime('%d/%m/%Y às %H:%M:%S')}\n")
                f.write(f"  Diretório do sistema: {self._dir_sistema}\n")
                f.write(f"  Diretório de auditoria: {self._dir_auditoria}\n")
                f.write(f"  Python: {sys.version}\n")
                f.write(f"  Plataforma: {sys.platform}\n")
                f.write("=" * 100 + "\n")
                f.write(f"{'DATA/HORA':<22} {'USUARIO/ORIGEM':<20} {'TIPO':<12} {'ACAO/DESCRICAO'}\n")
                f.write("-" * 100 + "\n")
        except Exception as e:
            print(f"[AUDITORIA] ERRO ao criar arquivo de auditoria: {e}")
        
        # Registra a criação do próprio sistema de auditoria
        self.registrar("SISTEMA", "INICIO", "Sistema de auditoria inicializado com sucesso")
        self.registrar("SISTEMA", "INICIO", f"Arquivo de auditoria: {self._arquivo_auditoria}")
        
        # Registra encerramento ao sair
        _atexit_auditoria.register(self._registrar_encerramento)
    
    def _registrar_encerramento(self):
        """Registra o encerramento do sistema."""
        try:
            self._flush_buffer()
            self.registrar("SISTEMA", "FIM", "Sistema encerrado")
            agora = _dt_auditoria.datetime.now()
            with open(self._arquivo_auditoria, 'a', encoding='utf-8') as f:
                f.write("-" * 100 + "\n")
                f.write(f"  FIM DO REGISTRO - Encerrado em: {agora.strftime('%d/%m/%Y às %H:%M:%S')}\n")
                f.write("=" * 100 + "\n")
        except Exception:
            pass
    
    def set_usuario(self, nome_usuario):
        """Define o usuário logado atualmente."""
        usuario_anterior = self._usuario_logado
        self._usuario_logado = nome_usuario
        if nome_usuario:
            self.registrar(nome_usuario, "LOGIN", f"Usuário '{nome_usuario}' autenticado no sistema")
        elif usuario_anterior:
            self.registrar(usuario_anterior, "LOGOUT", f"Usuário '{usuario_anterior}' desconectado")
    
    def get_usuario(self):
        """Retorna o nome do usuário logado ou 'SISTEMA'."""
        return self._usuario_logado if self._usuario_logado else "SISTEMA"
    
    def registrar(self, usuario, tipo, descricao):
        """
        Registra uma entrada de auditoria no arquivo.
        
        Args:
            usuario: Nome do usuário ou 'SISTEMA'
            tipo: Tipo da ação (INFO, ERRO, PROCESSO, LOGIN, etc.)
            descricao: Descrição detalhada da ação
        """
        try:
            agora = _dt_auditoria.datetime.now()
            data_hora = agora.strftime("%d/%m/%Y %H:%M:%S")
            
            # Limita tamanho dos campos para formatação
            usuario_str = str(usuario)[:20] if usuario else "SISTEMA"
            tipo_str = str(tipo)[:12] if tipo else "INFO"
            descricao_str = str(descricao) if descricao else ""
            
            linha = f"{data_hora:<22} {usuario_str:<20} {tipo_str:<12} {descricao_str}\n"
            
            with self._write_lock:
                with open(self._arquivo_auditoria, 'a', encoding='utf-8') as f:
                    f.write(linha)
                    f.flush()
        except Exception as e:
            # Em último caso, tenta adicionar ao buffer
            try:
                with self._buffer_lock:
                    self._buffer.append((usuario, tipo, descricao, str(e)))
            except Exception:
                pass
    
    def _flush_buffer(self):
        """Escreve entradas pendentes do buffer."""
        with self._buffer_lock:
            if not self._buffer:
                return
            try:
                with self._write_lock:
                    with open(self._arquivo_auditoria, 'a', encoding='utf-8') as f:
                        for usuario, tipo, descricao, erro in self._buffer:
                            agora = _dt_auditoria.datetime.now()
                            data_hora = agora.strftime("%d/%m/%Y %H:%M:%S")
                            f.write(f"{data_hora:<22} {str(usuario)[:20]:<20} {str(tipo)[:12]:<12} {descricao} [BUFFER-RECUPERADO, erro anterior: {erro}]\n")
                        f.flush()
                self._buffer.clear()
            except Exception:
                pass
    
    def info(self, descricao, usuario=None):
        """Registra informação geral."""
        self.registrar(usuario or self.get_usuario(), "INFO", descricao)
    
    def processo(self, descricao, usuario=None):
        """Registra um processo do sistema."""
        self.registrar(usuario or self.get_usuario(), "PROCESSO", descricao)
    
    def erro(self, descricao, usuario=None, exception=None):
        """Registra um erro."""
        msg = descricao
        if exception:
            msg += f" | Exceção: {type(exception).__name__}: {exception}"
        self.registrar(usuario or self.get_usuario(), "ERRO", msg)
    
    def erro_traceback(self, descricao, usuario=None):
        """Registra um erro com traceback completo."""
        tb = _traceback_auditoria.format_exc()
        self.registrar(usuario or self.get_usuario(), "ERRO", f"{descricao} | Traceback: {tb.replace(chr(10), ' | ')}")
    
    def acao_usuario(self, acao, detalhes="", usuario=None):
        """Registra uma ação do usuário."""
        msg = acao
        if detalhes:
            msg += f" | {detalhes}"
        self.registrar(usuario or self.get_usuario(), "ACAO", msg)
    
    def seguranca(self, descricao, usuario=None):
        """Registra evento de segurança."""
        self.registrar(usuario or self.get_usuario(), "SEGURANCA", descricao)
    
    def financeiro(self, descricao, usuario=None):
        """Registra operação financeira."""
        self.registrar(usuario or self.get_usuario(), "FINANCEIRO", descricao)
    
    def venda(self, descricao, usuario=None):
        """Registra operação de venda."""
        self.registrar(usuario or self.get_usuario(), "VENDA", descricao)
    
    def estoque(self, descricao, usuario=None):
        """Registra operação de estoque."""
        self.registrar(usuario or self.get_usuario(), "ESTOQUE", descricao)
    
    def caixa(self, descricao, usuario=None):
        """Registra operação de caixa."""
        self.registrar(usuario or self.get_usuario(), "CAIXA", descricao)
    
    def backup(self, descricao, usuario=None):
        """Registra operação de backup."""
        self.registrar(usuario or self.get_usuario(), "BACKUP", descricao)
    
    def impressao(self, descricao, usuario=None):
        """Registra operação de impressão."""
        self.registrar(usuario or self.get_usuario(), "IMPRESSAO", descricao)
    
    def configuracao(self, descricao, usuario=None):
        """Registra alteração de configuração."""
        self.registrar(usuario or self.get_usuario(), "CONFIG", descricao)
    
    def banco_dados(self, descricao, usuario=None):
        """Registra operação de banco de dados."""
        self.registrar(usuario or self.get_usuario(), "BD", descricao)
    
    def get_arquivo(self):
        """Retorna o caminho do arquivo de auditoria atual."""
        return self._arquivo_auditoria
    
    def get_dir_auditoria(self):
        """Retorna o caminho da pasta de auditoria."""
        return self._dir_auditoria


