# ═══════════════════════════════════════════════════════════════════════════════
# PROTEÇÃO CONTRA MÚLTIPLAS INSTÂNCIAS (PYINSTALLER)
# ═══════════════════════════════════════════════════════════════════════════════
# IMPORTANTE: Esta verificação DEVE estar no início do arquivo para evitar
# que o PyInstaller abra múltiplas janelas no Windows.
# ═══════════════════════════════════════════════════════════════════════════════

def is_already_running():
    """
    Verifica se já existe uma instância do programa rodando.
    Usa um arquivo de lock para garantir instância única.
    """
    import tempfile
    import atexit

    # Quando o Logoff reinicia o sistema, a nova instância pode abrir antes da
    # antiga liberar o arquivo de lock. Este marcador permite somente esse
    # reinício controlado, evitando que o novo processo feche imediatamente.
    try:
        if os.environ.get("QUANTUM_LOGOFF_RESTART") == "1":
            os.environ.pop("QUANTUM_LOGOFF_RESTART", None)
            return False
    except Exception:
        pass

    
    # Determina o diretório para o arquivo de lock
    if getattr(sys, 'frozen', False):
        # Executando como .exe (PyInstaller)
        lock_dir = os.path.dirname(sys.executable)
    else:
        # Executando como script Python
        lock_dir = os.path.dirname(os.path.abspath(__file__))
    
    lock_file = os.path.join(lock_dir, '.pdv_quantum_ultra.lock')
    
    # Tenta criar/abrir o arquivo de lock
    try:
        # No Windows, usamos uma abordagem diferente
        if sys.platform == 'win32':
            import msvcrt
            try:
                # Tenta abrir o arquivo em modo exclusivo
                lock_handle = open(lock_file, 'w')
                msvcrt.locking(lock_handle.fileno(), msvcrt.LK_NBLCK, 1)
                
                # Registra função para liberar o lock ao sair
                def release_lock():
                    try:
                        msvcrt.locking(lock_handle.fileno(), msvcrt.LK_UNLCK, 1)
                        lock_handle.close()
                        os.remove(lock_file)
                    except:
                        pass
                
                atexit.register(release_lock)
                return False  # Não está rodando, pode continuar
                
            except (IOError, OSError):
                return True  # Já está rodando
        else:
            # Linux/Mac - usa fcntl
            import fcntl
            lock_handle = open(lock_file, 'w')
            try:
                fcntl.flock(lock_handle.fileno(), fcntl.LOCK_EX | fcntl.LOCK_NB)
                
                def release_lock():
                    try:
                        fcntl.flock(lock_handle.fileno(), fcntl.LOCK_UN)
                        lock_handle.close()
                        os.remove(lock_file)
                    except:
                        pass
                
                atexit.register(release_lock)
                return False
                
            except (IOError, OSError):
                return True
                
    except Exception:
        return False  # Em caso de erro, permite executar

# Verifica se é o processo principal (não um processo filho do PyInstaller)
if __name__ == "__main__":
    # CRÍTICO: freeze_support() DEVE ser chamado ANTES de qualquer outro código
    # quando usando PyInstaller no Windows
    multiprocessing.freeze_support()
    AUDITORIA.processo("freeze_support() executado - Processo principal iniciado")
    
    # Verifica se já existe uma instância rodando
    if is_already_running():
        AUDITORIA.info("Tentativa de abrir segunda instância bloqueada")
        print("PDV QUANTUM ULTRA já está em execução!")
        sys.exit(0)
    AUDITORIA.processo("Verificação de instância única concluída - Nenhuma outra instância detectada")



