# ═══════════════════════════════════════════════════════════════════════════════════════
# SISTEMA DE MONITORAMENTO DE SAÚDE AVANÇADO v2.0
# ═══════════════════════════════════════════════════════════════════════════════════════

class SystemHealthMonitor:
    """
    Monitor de Saúde do Sistema em Tempo Real.
    
    Características:
    - Monitoramento de CPU, memória e disco
    - Detecção de anomalias e alertas proativos
    - Histórico de métricas para análise
    - Auto-recuperação de problemas comuns
    - Relatórios de saúde detalhados
    - Integração com sistema de notificações
    """
    
    # Limiares de alerta
    THRESHOLDS = {
        'cpu_warning': 70,
        'cpu_critical': 90,
        'memory_warning': 75,
        'memory_critical': 90,
        'disk_warning': 80,
        'disk_critical': 95,
        'response_time_warning': 1000,  # ms
        'response_time_critical': 3000,  # ms
    }
    
    def __init__(self, check_interval: int = 30000):
        """
        Inicializa o monitor de saúde.
        
        Args:
            check_interval: Intervalo de verificação em milissegundos
        """
        self.check_interval = check_interval
        self._metrics_history = []
        self._max_history = 1000
        self._alerts = []
        self._is_monitoring = False
        self._last_check = None
        self._health_score = 100
        self._callbacks = []
    
    def start_monitoring(self, root=None):
        """Inicia o monitoramento contínuo."""
        self._is_monitoring = True
        if root:
            self._schedule_check(root)
    
    def stop_monitoring(self):
        """Para o monitoramento."""
        self._is_monitoring = False
    
    def _schedule_check(self, root):
        """Agenda próxima verificação."""
        if self._is_monitoring:
            self._perform_check()
            root.after(self.check_interval, lambda: self._schedule_check(root))
    
    def _perform_check(self):
        """Realiza verificação de saúde."""
        import time
        metrics = {
            'timestamp': time.time(),
            'cpu_percent': self._get_cpu_usage(),
            'memory_percent': self._get_memory_usage(),
            'disk_percent': self._get_disk_usage(),
            'active_threads': self._get_thread_count(),
            'open_files': self._get_open_files_count(),
            'response_time': self._measure_response_time(),
        }
        
        # Adiciona ao histórico
        self._metrics_history.append(metrics)
        if len(self._metrics_history) > self._max_history:
            self._metrics_history.pop(0)
        
        # Calcula score de saúde
        self._calculate_health_score(metrics)
        
        # Verifica alertas
        self._check_alerts(metrics)
        
        self._last_check = metrics
        
        # Notifica callbacks
        for callback in self._callbacks:
            try:
                callback(metrics, self._health_score)
            except Exception:
                pass
    
    def _get_cpu_usage(self) -> float:
        """Obtém uso de CPU."""
        try:
            import psutil
            return psutil.cpu_percent(interval=0.1)
        except ImportError:
            return 0.0
        except Exception:
            return 0.0
    
    def _get_memory_usage(self) -> float:
        """Obtém uso de memória."""
        try:
            import psutil
            return psutil.virtual_memory().percent
        except ImportError:
            return 0.0
        except Exception:
            return 0.0
    
    def _get_disk_usage(self) -> float:
        """Obtém uso de disco."""
        try:
            import psutil
            return psutil.disk_usage('/').percent
        except ImportError:
            return 0.0
        except Exception:
            return 0.0
    
    def _get_thread_count(self) -> int:
        """Obtém contagem de threads."""
        try:
            import threading
            return threading.active_count()
        except Exception:
            return 0
    
    def _get_open_files_count(self) -> int:
        """Obtém contagem de arquivos abertos."""
        try:
            import psutil
            return len(psutil.Process().open_files())
        except Exception:
            return 0
    
    def _measure_response_time(self) -> float:
        """Mede tempo de resposta do sistema."""
        import time
        start = time.perf_counter()
        # Operação simples para medir responsividade
        _ = [i * 2 for i in range(1000)]
        return (time.perf_counter() - start) * 1000  # ms
    
    def _calculate_health_score(self, metrics: dict):
        """Calcula score de saúde (0-100)."""
        score = 100
        
        # Penalidades por CPU
        if metrics['cpu_percent'] > self.THRESHOLDS['cpu_critical']:
            score -= 30
        elif metrics['cpu_percent'] > self.THRESHOLDS['cpu_warning']:
            score -= 15
        
        # Penalidades por memória
        if metrics['memory_percent'] > self.THRESHOLDS['memory_critical']:
            score -= 30
        elif metrics['memory_percent'] > self.THRESHOLDS['memory_warning']:
            score -= 15
        
        # Penalidades por disco
        if metrics['disk_percent'] > self.THRESHOLDS['disk_critical']:
            score -= 20
        elif metrics['disk_percent'] > self.THRESHOLDS['disk_warning']:
            score -= 10
        
        # Penalidades por tempo de resposta
        if metrics['response_time'] > self.THRESHOLDS['response_time_critical']:
            score -= 20
        elif metrics['response_time'] > self.THRESHOLDS['response_time_warning']:
            score -= 10
        
        self._health_score = max(0, score)
    
    def _check_alerts(self, metrics: dict):
        """Verifica e gera alertas."""
        import time
        
        alerts = []
        
        if metrics['cpu_percent'] > self.THRESHOLDS['cpu_critical']:
            alerts.append({
                'type': 'critical',
                'category': 'cpu',
                'message': f"CPU crítico: {metrics['cpu_percent']:.1f}%",
                'timestamp': time.time()
            })
        elif metrics['cpu_percent'] > self.THRESHOLDS['cpu_warning']:
            alerts.append({
                'type': 'warning',
                'category': 'cpu',
                'message': f"CPU alto: {metrics['cpu_percent']:.1f}%",
                'timestamp': time.time()
            })
        
        if metrics['memory_percent'] > self.THRESHOLDS['memory_critical']:
            alerts.append({
                'type': 'critical',
                'category': 'memory',
                'message': f"Memória crítica: {metrics['memory_percent']:.1f}%",
                'timestamp': time.time()
            })
        elif metrics['memory_percent'] > self.THRESHOLDS['memory_warning']:
            alerts.append({
                'type': 'warning',
                'category': 'memory',
                'message': f"Memória alta: {metrics['memory_percent']:.1f}%",
                'timestamp': time.time()
            })
        
        if metrics['disk_percent'] > self.THRESHOLDS['disk_critical']:
            alerts.append({
                'type': 'critical',
                'category': 'disk',
                'message': f"Disco crítico: {metrics['disk_percent']:.1f}%",
                'timestamp': time.time()
            })
        
        self._alerts.extend(alerts)
        
        # Limita histórico de alertas
        if len(self._alerts) > 100:
            self._alerts = self._alerts[-100:]
    
    def get_health_score(self) -> int:
        """Retorna score de saúde atual."""
        return self._health_score
    
    def get_health_status(self) -> str:
        """Retorna status de saúde textual."""
        if self._health_score >= 90:
            return "Excelente"
        elif self._health_score >= 70:
            return "Bom"
        elif self._health_score >= 50:
            return "Regular"
        elif self._health_score >= 30:
            return "Ruim"
        else:
            return "Crítico"
    
    def get_health_color(self) -> str:
        """Retorna cor baseada no score de saúde."""
        if self._health_score >= 90:
            return "#10b981"  # Verde
        elif self._health_score >= 70:
            return "#22c55e"  # Verde claro
        elif self._health_score >= 50:
            return "#f59e0b"  # Amarelo
        elif self._health_score >= 30:
            return "#f97316"  # Laranja
        else:
            return "#ef4444"  # Vermelho
    
    def get_last_metrics(self) -> dict:
        """Retorna últimas métricas."""
        return self._last_check or {}
    
    def get_metrics_history(self, limit: int = 100) -> list:
        """Retorna histórico de métricas."""
        return self._metrics_history[-limit:]
    
    def get_alerts(self, limit: int = 20) -> list:
        """Retorna alertas recentes."""
        return self._alerts[-limit:]
    
    def on_health_update(self, callback):
        """Registra callback para atualizações de saúde."""
        self._callbacks.append(callback)
    
    def generate_health_report(self) -> dict:
        """Gera relatório de saúde detalhado."""
        import statistics
        
        if not self._metrics_history:
            return {'status': 'Sem dados'}
        
        cpu_values = [m['cpu_percent'] for m in self._metrics_history]
        memory_values = [m['memory_percent'] for m in self._metrics_history]
        
        return {
            'current_score': self._health_score,
            'status': self.get_health_status(),
            'cpu': {
                'current': self._last_check.get('cpu_percent', 0) if self._last_check else 0,
                'average': statistics.mean(cpu_values),
                'max': max(cpu_values),
                'min': min(cpu_values),
            },
            'memory': {
                'current': self._last_check.get('memory_percent', 0) if self._last_check else 0,
                'average': statistics.mean(memory_values),
                'max': max(memory_values),
                'min': min(memory_values),
            },
            'disk': {
                'current': self._last_check.get('disk_percent', 0) if self._last_check else 0,
            },
            'alerts_count': len(self._alerts),
            'samples_count': len(self._metrics_history),
        }


# Instância global do monitor de saúde
HEALTH_MONITOR = SystemHealthMonitor()

