# ═══════════════════════════════════════════════════════════════════════════════════════
# FUNÇÕES GLOBAIS DE CONTROLE DE JANELAS
# ═══════════════════════════════════════════════════════════════════════════════════════

_SAFE_WINDOW_PATCH_APPLIED = False
_ORIGINAL_TOPLEVEL_INIT = None
WINDOW_BOTTOM_SAFE_MARGIN = 80

# ═══════════════════════════════════════════════════════════════════════════════════════
# SISTEMA DE LAYOUT RESPONSIVO UNIVERSAL v2.0
# ═══════════════════════════════════════════════════════════════════════════════════════
# Este módulo garante que TODAS as telas, botões, barras de status e elementos
# se adaptem automaticamente a qualquer resolução de monitor, sem cortar, ocultar
# ou inibir nenhum conteúdo, mesmo com janelas maximizadas.
# ═══════════════════════════════════════════════════════════════════════════════════════

# Resolução de referência usada no design original
_REF_WIDTH = 1920
_REF_HEIGHT = 1080

# Cache global do fator de escala (calculado uma vez)
_SCALE_CACHE = {}


def _get_screen_info(window=None):
    """Obtém largura e altura reais da tela do monitor."""
    try:
        if window is not None and hasattr(window, 'winfo_screenwidth'):
            sw = window.winfo_screenwidth()
            sh = window.winfo_screenheight()
            if sw > 0 and sh > 0:
                return sw, sh
    except Exception:
        pass
    return _REF_WIDTH, _REF_HEIGHT


def get_scale_factor(window=None):
    """
    Calcula o fator de escala baseado na resolução atual vs. referência.
    Retorna um float (ex: 0.75 para 1366x768, 1.0 para 1920x1080, 1.5 para 2K).
    Usa o MENOR fator entre largura e altura para garantir que nada seja cortado.
    """
    cache_key = id(window) if window else 'default'
    if cache_key in _SCALE_CACHE:
        return _SCALE_CACHE[cache_key]
    
    sw, sh = _get_screen_info(window)
    
    scale_w = sw / _REF_WIDTH
    scale_h = sh / _REF_HEIGHT
    # Usa o menor para garantir que tudo caiba
    factor = min(scale_w, scale_h)
    # Limita entre 0.5 e 2.5 para evitar extremos
    factor = max(0.5, min(2.5, factor))
    
    _SCALE_CACHE[cache_key] = factor
    return factor


def clear_scale_cache():
    """Limpa o cache de escala (útil ao mudar de monitor)."""
    global _SCALE_CACHE
    _SCALE_CACHE.clear()


def scale_value(value, window=None):
    """Escala um valor numérico (int/float) pelo fator de escala."""
    factor = get_scale_factor(window)
    return int(round(value * factor))


def scale_font_size(size, window=None):
    """Escala o tamanho de fonte pelo fator de escala, com mínimo de 7."""
    factor = get_scale_factor(window)
    scaled = int(round(size * factor))
    return max(7, scaled)


def responsive_geometry(window, design_width, design_height, center=True):
    """
    Calcula e aplica geometry responsiva a uma janela.
    
    Args:
        window: Janela tk.Toplevel ou tk.Tk
        design_width: Largura original de design (para 1920x1080)
        design_height: Altura original de design (para 1920x1080)
        center: Se True, centraliza a janela na tela
    """
    try:
        sw = window.winfo_screenwidth()
        sh = window.winfo_screenheight()
    except Exception:
        sw, sh = _REF_WIDTH, _REF_HEIGHT
    
    # ─── Tamanho mínimo baseado na splash ───
    # Garante que nenhuma janela fique menor que a splash screen
    splash_min_w = max(520, min(800, int(sw * 0.42)))
    splash_min_h = max(420, min(680, int(sh * 0.58)))
    
    factor = get_scale_factor(window)
    new_w = max(300, int(round(design_width * factor)))
    new_h = max(200, int(round(design_height * factor)))
    
    # ─── Aplica tamanho mínimo da splash ───
    # Janelas com design muito pequeno são expandidas para o tamanho da splash
    # Exceção: notificações (design_height < 100) e diálogos de progresso (design_height <= 150 e design_width <= 460)
    is_notification = design_height < 100
    is_tiny_dialog = design_height <= 150 and design_width <= 460
    
    if not is_notification and not is_tiny_dialog:
        if new_w < splash_min_w:
            new_w = splash_min_w
        if new_h < splash_min_h:
            new_h = splash_min_h
    
    # Garante que não ultrapassa a tela
    new_w = min(new_w, sw - 20)
    new_h = min(new_h, sh - 60)
    
    if center:
        x = (sw - new_w) // 2
        y = (sh - new_h) // 2
        window.geometry(f"{new_w}x{new_h}+{x}+{y}")
    else:
        window.geometry(f"{new_w}x{new_h}")



def responsive_toplevel_setup(window, design_width=None, design_height=None, maximize=False):
    """
    Configura uma janela Toplevel para ser totalmente responsiva.
    
    Args:
        window: Janela tk.Toplevel
        design_width: Largura de design (None = maximizar)
        design_height: Altura de design (None = maximizar)
        maximize: Se True, maximiza a janela
    """
    try:
        sw = window.winfo_screenwidth()
        sh = window.winfo_screenheight()
    except Exception:
        sw, sh = _REF_WIDTH, _REF_HEIGHT
    
    if maximize or design_width is None:
        # Maximizar a janela
        try:
            if sys.platform.startswith('win'):
                window.state('zoomed')
            else:
                try:
                    window.state('zoomed')
                except Exception:
                    window.geometry(f"{sw}x{sh}+0+0")
        except Exception:
            window.geometry(f"{sw}x{sh}+0+0")
    else:
        responsive_geometry(window, design_width, design_height, center=True)
    
    # Sempre permite redimensionar
    window.resizable(True, True)


def responsive_minsize(window, design_min_w, design_min_h):
    """Define minsize responsivo para uma janela."""
    factor = get_scale_factor(window)
    min_w = max(300, int(round(design_min_w * factor)))
    min_h = max(200, int(round(design_min_h * factor)))
    window.minsize(min_w, min_h)


def get_responsive_work_area(window=None):
    """
    Retorna a área útil da tela, respeitando barra de tarefas.
    Versão melhorada que funciona em todos os SO.
    """
    try:
        if sys.platform.startswith('win'):
            import ctypes
            class RECT(ctypes.Structure):
                _fields_ = [
                    ('left', ctypes.c_long),
                    ('top', ctypes.c_long),
                    ('right', ctypes.c_long),
                    ('bottom', ctypes.c_long),
                ]
            rect = RECT()
            SPI_GETWORKAREA = 48
            if ctypes.windll.user32.SystemParametersInfoW(SPI_GETWORKAREA, 0, ctypes.byref(rect), 0):
                return (
                    int(rect.left),
                    int(rect.top),
                    int(rect.right - rect.left),
                    int(rect.bottom - rect.top),
                )
    except Exception:
        pass
    
    try:
        sw = int(window.winfo_screenwidth())
        sh = int(window.winfo_screenheight())
        # Reserva espaço para barra de tarefas (estimativa)
        taskbar_h = max(30, int(sh * 0.04))
        return 0, 0, sw, sh - taskbar_h
    except Exception:
        return 0, 0, 1366, 720


def position_window_responsive(window, width=None, height=None, x=None, y=None):
    """
    Posiciona a janela principal de forma responsiva, garantindo que
    a barra de status e todos os elementos fiquem visíveis.
    """
    try:
        if not window.winfo_exists():
            return
    except Exception:
        return
    
    try:
        window.update_idletasks()
    except Exception:
        pass
    
    area_x, area_y, area_w, area_h = get_responsive_work_area(window)
    
    # Calcula dimensões finais
    final_w = min(max(1, int(width if width is not None else area_w)), area_w)
    final_h = min(max(1, int(height if height is not None else area_h)), area_h)
    final_x = area_x if x is None else max(area_x, int(x))
    final_y = area_y if y is None else max(area_y, int(y))
    
    # Garante que a janela não ultrapasse a área visível
    if final_x + final_w > area_x + area_w:
        final_w = area_w - (final_x - area_x)
    if final_y + final_h > area_y + area_h:
        final_h = area_h - (final_y - area_y)
    
    try:
        window.geometry(f"{final_w}x{final_h}{final_x:+d}{final_y:+d}")
    except Exception:
        pass




def get_work_area(window=None):
    """Retorna a área útil da tela, respeitando a barra de tarefas. (Versão responsiva)"""
    return get_responsive_work_area(window)


def position_window_above_taskbar(window, width=None, height=None, x=None, y=None):
    """Reposiciona a janela principal de forma responsiva acima da barra de tarefas."""
    position_window_responsive(window, width, height, x, y)



def _schedule_position_above_taskbar(window):
    """Agenda o ajuste da janela principal para o próximo ciclo visual."""
    try:
        window.after_idle(lambda w=window: position_window_above_taskbar(w))
    except Exception:
        pass


def bind_escape_to_close(window):
    """Vincula a tecla ESC para fechar qualquer janela Toplevel."""
    def close_window(event=None):
        try:
            if window.winfo_exists():
                window.destroy()
        except tk.TclError:
            pass

    window.bind("<Escape>", close_window)
    return window


def _apply_safe_window_patch():
    """Aplica ESC e responsividade automática às janelas filhas."""
    global _SAFE_WINDOW_PATCH_APPLIED, _ORIGINAL_TOPLEVEL_INIT

    if _SAFE_WINDOW_PATCH_APPLIED:
        return

    _SAFE_WINDOW_PATCH_APPLIED = True
    _ORIGINAL_TOPLEVEL_INIT = tk.Toplevel.__init__

    def patched_toplevel_init(self, *args, **kwargs):
        _ORIGINAL_TOPLEVEL_INIT(self, *args, **kwargs)
        bind_escape_to_close(self)
        # Garante que a janela sempre permite redimensionamento
        try:
            self.resizable(True, True)
        except Exception:
            pass
        # Configura evento para ajustar conteúdo ao redimensionar
        def _on_configure_responsive(event):
            try:
                # Garante que a janela não ultrapasse os limites da tela
                sw = self.winfo_screenwidth()
                sh = self.winfo_screenheight()
                if self.winfo_width() > sw:
                    self.geometry(f"{sw}x{self.winfo_height()}")
                if self.winfo_height() > sh:
                    self.geometry(f"{self.winfo_width()}x{sh}")
            except Exception:
                pass
        try:
            self.bind("<Map>", _on_configure_responsive)
        except Exception:
            pass

        # ===================================================================
        # AUTO STATUS BAR: Adiciona barra de status automaticamente
        # em janelas Toplevel que nao sao dialogos pequenos/utilitarios.
        # Janelas que ja possuem StatusBar ou marcadas com _skip_auto_statusbar
        # sao ignoradas. A barra e adicionada com atraso para permitir que
        # o construtor da janela termine primeiro.
        # ===================================================================
        def _auto_add_statusbar(win):
            try:
                if not win.winfo_exists():
                    return
                # Pula se ja tem StatusBar ou se foi marcada para pular
                if getattr(win, '_skip_auto_statusbar', False):
                    return
                if hasattr(win, 'status_bar') and win.status_bar is not None:
                    return
                if hasattr(win, 'status_bar_frame'):
                    return
                # Pula janelas com overrideredirect (popups, tooltips, toasts)
                try:
                    if win.overrideredirect():
                        return
                except Exception:
                    return
                # Pula janelas muito pequenas (dialogos)
                try:
                    win.update_idletasks()
                    w = win.winfo_width()
                    h = win.winfo_height()
                    # Se a janela ainda nao foi renderizada, tenta pegar o geometry
                    if w <= 1 or h <= 1:
                        geo = win.geometry()
                        parts = geo.split('+')[0].split('x')
                        if len(parts) == 2:
                            w, h = int(parts[0]), int(parts[1])
                except Exception:
                    w, h = 0, 0
                # Adiciona StatusBar apenas em janelas com tamanho razoavel
                # (maiores que 450x300 ou maximizadas)
                is_zoomed = False
                try:
                    is_zoomed = (win.state() == 'zoomed')
                except Exception:
                    pass
                if is_zoomed or (w >= 450 and h >= 300):
                    try:
                        _user = 'Usuario'
                        # Tenta obter o usuario logado
                        try:
                            import builtins
                            if hasattr(builtins, '__pdv_logged_user__'):
                                _user = builtins.__pdv_logged_user__
                        except Exception:
                            pass
                        win.status_bar = StatusBar(win, user_name=_user)
                    except Exception:
                        pass
            except Exception:
                pass

        try:
            self.after(500, lambda w=self: _auto_add_statusbar(w))
        except Exception:
            pass

    tk.Toplevel.__init__ = patched_toplevel_init


def setup_escape_for_all_toplevels(root):
    """Configura ESC globalmente e preserva o ajuste especial apenas da tela principal."""
    _apply_safe_window_patch()
    bind_escape_to_close(root)
    return root


# ═══════════════════════════════════════════════════════════════════════════════════════
# PROTEÇÃO PDV SEMPRE VIVO - PRIORIDADE, MEMÓRIA E RECUPERAÇÃO VISUAL
# ═══════════════════════════════════════════════════════════════════════════════════════
# Objetivo: manter o PDV mais responsivo quando o Windows estiver pesado.
# - Eleva a prioridade do processo de forma segura.
# - Solicita prioridade alta de memória quando o Windows permitir.
# - Faz manutenção leve de memória sem apagar dados da venda/carrinho.
# - Reanima a interface ao voltar para a janela após alternar de aplicativo.
# - Usa watchdog do Tkinter para manter a janela desenhada e responsiva.
# ═══════════════════════════════════════════════════════════════════════════════════════

_QUANTUM_KEEPALIVE_SINGLETON = None


def quantum_aplicar_prioridade_alta_processo():
    """Aplica prioridade alta ao processo atual, com fallback seguro."""
    aplicado = False
    try:
        if sys.platform.startswith('win'):
            import ctypes
            kernel32 = ctypes.windll.kernel32
            handle = kernel32.GetCurrentProcess()

            # HIGH_PRIORITY_CLASS = 0x00000080
            try:
                if kernel32.SetPriorityClass(handle, 0x00000080):
                    aplicado = True
            except Exception:
                pass

            # Tenta pedir prioridade alta de memória no Windows 10/11.
            # Se a API não existir ou negar, apenas ignora sem afetar o PDV.
            try:
                class _MEMORY_PRIORITY_INFORMATION(ctypes.Structure):
                    _fields_ = [('MemoryPriority', ctypes.c_ulong)]

                # ProcessMemoryPriority = 0
                info = _MEMORY_PRIORITY_INFORMATION(5)  # 5 = MEMORY_PRIORITY_HIGH
                kernel32.SetProcessInformation(
                    handle,
                    0,
                    ctypes.byref(info),
                    ctypes.sizeof(info)
                )
            except Exception:
                pass

            # Mantém o escalonamento dinâmico do Windows ativo.
            try:
                kernel32.SetProcessPriorityBoost(handle, False)
            except Exception:
                pass
        else:
            try:
                os.nice(-5)
                aplicado = True
            except Exception:
                pass
    except Exception as e:
        try:
            AUDITORIA.erro('Falha ao aplicar prioridade alta do processo', exception=e)
        except Exception:
            pass

    try:
        AUDITORIA.processo(
            'Proteção PDV Sempre Vivo: prioridade alta aplicada'
            if aplicado else
            'Proteção PDV Sempre Vivo: prioridade alta solicitada com fallback seguro'
        )
    except Exception:
        pass
    return aplicado


def quantum_reduzir_paginacao_e_aliviar_memoria():
    """Executa manutenção leve de memória sem limpar venda, sacola, cache crítico ou telas."""
    try:
        import gc
        gc.collect()
    except Exception:
        pass

    # No Windows, EmptyWorkingSet apenas sugere ao sistema reorganizar páginas.
    # Não apaga objetos Python e não cancela vendas.
    try:
        if sys.platform.startswith('win'):
            import ctypes
            handle = ctypes.windll.kernel32.GetCurrentProcess()
            try:
                ctypes.windll.psapi.EmptyWorkingSet(handle)
            except Exception:
                try:
                    ctypes.windll.kernel32.SetProcessWorkingSetSize(handle, -1, -1)
                except Exception:
                    pass
    except Exception:
        pass


class QuantumPDVKeepAlive:
    """Watchdog visual e operacional para manter o PDV vivo sob pressão de memória."""

    def __init__(self, root, intervalo_ms=8000):
        self.root = root
        self.intervalo_ms = int(intervalo_ms)
        self._ativo = False
        self._ultimo_refresh = 0.0
        self._ultimo_gc = 0.0
        self._janela_principal_visivel = False

    def iniciar(self):
        if self._ativo:
            return self
        self._ativo = True
        quantum_aplicar_prioridade_alta_processo()
        self._instalar_eventos()
        self._agendar_watchdog(1200)
        try:
            AUDITORIA.processo('Proteção PDV Sempre Vivo iniciada: watchdog de interface ativo')
        except Exception:
            pass
        return self

    def marcar_janela_principal_visivel(self):
        self._janela_principal_visivel = True
        self.recuperar_visual(motivo='janela principal exibida')

    def _instalar_eventos(self):
        eventos = ('<FocusIn>', '<Map>', '<Visibility>', '<Expose>', '<Configure>')
        for ev in eventos:
            try:
                self.root.bind(ev, self._evento_recuperacao_visual, add='+')
            except Exception:
                pass
        try:
            self.root.bind_all('<Alt-Tab>', self._evento_recuperacao_visual, add='+')
        except Exception:
            pass

    def _evento_recuperacao_visual(self, event=None):
        self.recuperar_visual(motivo='evento de foco/visibilidade')

    def recuperar_visual(self, motivo='recuperação visual'):
        """Força redesenho seguro quando o usuário volta ao PDV."""
        try:
            import time
            agora = time.time()
            if agora - self._ultimo_refresh < 0.35:
                return
            self._ultimo_refresh = agora
        except Exception:
            pass

        try:
            if not self.root.winfo_exists():
                return
        except Exception:
            return

        try:
            # Corrige casos em que a janela volta transparente após splash/troca de app.
            try:
                alpha = self.root.attributes('-alpha')
                if alpha is None or float(alpha) < 0.95:
                    self.root.attributes('-alpha', 1)
            except Exception:
                pass

            # Se a janela principal já foi exibida e ficou withdrawn por falha visual, reexibe.
            try:
                estado = self.root.state()
                if self._janela_principal_visivel and estado == 'withdrawn':
                    self.root.deiconify()
            except Exception:
                pass

            self.root.update_idletasks()

            # Redesenha filhos sem tomar foco agressivamente de popups/modal.
            try:
                for filho in self.root.winfo_children():
                    try:
                        if hasattr(filho, 'winfo_exists') and filho.winfo_exists():
                            filho.update_idletasks()
                    except Exception:
                        pass
            except Exception:
                pass

            try:
                AUDITORIA.info(f'Proteção PDV Sempre Vivo: {motivo}')
            except Exception:
                pass
        except Exception as e:
            try:
                AUDITORIA.erro('Falha na recuperação visual do PDV', exception=e)
            except Exception:
                pass

    def _agendar_watchdog(self, delay=None):
        try:
            if self.root.winfo_exists() and self._ativo:
                self.root.after(int(delay or self.intervalo_ms), self._watchdog_tick)
        except Exception:
            pass

    def _watchdog_tick(self):
        if not self._ativo:
            return
        try:
            self.root.update_idletasks()
        except Exception:
            pass

        try:
            import time
            agora = time.time()
            # Manutenção de memória no máximo a cada 45 segundos para não causar engasgos.
            if agora - self._ultimo_gc >= 45:
                self._ultimo_gc = agora
                quantum_reduzir_paginacao_e_aliviar_memoria()
        except Exception:
            pass

        self._agendar_watchdog()


def iniciar_protecao_pdv_sempre_vivo(root):
    """Inicializa camada global de proteção do PDV."""
    global _QUANTUM_KEEPALIVE_SINGLETON
    try:
        if _QUANTUM_KEEPALIVE_SINGLETON is None:
            _QUANTUM_KEEPALIVE_SINGLETON = QuantumPDVKeepAlive(root).iniciar()
        return _QUANTUM_KEEPALIVE_SINGLETON
    except Exception as e:
        try:
            AUDITORIA.erro('Não foi possível iniciar Proteção PDV Sempre Vivo', exception=e)
        except Exception:
            pass
        return None


def marcar_pdv_principal_visivel_para_keepalive():
    """Marca que a janela principal já apareceu e pode ser recuperada pelo watchdog."""
    try:
        if _QUANTUM_KEEPALIVE_SINGLETON is not None:
            _QUANTUM_KEEPALIVE_SINGLETON.marcar_janela_principal_visivel()
    except Exception:
        pass


