class ModernSwitch(ttk.Frame):
    """
    Switch Toggle Moderno com Animação.
    
    Uso:
        switch = ModernSwitch(parent, text="Ativar recurso", command=on_toggle)
        switch.pack()
    """
    
    def __init__(self, parent, text: str = "", command=None, 
                 on_color: str = "#10b981", off_color: str = "#94a3b8",
                 width: int = 50, height: int = 26, **kwargs):
        super().__init__(parent, **kwargs)
        
        self.text = text
        self.command = command
        self.on_color = on_color
        self.off_color = off_color
        self.switch_width = width
        self.switch_height = height
        self._is_on = False
        self._animation_id = None
        
        self._create_switch()
    
    def _create_switch(self):
        """Cria a estrutura visual do switch."""
        # Label de texto
        if self.text:
            self.text_label = ttk.Label(self, text=self.text, font=('Segoe UI', 10))
            self.text_label.pack(side=tk.LEFT, padx=(0, 10))
        
        # Canvas do switch
        self.canvas = tk.Canvas(
            self,
            width=self.switch_width,
            height=self.switch_height,
            bg=self.off_color,
            highlightthickness=0,
            cursor='hand2'
        )
        self.canvas.pack(side=tk.LEFT)
        
        # Círculo do toggle
        padding = 3
        circle_size = self.switch_height - (padding * 2)
        self.circle = self.canvas.create_oval(
            padding, padding,
            padding + circle_size, padding + circle_size,
            fill='white',
            outline=''
        )
        
        # Bind de clique
        self.canvas.bind('<Button-1>', self._toggle)
    
    def _toggle(self, event=None):
        """Alterna o estado do switch."""
        self._is_on = not self._is_on
        self._animate_toggle()
        
        if self.command:
            self.command(self._is_on)
    
    def _animate_toggle(self):
        """Anima a transição do toggle."""
        if self._animation_id:
            self.after_cancel(self._animation_id)
        
        padding = 3
        circle_size = self.switch_height - (padding * 2)
        
        if self._is_on:
            target_x = self.switch_width - circle_size - padding
            target_color = self.on_color
        else:
            target_x = padding
            target_color = self.off_color
        
        current_coords = self.canvas.coords(self.circle)
        current_x = current_coords[0]
        
        steps = 10
        step_x = (target_x - current_x) / steps
        current_step = [0]
        
        def animate():
            if current_step[0] >= steps:
                self.canvas.configure(bg=target_color)
                return
            
            new_x = current_x + step_x * current_step[0]
            self.canvas.coords(
                self.circle,
                new_x, padding,
                new_x + circle_size, padding + circle_size
            )
            
            # Transição de cor gradual
            progress = current_step[0] / steps
            if self._is_on:
                self.canvas.configure(bg=self._interpolate_color(self.off_color, self.on_color, progress))
            else:
                self.canvas.configure(bg=self._interpolate_color(self.on_color, self.off_color, progress))
            
            current_step[0] += 1
            self._animation_id = self.after(16, animate)
        
        animate()
    
    def _interpolate_color(self, color1: str, color2: str, progress: float) -> str:
        """Interpola entre duas cores."""
        def hex_to_rgb(hex_color):
            hex_color = hex_color.lstrip('#')
            return tuple(int(hex_color[i:i+2], 16) for i in (0, 2, 4))
        
        def rgb_to_hex(rgb):
            return '#{:02x}{:02x}{:02x}'.format(*rgb)
        
        rgb1 = hex_to_rgb(color1)
        rgb2 = hex_to_rgb(color2)
        
        rgb = tuple(int(rgb1[i] + (rgb2[i] - rgb1[i]) * progress) for i in range(3))
        return rgb_to_hex(rgb)
    
    def get(self) -> bool:
        """Retorna o estado atual."""
        return self._is_on
    
    def set(self, value: bool):
        """Define o estado do switch."""
        if value != self._is_on:
            self._toggle()


class ModernBadge(ttk.Frame):
    """
    Badge/Etiqueta Moderna para Notificações e Status.
    
    Uso:
        badge = ModernBadge(parent, text="5", color="danger")
        badge.pack()
    """
    
    COLORS = {
        'primary': '#2563eb',
        'success': '#10b981',
        'danger': '#ef4444',
        'warning': '#f59e0b',
        'info': '#06b6d4',
        'secondary': '#64748b',
    }
    
    def __init__(self, parent, text: str = "", color: str = "primary",
                 size: str = "medium", **kwargs):
        super().__init__(parent, **kwargs)
        
        self.badge_text = text
        self.color = self.COLORS.get(color, color)
        self.size = size
        
        self._create_badge()
    
    def _create_badge(self):
        """Cria a estrutura visual do badge."""
        font_sizes = {'small': 8, 'medium': 10, 'large': 12}
        paddings = {'small': (4, 2), 'medium': (6, 3), 'large': (8, 4)}
        
        font_size = font_sizes.get(self.size, 10)
        padding = paddings.get(self.size, (6, 3))
        
        self.label = tk.Label(
            self,
            text=self.badge_text,
            font=('Segoe UI', font_size, 'bold'),
            bg=self.color,
            fg='white',
            padx=padding[0],
            pady=padding[1]
        )
        self.label.pack()
    
    def update_text(self, text: str):
        """Atualiza o texto do badge."""
        self.badge_text = text
        self.label.configure(text=text)
    
    def update_color(self, color: str):
        """Atualiza a cor do badge."""
        self.color = self.COLORS.get(color, color)
        self.label.configure(bg=self.color)


class ModernAccordion(ttk.Frame):
    """
    Accordion/Expansível Moderno com Animação.
    
    Uso:
        accordion = ModernAccordion(parent)
        accordion.add_section("Seção 1", content_frame1)
        accordion.add_section("Seção 2", content_frame2)
    """
    
    def __init__(self, parent, allow_multiple: bool = False, **kwargs):
        super().__init__(parent, **kwargs)
        
        self.allow_multiple = allow_multiple
        self._sections = []
    
    def add_section(self, title: str, content_widget=None, expanded: bool = False):
        """Adiciona uma seção ao accordion."""
        section_frame = ttk.Frame(self)
        section_frame.pack(fill=tk.X, pady=2)
        
        # Header da seção
        header = ttk.Frame(section_frame)
        header.pack(fill=tk.X)
        
        # Ícone de expansão
        icon_label = ttk.Label(header, text="▶", font=('Segoe UI', 10))
        icon_label.pack(side=tk.LEFT, padx=5)
        
        # Título
        title_label = ttk.Label(header, text=title, font=('Segoe UI', 10, 'bold'))
        title_label.pack(side=tk.LEFT, padx=5)
        
        # Container de conteúdo
        content_frame = ttk.Frame(section_frame)
        
        if content_widget:
            content_widget.pack(in_=content_frame, fill=tk.BOTH, expand=True)
        
        section_data = {
            'frame': section_frame,
            'header': header,
            'icon': icon_label,
            'title': title_label,
            'content': content_frame,
            'expanded': False
        }
        
        self._sections.append(section_data)
        
        # Bind de clique
        for widget in [header, icon_label, title_label]:
            widget.bind('<Button-1>', lambda e, s=section_data: self._toggle_section(s))
            widget.configure(cursor='hand2')
        
        if expanded:
            self._toggle_section(section_data)
        
        return content_frame
    
    def _toggle_section(self, section: dict):
        """Alterna a expansão de uma seção."""
        if section['expanded']:
            # Colapsa
            section['content'].pack_forget()
            section['icon'].configure(text="▶")
            section['expanded'] = False
        else:
            # Se não permite múltiplos, colapsa outros
            if not self.allow_multiple:
                for s in self._sections:
                    if s['expanded'] and s != section:
                        s['content'].pack_forget()
                        s['icon'].configure(text="▶")
                        s['expanded'] = False
            
            # Expande
            section['content'].pack(fill=tk.X, padx=20, pady=5)
            section['icon'].configure(text="▼")
            section['expanded'] = True
    
    def expand_all(self):
        """Expande todas as seções."""
        for section in self._sections:
            if not section['expanded']:
                self._toggle_section(section)
    
    def collapse_all(self):
        """Colapsa todas as seções."""
        for section in self._sections:
            if section['expanded']:
                self._toggle_section(section)


class ModernTabView(ttk.Frame):
    """
    Tab View Moderno com Animação de Transição.
    
    Uso:
        tabs = ModernTabView(parent)
        tab1 = tabs.add_tab("Vendas", icon="💰")
        tab2 = tabs.add_tab("Produtos", icon="📦")
    """
    
    def __init__(self, parent, tab_position: str = "top", **kwargs):
        super().__init__(parent, **kwargs)
        
        self.tab_position = tab_position
        self._tabs = []
        self._current_tab = None
        
        self._create_structure()
    
    def _create_structure(self):
        """Cria a estrutura do tab view."""
        # Container de abas
        self.tab_bar = ttk.Frame(self)
        
        # Container de conteúdo
        self.content_frame = ttk.Frame(self)
        
        if self.tab_position == "top":
            self.tab_bar.pack(fill=tk.X, side=tk.TOP)
            self.content_frame.pack(fill=tk.BOTH, expand=True, side=tk.TOP)
        elif self.tab_position == "bottom":
            self.content_frame.pack(fill=tk.BOTH, expand=True, side=tk.TOP)
            self.tab_bar.pack(fill=tk.X, side=tk.BOTTOM)
        elif self.tab_position == "left":
            self.tab_bar.pack(fill=tk.Y, side=tk.LEFT)
            self.content_frame.pack(fill=tk.BOTH, expand=True, side=tk.LEFT)
    
    def add_tab(self, title: str, icon: str = "") -> ttk.Frame:
        """Adiciona uma nova aba."""
        # Botão da aba
        tab_text = f"{icon} {title}" if icon else title
        tab_button = ttk.Button(
            self.tab_bar,
            text=tab_text,
            command=lambda: self._select_tab(len(self._tabs))
        )
        tab_button.pack(side=tk.LEFT if self.tab_position in ["top", "bottom"] else tk.TOP, padx=2, pady=2)
        
        # Frame de conteúdo
        content = ttk.Frame(self.content_frame)
        
        tab_data = {
            'button': tab_button,
            'content': content,
            'title': title,
            'icon': icon
        }
        
        self._tabs.append(tab_data)
        
        # Seleciona primeira aba automaticamente
        if len(self._tabs) == 1:
            self._select_tab(0)
        
        return content
    
    def _select_tab(self, index: int):
        """Seleciona uma aba."""
        if index < 0 or index >= len(self._tabs):
            return
        
        # Esconde aba atual
        if self._current_tab is not None:
            self._tabs[self._current_tab]['content'].pack_forget()
        
        # Mostra nova aba
        self._tabs[index]['content'].pack(fill=tk.BOTH, expand=True)
        self._current_tab = index
    
    def get_current_tab(self) -> int:
        """Retorna índice da aba atual."""
        return self._current_tab
    
    def select_tab(self, index: int):
        """Seleciona uma aba por índice."""
        self._select_tab(index)


class ModernStepper(ttk.Frame):
    """
    Stepper/Wizard Moderno para Processos Multi-Etapa.
    
    Uso:
        stepper = ModernStepper(parent, steps=["Dados", "Pagamento", "Confirmação"])
        stepper.next_step()
    """
    
    def __init__(self, parent, steps: list, **kwargs):
        super().__init__(parent, **kwargs)
        
        self.steps = steps
        self._current_step = 0
        self._step_widgets = []
        
        self._create_stepper()
    
    def _create_stepper(self):
        """Cria a estrutura visual do stepper."""
        self.steps_frame = ttk.Frame(self)
        self.steps_frame.pack(fill=tk.X, pady=10)
        
        for i, step in enumerate(self.steps):
            step_frame = ttk.Frame(self.steps_frame)
            step_frame.pack(side=tk.LEFT, expand=True)
            
            # Círculo do número
            circle = tk.Canvas(step_frame, width=30, height=30, highlightthickness=0)
            circle.pack()
            
            # Desenha círculo
            circle_id = circle.create_oval(2, 2, 28, 28, fill='#e2e8f0', outline='')
            text_id = circle.create_text(15, 15, text=str(i + 1), font=('Segoe UI', 10, 'bold'))
            
            # Label do passo
            label = ttk.Label(step_frame, text=step, font=('Segoe UI', 9))
            label.pack(pady=5)
            
            self._step_widgets.append({
                'canvas': circle,
                'circle': circle_id,
                'text': text_id,
                'label': label
            })
            
            # Linha conectora (exceto último)
            if i < len(self.steps) - 1:
                line_canvas = tk.Canvas(self.steps_frame, width=50, height=30, highlightthickness=0)
                line_canvas.pack(side=tk.LEFT, expand=True)
                line_canvas.create_line(0, 15, 50, 15, fill='#e2e8f0', width=2)
        
        self._update_visual()
    
    def _update_visual(self):
        """Atualiza visual baseado no passo atual."""
        for i, widget in enumerate(self._step_widgets):
            canvas = widget['canvas']
            circle = widget['circle']
            text = widget['text']
            
            if i < self._current_step:
                # Passo completado
                canvas.itemconfig(circle, fill='#10b981')
                canvas.itemconfig(text, fill='white', text='✓')
            elif i == self._current_step:
                # Passo atual
                canvas.itemconfig(circle, fill='#2563eb')
                canvas.itemconfig(text, fill='white', text=str(i + 1))
            else:
                # Passo futuro
                canvas.itemconfig(circle, fill='#e2e8f0')
                canvas.itemconfig(text, fill='#64748b', text=str(i + 1))
    
    def next_step(self) -> bool:
        """Avança para o próximo passo."""
        if self._current_step < len(self.steps) - 1:
            self._current_step += 1
            self._update_visual()
            return True
        return False
    
    def previous_step(self) -> bool:
        """Volta para o passo anterior."""
        if self._current_step > 0:
            self._current_step -= 1
            self._update_visual()
            return True
        return False
    
    def go_to_step(self, step: int) -> bool:
        """Vai para um passo específico."""
        if 0 <= step < len(self.steps):
            self._current_step = step
            self._update_visual()
            return True
        return False
    
    def get_current_step(self) -> int:
        """Retorna o passo atual."""
        return self._current_step
    
    def is_complete(self) -> bool:
        """Verifica se todos os passos foram completados."""
        return self._current_step == len(self.steps) - 1

