class AdvancedLoyaltySystem:
    """
    Sistema de Fidelidade Avançado com Pontos, Níveis e Cashback.
    
    Características:
    - Sistema de pontos por compra
    - Níveis de cliente (Bronze, Prata, Ouro, Platina, Diamante)
    - Cashback progressivo por nível
    - Bônus de aniversário
    - Promoções especiais
    - Resgate de pontos
    - Histórico completo
    - Notificações automáticas
    """
    
    # Configuração de níveis
    LEVELS = {
        'bronze': {
            'name': 'Bronze',
            'min_points': 0,
            'max_points': 999,
            'points_multiplier': 1.0,
            'cashback_percent': 1.0,
            'color': '#cd7f32',
            'icon': '🥉',
            'benefits': ['1 ponto por R$ 1 gasto', '1% de cashback']
        },
        'silver': {
            'name': 'Prata',
            'min_points': 1000,
            'max_points': 4999,
            'points_multiplier': 1.5,
            'cashback_percent': 2.0,
            'color': '#c0c0c0',
            'icon': '🥈',
            'benefits': ['1.5 pontos por R$ 1 gasto', '2% de cashback', 'Ofertas exclusivas']
        },
        'gold': {
            'name': 'Ouro',
            'min_points': 5000,
            'max_points': 14999,
            'points_multiplier': 2.0,
            'cashback_percent': 3.0,
            'color': '#ffd700',
            'icon': '🥇',
            'benefits': ['2 pontos por R$ 1 gasto', '3% de cashback', 'Frete grátis', 'Atendimento prioritário']
        },
        'platinum': {
            'name': 'Platina',
            'min_points': 15000,
            'max_points': 49999,
            'points_multiplier': 2.5,
            'cashback_percent': 5.0,
            'color': '#e5e4e2',
            'icon': '💎',
            'benefits': ['2.5 pontos por R$ 1 gasto', '5% de cashback', 'Presente de aniversário', 'Acesso antecipado']
        },
        'diamond': {
            'name': 'Diamante',
            'min_points': 50000,
            'max_points': float('inf'),
            'points_multiplier': 3.0,
            'cashback_percent': 7.0,
            'color': '#b9f2ff',
            'icon': '👑',
            'benefits': ['3 pontos por R$ 1 gasto', '7% de cashback', 'Concierge pessoal', 'Eventos VIP']
        }
    }
    
    POINT_VALUE = 0.01
    
    def __init__(self, db_connection=None):
        self.db = db_connection
        self._customers_data = {}
        self._promotions = []
        self._transaction_history = []
    
    def get_customer_level(self, total_points: int) -> str:
        for level_id, level_data in self.LEVELS.items():
            if level_data['min_points'] <= total_points <= level_data['max_points']:
                return level_id
        return 'bronze'
    
    def get_level_info(self, level_id: str) -> dict:
        return self.LEVELS.get(level_id, self.LEVELS['bronze'])
    
    def calculate_points(self, purchase_total: float, customer_level: str = 'bronze') -> int:
        level_data = self.LEVELS.get(customer_level, self.LEVELS['bronze'])
        multiplier = level_data['points_multiplier']
        base_points = int(purchase_total)
        return int(base_points * multiplier)
    
    def calculate_cashback(self, purchase_total: float, customer_level: str = 'bronze') -> float:
        level_data = self.LEVELS.get(customer_level, self.LEVELS['bronze'])
        cashback_percent = level_data['cashback_percent']
        return round(purchase_total * (cashback_percent / 100), 2)
    
    def get_points_to_next_level(self, current_points: int) -> dict:
        current_level = self.get_customer_level(current_points)
        current_level_data = self.LEVELS[current_level]
        level_order = ['bronze', 'silver', 'gold', 'platinum', 'diamond']
        current_index = level_order.index(current_level)
        
        if current_index >= len(level_order) - 1:
            return {'current_level': current_level, 'next_level': None, 'points_needed': 0, 'progress_percent': 100}
        
        next_level = level_order[current_index + 1]
        next_level_data = self.LEVELS[next_level]
        points_needed = next_level_data['min_points'] - current_points
        level_range = current_level_data['max_points'] - current_level_data['min_points']
        points_in_level = current_points - current_level_data['min_points']
        progress_percent = min(100, (points_in_level / level_range) * 100) if level_range > 0 else 100
        
        return {
            'current_level': current_level,
            'next_level': next_level,
            'points_needed': points_needed,
            'progress_percent': round(progress_percent, 1)
        }
    
    def add_points(self, customer_id: str, points: int, reason: str = 'purchase') -> dict:
        import datetime
        if customer_id not in self._customers_data:
            self._customers_data[customer_id] = {'points': 0, 'cashback_balance': 0}
        
        customer = self._customers_data[customer_id]
        old_level = self.get_customer_level(customer['points'])
        customer['points'] += points
        new_level = self.get_customer_level(customer['points'])
        
        self._transaction_history.append({
            'type': 'earn', 'customer_id': customer_id, 'points': points,
            'reason': reason, 'timestamp': datetime.datetime.now().isoformat()
        })
        
        result = {'success': True, 'points_added': points, 'total_points': customer['points'], 'level': new_level}
        if new_level != old_level:
            result['level_up'] = True
            result['old_level'] = old_level
            result['new_level'] = new_level
            result['new_benefits'] = self.LEVELS[new_level]['benefits']
        return result
    
    def redeem_points(self, customer_id: str, points_to_redeem: int) -> dict:
        customer = self._customers_data.get(customer_id, {})
        current_points = customer.get('points', 0)
        
        if points_to_redeem > current_points:
            return {'success': False, 'error': 'Pontos insuficientes', 'available_points': current_points}
        
        discount_value = points_to_redeem * self.POINT_VALUE
        customer['points'] = current_points - points_to_redeem
        self._customers_data[customer_id] = customer
        
        return {'success': True, 'points_redeemed': points_to_redeem, 'discount_value': discount_value, 'remaining_points': customer['points']}
    
    def get_customer_summary(self, customer_id: str) -> dict:
        customer = self._customers_data.get(customer_id, {'points': 0, 'cashback_balance': 0})
        points = customer.get('points', 0)
        level = self.get_customer_level(points)
        level_info = self.LEVELS[level]
        progress = self.get_points_to_next_level(points)
        
        return {
            'customer_id': customer_id, 'points': points,
            'points_value': round(points * self.POINT_VALUE, 2),
            'cashback_balance': customer.get('cashback_balance', 0),
            'level': level, 'level_name': level_info['name'],
            'level_icon': level_info['icon'], 'level_color': level_info['color'],
            'benefits': level_info['benefits'], 'cashback_percent': level_info['cashback_percent'],
            'points_multiplier': level_info['points_multiplier'], 'progress': progress
        }


LOYALTY_SYSTEM = AdvancedLoyaltySystem()

