class AdvancedKeyboardManager:
    """
    Gerenciador de Atalhos de Teclado Avançado.
    """
    
    DEFAULT_SHORTCUTS = {
        'F1': {'action': 'open_help', 'description': 'Abrir ajuda'},
        'F2': {'action': 'select_customer', 'description': 'Selecionar cliente'},
        'F3': {'action': 'open_products', 'description': 'Cadastro de produtos'},
        'F4': {'action': 'open_customers', 'description': 'Cadastro de clientes'},
        'F5': {'action': 'start_payment', 'description': 'Iniciar pagamento'},
        'F6': {'action': 'open_cash', 'description': 'Abrir caixa'},
        'F7': {'action': 'open_payables', 'description': 'Contas a pagar'},
        'F8': {'action': 'open_receivables', 'description': 'Contas a receber'},
        'F9': {'action': 'open_reports', 'description': 'Relatórios'},
        'F10': {'action': 'open_settings', 'description': 'Configurações'},
        'F11': {'action': 'toggle_fullscreen', 'description': 'Tela cheia'},
        'F12': {'action': 'clear_cart', 'description': 'Limpar carrinho'},
        'Control-p': {'action': 'open_products', 'description': 'Produtos'},
        'Control-f': {'action': 'focus_search', 'description': 'Focar busca'},
        'Control-n': {'action': 'new_sale', 'description': 'Nova venda'},
        'Control-s': {'action': 'save', 'description': 'Salvar'},
        'Control-q': {'action': 'quit', 'description': 'Sair'},
        'Escape': {'action': 'cancel', 'description': 'Cancelar/Fechar'},
        'Return': {'action': 'confirm', 'description': 'Confirmar'},
    }
    
    def __init__(self, root=None, config_file: str = None):
        self.root = root
        self.config_file = config_file or 'keyboard_config.json'
        self._shortcuts = self.DEFAULT_SHORTCUTS.copy()
        self._callbacks = {}
    
    def register_shortcut(self, shortcut: str, action: str, description: str = "", callback=None):
        self._shortcuts[shortcut] = {'action': action, 'description': description}
        if callback:
            self._callbacks[action] = callback
        if self.root:
            try:
                self.root.bind(f'<{shortcut}>', lambda e: self._execute_shortcut(shortcut))
            except Exception:
                pass
    
    def _execute_shortcut(self, shortcut: str):
        shortcut_data = self._shortcuts.get(shortcut)
        if not shortcut_data:
            return
        action = shortcut_data['action']
        if action in self._callbacks:
            try:
                self._callbacks[action]()
            except Exception:
                pass
    
    def get_shortcut_help(self) -> list:
        return [{'shortcut': k, 'description': v.get('description', '')} for k, v in self._shortcuts.items()]


KEYBOARD_MANAGER = AdvancedKeyboardManager()

