# SISTEMA DE NOTIFICAÇÕES AVANÇADO v2.0 - ULTRA PROFESSIONAL
# ═══════════════════════════════════════════════════════════════════════════════════════

class AdvancedNotificationCenter:
    """
    Central de Notificações Avançada com Prioridades e Histórico.
    
    Características:
    - Notificações com prioridades (baixa, normal, alta, urgente)
    - Histórico de notificações
    - Notificações persistentes
    - Agrupamento por categoria
    - Sons personalizados
    - Ações rápidas
    - Notificações push (quando disponível)
    """
    
    PRIORITIES = {
        'low': {'color': '#64748b', 'icon': 'ℹ️', 'sound': None, 'duration': 3000},
        'normal': {'color': '#2563eb', 'icon': '📢', 'sound': 'notify', 'duration': 5000},
        'high': {'color': '#f59e0b', 'icon': '⚠️', 'sound': 'warning', 'duration': 8000},
        'urgent': {'color': '#ef4444', 'icon': '🚨', 'sound': 'alert', 'duration': 0},  # 0 = não fecha automaticamente
    }
    
    CATEGORIES = {
        'sale': {'name': 'Vendas', 'icon': '💰'},
        'stock': {'name': 'Estoque', 'icon': '📦'},
        'payment': {'name': 'Pagamentos', 'icon': '💳'},
        'system': {'name': 'Sistema', 'icon': '⚙️'},
        'customer': {'name': 'Clientes', 'icon': '👤'},
        'alert': {'name': 'Alertas', 'icon': '🔔'},
    }
    
    def __init__(self, root=None, max_visible: int = 5, max_history: int = 100):
        self.root = root
        self.max_visible = max_visible
        self.max_history = max_history
        self._notifications = []
        self._history = []
        self._visible_notifications = []
        self._callbacks = {}
        self._muted = False
        self._do_not_disturb = False
    
    def notify(self, title: str, message: str, priority: str = 'normal',
               category: str = 'system', actions: list = None, 
               persistent: bool = False, data: dict = None) -> str:
        """
        Cria uma nova notificação.
        
        Args:
            title: Título da notificação
            message: Mensagem da notificação
            priority: Prioridade (low, normal, high, urgent)
            category: Categoria da notificação
            actions: Lista de ações rápidas [{'label': 'Ver', 'callback': func}]
            persistent: Se True, não fecha automaticamente
            data: Dados adicionais
            
        Returns:
            ID da notificação
        """
        import uuid
        import datetime
        
        notification_id = str(uuid.uuid4())[:8]
        
        priority_config = self.PRIORITIES.get(priority, self.PRIORITIES['normal'])
        category_config = self.CATEGORIES.get(category, self.CATEGORIES['system'])
        
        notification = {
            'id': notification_id,
            'title': title,
            'message': message,
            'priority': priority,
            'priority_config': priority_config,
            'category': category,
            'category_config': category_config,
            'actions': actions or [],
            'persistent': persistent or priority == 'urgent',
            'data': data or {},
            'timestamp': datetime.datetime.now().isoformat(),
            'read': False,
            'dismissed': False,
        }
        
        self._notifications.append(notification)
        self._history.append(notification.copy())
        
        # Limita histórico
        if len(self._history) > self.max_history:
            self._history = self._history[-self.max_history:]
        
        # Exibe notificação se não estiver em modo não perturbe
        if not self._do_not_disturb or priority == 'urgent':
            self._show_notification(notification)
        
        return notification_id
    
    def _show_notification(self, notification: dict):
        """Exibe a notificação visualmente."""
        if not self.root:
            return
        
        # Limita notificações visíveis
        if len(self._visible_notifications) >= self.max_visible:
            oldest = self._visible_notifications.pop(0)
            self._dismiss_visual(oldest['id'])
        
        self._visible_notifications.append(notification)
        
        # Cria widget de notificação
        self._create_notification_widget(notification)
        
        # Agenda fechamento automático
        duration = notification['priority_config']['duration']
        if duration > 0 and not notification['persistent']:
            self.root.after(duration, lambda: self.dismiss(notification['id']))
    
    def _create_notification_widget(self, notification: dict):
        """Cria widget visual da notificação."""
        # Implementação depende do contexto Tkinter
        pass
    
    def dismiss(self, notification_id: str):
        """Dispensa uma notificação."""
        for notif in self._notifications:
            if notif['id'] == notification_id:
                notif['dismissed'] = True
                break
        
        self._visible_notifications = [
            n for n in self._visible_notifications if n['id'] != notification_id
        ]
        
        self._dismiss_visual(notification_id)
    
    def _dismiss_visual(self, notification_id: str):
        """Remove widget visual da notificação."""
        pass
    
    def dismiss_all(self):
        """Dispensa todas as notificações."""
        for notif in self._notifications:
            notif['dismissed'] = True
        self._visible_notifications = []
    
    def mark_as_read(self, notification_id: str):
        """Marca notificação como lida."""
        for notif in self._notifications + self._history:
            if notif['id'] == notification_id:
                notif['read'] = True
    
    def mark_all_as_read(self):
        """Marca todas as notificações como lidas."""
        for notif in self._notifications + self._history:
            notif['read'] = True
    
    def get_unread_count(self) -> int:
        """Retorna contagem de não lidas."""
        return sum(1 for n in self._notifications if not n['read'] and not n['dismissed'])
    
    def get_history(self, category: str = None, limit: int = 50) -> list:
        """Retorna histórico de notificações."""
        history = self._history
        if category:
            history = [n for n in history if n['category'] == category]
        return history[-limit:]
    
    def mute(self):
        """Silencia notificações."""
        self._muted = True
    
    def unmute(self):
        """Reativa sons de notificações."""
        self._muted = False
    
    def enable_dnd(self, duration_minutes: int = None):
        """Ativa modo não perturbe."""
        self._do_not_disturb = True
        if duration_minutes and self.root:
            self.root.after(duration_minutes * 60000, self.disable_dnd)
    
    def disable_dnd(self):
        """Desativa modo não perturbe."""
        self._do_not_disturb = False
    
    def on_notification(self, callback):
        """Registra callback para novas notificações."""
        self._callbacks['on_notification'] = callback
    
    # Métodos de conveniência
    def info(self, title: str, message: str, **kwargs):
        """Notificação informativa."""
        return self.notify(title, message, priority='low', **kwargs)
    
    def success(self, title: str, message: str, **kwargs):
        """Notificação de sucesso."""
        return self.notify(title, message, priority='normal', category='sale', **kwargs)
    
    def warning(self, title: str, message: str, **kwargs):
        """Notificação de aviso."""
        return self.notify(title, message, priority='high', category='alert', **kwargs)
    
    def error(self, title: str, message: str, **kwargs):
        """Notificação de erro."""
        return self.notify(title, message, priority='urgent', category='system', **kwargs)
    
    def stock_alert(self, product_name: str, current_stock: int, min_stock: int):
        """Alerta de estoque baixo."""
        return self.notify(
            "Estoque Baixo",
            f"{product_name}: {current_stock} unidades (mínimo: {min_stock})",
            priority='high',
            category='stock'
        )
    
    def sale_completed(self, sale_id: str, total: float):
        """Notificação de venda concluída."""
        return self.notify(
            "Venda Concluída",
            f"Venda #{sale_id} - R$ {total:.2f}",
            priority='normal',
            category='sale'
        )


# Instância global da central de notificações
