class AdvancedUtils:
    """
    Utilitários Avançados para o Sistema PDV.
    
    Características:
    - Formatação de valores monetários
    - Formatação de datas
    - Cálculos financeiros
    - Geração de códigos
    - Manipulação de strings
    - Conversões diversas
    """
    
    @staticmethod
    def format_currency(value: float, symbol: str = 'R$', decimal_places: int = 2) -> str:
        """Formata valor como moeda brasileira."""
        try:
            formatted = f'{float(value):,.{decimal_places}f}'
            # Converte para formato brasileiro
            formatted = formatted.replace(',', 'X').replace('.', ',').replace('X', '.')
            return f'{symbol} {formatted}'
        except (ValueError, TypeError):
            return f'{symbol} 0,00'
    
    @staticmethod
    def parse_currency(value: str) -> float:
        """Converte string de moeda para float."""
        if not value:
            return 0.0
        
        # Remove símbolo e espaços
        value = str(value).replace('R$', '').replace(' ', '').strip()
        
        # Trata formato brasileiro
        if ',' in value and '.' in value:
            if value.rfind(',') > value.rfind('.'):
                value = value.replace('.', '').replace(',', '.')
            else:
                value = value.replace(',', '')
        elif ',' in value:
            value = value.replace(',', '.')
        
        try:
            return float(value)
        except ValueError:
            return 0.0
    
    @staticmethod
    def format_date(date_obj, format: str = '%d/%m/%Y') -> str:
        """Formata objeto de data."""
        import datetime
        
        if isinstance(date_obj, str):
            return date_obj
        
        if isinstance(date_obj, datetime.datetime):
            return date_obj.strftime(format)
        
        if isinstance(date_obj, datetime.date):
            return date_obj.strftime(format)
        
        return ''
    
    @staticmethod
    def format_datetime(date_obj, format: str = '%d/%m/%Y %H:%M:%S') -> str:
        """Formata objeto de data e hora."""
        return AdvancedUtils.format_date(date_obj, format)
    
    @staticmethod
    def format_cpf(cpf: str) -> str:
        """Formata CPF."""
        cpf = re.sub(r'[^0-9]', '', str(cpf))
        if len(cpf) == 11:
            return f'{cpf[:3]}.{cpf[3:6]}.{cpf[6:9]}-{cpf[9:]}'
        return cpf
    
    @staticmethod
    def format_cnpj(cnpj: str) -> str:
        """Formata CNPJ."""
        cnpj = re.sub(r'[^0-9]', '', str(cnpj))
        if len(cnpj) == 14:
            return f'{cnpj[:2]}.{cnpj[2:5]}.{cnpj[5:8]}/{cnpj[8:12]}-{cnpj[12:]}'
        return cnpj
    
    @staticmethod
    def format_phone(phone: str) -> str:
        """Formata telefone."""
        digits = re.sub(r'[^0-9]', '', str(phone))
        if len(digits) == 11:
            return f'({digits[:2]}) {digits[2:7]}-{digits[7:]}'
        elif len(digits) == 10:
            return f'({digits[:2]}) {digits[2:6]}-{digits[6:]}'
        return phone
    
    @staticmethod
    def format_cep(cep: str) -> str:
        """Formata CEP."""
        digits = re.sub(r'[^0-9]', '', str(cep))
        if len(digits) == 8:
            return f'{digits[:5]}-{digits[5:]}'
        return cep
    
    @staticmethod
    def generate_code(prefix: str = '', length: int = 8, uppercase: bool = True) -> str:
        """Gera código aleatório."""
        import random
        import string
        
        chars = string.ascii_uppercase + string.digits if uppercase else string.ascii_letters + string.digits
        code = ''.join(random.choices(chars, k=length))
        
        return f'{prefix}{code}' if prefix else code
    
    @staticmethod
    def generate_barcode(product_id: int, prefix: str = '789') -> str:
        """Gera código de barras EAN-13."""
        # Prefixo Brasil (789) + código do produto
        code = f'{prefix}{str(product_id).zfill(9)}'
        
        # Calcula dígito verificador
        odd_sum = sum(int(code[i]) for i in range(0, 12, 2))
        even_sum = sum(int(code[i]) for i in range(1, 12, 2))
        total = odd_sum + (even_sum * 3)
        check_digit = (10 - (total % 10)) % 10
        
        return f'{code}{check_digit}'
    
    @staticmethod
    def calculate_discount(original_price: float, discount_percent: float) -> dict:
        """Calcula desconto."""
        discount_value = original_price * (discount_percent / 100)
        final_price = original_price - discount_value
        
        return {
            'original_price': original_price,
            'discount_percent': discount_percent,
            'discount_value': round(discount_value, 2),
            'final_price': round(final_price, 2)
        }
    
    @staticmethod
    def calculate_markup(cost_price: float, markup_percent: float) -> dict:
        """Calcula markup."""
        markup_value = cost_price * (markup_percent / 100)
        sell_price = cost_price + markup_value
        
        return {
            'cost_price': cost_price,
            'markup_percent': markup_percent,
            'markup_value': round(markup_value, 2),
            'sell_price': round(sell_price, 2)
        }
    
    @staticmethod
    def calculate_margin(cost_price: float, sell_price: float) -> dict:
        """Calcula margem de lucro."""
        profit = sell_price - cost_price
        margin_percent = (profit / sell_price * 100) if sell_price > 0 else 0
        markup_percent = (profit / cost_price * 100) if cost_price > 0 else 0
        
        return {
            'cost_price': cost_price,
            'sell_price': sell_price,
            'profit': round(profit, 2),
            'margin_percent': round(margin_percent, 2),
            'markup_percent': round(markup_percent, 2)
        }
    
    @staticmethod
    def calculate_installments(total: float, num_installments: int, 
                                interest_rate: float = 0) -> list:
        """Calcula parcelas."""
        if num_installments <= 0:
            return []
        
        if interest_rate > 0:
            # Juros compostos
            rate = interest_rate / 100
            installment = total * (rate * (1 + rate) ** num_installments) / ((1 + rate) ** num_installments - 1)
            total_with_interest = installment * num_installments
        else:
            installment = total / num_installments
            total_with_interest = total
        
        installments = []
        for i in range(num_installments):
            installments.append({
                'number': i + 1,
                'value': round(installment, 2),
                'total_paid': round(installment * (i + 1), 2)
            })
        
        return {
            'installments': installments,
            'installment_value': round(installment, 2),
            'total_original': total,
            'total_with_interest': round(total_with_interest, 2),
            'interest_value': round(total_with_interest - total, 2)
        }
    
    @staticmethod
    def truncate_text(text: str, max_length: int, suffix: str = '...') -> str:
        """Trunca texto com sufixo."""
        if not text or len(text) <= max_length:
            return text
        return text[:max_length - len(suffix)] + suffix
    
    @staticmethod
    def slugify(text: str) -> str:
        """Converte texto para slug."""
        import unicodedata
        
        # Normaliza e remove acentos
        text = unicodedata.normalize('NFKD', str(text))
        text = text.encode('ascii', 'ignore').decode('ascii')
        
        # Converte para minúsculas e substitui espaços
        text = text.lower()
        text = re.sub(r'[^a-z0-9]+', '-', text)
        text = text.strip('-')
        
        return text
    
    @staticmethod
    def time_ago(date_obj) -> str:
        """Retorna tempo relativo (ex: 'há 5 minutos')."""
        import datetime
        
        if isinstance(date_obj, str):
            date_obj = datetime.datetime.fromisoformat(date_obj)
        
        now = datetime.datetime.now()
        diff = now - date_obj
        
        seconds = diff.total_seconds()
        
        if seconds < 60:
            return 'agora mesmo'
        elif seconds < 3600:
            minutes = int(seconds / 60)
            return f'há {minutes} minuto{"s" if minutes > 1 else ""}'
        elif seconds < 86400:
            hours = int(seconds / 3600)
            return f'há {hours} hora{"s" if hours > 1 else ""}'
        elif seconds < 604800:
            days = int(seconds / 86400)
            return f'há {days} dia{"s" if days > 1 else ""}'
        elif seconds < 2592000:
            weeks = int(seconds / 604800)
            return f'há {weeks} semana{"s" if weeks > 1 else ""}'
        elif seconds < 31536000:
            months = int(seconds / 2592000)
            return f'há {months} mês{"es" if months > 1 else ""}'
        else:
            years = int(seconds / 31536000)
            return f'há {years} ano{"s" if years > 1 else ""}'


# Instância global de utilitários
UTILS = AdvancedUtils()






















