class SelfServicePesagemWindow(tk.Toplevel):
    """
    Janela de Self-Service para Pesagem de Produtos.
    
    Interface moderna e intuitiva onde o cliente pode:
    - Ver o peso em tempo real com display grande
    - Selecionar o produto a ser pesado
    - Visualizar o preço por kg
    - Ver o valor total calculado automaticamente
    - Confirmar a pesagem para adicionar ao carrinho
    
    A tela atualiza automaticamente em tempo real quando o peso
    na balança é alterado.
    """
    
    def __init__(self, parent, app):
        super().__init__(parent)
        self.app = app
        self.leitura_ativa = False
        self.produto_selecionado = None
        self.peso_atual = 0.0
        self.preco_kg = 0.0
        
        # Configuração da janela
        self.title("⚖️ Self-Service - Pesagem de Produtos")
        responsive_geometry(self, 900, 700)
        self.resizable(True, True)
        self.configure(bg="#1a1a2e")
        
        # Torna a janela modal e em tela cheia opcional
        self.transient(parent)
        self.grab_set()
        
        # Cria interface
        self._criar_interface()
        self._carregar_produtos_peso()
        self._iniciar_leitura()
        
        # Maximiza a janela
        self.update_idletasks()
        try:
            # Windows
            self.state('zoomed')
        except tk.TclError:
            # Linux/Mac - usa fullscreen ou maximiza manualmente
            try:
                self.attributes('-zoomed', True)
            except tk.TclError:
                # Fallback: define tamanho igual à tela
                screen_width = self.winfo_screenwidth()
                screen_height = self.winfo_screenheight()
                self.geometry(f"{screen_width}x{screen_height}+0+0")
        
        # Protocolo de fechamento
        self.protocol("WM_DELETE_WINDOW", self._on_close)
        
        # Atalhos de teclado
        self.bind("<Escape>", lambda e: self._on_close())
        self.bind("<F11>", self._toggle_fullscreen)
        self.bind("<Return>", lambda e: self._confirmar_pesagem())
        
        self._fullscreen = False
    
