# COMPONENTES DE INTERFACE AVANÇADOS
# ═══════════════════════════════════════════════════════════════════════════════════════

class ModernButton(tk.Button):
    """
    Botão Moderno com Efeitos Visuais.
    
    Características:
    - Efeito hover suave
    - Efeito de clique
    - Ícones integrados
    - Tooltips automáticos
    - Variantes de estilo
    """
    
    STYLES = {
        'primary': {'bg': '#2563eb', 'fg': 'white', 'hover': '#1d4ed8', 'active': '#1e40af'},
        'success': {'bg': '#10b981', 'fg': 'white', 'hover': '#059669', 'active': '#047857'},
        'danger': {'bg': '#ef4444', 'fg': 'white', 'hover': '#dc2626', 'active': '#b91c1c'},
        'warning': {'bg': '#f59e0b', 'fg': 'white', 'hover': '#d97706', 'active': '#b45309'},
        'secondary': {'bg': '#6b7280', 'fg': 'white', 'hover': '#4b5563', 'active': '#374151'},
        'outline': {'bg': 'white', 'fg': '#2563eb', 'hover': '#eff6ff', 'active': '#dbeafe'},
        'ghost': {'bg': 'transparent', 'fg': '#2563eb', 'hover': '#eff6ff', 'active': '#dbeafe'},
    }
    
    def __init__(self, parent, text="", icon=None, style='primary', tooltip=None, **kwargs):
        self.style_name = style
        self.style_config = self.STYLES.get(style, self.STYLES['primary'])
        
        # Texto com ícone
        display_text = f"{icon} {text}" if icon else text
        
        super().__init__(
            parent,
            text=display_text,
            bg=self.style_config['bg'],
            fg=self.style_config['fg'],
            activebackground=self.style_config['active'],
            activeforeground=self.style_config['fg'],
            relief=tk.FLAT,
            cursor='hand2',
            font=('Segoe UI', 10),
            padx=15,
            pady=8,
            **kwargs
        )
        
        # Bind eventos de hover
        self.bind('<Enter>', self._on_enter)
        self.bind('<Leave>', self._on_leave)
        
        # Tooltip
        if tooltip:
            self._create_tooltip(tooltip)
    
    def _on_enter(self, event):
        """Efeito hover."""
        self.config(bg=self.style_config['hover'])
    
    def _on_leave(self, event):
        """Remove efeito hover."""
        self.config(bg=self.style_config['bg'])
    
    def _create_tooltip(self, text):
        """Cria tooltip para o botão."""
        self.tooltip = None
        
        def show_tooltip(event):
            x, y, _, _ = self.bbox("insert")
            x += self.winfo_rootx() + 25
            y += self.winfo_rooty() + 25
            
            self.tooltip = tk.Toplevel(self)
            self.tooltip.wm_overrideredirect(True)
            self.tooltip.wm_geometry(f"+{x}+{y}")
            
            label = tk.Label(self.tooltip, text=text, background="#333333", 
                           foreground="white", relief=tk.SOLID, borderwidth=1,
                           font=('Segoe UI', 9), padx=8, pady=4)
            label.pack()
        
        def hide_tooltip(event):
            if self.tooltip:
                self.tooltip.destroy()
                self.tooltip = None
        
        self.bind('<Enter>', lambda e: [self._on_enter(e), show_tooltip(e)])
        self.bind('<Leave>', lambda e: [self._on_leave(e), hide_tooltip(e)])


class ModernEntry(tk.Frame):
    """
    Campo de Entrada Moderno com Validação.
    
    Características:
    - Placeholder text
    - Validação em tempo real
    - Ícone de status
    - Máscara de entrada
    - Feedback visual
    """
    
    def __init__(self, parent, placeholder="", validator=None, mask=None, 
                 icon=None, password=False, **kwargs):
        super().__init__(parent, bg='white', highlightthickness=1, 
                        highlightbackground='#e2e8f0', highlightcolor='#2563eb')
        
        self.placeholder = placeholder
        self.validator = validator
        self.mask = mask
        self._is_placeholder = True
        
        # Frame interno
        inner_frame = tk.Frame(self, bg='white')
        inner_frame.pack(fill=tk.BOTH, expand=True, padx=2, pady=2)
        
        # Ícone (se houver)
        if icon:
            icon_label = tk.Label(inner_frame, text=icon, bg='white', 
                                 font=('Segoe UI', 12), fg='#64748b')
            icon_label.pack(side=tk.LEFT, padx=(5, 0))
        
        # Entry
        show_char = '●' if password else ''
        self.entry = tk.Entry(inner_frame, bg='white', fg='#94a3b8', 
                             relief=tk.FLAT, font=('Segoe UI', 11),
                             show=show_char, **kwargs)
        self.entry.pack(side=tk.LEFT, fill=tk.BOTH, expand=True, padx=5, pady=5)
        
        # Status icon
        self.status_label = tk.Label(inner_frame, text='', bg='white', 
                                    font=('Segoe UI', 12))
        self.status_label.pack(side=tk.RIGHT, padx=(0, 5))
        
        # Placeholder
        if placeholder:
            self.entry.insert(0, placeholder)
            self.entry.bind('<FocusIn>', self._on_focus_in)
            self.entry.bind('<FocusOut>', self._on_focus_out)
        
        # Validação
        if validator:
            self.entry.bind('<KeyRelease>', self._validate)
        
        # Máscara
        if mask:
            self.entry.bind('<KeyRelease>', self._apply_mask)
    
    def _on_focus_in(self, event):
        """Remove placeholder ao focar."""
        if self._is_placeholder:
            self.entry.delete(0, tk.END)
            self.entry.config(fg='#1e293b')
            self._is_placeholder = False
    
    def _on_focus_out(self, event):
        """Restaura placeholder se vazio."""
        if not self.entry.get():
            self.entry.insert(0, self.placeholder)
            self.entry.config(fg='#94a3b8')
            self._is_placeholder = True
    
    def _validate(self, event=None):
        """Valida o valor."""
        if self.validator and not self._is_placeholder:
            value = self.entry.get()
            is_valid, message = self.validator(value)
            
            if is_valid:
                self.status_label.config(text='✓', fg='#10b981')
                self.config(highlightbackground='#10b981')
            else:
                self.status_label.config(text='✗', fg='#ef4444')
                self.config(highlightbackground='#ef4444')
    
    def _apply_mask(self, event=None):
        """Aplica máscara de entrada."""
        if not self.mask:
            return
        
        value = self.entry.get()
        # Implementação básica de máscara
        # Pode ser expandida conforme necessidade
    
    def get(self):
        """Retorna o valor do campo."""
        if self._is_placeholder:
            return ''
        return self.entry.get()
    
    def set(self, value):
        """Define o valor do campo."""
        self._is_placeholder = False
        self.entry.config(fg='#1e293b')
        self.entry.delete(0, tk.END)
        self.entry.insert(0, value)


class ProgressRing(tk.Canvas):
    """
    Indicador de Progresso Circular Animado.
    
    Características:
    - Animação suave
    - Cores personalizáveis
    - Texto central
    - Múltiplos estilos
    """
    
    def __init__(self, parent, size=100, thickness=10, color='#2563eb', 
                 bg_color='#e2e8f0', **kwargs):
        super().__init__(parent, width=size, height=size, 
                        highlightthickness=0, bg=parent.cget('bg'), **kwargs)
        
        self.size = size
        self.thickness = thickness
        self.color = color
        self.bg_color = bg_color
        self._progress = 0
        self._animation_id = None
        
        # Desenha o anel de fundo
        padding = thickness / 2
        self.create_oval(padding, padding, size - padding, size - padding,
                        outline=bg_color, width=thickness, tags='bg_ring')
        
        # Desenha o anel de progresso
        self._progress_arc = self.create_arc(
            padding, padding, size - padding, size - padding,
            start=90, extent=0, outline=color, width=thickness,
            style=tk.ARC, tags='progress_ring'
        )
        
        # Texto central
        self._text = self.create_text(size/2, size/2, text='0%',
                                     font=('Segoe UI', int(size/5), 'bold'),
                                     fill='#1e293b', tags='progress_text')
    
    def set_progress(self, value, animate=True):
        """
        Define o progresso.
        
        Args:
            value: Valor de 0 a 100
            animate: Se deve animar a transição
        """
        value = max(0, min(100, value))
        
        if animate:
            self._animate_to(value)
        else:
            self._progress = value
            self._update_display()
    
    def _animate_to(self, target):
        """Anima até o valor alvo."""
        if self._animation_id:
            self.after_cancel(self._animation_id)
        
        def step():
            diff = target - self._progress
            if abs(diff) < 0.5:
                self._progress = target
                self._update_display()
                return
            
            self._progress += diff * 0.1
            self._update_display()
            self._animation_id = self.after(16, step)
        
        step()
    
    def _update_display(self):
        """Atualiza a exibição."""
        extent = -self._progress * 3.6  # 360 graus / 100
        self.itemconfig(self._progress_arc, extent=extent)
        self.itemconfig(self._text, text=f'{int(self._progress)}%')


class StatusIndicator(tk.Frame):
    """
    Indicador de Status com Animação.
    
    Características:
    - Múltiplos estados (online, offline, busy, away)
    - Animação de pulso
    - Tooltip com descrição
    """
    
    STATES = {
        'online': {'color': '#22c55e', 'text': 'Online'},
        'offline': {'color': '#ef4444', 'text': 'Offline'},
        'busy': {'color': '#f59e0b', 'text': 'Ocupado'},
        'away': {'color': '#6b7280', 'text': 'Ausente'},
        'connecting': {'color': '#3b82f6', 'text': 'Conectando...'},
    }
    
    def __init__(self, parent, state='offline', size=12, pulse=False, **kwargs):
        super().__init__(parent, **kwargs)
        
        self.size = size
        self.pulse = pulse
        self._state = state
        self._pulse_id = None
        
        # Canvas para o indicador
        self.canvas = tk.Canvas(self, width=size, height=size, 
                               highlightthickness=0, bg=self.cget('bg'))
        self.canvas.pack()
        
        # Desenha o indicador
        self._indicator = self.canvas.create_oval(
            2, 2, size-2, size-2,
            fill=self.STATES[state]['color'],
            outline='white', width=1
        )
        
        # Inicia animação se necessário
        if pulse:
            self._start_pulse()
    
    def set_state(self, state):
        """Define o estado do indicador."""
        if state not in self.STATES:
            return
        
        self._state = state
        self.canvas.itemconfig(self._indicator, fill=self.STATES[state]['color'])
    
    def _start_pulse(self):
        """Inicia animação de pulso."""
        def pulse():
            current_color = self.canvas.itemcget(self._indicator, 'fill')
            state_color = self.STATES[self._state]['color']
            
            # Alterna entre cor normal e mais clara
            if current_color == state_color:
                # Clareia a cor
                lighter = self._lighten_color(state_color, 0.3)
                self.canvas.itemconfig(self._indicator, fill=lighter)
            else:
                self.canvas.itemconfig(self._indicator, fill=state_color)
            
            self._pulse_id = self.after(500, pulse)
        
        pulse()
    
    def _lighten_color(self, hex_color, factor):
        """Clareia uma cor hex."""
        hex_color = hex_color.lstrip('#')
        r, g, b = int(hex_color[:2], 16), int(hex_color[2:4], 16), int(hex_color[4:], 16)
        r = int(r + (255 - r) * factor)
        g = int(g + (255 - g) * factor)
        b = int(b + (255 - b) * factor)
        return f'#{r:02x}{g:02x}{b:02x}'
    
    def stop_pulse(self):
        """Para a animação de pulso."""
        if self._pulse_id:
            self.after_cancel(self._pulse_id)
            self._pulse_id = None





