# DASHBOARD ANALYTICS AVANÇADO v2.0
# ═══════════════════════════════════════════════════════════════════════════════════════

class AdvancedDashboard:
    """
    Dashboard Analítico Avançado com Visualizações Interativas.
    
    Características:
    - Gráficos em tempo real
    - KPIs animados
    - Previsões de vendas
    - Análise de tendências
    - Comparativos de período
    - Exportação de relatórios
    """
    
    def __init__(self, parent, data_source):
        self.parent = parent
        self.data_source = data_source
        self.refresh_interval = 30000  # 30 segundos
        self._widgets = {}
    
    def create_kpi_card(self, parent, title, value, icon, change=None, change_type='positive'):
        """
        Cria um card de KPI animado.
        
        Args:
            parent: Widget pai
            title: Título do KPI
            value: Valor atual
            icon: Ícone do KPI
            change: Variação percentual
            change_type: 'positive', 'negative' ou 'neutral'
        """
        card = tk.Frame(parent, bg='white', relief=tk.RAISED, bd=1)
        card.pack(side=tk.LEFT, fill=tk.BOTH, expand=True, padx=5, pady=5)
        
        # Ícone
        icon_label = tk.Label(card, text=icon, font=('Segoe UI', 24), 
                             bg='white', fg='#2563eb')
        icon_label.pack(pady=(15, 5))
        
        # Valor
        value_label = tk.Label(card, text=value, font=('Segoe UI', 20, 'bold'),
                              bg='white', fg='#1e293b')
        value_label.pack()
        
        # Título
        title_label = tk.Label(card, text=title, font=('Segoe UI', 10),
                              bg='white', fg='#64748b')
        title_label.pack()
        
        # Variação
        if change is not None:
            change_colors = {
                'positive': '#10b981',
                'negative': '#ef4444',
                'neutral': '#6b7280'
            }
            change_icons = {
                'positive': '↑',
                'negative': '↓',
                'neutral': '→'
            }
            
            change_text = f"{change_icons[change_type]} {change}%"
            change_label = tk.Label(card, text=change_text, 
                                   font=('Segoe UI', 9, 'bold'),
                                   bg='white', fg=change_colors[change_type])
            change_label.pack(pady=(5, 15))
        else:
            tk.Label(card, text='', bg='white').pack(pady=(5, 15))
        
        return card
    
    def create_mini_chart(self, parent, data, chart_type='line', color='#2563eb'):
        """
        Cria um mini gráfico usando Canvas.
        
        Args:
            parent: Widget pai
            data: Lista de valores
            chart_type: 'line', 'bar' ou 'area'
            color: Cor do gráfico
        """
        width = 200
        height = 60
        
        canvas = tk.Canvas(parent, width=width, height=height, 
                          bg='white', highlightthickness=0)
        canvas.pack(pady=5)
        
        if not data:
            return canvas
        
        # Normaliza dados
        min_val = min(data)
        max_val = max(data)
        range_val = max_val - min_val if max_val != min_val else 1
        
        padding = 5
        chart_width = width - 2 * padding
        chart_height = height - 2 * padding
        
        points = []
        for i, val in enumerate(data):
            x = padding + (i / (len(data) - 1)) * chart_width if len(data) > 1 else width / 2
            y = height - padding - ((val - min_val) / range_val) * chart_height
            points.append((x, y))
        
        if chart_type == 'line':
            # Desenha linha
            for i in range(len(points) - 1):
                canvas.create_line(points[i][0], points[i][1],
                                  points[i+1][0], points[i+1][1],
                                  fill=color, width=2, smooth=True)
            
            # Desenha pontos
            for x, y in points:
                canvas.create_oval(x-3, y-3, x+3, y+3, fill=color, outline='white')
        
        elif chart_type == 'bar':
            bar_width = chart_width / len(data) - 2
            for i, (x, y) in enumerate(points):
                x1 = padding + i * (chart_width / len(data)) + 1
                canvas.create_rectangle(x1, y, x1 + bar_width, height - padding,
                                       fill=color, outline='')
        
        elif chart_type == 'area':
            # Cria polígono para área
            area_points = [(padding, height - padding)]
            area_points.extend(points)
            area_points.append((width - padding, height - padding))
            
            flat_points = [coord for point in area_points for coord in point]
            canvas.create_polygon(flat_points, fill=color + '33', outline=color, width=2)
        
        return canvas
    
    def create_sales_trend_widget(self, parent, sales_data):
        """Cria widget de tendência de vendas."""
        frame = tk.LabelFrame(parent, text="📈 Tendência de Vendas", 
                             font=('Segoe UI', 11, 'bold'), bg='white')
        frame.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)
        
        # Gráfico
        if sales_data:
            self.create_mini_chart(frame, sales_data, 'area', '#2563eb')
        
        # Estatísticas
        stats_frame = tk.Frame(frame, bg='white')
        stats_frame.pack(fill=tk.X, padx=10, pady=5)
        
        if sales_data:
            avg = sum(sales_data) / len(sales_data)
            max_val = max(sales_data)
            min_val = min(sales_data)
            
            tk.Label(stats_frame, text=f"Média: R$ {avg:,.2f}", 
                    font=('Segoe UI', 9), bg='white', fg='#64748b').pack(side=tk.LEFT)
            tk.Label(stats_frame, text=f"Máx: R$ {max_val:,.2f}", 
                    font=('Segoe UI', 9), bg='white', fg='#10b981').pack(side=tk.LEFT, padx=10)
            tk.Label(stats_frame, text=f"Mín: R$ {min_val:,.2f}", 
                    font=('Segoe UI', 9), bg='white', fg='#ef4444').pack(side=tk.LEFT)
        
        return frame
    
    def create_top_products_widget(self, parent, products_data):
        """Cria widget de produtos mais vendidos."""
        frame = tk.LabelFrame(parent, text="🏆 Top Produtos", 
                             font=('Segoe UI', 11, 'bold'), bg='white')
        frame.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)
        
        for i, (product, qty, total) in enumerate(products_data[:5], 1):
            row = tk.Frame(frame, bg='white')
            row.pack(fill=tk.X, padx=10, pady=3)
            
            # Posição
            pos_colors = ['#fbbf24', '#94a3b8', '#cd7f32', '#64748b', '#64748b']
            tk.Label(row, text=f"#{i}", font=('Segoe UI', 10, 'bold'),
                    bg='white', fg=pos_colors[i-1], width=3).pack(side=tk.LEFT)
            
            # Nome do produto
            tk.Label(row, text=product[:25], font=('Segoe UI', 10),
                    bg='white', fg='#1e293b', anchor='w', width=20).pack(side=tk.LEFT)
            
            # Quantidade
            tk.Label(row, text=f"{qty}x", font=('Segoe UI', 9),
                    bg='white', fg='#64748b').pack(side=tk.LEFT, padx=5)
            
            # Total
            tk.Label(row, text=f"R$ {total:,.2f}", font=('Segoe UI', 10, 'bold'),
                    bg='white', fg='#2563eb').pack(side=tk.RIGHT)
        
        return frame
    
    def create_payment_methods_widget(self, parent, payment_data):
        """Cria widget de formas de pagamento."""
        frame = tk.LabelFrame(parent, text="💳 Formas de Pagamento", 
                             font=('Segoe UI', 11, 'bold'), bg='white')
        frame.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)
        
        colors = ['#2563eb', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6']
        total = sum(v for _, v in payment_data) if payment_data else 1
        
        for i, (method, value) in enumerate(payment_data[:5]):
            row = tk.Frame(frame, bg='white')
            row.pack(fill=tk.X, padx=10, pady=3)
            
            # Nome
            tk.Label(row, text=method, font=('Segoe UI', 10),
                    bg='white', fg='#1e293b', width=15, anchor='w').pack(side=tk.LEFT)
            
            # Barra de progresso
            bar_frame = tk.Frame(row, bg='#e2e8f0', height=8, width=100)
            bar_frame.pack(side=tk.LEFT, padx=5)
            bar_frame.pack_propagate(False)
            
            percentage = (value / total) * 100 if total > 0 else 0
            bar = tk.Frame(bar_frame, bg=colors[i % len(colors)], 
                          width=int(percentage))
            bar.pack(side=tk.LEFT, fill=tk.Y)
            
            # Valor
            tk.Label(row, text=f"R$ {value:,.2f}", font=('Segoe UI', 9, 'bold'),
                    bg='white', fg=colors[i % len(colors)]).pack(side=tk.RIGHT)
        
        return frame





