# SISTEMA DE TEMAS DINÂMICOS v2.0
# ═══════════════════════════════════════════════════════════════════════════════════════

class ThemeManager:
    """
    Gerenciador de Temas Dinâmicos com Transições Suaves.
    
    Características:
    - Tema claro e escuro
    - Transição suave entre temas
    - Temas personalizados
    - Persistência de preferências
    - Cores acessíveis (WCAG 2.1)
    """
    
    THEMES = {
        'light': {
            'name': 'Claro',
            'background': '#f8fafc',
            'surface': '#ffffff',
            'primary': '#2563eb',
            'secondary': '#64748b',
            'text': '#1e293b',
            'text_secondary': '#64748b',
            'border': '#e2e8f0',
            'success': '#10b981',
            'warning': '#f59e0b',
            'danger': '#ef4444',
            'info': '#3b82f6',
            'card_bg': '#ffffff',
            'input_bg': '#ffffff',
            'hover': '#f1f5f9',
            'active': '#e2e8f0',
        },
        'dark': {
            'name': 'Escuro',
            'background': '#0f172a',
            'surface': '#1e293b',
            'primary': '#3b82f6',
            'secondary': '#94a3b8',
            'text': '#f1f5f9',
            'text_secondary': '#94a3b8',
            'border': '#334155',
            'success': '#22c55e',
            'warning': '#fbbf24',
            'danger': '#f87171',
            'info': '#60a5fa',
            'card_bg': '#1e293b',
            'input_bg': '#334155',
            'hover': '#334155',
            'active': '#475569',
        },
        'blue': {
            'name': 'Azul Profissional',
            'background': '#eff6ff',
            'surface': '#ffffff',
            'primary': '#1d4ed8',
            'secondary': '#6b7280',
            'text': '#1e3a8a',
            'text_secondary': '#3b82f6',
            'border': '#bfdbfe',
            'success': '#059669',
            'warning': '#d97706',
            'danger': '#dc2626',
            'info': '#2563eb',
            'card_bg': '#ffffff',
            'input_bg': '#f0f9ff',
            'hover': '#dbeafe',
            'active': '#bfdbfe',
        },
        'green': {
            'name': 'Verde Natural',
            'background': '#f0fdf4',
            'surface': '#ffffff',
            'primary': '#059669',
            'secondary': '#6b7280',
            'text': '#14532d',
            'text_secondary': '#22c55e',
            'border': '#bbf7d0',
            'success': '#16a34a',
            'warning': '#ca8a04',
            'danger': '#dc2626',
            'info': '#0891b2',
            'card_bg': '#ffffff',
            'input_bg': '#f0fdf4',
            'hover': '#dcfce7',
            'active': '#bbf7d0',
        },
    }
    
    def __init__(self, root, config_file=None):
        self.root = root
        self.config_file = config_file
        self._current_theme = 'light'
        self._widgets = []
        self._load_preference()
    
    def _load_preference(self):
        """Carrega preferência de tema salva."""
        if self.config_file:
            try:
                import json
                with open(self.config_file, 'r') as f:
                    config = json.load(f)
                    self._current_theme = config.get('theme', 'light')
            except:
                pass
    
    def _save_preference(self):
        """Salva preferência de tema."""
        if self.config_file:
            try:
                import json
                config = {'theme': self._current_theme}
                with open(self.config_file, 'w') as f:
                    json.dump(config, f)
            except:
                pass
    
    def register_widget(self, widget, color_map):
        """
        Registra um widget para atualização de tema.
        
        Args:
            widget: Widget Tkinter
            color_map: Dicionário mapeando propriedades para cores do tema
                      Ex: {'bg': 'background', 'fg': 'text'}
        """
        self._widgets.append((widget, color_map))
    
    def get_color(self, color_name):
        """Retorna uma cor do tema atual."""
        theme = self.THEMES.get(self._current_theme, self.THEMES['light'])
        return theme.get(color_name, '#000000')
    
    def get_theme(self):
        """Retorna o tema atual."""
        return self._current_theme
    
    def set_theme(self, theme_name, animate=True):
        """
        Define o tema.
        
        Args:
            theme_name: Nome do tema
            animate: Se deve animar a transição
        """
        if theme_name not in self.THEMES:
            return
        
        self._current_theme = theme_name
        self._apply_theme(animate)
        self._save_preference()
    
    def toggle_theme(self):
        """Alterna entre tema claro e escuro."""
        new_theme = 'dark' if self._current_theme == 'light' else 'light'
        self.set_theme(new_theme)
    
    def _apply_theme(self, animate=True):
        """Aplica o tema a todos os widgets registrados."""
        theme = self.THEMES[self._current_theme]
        
        for widget, color_map in self._widgets:
            try:
                for prop, color_name in color_map.items():
                    color = theme.get(color_name, '#000000')
                    widget.config(**{prop: color})
            except:
                pass
    
    def get_available_themes(self):
        """Retorna lista de temas disponíveis."""
        return [(name, data['name']) for name, data in self.THEMES.items()]


