# SISTEMA DE ATALHOS DE TECLADO INTELIGENTE
# ═══════════════════════════════════════════════════════════════════════════════════════

class SmartKeyboardManager:
    """
    Gerenciador de Atalhos de Teclado Inteligente.
    
    Características:
    - Atalhos contextuais
    - Detecção de conflitos
    - Personalização de atalhos
    - Ajuda integrada
    - Macros de teclado
    """
    
    # Atalhos padrão do sistema PDV
    DEFAULT_SHORTCUTS = {
        # Navegação Principal
        'F1': {'action': 'help', 'description': 'Ajuda do Sistema', 'context': 'global'},
        'F2': {'action': 'edit_item', 'description': 'Editar Item Selecionado', 'context': 'cart'},
        'F3': {'action': 'search', 'description': 'Buscar Produto', 'context': 'global'},
        'F4': {'action': 'new_sale', 'description': 'Nova Venda', 'context': 'global'},
        'F5': {'action': 'refresh', 'description': 'Atualizar Tela', 'context': 'global'},
        'F6': {'action': 'customers', 'description': 'Cadastro de Clientes', 'context': 'global'},
        'F7': {'action': 'products', 'description': 'Cadastro de Produtos', 'context': 'global'},
        'F8': {'action': 'reports', 'description': 'Relatórios', 'context': 'global'},
        'F9': {'action': 'settings', 'description': 'Configurações', 'context': 'global'},
        'F10': {'action': 'finalize', 'description': 'Finalizar Venda', 'context': 'sale'},
        'F11': {'action': 'fullscreen', 'description': 'Tela Cheia', 'context': 'global'},
        'F12': {'action': 'close_register', 'description': 'Fechar Caixa', 'context': 'global'},
        
        # Operações com Ctrl
        'Ctrl+N': {'action': 'new', 'description': 'Novo Registro', 'context': 'global'},
        'Ctrl+S': {'action': 'save', 'description': 'Salvar', 'context': 'global'},
        'Ctrl+P': {'action': 'print', 'description': 'Imprimir', 'context': 'global'},
        'Ctrl+F': {'action': 'find', 'description': 'Localizar', 'context': 'global'},
        'Ctrl+Z': {'action': 'undo', 'description': 'Desfazer', 'context': 'global'},
        'Ctrl+Y': {'action': 'redo', 'description': 'Refazer', 'context': 'global'},
        'Ctrl+Q': {'action': 'quit', 'description': 'Sair do Sistema', 'context': 'global'},
        'Ctrl+B': {'action': 'backup', 'description': 'Fazer Backup', 'context': 'global'},
        'Ctrl+E': {'action': 'export', 'description': 'Exportar', 'context': 'global'},
        'Ctrl+I': {'action': 'import', 'description': 'Importar', 'context': 'global'},
        'Ctrl+D': {'action': 'delete', 'description': 'Excluir', 'context': 'global'},
        'Ctrl+G': {'action': 'credit_client', 'description': 'Crédito Cliente', 'context': 'payment'},
        
        # Operações com Ctrl+Shift
        'Ctrl+Shift+D': {'action': 'return_sale', 'description': 'Devolução de Venda', 'context': 'global'},
        'Ctrl+Shift+C': {'action': 'close_day', 'description': 'Fechamento do Dia', 'context': 'global'},
        'Ctrl+Shift+R': {'action': 'reprint', 'description': 'Reimprimir Último Cupom', 'context': 'global'},
        
        # Operações de Pagamento
        'Alt+1': {'action': 'pay_cash', 'description': 'Pagamento em Dinheiro', 'context': 'payment'},
        'Alt+2': {'action': 'pay_debit', 'description': 'Pagamento em Débito', 'context': 'payment'},
        'Alt+3': {'action': 'pay_credit', 'description': 'Pagamento em Crédito', 'context': 'payment'},
        'Alt+4': {'action': 'pay_pix', 'description': 'Pagamento via PIX', 'context': 'payment'},
        
        # Operações do Carrinho
        'Delete': {'action': 'remove_item', 'description': 'Remover Item', 'context': 'cart'},
        '+': {'action': 'qty_up', 'description': 'Aumentar Quantidade', 'context': 'cart'},
        '-': {'action': 'qty_down', 'description': 'Diminuir Quantidade', 'context': 'cart'},
        '*': {'action': 'set_qty', 'description': 'Definir Quantidade', 'context': 'cart'},
        'Escape': {'action': 'cancel', 'description': 'Cancelar Operação', 'context': 'global'},
        'Enter': {'action': 'confirm', 'description': 'Confirmar', 'context': 'global'},
    }
    
    def __init__(self, root):
        self.root = root
        self._shortcuts = dict(self.DEFAULT_SHORTCUTS)
        self._callbacks = {}
        self._current_context = 'global'
        self._help_window = None
    
    def register(self, shortcut, callback, description=None, context='global'):
        """Registra um atalho de teclado."""
        self._shortcuts[shortcut] = {
            'action': shortcut,
            'description': description or shortcut,
            'context': context
        }
        self._callbacks[shortcut] = callback
        self._bind_shortcut(shortcut)
    
    def _bind_shortcut(self, shortcut):
        """Faz o bind do atalho."""
        try:
            key = self._convert_shortcut(shortcut)
            self.root.bind(f'<{key}>', lambda e: self._execute(shortcut))
        except:
            pass
    
    def _convert_shortcut(self, shortcut):
        """Converte formato de atalho para formato Tkinter."""
        parts = shortcut.replace('+', '-').split('-')
        result = []
        
        for part in parts:
            if part.lower() == 'ctrl':
                result.append('Control')
            elif part.lower() == 'alt':
                result.append('Alt')
            elif part.lower() == 'shift':
                result.append('Shift')
            else:
                result.append(part)
        
        return '-'.join(result)
    
    def _execute(self, shortcut):
        """Executa o callback do atalho."""
        info = self._shortcuts.get(shortcut)
        if not info:
            return
        
        # Verifica contexto
        if info['context'] != 'global' and info['context'] != self._current_context:
            return
        
        callback = self._callbacks.get(shortcut)
        if callback:
            try:
                callback()
            except Exception as e:
                try:
                    AUDITORIA.erro(f"Erro no sistema: {e}")
                except Exception:
                    pass
                print(f"Erro ao executar atalho {shortcut}: {e}")
    
    def set_context(self, context):
        """Define o contexto atual."""
        self._current_context = context
    
    def show_help(self):
        """Mostra janela de ajuda com atalhos."""
        if self._help_window and self._help_window.winfo_exists():
            self._help_window.lift()
            return
        
        self._help_window = tk.Toplevel(self.root)
        self._help_window.title("⌨️ Atalhos de Teclado")
        self._help_window.state('zoomed')
        self._help_window.transient(self.root)
        
        # Frame principal com scroll
        main_frame = tk.Frame(self._help_window, bg='white')
        main_frame.pack(fill=tk.BOTH, expand=True)
        
        # Título
        title = tk.Label(main_frame, text="⌨️ Atalhos de Teclado do Sistema",
                        font=('Segoe UI', 16, 'bold'), bg='white', fg='#1e293b')
        title.pack(pady=20)
        
        # Canvas com scroll
        canvas = tk.Canvas(main_frame, bg='white', highlightthickness=0)
        scrollbar = tk.Scrollbar(main_frame, orient='vertical', command=canvas.yview)
        scroll_frame = tk.Frame(canvas, bg='white')
        
        scroll_frame.bind('<Configure>', 
                         lambda e: canvas.configure(scrollregion=canvas.bbox('all')))
        
        canvas.create_window((0, 0), window=scroll_frame, anchor='nw', width=560)
        canvas.configure(yscrollcommand=scrollbar.set)
        
        # Agrupa por contexto
        contexts = {}
        for shortcut, info in self._shortcuts.items():
            ctx = info['context']
            if ctx not in contexts:
                contexts[ctx] = []
            contexts[ctx].append((shortcut, info['description']))
        
        context_names = {
            'global': '🌐 Atalhos Globais',
            'cart': '🛒 Carrinho de Compras',
            'payment': '💳 Pagamento',
            'sale': '💰 Venda',
        }
        
        for ctx, shortcuts in contexts.items():
            # Cabeçalho do contexto
            header = tk.Label(scroll_frame, text=context_names.get(ctx, ctx),
                            font=('Segoe UI', 12, 'bold'), bg='#f1f5f9', fg='#1e293b',
                            anchor='w', padx=10, pady=5)
            header.pack(fill=tk.X, pady=(10, 5))
            
            for shortcut, desc in sorted(shortcuts):
                row = tk.Frame(scroll_frame, bg='white')
                row.pack(fill=tk.X, padx=10, pady=2)
                
                # Atalho
                shortcut_label = tk.Label(row, text=shortcut, font=('Consolas', 10, 'bold'),
                                         bg='#e2e8f0', fg='#1e293b', width=15, anchor='w',
                                         padx=5, pady=2)
                shortcut_label.pack(side=tk.LEFT)
                
                # Descrição
                desc_label = tk.Label(row, text=desc, font=('Segoe UI', 10),
                                     bg='white', fg='#64748b', anchor='w')
                desc_label.pack(side=tk.LEFT, padx=10)
        
        canvas.pack(side=tk.LEFT, fill=tk.BOTH, expand=True, padx=10)
        scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
        
        # Botão fechar
        close_btn = tk.Button(main_frame, text="Fechar", font=('Segoe UI', 10),
                             bg='#2563eb', fg='white', relief=tk.FLAT,
                             padx=20, pady=8, cursor='hand2',
                             command=self._help_window.destroy)
        close_btn.pack(pady=20)


# ═══════════════════════════════════════════════════════════════════════════════════════
# SISTEMA DE RELATÓRIOS PDF AVANÇADO
# ═══════════════════════════════════════════════════════════════════════════════════════

class AdvancedPDFReport:
    """
    Gerador de Relatórios PDF Profissionais.
    
    Características:
    - Layout profissional
    - Gráficos integrados
    - Tabelas formatadas
    - Cabeçalho e rodapé
    - Múltiplas páginas
    - Marca d'água
    """
    
    def __init__(self, title, company_data=None):
        self.title = title
        self.company_data = company_data or {}
        self._content = []
        self._page_number = 1
    
    def add_header(self, text, level=1):
        """Adiciona cabeçalho."""
        self._content.append({
            'type': 'header',
            'text': text,
            'level': level
        })
    
    def add_paragraph(self, text):
        """Adiciona parágrafo."""
        self._content.append({
            'type': 'paragraph',
            'text': text
        })
    
    def add_table(self, headers, data, widths=None):
        """Adiciona tabela."""
        self._content.append({
            'type': 'table',
            'headers': headers,
            'data': data,
            'widths': widths
        })
    
    def add_chart(self, chart_type, data, title=''):
        """Adiciona gráfico."""
        self._content.append({
            'type': 'chart',
            'chart_type': chart_type,
            'data': data,
            'title': title
        })
    
    def add_summary_box(self, items):
        """Adiciona caixa de resumo."""
        self._content.append({
            'type': 'summary',
            'items': items
        })
    
    def add_page_break(self):
        """Adiciona quebra de página."""
        self._content.append({'type': 'page_break'})
    
    def generate(self, output_path):
        """
        Gera o PDF.
        
        Args:
            output_path: Caminho do arquivo de saída
        """
        try:
            from reportlab.lib.pagesizes import A4
            from reportlab.lib import colors
            from reportlab.lib.styles import getSampleStyleSheet, ParagraphStyle
            from reportlab.lib.units import cm, mm
            from reportlab.platypus import SimpleDocTemplate, Paragraph, Spacer, Table, TableStyle, PageBreak
            from reportlab.lib.enums import TA_CENTER, TA_LEFT, TA_RIGHT
            
            doc = SimpleDocTemplate(
                output_path,
                pagesize=A4,
                rightMargin=2*cm,
                leftMargin=2*cm,
                topMargin=2*cm,
                bottomMargin=2*cm
            )
            
            styles = getSampleStyleSheet()
            
            # Estilos personalizados
            styles.add(ParagraphStyle(
                name='CustomTitle',
                parent=styles['Heading1'],
                fontSize=18,
                spaceAfter=30,
                textColor=colors.HexColor('#1e293b'),
                alignment=TA_CENTER
            ))
            
            styles.add(ParagraphStyle(
                name='CustomHeading',
                parent=styles['Heading2'],
                fontSize=14,
                spaceAfter=12,
                textColor=colors.HexColor('#2563eb')
            ))
            
            story = []
            
            # Título do relatório
            story.append(Paragraph(self.title, styles['CustomTitle']))
            story.append(Spacer(1, 20))
            
            # Informações da empresa
            if self.company_data:
                company_info = f"""
                <b>{self.company_data.get('nome', 'Empresa')}</b><br/>
                {self.company_data.get('endereco', '')}<br/>
                CNPJ: {self.company_data.get('cnpj', '')}<br/>
                Tel: {self.company_data.get('telefone', '')}
                """
                story.append(Paragraph(company_info, styles['Normal']))
                story.append(Spacer(1, 20))
            
            # Processa conteúdo
            for item in self._content:
                if item['type'] == 'header':
                    style = styles['CustomHeading'] if item['level'] == 1 else styles['Heading3']
                    story.append(Paragraph(item['text'], style))
                    story.append(Spacer(1, 10))
                
                elif item['type'] == 'paragraph':
                    story.append(Paragraph(item['text'], styles['Normal']))
                    story.append(Spacer(1, 10))
                
                elif item['type'] == 'table':
                    table_data = [item['headers']] + item['data']
                    
                    t = Table(table_data, colWidths=item.get('widths'))
                    t.setStyle(TableStyle([
                        ('BACKGROUND', (0, 0), (-1, 0), colors.HexColor('#2563eb')),
                        ('TEXTCOLOR', (0, 0), (-1, 0), colors.whitesmoke),
                        ('ALIGN', (0, 0), (-1, -1), 'CENTER'),
                        ('FONTNAME', (0, 0), (-1, 0), 'Helvetica-Bold'),
                        ('FONTSIZE', (0, 0), (-1, 0), 10),
                        ('BOTTOMPADDING', (0, 0), (-1, 0), 12),
                        ('BACKGROUND', (0, 1), (-1, -1), colors.HexColor('#f8fafc')),
                        ('TEXTCOLOR', (0, 1), (-1, -1), colors.HexColor('#1e293b')),
                        ('FONTNAME', (0, 1), (-1, -1), 'Helvetica'),
                        ('FONTSIZE', (0, 1), (-1, -1), 9),
                        ('ALIGN', (0, 0), (-1, -1), 'CENTER'),
                        ('GRID', (0, 0), (-1, -1), 0.5, colors.HexColor('#e2e8f0')),
                        ('ROWBACKGROUNDS', (0, 1), (-1, -1), [colors.white, colors.HexColor('#f1f5f9')]),
                    ]))
                    story.append(t)
                    story.append(Spacer(1, 20))
                
                elif item['type'] == 'summary':
                    summary_data = [[k, v] for k, v in item['items'].items()]
                    t = Table(summary_data, colWidths=[200, 150])
                    t.setStyle(TableStyle([
                        ('BACKGROUND', (0, 0), (-1, -1), colors.HexColor('#eff6ff')),
                        ('TEXTCOLOR', (0, 0), (-1, -1), colors.HexColor('#1e293b')),
                        ('FONTNAME', (0, 0), (0, -1), 'Helvetica-Bold'),
                        ('FONTNAME', (1, 0), (1, -1), 'Helvetica'),
                        ('FONTSIZE', (0, 0), (-1, -1), 10),
                        ('PADDING', (0, 0), (-1, -1), 10),
                        ('GRID', (0, 0), (-1, -1), 0.5, colors.HexColor('#bfdbfe')),
                    ]))
                    story.append(t)
                    story.append(Spacer(1, 20))
                
                elif item['type'] == 'page_break':
                    story.append(PageBreak())
            
            # Data de geração
            from datetime import datetime
            story.append(Spacer(1, 30))
            story.append(Paragraph(
                f"Relatório gerado em: {datetime.now().strftime('%d/%m/%Y %H:%M:%S')}",
                styles['Normal']
            ))
            
            doc.build(story)
            return True
            
        except ImportError:
            print("ReportLab não instalado. Instale com: pip install reportlab")
            return False
        except Exception as e:
            try:
                AUDITORIA.erro(f"Erro no sistema: {e}")
            except Exception:
                pass
            print(f"Erro ao gerar PDF: {e}")
            return False


# ═══════════════════════════════════════════════════════════════════════════════════════
# FUNÇÃO AUXILIAR PARA GERAÇÃO DE PDF DE RECIBOS/CUPONS
# ═══════════════════════════════════════════════════════════════════════════════════════

def gerar_pdf_recibo(texto: str, titulo: str = "Documento", nome_arquivo: str = None, parent_window=None) -> str:
    """
    Gera um PDF a partir de texto formatado (recibo, cupom, comprovante, etc.).
    
    Args:
        texto: Texto formatado do documento
        titulo: Título do documento para o cabeçalho do PDF
        nome_arquivo: Nome sugerido para o arquivo (sem extensão)
        parent_window: Janela pai para o diálogo de salvamento
    
    Returns:
        Caminho do arquivo PDF salvo ou string vazia se cancelado/erro
    """
    try:
        from tkinter import filedialog, messagebox
        import os
        import datetime
        
        # Define nome padrão se não especificado
        if not nome_arquivo:
            timestamp = datetime.datetime.now().strftime('%Y%m%d_%H%M%S')
            nome_arquivo = f"documento_{timestamp}"
        
        # Solicita local para salvar
        arquivo = filedialog.asksaveasfilename(
            parent=parent_window,
            title=f"Salvar {titulo} como PDF",
            defaultextension=".pdf",
            filetypes=[("PDF files", "*.pdf"), ("All files", "*.*")],
            initialfile=f"{nome_arquivo}.pdf"
        )
        
        if not arquivo:
            return ""
        
        # Tenta usar FPDF para criar o PDF
        try:
            from fpdf import FPDF
            
            pdf = FPDF()
            pdf.add_page()
            pdf.set_auto_page_break(auto=True, margin=15)
            
            # Tenta usar fonte que suporta caracteres especiais
            try:
                # Tenta fontes comuns em diferentes sistemas
                fontes_possiveis = [
                    '/usr/share/fonts/truetype/dejavu/DejaVuSansMono.ttf',
                    '/usr/share/fonts/truetype/dejavu/DejaVuSans.ttf',
                    'C:/Windows/Fonts/consola.ttf',
                    'C:/Windows/Fonts/cour.ttf',
                    '/System/Library/Fonts/Menlo.ttc',
                ]
                fonte_encontrada = False
                for fonte in fontes_possiveis:
                    if os.path.exists(fonte):
                        pdf.add_font('CustomFont', '', fonte, uni=True)
                        pdf.set_font('CustomFont', '', 9)
                        fonte_encontrada = True
                        break
                
                if not fonte_encontrada:
                    pdf.set_font('Courier', '', 9)
            except Exception:
                pdf.set_font('Courier', '', 9)
            
            # Adiciona título
            pdf.set_font_size(12)
            pdf.cell(0, 10, titulo, ln=True, align='C')
            pdf.set_font_size(9)
            pdf.ln(5)
            
            # Adiciona conteúdo linha por linha
            for linha in texto.split('\n'):
                # Tenta manter caracteres especiais, senão substitui
                try:
                    pdf.cell(0, 4, linha, ln=True)
                except Exception:
                    linha_limpa = linha.encode('latin-1', 'replace').decode('latin-1')
                    pdf.cell(0, 4, linha_limpa, ln=True)
            
            pdf.output(arquivo)
            
            messagebox.showinfo("Sucesso", f"PDF salvo com sucesso!\n\n{arquivo}", parent=parent_window)
            
            # Pergunta se deseja abrir o arquivo
            if messagebox.askyesno("Abrir PDF", "Deseja abrir o arquivo PDF?", parent=parent_window):
                import webbrowser
                import sys
                if sys.platform == 'win32':
                    os.startfile(arquivo)
                elif sys.platform == 'darwin':
                    subprocess.run(['open', arquivo])
                else:
                    webbrowser.open(f'file://{arquivo}')
            
            return arquivo
            
        except ImportError:
            # Se FPDF não estiver disponível, tenta com reportlab
            try:
                from reportlab.lib.pagesizes import A4
                from reportlab.lib.units import mm
                from reportlab.pdfgen import canvas as pdf_canvas
                
                c = pdf_canvas.Canvas(arquivo, pagesize=A4)
                width, height = A4
                
                # Configurações
                c.setFont("Courier", 9)
                y = height - 30 * mm
                
                # Título
                c.setFont("Courier-Bold", 12)
                c.drawCentredString(width / 2, y, titulo)
                y -= 15 * mm
                c.setFont("Courier", 9)
                
                # Conteúdo
                for linha in texto.split('\n'):
                    if y < 30 * mm:
                        c.showPage()
                        c.setFont("Courier", 9)
                        y = height - 30 * mm
                    
                    try:
                        c.drawString(20 * mm, y, linha)
                    except Exception:
                        linha_limpa = linha.encode('latin-1', 'replace').decode('latin-1')
                        c.drawString(20 * mm, y, linha_limpa)
                    y -= 4 * mm
                
                c.save()
                
                messagebox.showinfo("Sucesso", f"PDF salvo com sucesso!\n\n{arquivo}", parent=parent_window)
                
                if messagebox.askyesno("Abrir PDF", "Deseja abrir o arquivo PDF?", parent=parent_window):
                    import webbrowser
                    import sys
                    if sys.platform == 'win32':
                        os.startfile(arquivo)
                    elif sys.platform == 'darwin':
                        subprocess.run(['open', arquivo])
                    else:
                        webbrowser.open(f'file://{arquivo}')
                
                return arquivo
                
            except ImportError:
                messagebox.showerror("Erro", "Nenhuma biblioteca PDF disponível.\n\nInstale com: pip install fpdf2\nou: pip install reportlab", parent=parent_window)
                return ""
                
    except Exception as e:
        from tkinter import messagebox
        messagebox.showerror("Erro", f"Erro ao gerar PDF:\n{e}", parent=parent_window)
        return ""


def gerar_pdf_automatico(texto: str, diretorio: str = None, prefixo: str = "documento") -> str:
    """
    Gera um PDF automaticamente sem diálogo de salvamento.
    Útil para geração automática junto com impressão.
    
    Args:
        texto: Texto formatado do documento
        diretorio: Diretório onde salvar (usa pasta padrão se None)
        prefixo: Prefixo do nome do arquivo
    
    Returns:
        Caminho do arquivo PDF salvo ou string vazia se erro
    """
    try:
        import os
        import datetime
        
        # Define diretório padrão
        if not diretorio:
            # Tenta usar pasta Documentos ou pasta do usuário
            if os.name == 'nt':  # Windows
                diretorio = os.path.join(os.path.expanduser('~'), 'Documents', 'PDV_PDFs')
            else:
                diretorio = os.path.join(os.path.expanduser('~'), 'PDV_PDFs')
        
        # Cria diretório se não existir
        os.makedirs(diretorio, exist_ok=True)
        
        # Gera nome do arquivo
        timestamp = datetime.datetime.now().strftime('%Y%m%d_%H%M%S')
        arquivo = os.path.join(diretorio, f"{prefixo}_{timestamp}.pdf")
        
        # Tenta usar FPDF
        try:
            from fpdf import FPDF
            
            pdf = FPDF()
            pdf.add_page()
            pdf.set_auto_page_break(auto=True, margin=15)
            
            # Tenta usar fonte monoespaçada
            try:
                fontes_possiveis = [
                    '/usr/share/fonts/truetype/dejavu/DejaVuSansMono.ttf',
                    'C:/Windows/Fonts/consola.ttf',
                ]
                for fonte in fontes_possiveis:
                    if os.path.exists(fonte):
                        pdf.add_font('CustomFont', '', fonte, uni=True)
                        pdf.set_font('CustomFont', '', 9)
                        break
                else:
                    pdf.set_font('Courier', '', 9)
            except Exception:
                pdf.set_font('Courier', '', 9)
            
            for linha in texto.split('\n'):
                try:
                    pdf.cell(0, 4, linha, ln=True)
                except Exception:
                    linha_limpa = linha.encode('latin-1', 'replace').decode('latin-1')
                    pdf.cell(0, 4, linha_limpa, ln=True)
            
            pdf.output(arquivo)
            return arquivo
            
        except ImportError:
            # Fallback para reportlab
            try:
                from reportlab.lib.pagesizes import A4
                from reportlab.lib.units import mm
                from reportlab.pdfgen import canvas as pdf_canvas
                
                c = pdf_canvas.Canvas(arquivo, pagesize=A4)
                width, height = A4
                c.setFont("Courier", 9)
                y = height - 20 * mm
                
                for linha in texto.split('\n'):
                    if y < 20 * mm:
                        c.showPage()
                        c.setFont("Courier", 9)
                        y = height - 20 * mm
                    try:
                        c.drawString(15 * mm, y, linha)
                    except Exception:
                        linha_limpa = linha.encode('latin-1', 'replace').decode('latin-1')
                        c.drawString(15 * mm, y, linha_limpa)
                    y -= 4 * mm
                
                c.save()
                return arquivo
            except ImportError:
                return ""
                
    except Exception as e:
        try:
            AUDITORIA.erro(f"Erro no sistema: {e}")
        except Exception:
            pass
        print(f"Erro ao gerar PDF automático: {e}")
        return ""


# ═══════════════════════════════════════════════════════════════════════════════════════
# SISTEMA DE CACHE INTELIGENTE LRU
# ═══════════════════════════════════════════════════════════════════════════════════════

class SmartCache:
    """
    Sistema de Cache Inteligente com LRU e TTL.
    
    Características:
    - Cache LRU (Least Recently Used)
    - TTL (Time To Live) configurável
    - Estatísticas de uso
    - Invalidação seletiva
    - Persistência opcional
    """
    
    def __init__(self, max_size=1000, default_ttl=300):
        self._cache = {}
        self._access_order = []
        self._max_size = max_size
        self._default_ttl = default_ttl
        self._stats = {'hits': 0, 'misses': 0}
    
    def get(self, key, default=None):
        """
        Obtém valor do cache.
        
        Args:
            key: Chave do cache
            default: Valor padrão se não encontrado
            
        Returns:
            Valor cacheado ou default
        """
        if key not in self._cache:
            self._stats['misses'] += 1
            return default
        
        entry = self._cache[key]
        
        # Verifica TTL
        if entry['expires'] and time.time() > entry['expires']:
            del self._cache[key]
            self._access_order.remove(key)
            self._stats['misses'] += 1
            return default
        
        # Atualiza ordem de acesso
        self._access_order.remove(key)
        self._access_order.append(key)
        
        self._stats['hits'] += 1
        return entry['value']
    
    def set(self, key, value, ttl=None):
        """
        Define valor no cache.
        
        Args:
            key: Chave do cache
            value: Valor a ser cacheado
            ttl: Tempo de vida em segundos (None para usar default)
        """
        # Remove se já existe
        if key in self._cache:
            self._access_order.remove(key)
        
        # Verifica limite de tamanho
        while len(self._cache) >= self._max_size:
            oldest_key = self._access_order.pop(0)
            del self._cache[oldest_key]
        
        # Calcula expiração
        ttl = ttl if ttl is not None else self._default_ttl
        expires = time.time() + ttl if ttl > 0 else None
        
        self._cache[key] = {
            'value': value,
            'expires': expires,
            'created': time.time()
        }
        self._access_order.append(key)
    
    def delete(self, key):
        """Remove item do cache."""
        if key in self._cache:
            del self._cache[key]
            self._access_order.remove(key)
            return True
        return False
    
    def clear(self):
        """Limpa todo o cache."""
        self._cache.clear()
        self._access_order.clear()
    
    def invalidate_pattern(self, pattern):
        """
        Invalida entradas que correspondem ao padrão.
        
        Args:
            pattern: Padrão regex para match
        """
        import re
        keys_to_delete = [k for k in self._cache.keys() if re.match(pattern, k)]
        for key in keys_to_delete:
            self.delete(key)
        return len(keys_to_delete)
    
    def get_stats(self):
        """Retorna estatísticas do cache."""
        total = self._stats['hits'] + self._stats['misses']
        hit_rate = (self._stats['hits'] / total * 100) if total > 0 else 0
        
        return {
            'size': len(self._cache),
            'max_size': self._max_size,
            'hits': self._stats['hits'],
            'misses': self._stats['misses'],
            'hit_rate': f"{hit_rate:.1f}%"
        }
    
    def cleanup_expired(self):
        """Remove entradas expiradas."""
        current_time = time.time()
        expired_keys = []
        
        for key, entry in self._cache.items():
            if entry['expires'] and current_time > entry['expires']:
                expired_keys.append(key)
        
        for key in expired_keys:
            self.delete(key)
        
        return len(expired_keys)





# ═══════════════════════════════════════════════════════════════════════════════════════
# SISTEMA DE PREVISÃO DE VENDAS COM IA SIMPLES
# ═══════════════════════════════════════════════════════════════════════════════════════

class SalesPredictionEngine:
    """
    Motor de Previsão de Vendas com Análise Estatística.
    
    Características:
    - Previsão baseada em histórico
    - Análise de sazonalidade
    - Detecção de tendências
    - Alertas de anomalias
    - Sugestões de estoque
    """
    
    def __init__(self, sales_data=None):
        self._sales_data = sales_data or []
        self._daily_averages = {}
        self._weekly_patterns = {}
        self._monthly_patterns = {}
    
    def load_sales_data(self, sales_data):
        """Carrega dados de vendas para análise."""
        self._sales_data = sales_data
        self._analyze_patterns()
    
    def _analyze_patterns(self):
        """Analisa padrões nos dados de vendas."""
        if not self._sales_data:
            return
        
        # Agrupa por dia da semana
        weekday_totals = {i: [] for i in range(7)}
        
        # Agrupa por hora
        hourly_totals = {i: [] for i in range(24)}
        
        # Agrupa por mês
        monthly_totals = {i: [] for i in range(1, 13)}
        
        for sale in self._sales_data:
            try:
                timestamp = sale.get('timestamp', '')
                if isinstance(timestamp, str):
                    dt = datetime.datetime.fromisoformat(timestamp.replace('Z', '+00:00'))
                else:
                    dt = timestamp
                
                total = float(sale.get('total', 0))
                
                weekday_totals[dt.weekday()].append(total)
                hourly_totals[dt.hour].append(total)
                monthly_totals[dt.month].append(total)
            except:
                continue
        
        # Calcula médias
        self._weekly_patterns = {
            day: sum(totals) / len(totals) if totals else 0
            for day, totals in weekday_totals.items()
        }
        
        self._hourly_patterns = {
            hour: sum(totals) / len(totals) if totals else 0
            for hour, totals in hourly_totals.items()
        }
        
        self._monthly_patterns = {
            month: sum(totals) / len(totals) if totals else 0
            for month, totals in monthly_totals.items()
        }
    
    def predict_daily_sales(self, target_date=None):
        """
        Prevê vendas para um dia específico.
        
        Args:
            target_date: Data alvo (datetime.date)
            
        Returns:
            Previsão de vendas
        """
        if target_date is None:
            target_date = datetime.date.today()
        
        weekday = target_date.weekday()
        month = target_date.month
        
        # Combina padrões
        weekday_factor = self._weekly_patterns.get(weekday, 0)
        monthly_factor = self._monthly_patterns.get(month, 0)
        
        if weekday_factor == 0 and monthly_factor == 0:
            return 0
        
        # Média ponderada
        prediction = (weekday_factor * 0.6 + monthly_factor * 0.4)
        
        return round(prediction, 2)
    
    def predict_weekly_sales(self, start_date=None):
        """Prevê vendas para a semana."""
        if start_date is None:
            start_date = datetime.date.today()
        
        predictions = []
        for i in range(7):
            day = start_date + datetime.timedelta(days=i)
            predictions.append({
                'date': day.isoformat(),
                'weekday': day.strftime('%A'),
                'predicted': self.predict_daily_sales(day)
            })
        
        return predictions
    
    def get_best_selling_hours(self, top_n=5):
        """Retorna os horários com mais vendas."""
        sorted_hours = sorted(
            self._hourly_patterns.items(),
            key=lambda x: x[1],
            reverse=True
        )
        return sorted_hours[:top_n]
    
    def get_best_selling_days(self):
        """Retorna os dias da semana com mais vendas."""
        day_names = ['Segunda', 'Terça', 'Quarta', 'Quinta', 'Sexta', 'Sábado', 'Domingo']
        sorted_days = sorted(
            self._weekly_patterns.items(),
            key=lambda x: x[1],
            reverse=True
        )
        return [(day_names[day], total) for day, total in sorted_days]
    
    def detect_anomalies(self, threshold=2.0):
        """
        Detecta anomalias nas vendas.
        
        Args:
            threshold: Número de desvios padrão para considerar anomalia
            
        Returns:
            Lista de anomalias detectadas
        """
        if not self._sales_data:
            return []
        
        totals = [float(s.get('total', 0)) for s in self._sales_data]
        
        if len(totals) < 2:
            return []
        
        mean = sum(totals) / len(totals)
        variance = sum((x - mean) ** 2 for x in totals) / len(totals)
        std_dev = variance ** 0.5
        
        anomalies = []
        for sale in self._sales_data:
            total = float(sale.get('total', 0))
            z_score = (total - mean) / std_dev if std_dev > 0 else 0
            
            if abs(z_score) > threshold:
                anomalies.append({
                    'sale': sale,
                    'z_score': round(z_score, 2),
                    'type': 'high' if z_score > 0 else 'low'
                })
        
        return anomalies
    
    def suggest_stock_levels(self, products_data, days_ahead=30):
        """
        Sugere níveis de estoque baseado em previsões.
        
        Args:
            products_data: Dados de produtos com vendas
            days_ahead: Dias para considerar
            
        Returns:
            Sugestões de estoque por produto
        """
        suggestions = []
        
        for product_id, data in products_data.items():
            avg_daily_sales = data.get('avg_daily_sales', 0)
            current_stock = data.get('stock', 0)
            
            needed = avg_daily_sales * days_ahead
            suggested = max(0, needed - current_stock)
            
            days_until_stockout = current_stock / avg_daily_sales if avg_daily_sales > 0 else float('inf')
            
            suggestions.append({
                'product_id': product_id,
                'product_name': data.get('name', ''),
                'current_stock': current_stock,
                'suggested_order': round(suggested, 0),
                'days_until_stockout': round(days_until_stockout, 1),
                'urgency': 'high' if days_until_stockout < 7 else 'medium' if days_until_stockout < 14 else 'low'
            })
        
        # Ordena por urgência
        urgency_order = {'high': 0, 'medium': 1, 'low': 2}
        suggestions.sort(key=lambda x: urgency_order.get(x['urgency'], 3))
        
        return suggestions


# ═══════════════════════════════════════════════════════════════════════════════════════
# SISTEMA DE FIDELIDADE E CASHBACK AVANÇADO
# ═══════════════════════════════════════════════════════════════════════════════════════

class LoyaltySystem:
    """
    Sistema de Fidelidade e Cashback Avançado.
    
    Características:
    - Acúmulo de pontos por compra
    - Níveis de fidelidade (Bronze, Prata, Ouro, Diamante)
    - Cashback progressivo
    - Promoções especiais
    - Aniversário com bônus
    - Indicação de amigos
    """
    
    LEVELS = {
        'bronze': {'min_points': 0, 'cashback': 0.01, 'multiplier': 1.0, 'color': '#cd7f32'},
        'silver': {'min_points': 1000, 'cashback': 0.02, 'multiplier': 1.5, 'color': '#c0c0c0'},
        'gold': {'min_points': 5000, 'cashback': 0.03, 'multiplier': 2.0, 'color': '#ffd700'},
        'diamond': {'min_points': 15000, 'cashback': 0.05, 'multiplier': 3.0, 'color': '#b9f2ff'},
    }
    
    def __init__(self, db_connection=None):
        self._db = db_connection
        self._promotions = []
    
    def get_customer_level(self, total_points):
        """Determina o nível do cliente baseado nos pontos."""
        level = 'bronze'
        for level_name, level_data in self.LEVELS.items():
            if total_points >= level_data['min_points']:
                level = level_name
        return level
    
    def calculate_points(self, purchase_total, customer_level='bronze'):
        """
        Calcula pontos ganhos em uma compra.
        
        Args:
            purchase_total: Valor total da compra
            customer_level: Nível atual do cliente
            
        Returns:
            Pontos ganhos
        """
        base_points = int(purchase_total)  # 1 ponto por real
        multiplier = self.LEVELS.get(customer_level, {}).get('multiplier', 1.0)
        return int(base_points * multiplier)
    
    def calculate_cashback(self, purchase_total, customer_level='bronze'):
        """
        Calcula cashback de uma compra.
        
        Args:
            purchase_total: Valor total da compra
            customer_level: Nível atual do cliente
            
        Returns:
            Valor do cashback
        """
        rate = self.LEVELS.get(customer_level, {}).get('cashback', 0.01)
        return round(purchase_total * rate, 2)
    
    def check_birthday_bonus(self, customer_birthday):
        """Verifica se o cliente faz aniversário hoje."""
        if not customer_birthday:
            return False, 0
        
        today = datetime.date.today()
        
        try:
            if isinstance(customer_birthday, str):
                # Tenta diferentes formatos
                for fmt in ['%Y-%m-%d', '%d/%m/%Y', '%d-%m-%Y']:
                    try:
                        birthday = datetime.datetime.strptime(customer_birthday, fmt).date()
                        break
                    except:
                        continue
                else:
                    return False, 0
            else:
                birthday = customer_birthday
            
            if birthday.month == today.month and birthday.day == today.day:
                return True, 100  # 100 pontos de bônus
            
            return False, 0
        except:
            return False, 0
    
    def get_level_progress(self, current_points, current_level):
        """Retorna progresso para o próximo nível."""
        levels_order = ['bronze', 'silver', 'gold', 'diamond']
        current_index = levels_order.index(current_level)
        
        if current_index >= len(levels_order) - 1:
            return {'next_level': None, 'points_needed': 0, 'progress': 100}
        
        next_level = levels_order[current_index + 1]
        next_min = self.LEVELS[next_level]['min_points']
        current_min = self.LEVELS[current_level]['min_points']
        
        points_needed = next_min - current_points
        progress = ((current_points - current_min) / (next_min - current_min)) * 100
        
        return {
            'next_level': next_level,
            'points_needed': max(0, points_needed),
            'progress': min(100, max(0, progress))
        }
    
    def add_promotion(self, promotion):
        """Adiciona uma promoção."""
        self._promotions.append(promotion)
    
    def get_active_promotions(self):
        """Retorna promoções ativas."""
        today = datetime.date.today()
        return [
            p for p in self._promotions
            if p.get('start_date', today) <= today <= p.get('end_date', today)
        ]
    
    def apply_promotion(self, purchase_total, customer_data, promotion):
        """Aplica uma promoção à compra."""
        promo_type = promotion.get('type')
        
        if promo_type == 'discount_percent':
            discount = purchase_total * (promotion.get('value', 0) / 100)
            return {'discount': discount, 'type': 'percent'}
        
        elif promo_type == 'discount_fixed':
            discount = min(promotion.get('value', 0), purchase_total)
            return {'discount': discount, 'type': 'fixed'}
        
        elif promo_type == 'bonus_points':
            bonus = promotion.get('value', 0)
            return {'bonus_points': bonus, 'type': 'points'}
        
        elif promo_type == 'double_cashback':
            return {'cashback_multiplier': 2, 'type': 'cashback'}
        
        return {}


