# SISTEMA DE NOTIFICAÇÕES PUSH INTERNAS
# ═══════════════════════════════════════════════════════════════════════════════════════

class NotificationCenter:
    """
    Central de Notificações do Sistema.
    
    Características:
    - Notificações em tempo real
    - Categorização por tipo
    - Histórico de notificações
    - Ações rápidas
    - Prioridades
    """
    
    TYPES = {
        'info': {'icon': 'ℹ️', 'color': '#3b82f6', 'sound': False},
        'success': {'icon': '✓', 'color': '#10b981', 'sound': False},
        'warning': {'icon': '⚠️', 'color': '#f59e0b', 'sound': True},
        'error': {'icon': '✗', 'color': '#ef4444', 'sound': True},
        'sale': {'icon': '💰', 'color': '#22c55e', 'sound': False},
        'stock': {'icon': '📦', 'color': '#f59e0b', 'sound': True},
        'customer': {'icon': '👤', 'color': '#3b82f6', 'sound': False},
        'system': {'icon': '⚙️', 'color': '#6b7280', 'sound': False},
    }
    
    def __init__(self, max_history=100):
        self._notifications = []
        self._unread_count = 0
        self._max_history = max_history
        self._callbacks = []
    
    def notify(self, title, message, notification_type='info', priority='normal', 
               action=None, action_text=None, persistent=False):
        """
        Cria uma nova notificação.
        
        Args:
            title: Título da notificação
            message: Mensagem
            notification_type: Tipo (info, success, warning, error, etc.)
            priority: Prioridade (low, normal, high, urgent)
            action: Callback para ação
            action_text: Texto do botão de ação
            persistent: Se deve persistir até ser lida
        """
        notification = {
            'id': len(self._notifications) + 1,
            'title': title,
            'message': message,
            'type': notification_type,
            'priority': priority,
            'action': action,
            'action_text': action_text,
            'persistent': persistent,
            'read': False,
            'timestamp': datetime.datetime.now().isoformat(),
        }
        
        self._notifications.insert(0, notification)
        self._unread_count += 1
        
        # Limita histórico
        if len(self._notifications) > self._max_history:
            self._notifications = self._notifications[:self._max_history]
        
        # Notifica callbacks
        for callback in self._callbacks:
            try:
                callback(notification)
            except:
                pass
        
        return notification
    
    def mark_as_read(self, notification_id):
        """Marca notificação como lida."""
        for notif in self._notifications:
            if notif['id'] == notification_id and not notif['read']:
                notif['read'] = True
                self._unread_count = max(0, self._unread_count - 1)
                return True
        return False
    
    def mark_all_as_read(self):
        """Marca todas as notificações como lidas."""
        for notif in self._notifications:
            notif['read'] = True
        self._unread_count = 0
    
    def get_unread_count(self):
        """Retorna contagem de não lidas."""
        return self._unread_count
    
    def get_notifications(self, unread_only=False, notification_type=None, limit=None):
        """Retorna lista de notificações."""
        result = self._notifications
        
        if unread_only:
            result = [n for n in result if not n['read']]
        
        if notification_type:
            result = [n for n in result if n['type'] == notification_type]
        
        if limit:
            result = result[:limit]
        
        return result
    
    def clear_all(self):
        """Limpa todas as notificações."""
        self._notifications.clear()
        self._unread_count = 0
    
    def on_notification(self, callback):
        """Registra callback para novas notificações."""
        self._callbacks.append(callback)
    
    def remove_callback(self, callback):
        """Remove callback."""
        if callback in self._callbacks:
            self._callbacks.remove(callback)


