# SISTEMA DE COMANDOS DE VOZ (PREPARADO PARA FUTURO)
# ═══════════════════════════════════════════════════════════════════════════════════════

class VoiceCommandSystem:
    """
    Sistema de Comandos de Voz (Interface Preparada).
    
    Características:
    - Reconhecimento de comandos básicos
    - Feedback por voz
    - Comandos personalizáveis
    - Modo mãos-livres
    
    Nota: Requer bibliotecas adicionais para funcionar completamente.
    """
    
    COMMANDS = {
        'nova venda': 'new_sale',
        'finalizar': 'finalize_sale',
        'cancelar': 'cancel',
        'buscar produto': 'search_product',
        'adicionar': 'add_item',
        'remover': 'remove_item',
        'pagamento': 'open_payment',
        'dinheiro': 'pay_cash',
        'cartão': 'pay_card',
        'pix': 'pay_pix',
        'ajuda': 'help',
        'relatório': 'reports',
    }
    
    def __init__(self, enabled=False):
        self._enabled = enabled
        self._listening = False
        self._callbacks = {}
        self._speech_available = False
        
        # Verifica disponibilidade
        try:
            import speech_recognition
            self._speech_available = True
        except ImportError:
            self._speech_available = False
    
    def is_available(self):
        """Verifica se o sistema de voz está disponível."""
        return self._speech_available
    
    def enable(self):
        """Ativa o sistema de voz."""
        if self._speech_available:
            self._enabled = True
            return True
        return False
    
    def disable(self):
        """Desativa o sistema de voz."""
        self._enabled = False
        self._listening = False
    
    def register_command(self, phrase, callback):
        """Registra um comando de voz."""
        self._callbacks[phrase.lower()] = callback
    
    def start_listening(self):
        """Inicia escuta de comandos."""
        if not self._enabled or not self._speech_available:
            return False
        
        self._listening = True
        # Implementação real requer thread separada
        return True
    
    def stop_listening(self):
        """Para escuta de comandos."""
        self._listening = False
    
    def process_command(self, text):
        """Processa um comando de texto."""
        text = text.lower().strip()
        
        # Busca comando exato
        if text in self._callbacks:
            self._callbacks[text]()
            return True
        
        # Busca comando parcial
        for phrase, callback in self._callbacks.items():
            if phrase in text:
                callback()
                return True
        
        return False
    
    def speak(self, text):
        """Fala um texto (TTS)."""
        if not self._enabled:
            return False
        
        try:
            import pyttsx3
            engine = pyttsx3.init()
            engine.say(text)
            engine.runAndWait()
            return True
        except:
            return False


