# SISTEMA DE INTEGRAÇÃO COM DISPOSITIVOS MÓVEIS
# ═══════════════════════════════════════════════════════════════════════════════════════

class MobileIntegration:
    """
    Sistema de Integração com Dispositivos Móveis.
    
    Características:
    - QR Code para conexão
    - Sincronização de dados
    - Notificações push
    - Controle remoto
    """
    
    def __init__(self, server_port=5000):
        self._port = server_port
        self._connected_devices = []
        self._sync_queue = []
    
    def generate_connection_qr(self, server_ip=None):
        """
        Gera QR Code para conexão.
        
        Args:
            server_ip: IP do servidor (auto-detecta se None)
            
        Returns:
            Dados para gerar QR Code
        """
        if server_ip is None:
            try:
                import socket
                s = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
                s.connect(("8.8.8.8", 80))
                server_ip = s.getsockname()[0]
                s.close()
            except:
                server_ip = "127.0.0.1"
        
        connection_data = {
            'type': 'pdv_connection',
            'ip': server_ip,
            'port': self._port,
            'timestamp': datetime.datetime.now().isoformat()
        }
        
        return json.dumps(connection_data)
    
    def register_device(self, device_id, device_name, device_type='mobile'):
        """Registra um dispositivo conectado."""
        device = {
            'id': device_id,
            'name': device_name,
            'type': device_type,
            'connected_at': datetime.datetime.now().isoformat(),
            'last_sync': None
        }
        self._connected_devices.append(device)
        return device
    
    def get_connected_devices(self):
        """Retorna lista de dispositivos conectados."""
        return self._connected_devices
    
    def sync_data(self, device_id, data_type, data):
        """Sincroniza dados com um dispositivo."""
        sync_item = {
            'device_id': device_id,
            'data_type': data_type,
            'data': data,
            'timestamp': datetime.datetime.now().isoformat()
        }
        self._sync_queue.append(sync_item)
        return True
    
    def get_pending_syncs(self, device_id=None):
        """Retorna sincronizações pendentes."""
        if device_id:
            return [s for s in self._sync_queue if s['device_id'] == device_id]
        return self._sync_queue





