# SISTEMA DE OTIMIZAÇÃO DE PERFORMANCE v2.0
# ═══════════════════════════════════════════════════════════════════════════════════════

class PerformanceOptimizer:
    """
    Otimizador de Performance do Sistema.
    
    Características:
    - Lazy loading de componentes
    - Pool de conexões de banco
    - Compressão de dados
    - Garbage collection otimizado
    - Profiling de operações
    """
    
    def __init__(self):
        self._metrics = {}
        self._start_times = {}
        self._gc_threshold = 1000
        self._operation_count = 0
    
    def start_timer(self, operation_name):
        """Inicia timer para uma operação."""
        self._start_times[operation_name] = time.time()
    
    def stop_timer(self, operation_name):
        """Para timer e registra métrica."""
        if operation_name not in self._start_times:
            return 0
        
        elapsed = time.time() - self._start_times[operation_name]
        
        if operation_name not in self._metrics:
            self._metrics[operation_name] = {
                'count': 0,
                'total_time': 0,
                'min_time': float('inf'),
                'max_time': 0
            }
        
        self._metrics[operation_name]['count'] += 1
        self._metrics[operation_name]['total_time'] += elapsed
        self._metrics[operation_name]['min_time'] = min(
            self._metrics[operation_name]['min_time'], elapsed
        )
        self._metrics[operation_name]['max_time'] = max(
            self._metrics[operation_name]['max_time'], elapsed
        )
        
        del self._start_times[operation_name]
        return elapsed
    
    def get_metrics(self):
        """Retorna métricas de performance."""
        result = {}
        for name, data in self._metrics.items():
            avg_time = data['total_time'] / data['count'] if data['count'] > 0 else 0
            result[name] = {
                'count': data['count'],
                'avg_time': f"{avg_time*1000:.2f}ms",
                'min_time': f"{data['min_time']*1000:.2f}ms",
                'max_time': f"{data['max_time']*1000:.2f}ms",
                'total_time': f"{data['total_time']:.2f}s"
            }
        return result
    
    def optimize_gc(self):
        """Otimiza garbage collection."""
        self._operation_count += 1
        
        if self._operation_count >= self._gc_threshold:
            import gc
            gc.collect()
            self._operation_count = 0
            return True
        return False
    
    def clear_metrics(self):
        """Limpa métricas."""
        self._metrics.clear()


class ConnectionPool:
    """
    Pool de Conexões MySQL.
    
    Características:
    - Reutilização de conexões MySQL
    - Limite de conexões
    - Timeout configurável
    - Health check automático com ping
    """
    
    def __init__(self, db_path=None, max_connections=5, timeout=30):
        self._max_connections = max_connections
        self._timeout = timeout
        self._available = []
        self._in_use = []
        self._lock = threading.Lock()
    
    def _create_connection(self):
        """Cria uma nova conexão MySQL."""
        config = get_mysql_config()
        conn = mysql.connector.connect(
            host=config['host'],
            port=config['port'],
            user=config['user'],
            password=config['password'],
            database=config['database'],
            charset=config['charset'],
            collation=config.get('collation', 'utf8mb4_unicode_ci'),
            autocommit=True,
            connect_timeout=self._timeout,
            use_pure=True
        )
        return conn
    
    def get_connection(self):
        """Obtém uma conexão do pool."""
        with self._lock:
            # Tenta reutilizar uma conexão disponível
            while self._available:
                conn = self._available.pop()
                try:
                    conn.ping(reconnect=True, attempts=1, delay=0)
                    self._in_use.append(conn)
                    return conn
                except Exception:
                    try:
                        conn.close()
                    except Exception:
                        pass
            
            if len(self._in_use) < self._max_connections:
                try:
                    conn = self._create_connection()
                    self._in_use.append(conn)
                    return conn
                except Exception as e:
                    print(f"[ConnectionPool] Erro ao criar conexão: {e}")
                    return None
            
            return None
    
    def release_connection(self, conn):
        """Libera uma conexão de volta ao pool."""
        with self._lock:
            if conn in self._in_use:
                self._in_use.remove(conn)
                try:
                    conn.ping(reconnect=False, attempts=1, delay=0)
                    self._available.append(conn)
                except Exception:
                    try:
                        conn.close()
                    except Exception:
                        pass
    
    def close_all(self):
        """Fecha todas as conexões."""
        with self._lock:
            for conn in self._available + self._in_use:
                try:
                    conn.close()
                except:
                    pass
            self._available.clear()
            self._in_use.clear()
    
    def get_stats(self):
        """Retorna estatísticas do pool."""
        return {
            'available': len(self._available),
            'in_use': len(self._in_use),
            'max': self._max_connections
        }


class LazyLoader:
    """
    Sistema de Lazy Loading para Componentes.
    """
    
    def __init__(self):
        self._components = {}
        self._loaders = {}
        self._loaded = set()
    
    def register(self, name, loader_func):
        """Registra um componente para lazy loading."""
        self._loaders[name] = loader_func
    
    def get(self, name):
        """Obtém um componente, carregando se necessário."""
        if name not in self._loaded:
            if name in self._loaders:
                self._components[name] = self._loaders[name]()
                self._loaded.add(name)
            else:
                return None
        return self._components.get(name)
    
    def preload(self, names):
        """Pré-carrega componentes em background."""
        def load_all():
            for name in names:
                if name not in self._loaded and name in self._loaders:
                    self._components[name] = self._loaders[name]()
                    self._loaded.add(name)
        
        thread = threading.Thread(target=load_all, daemon=True)
        thread.start()
    
    def is_loaded(self, name):
        """Verifica se componente está carregado."""
        return name in self._loaded
    
    def unload(self, name):
        """Descarrega um componente."""
        if name in self._loaded:
            self._loaded.remove(name)
            if name in self._components:
                del self._components[name]


