def instalar_dependencias():
    """
    Verifica e instala automaticamente todas as dependências necessárias.
    Executado apenas uma vez na primeira inicialização ou quando faltar alguma biblioteca.
    """
    AUDITORIA.processo("Iniciando verificação de dependências do sistema")
    
    # Lista de dependências necessárias
    # Formato: (nome_import, nome_pip, descricao)
    DEPENDENCIAS = [
        # ============================================
        # INTERFACE GRÁFICA
        # ============================================
        ('ttkbootstrap', 'ttkbootstrap', 'Interface moderna com temas Bootstrap'),
        ('PIL', 'Pillow', 'Manipulação e exibição de imagens'),
        
        # ============================================
        # GERAÇÃO DE PDFs E RELATÓRIOS
        # ============================================
        ('reportlab', 'reportlab', 'Geração de PDFs, relatórios e códigos de barras'),
        
        # ============================================
        # COMUNICAÇÃO SERIAL (BALANÇAS)
        # ============================================
        ('serial', 'pyserial', 'Comunicação com balanças via porta serial/USB'),
        
        # ============================================
        # CRIPTOGRAFIA E SEGURANÇA
        # ============================================
        ('bcrypt', 'bcrypt', 'Criptografia segura de senhas'),
        ('cryptography', 'cryptography', 'Criptografia avançada (Fernet/AES)'),
        
        # ============================================
        # CÁLCULOS NUMÉRICOS
        # ============================================
        # NOTA: matplotlib removido - incompatível com Python 32-bit
        # O dashboard agora usa gráficos nativos em Tkinter Canvas
        ('numpy', 'numpy', 'Cálculos numéricos e arrays'),
        
        # ============================================
        # UTILITÁRIOS
        # ============================================
        ('qrcode', 'qrcode', 'Geração de QR Codes'),
        
        # ============================================
        # SERVIDOR WEB (COMANDAS ONLINE)
        # ============================================
        ('flask', 'flask', 'Servidor web para comandas online'),
        ('flask_cors', 'flask-cors', 'Suporte a CORS para API REST'),
        
        # ============================================
        # IMPRESSAO TERMICA
        # ============================================
        ('win32print', 'pywin32', 'Impressao RAW no Windows'),
        
        # ============================================
    ]
    
    # Dependencias opcionais (nao bloqueiam a execucao se falharem)
    DEPENDENCIAS_OPCIONAIS = [
        ('bluetooth', 'pybluez', 'Comunicacao Bluetooth com balancas'),
        ('bleak', 'bleak', 'Comunicacao Bluetooth LE'),
        ('usb', 'pyusb', 'Comunicacao USB nativa para impressoras'),
    ]
    
    def verificar_pip():
        """Verifica se o pip está disponível e atualizado."""
        try:
            subprocess.check_call([sys.executable, '-m', 'pip', '--version'],
                                stdout=subprocess.DEVNULL, stderr=subprocess.DEVNULL)
            return True
        except Exception:
            return False
    
    def instalar_pacote(nome_pip, descricao=""):
        """Instala um pacote via pip."""
        try:
            print(f"   [PACOTE] Instalando {nome_pip}... ({descricao})")
            subprocess.check_call(
                [sys.executable, '-m', 'pip', 'install', nome_pip, '--quiet', '--disable-pip-version-check'],
                stdout=subprocess.DEVNULL,
                stderr=subprocess.DEVNULL
            )
            return True
        except subprocess.CalledProcessError:
            return False
        except Exception as e:
            return False
    
    def verificar_modulo(nome_import):
        """Verifica se um módulo está instalado."""
        try:
            __import__(nome_import)
            return True
        except ImportError:
            return False
    
    # Verifica se precisa instalar algo
    modulos_faltando = []
    for nome_import, nome_pip, descricao in DEPENDENCIAS:
        if not verificar_modulo(nome_import):
            modulos_faltando.append((nome_import, nome_pip, descricao))
    
    # Se não falta nada, retorna silenciosamente
    if not modulos_faltando:
        return True
    
    # Exibe mensagem de instalação
    print("")
    print("╔═══════════════════════════════════════════════════════════════════════════╗")
    print("║           [FERRAMENTA] INSTALADOR AUTOMÁTICO DE DEPENDÊNCIAS                        ║")
    print("║                   PDV QUANTUM ULTRA - NEXUS EDITION                       ║")
    print("╚═══════════════════════════════════════════════════════════════════════════╝")
    print("")
    print(f"   [ALERTA]  Foram detectadas {len(modulos_faltando)} dependência(s) faltando.")
    print("   [RECEBER] Iniciando instalação automática...")
    print("")
    
    # Verifica pip
    if not verificar_pip():
        print("   [ERRO] ERRO: pip não está disponível!")
        print("   Por favor, instale o pip manualmente e tente novamente.")
        input("\n   Pressione ENTER para sair...")
        sys.exit(1)
    
    # Atualiza pip silenciosamente
    try:
        subprocess.check_call(
            [sys.executable, '-m', 'pip', 'install', '--upgrade', 'pip', '--quiet', '--disable-pip-version-check'],
            stdout=subprocess.DEVNULL,
            stderr=subprocess.DEVNULL
        )
    except Exception:
        pass
    
    # Instala dependências obrigatórias
    falhas = []
    sucessos = []
    
    for nome_import, nome_pip, descricao in modulos_faltando:
        if instalar_pacote(nome_pip, descricao):
            sucessos.append(nome_pip)
            print(f"   [OK] {nome_pip} instalado com sucesso!")
        else:
            falhas.append(nome_pip)
            print(f"   [ERRO] Falha ao instalar {nome_pip}")
    
    # Tenta instalar dependências opcionais (sem bloquear)
    print("")
    print("   [PACOTE] Verificando dependências opcionais...")
    for nome_import, nome_pip, descricao in DEPENDENCIAS_OPCIONAIS:
        if not verificar_modulo(nome_import):
            if instalar_pacote(nome_pip, descricao):
                print(f"   [OK] {nome_pip} (opcional) instalado!")
            else:
                print(f"   [ALERTA]  {nome_pip} (opcional) não instalado - funcionalidade limitada")
    
    print("")
    print("═" * 75)
    
    if falhas:
        print(f"")
        print(f"   [ALERTA]  Algumas dependências não puderam ser instaladas: {', '.join(falhas)}")
        print(f"   O sistema pode não funcionar corretamente.")
        print(f"")
        print(f"   Tente instalar manualmente com:")
        for pacote in falhas:
            print(f"      pip install {pacote}")
        print("")
        input("   Pressione ENTER para tentar continuar mesmo assim...")
    else:
        print(f"")
        print(f"   [OK] Todas as {len(sucessos)} dependências foram instaladas com sucesso!")
        print(f"   [ROCKET] O sistema está pronto para uso.")
        print(f"")
        print("   Reiniciando em 3 segundos...")
        import time
        time.sleep(3)
        
        # Reinicia o script para carregar as novas dependências
        # NOTA: Não reinicia se estiver rodando como executável (PyInstaller)
        if not getattr(sys, 'frozen', False):
            print("   [SYNC] Reiniciando o sistema...")
            os.execv(sys.executable, [sys.executable] + sys.argv)
        else:
            print("   [OK] Dependências instaladas! Por favor, reinicie o programa manualmente.")
            input("   Pressione ENTER para sair...")
            sys.exit(0)
    
    return len(falhas) == 0

def criar_pastas_necessarias():
    """
    Cria todas as pastas necessárias para o funcionamento do sistema.
    """
    AUDITORIA.processo("Verificando e criando pastas necessárias do sistema")
    # Obtém o diretório onde o script está localizado
    SCRIPT_DIR = os.path.dirname(os.path.abspath(__file__))
    
    # Lista de pastas a serem criadas
    PASTAS = [
        ('Imagens_produtos', 'Pasta para armazenar imagens dos produtos'),
        ('dados', 'Pasta para armazenar dados do sistema'),
        ('backups', 'Pasta para armazenar backups'),
        ('relatorios', 'Pasta para armazenar relatórios gerados'),
    ]
    
    pastas_criadas = []
    
    for nome_pasta, descricao in PASTAS:
        caminho_pasta = os.path.join(SCRIPT_DIR, nome_pasta)
        if not os.path.exists(caminho_pasta):
            try:
                os.makedirs(caminho_pasta)
                pastas_criadas.append(nome_pasta)
            except Exception as e:
                print(f"   [ALERTA]  Não foi possível criar a pasta '{nome_pasta}': {e}")
    
    if pastas_criadas:
        print("")
        print("   [PASTA] Pastas criadas automaticamente:")
        for pasta in pastas_criadas:
            print(f"      [OK] {pasta}")
        print("")
    
    return True

