# CONSTANTES E COMANDOS ESC/POS
# ═══════════════════════════════════════════════════════════════════════════════

class ESC_POS:
    """Comandos ESC/POS padrão e estendidos para impressoras térmicas."""
    
    # ─────────────────────────────────────────────────────────────────────────
    # CARACTERES DE CONTROLE
    # ─────────────────────────────────────────────────────────────────────────
    NUL = b'\x00'  # Nulo
    LF = b'\x0a'   # Line Feed (nova linha)
    CR = b'\x0d'   # Carriage Return
    FF = b'\x0c'   # Form Feed
    HT = b'\x09'   # Horizontal Tab
    ESC = b'\x1b'  # Escape
    FS = b'\x1c'   # File Separator
    GS = b'\x1d'   # Group Separator
    DLE = b'\x10'  # Data Link Escape
    
    # ─────────────────────────────────────────────────────────────────────────
    # INICIALIZAÇÃO E RESET
    # ─────────────────────────────────────────────────────────────────────────
    INIT = b'\x1b\x40'              # ESC @ - Inicializa impressora
    RESET = b'\x1b\x40'             # ESC @ - Reset (mesmo que INIT)
    
    # ─────────────────────────────────────────────────────────────────────────
    # FORMATAÇÃO DE TEXTO
    # ─────────────────────────────────────────────────────────────────────────
    # Negrito
    BOLD_ON = b'\x1b\x45\x01'       # ESC E 1 - Liga negrito
    BOLD_OFF = b'\x1b\x45\x00'      # ESC E 0 - Desliga negrito
    
    # Sublinhado
    UNDERLINE_OFF = b'\x1b\x2d\x00' # ESC - 0 - Desliga sublinhado
    UNDERLINE_1 = b'\x1b\x2d\x01'   # ESC - 1 - Sublinhado 1 ponto
    UNDERLINE_2 = b'\x1b\x2d\x02'   # ESC - 2 - Sublinhado 2 pontos
    
    # Dupla largura/altura
    DOUBLE_HEIGHT_ON = b'\x1b\x21\x10'   # ESC ! 16
    DOUBLE_WIDTH_ON = b'\x1b\x21\x20'    # ESC ! 32
    DOUBLE_SIZE_ON = b'\x1b\x21\x30'     # ESC ! 48 (largura + altura)
    DOUBLE_OFF = b'\x1b\x21\x00'         # ESC ! 0 - Normal
    
    # Tamanho do caractere (GS !)
    CHAR_SIZE_NORMAL = b'\x1d\x21\x00'   # GS ! 0 - Normal
    CHAR_SIZE_2H = b'\x1d\x21\x01'       # GS ! 1 - 2x altura
    CHAR_SIZE_2W = b'\x1d\x21\x10'       # GS ! 16 - 2x largura
    CHAR_SIZE_2X = b'\x1d\x21\x11'       # GS ! 17 - 2x largura e altura
    CHAR_SIZE_3H = b'\x1d\x21\x02'       # GS ! 2 - 3x altura
    CHAR_SIZE_3W = b'\x1d\x21\x20'       # GS ! 32 - 3x largura
    CHAR_SIZE_3X = b'\x1d\x21\x22'       # GS ! 34 - 3x largura e altura
    CHAR_SIZE_4X = b'\x1d\x21\x33'       # GS ! 51 - 4x largura e altura
    
    # Inversão de cores
    INVERSE_ON = b'\x1d\x42\x01'    # GS B 1 - Liga inversão
    INVERSE_OFF = b'\x1d\x42\x00'   # GS B 0 - Desliga inversão
    
    # Rotação
    ROTATE_90_ON = b'\x1b\x56\x01'  # ESC V 1 - Rotação 90°
    ROTATE_90_OFF = b'\x1b\x56\x00' # ESC V 0 - Sem rotação
    
    # Upside-down (de cabeça para baixo)
    UPSIDE_DOWN_ON = b'\x1b\x7b\x01'  # ESC { 1
    UPSIDE_DOWN_OFF = b'\x1b\x7b\x00' # ESC { 0
    
    # ─────────────────────────────────────────────────────────────────────────
    # ALINHAMENTO
    # ─────────────────────────────────────────────────────────────────────────
    ALIGN_LEFT = b'\x1b\x61\x00'    # ESC a 0 - Alinhamento à esquerda
    ALIGN_CENTER = b'\x1b\x61\x01'  # ESC a 1 - Alinhamento centralizado
    ALIGN_RIGHT = b'\x1b\x61\x02'   # ESC a 2 - Alinhamento à direita
    
    # ─────────────────────────────────────────────────────────────────────────
    # FONTES
    # ─────────────────────────────────────────────────────────────────────────
    FONT_A = b'\x1b\x4d\x00'        # ESC M 0 - Fonte A (padrão, 12x24)
    FONT_B = b'\x1b\x4d\x01'        # ESC M 1 - Fonte B (condensada, 9x17)
    FONT_C = b'\x1b\x4d\x02'        # ESC M 2 - Fonte C (8x16, algumas impressoras)
    
    # ─────────────────────────────────────────────────────────────────────────
    # ESPAÇAMENTO
    # ─────────────────────────────────────────────────────────────────────────
    LINE_SPACING_DEFAULT = b'\x1b\x32'      # ESC 2 - Espaçamento padrão
    LINE_SPACING_SET = b'\x1b\x33'          # ESC 3 n - Define espaçamento (n pontos)
    
    # ─────────────────────────────────────────────────────────────────────────
    # CORTE DE PAPEL
    # ─────────────────────────────────────────────────────────────────────────
    # Corte padrão (GS V)
    CUT_FULL = b'\x1d\x56\x00'      # GS V 0 - Corte total
    CUT_PARTIAL = b'\x1d\x56\x01'   # GS V 1 - Corte parcial
    CUT_FULL_FEED = b'\x1d\x56\x41\x03'  # GS V A 3 - Corte total com avanço
    CUT_PARTIAL_FEED = b'\x1d\x56\x42\x03'  # GS V B 3 - Corte parcial com avanço
    
    # Corte alternativo (algumas impressoras antigas/chinesas)
    CUT_FULL_ALT = b'\x1b\x69'      # ESC i - Corte total
    CUT_PARTIAL_ALT = b'\x1b\x6d'   # ESC m - Corte parcial
    
    # Corte chinês (Xprinter, Gprinter, etc.)
    CUT_CHINESE = b'\x1d\x56\x42\x00'  # GS V B 0
    
    # ─────────────────────────────────────────────────────────────────────────
    # GAVETA DE DINHEIRO
    # ─────────────────────────────────────────────────────────────────────────
    DRAWER_KICK_2 = b'\x1b\x70\x00\x19\x78'  # ESC p 0 25 120 - Pino 2
    DRAWER_KICK_5 = b'\x1b\x70\x01\x19\x78'  # ESC p 1 25 120 - Pino 5
    DRAWER_KICK = b'\x1b\x70\x00\x32\xff'    # ESC p 0 50 255 - Padrão
    
    # Alternativo para algumas impressoras
    DRAWER_KICK_ALT = b'\x10\x14\x01\x00\x05'  # DLE DC4 1 0 5
    
    # ─────────────────────────────────────────────────────────────────────────
    # CÓDIGO DE BARRAS
    # ─────────────────────────────────────────────────────────────────────────
    # Posição do texto HRI (Human Readable Interpretation)
    HRI_OFF = b'\x1d\x48\x00'       # GS H 0 - Não imprime
    HRI_ABOVE = b'\x1d\x48\x01'     # GS H 1 - Acima do código
    HRI_BELOW = b'\x1d\x48\x02'     # GS H 2 - Abaixo do código
    HRI_BOTH = b'\x1d\x48\x03'      # GS H 3 - Acima e abaixo
    
    # Fonte HRI
    HRI_FONT_A = b'\x1d\x66\x00'    # GS f 0 - Fonte A
    HRI_FONT_B = b'\x1d\x66\x01'    # GS f 1 - Fonte B
    
    # Altura do código de barras
    BARCODE_HEIGHT = b'\x1d\x68'    # GS h n - Define altura (n pontos)
    
    # Largura do código de barras
    BARCODE_WIDTH = b'\x1d\x77'     # GS w n - Define largura (2-6)
    
    # Tipos de código de barras (GS k m d1...dk NUL)
    BARCODE_UPC_A = 0
    BARCODE_UPC_E = 1
    BARCODE_EAN13 = 2
    BARCODE_EAN8 = 3
    BARCODE_CODE39 = 4
    BARCODE_ITF = 5
    BARCODE_CODABAR = 6
    BARCODE_CODE93 = 72
    BARCODE_CODE128 = 73
    
    # ─────────────────────────────────────────────────────────────────────────
    # QR CODE
    # ─────────────────────────────────────────────────────────────────────────
    # Modelo do QR Code
    QRCODE_MODEL_1 = b'\x1d\x28\x6b\x04\x00\x31\x41\x31\x00'  # Modelo 1
    QRCODE_MODEL_2 = b'\x1d\x28\x6b\x04\x00\x31\x41\x32\x00'  # Modelo 2
    QRCODE_MICRO = b'\x1d\x28\x6b\x04\x00\x31\x41\x33\x00'    # Micro QR
    
    # Tamanho do módulo (1-16)
    QRCODE_SIZE_PREFIX = b'\x1d\x28\x6b\x03\x00\x31\x43'  # + tamanho (1 byte)
    
    # Nível de correção de erro
    QRCODE_ERROR_L = b'\x1d\x28\x6b\x03\x00\x31\x45\x30'  # 7%
    QRCODE_ERROR_M = b'\x1d\x28\x6b\x03\x00\x31\x45\x31'  # 15%
    QRCODE_ERROR_Q = b'\x1d\x28\x6b\x03\x00\x31\x45\x32'  # 25%
    QRCODE_ERROR_H = b'\x1d\x28\x6b\x03\x00\x31\x45\x33'  # 30%
    
    # Armazenar dados
    QRCODE_STORE_PREFIX = b'\x1d\x28\x6b'  # + pL pH 31 50 30 + dados
    
    # Imprimir QR Code
    QRCODE_PRINT = b'\x1d\x28\x6b\x03\x00\x31\x51\x30'
    
    # ─────────────────────────────────────────────────────────────────────────
    # IMAGEM
    # ─────────────────────────────────────────────────────────────────────────
    # Modo raster (GS v 0)
    IMAGE_RASTER = b'\x1d\x76\x30'
    
    # Modo coluna (ESC *)
    IMAGE_COLUMN_8 = b'\x1b\x2a\x00'   # 8-dot single density
    IMAGE_COLUMN_8D = b'\x1b\x2a\x01'  # 8-dot double density
    IMAGE_COLUMN_24 = b'\x1b\x2a\x20'  # 24-dot single density
    IMAGE_COLUMN_24D = b'\x1b\x2a\x21' # 24-dot double density
    
    # ─────────────────────────────────────────────────────────────────────────
    # CODIFICAÇÃO DE CARACTERES
    # ─────────────────────────────────────────────────────────────────────────
    CODEPAGE_PC437 = b'\x1b\x74\x00'   # USA: Standard Europe
    CODEPAGE_KATAKANA = b'\x1b\x74\x01' # Katakana
    CODEPAGE_PC850 = b'\x1b\x74\x02'   # Multilingual
    CODEPAGE_PC860 = b'\x1b\x74\x03'   # Portuguese
    CODEPAGE_PC863 = b'\x1b\x74\x04'   # Canadian-French
    CODEPAGE_PC865 = b'\x1b\x74\x05'   # Nordic
    CODEPAGE_WPC1252 = b'\x1b\x74\x10' # Windows Latin-1
    CODEPAGE_PC866 = b'\x1b\x74\x11'   # Cyrillic #2
    CODEPAGE_PC852 = b'\x1b\x74\x12'   # Latin 2
    CODEPAGE_PC858 = b'\x1b\x74\x13'   # Euro
    CODEPAGE_THAI42 = b'\x1b\x74\x14'  # Thai character code 42
    CODEPAGE_THAI11 = b'\x1b\x74\x15'  # Thai character code 11
    CODEPAGE_THAI13 = b'\x1b\x74\x16'  # Thai character code 13
    CODEPAGE_THAI14 = b'\x1b\x74\x17'  # Thai character code 14
    CODEPAGE_THAI16 = b'\x1b\x74\x18'  # Thai character code 16
    CODEPAGE_THAI17 = b'\x1b\x74\x19'  # Thai character code 17
    CODEPAGE_THAI18 = b'\x1b\x74\x1a'  # Thai character code 18
    
    # ─────────────────────────────────────────────────────────────────────────
    # STATUS DA IMPRESSORA
    # ─────────────────────────────────────────────────────────────────────────
    STATUS_PAPER = b'\x10\x04\x04'     # DLE EOT 4 - Status do papel
    STATUS_DRAWER = b'\x10\x04\x01'    # DLE EOT 1 - Status da gaveta
    STATUS_ERROR = b'\x10\x04\x02'     # DLE EOT 2 - Status de erro
    STATUS_ROLL = b'\x10\x04\x03'      # DLE EOT 3 - Status do rolo
    
    # ─────────────────────────────────────────────────────────────────────────
    # AVANÇO DE PAPEL
    # ─────────────────────────────────────────────────────────────────────────
    FEED_LINES = b'\x1b\x64'           # ESC d n - Avança n linhas
    FEED_DOTS = b'\x1b\x4a'            # ESC J n - Avança n pontos
    

class PrinterBrand(Enum):
    """Marcas de impressoras suportadas."""
    GENERIC = "generic"
    EPSON = "epson"
    BEMATECH = "bematech"
    ELGIN = "elgin"
    DARUMA = "daruma"
    XPRINTER = "xprinter"
    GPRINTER = "gprinter"
    ZJIANG = "zjiang"
    HPRT = "hprt"
    TANCA = "tanca"
    SWEDA = "sweda"
    DIEBOLD = "diebold"
    STAR = "star"
    CITIZEN = "citizen"
    CUSTOM = "custom"


class ConnectionType(Enum):
    """Tipos de conexão suportados."""
    USB = "usb"
    SERIAL = "serial"
    BLUETOOTH = "bluetooth"  # Bluetooth pareado como porta COM/RFCOMM
    NETWORK = "network"
    WINDOWS_RAW = "windows_raw"
    WINDOWS_DRIVER = "windows_driver"
    FILE = "file"
    CUPS = "cups"
    AUTO = "auto"


class PaperWidth(IntEnum):
    """Larguras de papel suportadas."""
    MM58 = 58
    MM80 = 80
    MM76 = 76
    MM57 = 57


class TextAlign(Enum):
    """Alinhamento de texto."""
    LEFT = "left"
    CENTER = "center"
    RIGHT = "right"


class BarcodeType(Enum):
    """Tipos de código de barras."""
    UPC_A = "UPC-A"
    UPC_E = "UPC-E"
    EAN13 = "EAN13"
    EAN8 = "EAN8"
    CODE39 = "CODE39"
    ITF = "ITF"
    CODABAR = "CODABAR"
    CODE93 = "CODE93"
    CODE128 = "CODE128"


class QRErrorLevel(Enum):
    """Níveis de correção de erro do QR Code."""
    L = "L"  # 7%
    M = "M"  # 15%
    Q = "Q"  # 25%
    H = "H"  # 30%


@dataclass
class PrinterProfile:
    """Perfil de configuração da impressora."""
    brand: PrinterBrand = PrinterBrand.GENERIC
    model: str = ""
    paper_width: PaperWidth = PaperWidth.MM80
    chars_per_line: int = 48
    supports_cut: bool = True
    supports_partial_cut: bool = True
    supports_drawer: bool = True
    supports_barcode: bool = True
    supports_qrcode: bool = True
    supports_image: bool = True
    supports_bold: bool = True
    supports_underline: bool = True
    supports_double_size: bool = True
    supports_inverse: bool = True
    default_encoding: str = "cp850"
    cut_command: bytes = ESC_POS.CUT_PARTIAL_FEED
    drawer_command: bytes = ESC_POS.DRAWER_KICK
    max_barcode_width: int = 6
    max_qrcode_size: int = 16
    init_sequence: bytes = ESC_POS.INIT
    
    @classmethod
    def for_58mm(cls, brand: PrinterBrand = PrinterBrand.GENERIC) -> 'PrinterProfile':
        """Cria perfil para impressora 58mm."""
        return cls(
            brand=brand,
            paper_width=PaperWidth.MM58,
            chars_per_line=32
        )
    
    @classmethod
    def for_80mm(cls, brand: PrinterBrand = PrinterBrand.GENERIC) -> 'PrinterProfile':
        """Cria perfil para impressora 80mm."""
        return cls(
            brand=brand,
            paper_width=PaperWidth.MM80,
            chars_per_line=48
        )


