# CLASSE STATUSBAR - BARRA DE STATUS REUTILIZÁVEL
# ═══════════════════════════════════════════════════════════════════════════════

class StatusBar:
    """
    Classe para gerenciar a barra de status em todas as telas.
    Exibe: usuário logado, data/hora, status de conexão e versão do sistema.
    Atualiza em tempo real.
    """
    
    def __init__(self, parent_window, user_name: str = "Usuário", version: str = "12.0.0"):
        """
        Inicializa a barra de status.
        
        Args:
            parent_window: Janela pai (tk.Toplevel ou tk.Tk)
            user_name: Nome do usuário logado
            version: Versão do sistema
        """
        self.parent = parent_window
        self.user_name = user_name
        self.version = version
        self.is_running = True
        self.connection_status = "Conectado"
        # Guarda o id do .after() para cancelar quando a tela/barra for destruida.
        # Sem isso, ao recriar a tela principal no modo SUPERMERCADO, o Tkinter
        # continuava tentando atualizar labels antigos ja destruidos, gerando:
        # invalid command name ".!frame2.!label2".
        self._after_id = None
        
        # Criar frame da barra de status na base da janela
        self.status_frame = tk.Frame(
            parent_window,
            bg='#d3d3d3',  # Cinza claro
            height=scale_value(50),
            relief=tk.SUNKEN,
            bd=1
        )
        self.status_frame.pack(side=tk.BOTTOM, fill=tk.X, expand=False)
        self.status_frame.pack_propagate(False)
        try:
            self.status_frame.bind("<Destroy>", self._on_destroy, add="+")
        except Exception:
            pass
        
        # Label para informações do usuário
        self.user_label = tk.Label(
            self.status_frame,
            text=f"👤 {self.user_name}",
            bg='#d3d3d3',
            fg='#000000',
            font=('Segoe UI', 9),
            anchor=tk.W,
            padx=10
        )
        self.user_label.pack(side=tk.LEFT, fill=tk.Y, expand=False)
        
        # Separador
        ttk.Separator(self.status_frame, orient=tk.VERTICAL).pack(side=tk.LEFT, fill=tk.Y, padx=5)
        
        # Label para data e hora
        self.datetime_label = tk.Label(
            self.status_frame,
            text="",
            bg='#d3d3d3',
            fg='#000000',
            font=('Segoe UI', 9),
            anchor=tk.W,
            padx=10
        )
        self.datetime_label.pack(side=tk.LEFT, fill=tk.Y, expand=False)
        
        # Separador
        ttk.Separator(self.status_frame, orient=tk.VERTICAL).pack(side=tk.LEFT, fill=tk.Y, padx=5)
        
        # Label para status de conexão
        self.connection_label = tk.Label(
            self.status_frame,
            text="🟢 Conectado",
            bg='#d3d3d3',
            fg='#28a745',
            font=('Segoe UI', 9),
            anchor=tk.W,
            padx=10
        )
        self.connection_label.pack(side=tk.LEFT, fill=tk.Y, expand=False)

        # Separador
        ttk.Separator(self.status_frame, orient=tk.VERTICAL).pack(side=tk.LEFT, fill=tk.Y, padx=5)

        # Endereço do banco de dados na barra de status.
        self.db_address_label = tk.Label(
            self.status_frame,
            text=self._get_database_address_text(),
            bg='#d3d3d3',
            fg='#334155',
            font=('Segoe UI', 9),
            anchor=tk.W,
            padx=8
        )

        try:
            if isinstance(self.parent, tk.Tk) or bool(getattr(self.parent, '_show_database_address', False)):
                self.db_address_label.pack(side=tk.LEFT, fill=tk.Y, expand=False, padx=(0, 8))
        except Exception:
            self.db_address_label.pack(side=tk.LEFT, fill=tk.Y, expand=False, padx=(0, 8))

        # Espaço flexível
        spacer = tk.Label(
            self.status_frame,
            text="",
            bg='#d3d3d3'
        )
        spacer.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        
        # Label para versão do sistema
        self.version_label = tk.Label(
            self.status_frame,
            text=f"v{self.version}",
            bg='#d3d3d3',
            fg='#666666',
            font=('Segoe UI', 8),
            anchor=tk.E,
            padx=10
        )
        self.version_label.pack(side=tk.RIGHT, fill=tk.Y, expand=False)
        
        # Iniciar atualização em tempo real
        self.update_status()
        
        # CORREÇÃO: não redimensionar/maximizar automaticamente janelas filhas.
        # Antes, a barra de status chamava position_window_above_taskbar() para
        # qualquer Toplevel. Como width/height eram None, a função expandia a
        # janela para toda a área útil da tela. Isso fazia telas como
        # "Reimpressão de Cupom" abrirem no tamanho correto e, após alguns
        # instantes, maximizarem sozinhas.
        # Agora esse ajuste é aplicado somente na janela principal (tk.Tk) ou
        # em janelas marcadas explicitamente com _statusbar_adjust_work_area=True.
        try:
            deve_ajustar_area = isinstance(self.parent, tk.Tk) or bool(getattr(self.parent, '_statusbar_adjust_work_area', False))
            if deve_ajustar_area:
                self.parent.after_idle(lambda w=self.parent: position_window_above_taskbar(w))
                self.parent.after(200, lambda w=self.parent: position_window_above_taskbar(w))
        except Exception:
            pass
    
    def _get_database_address_text(self):
        """Retorna texto amigável com o endereço do banco de dados atual."""
        try:
            cfg_func = globals().get('get_mysql_config')
            if callable(cfg_func):
                cfg = cfg_func()
            else:
                cfg = globals().get('MYSQL_CONFIG', {}) or {}

            host = str(cfg.get('host', 'localhost') or 'localhost')
            port = str(cfg.get('port', '3306') or '3306')
            database = str(cfg.get('database', 'pdv_quantum') or 'pdv_quantum')

            return f"🗄 Banco: {host}:{port}/{database}"
        except Exception:
            return "🗄 Banco: não identificado"


    def _widget_alive(self, widget):
        """Retorna True somente se o widget ainda existe no Tkinter."""
        try:
            return widget is not None and bool(widget.winfo_exists())
        except tk.TclError:
            return False
        except Exception:
            return False

    def _on_destroy(self, event=None):
        """Para o relógio da barra quando a barra/tela for destruída."""
        try:
            # Evita parar por eventos de destruição de filhos; só para quando
            # o próprio frame principal da StatusBar for destruído.
            if event is not None and getattr(event, 'widget', None) is not self.status_frame:
                return
        except Exception:
            pass
        self.stop()

    def stop(self):
        """Cancela atualização pendente e marca a barra como inativa."""
        self.is_running = False
        try:
            if self._after_id is not None and self._widget_alive(self.parent):
                self.parent.after_cancel(self._after_id)
        except Exception:
            pass
        self._after_id = None

    def update_status(self):
        """
        Atualiza as informações da barra de status em tempo real.
        Correção crítica: antes de atualizar qualquer Label, valida se a barra
        e todos os widgets ainda existem. Isso impede o erro repetido:
        invalid command name ".!frame2.!label2" quando a tela principal é
        destruída/recriada no modo SUPERMERCADO.
        """
        if not self.is_running:
            return

        # Se a janela ou a barra já foi destruída, encerra o loop silenciosamente.
        if not self._widget_alive(self.parent) or not self._widget_alive(getattr(self, 'status_frame', None)):
            self.stop()
            return

        try:
            # Atualizar data e hora
            from datetime import datetime
            current_time = datetime.now().strftime("%d/%m/%Y %H:%M:%S")

            if self._widget_alive(getattr(self, 'datetime_label', None)):
                self.datetime_label.config(text=f"📅 {current_time}")
            else:
                self.stop()
                return

            # Atualizar status de conexão (simulado - pode ser integrado com verificação real)
            if self._widget_alive(getattr(self, 'connection_label', None)):
                self.connection_label.config(text="🟢 Conectado", fg='#28a745')
            else:
                self.stop()
                return

            # Atualizar endereço do banco ao lado do botão Logoff
            if hasattr(self, 'db_address_label') and self._widget_alive(self.db_address_label):
                self.db_address_label.config(text=self._get_database_address_text())

        except tk.TclError:
            # Widget antigo destruído. Não registrar/printar em loop; apenas parar.
            self.stop()
            return
        except Exception as e:
            try:
                AUDITORIA.erro(f"Erro no sistema: {e}")
            except Exception:
                pass
            print(f"Erro ao atualizar status bar: {e}")

        # Agendar próxima atualização (a cada 1 segundo) somente se tudo ainda existir.
        if self.is_running and self._widget_alive(self.parent) and self._widget_alive(getattr(self, 'status_frame', None)):
            try:
                self._after_id = self.parent.after(1000, self.update_status)
            except Exception:
                self.stop()

    def set_connection_status(self, status: str, is_connected: bool = True):
        """
        Define o status de conexão.
        
        Args:
            status: Texto do status
            is_connected: True para conectado (verde), False para desconectado (vermelho)
        """
        color = '#28a745' if is_connected else '#dc3545'
        icon = '🟢' if is_connected else '🔴'
        self.connection_label.config(text=f"{icon} {status}", fg=color)
    
    def set_user_name(self, user_name: str):
        """
        Atualiza o nome do usuário exibido.
        
        Args:
            user_name: Novo nome do usuário
        """
        self.user_name = user_name
        self.user_label.config(text=f"👤 {self.user_name}")
    
    def stop(self):
        """
        Para a atualização da barra de status.
        """
        self.is_running = False


