# CLASSE BASE PARA CONEXÕES
# ═══════════════════════════════════════════════════════════════════════════════

class PrinterConnection(ABC):
    """Classe base abstrata para conexões de impressora."""
    
    def __init__(self):
        self._is_open = False
        self._lock = threading.Lock()
    
    @property
    def is_open(self) -> bool:
        """Verifica se a conexão está aberta."""
        return self._is_open
    
    @abstractmethod
    def open(self) -> bool:
        """Abre a conexão com a impressora."""
        pass
    
    @abstractmethod
    def close(self) -> None:
        """Fecha a conexão com a impressora."""
        pass
    
    @abstractmethod
    def write(self, data: bytes) -> bool:
        """Envia dados para a impressora."""
        pass
    
    def read(self, size: int = 1, timeout: float = 1.0) -> bytes:
        """Lê dados da impressora (se suportado)."""
        return b''
    
    def flush(self) -> None:
        """Força o envio de dados pendentes."""
        pass
    
    def __enter__(self):
        self.open()
        return self
    
    def __exit__(self, exc_type, exc_val, exc_tb):
        self.close()
        return False


class WindowsRawConnection(PrinterConnection):
    """Conexão via Windows RAW printing (win32print)."""
    
    def __init__(self, printer_name: str = ""):
        super().__init__()
        self.printer_name = printer_name
        self._handle = None
        self._job = None
        self._win32print = None
    
    def _import_win32print(self):
        """Importa win32print sob demanda."""
        if self._win32print is None:
            try:
                import win32print
                self._win32print = win32print
            except ImportError:
                raise ImportError(
                    "Biblioteca pywin32 não encontrada. "
                    "Instale com: pip install pywin32"
                )
        return self._win32print
    
    def get_available_printers(self) -> List[str]:
        """Retorna lista de impressoras disponíveis no Windows."""
        try:
            win32print = self._import_win32print()
            printers = win32print.EnumPrinters(
                win32print.PRINTER_ENUM_LOCAL | win32print.PRINTER_ENUM_CONNECTIONS
            )
            return [p[2] for p in printers]
        except Exception:
            return []
    
    def get_default_printer(self) -> str:
        """Retorna o nome da impressora padrão do Windows."""
        try:
            win32print = self._import_win32print()
            return win32print.GetDefaultPrinter()
        except Exception:
            return ""
    
    def open(self) -> bool:
        """Abre conexão com a impressora via Windows RAW."""
        with self._lock:
            if self._is_open:
                return True
            
            try:
                win32print = self._import_win32print()
                
                # Se não especificou impressora, usa a padrão
                if not self.printer_name:
                    self.printer_name = win32print.GetDefaultPrinter()
                
                # Abre a impressora
                self._handle = win32print.OpenPrinter(self.printer_name)
                
                # Inicia um documento de impressão RAW
                self._job = win32print.StartDocPrinter(
                    self._handle, 
                    1, 
                    ("PDV Quantum Print Job", None, "RAW")
                )
                win32print.StartPagePrinter(self._handle)
                
                self._is_open = True
                return True
                
            except Exception as e:
                self._handle = None
                self._job = None
                self._is_open = False
                raise ConnectionError(f"Erro ao abrir impressora '{self.printer_name}': {e}")
    
    def close(self) -> None:
        """Fecha a conexão com a impressora."""
        with self._lock:
            if not self._is_open:
                return
            
            try:
                win32print = self._import_win32print()
                
                if self._handle:
                    try:
                        win32print.EndPagePrinter(self._handle)
                    except Exception:
                        pass  # Exceção silenciada intencionalmente
                    try:
                        win32print.EndDocPrinter(self._handle)
                    except Exception:
                        pass  # Exceção silenciada intencionalmente
                    try:
                        win32print.ClosePrinter(self._handle)
                    except Exception:
                        pass  # Exceção silenciada intencionalmente
            finally:
                self._handle = None
                self._job = None
                self._is_open = False
    
    def write(self, data: bytes) -> bool:
        """Envia dados para a impressora."""
        with self._lock:
            if not self._is_open:
                raise ConnectionError("Conexão não está aberta")
            
            try:
                win32print = self._import_win32print()
                win32print.WritePrinter(self._handle, data)
                return True
            except Exception as e:
                raise IOError(f"Erro ao enviar dados para impressora: {e}")


class WindowsDriverConnection(PrinterConnection):
    """Conexão via driver do Windows (spooler) - para impressoras sem suporte RAW."""
    
    def __init__(self, printer_name: str = ""):
        super().__init__()
        self.printer_name = printer_name
        self._temp_file = None
        self._buffer = bytearray()
    
    def open(self) -> bool:
        """Abre conexão (prepara buffer)."""
        with self._lock:
            if self._is_open:
                return True
            
            self._buffer = bytearray()
            self._is_open = True
            return True
    
    def close(self) -> None:
        """Fecha a conexão e envia para impressão."""
        with self._lock:
            if not self._is_open:
                return
            
            try:
                if self._buffer:
                    self._print_via_spooler()
            finally:
                self._buffer = bytearray()
                self._is_open = False
    
    def write(self, data: bytes) -> bool:
        """Adiciona dados ao buffer."""
        with self._lock:
            if not self._is_open:
                raise ConnectionError("Conexão não está aberta")
            
            self._buffer.extend(data)
            return True
    
    def flush(self) -> None:
        """Envia dados pendentes para impressão."""
        with self._lock:
            if self._buffer:
                self._print_via_spooler()
                self._buffer = bytearray()
    
    def _print_via_spooler(self):
        """Envia dados para impressão via spooler do Windows."""
        if not self._buffer:
            return
        
        # Cria arquivo temporário
        with tempfile.NamedTemporaryFile(
            mode='wb', 
            delete=False, 
            suffix='.prn'
        ) as f:
            f.write(bytes(self._buffer))
            temp_path = f.name
        
        try:
            if platform.system() == "Windows":
                import subprocess
                
                # Tenta usar o comando copy para enviar para impressora
                if self.printer_name:
                    # Envia para impressora específica
                    cmd = f'copy /b "{temp_path}" "\\\\localhost\\{self.printer_name}"'
                    subprocess.run(cmd, shell=True, check=False, 
                                 capture_output=True, timeout=30)
                else:
                    # Usa impressora padrão via notepad /p
                    os.startfile(temp_path, "print")
                    time.sleep(2)  # Aguarda início da impressão
        finally:
            # Remove arquivo temporário após um delay
            try:
                time.sleep(1)
                os.unlink(temp_path)
            except Exception:
                pass  # Exceção silenciada intencionalmente


class SerialConnection(PrinterConnection):
    """Conexão via porta serial (COM/ttyUSB)."""
    
    def __init__(
        self, 
        port: str = "", 
        baudrate: int = 9600,
        bytesize: int = 8,
        parity: str = 'N',
        stopbits: int = 1,
        timeout: float = 2.0,
        dsrdtr: bool = False,
        xonxoff: bool = False
    ):
        super().__init__()
        self.port = port
        self.baudrate = baudrate
        self.bytesize = bytesize
        self.parity = parity
        self.stopbits = stopbits
        self.timeout = timeout
        self.dsrdtr = dsrdtr
        self.xonxoff = xonxoff
        self._serial = None
    
    @staticmethod
    def list_ports() -> List[str]:
        """Lista portas seriais disponíveis."""
        try:
            import serial.tools.list_ports
            return [p.device for p in serial.tools.list_ports.comports()]
        except ImportError:
            # Fallback para Windows
            if platform.system() == "Windows":
                ports = []
                for i in range(256):
                    try:
                        import serial
                        s = serial.Serial(f'COM{i}')
                        s.close()
                        ports.append(f'COM{i}')
                    except Exception:
                        pass  # Exceção silenciada intencionalmente
                return ports
            return []
    
    def open(self) -> bool:
        """Abre conexão serial."""
        with self._lock:
            if self._is_open:
                return True
            
            try:
                import serial
                
                self._serial = serial.Serial(
                    port=self.port,
                    baudrate=self.baudrate,
                    bytesize=self.bytesize,
                    parity=self.parity,
                    stopbits=self.stopbits,
                    timeout=max(float(self.timeout or 2), 2.0),
                    dsrdtr=False,
                    xonxoff=False,
                    rtscts=False,
                    write_timeout=5
                )
                
                self._is_open = True
                return True
                
            except ImportError:
                raise ImportError(
                    "Biblioteca pyserial não encontrada. "
                    "Instale com: pip install pyserial"
                )
            except Exception as e:
                self._serial = None
                self._is_open = False
                raise ConnectionError(f"Erro ao abrir porta serial '{self.port}': {e}")
    
    def close(self) -> None:
        """Fecha conexão serial."""
        with self._lock:
            if not self._is_open:
                return
            
            try:
                if self._serial:
                    self._serial.close()
            finally:
                self._serial = None
                self._is_open = False
    
    def write(self, data: bytes) -> bool:
        """Envia dados pela porta serial."""
        with self._lock:
            if not self._is_open or not self._serial:
                raise ConnectionError("Conexão serial não está aberta")
            
            try:
                self._serial.write(data)
                return True
            except Exception as e:
                raise IOError(f"Erro ao enviar dados pela serial: {e}")
    
    def read(self, size: int = 1, timeout: float = 1.0) -> bytes:
        """Lê dados da porta serial."""
        with self._lock:
            if not self._is_open or not self._serial:
                return b''
            
            try:
                old_timeout = self._serial.timeout
                self._serial.timeout = timeout
                data = self._serial.read(size)
                self._serial.timeout = old_timeout
                return data
            except Exception:
                return b''
    
    def flush(self) -> None:
        """Força envio de dados pendentes."""
        with self._lock:
            if self._serial:
                try:
                    self._serial.flush()
                except Exception:
                    pass  # Exceção silenciada intencionalmente


class NetworkConnection(PrinterConnection):
    """Conexão via rede TCP/IP."""
    
    def __init__(self, host: str, port: int = 9100, timeout: float = 10.0):
        super().__init__()
        self.host = host
        self.port = port
        self.timeout = timeout
        self._socket = None
    
    def open(self) -> bool:
        """Abre conexão de rede."""
        with self._lock:
            if self._is_open:
                return True
            
            try:
                import socket
                
                self._socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
                self._socket.settimeout(self.timeout)
                self._socket.connect((self.host, self.port))
                
                self._is_open = True
                return True
                
            except Exception as e:
                self._socket = None
                self._is_open = False
                raise ConnectionError(f"Erro ao conectar em {self.host}:{self.port}: {e}")
    
    def close(self) -> None:
        """Fecha conexão de rede."""
        with self._lock:
            if not self._is_open:
                return
            
            try:
                if self._socket:
                    self._socket.close()
            finally:
                self._socket = None
                self._is_open = False
    
    def write(self, data: bytes) -> bool:
        """Envia dados pela rede."""
        with self._lock:
            if not self._is_open or not self._socket:
                raise ConnectionError("Conexão de rede não está aberta")
            
            try:
                self._socket.sendall(data)
                return True
            except Exception as e:
                raise IOError(f"Erro ao enviar dados pela rede: {e}")
    
    def read(self, size: int = 1, timeout: float = 1.0) -> bytes:
        """Lê dados da rede."""
        with self._lock:
            if not self._is_open or not self._socket:
                return b''
            
            try:
                self._socket.settimeout(timeout)
                return self._socket.recv(size)
            except Exception:
                return b''


class FileConnection(PrinterConnection):
    """Conexão via arquivo/dispositivo."""
    
    def __init__(self, path: str, auto_flush: bool = True):
        super().__init__()
        self.path = path
        self.auto_flush = auto_flush
        self._file = None
    
    def open(self) -> bool:
        """Abre arquivo/dispositivo."""
        with self._lock:
            if self._is_open:
                return True
            
            try:
                self._file = open(self.path, 'wb')
                self._is_open = True
                return True
            except Exception as e:
                self._file = None
                self._is_open = False
                raise ConnectionError(f"Erro ao abrir '{self.path}': {e}")
    
    def close(self) -> None:
        """Fecha arquivo/dispositivo."""
        with self._lock:
            if not self._is_open:
                return
            
            try:
                if self._file:
                    self._file.close()
            finally:
                self._file = None
                self._is_open = False
    
    def write(self, data: bytes) -> bool:
        """Escreve dados no arquivo."""
        with self._lock:
            if not self._is_open or not self._file:
                raise ConnectionError("Arquivo não está aberto")
            
            try:
                self._file.write(data)
                if self.auto_flush:
                    self._file.flush()
                return True
            except Exception as e:
                raise IOError(f"Erro ao escrever no arquivo: {e}")
    
    def flush(self) -> None:
        """Força escrita de dados pendentes."""
        with self._lock:
            if self._file:
                try:
                    self._file.flush()
                except Exception:
                    pass  # Exceção silenciada intencionalmente


class USBConnection(PrinterConnection):
    """Conexão via USB nativo (pyusb/libusb)."""
    
    def __init__(
        self, 
        vendor_id: int = None, 
        product_id: int = None,
        in_ep: int = 0x82,
        out_ep: int = 0x01,
        timeout: int = 5000
    ):
        super().__init__()
        self.vendor_id = vendor_id
        self.product_id = product_id
        self.in_ep = in_ep
        self.out_ep = out_ep
        self.timeout = timeout
        self._device = None
        self._usb = None
    
    @staticmethod
    def list_devices() -> List[Dict[str, Any]]:
        """Lista dispositivos USB disponíveis."""
        try:
            import usb.core
            import usb.util
            devices = []
            for dev in usb.core.find(find_all=True):
                devices.append({
                    'vendor_id': dev.idVendor,
                    'product_id': dev.idProduct,
                    'manufacturer': getattr(dev, 'manufacturer', 'Unknown'),
                    'product': getattr(dev, 'product', 'Unknown')
                })
            return devices
        except ImportError:
            # PyUSB não está instalado
            return []
        except Exception as e:
            # NoBackendError ou qualquer outro erro na listagem USB
            # (inclui usb.core.NoBackendError quando libusb não está instalado)
            return []
    
    def open(self) -> bool:
        """Abre conexão USB."""
        with self._lock:
            if self._is_open:
                return True
            
            try:
                import usb.core
                import usb.util
                self._usb = usb
                
                # Busca o dispositivo
                self._device = usb.core.find(
                    idVendor=self.vendor_id,
                    idProduct=self.product_id
                )
                
                if self._device is None:
                    raise ConnectionError(
                        f"Dispositivo USB não encontrado "
                        f"(VID: {self.vendor_id:04x}, PID: {self.product_id:04x})"
                    )
                
                # Configura o dispositivo
                try:
                    if self._device.is_kernel_driver_active(0):
                        self._device.detach_kernel_driver(0)
                except Exception:
                    pass  # Exceção silenciada intencionalmente
                
                self._device.set_configuration()
                
                self._is_open = True
                return True
                
            except ImportError:
                raise ImportError(
                    "Biblioteca pyusb não encontrada. "
                    "Instale com: pip install pyusb"
                )
            except Exception as e:
                self._device = None
                self._is_open = False
                raise ConnectionError(f"Erro ao abrir dispositivo USB: {e}")
    
    def close(self) -> None:
        """Fecha conexão USB."""
        with self._lock:
            if not self._is_open:
                return
            
            try:
                if self._device and self._usb:
                    self._usb.util.dispose_resources(self._device)
            finally:
                self._device = None
                self._is_open = False
    
    def write(self, data: bytes) -> bool:
        """Envia dados via USB."""
        with self._lock:
            if not self._is_open or not self._device:
                raise ConnectionError("Conexão USB não está aberta")
            
            try:
                self._device.write(self.out_ep, data, self.timeout)
                return True
            except Exception as e:
                raise IOError(f"Erro ao enviar dados via USB: {e}")
    
    def read(self, size: int = 1, timeout: float = 1.0) -> bytes:
        """Lê dados via USB."""
        with self._lock:
            if not self._is_open or not self._device:
                return b''
            
            try:
                return bytes(self._device.read(self.in_ep, size, int(timeout * 1000)))
            except Exception:
                return b''


