# CLASSE PRINCIPAL - IMPRESSORA TÉRMICA UNIVERSAL
# ═══════════════════════════════════════════════════════════════════════════════

class ThermalPrinter:
    """
    Classe principal para controle de impressoras térmicas.
    
    Suporta múltiplos tipos de conexão e marcas de impressoras.
    Implementa protocolo ESC/POS com variações para impressoras chinesas.
    """
    
    def __init__(
        self,
        connection: PrinterConnection = None,
        profile: PrinterProfile = None,
        auto_init: bool = True
    ):
        """
        Inicializa a impressora térmica.
        
        Args:
            connection: Objeto de conexão (WindowsRawConnection, SerialConnection, etc.)
            profile: Perfil da impressora (define características e comandos)
            auto_init: Se True, envia comando de inicialização ao conectar
        """
        self.connection = connection
        self.profile = profile or PrinterProfile()
        self.auto_init = auto_init
        
        # Estado interno
        self._encoding = self.profile.default_encoding
        self._buffer = bytearray()
        self._use_buffer = False
    
    # ─────────────────────────────────────────────────────────────────────────
    # MÉTODOS DE CONEXÃO
    # ─────────────────────────────────────────────────────────────────────────
    
    def connect(self) -> bool:
        """Abre conexão com a impressora."""
        if not self.connection:
            raise ValueError("Nenhuma conexão configurada")
        
        result = self.connection.open()
        
        if result and self.auto_init:
            self.init()
        
        return result
    
    def disconnect(self) -> None:
        """Fecha conexão com a impressora."""
        if self.connection:
            self.connection.close()
    
    def is_connected(self) -> bool:
        """Verifica se está conectado."""
        return self.connection and self.connection.is_open
    
    def __enter__(self):
        self.connect()
        return self
    
    def __exit__(self, exc_type, exc_val, exc_tb):
        self.disconnect()
        return False
    
    # ─────────────────────────────────────────────────────────────────────────
    # MÉTODOS DE ESCRITA DE BAIXO NÍVEL
    # ─────────────────────────────────────────────────────────────────────────
    
    def _write(self, data: bytes) -> None:
        """Escreve dados na impressora ou buffer."""
        if self._use_buffer:
            self._buffer.extend(data)
        elif self.connection and self.connection.is_open:
            self.connection.write(data)
    
    def _write_text(self, text: str) -> None:
        """Escreve texto codificado na impressora com suporte a português e simulador MiniPrint."""
        # Corrige textos vindos com barras literais "\\n"/"\\r\\n".
        # Esse era um dos motivos do cupom sair quebrado/desfocado/irregular no simulador.
        text = str(text or '')
        text = (text
                .replace('\\\\r\\\\n', '\n')
                .replace('\\\\n', '\n')
                .replace('\\\\r', '\n')
                .replace('\r\n', '\n')
                .replace('\r', '\n'))

        enc = (self._encoding or 'cp850').lower().replace('_', '-')

        # CORREÇÃO ESPECÍFICA PARA O SIMULADOR ANDROID MINIPRINT BT-580:
        # Alguns simuladores/app Bluetooth exibem acentos como símbolos mesmo recebendo UTF-8,
        # principalmente em combinações como ç, ã, õ, á, é, í, ó, ú, Nº etc.
        # Para cupom comercial é melhor imprimir sem acento do que imprimir caracteres quebrados.
        # Ex.: "CUPOM NÃO FISCAL" -> "CUPOM NAO FISCAL"; "Endereço" -> "Endereco".
        try:
            _profile_name = ((getattr(self.profile, 'model', '') or '') + ' ' + (getattr(self.profile, 'brand', '') or '')).lower()
        except Exception:
            _profile_name = ''
        if 'miniprint' in _profile_name or 'bt-580' in _profile_name:
            text = self._sanitize_text_for_miniprint(text)

        # O simulador Android MiniPrint BT-580 recebe melhor texto limpo/ASCII.
        # Mantemos UTF-8 para não quebrar o protocolo, mas o texto já vem sem acentos problemáticos.
        if enc in ('utf-8', 'utf8'):
            encoded = text.encode('utf-8', errors='replace')
            self._write(encoded)
            return

        try:
            encoded = text.encode(self._encoding)
        except UnicodeEncodeError:
            # Para impressoras físicas ESC/POS, tenta páginas de código comuns no Brasil.
            fallback_encodings = ['cp850', 'cp860', 'cp858', 'cp1252']
            encoded = None
            for fb_enc in fallback_encodings:
                if fb_enc.lower() == enc:
                    continue
                try:
                    encoded = text.encode(fb_enc)
                    break
                except UnicodeEncodeError:
                    continue

            if encoded is None:
                # Último recurso: transliteração para ASCII, evitando o caractere �.
                _transliteration_map = {
                    '\u00e0': 'a', '\u00e1': 'a', '\u00e2': 'a', '\u00e3': 'a', '\u00e4': 'a',
                    '\u00c0': 'A', '\u00c1': 'A', '\u00c2': 'A', '\u00c3': 'A', '\u00c4': 'A',
                    '\u00e8': 'e', '\u00e9': 'e', '\u00ea': 'e', '\u00eb': 'e',
                    '\u00c8': 'E', '\u00c9': 'E', '\u00ca': 'E', '\u00cb': 'E',
                    '\u00ec': 'i', '\u00ed': 'i', '\u00ee': 'i', '\u00ef': 'i',
                    '\u00cc': 'I', '\u00cd': 'I', '\u00ce': 'I', '\u00cf': 'I',
                    '\u00f2': 'o', '\u00f3': 'o', '\u00f4': 'o', '\u00f5': 'o', '\u00f6': 'o',
                    '\u00d2': 'O', '\u00d3': 'O', '\u00d4': 'O', '\u00d5': 'O', '\u00d6': 'O',
                    '\u00f9': 'u', '\u00fa': 'u', '\u00fb': 'u', '\u00fc': 'u',
                    '\u00d9': 'U', '\u00da': 'U', '\u00db': 'U', '\u00dc': 'U',
                    '\u00e7': 'c', '\u00c7': 'C',
                    '\u00f1': 'n', '\u00d1': 'N',
                    '\u00ba': 'o', '\u00aa': 'a',
                }
                transliterated = ''.join(_transliteration_map.get(c, c) for c in text)
                encoded = transliterated.encode('ascii', errors='replace')
        self._write(encoded)

    def _sanitize_text_for_miniprint(self, text: str) -> str:
        """Remove acentos/caracteres que o simulador MiniPrint BT-580 transforma em símbolos."""
        import unicodedata
        text = str(text or '')
        special_map = {
            'ç': 'c', 'Ç': 'C',
            'ã': 'a', 'Ã': 'A', 'õ': 'o', 'Õ': 'O',
            'á': 'a', 'Á': 'A', 'à': 'a', 'À': 'A', 'â': 'a', 'Â': 'A', 'ä': 'a', 'Ä': 'A',
            'é': 'e', 'É': 'E', 'ê': 'e', 'Ê': 'E', 'è': 'e', 'È': 'E', 'ë': 'e', 'Ë': 'E',
            'í': 'i', 'Í': 'I', 'ì': 'i', 'Ì': 'I', 'î': 'i', 'Î': 'I', 'ï': 'i', 'Ï': 'I',
            'ó': 'o', 'Ó': 'O', 'ò': 'o', 'Ò': 'O', 'ô': 'o', 'Ô': 'O', 'ö': 'o', 'Ö': 'O',
            'ú': 'u', 'Ú': 'U', 'ù': 'u', 'Ù': 'U', 'û': 'u', 'Û': 'U', 'ü': 'u', 'Ü': 'U',
            'ñ': 'n', 'Ñ': 'N',
            'º': 'o', 'ª': 'a', '°': 'o',
            '–': '-', '—': '-', '“': '"', '”': '"', '‘': "'", '’': "'",
            '€': 'EUR', '₢': 'Cr$',
        }
        text = ''.join(special_map.get(ch, ch) for ch in text)
        # Remove qualquer acento/combinação Unicode restante sem gerar ? ou �.
        text = unicodedata.normalize('NFKD', text)
        text = ''.join(ch for ch in text if not unicodedata.combining(ch))
        # Mantém apenas caracteres seguros para o simulador/cupom.
        return text.encode('ascii', errors='replace').decode('ascii').replace('?', '')

    def raw(self, data: bytes) -> 'ThermalPrinter':
        """Envia dados brutos para a impressora."""
        self._write(data)
        return self
    
    def flush(self) -> 'ThermalPrinter':
        """Força envio de dados pendentes."""
        if self._use_buffer and self._buffer:
            if self.connection and self.connection.is_open:
                self.connection.write(bytes(self._buffer))
                self._buffer = bytearray()
        elif self.connection:
            self.connection.flush()
        return self
    
    def start_buffer(self) -> 'ThermalPrinter':
        """Inicia modo de buffer (acumula comandos antes de enviar)."""
        self._use_buffer = True
        self._buffer = bytearray()
        return self
    
    def end_buffer(self) -> 'ThermalPrinter':
        """Finaliza modo de buffer e envia dados."""
        self._use_buffer = False
        self.flush()
        return self
    
    # ─────────────────────────────────────────────────────────────────────────
    # INICIALIZAÇÃO E CONFIGURAÇÃO
    # ─────────────────────────────────────────────────────────────────────────
    
    def init(self) -> 'ThermalPrinter':
        """Inicializa/reseta a impressora e configura code page para caracteres especiais."""
        self._write(self.profile.init_sequence)
        # CORREÇÃO: Envia o comando ESC/POS de code page para a impressora física
        # para garantir que caracteres acentuados (ç, ã, õ, é, á, etc.) sejam
        # impressos corretamente. Sem isso, a impressora pode usar uma code page
        # padrão diferente da configurada no Python, causando caracteres estranhos.
        codepage_map = {
            'cp437': ESC_POS.CODEPAGE_PC437,
            'cp850': ESC_POS.CODEPAGE_PC850,
            'cp860': ESC_POS.CODEPAGE_PC860,
            'cp858': ESC_POS.CODEPAGE_PC858,
            'cp1252': ESC_POS.CODEPAGE_WPC1252,
            'cp852': ESC_POS.CODEPAGE_PC852,
            'cp866': ESC_POS.CODEPAGE_PC866,
        }
        enc = (self._encoding or '').lower().replace('_', '-')
        if enc in ('utf-8', 'utf8'):
            return self
        if enc in codepage_map:
            self._write(codepage_map[enc])
        return self
    
    def reset(self) -> 'ThermalPrinter':
        """Alias para init()."""
        return self.init()
    
    def set_encoding(self, encoding: str) -> 'ThermalPrinter':
        """Define a codificação de caracteres."""
        self._encoding = encoding
        
        # Envia comando de code page se suportado
        codepage_map = {
            'cp437': ESC_POS.CODEPAGE_PC437,
            'cp850': ESC_POS.CODEPAGE_PC850,
            'cp860': ESC_POS.CODEPAGE_PC860,
            'cp858': ESC_POS.CODEPAGE_PC858,
            'cp1252': ESC_POS.CODEPAGE_WPC1252,
            'cp852': ESC_POS.CODEPAGE_PC852,
            'cp866': ESC_POS.CODEPAGE_PC866,
        }
        
        if encoding.lower() in codepage_map:
            self._write(codepage_map[encoding.lower()])
        
        return self
    
    def set_codepage(self, page: int) -> 'ThermalPrinter':
        """Define code page por número."""
        self._write(b'\x1b\x74' + bytes([page]))
        return self
    
    # ─────────────────────────────────────────────────────────────────────────
    # FORMATAÇÃO DE TEXTO
    # ─────────────────────────────────────────────────────────────────────────
    
    def text(self, text: str) -> 'ThermalPrinter':
        """Imprime texto."""
        self._write_text(text)
        return self
    
    def ln(self, lines: int = 1) -> 'ThermalPrinter':
        """Avança linhas."""
        for _ in range(lines):
            self._write(ESC_POS.LF)
        return self
    
    def feed(self, lines: int = 1) -> 'ThermalPrinter':
        """Avança papel (linhas)."""
        if lines > 0:
            self._write(ESC_POS.FEED_LINES + bytes([min(lines, 255)]))
        return self
    
    def feed_dots(self, dots: int) -> 'ThermalPrinter':
        """Avança papel (pontos)."""
        self._write(ESC_POS.FEED_DOTS + bytes([min(dots, 255)]))
        return self
    
    def textln(self, text: str = "") -> 'ThermalPrinter':
        """Imprime texto com nova linha."""
        self._write_text(text)
        self._write(ESC_POS.LF)
        return self
    
    def println(self, text: str = "") -> 'ThermalPrinter':
        """Alias para textln()."""
        return self.textln(text)
    
    # Alinhamento
    def align(self, alignment: TextAlign) -> 'ThermalPrinter':
        """Define alinhamento do texto."""
        align_map = {
            TextAlign.LEFT: ESC_POS.ALIGN_LEFT,
            TextAlign.CENTER: ESC_POS.ALIGN_CENTER,
            TextAlign.RIGHT: ESC_POS.ALIGN_RIGHT,
        }
        self._write(align_map.get(alignment, ESC_POS.ALIGN_LEFT))
        return self
    
    def left(self) -> 'ThermalPrinter':
        """Alinha à esquerda."""
        return self.align(TextAlign.LEFT)
    
    def center(self) -> 'ThermalPrinter':
        """Centraliza texto."""
        return self.align(TextAlign.CENTER)
    
    def right(self) -> 'ThermalPrinter':
        """Alinha à direita."""
        return self.align(TextAlign.RIGHT)
    
    # Negrito
    def bold(self, on: bool = True) -> 'ThermalPrinter':
        """Liga/desliga negrito."""
        if self.profile.supports_bold:
            self._write(ESC_POS.BOLD_ON if on else ESC_POS.BOLD_OFF)
        return self
    
    def bold_on(self) -> 'ThermalPrinter':
        """Liga negrito."""
        return self.bold(True)
    
    def bold_off(self) -> 'ThermalPrinter':
        """Desliga negrito."""
        return self.bold(False)
    
    # Sublinhado
    def underline(self, mode: int = 1) -> 'ThermalPrinter':
        """Define sublinhado (0=off, 1=fino, 2=grosso)."""
        if self.profile.supports_underline:
            if mode == 0:
                self._write(ESC_POS.UNDERLINE_OFF)
            elif mode == 1:
                self._write(ESC_POS.UNDERLINE_1)
            else:
                self._write(ESC_POS.UNDERLINE_2)
        return self
    
    def underline_on(self) -> 'ThermalPrinter':
        """Liga sublinhado."""
        return self.underline(1)
    
    def underline_off(self) -> 'ThermalPrinter':
        """Desliga sublinhado."""
        return self.underline(0)
    
    # Tamanho do texto
    def set_size(self, width: int = 1, height: int = 1) -> 'ThermalPrinter':
        """Define tamanho do texto (1-8 para largura e altura)."""
        if self.profile.supports_double_size:
            width = max(1, min(8, width)) - 1
            height = max(1, min(8, height)) - 1
            size = (width << 4) | height
            self._write(b'\x1d\x21' + bytes([size]))
        return self
    
    def double_width(self, on: bool = True) -> 'ThermalPrinter':
        """Liga/desliga largura dupla."""
        if on:
            self._write(ESC_POS.CHAR_SIZE_2W)
        else:
            self._write(ESC_POS.CHAR_SIZE_NORMAL)
        return self
    
    def double_height(self, on: bool = True) -> 'ThermalPrinter':
        """Liga/desliga altura dupla."""
        if on:
            self._write(ESC_POS.CHAR_SIZE_2H)
        else:
            self._write(ESC_POS.CHAR_SIZE_NORMAL)
        return self
    
    def double_size(self, on: bool = True) -> 'ThermalPrinter':
        """Liga/desliga tamanho duplo (largura e altura)."""
        if on:
            self._write(ESC_POS.CHAR_SIZE_2X)
        else:
            self._write(ESC_POS.CHAR_SIZE_NORMAL)
        return self
    
    def normal_size(self) -> 'ThermalPrinter':
        """Retorna ao tamanho normal."""
        self._write(ESC_POS.CHAR_SIZE_NORMAL)
        return self
    
    # Inversão de cores
    def inverse(self, on: bool = True) -> 'ThermalPrinter':
        """Liga/desliga inversão de cores (branco no preto)."""
        if self.profile.supports_inverse:
            self._write(ESC_POS.INVERSE_ON if on else ESC_POS.INVERSE_OFF)
        return self
    
    def inverse_on(self) -> 'ThermalPrinter':
        """Liga inversão."""
        return self.inverse(True)
    
    def inverse_off(self) -> 'ThermalPrinter':
        """Desliga inversão."""
        return self.inverse(False)
    
    # Fonte
    def font(self, font: str = 'A') -> 'ThermalPrinter':
        """Seleciona fonte (A, B ou C)."""
        font_map = {
            'A': ESC_POS.FONT_A,
            'B': ESC_POS.FONT_B,
            'C': ESC_POS.FONT_C,
        }
        self._write(font_map.get(font.upper(), ESC_POS.FONT_A))
        return self
    
    # ─────────────────────────────────────────────────────────────────────────
    # MÉTODOS DE FORMATAÇÃO DE RECIBO
    # ─────────────────────────────────────────────────────────────────────────
    
    def separator(self, char: str = '-', width: int = None) -> 'ThermalPrinter':
        """Imprime linha separadora."""
        if width is None:
            width = self.profile.chars_per_line
        self.textln(char * width)
        return self
    
    def line(self, width: int = None) -> 'ThermalPrinter':
        """Imprime linha com traços."""
        return self.separator('-', width)
    
    def double_line(self, width: int = None) -> 'ThermalPrinter':
        """Imprime linha dupla."""
        return self.separator('=', width)
    
    def stars(self, width: int = None) -> 'ThermalPrinter':
        """Imprime linha de asteriscos."""
        return self.separator('*', width)
    
    def row(self, left: str, right: str, fill: str = ' ') -> 'ThermalPrinter':
        """Imprime linha com texto à esquerda e direita."""
        width = self.profile.chars_per_line
        left_len = len(left)
        right_len = len(right)
        fill_len = width - left_len - right_len
        
        if fill_len < 1:
            # Se não couber, trunca
            self.textln(left[:width])
        else:
            self.textln(left + (fill * fill_len) + right)
        
        return self
    
    def columns(self, *cols, widths: List[int] = None) -> 'ThermalPrinter':
        """Imprime texto em colunas."""
        total_width = self.profile.chars_per_line
        num_cols = len(cols)
        
        if widths is None:
            # Distribui igualmente
            col_width = total_width // num_cols
            widths = [col_width] * num_cols
            # Ajusta última coluna para preencher
            widths[-1] = total_width - (col_width * (num_cols - 1))
        
        line = ""
        for i, (col, width) in enumerate(zip(cols, widths)):
            col_text = str(col)[:width]
            if i == num_cols - 1:
                # Última coluna alinhada à direita
                line += col_text.rjust(width)
            else:
                line += col_text.ljust(width)
        
        self.textln(line)
        return self
    
    def item(self, description: str, quantity: float, unit_price: float, 
             total: float = None) -> 'ThermalPrinter':
        """Imprime item de venda formatado."""
        if total is None:
            total = quantity * unit_price
        
        width = self.profile.chars_per_line
        
        # Formata valores
        qty_str = f"{quantity:.0f}" if quantity == int(quantity) else f"{quantity:.2f}"
        price_str = f"{unit_price:.2f}"
        total_str = f"{total:.2f}"
        
        # Linha 1: Descrição (com word wrap para exibir completa)
        if len(description) <= width:
            self.textln(description)
        else:
            _palavras = description.split()
            _linha_atual = ""
            for _p in _palavras:
                if _linha_atual and len(_linha_atual) + 1 + len(_p) > width:
                    self.textln(_linha_atual)
                    _linha_atual = _p
                elif not _linha_atual:
                    _linha_atual = _p
                else:
                    _linha_atual += " " + _p
            if _linha_atual:
                self.textln(_linha_atual)
        
        # Linha 2: Qtd x Preço = Total
        detail = f"  {qty_str} x {price_str}"
        self.row(detail, total_str)
        
        return self
    
    def total(self, label: str, value: float) -> 'ThermalPrinter':
        """Imprime linha de total."""
        self.bold_on()
        self.row(label, f"{value:.2f}")
        self.bold_off()
        return self
    
    def header(self, text: str) -> 'ThermalPrinter':
        """Imprime cabeçalho centralizado em destaque."""
        self.center()
        self.bold_on()
        self.double_size(True)
        self.textln(text)
        self.double_size(False)
        self.bold_off()
        self.left()
        return self
    
    def subheader(self, text: str) -> 'ThermalPrinter':
        """Imprime subcabeçalho centralizado."""
        self.center()
        self.bold_on()
        self.textln(text)
        self.bold_off()
        self.left()
        return self
    
    # ─────────────────────────────────────────────────────────────────────────
    # CORTE DE PAPEL
    # ─────────────────────────────────────────────────────────────────────────
    
    def cut(self, partial: bool = True, feed: int = 3) -> 'ThermalPrinter':
        """Corta o papel."""
        if not self.profile.supports_cut:
            # Se não suporta corte, apenas avança papel
            self.feed(5)
            return self
        
        # Avança papel antes do corte
        if feed > 0:
            self.feed(feed)
        
        # Usa comando de corte do perfil ou padrão
        if partial and self.profile.supports_partial_cut:
            self._write(self.profile.cut_command)
        else:
            # Tenta corte total
            self._write(ESC_POS.CUT_FULL)
        
        return self
    
    def cut_full(self) -> 'ThermalPrinter':
        """Corte total do papel."""
        return self.cut(partial=False)
    
    def cut_partial(self) -> 'ThermalPrinter':
        """Corte parcial do papel."""
        return self.cut(partial=True)
    
    # ─────────────────────────────────────────────────────────────────────────
    # GAVETA DE DINHEIRO
    # ─────────────────────────────────────────────────────────────────────────
    
    def open_drawer(self, pin: int = 2) -> 'ThermalPrinter':
        """Abre a gaveta de dinheiro."""
        if not self.profile.supports_drawer:
            return self
        
        if pin == 2:
            self._write(ESC_POS.DRAWER_KICK_2)
        elif pin == 5:
            self._write(ESC_POS.DRAWER_KICK_5)
        else:
            self._write(self.profile.drawer_command)
        
        return self
    
    def kick_drawer(self) -> 'ThermalPrinter':
        """Alias para open_drawer()."""
        return self.open_drawer()
    
    # ─────────────────────────────────────────────────────────────────────────
    # CÓDIGO DE BARRAS
    # ─────────────────────────────────────────────────────────────────────────
    
    def barcode(
        self, 
        data: str, 
        barcode_type: BarcodeType = BarcodeType.CODE128,
        height: int = 80,
        width: int = 3,
        hri_position: str = 'below',
        hri_font: str = 'A'
    ) -> 'ThermalPrinter':
        """
        Imprime código de barras.
        
        Args:
            data: Dados do código de barras
            barcode_type: Tipo do código (CODE128, EAN13, etc.)
            height: Altura em pontos (1-255)
            width: Largura do módulo (2-6)
            hri_position: Posição do texto ('none', 'above', 'below', 'both')
            hri_font: Fonte do texto ('A' ou 'B')
        """
        if not self.profile.supports_barcode:
            return self
        
        # Configura posição HRI
        hri_map = {
            'none': ESC_POS.HRI_OFF,
            'above': ESC_POS.HRI_ABOVE,
            'below': ESC_POS.HRI_BELOW,
            'both': ESC_POS.HRI_BOTH,
        }
        self._write(hri_map.get(hri_position.lower(), ESC_POS.HRI_BELOW))
        
        # Configura fonte HRI
        self._write(ESC_POS.HRI_FONT_A if hri_font.upper() == 'A' else ESC_POS.HRI_FONT_B)
        
        # Configura altura
        self._write(ESC_POS.BARCODE_HEIGHT + bytes([min(255, max(1, height))]))
        
        # Configura largura
        self._write(ESC_POS.BARCODE_WIDTH + bytes([min(6, max(2, width))]))
        
        # Mapa de tipos de código de barras
        type_map = {
            BarcodeType.UPC_A: (65, None),
            BarcodeType.UPC_E: (66, None),
            BarcodeType.EAN13: (67, None),
            BarcodeType.EAN8: (68, None),
            BarcodeType.CODE39: (69, None),
            BarcodeType.ITF: (70, None),
            BarcodeType.CODABAR: (71, None),
            BarcodeType.CODE93: (72, None),
            BarcodeType.CODE128: (73, '{B'),  # Code set B para alfanumérico
        }
        
        bc_type, prefix = type_map.get(barcode_type, (73, '{B'))
        
        # Prepara dados
        if prefix:
            bc_data = prefix + data
        else:
            bc_data = data
        
        # Envia comando de código de barras (formato GS k m n d1...dn)
        self._write(b'\x1d\x6b' + bytes([bc_type, len(bc_data)]) + bc_data.encode('ascii', errors='replace'))
        
        return self
    
    def ean13(self, data: str, **kwargs) -> 'ThermalPrinter':
        """Imprime código de barras EAN-13."""
        return self.barcode(data, BarcodeType.EAN13, **kwargs)
    
    def ean8(self, data: str, **kwargs) -> 'ThermalPrinter':
        """Imprime código de barras EAN-8."""
        return self.barcode(data, BarcodeType.EAN8, **kwargs)
    
    def code128(self, data: str, **kwargs) -> 'ThermalPrinter':
        """Imprime código de barras Code 128."""
        return self.barcode(data, BarcodeType.CODE128, **kwargs)
    
    def code39(self, data: str, **kwargs) -> 'ThermalPrinter':
        """Imprime código de barras Code 39."""
        return self.barcode(data, BarcodeType.CODE39, **kwargs)
    
    # ─────────────────────────────────────────────────────────────────────────
    # QR CODE
    # ─────────────────────────────────────────────────────────────────────────
    
    def qrcode(
        self, 
        data: str, 
        size: int = 6,
        error_level: QRErrorLevel = QRErrorLevel.M
    ) -> 'ThermalPrinter':
        """
        Imprime QR Code.
        
        Args:
            data: Dados do QR Code
            size: Tamanho do módulo (1-16)
            error_level: Nível de correção de erro (L, M, Q, H)
        """
        if not self.profile.supports_qrcode:
            return self
        
        # Limita tamanho
        size = max(1, min(self.profile.max_qrcode_size, size))
        
        # Seleciona modelo 2
        self._write(ESC_POS.QRCODE_MODEL_2)
        
        # Define tamanho do módulo
        self._write(ESC_POS.QRCODE_SIZE_PREFIX + bytes([size]))
        
        # Define nível de correção de erro
        error_map = {
            QRErrorLevel.L: ESC_POS.QRCODE_ERROR_L,
            QRErrorLevel.M: ESC_POS.QRCODE_ERROR_M,
            QRErrorLevel.Q: ESC_POS.QRCODE_ERROR_Q,
            QRErrorLevel.H: ESC_POS.QRCODE_ERROR_H,
        }
        self._write(error_map.get(error_level, ESC_POS.QRCODE_ERROR_M))
        
        # Armazena dados
        data_bytes = data.encode('utf-8')
        data_len = len(data_bytes) + 3
        pL = data_len & 0xFF
        pH = (data_len >> 8) & 0xFF
        self._write(ESC_POS.QRCODE_STORE_PREFIX + bytes([pL, pH, 0x31, 0x50, 0x30]) + data_bytes)
        
        # Imprime QR Code
        self._write(ESC_POS.QRCODE_PRINT)
        
        return self
    
    # ─────────────────────────────────────────────────────────────────────────
    # IMAGEM
    # ─────────────────────────────────────────────────────────────────────────
    
    def image(
        self, 
        image_path: str = None,
        image_data: bytes = None,
        width: int = None,
        align: TextAlign = TextAlign.CENTER
    ) -> 'ThermalPrinter':
        """
        Imprime imagem.
        
        Args:
            image_path: Caminho para arquivo de imagem
            image_data: Dados da imagem em bytes
            width: Largura máxima em pixels (None = largura do papel)
            align: Alinhamento da imagem
        """
        if not self.profile.supports_image:
            return self
        
        try:
            from PIL import Image
            import io
            
            # Carrega imagem
            if image_path:
                img = Image.open(image_path)
            elif image_data:
                img = Image.open(io.BytesIO(image_data))
            else:
                return self
            
            # Converte para escala de cinza e depois para 1-bit
            img = img.convert('L')
            
            # Redimensiona se necessário
            max_width = width or (self.profile.paper_width * 8 - 16)  # ~8 dots/mm
            if img.width > max_width:
                ratio = max_width / img.width
                new_height = int(img.height * ratio)
                img = img.resize((max_width, new_height), Image.LANCZOS)
            
            # Converte para 1-bit (preto e branco)
            img = img.convert('1')
            
            # Define alinhamento
            self.align(align)
            
            # Gera dados raster
            width_bytes = (img.width + 7) // 8
            
            # Comando GS v 0
            self._write(ESC_POS.IMAGE_RASTER + bytes([0]))  # modo 0 = normal
            self._write(bytes([width_bytes & 0xFF, (width_bytes >> 8) & 0xFF]))
            self._write(bytes([img.height & 0xFF, (img.height >> 8) & 0xFF]))
            
            # Envia dados da imagem
            pixels = list(img.getdata())
            for y in range(img.height):
                row_data = bytearray()
                for x_byte in range(width_bytes):
                    byte_val = 0
                    for bit in range(8):
                        x = x_byte * 8 + bit
                        if x < img.width:
                            pixel_idx = y * img.width + x
                            if pixels[pixel_idx] == 0:  # Preto
                                byte_val |= (0x80 >> bit)
                    row_data.append(byte_val)
                self._write(bytes(row_data))
            
            self.left()
            
        except ImportError:
            # PIL não disponível
            pass
        except Exception:
            pass
        
        return self
    
    # ─────────────────────────────────────────────────────────────────────────
    # STATUS DA IMPRESSORA
    # ─────────────────────────────────────────────────────────────────────────
    
    def get_status(self) -> Dict[str, Any]:
        """Obtém status da impressora (se suportado)."""
        status = {
            'connected': self.is_connected(),
            'paper_present': None,
            'drawer_open': None,
            'error': None,
        }
        
        if not self.is_connected():
            return status
        
        try:
            # Envia comando de status do papel
            self._write(ESC_POS.STATUS_PAPER)
            response = self.connection.read(1, timeout=0.5)
            
            if response:
                byte = response[0]
                status['paper_present'] = not (byte & 0x60)  # Bits 5 e 6 indicam fim de papel
                status['error'] = bool(byte & 0x08)  # Bit 3 indica erro
        except Exception:
            pass  # Exceção silenciada intencionalmente
        
        return status
    
    def has_paper(self) -> bool:
        """Verifica se há papel na impressora."""
        status = self.get_status()
        return status.get('paper_present', True)


# ═══════════════════════════════════════════════════════════════════════════════
# FACTORY E AUTO-DETECÇÃO
# ═══════════════════════════════════════════════════════════════════════════════

class ThermalPrinterFactory:
    """
    Factory para criação de impressoras térmicas.
    Facilita a configuração e auto-detecção de impressoras.
    """
    
    # IDs de fabricantes USB conhecidos
    USB_VENDORS = {
        0x04B8: PrinterBrand.EPSON,      # Epson
        0x0519: PrinterBrand.ELGIN,      # Elgin
        0x0DD4: PrinterBrand.BEMATECH,   # Bematech
        0x0483: PrinterBrand.XPRINTER,   # STMicroelectronics (usado por Xprinter)
        0x0416: PrinterBrand.GPRINTER,   # Winbond (usado por Gprinter)
        0x1504: PrinterBrand.ZJIANG,     # ZJiang
        0x0FE6: PrinterBrand.HPRT,       # HPRT
        0x154F: PrinterBrand.DARUMA,     # Daruma
        0x0B00: PrinterBrand.SWEDA,      # Sweda
        0x0525: PrinterBrand.GENERIC,    # Genérico (PLX)
        0x1A86: PrinterBrand.GENERIC,    # CH340 (USB-Serial chinês)
        0x067B: PrinterBrand.GENERIC,    # Prolific (USB-Serial)
        0x0403: PrinterBrand.GENERIC,    # FTDI (USB-Serial)
    }
    
    @classmethod
    def create_windows_raw(
        cls,
        printer_name: str = "",
        profile: PrinterProfile = None,
        auto_detect_profile: bool = True
    ) -> ThermalPrinter:
        """
        Cria impressora usando Windows RAW printing.
        
        Args:
            printer_name: Nome da impressora no Windows (vazio = padrão)
            profile: Perfil da impressora
            auto_detect_profile: Tenta detectar perfil pelo nome
        """
        connection = WindowsRawConnection(printer_name)
        
        if profile is None and auto_detect_profile and printer_name:
            profile = cls._detect_profile_from_name(printer_name)
        
        return ThermalPrinter(connection, profile or PrinterProfile())
    
    @classmethod
    def create_windows_driver(
        cls,
        printer_name: str = "",
        profile: PrinterProfile = None
    ) -> ThermalPrinter:
        """
        Cria impressora usando driver do Windows (spooler).
        Útil para impressoras que não suportam RAW.
        """
        connection = WindowsDriverConnection(printer_name)
        return ThermalPrinter(connection, profile or PrinterProfile())
    
    @classmethod
    def create_serial(
        cls,
        port: str,
        baudrate: int = 9600,
        profile: PrinterProfile = None,
        **serial_kwargs
    ) -> ThermalPrinter:
        """
        Cria impressora usando conexão serial.
        
        Args:
            port: Porta serial (COM1, /dev/ttyUSB0, etc.)
            baudrate: Taxa de transmissão
            profile: Perfil da impressora
            **serial_kwargs: Argumentos adicionais para pyserial
        """
        connection = SerialConnection(
            port=port,
            baudrate=baudrate,
            **serial_kwargs
        )
        return ThermalPrinter(connection, profile or PrinterProfile())
    
    @classmethod
    def create_bluetooth(
        cls,
        port: str,
        baudrate: int = 9600,
        profile: PrinterProfile = None,
        **serial_kwargs
    ) -> ThermalPrinter:
        """
        Cria impressora Bluetooth pareada.

        Observação importante:
        No Windows, a maioria das impressoras térmicas Bluetooth aparece como
        uma porta COM após o pareamento. Por isso a comunicação Bluetooth usa
        o mesmo canal serial/RFCOMM, mantendo compatibilidade com ESC/POS.
        """
        return cls.create_serial(
            port=port or "COM1",
            baudrate=baudrate,
            profile=profile,
            **serial_kwargs
        )
    
    @classmethod
    def create_network(
        cls,
        host: str,
        port: int = 9100,
        profile: PrinterProfile = None,
        timeout: float = 10.0
    ) -> ThermalPrinter:
        """
        Cria impressora usando conexão de rede.
        
        Args:
            host: Endereço IP ou hostname
            port: Porta TCP (geralmente 9100)
            profile: Perfil da impressora
            timeout: Timeout de conexão
        """
        connection = NetworkConnection(host, port, timeout)
        return ThermalPrinter(connection, profile or PrinterProfile())
    
    @classmethod
    def create_usb(
        cls,
        vendor_id: int = None,
        product_id: int = None,
        profile: PrinterProfile = None,
        **usb_kwargs
    ) -> ThermalPrinter:
        """
        Cria impressora usando conexão USB nativa.
        
        Args:
            vendor_id: ID do fabricante USB
            product_id: ID do produto USB
            profile: Perfil da impressora
        """
        connection = USBConnection(
            vendor_id=vendor_id,
            product_id=product_id,
            **usb_kwargs
        )
        
        if profile is None and vendor_id:
            brand = cls.USB_VENDORS.get(vendor_id, PrinterBrand.GENERIC)
            profile = PrinterProfile(brand=brand)
        
        return ThermalPrinter(connection, profile or PrinterProfile())
    
    @classmethod
    def create_file(
        cls,
        path: str,
        profile: PrinterProfile = None
    ) -> ThermalPrinter:
        """
        Cria impressora usando arquivo/dispositivo.
        
        Args:
            path: Caminho do arquivo ou dispositivo
            profile: Perfil da impressora
        """
        connection = FileConnection(path)
        return ThermalPrinter(connection, profile or PrinterProfile())
    
    @classmethod
    def create_auto(
        cls,
        printer_name: str = None,
        profile: PrinterProfile = None
    ) -> ThermalPrinter:
        """
        Cria impressora com auto-detecção do tipo de conexão.
        
        Tenta na seguinte ordem:
        1. Windows RAW (se no Windows e nome fornecido)
        2. USB nativo
        3. Serial
        4. Windows driver padrão
        """
        # Windows com nome de impressora
        if platform.system() == "Windows":
            try:
                printer = cls.create_windows_raw(printer_name or "", profile)
                printer.connect()
                return printer
            except Exception:
                pass  # Exceção silenciada intencionalmente
        
        # Tenta USB
        try:
            devices = USBConnection.list_devices()
            for dev in devices:
                if dev['vendor_id'] in cls.USB_VENDORS:
                    try:
                        printer = cls.create_usb(
                            dev['vendor_id'],
                            dev['product_id'],
                            profile
                        )
                        printer.connect()
                        return printer
                    except Exception:
                        continue
        except Exception:
            pass  # Exceção silenciada intencionalmente
        
        # Tenta Serial
        try:
            ports = SerialConnection.list_ports()
            for port in ports:
                try:
                    printer = cls.create_serial(port, profile=profile)
                    printer.connect()
                    return printer
                except Exception:
                    continue
        except Exception:
            pass  # Exceção silenciada intencionalmente
        
        # Fallback para Windows driver
        if platform.system() == "Windows":
            return cls.create_windows_driver(printer_name or "", profile)
        
        raise ConnectionError("Nenhuma impressora térmica encontrada")
    
    @classmethod
    def _detect_profile_from_name(cls, name: str) -> PrinterProfile:
        """Detecta perfil da impressora pelo nome."""
        name_lower = name.lower()
        
        # Verifica modelos conhecidos
        for model_name, profile in PRINTER_PROFILES.items():
            if model_name.lower() in name_lower:
                return profile
        
        # Verifica marcas
        brand_keywords = {
            PrinterBrand.EPSON: ['epson', 'tm-t', 'tm-u'],
            PrinterBrand.BEMATECH: ['bematech', 'mp-'],
            PrinterBrand.ELGIN: ['elgin', 'i7', 'i9', 'vox'],
            PrinterBrand.DARUMA: ['daruma', 'dr700', 'dr800'],
            PrinterBrand.XPRINTER: ['xprinter', 'xp-'],
            PrinterBrand.GPRINTER: ['gprinter', 'gp-'],
            PrinterBrand.ZJIANG: ['zjiang', 'zj-'],
            PrinterBrand.HPRT: ['hprt'],
        }
        
        for brand, keywords in brand_keywords.items():
            for keyword in keywords:
                if keyword in name_lower:
                    # Detecta largura pelo nome
                    if '58' in name_lower:
                        return PrinterProfile.for_58mm(brand)
                    else:
                        return PrinterProfile.for_80mm(brand)
        
        # Padrão genérico 80mm
        return PrinterProfile.for_80mm(PrinterBrand.GENERIC)
    
    @classmethod
    def list_windows_printers(cls) -> List[Dict[str, str]]:
        """Lista impressoras disponíveis no Windows."""
        try:
            import win32print
            printers = []
            
            for flags, desc, name, comment in win32print.EnumPrinters(
                win32print.PRINTER_ENUM_LOCAL | win32print.PRINTER_ENUM_CONNECTIONS
            ):
                printers.append({
                    'name': name,
                    'description': desc,
                    'comment': comment,
                    'is_default': name == win32print.GetDefaultPrinter()
                })
            
            return printers
        except Exception:
            return []
    
    @classmethod
    def list_serial_ports(cls) -> List[str]:
        """Lista portas seriais disponíveis."""
        return SerialConnection.list_ports()

    @classmethod
    def list_bluetooth_ports(cls) -> List[Dict[str, str]]:
        """Lista aparelhos Bluetooth emparelhados diretamente do Windows.

        Correção reforçada:
        - Lê os aparelhos pareados pela API moderna do Windows/WinRT, que é a
          fonte mais próxima da tela Configurações > Bluetooth e dispositivos.
        - Lê também PnP/CIM e Registro do Windows para pegar nomes que a API
          WinRT não devolve em algumas versões do Windows.
        - Associa automaticamente a porta COM quando o serviço Bluetooth Serial
          SPP/RFCOMM já foi criado.

        Observação importante: o aparelho pode aparecer na lista mesmo sem COM.
        Para imprimir em impressora térmica Bluetooth clássica ESC/POS, o Windows
        precisa ter criado uma porta COM de saída para esse aparelho.
        """
        dispositivos = []
        por_chave = {}

        def _normalizar_mac(valor):
            import re
            texto = str(valor or '').upper()
            m = re.search(r'([0-9A-F]{2}[:\-]){5}[0-9A-F]{2}', texto)
            if m:
                return re.sub(r'[^0-9A-F]', '', m.group(0).upper())
            m = re.search(r'(?:DEV_|DEVICE_|BTHENUM\\[^\\]*_)?([0-9A-F]{12})', texto)
            return m.group(1).upper() if m else ''

        def _limpar_nome(nome):
            nome = str(nome or '').replace('@', '').strip()
            if ';' in nome:
                nome = nome.split(';')[-1].strip()
            lixo = (
                'microsoft bluetooth enumerator', 'bluetooth device',
                'dispositivo bluetooth', 'enumerador bluetooth',
                'qualcomm', 'intel(r)', 'realtek bluetooth', 'radio bluetooth',
                'adaptador bluetooth', 'generic bluetooth adapter'
            )
            baixo = nome.lower()
            if baixo in lixo:
                return ''
            return nome

        def _decode_reg_name(valor):
            try:
                if isinstance(valor, bytes):
                    bruto = valor.strip(b'\x00')
                    candidatos = []
                    for enc in ('utf-16-le', 'utf-8', 'latin1'):
                        try:
                            candidatos.append(bruto.decode(enc, errors='ignore'))
                        except Exception:
                            pass
                    for nome in candidatos:
                        nome = _limpar_nome(nome.strip('\x00 ').strip())
                        if nome and len(nome) >= 2:
                            return nome
                    return ''
                return _limpar_nome(str(valor or '').strip())
            except Exception:
                return ''

        def _add(nome='', porta='', descricao='', hwid='', origem='', paired=True, kind='bluetooth_device', printer_name=''):
            nome = _limpar_nome(nome) or _limpar_nome(descricao) or 'Dispositivo Bluetooth'
            porta = str(porta or '').strip().upper()
            descricao = str(descricao or '').strip()
            hwid = str(hwid or '').strip()
            origem = str(origem or '').strip()
            kind = str(kind or 'bluetooth_device').strip()
            printer_name = str(printer_name or '').strip()
            mac = _normalizar_mac(hwid) or _normalizar_mac(descricao) or _normalizar_mac(nome)

            texto_filtro = ' '.join([nome, descricao, hwid]).lower()
            filtros = (
                'enumerator', 'enumerador', 'adapter', 'adaptador', 'radio',
                'intel wireless bluetooth', 'realtek bluetooth adapter',
                'microsoft bluetooth le enumerator'
            )
            if kind != 'windows_printer' and any(f in texto_filtro for f in filtros) and not porta:
                return

            chave = ('WINPRINTER:' + printer_name.lower()) if kind == 'windows_printer' and printer_name else (mac or porta or nome.lower())
            existente = por_chave.get(chave)
            if existente:
                if porta and not existente.get('port'):
                    existente['port'] = porta
                if printer_name and not existente.get('printer_name'):
                    existente['printer_name'] = printer_name
                if kind and existente.get('kind') != 'windows_printer':
                    existente['kind'] = kind
                if nome and (existente.get('name') in ('Dispositivo Bluetooth', '') or len(nome) > len(existente.get('name', ''))):
                    existente['name'] = nome
                if descricao and not existente.get('description'):
                    existente['description'] = descricao
                if hwid and not existente.get('hwid'):
                    existente['hwid'] = hwid
                if origem and origem not in existente.get('source', ''):
                    existente['source'] = (existente.get('source', '') + ',' + origem).strip(',')
                existente['paired'] = existente.get('paired', False) or bool(paired)
                return

            item = {
                'port': porta,
                'name': nome,
                'description': descricao,
                'hwid': hwid,
                'mac': mac,
                'source': origem,
                'paired': bool(paired),
                'kind': kind,
                'printer_name': printer_name,
            }
            por_chave[chave] = item
            dispositivos.append(item)

        def _executar_powershell(script, timeout=12):
            """Executa PowerShell oculto e retorna JSON já decodificado."""
            try:
                import json
                import subprocess
                flags = 0x08000000 if platform.system() == 'Windows' else 0
                cmd = ['powershell.exe', '-NoProfile', '-ExecutionPolicy', 'Bypass', '-Command', script]
                proc = subprocess.run(cmd, capture_output=True, text=True, timeout=timeout, creationflags=flags)
                saida = (proc.stdout or '').strip()
                if not saida:
                    return []
                dados = json.loads(saida)
                if isinstance(dados, dict):
                    return [dados]
                return dados if isinstance(dados, list) else []
            except Exception:
                return []

        # 1) Primeiro: impressoras que aparecem em Configurações > Impressoras e scanners.
        # Essas impressoras podem ser Bluetooth, USB ou virtuais. Se o usuário escolher uma delas,
        # o sistema imprime pelo driver/spooler do Windows, sem exigir porta COM.
        try:
            for p in cls.list_windows_printers():
                nome_imp = str(p.get('name') or '').strip()
                if nome_imp:
                    origem = 'Impressoras e scanners do Windows'
                    if p.get('is_default'):
                        origem += ' / padrão'
                    _add(
                        nome=nome_imp,
                        descricao=str(p.get('comment') or 'Impressora instalada no Windows'),
                        hwid='WINPRINTER:' + nome_imp,
                        origem=origem,
                        paired=True,
                        kind='windows_printer',
                        printer_name=nome_imp
                    )
        except Exception:
            pass

        if platform.system() == 'Windows':
            ps_winrt = """
$ErrorActionPreference = 'SilentlyContinue'
Add-Type -AssemblyName System.Runtime.WindowsRuntime | Out-Null
[Windows.Devices.Enumeration.DeviceInformation,Windows.Devices.Enumeration,ContentType=WindowsRuntime] | Out-Null
[Windows.Devices.Bluetooth.BluetoothDevice,Windows.Devices.Bluetooth,ContentType=WindowsRuntime] | Out-Null
[Windows.Devices.Bluetooth.BluetoothLEDevice,Windows.Devices.Bluetooth,ContentType=WindowsRuntime] | Out-Null
$asTaskGeneric = ([System.WindowsRuntimeSystemExtensions].GetMethods() | Where-Object { $_.Name -eq 'AsTask' -and $_.IsGenericMethod -and $_.GetParameters().Count -eq 1 } | Select-Object -First 1)
function AwaitWinRT($Operation, $ResultType) {
    $asTask = $asTaskGeneric.MakeGenericMethod($ResultType)
    $task = $asTask.Invoke($null, @($Operation))
    $task.Wait() | Out-Null
    return $task.Result
}
$resultado = @()
$selectors = @(
    [Windows.Devices.Bluetooth.BluetoothDevice]::GetDeviceSelectorFromPairingState($true),
    [Windows.Devices.Bluetooth.BluetoothLEDevice]::GetDeviceSelectorFromPairingState($true)
)
foreach ($selector in $selectors) {
    $op = [Windows.Devices.Enumeration.DeviceInformation]::FindAllAsync($selector)
    $lista = AwaitWinRT $op ([System.Collections.Generic.IReadOnlyList[Windows.Devices.Enumeration.DeviceInformation]])
    foreach ($d in $lista) {
        if ($d.Name) {
            $resultado += [PSCustomObject]@{ Name = $d.Name; Id = $d.Id; Status = 'Paired'; Source = 'WinRT Bluetooth Settings' }
        }
    }
}
$resultado | Sort-Object Name -Unique | ConvertTo-Json -Compress
"""
            for dev in _executar_powershell(ps_winrt, timeout=15):
                _add(nome=dev.get('Name', ''), descricao=dev.get('Status', 'Paired'), hwid=dev.get('Id', ''), origem=dev.get('Source', 'WinRT Bluetooth Settings'), paired=True)

            ps_pnp = """
$ErrorActionPreference = 'SilentlyContinue'
$items = @()
$items += Get-CimInstance Win32_PnPEntity | Where-Object {
    $_.PNPDeviceID -like 'BTHENUM\\*' -or $_.PNPDeviceID -like 'BTHLE\\*' -or $_.Service -match 'BTH|RFCOMM'
} | ForEach-Object {
    [PSCustomObject]@{ Name = $_.Name; Id = $_.PNPDeviceID; Status = $_.Status; Source = 'CIM Bluetooth/PnP' }
}
if (Get-Command Get-PnpDevice -ErrorAction SilentlyContinue) {
    $items += Get-PnpDevice | Where-Object {
        $_.InstanceId -like 'BTHENUM\\*' -or $_.InstanceId -like 'BTHLE\\*' -or $_.Class -eq 'Bluetooth'
    } | ForEach-Object {
        [PSCustomObject]@{ Name = $_.FriendlyName; Id = $_.InstanceId; Status = $_.Status; Source = 'Get-PnpDevice Bluetooth' }
    }
}
$items | Where-Object { $_.Name } | Sort-Object Name -Unique | ConvertTo-Json -Compress
"""
            for dev in _executar_powershell(ps_pnp, timeout=12):
                _add(nome=dev.get('Name', ''), descricao=dev.get('Status', ''), hwid=dev.get('Id', ''), origem=dev.get('Source', 'PnP Bluetooth'), paired=True)

            ps_bluetooth_settings = """
$ErrorActionPreference = 'SilentlyContinue'
$items = @()
$items += Get-PnpDevice -PresentOnly | Where-Object {
    $_.InstanceId -like 'BTHENUM\\*' -or $_.InstanceId -like 'BTHLE\\*' -or $_.InstanceId -like 'SWD\\WPDBUSENUM\\*' -or $_.Class -eq 'Bluetooth'
} | ForEach-Object {
    [PSCustomObject]@{ Name = $_.FriendlyName; Id = $_.InstanceId; Status = $_.Status; Source = 'Bluetooth e dispositivos do Windows' }
}
$items | Where-Object { $_.Name } | Sort-Object Name -Unique | ConvertTo-Json -Compress
"""
            for dev in _executar_powershell(ps_bluetooth_settings, timeout=12):
                _add(nome=dev.get('Name', ''), descricao=dev.get('Status', ''), hwid=dev.get('Id', ''), origem=dev.get('Source', 'Bluetooth Settings/PnP'), paired=True)

            try:
                import winreg
                for base in (
                    r'SYSTEM\CurrentControlSet\Services\BTHPORT\Parameters\Devices',
                    r'SYSTEM\CurrentControlSet\Services\BTHPORT\Parameters\Keys'
                ):
                    try:
                        with winreg.OpenKey(winreg.HKEY_LOCAL_MACHINE, base) as root:
                            i = 0
                            while True:
                                try:
                                    mac_key = winreg.EnumKey(root, i)
                                    i += 1
                                except OSError:
                                    break
                                try:
                                    with winreg.OpenKey(root, mac_key) as dev_key:
                                        nome = ''
                                        for valor_nome in ('Name', 'DeviceName', 'FriendlyName', 'DeviceDesc'):
                                            try:
                                                valor = winreg.QueryValueEx(dev_key, valor_nome)[0]
                                                nome = _decode_reg_name(valor)
                                                if nome:
                                                    break
                                            except Exception:
                                                pass
                                        _add(nome=nome or f'Bluetooth {mac_key}', descricao='Aparelho pareado no Windows', hwid=mac_key, origem='Registro Bluetooth Windows', paired=True)
                                except Exception:
                                    pass
                    except Exception:
                        pass
            except Exception:
                pass

            try:
                import winreg
                def _read_value(key, value_name):
                    try:
                        return winreg.QueryValueEx(key, value_name)[0]
                    except Exception:
                        return ''
                def _walk(root, path, depth=0):
                    if depth > 14:
                        return
                    try:
                        with winreg.OpenKey(root, path) as key:
                            port_name = _read_value(key, 'PortName')
                            friendly = _read_value(key, 'FriendlyName') or _read_value(key, 'DeviceDesc')
                            nome = _decode_reg_name(friendly)
                            if port_name and str(port_name).upper().startswith('COM'):
                                _add(nome=nome or 'Dispositivo Bluetooth Serial', porta=str(port_name).upper(), descricao=nome, hwid=path, origem='Porta COM Bluetooth/RFCOMM', paired=True)
                            i = 0
                            while True:
                                try:
                                    sub = winreg.EnumKey(key, i)
                                    _walk(root, path + '\\' + sub, depth + 1)
                                    i += 1
                                except OSError:
                                    break
                    except Exception:
                        return
                for base in (
                    r'SYSTEM\CurrentControlSet\Enum\BTHENUM',
                    r'SYSTEM\CurrentControlSet\Enum\BTHLE',
                    r'SYSTEM\CurrentControlSet\Enum\RFCOMM',
                    r'SYSTEM\CurrentControlSet\Enum\SERENUM',
                ):
                    _walk(winreg.HKEY_LOCAL_MACHINE, base)
            except Exception:
                pass


        # EXTRA: varredura completa do Registro PnP Bluetooth.
        # Esta parte pega os aparelhos que aparecem em Configurações > Bluetooth e outros dispositivos,
        # inclusive fones/áudio/celulares que não têm porta COM nem aparecem como impressora.
        if sys.platform.startswith('win'):
            try:
                import winreg

                def _bt_read_value_extra(key, value_name):
                    try:
                        return winreg.QueryValueEx(key, value_name)[0]
                    except Exception:
                        return ''

                def _bt_read_first_extra(key, names):
                    for n in names:
                        v = _bt_read_value_extra(key, n)
                        texto = _decode_reg_name(v)
                        if texto:
                            return texto
                    return ''

                def _bt_walk_enum_extra(root, path, depth=0):
                    if depth > 12:
                        return
                    try:
                        with winreg.OpenKey(root, path) as key:
                            port_name = str(_bt_read_value_extra(key, 'PortName') or '').upper().strip()
                            nome = _bt_read_first_extra(key, ('FriendlyName', 'DeviceDesc', 'Name', 'Mfg', 'Service'))
                            hwid = path
                            texto_path = path.upper()
                            eh_bt = any(x in texto_path for x in (
                                'BTHENUM', 'BTHLE', 'BTHHFENUM', 'BTHPAN', 'BTHMODEM', 'RFCOMM', 'BTHMINI'
                            ))
                            if eh_bt and nome:
                                _add(
                                    nome=nome,
                                    porta=port_name if port_name.startswith('COM') else '',
                                    descricao=nome,
                                    hwid=hwid,
                                    origem='Registro Enum Bluetooth completo',
                                    paired=True,
                                    kind='bluetooth_com' if port_name.startswith('COM') else 'bluetooth_device'
                                )

                            i = 0
                            while True:
                                try:
                                    sub = winreg.EnumKey(key, i)
                                    _bt_walk_enum_extra(root, path + '\\' + sub, depth + 1)
                                    i += 1
                                except OSError:
                                    break
                    except Exception:
                        return

                for _bt_base_extra in (
                    r'SYSTEM\CurrentControlSet\Enum\BTHENUM',
                    r'SYSTEM\CurrentControlSet\Enum\BTHLE',
                    r'SYSTEM\CurrentControlSet\Enum\BTHHFENUM',
                    r'SYSTEM\CurrentControlSet\Enum\BTHPAN',
                    r'SYSTEM\CurrentControlSet\Enum\BTHMODEM',
                    r'SYSTEM\CurrentControlSet\Enum\RFCOMM',
                ):
                    _bt_walk_enum_extra(winreg.HKEY_LOCAL_MACHINE, _bt_base_extra)
            except Exception:
                pass

        # EXTRA: PowerShell amplo para pegar classes que o Windows mostra em Bluetooth,
        # mas registra como AudioEndpoint, MEDIA, HID, Mouse, Keyboard, WPD etc.
        if sys.platform.startswith('win'):
            ps_bt_amplo_extra = r'''$ErrorActionPreference = 'SilentlyContinue'
$items = @()
$classes = @('Bluetooth','AudioEndpoint','MEDIA','HIDClass','Ports','Modem','Net','Mouse','Keyboard','Image','WPD')
$items += Get-CimInstance Win32_PnPEntity | Where-Object {
    $_.PNPDeviceID -match 'BTHENUM|BTHLE|BTHHFENUM|BTHPAN|BTHMODEM|RFCOMM|BTHMINI|Bluetooth' -or
    $_.Service -match 'BTH|RFCOMM|BthHFEnum|BthEnum' -or
    $_.Name -match 'Bluetooth'
} | ForEach-Object {
    [PSCustomObject]@{ Name = $_.Name; Id = $_.PNPDeviceID; Status = $_.Status; Class = $_.PNPClass; Source = 'CIM Bluetooth completo' }
}
if (Get-Command Get-PnpDevice -ErrorAction SilentlyContinue) {
    $items += Get-PnpDevice | Where-Object {
        $_.InstanceId -match 'BTHENUM|BTHLE|BTHHFENUM|BTHPAN|BTHMODEM|RFCOMM|BTHMINI|Bluetooth' -or
        ($_.Class -in $classes -and ($_.InstanceId -match 'BTH|Bluetooth|RFCOMM' -or $_.FriendlyName -match 'Bluetooth'))
    } | ForEach-Object {
        [PSCustomObject]@{ Name = $_.FriendlyName; Id = $_.InstanceId; Status = $_.Status; Class = $_.Class; Source = 'Get-PnpDevice Bluetooth completo' }
    }
}
$items | Where-Object { $_.Name } | Sort-Object Name -Unique | ConvertTo-Json -Compress
'''
            for dev in _executar_powershell(ps_bt_amplo_extra, timeout=18):
                _add(
                    nome=dev.get('Name', ''),
                    descricao=dev.get('Status', ''),
                    hwid=dev.get('Id', ''),
                    origem=dev.get('Source', 'Bluetooth completo'),
                    paired=True,
                    kind='bluetooth_device'
                )

        try:
            import serial.tools.list_ports
            for item in serial.tools.list_ports.comports():
                porta = getattr(item, 'device', '') or ''
                descricao = getattr(item, 'description', '') or ''
                hwid = getattr(item, 'hwid', '') or ''
                fabricante = getattr(item, 'manufacturer', '') or ''
                produto = getattr(item, 'product', '') or ''
                texto = ' '.join([porta, descricao, hwid, fabricante, produto]).lower()
                eh_bluetooth = any(k in texto for k in (
                    'bluetooth', 'bth', 'bthenum', 'bthmodem', 'rfcomm', 'spp',
                    'serial over bluetooth', 'standard serial over bluetooth'
                ))
                if eh_bluetooth:
                    _add(nome=produto or descricao or fabricante or 'Dispositivo Bluetooth Serial', porta=porta, descricao=descricao, hwid=hwid, origem='PySerial Bluetooth COM', paired=True)
        except Exception:
            pass

        for dev in dispositivos:
            nome = str(dev.get('name') or 'Dispositivo Bluetooth').strip()
            porta = str(dev.get('port') or '').strip().upper()
            origem = str(dev.get('source') or '').strip()
            kind = str(dev.get('kind') or '').strip()
            if kind == 'windows_printer':
                if 'padrão' in origem.lower() or 'padrao' in origem.lower():
                    dev['label'] = f"🖨️ {nome}  (impressora Windows padrão)"
                else:
                    dev['label'] = f"🖨️ {nome}  (impressora Windows)"
            elif porta:
                dev['label'] = f"🔵 {nome}  ({porta})"
            else:
                dev['label'] = f"🔵 {nome}  (Bluetooth emparelhado - sem porta COM)"
            dev['debug'] = origem

        vistos = set()
        unicos = []
        for dev in dispositivos:
            assinatura = (str(dev.get('name', '')).lower(), str(dev.get('port', '')).upper())
            if assinatura in vistos:
                continue
            vistos.add(assinatura)
            unicos.append(dev)

        unicos.sort(key=lambda d: (0 if d.get('kind') == 'windows_printer' else (1 if d.get('port') else 2), str(d.get('name', '')).lower()))
        return unicos

    @classmethod
    def list_usb_devices(cls) -> List[Dict[str, Any]]:
        """Lista dispositivos USB disponíveis."""
        return USBConnection.list_devices()


