# FUNÇÕES DE CONVENIÊNCIA
# ═══════════════════════════════════════════════════════════════════════════════

def get_printer(
    printer_name: str = None,
    connection_type: ConnectionType = ConnectionType.AUTO,
    profile: str = None,
    **kwargs
) -> ThermalPrinter:
    """
    Função de conveniência para obter uma impressora térmica.
    
    Args:
        printer_name: Nome da impressora ou endereço
        connection_type: Tipo de conexão desejado
        profile: Nome do perfil pré-configurado
        **kwargs: Argumentos adicionais para a conexão
    
    Returns:
        ThermalPrinter configurada
    
    Examples:
        # Windows com impressora padrão
        printer = get_printer()
        
        # Windows com impressora específica
        printer = get_printer("EPSON TM-T20")
        
        # Serial
        printer = get_printer("COM3", ConnectionType.SERIAL, baudrate=9600)
        
        # Rede
        printer = get_printer("192.168.1.100", ConnectionType.NETWORK)
        
        # Com perfil específico
        printer = get_printer("COM3", ConnectionType.SERIAL, profile="XP-80")
    """
    # Obtém perfil
    printer_profile = None
    if profile:
        printer_profile = PRINTER_PROFILES.get(profile)
    
    # Cria impressora baseado no tipo de conexão
    if connection_type == ConnectionType.AUTO:
        return ThermalPrinterFactory.create_auto(printer_name, printer_profile)
    
    elif connection_type == ConnectionType.WINDOWS_RAW:
        return ThermalPrinterFactory.create_windows_raw(
            printer_name or "", printer_profile
        )
    
    elif connection_type == ConnectionType.WINDOWS_DRIVER:
        return ThermalPrinterFactory.create_windows_driver(
            printer_name or "", printer_profile
        )
    
    elif connection_type == ConnectionType.SERIAL:
        return ThermalPrinterFactory.create_serial(
            printer_name or "COM1",
            profile=printer_profile,
            **kwargs
        )
    
    elif connection_type == ConnectionType.BLUETOOTH:
        return ThermalPrinterFactory.create_bluetooth(
            printer_name or "COM1",
            profile=printer_profile,
            **kwargs
        )
    
    elif connection_type == ConnectionType.NETWORK:
        port = kwargs.pop('port', 9100)
        return ThermalPrinterFactory.create_network(
            printer_name or "localhost",
            port,
            printer_profile,
            **kwargs
        )
    
    elif connection_type == ConnectionType.USB:
        vendor_id = kwargs.pop('vendor_id', None)
        product_id = kwargs.pop('product_id', None)
        return ThermalPrinterFactory.create_usb(
            vendor_id, product_id, printer_profile, **kwargs
        )
    
    elif connection_type == ConnectionType.FILE:
        return ThermalPrinterFactory.create_file(
            printer_name or "/dev/usb/lp0", printer_profile
        )
    
    else:
        return ThermalPrinterFactory.create_auto(printer_name, printer_profile)


def print_test_page(printer: ThermalPrinter) -> None:
    """Imprime página de teste."""
    with printer:
        printer.init()
        
        # Cabeçalho
        printer.center()
        printer.double_size(True)
        printer.textln("TESTE DE IMPRESSÃO")
        printer.double_size(False)
        printer.textln("PDV QUANTUM ULTRA")
        printer.left()
        
        printer.double_line()
        
        # Informações do perfil
        printer.textln(f"Marca: {printer.profile.brand.value}")
        printer.textln(f"Modelo: {printer.profile.model or 'Genérico'}")
        printer.textln(f"Largura: {printer.profile.paper_width}mm")
        printer.textln(f"Caracteres/linha: {printer.profile.chars_per_line}")
        
        printer.line()
        
        # Teste de formatação
        printer.textln("Teste de formatação:")
        printer.bold_on().textln("Texto em NEGRITO").bold_off()
        printer.underline_on().textln("Texto SUBLINHADO").underline_off()
        printer.inverse_on().textln("Texto INVERTIDO").inverse_off()
        printer.double_width(True).textln("LARGURA DUPLA").double_width(False)
        printer.double_height(True).textln("ALTURA DUPLA").double_height(False)
        
        printer.line()
        
        # Teste de alinhamento
        printer.textln("Teste de alinhamento:")
        printer.left().textln("Esquerda")
        printer.center().textln("Centro")
        printer.right().textln("Direita")
        printer.left()
        
        printer.line()
        
        # Teste de código de barras
        if printer.profile.supports_barcode:
            printer.textln("Código de barras:")
            printer.center()
            printer.code128("PDV123456")
            printer.left()
            printer.ln()
        
        # Teste de QR Code
        if printer.profile.supports_qrcode:
            printer.textln("QR Code:")
            printer.center()
            printer.qrcode("https://pdv-quantum.com.br")
            printer.left()
            printer.ln()
        
        printer.double_line()
        
        # Rodapé
        printer.center()
        printer.textln("Teste concluído com sucesso!")
        printer.textln(time.strftime("%d/%m/%Y %H:%M:%S"))
        printer.left()
        
        printer.feed(3)
        printer.cut()


def print_receipt(
    printer: ThermalPrinter,
    company_name: str,
    company_info: List[str],
    items: List[Dict],
    subtotal: float,
    discount: float = 0,
    tax: float = 0,
    total: float = None,
    payment_method: str = "",
    payment_value: float = None,
    change: float = None,
    footer_lines: List[str] = None,
    receipt_number: str = "",
    operator: str = "",
    customer_data: Dict = None,
    vendedor: str = "",
    entregador: str = "",
    is_delivery: bool = False
) -> None:
    """
    Imprime cupom de venda completo.
    
    Args:
        printer: Impressora térmica
        company_name: Nome da empresa
        company_info: Linhas de informação da empresa (endereço, CNPJ, etc.)
        items: Lista de itens [{description, quantity, unit_price, total}, ...]
        subtotal: Subtotal da venda
        discount: Valor do desconto
        tax: Valor de impostos/taxas
        total: Total da venda (calculado se não fornecido)
        payment_method: Forma de pagamento
        payment_value: Valor pago
        change: Troco
        footer_lines: Linhas de rodapé
        receipt_number: Número do cupom
        operator: Nome do operador
    """
    if total is None:
        total = subtotal - discount + tax
    
    with printer:
        printer.init()
        
        # Cabeçalho da empresa
        printer.center()
        printer.double_size(True)
        printer.textln(company_name)
        printer.double_size(False)
        
        for line in company_info:
            printer.textln(line)
        
        printer.left()
        printer.double_line()
        
        # Informações do cupom
        if receipt_number:
            printer.textln(f"Cupom: {receipt_number}")
        printer.textln(f"Data: {time.strftime('%d/%m/%Y %H:%M:%S')}")
        if operator:
            printer.textln(f"Operador: {operator}")
        if vendedor:
            printer.textln(f"Vendedor: {vendedor}")
        if is_delivery and entregador:
            printer.textln(f"Entregador: {entregador}")
        
        printer.line()
        
        # Cabeçalho dos itens
        printer.bold_on()
        printer.textln("ITEM                         TOTAL")
        printer.bold_off()
        printer.line()
        
        # Itens
        for item in items:
            printer.item(
                item.get('description', ''),
                item.get('quantity', 1),
                item.get('unit_price', 0),
                item.get('total')
            )
        
        printer.line()
        
        # Totais
        printer.row("Subtotal:", f"{subtotal:.2f}")
        
        if discount > 0:
            printer.row("Desconto:", f"-{discount:.2f}")
        
        if tax > 0:
            printer.row("Impostos:", f"{tax:.2f}")
        
        printer.double_line()
        printer.bold_on()
        printer.double_size(True)
        printer.row("TOTAL:", f"{total:.2f}")
        printer.double_size(False)
        printer.bold_off()
        printer.double_line()
        
        # Pagamento
        if payment_method:
            printer.textln(f"Pagamento: {payment_method}")
        
        if payment_value is not None:
            printer.row("Valor pago:", f"{payment_value:.2f}")
        
        if change is not None and change > 0:
            printer.row("Troco:", f"{change:.2f}")
        
        printer.line()
        
        # Rodapé
        if footer_lines:
            printer.center()
            for line in footer_lines:
                printer.textln(line)
            printer.left()
        
        printer.ln(2)
        printer.center()
        printer.textln("Obrigado pela preferência!")
        printer.left()

        # Dados do Cliente
        if customer_data:
            nome = customer_data.get('nome', '')
            cpf = customer_data.get('cpf', '')
            telefone = customer_data.get('telefone', '')
            endereco = customer_data.get('endereco', '')
            bairro = customer_data.get('bairro', '')
            observacao = customer_data.get('observacao', '')

            if nome or cpf or telefone or endereco or bairro:
                printer.ln(1)
                printer.line()
                printer.center()
                printer.textln("DADOS DO CLIENTE")
                printer.left()
                printer.line()
                
                if nome:
                    printer.textln(f"Nome: {nome}")
                if cpf:
                    printer.textln(f"CPF/CNPJ: {cpf}")
                if telefone:
                    printer.textln(f"Telefone: {telefone}")
                if endereco:
                    # Quebra de linha simples para endereço
                    printer.textln(f"Endereço: {endereco}")
                if bairro:
                    printer.textln(f"Bairro: {bairro}")
                if observacao:
                    printer.textln(f"Obs: {observacao}")
                
                printer.line()
        
        printer.feed(3)
        printer.cut()


