class ConfiguracaoImpressoraWindow(tk.Toplevel):
    """
    Janela de configuração de impressora térmica.
    Permite configurar tipo de conexão, perfil e parâmetros.
    """
    
    def __init__(self, parent, config_file: str, callback_salvar: callable = None):
        super().__init__(parent)
        self.status_bar = StatusBar(self, user_name=getattr(self, 'current_user', 'Usuário'))
        
        self.config_file = config_file
        self.callback_salvar = callback_salvar
        self.config = {}
        
        # Carrega configuração existente
        self._carregar_config()
        
        # Configura janela
        self.title("Configuração de Impressora Térmica / Etiquetas Avançadas")
        self.state('zoomed')
        self.resizable(True, True)
        self.transient(parent)
        self.grab_set()
        
        # Cria interface
        self._criar_interface()
        
        # Centraliza
        self.update_idletasks()
        x = (self.winfo_screenwidth() - self.winfo_width()) // 2
        y = (self.winfo_screenheight() - self.winfo_height()) // 2
        self.geometry(f"+{x}+{y}")
    
    def _carregar_config(self):
        """Carrega configuração do arquivo."""
        try:
            if os.path.exists(self.config_file):
                with open(self.config_file, 'r', encoding='utf-8') as f:
                    self.config = json.load(f)
        except Exception as e:
            logger.warning(f"Erro ao carregar configuração: {e}")
            self.config = {}
    
    def _criar_interface(self):
        """Cria a interface da janela."""
        # Frame principal com scroll
        main_canvas = tk.Canvas(self, highlightthickness=0)
        scrollbar = ttk.Scrollbar(self, orient="vertical", command=main_canvas.yview)
        scrollable_frame = ttk.Frame(main_canvas, padding=20)
        
        scrollable_frame.bind(
            "<Configure>",
            lambda e: main_canvas.configure(scrollregion=main_canvas.bbox("all"))
        )
        
        main_canvas.create_window((0, 0), window=scrollable_frame, anchor="nw")
        main_canvas.configure(yscrollcommand=scrollbar.set)
        
        # Título
        ttk.Label(
            scrollable_frame, 
            text="Configuração de Impressora Térmica / Etiquetas Avançadas",
            font=('Segoe UI', 16, 'bold')
        ).pack(pady=(0, 20))
        
        # ═══════════════════════════════════════════════════════════════════════
        # SEÇÃO: HABILITAÇÃO
        # ═══════════════════════════════════════════════════════════════════════
        frame_habilitar = tk.LabelFrame(scrollable_frame, text="Status", padx=10, pady=10)
