class ConfiguracaoMultiplasImpressorasWindow(tk.Toplevel):
    """
    Janela de configuração de múltiplas impressoras térmicas.
    Permite configurar até 4 impressoras e associar categorias a cada uma.
    """
    
    def __init__(self, parent, config_file: str, categories_dict: dict, callback_salvar: callable = None):
        super().__init__(parent)
        self.status_bar = StatusBar(self, user_name=getattr(self, 'current_user', 'Usuário'))
        
        self.config_file = config_file
        self.categories_dict = categories_dict
        self.callback_salvar = callback_salvar
        self.config = {}
        
        # Carrega configuração existente
        self._carregar_config()
        
        # Configura janela
        self.title("Configuração de Múltiplas Impressoras por Categoria")
        self.state('zoomed')
        self.resizable(True, True)
        self.transient(parent)
        self.grab_set()
        
        # Cria interface
        self._criar_interface()
        
        # Centraliza
        self.update_idletasks()
        x = (self.winfo_screenwidth() - self.winfo_width()) // 2
        y = (self.winfo_screenheight() - self.winfo_height()) // 2
        self.geometry(f"+{x}+{y}")
    
    def _carregar_config(self):
        """Carrega configuração do arquivo."""
        try:
            if os.path.exists(self.config_file):
                with open(self.config_file, 'r', encoding='utf-8') as f:
                    self.config = json.load(f)
        except Exception as e:
            logger.warning(f"Erro ao carregar configuração de múltiplas impressoras: {e}")
            self.config = {}
        
        # Inicializa estrutura padrão se não existir
        if 'impressoras' not in self.config:
            self.config['impressoras'] = {}
        if 'categorias_impressoras' not in self.config:
            self.config['categorias_impressoras'] = {}
        if 'habilitado' not in self.config:
            self.config['habilitado'] = False
    
    def _criar_interface(self):
        """Cria a interface da janela."""
        # Frame principal com scroll
        main_canvas = tk.Canvas(self, highlightthickness=0)
        scrollbar = ttk.Scrollbar(self, orient="vertical", command=main_canvas.yview)
        scrollable_frame = ttk.Frame(main_canvas, padding=20)
        
        scrollable_frame.bind(
            "<Configure>",
            lambda e: main_canvas.configure(scrollregion=main_canvas.bbox("all"))
        )
        
        main_canvas.create_window((0, 0), window=scrollable_frame, anchor="nw")
        main_canvas.configure(yscrollcommand=scrollbar.set)
        
        # Título
        ttk.Label(
            scrollable_frame, 
            text="Configuração de Múltiplas Impressoras por Categoria",
            font=('Segoe UI', 16, 'bold')
        ).pack(pady=(0, 10))
        
        ttk.Label(
            scrollable_frame, 
            text="Configure até 4 impressoras diferentes e associe cada categoria de produto a uma impressora específica.",
            font=('Segoe UI', 10),
            foreground='gray',
            wraplength=850
        ).pack(pady=(0, 20))
        
        # SEÇÃO: HABILITAÇÃO DO SISTEMA
        frame_habilitar = tk.LabelFrame(scrollable_frame, text="Status do Sistema", padx=10, pady=10)
        frame_habilitar.pack(fill=tk.X, pady=5)
        
        self.var_habilitado = tk.BooleanVar(value=self.config.get('habilitado', False))
        ttk.Checkbutton(
            frame_habilitar,
            text="Sistema de múltiplas impressoras habilitado",
            variable=self.var_habilitado,
            bootstyle="success-round-toggle"
        ).pack(anchor=tk.W)
        
        ttk.Label(
            frame_habilitar,
            text="Quando habilitado, os produtos serão impressos na impressora associada à sua categoria. "
                 "Se desabilitado, será usada a impressora padrão configurada.",
            font=('Segoe UI', 9),
            foreground='gray',
            wraplength=850
        ).pack(anchor=tk.W, pady=(5, 0))
        
        # SEÇÃO: CONFIGURAÇÃO DAS 4 IMPRESSORAS
        frame_impressoras = tk.LabelFrame(scrollable_frame, text="Configuração das Impressoras", padx=10, pady=10)
        frame_impressoras.pack(fill=tk.X, pady=10)
        
        # Obtém lista de impressoras Windows disponíveis
        self.impressoras_disponiveis = self._obter_impressoras_windows()
        
        self.vars_impressoras = {}
        self.vars_nomes = {}
        self.vars_habilitadas = {}
        self.vars_perfis = {}
        self.vars_tipos_conexao = {}
        
        cores_impressoras = ['#3498db', '#27ae60', '#e74c3c', '#9b59b6']
        nomes_padrao = ['Impressora 1 (Principal)', 'Impressora 2 (Cozinha)', 'Impressora 3 (Bar)', 'Impressora 4 (Auxiliar)']
        
        for i in range(1, 5):
            impressora_key = f'impressora_{i}'
            config_imp = self.config.get('impressoras', {}).get(impressora_key, {})
            
            frame_imp = ttk.Frame(frame_impressoras)
            frame_imp.pack(fill=tk.X, pady=5)
            
            # Indicador colorido
            canvas_cor = tk.Canvas(frame_imp, width=20, height=20, highlightthickness=0)
            canvas_cor.pack(side=tk.LEFT, padx=(0, 10))
            canvas_cor.create_oval(2, 2, 18, 18, fill=cores_impressoras[i-1], outline='')
            
            # Checkbox de habilitação
            self.vars_habilitadas[impressora_key] = tk.BooleanVar(value=config_imp.get('habilitada', False))
            ttk.Checkbutton(
                frame_imp,
                variable=self.vars_habilitadas[impressora_key],
                bootstyle="round-toggle"
            ).pack(side=tk.LEFT, padx=(0, 5))
            
            # Nome personalizado
            ttk.Label(frame_imp, text="Nome:", width=6).pack(side=tk.LEFT)
            self.vars_nomes[impressora_key] = tk.StringVar(value=config_imp.get('nome', nomes_padrao[i-1]))
            ttk.Entry(frame_imp, textvariable=self.vars_nomes[impressora_key], width=25).pack(side=tk.LEFT, padx=(0, 10))
            
            # Seleção da impressora Windows
            ttk.Label(frame_imp, text="Impressora:", width=10).pack(side=tk.LEFT)
            self.vars_impressoras[impressora_key] = tk.StringVar(value=config_imp.get('endereco', ''))
            combo = ttk.Combobox(
                frame_imp, 
                textvariable=self.vars_impressoras[impressora_key],
                values=self.impressoras_disponiveis,
                width=40
            )
            combo.pack(side=tk.LEFT, padx=(0, 10))
            
            # Botão de teste
            ttk.Button(
                frame_imp,
                text="Testar",
                command=lambda key=impressora_key: self._testar_impressora(key),
                bootstyle="info-outline",
                width=8
            ).pack(side=tk.LEFT)
        
        # Botão para atualizar lista de impressoras
        ttk.Button(
            frame_impressoras,
            text="Atualizar Lista de Impressoras",
            command=self._atualizar_lista_impressoras,
            bootstyle="info-outline"
        ).pack(anchor=tk.W, pady=(10, 0))
        
        # SEÇÃO: ASSOCIAÇÃO DE CATEGORIAS A IMPRESSORAS
        frame_categorias = tk.LabelFrame(scrollable_frame, text="Associação de Categorias a Impressoras", padx=10, pady=10)
        frame_categorias.pack(fill=tk.BOTH, expand=True, pady=10)
        
        ttk.Label(
            frame_categorias,
            text="Selecione qual impressora será usada para cada categoria de produto:",
            font=('Segoe UI', 10),
            foreground='gray'
        ).pack(anchor=tk.W, pady=(0, 10))
        
        # Frame com scroll para categorias
        cat_canvas = tk.Canvas(frame_categorias, height=250, highlightthickness=1, highlightbackground='gray')
        cat_scrollbar = ttk.Scrollbar(frame_categorias, orient="vertical", command=cat_canvas.yview)
        cat_frame = ttk.Frame(cat_canvas)
        
        cat_frame.bind(
            "<Configure>",
            lambda e: cat_canvas.configure(scrollregion=cat_canvas.bbox("all"))
        )
        
