class TipoConexao(Enum):
    """Tipos de conexão suportados"""
    SERIAL = "serial"
    USB = "usb"
    BLUETOOTH = "bluetooth"
    BLUETOOTH_LE = "bluetooth_le"
    VIRTUAL = "virtual"  # Para testes


class ProtocoloBalanca(Enum):
    """Protocolos de comunicação suportados"""
    # Toledo
    TOLEDO_A = "toledo_a"           # STX/ETX sob demanda (ENQ)
    TOLEDO_B = "toledo_b"           # STX/CR contínuo
    TOLEDO_P05A = "toledo_p05a"     # Protocolo estendido
    TOLEDO_8217 = "toledo_8217"     # Modelo específico checkout
    
    # Filizola
    FILIZOLA_STX_ETX = "filizola_stx_etx"
    FILIZOLA_CONTINUO = "filizola_continuo"
    
    # Urano
    URANO_URAN12 = "urano_uran12"   # Protocolo completo
    URANO_STD01 = "urano_std01"     # Peso em kg com espaços
    URANO_STD02 = "urano_std02"     # Peso em kg com zeros
    URANO_STD03 = "urano_std03"     # Peso em kg formatado
    URANO_STD04 = "urano_std04"     # Peso em gramas
    URANO_STD05 = "urano_std05"     # Variante
    
    # Elgin
    ELGIN_DP = "elgin_dp"           # Série DP
    ELGIN_SA = "elgin_sa"           # Série SA
    
    # Balmak
    BALMAK_FLP15 = "balmak_flp15"   # Equivalente PRT3
    BALMAK_ELINE = "balmak_eline"
    
    # Digitron
    DIGITRON_STD = "digitron_std"
    
    # Genéricos
    GENERICO_STX_ETX = "generico_stx_etx"
    GENERICO_CONTINUO = "generico_continuo"
    GENERICO_PESO_SIMPLES = "generico_peso_simples"
    
    # Auto-detecção
    AUTO_DETECT = "auto_detect"


class EstadoBalanca(Enum):
    """Estados possíveis da balança"""
    DESCONECTADA = auto()
    CONECTANDO = auto()
    CONECTADA = auto()
    LENDO = auto()
    ERRO = auto()
    PESO_ESTAVEL = auto()
    PESO_INSTAVEL = auto()
    SOBRECARGA = auto()
    SUBCARGA = auto()
    MOVIMENTO = auto()


class UnidadePeso(Enum):
    """Unidades de peso suportadas"""
    GRAMAS = "g"
    KILOGRAMAS = "kg"
    LIBRAS = "lb"
    ONCAS = "oz"


# Caracteres de controle ASCII
ASCII_STX = 0x02  # Start of Text
ASCII_ETX = 0x03  # End of Text
ASCII_ENQ = 0x05  # Enquiry
ASCII_ACK = 0x06  # Acknowledge
ASCII_NAK = 0x15  # Negative Acknowledge
ASCII_CR = 0x0D   # Carriage Return
ASCII_LF = 0x0A   # Line Feed
ASCII_ESC = 0x1B  # Escape


