# ESTRUTURAS DE DADOS
# ═══════════════════════════════════════════════════════════════════════════════

@dataclass
class ConfiguracaoSerial:
    """Configuração de porta serial"""
    porta: str = ""
    baudrate: int = 9600
    bytesize: int = 8
    parity: str = "N"  # N, E, O
    stopbits: float = 1.0
    timeout: float = 1.0
    xonxoff: bool = False
    rtscts: bool = False
    dsrdtr: bool = False
    
    def to_dict(self) -> dict:
        return asdict(self)
    
    @classmethod
    def from_dict(cls, data: dict) -> 'ConfiguracaoSerial':
        return cls(**{k: v for k, v in data.items() if k in cls.__dataclass_fields__})


@dataclass
class ConfiguracaoProtocolo:
    """Configuração de protocolo de comunicação"""
    protocolo: ProtocoloBalanca = ProtocoloBalanca.AUTO_DETECT
    modo_leitura: str = "sob_demanda"  # sob_demanda, continuo
    intervalo_leitura_ms: int = 100
    timeout_resposta_ms: int = 500
    tentativas_reconexao: int = 3
    casas_decimais: int = 3
    unidade_padrao: UnidadePeso = UnidadePeso.GRAMAS
    fator_conversao: float = 1.0  # Para ajustes de calibração
    
    def to_dict(self) -> dict:
        d = asdict(self)
        d['protocolo'] = self.protocolo.value
        d['unidade_padrao'] = self.unidade_padrao.value
        return d
    
    @classmethod
    def from_dict(cls, data: dict) -> 'ConfiguracaoProtocolo':
        if 'protocolo' in data and isinstance(data['protocolo'], str):
            data['protocolo'] = ProtocoloBalanca(data['protocolo'])
        if 'unidade_padrao' in data and isinstance(data['unidade_padrao'], str):
            data['unidade_padrao'] = UnidadePeso(data['unidade_padrao'])
        return cls(**{k: v for k, v in data.items() if k in cls.__dataclass_fields__})


@dataclass
class LeituraPeso:
    """Resultado de uma leitura de peso"""
    peso_bruto: float = 0.0
    peso_liquido: float = 0.0
    tara: float = 0.0
    unidade: UnidadePeso = UnidadePeso.GRAMAS
    estavel: bool = False
    valido: bool = False
    estado: EstadoBalanca = EstadoBalanca.DESCONECTADA
    timestamp: datetime = field(default_factory=lambda: datetime.now() if hasattr(datetime, 'now') else datetime.datetime.now())
    dados_raw: bytes = b""
    mensagem_erro: str = ""
    
    def peso_em_gramas(self) -> float:
        """Retorna o peso líquido convertido para gramas"""
        if self.unidade == UnidadePeso.GRAMAS:
            return self.peso_liquido
        elif self.unidade == UnidadePeso.KILOGRAMAS:
            return self.peso_liquido * 1000.0
        elif self.unidade == UnidadePeso.LIBRAS:
            return self.peso_liquido * 453.592
        elif self.unidade == UnidadePeso.ONCAS:
            return self.peso_liquido * 28.3495
        return self.peso_liquido
    
    def peso_em_kg(self) -> float:
        """Retorna o peso líquido convertido para kilogramas"""
        return self.peso_em_gramas() / 1000.0
    
    def to_dict(self) -> dict:
        return {
            'peso_bruto': self.peso_bruto,
            'peso_liquido': self.peso_liquido,
            'tara': self.tara,
            'unidade': self.unidade.value,
            'estavel': self.estavel,
            'valido': self.valido,
            'estado': self.estado.name,
            'timestamp': self.timestamp.isoformat(),
            'mensagem_erro': self.mensagem_erro
        }


@dataclass
class ConfiguracaoBalanca:
    """Configuração completa de uma balança"""
    nome: str = "Balança Principal"
    tipo_conexao: TipoConexao = TipoConexao.SERIAL
    config_serial: ConfiguracaoSerial = field(default_factory=ConfiguracaoSerial)
    config_protocolo: ConfiguracaoProtocolo = field(default_factory=ConfiguracaoProtocolo)
    endereco_bluetooth: str = ""
    ativo: bool = True
    
    def to_dict(self) -> dict:
        return {
            'nome': self.nome,
            'tipo_conexao': self.tipo_conexao.value,
            'config_serial': self.config_serial.to_dict(),
            'config_protocolo': self.config_protocolo.to_dict(),
            'endereco_bluetooth': self.endereco_bluetooth,
            'ativo': self.ativo
        }
    
    @classmethod
    def from_dict(cls, data: dict) -> 'ConfiguracaoBalanca':
        config = cls()
        config.nome = data.get('nome', config.nome)
        if 'tipo_conexao' in data:
            config.tipo_conexao = TipoConexao(data['tipo_conexao'])
        if 'config_serial' in data:
            config.config_serial = ConfiguracaoSerial.from_dict(data['config_serial'])
        if 'config_protocolo' in data:
            config.config_protocolo = ConfiguracaoProtocolo.from_dict(data['config_protocolo'])
        config.endereco_bluetooth = data.get('endereco_bluetooth', '')
        config.ativo = data.get('ativo', True)
        return config


