# PARSERS DE PROTOCOLO - CLASSES ABSTRATAS E IMPLEMENTAÇÕES
# ═══════════════════════════════════════════════════════════════════════════════

class ProtocolParser(ABC):
    """Classe base abstrata para parsers de protocolo"""
    
    @abstractmethod
    def parse(self, data: bytes) -> LeituraPeso:
        """Faz o parse dos dados recebidos e retorna uma leitura de peso"""
        pass
    
    @abstractmethod
    def get_comando_leitura(self) -> bytes:
        """Retorna o comando para solicitar leitura (se aplicável)"""
        pass
    
    @abstractmethod
    def get_nome_protocolo(self) -> str:
        """Retorna o nome do protocolo"""
        pass
    
    def _extrair_numero(self, texto: str) -> Optional[float]:
        """Extrai um número de uma string, tratando formatos brasileiros"""
        try:
            # Remove espaços e caracteres não numéricos exceto . , -
            texto = texto.strip()
            texto = re.sub(r'[^\d.,\-]', '', texto)
            
            # Trata formato brasileiro (vírgula como decimal)
            if ',' in texto and '.' in texto:
                # Assume formato 1.234,56
                texto = texto.replace('.', '').replace(',', '.')
            elif ',' in texto:
                texto = texto.replace(',', '.')
            
            return float(texto) if texto else None
        except (ValueError, TypeError):
            return None


class ToledoProtocolA(ProtocolParser):
    """Parser para protocolo Toledo A (STX/ETX sob demanda)"""
    
    def get_nome_protocolo(self) -> str:
        return "Toledo Protocolo A (STX/ETX)"
    
    def get_comando_leitura(self) -> bytes:
        return bytes([ASCII_ENQ])
    
    def parse(self, data: bytes) -> LeituraPeso:
        leitura = LeituraPeso(dados_raw=data)
        
        try:
            # Formato: STX + 5 chars peso + ETX
            # Peso: 2 inteiros + 3 decimais (ex: "12345" = 12.345 kg)
            if len(data) < 7:
                leitura.mensagem_erro = "Dados insuficientes"
                return leitura
            
            # Encontra STX e ETX
            stx_pos = data.find(bytes([ASCII_STX]))
            etx_pos = data.find(bytes([ASCII_ETX]))
            
            if stx_pos == -1 or etx_pos == -1 or etx_pos <= stx_pos:
                leitura.mensagem_erro = "Formato inválido (STX/ETX não encontrado)"
                return leitura
            
            peso_bytes = data[stx_pos + 1:etx_pos]
            peso_str = peso_bytes.decode('ascii', errors='ignore').strip()
            
            # Verifica estados especiais
            if 'I' * 5 in peso_str or peso_str.count('I') >= 3:
                leitura.estado = EstadoBalanca.PESO_INSTAVEL
                leitura.estavel = False
                leitura.valido = True
                return leitura
            
            if 'N' * 5 in peso_str or peso_str.count('N') >= 3:
                leitura.estado = EstadoBalanca.SUBCARGA
                leitura.valido = True
                return leitura
            
            if 'S' * 5 in peso_str or peso_str.count('S') >= 3:
                leitura.estado = EstadoBalanca.SOBRECARGA
                leitura.valido = True
                return leitura
            
            # Parse do peso (formato: IIDDD onde II=inteiro, DDD=decimal)
            if len(peso_str) >= 5:
                parte_inteira = peso_str[:2]
                parte_decimal = peso_str[2:5]
                peso_valor = float(f"{parte_inteira}.{parte_decimal}")
                
                leitura.peso_bruto = peso_valor
                leitura.peso_liquido = peso_valor
                leitura.unidade = UnidadePeso.KILOGRAMAS
                leitura.estavel = True
                leitura.valido = True
                leitura.estado = EstadoBalanca.PESO_ESTAVEL
            else:
                # Tenta parse genérico
                peso = self._extrair_numero(peso_str)
                if peso is not None:
                    leitura.peso_bruto = peso
                    leitura.peso_liquido = peso
                    leitura.unidade = UnidadePeso.KILOGRAMAS
                    leitura.estavel = True
                    leitura.valido = True
                    leitura.estado = EstadoBalanca.PESO_ESTAVEL
                else:
                    leitura.mensagem_erro = f"Não foi possível interpretar peso: {peso_str}"
            
        except Exception as e:
            leitura.mensagem_erro = f"Erro no parse: {str(e)}"
            leitura.estado = EstadoBalanca.ERRO
        
        return leitura


class ToledoProtocolB(ProtocolParser):
    """Parser para protocolo Toledo B (STX/CR contínuo)"""
    
    def get_nome_protocolo(self) -> str:
        return "Toledo Protocolo B (STX/CR Contínuo)"
    
    def get_comando_leitura(self) -> bytes:
        return b""  # Não precisa de comando, é contínuo
    
    def parse(self, data: bytes) -> LeituraPeso:
        leitura = LeituraPeso(dados_raw=data)
        
        try:
            # Formato: STX + 5 chars peso + CR
            stx_pos = data.find(bytes([ASCII_STX]))
            cr_pos = data.find(bytes([ASCII_CR]))
            
            if stx_pos == -1:
                # Tenta sem STX
                cr_pos = data.find(bytes([ASCII_CR]))
                if cr_pos == -1:
                    cr_pos = len(data)
                peso_bytes = data[:cr_pos]
            else:
                if cr_pos == -1:
                    cr_pos = len(data)
                peso_bytes = data[stx_pos + 1:cr_pos]
            
            peso_str = peso_bytes.decode('ascii', errors='ignore').strip()
            
            # Verifica estados especiais
            if 'I' * 3 in peso_str:
                leitura.estado = EstadoBalanca.PESO_INSTAVEL
                leitura.estavel = False
                leitura.valido = True
                return leitura
            
            # Parse do peso
            if len(peso_str) >= 5:
                parte_inteira = peso_str[:2]
                parte_decimal = peso_str[2:5]
                try:
                    peso_valor = float(f"{parte_inteira}.{parte_decimal}")
                    leitura.peso_bruto = peso_valor
                    leitura.peso_liquido = peso_valor
                    leitura.unidade = UnidadePeso.KILOGRAMAS
                    leitura.estavel = True
                    leitura.valido = True
                    leitura.estado = EstadoBalanca.PESO_ESTAVEL
                except ValueError:
                    peso = self._extrair_numero(peso_str)
                    if peso is not None:
                        leitura.peso_bruto = peso
                        leitura.peso_liquido = peso
                        leitura.unidade = UnidadePeso.KILOGRAMAS
                        leitura.estavel = True
                        leitura.valido = True
                        leitura.estado = EstadoBalanca.PESO_ESTAVEL
            else:
                peso = self._extrair_numero(peso_str)
                if peso is not None:
                    leitura.peso_bruto = peso
                    leitura.peso_liquido = peso
                    leitura.unidade = UnidadePeso.KILOGRAMAS
                    leitura.estavel = True
                    leitura.valido = True
                    leitura.estado = EstadoBalanca.PESO_ESTAVEL
                    
        except Exception as e:
            leitura.mensagem_erro = f"Erro no parse: {str(e)}"
            leitura.estado = EstadoBalanca.ERRO
        
        return leitura


class FilizolaProtocol(ProtocolParser):
    """Parser para protocolo Filizola (similar ao Toledo)"""
    
    def get_nome_protocolo(self) -> str:
        return "Filizola STX/ETX"
    
    def get_comando_leitura(self) -> bytes:
        return bytes([ASCII_ENQ])
    
    def parse(self, data: bytes) -> LeituraPeso:
        # Filizola usa formato similar ao Toledo
        toledo_parser = ToledoProtocolA()
        return toledo_parser.parse(data)


class UranoStdProtocol(ProtocolParser):
    """Parser para protocolos Urano Std01-05"""
    
    def __init__(self, variante: str = "std01"):
        self.variante = variante
    
    def get_nome_protocolo(self) -> str:
        return f"Urano {self.variante.upper()}"
    
    def get_comando_leitura(self) -> bytes:
        return bytes([ASCII_ENQ])
    
    def parse(self, data: bytes) -> LeituraPeso:
        leitura = LeituraPeso(dados_raw=data)
        
        try:
            # Formato: STX + S + P + P + D + P + P + P + ETX
            # S = sinal (espaço ou -)
            # P = dígitos do peso
            # D = ponto decimal
            
            stx_pos = data.find(bytes([ASCII_STX]))
            etx_pos = data.find(bytes([ASCII_ETX]))
            
            if stx_pos == -1 or etx_pos == -1:
                leitura.mensagem_erro = "Formato inválido"
                return leitura
            
            peso_bytes = data[stx_pos + 1:etx_pos]
            peso_str = peso_bytes.decode('ascii', errors='ignore')
            
            # Verifica estados especiais
            if 'I' * 3 in peso_str:
                leitura.estado = EstadoBalanca.PESO_INSTAVEL
                leitura.estavel = False
                leitura.valido = True
                return leitura
            
            if 'N' * 3 in peso_str:
                leitura.estado = EstadoBalanca.SUBCARGA
                leitura.valido = True
                return leitura
            
            if 'S' * 3 in peso_str:
                leitura.estado = EstadoBalanca.SOBRECARGA
                leitura.valido = True
                return leitura
            
            # Extrai o peso
            peso = self._extrair_numero(peso_str)
            if peso is not None:
                leitura.peso_bruto = abs(peso)
                leitura.peso_liquido = peso
                
                # Std04 envia em gramas, outros em kg
                if self.variante == "std04":
                    leitura.unidade = UnidadePeso.GRAMAS
                else:
                    leitura.unidade = UnidadePeso.KILOGRAMAS
                
                leitura.estavel = True
                leitura.valido = True
                leitura.estado = EstadoBalanca.PESO_ESTAVEL
            else:
                leitura.mensagem_erro = f"Não foi possível interpretar: {peso_str}"
                
        except Exception as e:
            leitura.mensagem_erro = f"Erro no parse: {str(e)}"
            leitura.estado = EstadoBalanca.ERRO
        
        return leitura


class UranoUran12Protocol(ProtocolParser):
    """Parser para protocolo Urano Uran12 (completo)"""
    
    def get_nome_protocolo(self) -> str:
        return "Urano URAN12"
    
    def get_comando_leitura(self) -> bytes:
        return b""  # Contínuo
    
    def parse(self, data: bytes) -> LeituraPeso:
        leitura = LeituraPeso(dados_raw=data)
        
        try:
            # Formato complexo do Uran12
            # T1=A13=N0=S2=D4=Q193=B.:PESO:000000kg=E=P01
            texto = data.decode('ascii', errors='ignore')
            
            # Procura pelo peso no formato PESO:XXXXXX
            match = re.search(r'PESO[:\s]*([0-9.,\-]+)\s*(kg|g)?', texto, re.IGNORECASE)
            if match:
                peso_str = match.group(1)
                unidade_str = match.group(2) if match.group(2) else 'kg'
                
                peso = self._extrair_numero(peso_str)
                if peso is not None:
                    leitura.peso_bruto = abs(peso)
                    leitura.peso_liquido = peso
                    leitura.unidade = UnidadePeso.KILOGRAMAS if unidade_str.lower() == 'kg' else UnidadePeso.GRAMAS
                    leitura.estavel = True
                    leitura.valido = True
                    leitura.estado = EstadoBalanca.PESO_ESTAVEL
            else:
                # Tenta parse genérico
                peso = self._extrair_numero(texto)
                if peso is not None:
                    leitura.peso_bruto = abs(peso)
                    leitura.peso_liquido = peso
                    leitura.unidade = UnidadePeso.KILOGRAMAS
                    leitura.estavel = True
                    leitura.valido = True
                    leitura.estado = EstadoBalanca.PESO_ESTAVEL
                else:
                    leitura.mensagem_erro = "Formato não reconhecido"
                    
        except Exception as e:
            leitura.mensagem_erro = f"Erro no parse: {str(e)}"
            leitura.estado = EstadoBalanca.ERRO
        
        return leitura


