class DigitronProtocol(ProtocolParser):
    """Parser para balanças Digitron"""
    
    def get_nome_protocolo(self) -> str:
        return "Digitron Standard"
    
    def get_comando_leitura(self) -> bytes:
        return bytes([ASCII_ENQ])
    
    def parse(self, data: bytes) -> LeituraPeso:
        leitura = LeituraPeso(dados_raw=data)
        
        try:
            texto = data.decode('ascii', errors='ignore').strip()
            
            # Digitron pode enviar em vários formatos
            # Tenta extrair número
            peso = self._extrair_numero(texto)
            if peso is not None:
                leitura.peso_bruto = abs(peso)
                leitura.peso_liquido = peso
                leitura.unidade = UnidadePeso.KILOGRAMAS
                leitura.estavel = True
                leitura.valido = True
                leitura.estado = EstadoBalanca.PESO_ESTAVEL
            else:
                leitura.mensagem_erro = f"Formato não reconhecido: {texto}"
                
        except Exception as e:
            leitura.mensagem_erro = f"Erro no parse: {str(e)}"
            leitura.estado = EstadoBalanca.ERRO
        
        return leitura


class GenericoProtocol(ProtocolParser):
    """Parser genérico para balanças desconhecidas"""
    
    def __init__(self, modo: str = "stx_etx"):
        self.modo = modo
    
    def get_nome_protocolo(self) -> str:
        return f"Genérico ({self.modo})"
    
    def get_comando_leitura(self) -> bytes:
        if self.modo == "continuo":
            return b""
        return bytes([ASCII_ENQ])
    
    def parse(self, data: bytes) -> LeituraPeso:
        leitura = LeituraPeso(dados_raw=data)
        
        try:
            # Tenta múltiplos formatos
            texto = data.decode('ascii', errors='ignore').strip()
            
            # Remove caracteres de controle
            texto_limpo = re.sub(r'[\x00-\x1F\x7F]', ' ', texto).strip()
            
            # Tenta extrair número
            peso = self._extrair_numero(texto_limpo)
            if peso is not None:
                leitura.peso_bruto = abs(peso)
                leitura.peso_liquido = peso
                
                # Detecta unidade
                if 'kg' in texto.lower():
                    leitura.unidade = UnidadePeso.KILOGRAMAS
                elif 'lb' in texto.lower():
                    leitura.unidade = UnidadePeso.LIBRAS
                elif 'oz' in texto.lower():
                    leitura.unidade = UnidadePeso.ONCAS
                else:
                    # Assume gramas se valor > 100, kg se <= 100
                    leitura.unidade = UnidadePeso.GRAMAS if peso > 100 else UnidadePeso.KILOGRAMAS
                
                leitura.estavel = True
                leitura.valido = True
                leitura.estado = EstadoBalanca.PESO_ESTAVEL
            else:
                leitura.mensagem_erro = f"Não foi possível extrair peso de: {texto_limpo}"
                
        except Exception as e:
            leitura.mensagem_erro = f"Erro no parse: {str(e)}"
            leitura.estado = EstadoBalanca.ERRO
        
        return leitura


# ═══════════════════════════════════════════════════════════════════════════════
# FACTORY DE PARSERS
# ═══════════════════════════════════════════════════════════════════════════════

class ProtocolParserFactory:
    """Factory para criar parsers de protocolo"""
    
    @staticmethod
    def criar_parser(protocolo: ProtocoloBalanca) -> ProtocolParser:
        """Cria um parser para o protocolo especificado"""
        
        parsers = {
            ProtocoloBalanca.TOLEDO_A: ToledoProtocolA,
            ProtocoloBalanca.TOLEDO_B: ToledoProtocolB,
            ProtocoloBalanca.TOLEDO_P05A: ToledoProtocolA,  # Similar
            ProtocoloBalanca.TOLEDO_8217: ToledoProtocolA,
            
            ProtocoloBalanca.FILIZOLA_STX_ETX: FilizolaProtocol,
            ProtocoloBalanca.FILIZOLA_CONTINUO: lambda: GenericoProtocol("continuo"),
            
            ProtocoloBalanca.URANO_URAN12: UranoUran12Protocol,
            ProtocoloBalanca.URANO_STD01: lambda: UranoStdProtocol("std01"),
            ProtocoloBalanca.URANO_STD02: lambda: UranoStdProtocol("std02"),
            ProtocoloBalanca.URANO_STD03: lambda: UranoStdProtocol("std03"),
            ProtocoloBalanca.URANO_STD04: lambda: UranoStdProtocol("std04"),
            ProtocoloBalanca.URANO_STD05: lambda: UranoStdProtocol("std05"),
            
            ProtocoloBalanca.ELGIN_DP: ElginProtocol,
            ProtocoloBalanca.ELGIN_SA: ElginProtocol,
            
            ProtocoloBalanca.BALMAK_FLP15: BalmakProtocol,
            ProtocoloBalanca.BALMAK_ELINE: BalmakProtocol,
            
            ProtocoloBalanca.DIGITRON_STD: DigitronProtocol,
            
            ProtocoloBalanca.GENERICO_STX_ETX: lambda: GenericoProtocol("stx_etx"),
            ProtocoloBalanca.GENERICO_CONTINUO: lambda: GenericoProtocol("continuo"),
            ProtocoloBalanca.GENERICO_PESO_SIMPLES: lambda: GenericoProtocol("simples"),
            
            ProtocoloBalanca.AUTO_DETECT: lambda: GenericoProtocol("stx_etx"),
        }
        
        parser_class = parsers.get(protocolo, lambda: GenericoProtocol("stx_etx"))
        
        if callable(parser_class):
            return parser_class()
        return parser_class()


# ═══════════════════════════════════════════════════════════════════════════════
# CLASSE PRINCIPAL - GERENCIADOR DE BALANÇA
# ═══════════════════════════════════════════════════════════════════════════════

class GerenciadorBalanca:
    """
    Gerenciador principal de comunicação com balanças.
    Suporta múltiplos tipos de conexão e protocolos.
    """
    
    def __init__(self, configuracao: Optional[ConfiguracaoBalanca] = None):
        self.configuracao = configuracao or ConfiguracaoBalanca()
        self.estado = EstadoBalanca.DESCONECTADA
        self.ultima_leitura: Optional[LeituraPeso] = None
        self.parser: Optional[ProtocolParser] = None
        
        # Conexão serial
        self._serial: Optional[serial.Serial] = None
        
        # Thread de leitura contínua
        self._thread_leitura: Optional[threading.Thread] = None
        self._parar_leitura = threading.Event()
        self._fila_leituras: queue.Queue = queue.Queue(maxsize=100)
        
        # Callbacks
        self._callback_leitura: Optional[Callable[[LeituraPeso], None]] = None
        self._callback_estado: Optional[Callable[[EstadoBalanca], None]] = None
        self._callback_erro: Optional[Callable[[str], None]] = None
        
        # Lock para thread-safety
        self._lock = threading.Lock()
        
        # Histórico de leituras
        self._historico_leituras: List[LeituraPeso] = []
        self._max_historico = 100
        
        # Inicializa parser
        self._inicializar_parser()
    
    def _inicializar_parser(self):
        """Inicializa o parser de protocolo"""
        self.parser = ProtocolParserFactory.criar_parser(
            self.configuracao.config_protocolo.protocolo
        )
        logger.info(f"Parser inicializado: {self.parser.get_nome_protocolo()}")
    
    # ═══════════════════════════════════════════════════════════════════════════
    # MÉTODOS DE CONEXÃO
    # ═══════════════════════════════════════════════════════════════════════════
    
    def conectar(self) -> bool:
        """Estabelece conexão com a balança"""
        with self._lock:
            try:
                self._atualizar_estado(EstadoBalanca.CONECTANDO)
                
                if self.configuracao.tipo_conexao in [TipoConexao.SERIAL, TipoConexao.USB]:
                    return self._conectar_serial()
                elif self.configuracao.tipo_conexao == TipoConexao.BLUETOOTH:
                    return self._conectar_bluetooth()
                elif self.configuracao.tipo_conexao == TipoConexao.VIRTUAL:
                    return self._conectar_virtual()
                else:
                    logger.error(f"Tipo de conexão não suportado: {self.configuracao.tipo_conexao}")
                    return False
                    
            except Exception as e:
                logger.error(f"Erro ao conectar: {e}")
                self._atualizar_estado(EstadoBalanca.ERRO)
                if self._callback_erro:
                    self._callback_erro(str(e))
                return False
    
    def _conectar_serial(self) -> bool:
        """Conecta via porta serial"""
        if not SERIAL_AVAILABLE:
            logger.error("PySerial não disponível")
            return False
        
        config = self.configuracao.config_serial
        
        try:
            # Fecha conexão anterior se existir
            if self._serial and self._serial.is_open:
                self._serial.close()
            
            # Mapeia paridade
            parity_map = {'N': serial.PARITY_NONE, 'E': serial.PARITY_EVEN, 'O': serial.PARITY_ODD}
            parity = parity_map.get(config.parity, serial.PARITY_NONE)
            
            # Mapeia stop bits
            stopbits_map = {1: serial.STOPBITS_ONE, 1.5: serial.STOPBITS_ONE_POINT_FIVE, 2: serial.STOPBITS_TWO}
            stopbits = stopbits_map.get(config.stopbits, serial.STOPBITS_ONE)
            
            self._serial = serial.Serial(
                port=config.porta,
                baudrate=config.baudrate,
                bytesize=config.bytesize,
                parity=parity,
                stopbits=stopbits,
                timeout=config.timeout,
                xonxoff=config.xonxoff,
                rtscts=config.rtscts,
                dsrdtr=config.dsrdtr
            )
            
            if self._serial.is_open:
                logger.info(f"Conectado à porta {config.porta} @ {config.baudrate} bps")
                self._atualizar_estado(EstadoBalanca.CONECTADA)
                return True
            else:
                logger.error("Falha ao abrir porta serial")
                return False
                
        except serial.SerialException as e:
            logger.error(f"Erro serial: {e}")
            self._atualizar_estado(EstadoBalanca.ERRO)
            return False
    
    def _conectar_bluetooth(self) -> bool:
        """Conecta via Bluetooth"""
        if not BLUETOOTH_AVAILABLE:
            logger.error("Bluetooth não disponível")
            return False
        
        # Implementação básica - pode ser expandida
        logger.warning("Conexão Bluetooth ainda em desenvolvimento")
        return False
    
    def _conectar_virtual(self) -> bool:
        """Conexão virtual para testes"""
        logger.info("Conexão virtual estabelecida (modo teste)")
        self._atualizar_estado(EstadoBalanca.CONECTADA)
        return True
    
    def desconectar(self):
        """Desconecta da balança"""
        with self._lock:
            self.parar_leitura_continua()
            
            if self._serial and self._serial.is_open:
                try:
                    self._serial.close()
                    logger.info("Porta serial fechada")
                except Exception as e:
                    logger.error(f"Erro ao fechar porta: {e}")
            
            self._serial = None
            self._atualizar_estado(EstadoBalanca.DESCONECTADA)
    
    def esta_conectado(self) -> bool:
        """Verifica se está conectado"""
        if self.configuracao.tipo_conexao == TipoConexao.VIRTUAL:
            return self.estado == EstadoBalanca.CONECTADA
        
        return self._serial is not None and self._serial.is_open
    
    # ═══════════════════════════════════════════════════════════════════════════
    # MÉTODOS DE LEITURA
    # ═══════════════════════════════════════════════════════════════════════════
    
    def ler_peso(self) -> LeituraPeso:
        """
        Realiza uma leitura de peso sob demanda.
        Retorna um objeto LeituraPeso com o resultado.
        """
        if not self.esta_conectado():
            return LeituraPeso(
                valido=False,
                estado=EstadoBalanca.DESCONECTADA,
                mensagem_erro="Balança não conectada"
            )
        
        with self._lock:
            try:
                self._atualizar_estado(EstadoBalanca.LENDO)
                
                # Envia comando de leitura se necessário
                comando = self.parser.get_comando_leitura()
                if comando and self._serial:
                    self._serial.write(comando)
                    time.sleep(0.05)  # Pequeno delay
                
                # Lê resposta
                dados = self._ler_dados_serial()
                
                if dados:
                    leitura = self.parser.parse(dados)
                    try:
                        leitura.timestamp = datetime.now()
                    except AttributeError:
                        leitura.timestamp = datetime.datetime.now()
                    
                    # Aplica fator de conversão
                    if self.configuracao.config_protocolo.fator_conversao != 1.0:
                        leitura.peso_bruto *= self.configuracao.config_protocolo.fator_conversao
                        leitura.peso_liquido *= self.configuracao.config_protocolo.fator_conversao
                    
                    self.ultima_leitura = leitura
                    self._adicionar_historico(leitura)
                    
                    if leitura.valido:
                        self._atualizar_estado(leitura.estado)
                    
                    return leitura
                else:
                    return LeituraPeso(
                        valido=False,
                        estado=EstadoBalanca.ERRO,
                        mensagem_erro="Nenhum dado recebido"
                    )
                    
            except Exception as e:
                logger.error(f"Erro na leitura: {e}")
                return LeituraPeso(
                    valido=False,
                    estado=EstadoBalanca.ERRO,
                    mensagem_erro=str(e)
                )
    
    def _ler_dados_serial(self) -> bytes:
        """Lê dados da porta serial"""
        if not self._serial or not self._serial.is_open:
            return b""
        
        dados = b""
        timeout_ms = self.configuracao.config_protocolo.timeout_resposta_ms
        inicio = time.time()
        
        while (time.time() - inicio) * 1000 < timeout_ms:
            if self._serial.in_waiting > 0:
                dados += self._serial.read(self._serial.in_waiting)
                
                # Verifica se recebeu pacote completo
                if self._pacote_completo(dados):
                    break
            else:
                time.sleep(0.01)
        
        return dados
    
    def _pacote_completo(self, dados: bytes) -> bool:
        """Verifica se recebeu um pacote completo"""
        if not dados:
            return False
        
        # Verifica terminadores comuns
        if bytes([ASCII_ETX]) in dados:
            return True
        if bytes([ASCII_CR]) in dados:
            return True
        if bytes([ASCII_LF]) in dados:
            return True
        
        # Verifica tamanho mínimo
        return len(dados) >= 5
    
    # ═══════════════════════════════════════════════════════════════════════════
    # LEITURA CONTÍNUA
    # ═══════════════════════════════════════════════════════════════════════════
    
    def iniciar_leitura_continua(self, callback: Optional[Callable[[LeituraPeso], None]] = None):
        """Inicia leitura contínua em thread separada"""
        if self._thread_leitura and self._thread_leitura.is_alive():
            logger.warning("Leitura contínua já está ativa")
            return
        
        self._callback_leitura = callback
        self._parar_leitura.clear()
        
        self._thread_leitura = threading.Thread(
            target=self._loop_leitura_continua,
            daemon=True,  # NOTA: Thread daemon - será encerrada quando o programa principal terminar
            name="BalancaLeituraThread"
        )
        self._thread_leitura.start()
        logger.info("Leitura contínua iniciada")
    
    def parar_leitura_continua(self):
        """Para a leitura contínua"""
        self._parar_leitura.set()
        
        if self._thread_leitura and self._thread_leitura.is_alive():
            self._thread_leitura.join(timeout=2.0)
            logger.info("Leitura contínua parada")
    
    def _loop_leitura_continua(self):
        """Loop de leitura contínua"""
        intervalo = self.configuracao.config_protocolo.intervalo_leitura_ms / 1000.0
        
        while not self._parar_leitura.is_set():
            try:
                leitura = self.ler_peso()
                
                if leitura.valido:
                    # Adiciona à fila
                    try:
                        self._fila_leituras.put_nowait(leitura)
                    except queue.Full:
                        # Remove item antigo e adiciona novo
                        try:
                            self._fila_leituras.get_nowait()
                            self._fila_leituras.put_nowait(leitura)
                        except queue.Empty:
                            pass
                    
                    # Chama callback
                    if self._callback_leitura:
                        try:
                            self._callback_leitura(leitura)
                        except Exception as e:
                            logger.error(f"Erro no callback: {e}")
                
                time.sleep(intervalo)
                
            except Exception as e:
                logger.error(f"Erro no loop de leitura: {e}")
                time.sleep(0.5)
    
    def obter_ultima_leitura_fila(self) -> Optional[LeituraPeso]:
        """Obtém a última leitura da fila"""
        try:
            return self._fila_leituras.get_nowait()
        except queue.Empty:
            return None
    
    # ═══════════════════════════════════════════════════════════════════════════
    # CALLBACKS E EVENTOS
    # ═══════════════════════════════════════════════════════════════════════════
    
    def set_callback_leitura(self, callback: Callable[[LeituraPeso], None]):
        """Define callback para novas leituras"""
        self._callback_leitura = callback
    
    def set_callback_estado(self, callback: Callable[[EstadoBalanca], None]):
        """Define callback para mudanças de estado"""
        self._callback_estado = callback
    
    def set_callback_erro(self, callback: Callable[[str], None]):
        """Define callback para erros"""
        self._callback_erro = callback
    
    def _atualizar_estado(self, novo_estado: EstadoBalanca):
        """Atualiza o estado e notifica callback"""
        if self.estado != novo_estado:
            estado_anterior = self.estado
            self.estado = novo_estado
            logger.debug(f"Estado: {estado_anterior.name} -> {novo_estado.name}")
            
            if self._callback_estado:
                try:
                    self._callback_estado(novo_estado)
                except Exception as e:
                    logger.error(f"Erro no callback de estado: {e}")
    
    # ═══════════════════════════════════════════════════════════════════════════
    # HISTÓRICO
    # ═══════════════════════════════════════════════════════════════════════════
    
    def _adicionar_historico(self, leitura: LeituraPeso):
        """Adiciona leitura ao histórico"""
        self._historico_leituras.append(leitura)
        
        # Limita tamanho do histórico
        while len(self._historico_leituras) > self._max_historico:
            self._historico_leituras.pop(0)
    
    def obter_historico(self) -> List[LeituraPeso]:
        """Retorna o histórico de leituras"""
        return self._historico_leituras.copy()
    
    def limpar_historico(self):
        """Limpa o histórico de leituras"""
        self._historico_leituras.clear()
    
    # ═══════════════════════════════════════════════════════════════════════════
    # UTILITÁRIOS
    # ═══════════════════════════════════════════════════════════════════════════
    
    @staticmethod
    def listar_portas_disponiveis() -> List[Dict[str, str]]:
        """Lista todas as portas seriais disponíveis"""
        if not SERIAL_AVAILABLE:
            return []
        
        portas = []
        for porta in serial.tools.list_ports.comports():
            portas.append({
                'porta': porta.device,
                'descricao': porta.description,
                'hwid': porta.hwid,
                'fabricante': porta.manufacturer or '',
                'produto': porta.product or '',
                'serial': porta.serial_number or '',
                'vid': f"0x{porta.vid:04X}" if porta.vid else '',
                'pid': f"0x{porta.pid:04X}" if porta.pid else ''
            })
        
        return portas
    
    @staticmethod
    def detectar_balancas() -> List[Dict[str, Any]]:
        """
        Tenta detectar balanças conectadas automaticamente.
        Retorna lista de balanças encontradas com informações.
        """
        balancas_encontradas = []
        
        if not SERIAL_AVAILABLE:
            return balancas_encontradas
        
        portas = GerenciadorBalanca.listar_portas_disponiveis()
        
        # Palavras-chave que indicam balanças
        keywords_balanca = [
            'toledo', 'filizola', 'urano', 'elgin', 'balmak', 'digitron',
            'scale', 'balança', 'balanca', 'weight', 'serial', 'usb-serial',
            'ch340', 'cp210', 'ftdi', 'pl2303', 'prolific'
        ]
        
        for porta in portas:
            descricao_lower = (porta['descricao'] + ' ' + porta['fabricante'] + ' ' + porta['produto']).lower()
            
            # Verifica se é uma porta que pode ser balança
            is_potential_scale = any(kw in descricao_lower for kw in keywords_balanca)
            
            if is_potential_scale or 'COM' in porta['porta'] or '/dev/tty' in porta['porta']:
                balancas_encontradas.append({
                    'porta': porta['porta'],
                    'descricao': porta['descricao'],
                    'fabricante': porta['fabricante'],
                    'provavel_balanca': is_potential_scale,
                    'info_completa': porta
                })
        
        return balancas_encontradas
    
    def testar_conexao(self) -> Tuple[bool, str]:
        """
        Testa a conexão com a balança.
        Retorna (sucesso, mensagem).
        """
        if not self.esta_conectado():
            if not self.conectar():
                return False, "Falha ao conectar"
        
        try:
            leitura = self.ler_peso()
            
            if leitura.valido:
                peso_str = f"{leitura.peso_liquido:.3f} {leitura.unidade.value}"
                return True, f"Conexão OK - Peso: {peso_str}"
            elif leitura.estado == EstadoBalanca.PESO_INSTAVEL:
                return True, "Conexão OK - Peso instável (movimento)"
            else:
                return False, f"Erro na leitura: {leitura.mensagem_erro}"
                
        except Exception as e:
            return False, f"Erro no teste: {str(e)}"
    
    def auto_detectar_protocolo(self) -> Optional[ProtocoloBalanca]:
        """
        Tenta detectar automaticamente o protocolo da balança.
        """
        if not self.esta_conectado():
            return None
        
        protocolos_testar = [
            ProtocoloBalanca.TOLEDO_A,
            ProtocoloBalanca.TOLEDO_B,
            ProtocoloBalanca.FILIZOLA_STX_ETX,
            ProtocoloBalanca.URANO_STD01,
            ProtocoloBalanca.GENERICO_STX_ETX,
        ]
        
        for protocolo in protocolos_testar:
            try:
                self.configuracao.config_protocolo.protocolo = protocolo
                self._inicializar_parser()
                
                leitura = self.ler_peso()
                
                if leitura.valido:
                    logger.info(f"Protocolo detectado: {protocolo.value}")
                    return protocolo
                    
            except Exception as e:
                logger.debug(f"Protocolo {protocolo.value} falhou: {e}")
                continue
        
        return None


# ═══════════════════════════════════════════════════════════════════════════════
# GERENCIADOR DE CONFIGURAÇÃO
# ═══════════════════════════════════════════════════════════════════════════════

class ConfiguracaoBalancaManager:
    """Gerenciador de configurações de balanças"""
    
    def __init__(self, arquivo_config: str = "balanca_config.json"):
        self.arquivo_config = arquivo_config
        self.configuracoes: Dict[str, ConfiguracaoBalanca] = {}
        self.carregar()
    
    def carregar(self):
        """Carrega configurações do arquivo"""
        if os.path.exists(self.arquivo_config):
            try:
                with open(self.arquivo_config, 'r', encoding='utf-8') as f:
                    data = json.load(f)
                    
                for nome, config_dict in data.get('balancas', {}).items():
                    self.configuracoes[nome] = ConfiguracaoBalanca.from_dict(config_dict)
                    
                logger.info(f"Configurações carregadas: {len(self.configuracoes)} balanças")
                
            except Exception as e:
                logger.error(f"Erro ao carregar configurações: {e}")
    
    def salvar(self):
        """Salva configurações no arquivo"""
        try:
            data = {
                'balancas': {
                    nome: config.to_dict()
                    for nome, config in self.configuracoes.items()
                },
                'ultima_atualizacao': (datetime.now() if hasattr(datetime, 'now') else datetime.datetime.now()).isoformat()
            }
            
            with open(self.arquivo_config, 'w', encoding='utf-8') as f:
                json.dump(data, f, indent=2, ensure_ascii=False)
                
            logger.info("Configurações salvas")
            
        except Exception as e:
            logger.error(f"Erro ao salvar configurações: {e}")
    
    def adicionar_balanca(self, nome: str, config: ConfiguracaoBalanca):
        """Adiciona uma configuração de balança"""
        self.configuracoes[nome] = config
        self.salvar()
    
    def remover_balanca(self, nome: str):
        """Remove uma configuração de balança"""
        if nome in self.configuracoes:
            del self.configuracoes[nome]
            self.salvar()
    
    def obter_balanca(self, nome: str) -> Optional[ConfiguracaoBalanca]:
        """Obtém configuração de uma balança"""
        return self.configuracoes.get(nome)
    
    def listar_balancas(self) -> List[str]:
        """Lista nomes de balanças configuradas"""
        return list(self.configuracoes.keys())
    
    def obter_balanca_padrao(self) -> Optional[ConfiguracaoBalanca]:
        """Obtém a primeira balança ativa como padrão"""
        for config in self.configuracoes.values():
            if config.ativo:
                return config
        return None


# ═══════════════════════════════════════════════════════════════════════════════
# BALANÇA VIRTUAL PARA TESTES
# ═══════════════════════════════════════════════════════════════════════════════

class BalancaVirtual:
    """Balança virtual para testes e desenvolvimento"""
    
    def __init__(self):
        self.peso_atual = 0.0
        self.tara = 0.0
        self.estavel = True
        self.unidade = UnidadePeso.GRAMAS
    
    def set_peso(self, peso: float):
        """Define o peso atual"""
        self.peso_atual = peso
    
    def set_tara(self, tara: float):
        """Define a tara"""
        self.tara = tara
    
    def zerar_tara(self):
        """Zera a tara"""
        self.tara = self.peso_atual
    
    def get_leitura(self) -> LeituraPeso:
        """Retorna uma leitura simulada"""
        return LeituraPeso(
            peso_bruto=self.peso_atual,
            peso_liquido=self.peso_atual - self.tara,
            tara=self.tara,
            unidade=self.unidade,
            estavel=self.estavel,
            valido=True,
            estado=EstadoBalanca.PESO_ESTAVEL if self.estavel else EstadoBalanca.PESO_INSTAVEL,
            timestamp=(datetime.now() if hasattr(datetime, 'now') else datetime.datetime.now())
        )
    
    def simular_movimento(self):
        """Simula movimento na balança"""
        import random
        self.estavel = False
        self.peso_atual += random.uniform(-0.5, 0.5)
    
    def estabilizar(self):
        """Estabiliza a balança"""
        self.estavel = True


# ═══════════════════════════════════════════════════════════════════════════════
# FUNÇÕES DE CONVENIÊNCIA
# ═══════════════════════════════════════════════════════════════════════════════

def criar_gerenciador_padrao(porta: str = "", protocolo: ProtocoloBalanca = ProtocoloBalanca.AUTO_DETECT) -> GerenciadorBalanca:
    """
    Cria um gerenciador de balança com configurações padrão.
    """
    config = ConfiguracaoBalanca(
        nome="Balança PDV",
        tipo_conexao=TipoConexao.SERIAL,
        config_serial=ConfiguracaoSerial(
            porta=porta,
            baudrate=9600,
            bytesize=8,
            parity="N",
            stopbits=1.0,
            timeout=1.0
        ),
        config_protocolo=ConfiguracaoProtocolo(
            protocolo=protocolo,
            modo_leitura="sob_demanda",
            timeout_resposta_ms=500,
            casas_decimais=3,
            unidade_padrao=UnidadePeso.GRAMAS
        )
    )
    
    return GerenciadorBalanca(config)


def listar_protocolos_disponiveis() -> List[Dict[str, str]]:
    """Lista todos os protocolos disponíveis"""
    return [
        {'valor': p.value, 'nome': p.name, 'descricao': _get_descricao_protocolo(p)}
        for p in ProtocoloBalanca
    ]


def _get_descricao_protocolo(protocolo: ProtocoloBalanca) -> str:
    """Retorna descrição do protocolo"""
    descricoes = {
        ProtocoloBalanca.TOLEDO_A: "Toledo Protocolo A (STX/ETX sob demanda)",
        ProtocoloBalanca.TOLEDO_B: "Toledo Protocolo B (STX/CR contínuo)",
        ProtocoloBalanca.TOLEDO_P05A: "Toledo P05A (estendido)",
        ProtocoloBalanca.TOLEDO_8217: "Toledo 8217 Checkout",
        ProtocoloBalanca.FILIZOLA_STX_ETX: "Filizola STX/ETX",
        ProtocoloBalanca.FILIZOLA_CONTINUO: "Filizola Contínuo",
        ProtocoloBalanca.URANO_URAN12: "Urano URAN12 (completo)",
        ProtocoloBalanca.URANO_STD01: "Urano Std01 (kg com espaços)",
        ProtocoloBalanca.URANO_STD02: "Urano Std02 (kg com zeros)",
        ProtocoloBalanca.URANO_STD03: "Urano Std03 (kg formatado)",
        ProtocoloBalanca.URANO_STD04: "Urano Std04 (gramas)",
        ProtocoloBalanca.URANO_STD05: "Urano Std05 (variante)",
        ProtocoloBalanca.ELGIN_DP: "Elgin série DP",
        ProtocoloBalanca.ELGIN_SA: "Elgin série SA",
        ProtocoloBalanca.BALMAK_FLP15: "Balmak FLP15 (PRT3)",
        ProtocoloBalanca.BALMAK_ELINE: "Balmak E-Line",
        ProtocoloBalanca.DIGITRON_STD: "Digitron Standard",
        ProtocoloBalanca.GENERICO_STX_ETX: "Genérico STX/ETX",
        ProtocoloBalanca.GENERICO_CONTINUO: "Genérico Contínuo",
        ProtocoloBalanca.GENERICO_PESO_SIMPLES: "Genérico Peso Simples",
        ProtocoloBalanca.AUTO_DETECT: "Detecção Automática",
    }
    return descricoes.get(protocolo, protocolo.value)


