# INTERFACE GRÁFICA DE CONFIGURAÇÃO DE BALANÇAS
# ═══════════════════════════════════════════════════════════════════════════

import tkinter as tk
from tkinter import ttk, messagebox, simpledialog

# Classes já definidas acima no módulo de balança


# ═══════════════════════════════════════════════════════════════════════════════
# JANELA DE CONFIGURAÇÃO DE BALANÇA
# ═══════════════════════════════════════════════════════════════════════════════

class ConfiguracaoBalancaWindow(tk.Toplevel):
    """Janela de configuração completa de balança"""
    
    def __init__(self, parent, config_manager: ConfiguracaoBalancaManager, 
                 callback_salvar: Optional[Callable] = None):
        super().__init__(parent)
        self.status_bar = StatusBar(self, user_name=getattr(self, 'current_user', 'Usuário'))
        self.parent = parent
        self.config_manager = config_manager
        self.callback_salvar = callback_salvar
        
        self.title("⚖️ Configuração de Balança")
        self.state('zoomed')
        self.resizable(True, True)
        self.transient(parent)
        self.grab_set()
        
        # Variáveis
        self.vars = {}
        self.gerenciador_teste: Optional[GerenciadorBalanca] = None
        
        self._criar_interface()
        self._carregar_configuracao_existente()
        
        # Centraliza
        self.update_idletasks()
        x = (self.winfo_screenwidth() - self.winfo_width()) // 2
        y = (self.winfo_screenheight() - self.winfo_height()) // 2
        self.geometry(f"+{x}+{y}")
    
    def _criar_interface(self):
        """Cria a interface da janela"""
        # Frame principal com scroll
        main_frame = ttk.Frame(self, padding=10)
        main_frame.pack(fill=tk.BOTH, expand=True)
        
        # Notebook para organizar seções
        notebook = ttk.Notebook(main_frame)
        notebook.pack(fill=tk.BOTH, expand=True, pady=(0, 10))
        
        # Aba 1: Conexão
        tab_conexao = ttk.Frame(notebook, padding=10)
        notebook.add(tab_conexao, text="📡 Conexão")
        self._criar_aba_conexao(tab_conexao)
        
        # Aba 2: Protocolo
        tab_protocolo = ttk.Frame(notebook, padding=10)
        notebook.add(tab_protocolo, text="📋 Protocolo")
        self._criar_aba_protocolo(tab_protocolo)
        
        # Aba 3: Teste
        tab_teste = ttk.Frame(notebook, padding=10)
        notebook.add(tab_teste, text="🧪 Teste")
        self._criar_aba_teste(tab_teste)
        
        # Aba 4: Avançado
        tab_avancado = ttk.Frame(notebook, padding=10)
        notebook.add(tab_avancado, text="⚙️ Avançado")
        self._criar_aba_avancado(tab_avancado)
        
        # Botões de ação
        btn_frame = ttk.Frame(main_frame)
        btn_frame.pack(fill=tk.X)
        
        ttk.Button(btn_frame, text="💾 Salvar", command=self._salvar, 
                   bootstyle="success", width=15).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="🔍 Detectar Portas", command=self._detectar_portas,
                   bootstyle="info", width=15).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="🧪 Testar Conexão", command=self._testar_conexao,
                   bootstyle="warning", width=15).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="❌ Cancelar", command=self.destroy,
                   bootstyle="secondary", width=15).pack(side=tk.RIGHT, padx=5)
    
    def _criar_aba_conexao(self, parent):
        """Cria a aba de configuração de conexão"""
        # Nome da balança
        frame_nome = ttk.Labelframe(parent, text="Identificação", padding=10)
        frame_nome.pack(fill=tk.X, pady=5)
        
        ttk.Label(frame_nome, text="Nome da Balança:").grid(row=0, column=0, sticky="w", pady=2)
        self.vars['nome'] = tk.StringVar(value="Balança Principal")
        ttk.Entry(frame_nome, textvariable=self.vars['nome'], width=40).grid(row=0, column=1, sticky="ew", padx=5)
        
        self.vars['ativo'] = tk.BooleanVar(value=True)
        ttk.Checkbutton(frame_nome, text="Balança Ativa", variable=self.vars['ativo']).grid(row=0, column=2, padx=10)
        
        frame_nome.columnconfigure(1, weight=1)
        
        # Tipo de conexão
        frame_tipo = ttk.Labelframe(parent, text="Tipo de Conexão", padding=10)
        frame_tipo.pack(fill=tk.X, pady=5)
        
        self.vars['tipo_conexao'] = tk.StringVar(value="serial")
        tipos = [
            ("Serial RS-232", "serial"),
            ("USB (Serial Virtual)", "usb"),
            ("Bluetooth", "bluetooth"),
            ("Virtual (Teste)", "virtual")
        ]
        
        for i, (texto, valor) in enumerate(tipos):
            ttk.Radiobutton(frame_tipo, text=texto, value=valor, 
                           variable=self.vars['tipo_conexao'],
                           command=self._on_tipo_conexao_change).grid(row=0, column=i, padx=10)
        
        # Configuração Serial
        self.frame_serial = ttk.Labelframe(parent, text="Configuração Serial", padding=10)
        self.frame_serial.pack(fill=tk.X, pady=5)
        
        # Porta
        ttk.Label(self.frame_serial, text="Porta:").grid(row=0, column=0, sticky="w", pady=2)
        self.vars['porta'] = tk.StringVar()
        self.combo_porta = ttk.Combobox(self.frame_serial, textvariable=self.vars['porta'], width=20)
        self.combo_porta.grid(row=0, column=1, sticky="w", padx=5)
        ttk.Button(self.frame_serial, text="🔄", command=self._detectar_portas, width=3).grid(row=0, column=2)
        
        # Baudrate
        ttk.Label(self.frame_serial, text="Velocidade (bps):").grid(row=1, column=0, sticky="w", pady=2)
        self.vars['baudrate'] = tk.StringVar(value="9600")
        combo_baud = ttk.Combobox(self.frame_serial, textvariable=self.vars['baudrate'], width=10,
                                  values=["1200", "2400", "4800", "9600", "19200", "38400", "57600", "115200"])
        combo_baud.grid(row=1, column=1, sticky="w", padx=5)
        
        # Data bits
        ttk.Label(self.frame_serial, text="Data Bits:").grid(row=2, column=0, sticky="w", pady=2)
        self.vars['bytesize'] = tk.StringVar(value="8")
        ttk.Combobox(self.frame_serial, textvariable=self.vars['bytesize'], width=5,
                     values=["5", "6", "7", "8"]).grid(row=2, column=1, sticky="w", padx=5)
        
        # Paridade
        ttk.Label(self.frame_serial, text="Paridade:").grid(row=0, column=3, sticky="w", pady=2, padx=(20, 0))
        self.vars['parity'] = tk.StringVar(value="N")
        ttk.Combobox(self.frame_serial, textvariable=self.vars['parity'], width=10,
                     values=["N (Nenhuma)", "E (Par)", "O (Ímpar)"]).grid(row=0, column=4, sticky="w", padx=5)
        
        # Stop bits
        ttk.Label(self.frame_serial, text="Stop Bits:").grid(row=1, column=3, sticky="w", pady=2, padx=(20, 0))
        self.vars['stopbits'] = tk.StringVar(value="1")
        ttk.Combobox(self.frame_serial, textvariable=self.vars['stopbits'], width=5,
                     values=["1", "1.5", "2"]).grid(row=1, column=4, sticky="w", padx=5)
        
        # Timeout
        ttk.Label(self.frame_serial, text="Timeout (s):").grid(row=2, column=3, sticky="w", pady=2, padx=(20, 0))
        self.vars['timeout'] = tk.StringVar(value="1.0")
        ttk.Entry(self.frame_serial, textvariable=self.vars['timeout'], width=8).grid(row=2, column=4, sticky="w", padx=5)

        # Botão de Confirmação de Escolha (Solicitado pelo Usuário)
        # Inserido diretamente no grid do frame de Configuração Serial para visibilidade total
        self.btn_confirmar_escolha = ttk.Button(
            self.frame_serial, 
            text="✅ CONFIRMAR ESCOLHA DA BALANÇA", 
            command=self._confirmar_escolha_manual,
            bootstyle="success",
            width=45
        )
        # Garantindo que o grid tenha espaço e o botão seja visível
        self.btn_confirmar_escolha.grid(row=4, column=0, columnspan=5, pady=(20, 10), padx=10, sticky="ew")
        
        # Estilo para o botão ficar em destaque supremo
        style = ttk.Style()
        style.configure("Confirmar.TButton", font=("Segoe UI", 13, "bold"), padding=10)
        self.btn_confirmar_escolha.configure(style="Confirmar.TButton")
        
        # Configuração Bluetooth
        self.frame_bluetooth = ttk.Labelframe(parent, text="Configuração Bluetooth", padding=10)
        
        ttk.Label(self.frame_bluetooth, text="Endereço MAC:").grid(row=0, column=0, sticky="w", pady=2)
        self.vars['endereco_bluetooth'] = tk.StringVar()
        ttk.Entry(self.frame_bluetooth, textvariable=self.vars['endereco_bluetooth'], width=25).grid(row=0, column=1, padx=5)
        ttk.Button(self.frame_bluetooth, text="🔍 Buscar", command=self._buscar_bluetooth, width=10).grid(row=0, column=2)
        
        # Detecta portas inicialmente
        self._detectar_portas()
    
    def _confirmar_escolha_manual(self):
        """Ação do botão visual de confirmação de escolha"""
        self._salvar()

    def _criar_aba_protocolo(self, parent):
        """Cria a aba de configuração de protocolo"""
        # Protocolo
        frame_proto = ttk.Labelframe(parent, text="Protocolo de Comunicação", padding=10)
        frame_proto.pack(fill=tk.X, pady=5)
        
        ttk.Label(frame_proto, text="Protocolo:").grid(row=0, column=0, sticky="w", pady=2)
        self.vars['protocolo'] = tk.StringVar(value="auto_detect")
        
        protocolos = listar_protocolos_disponiveis()
        valores_proto = [p['valor'] for p in protocolos]
        
        self.combo_protocolo = ttk.Combobox(frame_proto, textvariable=self.vars['protocolo'], 
                                            values=valores_proto, width=30)
        self.combo_protocolo.grid(row=0, column=1, sticky="w", padx=5)
        
        # Descrição do protocolo
        self.lbl_desc_protocolo = ttk.Label(frame_proto, text="", foreground="gray")
        self.lbl_desc_protocolo.grid(row=1, column=0, columnspan=2, sticky="w", pady=5)
        self.combo_protocolo.bind("<<ComboboxSelected>>", self._on_protocolo_change)
        
        # Modo de leitura
        frame_modo = ttk.Labelframe(parent, text="Modo de Leitura", padding=10)
        frame_modo.pack(fill=tk.X, pady=5)
        
        self.vars['modo_leitura'] = tk.StringVar(value="sob_demanda")
        ttk.Radiobutton(frame_modo, text="Sob Demanda (solicita peso)", 
                       value="sob_demanda", variable=self.vars['modo_leitura']).grid(row=0, column=0, padx=10)
        ttk.Radiobutton(frame_modo, text="Contínuo (recebe automaticamente)", 
                       value="continuo", variable=self.vars['modo_leitura']).grid(row=0, column=1, padx=10)
        
        # Configurações de leitura
        frame_leitura = ttk.Labelframe(parent, text="Parâmetros de Leitura", padding=10)
        frame_leitura.pack(fill=tk.X, pady=5)
        
        ttk.Label(frame_leitura, text="Intervalo de Leitura (ms):").grid(row=0, column=0, sticky="w", pady=2)
        self.vars['intervalo_leitura'] = tk.StringVar(value="100")
        ttk.Entry(frame_leitura, textvariable=self.vars['intervalo_leitura'], width=10).grid(row=0, column=1, padx=5)
        
        ttk.Label(frame_leitura, text="Timeout Resposta (ms):").grid(row=0, column=2, sticky="w", pady=2, padx=(20, 0))
        self.vars['timeout_resposta'] = tk.StringVar(value="500")
        ttk.Entry(frame_leitura, textvariable=self.vars['timeout_resposta'], width=10).grid(row=0, column=3, padx=5)
        
        ttk.Label(frame_leitura, text="Casas Decimais:").grid(row=1, column=0, sticky="w", pady=2)
        self.vars['casas_decimais'] = tk.StringVar(value="3")
        ttk.Combobox(frame_leitura, textvariable=self.vars['casas_decimais'], 
                     values=["0", "1", "2", "3", "4"], width=5).grid(row=1, column=1, padx=5)
        
        ttk.Label(frame_leitura, text="Unidade Padrão:").grid(row=1, column=2, sticky="w", pady=2, padx=(20, 0))
        self.vars['unidade_padrao'] = tk.StringVar(value="g")
        ttk.Combobox(frame_leitura, textvariable=self.vars['unidade_padrao'],
                     values=["g", "kg", "lb", "oz"], width=5).grid(row=1, column=3, padx=5)
        
        # Tabela de protocolos por marca
        frame_info = ttk.Labelframe(parent, text="📋 Guia de Protocolos por Marca", padding=10)
        frame_info.pack(fill=tk.BOTH, expand=True, pady=5)
        
        info_text = """
TOLEDO:
  • Prix II, III, 9094: toledo_a (STX/ETX) ou toledo_b (contínuo)
  • 8217 Checkout: toledo_8217
  • Modelos novos: toledo_p05a

FILIZOLA:
  • Platina, CS, MF: filizola_stx_etx

URANO:
  • UDC CO/CO-E: urano_std01 a urano_std05 ou urano_uran12
  • POP, US: urano_std01 (equivalente PRT3)

ELGIN:
  • DP-3005: elgin_dp
  • SA-110: elgin_sa

BALMAK:
  • E-Line, BCK: balmak_flp15 (equivalente PRT3)

DIGITRON:
  • Todas as linhas: digitron_std

Se não souber o protocolo, use "auto_detect" para detecção automática.
        """
        
        text_widget = tk.Text(frame_info, height=12, wrap=tk.WORD, font=("Consolas", 9))
        text_widget.insert("1.0", info_text.strip())
        text_widget.config(state=tk.DISABLED)
        text_widget.pack(fill=tk.BOTH, expand=True)
    
    def _criar_aba_teste(self, parent):
        """Cria a aba de teste de conexão"""
        # Status
        frame_status = ttk.Labelframe(parent, text="Status da Conexão", padding=10)
        frame_status.pack(fill=tk.X, pady=5)
        
        self.lbl_status = ttk.Label(frame_status, text="⚪ Desconectado", font=("Segoe UI", 12))
        self.lbl_status.pack(anchor="w")
        
        self.lbl_protocolo_atual = ttk.Label(frame_status, text="Protocolo: -", foreground="gray")
        self.lbl_protocolo_atual.pack(anchor="w")
        
        # Leitura atual
        frame_leitura = ttk.Labelframe(parent, text="Leitura Atual", padding=10)
        frame_leitura.pack(fill=tk.X, pady=5)
        
        self.lbl_peso = ttk.Label(frame_leitura, text="0,000 g", font=("Segoe UI", 36, "bold"), foreground="#28a745")
        self.lbl_peso.pack(pady=10)
        
        self.lbl_estado_peso = ttk.Label(frame_leitura, text="", foreground="gray")
        self.lbl_estado_peso.pack()
        
        # Botões de teste
        frame_btns = ttk.Frame(parent)
        frame_btns.pack(fill=tk.X, pady=10)
        
        ttk.Button(frame_btns, text="🔌 Conectar", command=self._conectar_teste,
                   bootstyle="success", width=15).pack(side=tk.LEFT, padx=5)
        ttk.Button(frame_btns, text="📖 Ler Peso", command=self._ler_peso_teste,
                   bootstyle="primary", width=15).pack(side=tk.LEFT, padx=5)
        ttk.Button(frame_btns, text="🔄 Leitura Contínua", command=self._toggle_leitura_continua,
                   bootstyle="info", width=15).pack(side=tk.LEFT, padx=5)
        ttk.Button(frame_btns, text="🔌 Desconectar", command=self._desconectar_teste,
                   bootstyle="danger", width=15).pack(side=tk.LEFT, padx=5)
        
        self.leitura_continua_ativa = False
        
        # Log de comunicação
        frame_log = ttk.Labelframe(parent, text="Log de Comunicação", padding=10)
        frame_log.pack(fill=tk.BOTH, expand=True, pady=5)
        
        self.text_log = tk.Text(frame_log, height=8, wrap=tk.WORD, font=("Consolas", 9))
        self.text_log.pack(fill=tk.BOTH, expand=True)
        
        scrollbar = ttk.Scrollbar(self.text_log, orient=tk.VERTICAL, command=self.text_log.yview)
        self.text_log.configure(yscrollcommand=scrollbar.set)
        scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
    
    def _criar_aba_avancado(self, parent):
        """Cria a aba de configurações avançadas"""
        # Fator de conversão
        frame_conv = ttk.Labelframe(parent, text="Calibração e Conversão", padding=10)
        frame_conv.pack(fill=tk.X, pady=5)
        
        ttk.Label(frame_conv, text="Fator de Conversão:").grid(row=0, column=0, sticky="w", pady=2)
        self.vars['fator_conversao'] = tk.StringVar(value="1.0")
        ttk.Entry(frame_conv, textvariable=self.vars['fator_conversao'], width=10).grid(row=0, column=1, padx=5)
        ttk.Label(frame_conv, text="(multiplica o peso lido)", foreground="gray").grid(row=0, column=2, padx=5)
        
        ttk.Label(frame_conv, text="Tentativas de Reconexão:").grid(row=1, column=0, sticky="w", pady=2)
        self.vars['tentativas_reconexao'] = tk.StringVar(value="3")
        ttk.Entry(frame_conv, textvariable=self.vars['tentativas_reconexao'], width=5).grid(row=1, column=1, padx=5)
        
        # Controle de fluxo
        frame_fluxo = ttk.Labelframe(parent, text="Controle de Fluxo", padding=10)
        frame_fluxo.pack(fill=tk.X, pady=5)
        
        self.vars['xonxoff'] = tk.BooleanVar(value=False)
        ttk.Checkbutton(frame_fluxo, text="XON/XOFF (Software)", variable=self.vars['xonxoff']).grid(row=0, column=0, padx=10)
        
        self.vars['rtscts'] = tk.BooleanVar(value=False)
        ttk.Checkbutton(frame_fluxo, text="RTS/CTS (Hardware)", variable=self.vars['rtscts']).grid(row=0, column=1, padx=10)
        
        self.vars['dsrdtr'] = tk.BooleanVar(value=False)
        ttk.Checkbutton(frame_fluxo, text="DSR/DTR", variable=self.vars['dsrdtr']).grid(row=0, column=2, padx=10)
        
        # Informações do sistema
        frame_info = ttk.Labelframe(parent, text="Informações do Sistema", padding=10)
        frame_info.pack(fill=tk.X, pady=5)
        
        info = f"PySerial: {'✓ Disponível' if SERIAL_AVAILABLE else '✗ Não instalado'}"
        ttk.Label(frame_info, text=info).pack(anchor="w")
        
        # Botão para instalar dependências
        if not SERIAL_AVAILABLE:
            ttk.Button(frame_info, text="📦 Instalar PySerial", 
                      command=self._instalar_pyserial, bootstyle="warning").pack(pady=5)
    
    def _on_tipo_conexao_change(self):
        """Callback quando tipo de conexão muda"""
        tipo = self.vars['tipo_conexao'].get()
        
        if tipo in ['serial', 'usb']:
            self.frame_serial.pack(fill=tk.X, pady=5, after=self.frame_serial.master.winfo_children()[1])
            self.frame_bluetooth.pack_forget()
        elif tipo == 'bluetooth':
            self.frame_serial.pack_forget()
            self.frame_bluetooth.pack(fill=tk.X, pady=5, after=self.frame_serial.master.winfo_children()[1])
        else:
            self.frame_serial.pack_forget()
            self.frame_bluetooth.pack_forget()
    
    def _on_protocolo_change(self, event=None):
        """Callback quando protocolo muda"""
        protocolo = self.vars['protocolo'].get()
        protocolos = listar_protocolos_disponiveis()
        
        for p in protocolos:
            if p['valor'] == protocolo:
                self.lbl_desc_protocolo.config(text=p['descricao'])
                break
    
    def _detectar_portas(self):
        """Detecta portas seriais disponíveis"""
        portas = GerenciadorBalanca.listar_portas_disponiveis()
        valores = [f"{p['porta']} - {p['descricao']}" for p in portas]
        
        self.combo_porta['values'] = valores
        
        if valores and not self.vars['porta'].get():
            self.combo_porta.current(0)
        
        self._log(f"Detectadas {len(portas)} portas seriais")
    
    def _buscar_bluetooth(self):
        """Busca dispositivos Bluetooth"""
        messagebox.showinfo("Bluetooth", "Busca de dispositivos Bluetooth ainda em desenvolvimento.\n\n"
                           "Por favor, insira o endereço MAC manualmente.")
    
    def _instalar_pyserial(self):
        """Instala PySerial"""
        import subprocess
        try:
            subprocess.check_call(['pip', 'install', 'pyserial'])
            messagebox.showinfo("Sucesso", "PySerial instalado com sucesso!\n\nReinicie o aplicativo.")
        except Exception as e:
            messagebox.showerror("Erro", f"Falha ao instalar PySerial:\n{e}")
    
    def _criar_configuracao(self) -> ConfiguracaoBalanca:
        """Cria objeto de configuração a partir dos campos"""
        # Extrai porta (remove descrição)
        porta_str = self.vars['porta'].get()
        porta = porta_str.split(' - ')[0] if ' - ' in porta_str else porta_str
        
        # Extrai paridade
        parity_str = self.vars['parity'].get()
        parity = parity_str[0] if parity_str else 'N'
        
        config = ConfiguracaoBalanca(
            nome=self.vars['nome'].get(),
            tipo_conexao=TipoConexao(self.vars['tipo_conexao'].get()),
            config_serial=ConfiguracaoSerial(
                porta=porta,
                baudrate=int(self.vars['baudrate'].get()),
                bytesize=int(self.vars['bytesize'].get()),
                parity=parity,
                stopbits=float(self.vars['stopbits'].get()),
                timeout=float(self.vars['timeout'].get()),
                xonxoff=self.vars['xonxoff'].get(),
                rtscts=self.vars['rtscts'].get(),
                dsrdtr=self.vars['dsrdtr'].get()
            ),
            config_protocolo=ConfiguracaoProtocolo(
                protocolo=ProtocoloBalanca(self.vars['protocolo'].get()),
                modo_leitura=self.vars['modo_leitura'].get(),
                intervalo_leitura_ms=int(self.vars['intervalo_leitura'].get()),
                timeout_resposta_ms=int(self.vars['timeout_resposta'].get()),
                tentativas_reconexao=int(self.vars['tentativas_reconexao'].get()),
                casas_decimais=int(self.vars['casas_decimais'].get()),
                unidade_padrao=UnidadePeso(self.vars['unidade_padrao'].get()),
                fator_conversao=float(self.vars['fator_conversao'].get())
            ),
            endereco_bluetooth=self.vars['endereco_bluetooth'].get(),
            ativo=self.vars['ativo'].get()
        )
        
        return config
    
    def _carregar_configuracao_existente(self):
        """Carrega configuração existente se houver"""
        config = self.config_manager.obter_balanca_padrao()
        if config:
            self.vars['nome'].set(config.nome)
            self.vars['tipo_conexao'].set(config.tipo_conexao.value)
            self.vars['porta'].set(config.config_serial.porta)
            self.vars['baudrate'].set(str(config.config_serial.baudrate))
            self.vars['bytesize'].set(str(config.config_serial.bytesize))
            self.vars['parity'].set(config.config_serial.parity)
            self.vars['stopbits'].set(str(config.config_serial.stopbits))
            self.vars['timeout'].set(str(config.config_serial.timeout))
            self.vars['protocolo'].set(config.config_protocolo.protocolo.value)
            self.vars['modo_leitura'].set(config.config_protocolo.modo_leitura)
            self.vars['intervalo_leitura'].set(str(config.config_protocolo.intervalo_leitura_ms))
            self.vars['timeout_resposta'].set(str(config.config_protocolo.timeout_resposta_ms))
            self.vars['casas_decimais'].set(str(config.config_protocolo.casas_decimais))
            self.vars['unidade_padrao'].set(config.config_protocolo.unidade_padrao.value)
            self.vars['fator_conversao'].set(str(config.config_protocolo.fator_conversao))
            self.vars['tentativas_reconexao'].set(str(config.config_protocolo.tentativas_reconexao))
            self.vars['endereco_bluetooth'].set(config.endereco_bluetooth)
            self.vars['ativo'].set(config.ativo)
            self.vars['xonxoff'].set(config.config_serial.xonxoff)
            self.vars['rtscts'].set(config.config_serial.rtscts)
            self.vars['dsrdtr'].set(config.config_serial.dsrdtr)
    
    def _salvar(self):
        """Salva a configuração"""
        try:
            config = self._criar_configuracao()
            
            # Modal de Confirmação de Escolha da Balança
            confirmacao = messagebox.askyesno(
                "Confirmar Escolha da Balança",
                f"Você selecionou a balança: {config.nome}\n\n"
                f"Tipo de Conexão: {config.tipo_conexao.value.upper()}\n"
                f"Protocolo: {config.config_protocolo.protocolo.value}\n\n"
                "Deseja confirmar esta escolha e salvar as configurações?",
                parent=self
            )
            
            if not confirmacao:
                return
                
            self.config_manager.adicionar_balanca(config.nome, config)
            
            if self.callback_salvar:
                self.callback_salvar(config)
            
            messagebox.showinfo("Sucesso", "Configuração da balança salva e confirmada com sucesso!", parent=self)
            self.destroy()
            
        except Exception as e:
            messagebox.showerror("Erro", f"Erro ao salvar configuração:\n{e}", parent=self)
    
    def _testar_conexao(self):
        """Testa a conexão com a balança"""
        self._conectar_teste()
        if self.gerenciador_teste and self.gerenciador_teste.esta_conectado():
            self._ler_peso_teste()
    
    def _conectar_teste(self):
        """Conecta para teste"""
        try:
            config = self._criar_configuracao()
            self.gerenciador_teste = GerenciadorBalanca(config)
            
            if self.gerenciador_teste.conectar():
                self.lbl_status.config(text="🟢 Conectado", foreground="#28a745")
                self.lbl_protocolo_atual.config(text=f"Protocolo: {self.gerenciador_teste.parser.get_nome_protocolo()}")
                self._log("Conexão estabelecida com sucesso")
            else:
                self.lbl_status.config(text="🔴 Falha na conexão", foreground="#dc3545")
                self._log("Falha ao conectar")
                
        except Exception as e:
            self.lbl_status.config(text="🔴 Erro", foreground="#dc3545")
            self._log(f"Erro: {e}")
    
    def _desconectar_teste(self):
        """Desconecta do teste"""
        if self.gerenciador_teste:
            self.gerenciador_teste.desconectar()
            self.gerenciador_teste = None
        
        self.leitura_continua_ativa = False
        self.lbl_status.config(text="⚪ Desconectado", foreground="gray")
        self.lbl_protocolo_atual.config(text="Protocolo: -")
        self._log("Desconectado")
    
    def _ler_peso_teste(self):
        """Lê peso para teste"""
        if not self.gerenciador_teste or not self.gerenciador_teste.esta_conectado():
            self._log("Não conectado")
            return
        
        leitura = self.gerenciador_teste.ler_peso()
        self._atualizar_display_peso(leitura)
        
        if leitura.valido:
            self._log(f"Peso: {leitura.peso_liquido:.3f} {leitura.unidade.value}")
        else:
            self._log(f"Erro na leitura: {leitura.mensagem_erro}")
    
    def _toggle_leitura_continua(self):
        """Liga/desliga leitura contínua"""
        if not self.gerenciador_teste or not self.gerenciador_teste.esta_conectado():
            self._log("Não conectado")
            return
        
        if self.leitura_continua_ativa:
            self.gerenciador_teste.parar_leitura_continua()
            self.leitura_continua_ativa = False
            self._log("Leitura contínua parada")
        else:
            self.gerenciador_teste.iniciar_leitura_continua(self._callback_leitura_continua)
            self.leitura_continua_ativa = True
            self._log("Leitura contínua iniciada")
    
    def _callback_leitura_continua(self, leitura: LeituraPeso):
        """Callback para leitura contínua"""
        self.after(0, lambda: self._atualizar_display_peso(leitura))
    
    def _atualizar_display_peso(self, leitura: LeituraPeso):
        """Atualiza o display de peso"""
        if leitura.valido:
            peso_str = f"{leitura.peso_liquido:,.3f} {leitura.unidade.value}".replace(',', 'X').replace('.', ',').replace('X', '.')
            self.lbl_peso.config(text=peso_str, foreground="#28a745")
            
            estado_str = "✓ Estável" if leitura.estavel else "⚡ Instável"
            self.lbl_estado_peso.config(text=estado_str)
        else:
            self.lbl_peso.config(text="---", foreground="#dc3545")
            self.lbl_estado_peso.config(text=leitura.mensagem_erro)
    
    def _log(self, mensagem: str):
        """Adiciona mensagem ao log"""
        try:
            import datetime as _dt_local
            # Tenta acessar como módulo, se falhar tenta como classe
            try:
                now_obj = _dt_local.datetime.now()
            except AttributeError:
                now_obj = _dt_local.now()
            timestamp = now_obj.strftime("%H:%M:%S")
        except Exception:
            timestamp = "--:--:--"
        
        if hasattr(self, 'text_log') and self.text_log:
            self.text_log.insert(tk.END, f"[{timestamp}] {mensagem}\n")
            self.text_log.see(tk.END)
    
    def destroy(self):
        """Limpa recursos ao fechar"""
        if self.gerenciador_teste:
            self.gerenciador_teste.desconectar()
        super().destroy()


# ═══════════════════════════════════════════════════════════════════════════════
# WIDGET DE PESAGEM PARA PDV
# ═══════════════════════════════════════════════════════════════════════════════

class WidgetPesagem(ttk.Frame):
    """Widget compacto para pesagem no PDV"""
    
    def __init__(self, parent, gerenciador: Optional[GerenciadorBalanca] = None,
                 callback_peso: Optional[Callable[[float], None]] = None, **kwargs):
        super().__init__(parent, **kwargs)
        
        self.gerenciador = gerenciador
        self.callback_peso = callback_peso
        self.ultima_leitura: Optional[LeituraPeso] = None
        
        self._criar_interface()
    
    def _criar_interface(self):
        """Cria a interface do widget"""
        # Frame principal
        self.configure(padding=5)
        
        # Indicador de status
        status_frame = ttk.Frame(self)
        status_frame.pack(fill=tk.X)
        
        self.lbl_status = ttk.Label(status_frame, text="⚖️", font=("Segoe UI", 12))
        self.lbl_status.pack(side=tk.LEFT)
        
        self.lbl_conexao = ttk.Label(status_frame, text="Desconectado", font=("Segoe UI", 9), foreground="gray")
        self.lbl_conexao.pack(side=tk.LEFT, padx=5)
        
        # Display de peso
        self.lbl_peso = ttk.Label(self, text="0,000 g", font=("Segoe UI", 18, "bold"), foreground="#28a745")
        self.lbl_peso.pack(pady=5)
        
        # Botão de pesar
        self.btn_pesar = ttk.Button(self, text="⚖️ PESAR", command=self.pesar, bootstyle="success")
        self.btn_pesar.pack(fill=tk.X, pady=2)
        
        # Botão de usar peso
        self.btn_usar = ttk.Button(self, text="✓ Usar Este Peso", command=self._usar_peso, 
                                   bootstyle="primary", state=tk.DISABLED)
        self.btn_usar.pack(fill=tk.X, pady=2)
    
    def set_gerenciador(self, gerenciador: GerenciadorBalanca):
        """Define o gerenciador de balança"""
        self.gerenciador = gerenciador
        self._atualizar_status()
    
    def set_callback(self, callback: Callable[[float], None]):
        """Define callback para quando peso for usado"""
        self.callback_peso = callback
    
    def _atualizar_status(self):
        """Atualiza indicador de status"""
        if self.gerenciador and self.gerenciador.esta_conectado():
            self.lbl_conexao.config(text="Conectado", foreground="#28a745")
            self.btn_pesar.config(state=tk.NORMAL)
        else:
            self.lbl_conexao.config(text="Desconectado", foreground="gray")
            self.btn_pesar.config(state=tk.DISABLED)
    
    def conectar(self) -> bool:
        """Conecta à balança"""
        if self.gerenciador:
            resultado = self.gerenciador.conectar()
            self._atualizar_status()
            return resultado
        return False
    
    def desconectar(self):
        """Desconecta da balança"""
        if self.gerenciador:
            self.gerenciador.desconectar()
            self._atualizar_status()
    
    def pesar(self) -> Optional[float]:
        """Realiza uma pesagem e retorna o peso em gramas"""
        if not self.gerenciador:
            return None
        
        if not self.gerenciador.esta_conectado():
            if not self.conectar():
                messagebox.showerror("Erro", "Não foi possível conectar à balança")
                return None
        
        leitura = self.gerenciador.ler_peso()
        self.ultima_leitura = leitura
        
        if leitura.valido:
            peso_gramas = leitura.peso_em_gramas()
            peso_str = f"{peso_gramas:,.3f} g".replace(',', 'X').replace('.', ',').replace('X', '.')
            self.lbl_peso.config(text=peso_str, foreground="#28a745")
            self.btn_usar.config(state=tk.NORMAL)
            return peso_gramas
        else:
            self.lbl_peso.config(text="Erro", foreground="#dc3545")
            self.btn_usar.config(state=tk.DISABLED)
            
            if leitura.estado == EstadoBalanca.PESO_INSTAVEL:
                messagebox.showwarning("Aviso", "Peso instável. Aguarde a estabilização.")
            else:
                messagebox.showerror("Erro", f"Erro na leitura: {leitura.mensagem_erro}")
            
            return None
    
    def _usar_peso(self):
        """Usa o peso atual"""
        if self.ultima_leitura and self.ultima_leitura.valido and self.callback_peso:
            peso_gramas = self.ultima_leitura.peso_em_gramas()
            self.callback_peso(peso_gramas)
    
    def obter_peso_atual(self) -> Optional[float]:
        """Retorna o último peso lido em gramas"""
        if self.ultima_leitura and self.ultima_leitura.valido:
            return self.ultima_leitura.peso_em_gramas()
        return None


# ═══════════════════════════════════════════════════════════════════════════════
# DIÁLOGO DE PESAGEM RÁPIDA
# ═══════════════════════════════════════════════════════════════════════════════

class DialogoPesagem(tk.Toplevel):
    """Diálogo para pesagem rápida"""
    
    def __init__(self, parent, gerenciador: GerenciadorBalanca, titulo: str = "Pesagem"):
        super().__init__(parent)
        self.status_bar = StatusBar(self, user_name=getattr(self, 'current_user', 'Usuário'))
        self.gerenciador = gerenciador
        self.resultado: Optional[float] = None
        
        self.title(f"⚖️ {titulo}")
        responsive_geometry(self, 350, 300)
        self.resizable(True, True)
        self.transient(parent)
        self.grab_set()
        
        self._criar_interface()
        
        # Centraliza
        self.update_idletasks()
        x = (self.winfo_screenwidth() - self.winfo_width()) // 2
        y = (self.winfo_screenheight() - self.winfo_height()) // 2
        self.geometry(f"+{x}+{y}")
        
        # Conecta automaticamente
        self.after(100, self._conectar_e_ler)
    
    def _criar_interface(self):
        """Cria interface do diálogo"""
        main_frame = ttk.Frame(self, padding=20)
        main_frame.pack(fill=tk.BOTH, expand=True)
        
        # Título
        ttk.Label(main_frame, text="Coloque o produto na balança", 
                 font=("Segoe UI", 11)).pack(pady=10)
        
        # Display de peso
        self.lbl_peso = ttk.Label(main_frame, text="Aguardando...", 
                                  font=("Segoe UI", 32, "bold"), foreground="#6c757d")
        self.lbl_peso.pack(pady=20)
        
        # Status
        self.lbl_status = ttk.Label(main_frame, text="", foreground="gray")
        self.lbl_status.pack()
        
        # Botões
        btn_frame = ttk.Frame(main_frame)
        btn_frame.pack(fill=tk.X, pady=20)
        
        ttk.Button(btn_frame, text="🔄 Ler Novamente", command=self._ler_peso,
                   bootstyle="info", width=15).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="✓ Confirmar", command=self._confirmar,
                   bootstyle="success", width=15).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="✗ Cancelar", command=self._cancelar,
                   bootstyle="secondary", width=15).pack(side=tk.RIGHT, padx=5)
    
    def _conectar_e_ler(self):
        """Conecta e faz primeira leitura"""
        if not self.gerenciador.esta_conectado():
            self.lbl_status.config(text="Conectando...")
            if not self.gerenciador.conectar():
                self.lbl_peso.config(text="Erro", foreground="#dc3545")
                self.lbl_status.config(text="Falha na conexão")
                return
        
        self._ler_peso()
    
    def _ler_peso(self):
        """Lê o peso da balança"""
        self.lbl_status.config(text="Lendo...")
        self.update()
        
        leitura = self.gerenciador.ler_peso()
        
        if leitura.valido:
            self.resultado = leitura.peso_em_gramas()
            peso_str = f"{self.resultado:,.3f} g".replace(',', 'X').replace('.', ',').replace('X', '.')
            self.lbl_peso.config(text=peso_str, foreground="#28a745")
            self.lbl_status.config(text="✓ Peso estável" if leitura.estavel else "⚡ Peso instável")
        else:
            self.resultado = None
            self.lbl_peso.config(text="---", foreground="#dc3545")
            self.lbl_status.config(text=leitura.mensagem_erro)
    
    def _confirmar(self):
        """Confirma o peso"""
        if self.resultado is not None:
            self.destroy()
        else:
            messagebox.showwarning("Aviso", "Nenhum peso válido para confirmar")
    
    def _cancelar(self):
        """Cancela a pesagem"""
        self.resultado = None
        self.destroy()


# ═══════════════════════════════════════════════════════════════════════════════
# FUNÇÕES DE CONVENIÊNCIA
# ═══════════════════════════════════════════════════════════════════════════════

def abrir_dialogo_pesagem(parent, gerenciador: GerenciadorBalanca, titulo: str = "Pesagem") -> Optional[float]:
    """
    Abre diálogo de pesagem e retorna o peso em gramas.
    Retorna None se cancelado.
    """
    dialogo = DialogoPesagem(parent, gerenciador, titulo)
    parent.wait_window(dialogo)
    return dialogo.resultado


def criar_widget_pesagem(parent, config_manager: ConfiguracaoBalancaManager,
                         callback_peso: Optional[Callable[[float], None]] = None) -> WidgetPesagem:
    """
    Cria um widget de pesagem configurado.
    """
    config = config_manager.obter_balanca_padrao()
    gerenciador = GerenciadorBalanca(config) if config else None
    
    widget = WidgetPesagem(parent, gerenciador, callback_peso)
    return widget


