# INTEGRAÇÃO DE BALANÇA COM PDV
# ═══════════════════════════════════════════════════════════════════════════

import tkinter as tk
from tkinter import ttk, messagebox

# Classes de balança já definidas acima
BALANCA_DISPONIVEL = True


# ═══════════════════════════════════════════════════════════════════════════════
# CLASSE DE INTEGRAÇÃO COM PDV
# ═══════════════════════════════════════════════════════════════════════════════

class BalancaIntegracaoPDV:
    """
    Classe que integra o sistema de balanças com o PDV.
    Gerencia a conexão, leitura e aplicação do peso nos produtos.
    """
    
    def __init__(self, app, persistence_dir: str):
        """
        Inicializa a integração de balança com o PDV.
        
        Args:
            app: Instância do PDVSuperApp
            persistence_dir: Diretório para salvar configurações
        """
        self.app = app
        self.persistence_dir = persistence_dir
        self.config_file = os.path.join(persistence_dir, "balanca_config.json")
        
        # Gerenciadores
        self.config_manager: Optional[ConfiguracaoBalancaManager] = None
        self.gerenciador: Optional[GerenciadorBalanca] = None
        
        # Estado
        self.conectado = False
        self.leitura_continua_ativa = False
        self.ultima_leitura: Optional[LeituraPeso] = None
        
        # Widgets
        self.widget_status: Optional[ttk.Label] = None
        self.widget_peso: Optional[ttk.Label] = None
        self.btn_pesar: Optional[ttk.Button] = None
        
        # Inicializa
        if BALANCA_DISPONIVEL:
            self._carregar_configuracao()
    
    def _carregar_configuracao(self):
        """Carrega configuração salva"""
        self.config_manager = ConfiguracaoBalancaManager(self.config_file)
        
        # Se há configuração, cria o gerenciador
        config = self.config_manager.obter_balanca_padrao()
        if config:
            self.gerenciador = GerenciadorBalanca(config)
    
    def _salvar_configuracao(self, config: ConfiguracaoBalanca):
        """Salva configuração da balança"""
        if self.config_manager:
            self.config_manager.adicionar_balanca(config.nome, config)
            # Recria o gerenciador com a nova configuração
            self.gerenciador = GerenciadorBalanca(config)
    
    # ═══════════════════════════════════════════════════════════════════════════
    # MÉTODOS DE CONEXÃO
    # ═══════════════════════════════════════════════════════════════════════════
    
    def conectar(self) -> bool:
        """Conecta à balança configurada"""
        if not BALANCA_DISPONIVEL:
            messagebox.showerror("Erro", "Módulo de balança não disponível.\n\n"
                               "Instale o PySerial: pip install pyserial")
            return False
        
        if not self.gerenciador:
            messagebox.showwarning("Configuração", "Nenhuma balança configurada.\n\n"
                                  "Configure a balança em Sistema > Balança > Configurar")
            return False
        
        try:
            if self.gerenciador.conectar():
                self.conectado = True
                self._atualizar_status_visual()
                self._log_acao("Balança conectada")
                return True
            else:
                messagebox.showerror("Erro", "Não foi possível conectar à balança.\n\n"
                                   "Verifique se está ligada e conectada corretamente.")
                return False
        except Exception as e:
            messagebox.showerror("Erro", f"Erro ao conectar à balança:\n{e}")
            return False
    
    def desconectar(self):
        """Desconecta da balança"""
        if self.gerenciador:
            self.gerenciador.desconectar()
        self.conectado = False
        self.leitura_continua_ativa = False
        self._atualizar_status_visual()
        self._log_acao("Balança desconectada")
    
    def esta_conectado(self) -> bool:
        """Verifica se está conectado"""
        return self.conectado and self.gerenciador and self.gerenciador.esta_conectado()
    
    # ═══════════════════════════════════════════════════════════════════════════
    # MÉTODOS DE LEITURA
    # ═══════════════════════════════════════════════════════════════════════════
    
    def ler_peso(self) -> Optional[float]:
        """
        Lê o peso da balança.
        
        Returns:
            Peso em gramas ou None se erro
        """
        if not self.esta_conectado():
            if not self.conectar():
                return None
        
        try:
            leitura = self.gerenciador.ler_peso()
            self.ultima_leitura = leitura
            
            if leitura.valido:
                peso_gramas = leitura.peso_em_gramas()
                self._atualizar_display_peso(peso_gramas, leitura.estavel)
                return peso_gramas
            else:
                self._mostrar_erro_leitura(leitura)
                return None
                
        except Exception as e:
            messagebox.showerror("Erro", f"Erro ao ler peso:\n{e}")
            return None
    
    def pesar_para_produto(self, prod_id: str = None) -> Optional[float]:
        """
        Abre diálogo de pesagem e retorna o peso.
        Se prod_id for fornecido, usa para contexto.
        
        Returns:
            Peso em gramas ou None se cancelado
        """
        if not BALANCA_DISPONIVEL:
            messagebox.showerror("Erro", "Módulo de balança não disponível.")
            return None
        
        if not self.gerenciador:
            # Tenta usar balança virtual para demonstração
            config = ConfiguracaoBalanca(
                nome="Balança Virtual",
                tipo_conexao=TipoConexao.VIRTUAL,
                config_serial=ConfiguracaoSerial(),
                config_protocolo=ConfiguracaoProtocolo()
            )
            self.gerenciador = GerenciadorBalanca(config)
        
        # Conecta se necessário
        if not self.esta_conectado():
            self.gerenciador.conectar()
        
        # Abre diálogo de pesagem
        titulo = "Pesagem"
        if prod_id and hasattr(self.app, 'products'):
            produto = self.app.products.get(prod_id, {})
            nome = produto.get('nome', '')
            if nome:
                titulo = f"Pesagem: {nome}"
        
        peso = abrir_dialogo_pesagem(self.app.root, self.gerenciador, titulo)
        
        if peso is not None:
            self._log_acao(f"Pesagem realizada: {peso:.3f}g")
        
        return peso
    
    def _mostrar_erro_leitura(self, leitura: LeituraPeso):
        """Mostra mensagem de erro apropriada"""
        if leitura.estado == EstadoBalanca.PESO_INSTAVEL:
            messagebox.showwarning("Peso Instável", 
                                  "O peso está instável.\n\n"
                                  "Aguarde a estabilização e tente novamente.")
        elif leitura.estado == EstadoBalanca.SOBRECARGA:
            messagebox.showerror("Sobrecarga", 
                                "A balança está em sobrecarga!\n\n"
                                "Remova parte do peso.")
        elif leitura.estado == EstadoBalanca.PESO_NEGATIVO:
            messagebox.showwarning("Peso Negativo", 
                                  "Peso negativo detectado.\n\n"
                                  "Tare a balança antes de pesar.")
        else:
            messagebox.showerror("Erro de Leitura", 
                                f"Não foi possível ler o peso.\n\n{leitura.mensagem_erro}")
    
    # ═══════════════════════════════════════════════════════════════════════════
    # INTEGRAÇÃO COM CARRINHO
    # ═══════════════════════════════════════════════════════════════════════════
    
    def pesar_produto_selecionado(self):
        """
        Pesa o produto selecionado no carrinho ou na lista de produtos.
        Atualiza automaticamente a quantidade/peso.
        """
        # Verifica se há produto selecionado no carrinho
        prod_id = None
        
        # Tenta pegar do carrinho primeiro
        if hasattr(self.app, 'tree_carrinho'):
            selected = self.app.tree_carrinho.selection()
            if selected:
                prod_id = selected[0]
        
        # Se não, tenta da lista de produtos
        if not prod_id and hasattr(self.app, 'tree_produtos'):
            selected = self.app.tree_produtos.selection()
            if selected:
                prod_id = selected[0]
        
        if not prod_id:
            # Abre pesagem genérica
            peso = self.pesar_para_produto()
            if peso is not None:
                messagebox.showinfo("Peso Lido", 
                                   f"Peso: {peso:,.3f}g\n\n"
                                   f"Selecione um produto para aplicar o peso.")
            return
        
        # Verifica se é produto do tipo peso
        if hasattr(self.app, 'products'):
            produto = self.app.products.get(prod_id, {})
            tipo = produto.get('tipo', 'unidade')
            
            if tipo != 'peso':
                messagebox.showwarning("Tipo de Produto", 
                                      "Este produto não é vendido por peso.\n\n"
                                      "A pesagem só funciona para produtos do tipo 'peso'.")
                return
        
        # Realiza a pesagem
        peso = self.pesar_para_produto(prod_id)
        
        if peso is None:
            return
        
        # Aplica o peso
        self._aplicar_peso_no_carrinho(prod_id, peso)
    
    def _aplicar_peso_no_carrinho(self, prod_id: str, peso_gramas: float):
        """Aplica o peso lido no carrinho"""
        if not hasattr(self.app, 'carrinho'):
            return
        
        # Se o produto já está no carrinho, atualiza
        if prod_id in self.app.carrinho:
            self.app.carrinho[prod_id]['quantidade_peso'] = peso_gramas
            self._log_acao(f"Peso atualizado no carrinho: {peso_gramas:.3f}g")
        else:
            # Adiciona ao carrinho com o peso
            if hasattr(self.app, 'adicionar_produto_por_id'):
                self.app.adicionar_produto_por_id(prod_id, quantidade_predefinida=peso_gramas)
                self._log_acao(f"Produto adicionado com peso: {peso_gramas:.3f}g")
        
        # Atualiza a visualização
        if hasattr(self.app, '_atualizar_carrinho_e_total'):
            self.app._atualizar_carrinho_e_total()
    
    def adicionar_produto_com_pesagem(self, prod_id: str):
        """
        Adiciona um produto ao carrinho usando pesagem automática.
        Chamado quando um produto do tipo peso é selecionado.
        """
        if not hasattr(self.app, 'products'):
            return
        
        produto = self.app.products.get(prod_id, {})
        tipo = produto.get('tipo', 'unidade')
        
        if tipo != 'peso':
            # Produto não é por peso, usa fluxo normal
            if hasattr(self.app, 'adicionar_produto_por_id'):
                self.app.adicionar_produto_por_id(prod_id)
            return
        
        # Produto é por peso - pergunta se quer usar balança
        resposta = messagebox.askyesnocancel(
            "Produto por Peso",
            f"'{produto.get('nome', 'Produto')}' é vendido por peso.\n\n"
            "Deseja usar a balança para pesar?\n\n"
            "Sim = Usar balança\n"
            "Não = Digitar peso manualmente\n"
            "Cancelar = Cancelar operação"
        )
        
        if resposta is None:
            return
        
        if resposta:
            # Usar balança
            peso = self.pesar_para_produto(prod_id)
            if peso is not None:
                self._aplicar_peso_no_carrinho(prod_id, peso)
        else:
            # Digitar manualmente - usa fluxo normal
            if hasattr(self.app, 'adicionar_produto_por_id'):
                self.app.adicionar_produto_por_id(prod_id)
    
    # ═══════════════════════════════════════════════════════════════════════════
    # INTERFACE VISUAL
    # ═══════════════════════════════════════════════════════════════════════════
    
    def criar_widgets_status(self, parent: tk.Widget) -> ttk.Frame:
        """
        Cria widgets de status da balança para exibir no PDV.
        
        Returns:
            Frame contendo os widgets
        """
        frame = ttk.Frame(parent)
        
        # Indicador de status
        status_frame = ttk.Frame(frame)
        status_frame.pack(fill=tk.X)
        
        ttk.Label(status_frame, text="⚖️", font=("Segoe UI", 12)).pack(side=tk.LEFT)
        self.widget_status = ttk.Label(status_frame, text="Desconectado", 
                                       font=("Segoe UI", 9), foreground="gray")
        self.widget_status.pack(side=tk.LEFT, padx=5)
        
        # Display de peso
        self.widget_peso = ttk.Label(frame, text="---", 
                                     font=("Segoe UI", 14, "bold"), foreground="#6c757d")
        self.widget_peso.pack(pady=2)
        
        # Botão de pesar
        self.btn_pesar = ttk.Button(frame, text="⚖️ PESAR (F9)", 
                                    command=self.pesar_produto_selecionado,
                                    bootstyle="success-outline")
        self.btn_pesar.pack(fill=tk.X, pady=2)
        
        return frame
    
    def _atualizar_status_visual(self):
        """Atualiza indicadores visuais de status"""
        if self.widget_status:
            if self.esta_conectado():
                self.widget_status.config(text="Conectado", foreground="#28a745")
            else:
                self.widget_status.config(text="Desconectado", foreground="gray")
    
    def _atualizar_display_peso(self, peso_gramas: float, estavel: bool = True):
        """Atualiza o display de peso"""
        if self.widget_peso:
            peso_str = f"{peso_gramas:,.3f}g".replace(',', 'X').replace('.', ',').replace('X', '.')
            cor = "#28a745" if estavel else "#ffc107"
            self.widget_peso.config(text=peso_str, foreground=cor)
    
    # ═══════════════════════════════════════════════════════════════════════════
    # JANELAS DE CONFIGURAÇÃO
    # ═══════════════════════════════════════════════════════════════════════════
    
    def abrir_configuracao(self):
        """Abre janela de configuração de balança"""
        if not BALANCA_DISPONIVEL:
            messagebox.showerror("Erro", "Módulo de balança não disponível.\n\n"
                               "Instale o PySerial: pip install pyserial")
            return
        
        if not self.config_manager:
            self._carregar_configuracao()
        
        ConfiguracaoBalancaWindow(
            self.app.root, 
            self.config_manager,
            callback_salvar=self._salvar_configuracao
        )
    
    def abrir_monitor_peso(self):
        """Abre janela de monitoramento de peso em tempo real"""
        if not check_permission("balanca.monitor"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para acessar o monitor de peso.")
            return
        if not self.esta_conectado():
            if not self.conectar():
                return
        
        MonitorPesoWindow(self.app.root, self)
    
    # ═══════════════════════════════════════════════════════════════════════════
    # UTILITÁRIOS
    # ═══════════════════════════════════════════════════════════════════════════
    
    def _log_acao(self, mensagem: str):
        """Registra ação no log do sistema"""
        try:
            # Tenta usar o sistema de log do PDV
            if hasattr(self.app, 'log_user_action'):
                self.app.log_user_action("Balança", mensagem)
            else:
                # Fallback para print
                try:
                    timestamp = datetime.now().strftime("%Y-%m-%d %H:%M:%S")
                except AttributeError:
                    timestamp = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
                print(f"[{timestamp}] [Balança] {mensagem}")
        except Exception:
            pass


# ═══════════════════════════════════════════════════════════════════════════════
# JANELA DE MONITORAMENTO DE PESO
# ═══════════════════════════════════════════════════════════════════════════════

class MonitorPesoWindow(tk.Toplevel):
    """Janela para monitoramento de peso em tempo real"""
    
    def __init__(self, parent, integracao: BalancaIntegracaoPDV):
        super().__init__(parent)
        self.status_bar = StatusBar(self, user_name=getattr(self, 'current_user', 'Usuário'))
        self.integracao = integracao
        self.leitura_ativa = False
        
        self.title("⚖️ Monitor de Peso")
        responsive_geometry(self, 400, 350)
        self.resizable(True, True)
        self.transient(parent)
        
        self._criar_interface()
        self._iniciar_leitura()
        
        # Centraliza
        self.update_idletasks()
        x = (self.winfo_screenwidth() - self.winfo_width()) // 2
        y = (self.winfo_screenheight() - self.winfo_height()) // 2
        self.geometry(f"+{x}+{y}")
        
        self.protocol("WM_DELETE_WINDOW", self._on_close)
    
    def _criar_interface(self):
        """Cria interface da janela"""
        main_frame = ttk.Frame(self, padding=20)
        main_frame.pack(fill=tk.BOTH, expand=True)
        
        # Título
        ttk.Label(main_frame, text="Peso em Tempo Real", 
                 font=("Segoe UI", 14, "bold")).pack(pady=10)
        
        # Display de peso grande
        self.lbl_peso = ttk.Label(main_frame, text="---", 
                                  font=("Segoe UI", 48, "bold"), foreground="#28a745")
        self.lbl_peso.pack(pady=20)
        
        # Status
        self.lbl_status = ttk.Label(main_frame, text="", foreground="gray")
        self.lbl_status.pack()
        
        # Informações adicionais
        info_frame = ttk.Frame(main_frame)
        info_frame.pack(fill=tk.X, pady=10)
        
        ttk.Label(info_frame, text="Peso Bruto:").grid(row=0, column=0, sticky="w")
        self.lbl_bruto = ttk.Label(info_frame, text="---")
        self.lbl_bruto.grid(row=0, column=1, sticky="e", padx=10)
        
        ttk.Label(info_frame, text="Tara:").grid(row=1, column=0, sticky="w")
        self.lbl_tara = ttk.Label(info_frame, text="---")
        self.lbl_tara.grid(row=1, column=1, sticky="e", padx=10)
        
        ttk.Label(info_frame, text="Unidade:").grid(row=2, column=0, sticky="w")
        self.lbl_unidade = ttk.Label(info_frame, text="---")
        self.lbl_unidade.grid(row=2, column=1, sticky="e", padx=10)
        
        info_frame.columnconfigure(1, weight=1)
        
        # Botões
        btn_frame = ttk.Frame(main_frame)
        btn_frame.pack(fill=tk.X, pady=10)
        
        ttk.Button(btn_frame, text="⏸️ Pausar", command=self._toggle_leitura,
                   bootstyle="warning").pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="✓ Usar Este Peso", command=self._usar_peso,
                   bootstyle="success").pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="✗ Fechar", command=self._on_close,
                   bootstyle="secondary").pack(side=tk.RIGHT, padx=5)
    
    def _iniciar_leitura(self):
        """Inicia leitura contínua"""
        self.leitura_ativa = True
        self._ler_peso_loop()
    
    def _ler_peso_loop(self):
        """Loop de leitura de peso"""
        if not self.leitura_ativa or not self.winfo_exists():
            return
        
        try:
            if self.integracao.gerenciador and self.integracao.gerenciador.esta_conectado():
                leitura = self.integracao.gerenciador.ler_peso()
                self._atualizar_display(leitura)
        except Exception as e:
            self.lbl_status.config(text=f"Erro: {e}", foreground="red")
        
        # Agenda próxima leitura
        if self.leitura_ativa:
            self.after(200, self._ler_peso_loop)
    
    def _atualizar_display(self, leitura: LeituraPeso):
        """Atualiza o display com a leitura"""
        if leitura.valido:
            peso_gramas = leitura.peso_em_gramas()
            peso_str = f"{peso_gramas:,.3f}g".replace(',', 'X').replace('.', ',').replace('X', '.')
            
            cor = "#28a745" if leitura.estavel else "#ffc107"
            self.lbl_peso.config(text=peso_str, foreground=cor)
            
            status = "✓ Estável" if leitura.estavel else "⚡ Instável"
            self.lbl_status.config(text=status, foreground=cor)
            
            # Informações adicionais
            self.lbl_bruto.config(text=f"{leitura.peso_bruto:,.3f}g".replace(',', 'X').replace('.', ',').replace('X', '.'))
            self.lbl_tara.config(text=f"{leitura.tara:,.3f}g".replace(',', 'X').replace('.', ',').replace('X', '.'))
            self.lbl_unidade.config(text=leitura.unidade.value)
        else:
            self.lbl_peso.config(text="---", foreground="#dc3545")
            self.lbl_status.config(text=leitura.mensagem_erro, foreground="#dc3545")
    
    def _toggle_leitura(self):
        """Liga/desliga leitura"""
        self.leitura_ativa = not self.leitura_ativa
        if self.leitura_ativa:
            self._ler_peso_loop()
    
    def _usar_peso(self):
        """Usa o peso atual"""
        if self.integracao.ultima_leitura and self.integracao.ultima_leitura.valido:
            peso = self.integracao.ultima_leitura.peso_em_gramas()
            self.integracao.pesar_produto_selecionado()
            self._on_close()
    
    def _on_close(self):
        """Fecha a janela"""
        self.leitura_ativa = False
        self.destroy()


