def integrar_balanca_ao_pdv(app, persistence_dir: str) -> BalancaIntegracaoPDV:
    """
    Integra o sistema de balança ao PDV.
    
    Args:
        app: Instância do PDVSuperApp
        persistence_dir: Diretório de persistência
        
    Returns:
        Instância de BalancaIntegracaoPDV
    """
    integracao = BalancaIntegracaoPDV(app, persistence_dir)
    
    # Adiciona referência no app
    app.balanca = integracao
    
    return integracao


def criar_menu_balanca(menubar: tk.Menu, app) -> tk.Menu:
    """
    Cria o menu de balança no menubar do PDV.
    
    Args:
        menubar: Menu principal do PDV
        app: Instância do PDVSuperApp
        
    Returns:
        Menu de balança criado
    """
    balanca_menu = tk.Menu(menubar, tearoff=0)
    menubar.add_cascade(label="⚖️ Balança", menu=balanca_menu)
    
    if hasattr(app, 'balanca'):
        balanca_menu.add_command(
            label="⚙️ Configurar Balança", 
            command=app.balanca.abrir_configuracao
        )
        balanca_menu.add_separator()
        balanca_menu.add_command(
            label="🔌 Conectar", 
            command=app.balanca.conectar
        )
        balanca_menu.add_command(
            label="🔌 Desconectar", 
            command=app.balanca.desconectar
        )
        balanca_menu.add_separator()
        balanca_menu.add_command(
            label="⚖️ Pesar Produto (F9)", 
            command=app.balanca.pesar_produto_selecionado,
            accelerator="F9"
        )
        balanca_menu.add_command(
            label="📊 Monitor de Peso", 
            command=app.balanca.abrir_monitor_peso
        )
    else:
        balanca_menu.add_command(
            label="Balança não disponível", 
            state="disabled"
        )
    
    return balanca_menu


def adicionar_atalhos_balanca(app):
    """
    Adiciona atalhos de teclado para balança.
    
    Args:
        app: Instância do PDVSuperApp
    """
    if hasattr(app, 'balanca') and hasattr(app, 'root'):
        # F9 para pesar
        app.root.bind("<F9>", lambda e: app.balanca.pesar_produto_selecionado())
        
        # Ctrl+B para conectar/desconectar
        def toggle_conexao(e):
            if app.balanca.esta_conectado():
                app.balanca.desconectar()
            else:
                app.balanca.conectar()
        
        app.root.bind("<Control-Shift-b>", toggle_conexao)
        app.root.bind("<Control-Shift-B>", toggle_conexao)


