# SISTEMA DE PERSISTÊNCIA E DIRETÓRIOS
# ═══════════════════════════════════════════════════════════════════════════

def get_persistence_dir():
    """Retorna o diretório onde o executável está localizado."""
    if getattr(sys, 'frozen', False):
        # Estamos rodando como um executável PyInstaller
        return os.path.dirname(sys.executable)
    else:
        # Estamos rodando como um script Python normal
        return os.path.dirname(os.path.abspath(__file__))

PERSISTENCE_DIR = get_persistence_dir()

# ═══════════════════════════════════════════════════════════════════════════
# SISTEMA DE ARQUIVO DE CONFIGURAÇÃO (config.ini)
# ═══════════════════════════════════════════════════════════════════════════
# O arquivo config.ini armazena as credenciais do MySQL e outras
# configurações do sistema. Se não existir, será solicitada a
# configuração ao usuário no primeiro acesso via interface gráfica.
# ═══════════════════════════════════════════════════════════════════════════

MYSQL_CONFIG_FILE = os.path.join(PERSISTENCE_DIR, "config.ini")

def carregar_config():
    """Carrega as configurações do arquivo config.ini.
    
    Returns:
        configparser.ConfigParser: Objeto com as configurações carregadas,
        ou None se o arquivo não existir.
    """
    config = configparser.ConfigParser()
    if os.path.exists(MYSQL_CONFIG_FILE):
        try:
            config.read(MYSQL_CONFIG_FILE, encoding='utf-8')
            return config
        except (configparser.Error, IOError) as e:
            print(f"[CONFIG] Erro ao ler config.ini: {e}")
            return None
    return None


def salvar_config(host, port, user, password, database):
    """Salva as configurações do MySQL no arquivo config.ini.
    
    Args:
        host: Endereço do servidor MySQL.
        port: Porta do servidor MySQL.
        user: Usuário do MySQL.
        password: Senha do MySQL.
        database: Nome do banco de dados.
    
    Returns:
        bool: True se salvo com sucesso, False caso contrário.
    """
    config = configparser.ConfigParser()
    config['mysql'] = {
        'host': str(host),
        'port': str(port),
        'user': str(user),
        'password': str(password),
        'database': str(database),
    }
    try:
        with open(MYSQL_CONFIG_FILE, 'w', encoding='utf-8') as f:
            config.write(f)
        print(f"[CONFIG] Configurações salvas em: {MYSQL_CONFIG_FILE}")
        return True
    except (IOError, OSError) as e:
        print(f"[CONFIG] Erro ao salvar config.ini: {e}")
        return False


def testar_conexao_mysql(host, port, user, password, database=''):
    """Testa a conexão com o servidor MySQL.
    
    Args:
        host: Endereço do servidor.
        port: Porta do servidor.
        user: Usuário.
        password: Senha.
        database: Nome do banco (opcional, testa sem banco se vazio).
    
    Returns:
        tuple: (sucesso: bool, mensagem: str)
    """
    try:
        import mysql.connector as _mc
        conn_params = {
            'host': host,
            'port': int(port),
            'user': user,
            'password': password,
            'connect_timeout': 10,
            'use_pure': True,
        }
        if database:
            conn_params['database'] = database
        conn = _mc.connect(**conn_params)
        conn.close()
        return True, "Conexão estabelecida com sucesso!"
    except Exception as e:
        return False, str(e)


def solicitar_configuracao_mysql():
    """Exibe uma janela gráfica para o usuário configurar o MySQL.
    
    Esta função é chamada automaticamente quando o arquivo config.ini
    não existe (primeiro acesso) ou quando as credenciais estão inválidas.
    Permite ao usuário informar host, porta, usuário, senha e banco de dados,
    testar a conexão e salvar as configurações.
    
    Returns:
        bool: True se a configuração foi salva com sucesso, False se cancelou.
    """
    import tkinter as _tk
    from tkinter import messagebox as _mb
    
    config_salva = [False]  # Usa lista para permitir mutação dentro do closure
    
    # Cria janela de configuração
    cfg_win = _tk.Tk()
    cfg_win.title("Configuração Inicial do MySQL - PDV Quantum")
    cfg_win.resizable(True, True)
    
    # Centraliza a janela na tela com tamanho adequado
    largura_janela = 520
    altura_janela = 620
    largura_tela = cfg_win.winfo_screenwidth()
    altura_tela = cfg_win.winfo_screenheight()
    pos_x = (largura_tela - largura_janela) // 2
    pos_y = (altura_tela - altura_janela) // 2
    cfg_win.geometry(f"{largura_janela}x{altura_janela}+{pos_x}+{pos_y}")
    cfg_win.minsize(480, 580)
    cfg_win.configure(bg='#f0f0f0')
    
    # Tenta colocar a janela no topo
    try:
        cfg_win.attributes('-topmost', True)
    except Exception:
        pass
    
    # Frame dos botões FIXO na parte inferior da janela
    btn_frame = _tk.Frame(cfg_win, bg='#f0f0f0', padx=30, pady=15)
    btn_frame.pack(side='bottom', fill='x')
    
    # Separador acima dos botões
    _tk.Frame(cfg_win, height=1, bg='#d0d0d0').pack(side='bottom', fill='x', padx=30)
    
    # Label de status FIXO acima dos botões
    status_label = _tk.Label(
        cfg_win,
        text="",
        font=("Segoe UI", 9),
        bg='#f0f0f0',
        fg='#64748b',
        wraplength=450
    )
    status_label.pack(side='bottom', pady=(5, 5))
    
    # Frame principal (área de scroll se necessário)
    main_frame = _tk.Frame(cfg_win, bg='#f0f0f0', padx=30, pady=20)
    main_frame.pack(fill='both', expand=True)
    
    # Título
    titulo = _tk.Label(
        main_frame,
        text="Configuração do Banco de Dados MySQL",
        font=("Segoe UI", 14, "bold"),
        bg='#f0f0f0',
        fg='#1e293b'
    )
    titulo.pack(pady=(0, 5))
    
    subtitulo = _tk.Label(
        main_frame,
        text="Arquivo config.ini não encontrado.\nPreencha os dados de conexão abaixo:",
        font=("Segoe UI", 9),
        bg='#f0f0f0',
        fg='#64748b',
        justify='center'
    )
    subtitulo.pack(pady=(0, 15))
    
    # Frame dos campos
    campos_frame = _tk.Frame(main_frame, bg='#f0f0f0')
    campos_frame.pack(fill='x')
    
    # Variáveis
    var_host = _tk.StringVar(value='127.0.0.1')
    var_port = _tk.StringVar(value='3306')
    var_user = _tk.StringVar(value='root')
    var_pass = _tk.StringVar(value='')
    var_db = _tk.StringVar(value='pdv_quantum')
    
    campos = [
        ("Host (Servidor):", var_host),
        ("Porta:", var_port),
        ("Usuário:", var_user),
        ("Senha:", var_pass),
        ("Nome do Banco de Dados:", var_db),
    ]
    
    entries = []
    for i, (label_text, var) in enumerate(campos):
        lbl = _tk.Label(
            campos_frame,
            text=label_text,
            font=("Segoe UI", 10),
            bg='#f0f0f0',
            fg='#334155',
            anchor='w'
        )
        lbl.pack(fill='x', pady=(6, 1))
        
        show_char = '*' if 'Senha' in label_text else ''
        entry = _tk.Entry(
            campos_frame,
            textvariable=var,
            font=("Segoe UI", 11),
            relief='solid',
            bd=1,
            show=show_char
        )
        entry.pack(fill='x', ipady=4)
        entries.append(entry)
    
    def ao_testar():
        """Testa a conexão com os dados informados."""
        host = var_host.get().strip()
        port = var_port.get().strip()
        user = var_user.get().strip()
        password = var_pass.get()
        
        if not host or not port or not user:
            _mb.showwarning("Aviso", "Preencha pelo menos Host, Porta e Usuário.", parent=cfg_win)
            return
        
        status_label.config(text="Testando conexão...", fg='#2563eb')
        cfg_win.update_idletasks()
        
        sucesso, msg = testar_conexao_mysql(host, port, user, password)
        
        if sucesso:
            status_label.config(text="Conexão OK!", fg='#10b981')
            _mb.showinfo("Sucesso", "Conexão com o MySQL estabelecida com sucesso!", parent=cfg_win)
        else:
            status_label.config(text=f"Falha: {msg}", fg='#ef4444')
            _mb.showerror("Erro de Conexão", f"Não foi possível conectar ao MySQL:\n\n{msg}", parent=cfg_win)
    
    def ao_salvar():
        """Valida, testa e salva a configuração."""
        host = var_host.get().strip()
        port = var_port.get().strip()
        user = var_user.get().strip()
        password = var_pass.get()
        database = var_db.get().strip()
        
        if not host or not port or not user or not database:
            _mb.showwarning("Aviso", "Preencha todos os campos obrigatórios:\nHost, Porta, Usuário e Nome do Banco.", parent=cfg_win)
            return
        
        try:
            int(port)
        except ValueError:
            _mb.showwarning("Aviso", "A porta deve ser um número válido.", parent=cfg_win)
            return
        
        status_label.config(text="Testando conexão antes de salvar...", fg='#2563eb')
        cfg_win.update_idletasks()
        
        sucesso, msg = testar_conexao_mysql(host, port, user, password)
        
        if not sucesso:
            resposta = _mb.askyesno(
                "Conexão Falhou",
                f"Não foi possível conectar ao MySQL:\n\n{msg}\n\n"
                f"Deseja salvar a configuração mesmo assim?",
                parent=cfg_win
            )
            if not resposta:
                status_label.config(text=f"Falha: {msg}", fg='#ef4444')
                return
        
        if salvar_config(host, port, user, password, database):
            config_salva[0] = True
            status_label.config(text="Configuração salva com sucesso!", fg='#10b981')
            _mb.showinfo(
                "Configuração Salva",
                "As configurações do MySQL foram salvas no arquivo config.ini.\n\n"
                "O sistema será iniciado agora.",
                parent=cfg_win
            )
            cfg_win.destroy()
        else:
            _mb.showerror("Erro", "Não foi possível salvar o arquivo config.ini.", parent=cfg_win)
    
    def ao_cancelar():
        """Cancela e fecha o sistema."""
        resposta = _mb.askyesno(
            "Cancelar Configuração",
            "Sem a configuração do MySQL, o sistema não poderá funcionar.\n\n"
            "Deseja realmente sair?",
            parent=cfg_win
        )
        if resposta:
            cfg_win.destroy()
    
    # Botão Testar Conexão
    btn_testar = _tk.Button(
        btn_frame,
        text="Testar Conexão",
        font=("Segoe UI", 10),
        bg='#2563eb',
        fg='white',
        activebackground='#1d4ed8',
        activeforeground='white',
        relief='flat',
        cursor='hand2',
        padx=15,
        pady=6,
        command=ao_testar
    )
    btn_testar.pack(side='left', padx=(0, 5))
    
    # Botão Cancelar
    btn_cancelar = _tk.Button(
        btn_frame,
        text="Cancelar / Sair",
        font=("Segoe UI", 10),
        bg='#6b7280',
        fg='white',
        activebackground='#4b5563',
        activeforeground='white',
        relief='flat',
        cursor='hand2',
        padx=15,
        pady=6,
        command=ao_cancelar
    )
    btn_cancelar.pack(side='right', padx=(5, 0))
    
    # Botão Salvar
    btn_salvar = _tk.Button(
        btn_frame,
        text="Salvar e Iniciar",
        font=("Segoe UI", 10, "bold"),
        bg='#10b981',
        fg='white',
        activebackground='#059669',
        activeforeground='white',
        relief='flat',
        cursor='hand2',
        padx=15,
        pady=6,
        command=ao_salvar
    )
    btn_salvar.pack(side='right', padx=(5, 5))
    
    # Protocolo de fechamento
    cfg_win.protocol("WM_DELETE_WINDOW", ao_cancelar)
    
    # Foca no campo de senha se os outros já estão preenchidos
    entries[3].focus_set()
    
    cfg_win.mainloop()
    
    return config_salva[0]


def verificar_e_solicitar_config():
    """Verifica se o config.ini existe e é válido.
    AUDITORIA: Registra verificação de configuração.
    
    Se não existir ou estiver incompleto, solicita a configuração ao usuário.
    Se o usuário cancelar, encerra o sistema.
    
    Returns:
        dict: Dicionário com as configurações do MySQL.
    """
    AUDITORIA.processo("Verificando configuração do MySQL")
    config = carregar_config()
    
    # Verifica se o config.ini existe e tem a seção [mysql]
    if config is not None and config.has_section('mysql'):
        # Verifica se tem os campos mínimos obrigatórios
        campos_obrigatorios = ['host', 'port', 'user', 'database']
        campos_presentes = all(config.has_option('mysql', campo) for campo in campos_obrigatorios)
        
        if campos_presentes:
            print(f"[CONFIG] Arquivo config.ini carregado de: {MYSQL_CONFIG_FILE}")
            return {
                'host': config.get('mysql', 'host', fallback='127.0.0.1'),
                'port': config.getint('mysql', 'port', fallback=3306),
                'user': config.get('mysql', 'user', fallback='root'),
                'password': config.get('mysql', 'password', fallback=''),
                'database': config.get('mysql', 'database', fallback='pdv_quantum'),
            }
    
    # config.ini não existe ou está incompleto - solicitar configuração
    print("[CONFIG] Arquivo config.ini não encontrado ou incompleto.")
    print("[CONFIG] Solicitando configuração ao usuário...")
    
    if solicitar_configuracao_mysql():
        # Recarrega após salvar
        config = carregar_config()
        if config is not None and config.has_section('mysql'):
            return {
                'host': config.get('mysql', 'host', fallback='127.0.0.1'),
                'port': config.getint('mysql', 'port', fallback=3306),
                'user': config.get('mysql', 'user', fallback='root'),
                'password': config.get('mysql', 'password', fallback=''),
                'database': config.get('mysql', 'database', fallback='pdv_quantum'),
            }
    
    # Usuário cancelou - encerra o sistema
    print("[CONFIG] Configuração cancelada pelo usuário. Encerrando...")
    sys.exit(0)


