# Configuração de conexão MySQL
# NOTA: As credenciais são carregadas PRIMARIAMENTE do arquivo config.ini.
# Também suporta variáveis de ambiente e network_settings.json como fallback.
# A prioridade é: config.ini > variáveis de ambiente > network_settings.json > padrão.

# Configurações padrão do MySQL (usadas como fallback final)
MYSQL_CONFIG = {
    'host': _CONFIG_MYSQL.get('host', '127.0.0.1'),
    'port': _CONFIG_MYSQL.get('port', 3306),
    'user': _CONFIG_MYSQL.get('user', 'root'),
    'password': _CONFIG_MYSQL.get('password', ''),
    'database': _CONFIG_MYSQL.get('database', 'pdv_quantum'),
    'charset': 'utf8mb4',
    'collation': 'utf8mb4_unicode_ci',
    'autocommit': True,
    'connect_timeout': 30,
    'pool_name': 'pdv_pool',
    'pool_size': 5,
    'pool_reset_session': True,
}

def get_mysql_config():
    """Retorna a configuração de conexão MySQL.
    
    Ordem de prioridade:
    1. Arquivo config.ini (fonte primária, configurado no primeiro acesso)
    2. Variáveis de ambiente (MYSQL_HOST, MYSQL_PORT, etc.)
    3. Arquivo network_settings.json (compatibilidade com versões anteriores)
    4. Valores padrão do MYSQL_CONFIG
    """
    import json
    
    config = MYSQL_CONFIG.copy()
    
    # 1. Verificar variáveis de ambiente (sobrescrevem config.ini)
    env_host = os.environ.get('MYSQL_HOST')
    env_port = os.environ.get('MYSQL_PORT')
    env_user = os.environ.get('MYSQL_USER')
    env_pass = os.environ.get('MYSQL_PASSWORD')
    env_db = os.environ.get('MYSQL_DATABASE')
    
    if env_host:
        config['host'] = env_host
    if env_port:
        config['port'] = int(env_port)
    if env_user:
        config['user'] = env_user
    if env_pass:
        config['password'] = env_pass
    if env_db:
        config['database'] = env_db
    
    # 2. Verificar arquivo de configuração de rede (compatibilidade)
    network_config_file = os.path.join(PERSISTENCE_DIR, "network_settings.json")
    
    if os.path.exists(network_config_file):
        try:
            with open(network_config_file, 'r', encoding='utf-8') as f:
                settings = json.load(f)
                if settings.get("mysql_host"):
                    config['host'] = settings['mysql_host']
                if settings.get("mysql_port"):
                    config['port'] = int(settings['mysql_port'])
                if settings.get("mysql_user"):
                    config['user'] = settings['mysql_user']
                if settings.get("mysql_password"):
                    config['password'] = settings['mysql_password']
                if settings.get("mysql_database"):
                    config['database'] = settings['mysql_database']
        except (json.JSONDecodeError, IOError):
            pass
    
    return config

# Nome do banco de dados MySQL (será usado em várias partes do sistema)
MYSQL_DB_NAME = get_mysql_config().get('database', 'pdv_quantum')

class MySQLDB:
    """Gerenciador de conexão MySQL thread-safe com connection pooling."""
    _local = threading.local()
    _pool = None
    _pool_lock = threading.Lock()
    _config_hash = None
    
    @classmethod
    def _get_config_hash(cls):
        """Retorna um hash da configuração atual para detectar mudanças."""
        config = get_mysql_config()
        return f"{config['host']}:{config['port']}:{config['user']}:{config['database']}"
    
    @classmethod
    def _ensure_database_exists(cls):
        """Garante que o banco de dados MySQL exista, criando-o se necessário."""
        config = get_mysql_config()
        try:
            conn = mysql.connector.connect(
                host=config['host'],
                port=config['port'],
                user=config['user'],
                password=config['password'],
                charset=config['charset'],
                connect_timeout=config['connect_timeout']
            )
            cursor = conn.cursor(dictionary=True)
            cursor.execute(f"CREATE DATABASE IF NOT EXISTS `{config['database']}` CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci")
            cursor.close()
            conn.close()
        except Exception as e:
            print(f"[MySQL] Aviso ao verificar/criar banco de dados: {e}")
    
    @classmethod
    def get_connection(cls):
        """Obtém uma conexão MySQL thread-safe."""
        config = get_mysql_config()
        current_hash = cls._get_config_hash()
        
        # Verifica se já existe uma conexão válida para esta thread
        if (hasattr(cls._local, 'connection') and 
            cls._local.connection is not None and
            hasattr(cls._local, 'config_hash') and
            cls._local.config_hash == current_hash):
            try:
                cls._local.connection.ping(reconnect=True, attempts=3, delay=1)
                return cls._local.connection
            except Exception:
                # Conexão perdida, será recriada abaixo
                try:
                    cls._local.connection.close()
                except Exception:
                    pass
                cls._local.connection = None
        
        # Fecha conexão antiga se existir
        if hasattr(cls._local, 'connection') and cls._local.connection is not None:
            try:
                cls._local.connection.close()
            except Exception:
                pass
        
        # Garante que o banco de dados exista
        cls._ensure_database_exists()
        
        # Cria nova conexão para esta thread
        try:
            cls._local.connection = mysql.connector.connect(
                host=config['host'],
                port=config['port'],
                user=config['user'],
                password=config['password'],
                database=config['database'],
                charset=config['charset'],
                collation=config.get('collation', 'utf8mb4_unicode_ci'),
                autocommit=config.get('autocommit', True),
                connect_timeout=config['connect_timeout'],
                use_pure=True
            )
            cls._local.config_hash = current_hash
            
            # Configurações de sessão MySQL equivalentes aos PRAGMAs do SQLite
            cursor = cls._local.connection.cursor()
            cursor.execute("SET SESSION sql_mode = 'NO_ZERO_DATE,NO_ZERO_IN_DATE,ERROR_FOR_DIVISION_BY_ZERO,NO_ENGINE_SUBSTITUTION'")
            cursor.execute("SET SESSION innodb_lock_wait_timeout = 30")
            cursor.execute("SET NAMES utf8mb4")
            cursor.close()
        except Exception as e:
            print(f"[MySQL] Erro ao conectar: {e}")
            raise
        
        return cls._local.connection
    
    @classmethod
    def execute(cls, query, params=()):
        """Executa uma query SQL com commit automático."""
        conn = cls.get_connection()
        cursor = conn.cursor(dictionary=True)
        try:
            cursor.execute(query, params)
            if not conn.autocommit:
                conn.commit()
        except MySQLError as e:
            if "Lock wait timeout exceeded" in str(e) or e.errno == 1205:
                # Tenta novamente após um pequeno delay
                import time
                time.sleep(0.1)
                cursor.execute(query, params)
                if not conn.autocommit:
                    conn.commit()
            elif e.errno in (2006, 2013, 2055):
                # FIX: Conexão perdida – reconecta e tenta novamente
                cls._local.connection = None
                conn = cls.get_connection()
                cursor = conn.cursor(dictionary=True)
                cursor.execute(query, params)
                if not conn.autocommit:
                    conn.commit()
            else:
                raise
        return cursor
    
    @classmethod
    def commit(cls):
        """Faz commit da transação atual (para compatibilidade)."""
        try:
            conn = cls.get_connection()
            conn.commit()
        except Exception:
            pass
    
    @classmethod
    def fetchone(cls, query, params=()):
        """Executa uma query e retorna uma única linha como dicionário."""
        conn = cls.get_connection()
        cursor = conn.cursor(dictionary=True)
        try:
            cursor.execute(query, params)
        except MySQLError as e:
            if "Lock wait timeout exceeded" in str(e) or e.errno == 1205:
                import time
                time.sleep(0.1)
                cursor.execute(query, params)
            elif e.errno in (2006, 2013, 2055):
                # FIX: Conexão perdida – reconecta e tenta novamente
                cls._local.connection = None
                conn = cls.get_connection()
                cursor = conn.cursor(dictionary=True)
                cursor.execute(query, params)
            else:
                raise
        row = cursor.fetchone()
        return dict(row) if row else None
    
    @classmethod
    def fetchall(cls, query, params=()):
        """Executa uma query e retorna todas as linhas como lista de dicionários."""
        conn = cls.get_connection()
        cursor = conn.cursor(dictionary=True)
        try:
            cursor.execute(query, params)
        except MySQLError as e:
            if "Lock wait timeout exceeded" in str(e) or e.errno == 1205:
                import time
                time.sleep(0.1)
                cursor.execute(query, params)
            elif e.errno in (2006, 2013, 2055):
                # FIX: Conexão perdida – reconecta e tenta novamente
                cls._local.connection = None
                conn = cls.get_connection()
                cursor = conn.cursor(dictionary=True)
                cursor.execute(query, params)
            else:
                raise
        return [dict(row) for row in cursor.fetchall()]


# ═══════════════════════════════════════════════════════════════════════════════
# 🛡️ WRAPPER AMIGÁVEL PARA ERROS DE BANCO DE DADOS
# ═══════════════════════════════════════════════════════════════════════════════

def _install_friendly_mysql_wrappers():
    """Envolve operações MySQL para registrar contexto claro em falhas."""
    try:
        if getattr(MySQLDB, "_friendly_wrappers_installed", False):
            return
        MySQLDB._friendly_wrappers_installed = True

        _orig_execute = MySQLDB.execute
        _orig_fetchone = MySQLDB.fetchone
        _orig_fetchall = MySQLDB.fetchall

        def _short_sql(query):
            try:
                q = " ".join(str(query).split())
                return q[:220] + ("..." if len(q) > 220 else "")
            except Exception:
                return "SQL indisponível"

        @classmethod
        def _execute(cls, query, params=()):
            try:
                return _orig_execute(query, params)
            except Exception as e:
                try:
                    AUDITORIA.erro(f"Falha em comando SQL | SQL: {_short_sql(query)} | Erro: {type(e).__name__}: {e}")
                except Exception:
                    pass
                raise

        @classmethod
        def _fetchone(cls, query, params=()):
            try:
                return _orig_fetchone(query, params)
            except Exception as e:
                try:
                    AUDITORIA.erro(f"Falha em consulta SQL única | SQL: {_short_sql(query)} | Erro: {type(e).__name__}: {e}")
                except Exception:
                    pass
                raise

        @classmethod
        def _fetchall(cls, query, params=()):
            try:
                return _orig_fetchall(query, params)
            except Exception as e:
                try:
                    AUDITORIA.erro(f"Falha em consulta SQL lista | SQL: {_short_sql(query)} | Erro: {type(e).__name__}: {e}")
                except Exception:
                    pass
                raise

        MySQLDB.execute = _execute
        MySQLDB.fetchone = _fetchone
        MySQLDB.fetchall = _fetchall
    except Exception as e:
        try:
            AUDITORIA.erro(f"Não foi possível instalar wrapper amigável do MySQL: {e}")
        except Exception:
            pass

_install_friendly_mysql_wrappers()


def get_db():
    return MySQLDB


def reabrir_comanda_deletada(numero_comanda, app_instance):
    """
    Reabilita uma comanda que foi deletada quando foi fechada.
    Chamada quando garçom tenta adicionar item em comanda deletada.
    """
    try:
        db = get_db()
        
        # Verifica se comanda existe no banco
        cursor = db.execute("SELECT * FROM comandas WHERE numero = %s", (numero_comanda,))
        row = cursor.fetchone()
        
        if row:
            # Comanda existe no banco, apenas muda status para aberta
            db.execute(
                "UPDATE comandas SET status = 'aberta', updated_at = CURRENT_TIMESTAMP WHERE numero = %s",
                (numero_comanda,)
            )
            db.commit()
            print(f"[REABRIR] Comanda #{numero_comanda} mudou para ABERTA")
            return True
        else:
            print(f"[REABRIR] Comanda #{numero_comanda} não encontrada no banco")
            return False
    except Exception as e:
        try:
            AUDITORIA.erro(f"Erro no sistema: {e}")
        except Exception:
            pass
        print(f"[ERRO] Ao reabrir comanda: {e}")
        return False

