def _insert_default_data():
    """Insere dados padrão no banco de dados."""
    db = get_db()
    
    # Categoria padrão
    if not db.fetchone("SELECT id FROM categorias WHERE id = 1"):
        db.execute("INSERT INTO categorias (id, nome, descricao) VALUES (1, 'Geral', 'Categoria padrão')")
    
    # Cliente padrão
    if not db.fetchone("SELECT id FROM clientes WHERE id = 1"):
        db.execute("INSERT INTO clientes (id, nome, cpf) VALUES (1, 'Consumidor Final', '')")
    
    # Empresa padrão
    if not db.fetchone("SELECT id FROM empresa WHERE id = 1"):
        db.execute("INSERT INTO empresa (id, nome, endereco) VALUES (1, 'Sua Empresa Aqui', 'Endereço não configurado')")
    
    # Configurações padrão
    default_configs = [
        ('store_name', 'Sua Loja Aqui'),
        ('store_address', 'Seu Endereço Aqui, 123\nSua Cidade, UF - CEP 12345-678'),
        ('last_coupon_number', '0')
    ]
    for chave, valor in default_configs:
        if not db.fetchone("SELECT id FROM configuracoes WHERE chave = %s", (chave,)):
            db.execute("INSERT INTO configuracoes (chave, valor) VALUES (%s, %s)", (chave, valor))
    
    # Sequência de nota de entrada
    if not db.fetchone("SELECT id FROM sequencias WHERE nome = 'nota_entrada'"):
        db.execute("INSERT INTO sequencias (nome, valor) VALUES ('nota_entrada', 0)")
    
    # Usuário adm padrão
