def _mysql_load_products():
    db = get_db()
    rows = db.fetchall("SELECT * FROM produtos WHERE ativo = 1")
    result = {}
    for row in rows:
        cat_id = str(row['categoria_id']) if row['categoria_id'] else '1'
        row_keys = row.keys() if hasattr(row, 'keys') else []
        result[str(row['id'])] = {
            'nome': row['nome'],
            'codigo_barras': row['codigo_barras'] or '',
            'categoria_id': cat_id,
            'category_id': cat_id,
            'categoria': cat_id,  # Campo para compatibilidade com frontend web
            'preco': row['preco'] or 0.0,
            'preco_atacado': row['preco_atacado'] if 'preco_atacado' in row_keys else 0.0,
            'atacado_qtd_minima': row['atacado_qtd_minima'] if 'atacado_qtd_minima' in row_keys else 10.0,
            'preco_promocional': row['preco_promocional'] if 'preco_promocional' in row_keys else 0.0,
            'promocao_ativa': (row['promocao_ativa'] in (1, True, '1', 'true', 'True')) if 'promocao_ativa' in row_keys else False,
            'promocao_inicio': row['promocao_inicio'] if 'promocao_inicio' in row_keys else '',
            'promocao_fim': row['promocao_fim'] if 'promocao_fim' in row_keys else '',
            'preco_compra': row['preco_compra'] or 0.0,
            'tipo': row['tipo'] or 'unidade',
            'estoque': row['estoque'] or 0.0,
            'estoque_minimo': row['estoque_minimo'] or 5.0,
            'fidelidade_pontos': row['fidelidade_pontos'] or 0,
            'tamanho_id': row['tamanho_id'] if 'tamanho_id' in row_keys else None,
            'imagem': '',
            'imagens': []
        }
        
        # Processa campo imagem (pode ser JSON com lista ou string única)
        if 'imagem' in row_keys and row['imagem']:
            img_val = row['imagem']
            if img_val.startswith('[') and img_val.endswith(']'):
                try:
                    import json
                    imgs = json.loads(img_val)
                    if isinstance(imgs, list):
                        result[str(row['id'])]['imagens'] = imgs
                        result[str(row['id'])]['imagem'] = imgs[0] if imgs else ''
                    else:
                        result[str(row['id'])]['imagem'] = img_val
                        result[str(row['id'])]['imagens'] = [img_val]
                except:
                    result[str(row['id'])]['imagem'] = img_val
                    result[str(row['id'])]['imagens'] = [img_val]
            else:
                result[str(row['id'])]['imagem'] = img_val
                result[str(row['id'])]['imagens'] = [img_val]
                
    return result

