def _mysql_load_comandas():
    db = get_db()
    rows = db.fetchall("SELECT * FROM comandas WHERE status = 'aberta'")
    result = {}
    for row in rows:
        # Carrega os itens e converte para o formato esperado pelo frontend
        itens_raw = json.loads(row['itens']) if row['itens'] else []
        itens_formatados = []
        for item in itens_raw:
            # Converte campos do formato interno para o formato do frontend
            item_formatado = {
                'id': item.get('id'),  # IMPORTANTE: Preserva o ID do produto para devolução ao estoque
                'nome': item.get('nome', 'Produto'),
                'quantidade': item.get('qtd', item.get('quantidade', 1)),
                'qtd': item.get('qtd', item.get('quantidade', 1)),  # Mantém compatibilidade
                'preco_unit': item.get('preco', item.get('preco_unit', 0)),
                'preco': item.get('preco', item.get('preco_unit', 0)),  # Mantém compatibilidade
                'subtotal': item.get('subtotal', 0),
                'observacao': item.get('observacao', ''),
                'feito_cozinha': item.get('feito_cozinha', False),
                'feito_por': item.get('feito_por', ''),
                'feito_em': item.get('feito_em', ''),
                'excluido': item.get('excluido', False)
            }
            itens_formatados.append(item_formatado)
        
        # Verifica se a coluna sinalizada_para_fechar existe
        sinalizada = False
        sinalizada_por = ''
        try:
            if 'sinalizada_para_fechar' in row.keys():
                sinalizada = bool(row['sinalizada_para_fechar'])
            if 'sinalizada_por' in row.keys():
                sinalizada_por = row['sinalizada_por'] or ''
        except Exception:
            pass  # Exceção silenciada intencionalmente
        
        # Verifica status de conclusão pela cozinha
        oculto_cozinha = False
        oculto_cozinha_por = ''
        oculto_cozinha_em = ''
        try:
            if 'oculto_cozinha' in row.keys():
                oculto_cozinha = bool(row['oculto_cozinha'])
            if 'oculto_cozinha_por' in row.keys():
                oculto_cozinha_por = row['oculto_cozinha_por'] or ''
            if 'oculto_cozinha_em' in row.keys():
                oculto_cozinha_em = row['oculto_cozinha_em'] or ''
        except Exception:
            pass  # Exceção silenciada intencionalmente
        
        result[row['numero']] = {
            'cliente': row['cliente'] or 'Consumidor Final',
            'observacao': row['observacao'] or '',
            'itens': itens_formatados,
            'status': row['status'],
            'abertura': row['created_at'] if 'created_at' in row.keys() else '',
            'cliente_id': '1',
            'sinalizada_para_fechar': sinalizada,
            'sinalizada_por': sinalizada_por,
            'concluida_cozinha': oculto_cozinha,
            'concluida_cozinha_por': oculto_cozinha_por,
            'concluida_cozinha_em': oculto_cozinha_em
        }
    return result

def _mysql_load_caixa():
    """Carrega os dados do caixa do MySQL com tratamento robusto de erros."""
    try:
        db = get_db()
        row = db.fetchone("SELECT * FROM caixa ORDER BY id DESC LIMIT 1")
        if row:
            raw_transacoes = row.get('transacoes')
            transacoes = _deserialize_cash_transactions(raw_transacoes, 'caixa')

            # ─── REPARO AUTOMÁTICO: se o JSON estava corrompido, salva a versão recuperada ───
            _auto_repair_transacoes(db, 'caixa', row.get('id'), raw_transacoes, transacoes)

            return {
                'status': row['status'] or 'fechado',
                'saldo_inicial': float(row['saldo_inicial'] or 0.0),
                'transacoes': transacoes,
                'data_abertura': row.get('data_abertura', ''),
                'usuario_abertura': row.get('usuario_abertura', '')
            }
    except Exception as e:
        logging.error(f"Erro ao carregar dados do caixa: {e}")
    return {"status": "fechado", "transacoes": [], "saldo_inicial": 0.0}

