def _mysql_load_config():
    db = get_db()
    rows = db.fetchall("SELECT * FROM configuracoes")
    # Usa TODAS as chaves do DEFAULT_CONFIG como base.
    # Antes algumas chaves novas eram carregadas como texto ("False"),
    # e bool("False") em Python vira True, por isso os campos não sumiam.
    result = DEFAULT_CONFIG.copy() if 'DEFAULT_CONFIG' in globals() else {
        "store_name": "Sua Loja Aqui",
        "store_address": "Seu Endereço Aqui, 123\nSua Cidade, UF - CEP 12345-678",
        "last_coupon_number": 0,
        "last_comanda_number": 0,
        "atacado_qtd_minima": 10,
        "atacado_habilitado": True,
        "vendedor_obrigatorio": True,
        "imprimir_canhoto_loja": True,
        "acrescentar_taxa_cartao_pagamento": True,
        "taxa_garcom_ativa": False,
        "garcom_obrigatorio_pagamento": False,
        "modo_supermercado": False,
        "pagamento_mostrar_total_venda": True,
        "pagamento_mostrar_cliente": True,
        "pagamento_mostrar_entrega": True,
        "pagamento_mostrar_vendedor": True,
        "pagamento_mostrar_garcom_taxa": True,
    }
    for row in rows:
        chave = row['chave']
        valor = row['valor']
        if chave in ['last_coupon_number', 'last_comanda_number', 'atacado_qtd_minima']:
            result[chave] = int(valor) if valor else 0
        elif chave in [
            'atacado_habilitado',
            'vendedor_obrigatorio',
            'imprimir_canhoto_loja',
            'acrescentar_taxa_cartao_pagamento',
            'taxa_garcom_ativa',
            'garcom_obrigatorio_pagamento',
            'modo_supermercado',
            'pagamento_mostrar_total_venda',
            'pagamento_mostrar_cliente',
            'pagamento_mostrar_entrega',
            'pagamento_mostrar_vendedor',
            'pagamento_mostrar_garcom_taxa',
        ]:
            result[chave] = cfg_bool(valor, result.get(chave, False)) if 'cfg_bool' in globals() else (valor.lower() in ['true', '1', 'sim', 'yes'] if isinstance(valor, str) else bool(valor))
        else:
            result[chave] = valor
    return result

def _mysql_load_empresa():
    db = get_db()
    row = db.fetchone("SELECT * FROM empresa WHERE id = 1")
    if row:
        # Tenta obter chave_pix de forma segura
        try:
            chave_pix = row['chave_pix'] if row['chave_pix'] else ''
        except (KeyError, IndexError):
            chave_pix = ''
        
        # Tenta obter politica_troca de forma segura
        try:
            politica_troca = row['politica_troca'] if row['politica_troca'] else ''
        except (KeyError, IndexError):
            politica_troca = ''
        
        return {
            'nome': row['nome'] or 'Sua Empresa Aqui',
            'cnpj': row['cnpj'] or '',
            'endereco': row['endereco'] or 'Endereço não configurado',
            'telefone': row['telefone'] or '',
            'email': row['email'] or '',
            'cidade': row['cidade'] or '',
            'estado': row['estado'] or '',
            'cep': row['cep'] or '',
            'chave_pix': chave_pix,
            'politica_troca': politica_troca
        }
    return DEFAULT_EMPRESA.copy()

def _mysql_load_user_log():
    db = get_db()
    rows = db.fetchall("SELECT * FROM user_log ORDER BY id")
    result = []
    for row in rows:
        result.append({
            'usuario': row['usuario'],
            'acao': row['acao'],
            'detalhes': row['detalhes'],
            'datahora': row['datahora']
        })
    return result

def _mysql_load_users():
    db = get_db()
    rows = db.fetchall("SELECT * FROM usuarios WHERE ativo = 1")
    result = {}
    for row in rows:
        # FIX: JSON corrompido/truncado no campo permissoes → retorna lista vazia
        try:
            permissoes = json.loads(row['permissoes']) if row['permissoes'] else []
        except (json.JSONDecodeError, ValueError, TypeError):
            permissoes = []
        result[row['username']] = {
            'password': row['password_hash'],
            'nivel_acesso': row['nivel_acesso'] or 'caixa',
            'permissoes': permissoes
        }
    # Revisa usuários existentes para receber permissões criadas após os níveis antigos.
    try:
        if "sincronizar_todos_usuarios_com_niveis" in globals():
            result = sincronizar_todos_usuarios_com_niveis(result, salvar=True)
    except Exception as e:
        print(f"[PERMISSÕES] Aviso ao sincronizar usuários existentes: {e}")
    return result

