def _mysql_save_products_single(prod_id, prod_data):
    """Salva um único produto no banco de dados de forma otimizada."""
    db = get_db()
    existing = db.fetchone("SELECT id FROM produtos WHERE id = %s", (int(prod_id),))
    categoria_id = prod_data.get('categoria_id') or prod_data.get('category_id') or '1'
    
    tamanho_id_raw = prod_data.get('tamanho_id')
    tamanho_id = None
    if tamanho_id_raw is not None and tamanho_id_raw != '' and tamanho_id_raw != 'None':
        try:
            tamanho_id = int(tamanho_id_raw)
        except (ValueError, TypeError):
            tamanho_id = None
    
    if existing:
        db.execute("""
            UPDATE produtos SET 
                nome = %s, codigo_barras = %s, categoria_id = %s, preco = %s,
                preco_atacado = %s, atacado_qtd_minima = %s, preco_promocional = %s,
                promocao_ativa = %s, promocao_inicio = %s, promocao_fim = %s, preco_compra = %s, tipo = %s, 
                estoque = %s, estoque_minimo = %s, fidelidade_pontos = %s, tamanho_id = %s,
                imagem = %s,
                ativo = 1, updated_at = CURRENT_TIMESTAMP
            WHERE id = %s
        """, (
            prod_data.get('nome', ''),
            prod_data.get('codigo_barras', ''),
            int(categoria_id) if categoria_id else 1,
            parse_br_float(prod_data.get('preco', 0)),
            parse_br_float(prod_data.get('preco_atacado', 0)),
            parse_br_float(prod_data.get('atacado_qtd_minima', 10)),
            parse_br_float(prod_data.get('preco_promocional', 0)),
            1 if prod_data.get('promocao_ativa', False) else 0,
            prod_data.get('promocao_inicio', ''),
            prod_data.get('promocao_fim', ''),
            parse_br_float(prod_data.get('preco_compra', 0)),
            prod_data.get('tipo', 'unidade'),
            parse_br_float(prod_data.get('estoque', 0)),
            parse_br_float(prod_data.get('estoque_minimo', 5)),
            int(prod_data.get('fidelidade_pontos', 0)),
            tamanho_id,
            json.dumps(prod_data.get('imagens', [])) if prod_data.get('imagens') else (prod_data.get('imagem', '') or ''),
            int(prod_id)
        ))
    else:
        db.execute("""
            INSERT INTO produtos (id, nome, codigo_barras, categoria_id, preco, preco_atacado, 
                atacado_qtd_minima, preco_promocional, promocao_ativa, promocao_inicio, promocao_fim,
                preco_compra, tipo, estoque, estoque_minimo, fidelidade_pontos, tamanho_id, imagem, ativo)
            VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, 1)
        """, (
            int(prod_id),
            prod_data.get('nome', ''),
            prod_data.get('codigo_barras', ''),
            int(categoria_id) if categoria_id else 1,
            parse_br_float(prod_data.get('preco', 0)),
            parse_br_float(prod_data.get('preco_atacado', 0)),
            parse_br_float(prod_data.get('atacado_qtd_minima', 10)),
            parse_br_float(prod_data.get('preco_promocional', 0)),
            1 if prod_data.get('promocao_ativa', False) else 0,
            prod_data.get('promocao_inicio', ''),
            prod_data.get('promocao_fim', ''),
            parse_br_float(prod_data.get('preco_compra', 0)),
            prod_data.get('tipo', 'unidade'),
            parse_br_float(prod_data.get('estoque', 0)),
            parse_br_float(prod_data.get('estoque_minimo', 5)),
            int(prod_data.get('fidelidade_pontos', 0)),
            tamanho_id,
            json.dumps(prod_data.get('imagens', [])) if prod_data.get('imagens') else (prod_data.get('imagem', '') or '')
        ))
    return True

def _mysql_delete_product(prod_id):
    """Marca um produto como inativo no banco de dados de forma otimizada."""
    db = get_db()
    try:
        db.execute('UPDATE produtos SET ativo = 0 WHERE id = %s', (int(prod_id),))
        return True
    except Exception as e:
        print(f"Erro ao excluir produto {prod_id}: {e}")
        return False

def _mysql_save_products(data):
    db = get_db()
    existing_rows = db.fetchall("SELECT id FROM produtos")
    existing_ids = set(str(row['id']) for row in existing_rows) if existing_rows else set()
    data_ids = set(str(prod_id) for prod_id in data.keys())
    ids_to_delete = existing_ids - data_ids
    for prod_id in ids_to_delete:
        _mysql_delete_product(prod_id)
    for prod_id, prod_data in data.items():
        _mysql_save_products_single(prod_id, prod_data)
    return True

def _mysql_save_categories(data):
    db = get_db()
    
    # Obtém todos os IDs de categorias existentes no banco
    existing_rows = db.fetchall("SELECT id FROM categorias")
    existing_ids = set(str(row['id']) for row in existing_rows) if existing_rows else set()
    
    # IDs que devem permanecer (os que estão no dicionário data)
    data_ids = set(str(cat_id) for cat_id in data.keys())
    
    # IDs a serem excluídos (existem no banco mas não estão mais no dicionário)
    ids_to_delete = existing_ids - data_ids
    
    # Exclui as categorias removidas (marca como inativo)
    for cat_id in ids_to_delete:
        db.execute('UPDATE categorias SET ativo = 0 WHERE id = %s', (int(cat_id),))
    
    # Insere ou atualiza as categorias do dicionário
    for cat_id, cat_data in data.items():
        existing = db.fetchone("SELECT id FROM categorias WHERE id = %s", (int(cat_id),))
        if existing:
            db.execute('UPDATE categorias SET nome = %s, descricao = %s, ativo = 1 WHERE id = %s',
                (cat_data.get('nome', ''), cat_data.get('descricao', ''), int(cat_id)))
        else:
            db.execute('INSERT INTO categorias (id, nome, descricao, ativo) VALUES (%s, %s, %s, 1)',
                (int(cat_id), cat_data.get('nome', ''), cat_data.get('descricao', '')))
    return True

