def _mysql_load_tamanhos():
    """Carrega tamanhos do banco de dados MySQL."""
    db = get_db()
    rows = db.fetchall("SELECT * FROM tamanhos WHERE ativo = 1")
    result = {}
    for row in rows:
        result[str(row['id'])] = {
            'nome': row['nome'],
            'sigla': row['sigla'] or '',
            'ordem': row['ordem'] or 0,
            'tipo': row['tipo'] or 'Roupa',
            'descricao': row['descricao'] or '',
            'ativo': True  # Sempre True pois filtramos ativo = 1
        }
    return result

