def _mysql_save_sales(data):
    db = get_db()
    rows = db.fetchall("SELECT id, coupon_number FROM vendas")
    existing_coupons = {row['coupon_number']: row['id'] for row in rows}
    
    for venda in data:
        coupon_number = venda.get('coupon_number')
        if coupon_number in existing_coupons:
            db.execute("""
                UPDATE vendas SET 
                    timestamp = %s, data = %s, cliente_id = %s, cliente_nome = %s,
                    total = %s, formas_pagamento = %s, troco = %s, usuario = %s,
                    is_delivery = %s, itens = %s, entregador_id = %s, entregador_nome = %s, entrega_concluida = %s, data_entrega_concluida = %s,
                    vendedor_id = %s, vendedor_nome = %s
                WHERE coupon_number = %s
            """, (
                venda.get('timestamp'),
                venda.get('data'),
                int(venda.get('cliente_id', 1)) if venda.get('cliente_id') else 1,
                venda.get('cliente_nome', 'Consumidor Final'),
                float(venda.get('total', 0)),
                json.dumps(venda.get('formas_pagamento', {})),
                float(venda.get('troco', 0)),
                venda.get('usuario', ''),
                1 if venda.get('is_delivery') else 0,
                json.dumps(venda.get('itens', {})),
                venda.get('entregador_id', ''),
                venda.get('entregador_nome', ''),
                1 if venda.get('entrega_concluida') else 0,
                venda.get('data_entrega_concluida', ''),
                venda.get('vendedor_id', '') or '',
                venda.get('vendedor_nome', '') or '',
                coupon_number
            ))
        else:
            db.execute("""
                INSERT INTO vendas (coupon_number, timestamp, data, cliente_id, cliente_nome, total, formas_pagamento, troco, usuario, is_delivery, itens, entregador_id, entregador_nome, entrega_concluida, data_entrega_concluida, vendedor_id, vendedor_nome)
                VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s, %s)
            """, (
                coupon_number,
                venda.get('timestamp'),
                venda.get('data'),
                int(venda.get('cliente_id', 1)) if venda.get('cliente_id') else 1,
                venda.get('cliente_nome', 'Consumidor Final'),
                float(venda.get('total', 0)),
                json.dumps(venda.get('formas_pagamento', {})),
                float(venda.get('troco', 0)),
                venda.get('usuario', ''),
                1 if venda.get('is_delivery') else 0,
                json.dumps(venda.get('itens', {})),
                venda.get('entregador_id', ''),
                venda.get('entregador_nome', ''),
                1 if venda.get('entrega_concluida') else 0,
                venda.get('data_entrega_concluida', ''),
                venda.get('vendedor_id', '') or '',
                venda.get('vendedor_nome', '') or ''
            ))
    return True

