def _mysql_save_caixa_by_id(caixa_id, data):
    """
    Salva os dados de um caixa especifico pelo ID.
    
    CORREÇÃO: Usa transação explícita com SELECT ... FOR UPDATE para garantir
    atomicidade e evitar que escritas concorrentes produzam JSON truncado
    (erro "Unterminated string starting at...").
    """
    db = get_db()
    conn = db.get_connection()
    cursor = conn.cursor(dictionary=True)
    original_autocommit = conn.autocommit
    try:
        # Desabilita autocommit para usar transação explícita
        conn.autocommit = False
        conn.start_transaction()
        
        # SELECT FOR UPDATE bloqueia a linha até o COMMIT, impedindo
        # que outra thread leia/escreva dados parciais
        cursor.execute(
            "SELECT id FROM caixa WHERE caixa_id = %s ORDER BY id DESC LIMIT 1 FOR UPDATE",
            (caixa_id,)
        )
        existing = cursor.fetchone()
        
        transacoes_json = _serialize_cash_transactions(data.get('transacoes', []))
        
        if existing:
            cursor.execute("""
                UPDATE caixa SET status = %s, saldo_inicial = %s, transacoes = %s, data_abertura = %s, usuario_abertura = %s
                WHERE id = %s
            """, (
                data.get('status', 'fechado'),
                float(data.get('saldo_inicial', 0)),
                transacoes_json,
                data.get('data_abertura', ''),
                data.get('usuario_abertura', ''),
                existing['id']
            ))
        else:
            cursor.execute("""
                INSERT INTO caixa (caixa_id, status, saldo_inicial, transacoes, data_abertura, usuario_abertura)
                VALUES (%s, %s, %s, %s, %s, %s)
            """, (
                caixa_id,
                data.get('status', 'fechado'),
                float(data.get('saldo_inicial', 0)),
                transacoes_json,
                data.get('data_abertura', ''),
                data.get('usuario_abertura', '')
            ))
        
        conn.commit()
        return True
    except Exception as e:
        try:
            conn.rollback()
        except Exception:
            pass
        logging.error(f"Erro ao salvar caixa {caixa_id} no MySQL: {e}")
        # Fallback: tenta salvar sem transação explícita (compatibilidade)
        try:
            conn.autocommit = True
            existing2 = db.fetchone("SELECT id FROM caixa WHERE caixa_id = %s ORDER BY id DESC LIMIT 1", (caixa_id,))
            transacoes_json = _serialize_cash_transactions(data.get('transacoes', []))
            if existing2:
                db.execute("""
                    UPDATE caixa SET status = %s, saldo_inicial = %s, transacoes = %s, data_abertura = %s, usuario_abertura = %s
                    WHERE id = %s
                """, (
                    data.get('status', 'fechado'),
                    float(data.get('saldo_inicial', 0)),
                    transacoes_json,
                    data.get('data_abertura', ''),
                    data.get('usuario_abertura', ''),
                    existing2['id']
                ))
            else:
                db.execute("""
                    INSERT INTO caixa (caixa_id, status, saldo_inicial, transacoes, data_abertura, usuario_abertura)
                    VALUES (%s, %s, %s, %s, %s, %s)
                """, (
                    caixa_id,
                    data.get('status', 'fechado'),
                    float(data.get('saldo_inicial', 0)),
                    transacoes_json,
                    data.get('data_abertura', ''),
                    data.get('usuario_abertura', '')
                ))
            return True
        except Exception as e2:
            logging.error(f"Erro no fallback ao salvar caixa {caixa_id}: {e2}")
            return False
    finally:
        try:
            conn.autocommit = original_autocommit
        except Exception:
            pass
        try:
            cursor.close()
        except Exception:
            pass

def _mysql_save_fechamentos_caixa_by_id(caixa_id, data):
    """Salva o historico de fechamentos de um caixa especifico."""
    db = get_db()
    # Deleta apenas os fechamentos deste caixa especifico
    db.execute("DELETE FROM fechamentos_caixa WHERE caixa_id = %s", (caixa_id,))
    for fechamento in data:
        db.execute("""
            INSERT INTO fechamentos_caixa (caixa_id, data_abertura, data_fechamento, saldo_inicial, saldo_final, total_entradas, total_saidas, usuario, transacoes)
            VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s)
        """, (
            caixa_id,
            fechamento.get('data_abertura'),
            fechamento.get('data_fechamento'),
            float(fechamento.get('saldo_inicial', 0)),
            float(fechamento.get('saldo_final', 0)),
            float(fechamento.get('total_entradas', 0)),
            float(fechamento.get('total_saidas', 0)),
            fechamento.get('usuario', ''),
            _serialize_cash_transactions(fechamento.get('transacoes', []))
        ))
    return True

def _mysql_save_config(data):
    db = get_db()
    for chave, valor in data.items():
        existing = db.fetchone("SELECT id FROM configuracoes WHERE chave = %s", (chave,))
        if existing:
            db.execute('UPDATE configuracoes SET valor = %s, updated_at = CURRENT_TIMESTAMP WHERE chave = %s',
                (str(valor), chave))
        else:
            db.execute('INSERT INTO configuracoes (chave, valor) VALUES (%s, %s)', (chave, str(valor)))
    return True

