def _mysql_save_user_log(data):
    db = get_db()
    count_row = db.fetchone("SELECT COUNT(*) as count FROM user_log")
    existing_count = count_row['count'] if count_row else 0
    for i, log_entry in enumerate(data):
        if i >= existing_count:
            db.execute("""
                INSERT INTO user_log (usuario, acao, detalhes, datahora)
                VALUES (%s, %s, %s, %s)
            """, (
                log_entry.get('usuario', ''),
                log_entry.get('acao', ''),
                log_entry.get('detalhes', ''),
                log_entry.get('datahora')
            ))
    return True

def _mysql_save_users(data):
    db = get_db()

    # Mantém a tabela sincronizada com o dicionário recebido.
    # Isso garante persistência correta de edição, exclusão e renomeação.
    usernames_ativos = set()

    for username, user_data in data.items():
        username = str(username).strip().lower()
        if not username:
            continue

        usernames_ativos.add(username)
        permissoes_json = json.dumps(user_data.get('permissoes', []), ensure_ascii=False)
        existing = db.fetchone("SELECT id FROM usuarios WHERE username = %s", (username,))

        if existing:
            db.execute("""
                UPDATE usuarios SET 
                    password_hash = %s,
                    nivel_acesso = %s,
                    permissoes = %s,
                    ativo = 1,
                    updated_at = CURRENT_TIMESTAMP
                WHERE username = %s
            """, (
                user_data.get('password', ''),
                user_data.get('nivel_acesso', 'caixa'),
                permissoes_json,
                username
            ))
        else:
            db.execute("""
                INSERT INTO usuarios (username, password_hash, nivel_acesso, permissoes, ativo)
                VALUES (%s, %s, %s, %s, 1)
            """, (
                username,
                user_data.get('password', ''),
                user_data.get('nivel_acesso', 'caixa'),
                permissoes_json
            ))

    # Desativa usuários que não existem mais no dicionário atual.
    # Protege os usuários de sistema contra desativação acidental.
    existentes = db.fetchall("SELECT username FROM usuarios WHERE ativo = 1") or []
    protegidos = {'adm', 'phda'}
    for row in existentes:
        username_db = str(row.get('username', '')).strip().lower()
        if username_db and username_db not in usernames_ativos and username_db not in protegidos:
            db.execute("""
                UPDATE usuarios
                SET ativo = 0, updated_at = CURRENT_TIMESTAMP
                WHERE username = %s
            """, (username_db,))

    return True


