# ===========================================================================
# CORREÇÃO GLOBAL: DateEntry brasileiro sem aviso/travamento visual
# ===========================================================================
# O ttkbootstrap emite UserWarning quando o texto interno do DateEntry não bate
# com dateformat. Normalizamos datas para dd/MM/yyyy e impedimos que avisos
# poluam o console durante a abertura ou uso das telas.
warnings.filterwarnings(
    "ignore",
    message=r"Date entry text does not match with date format:.*",
    category=UserWarning,
)

def _normalizar_data_br_para_dateentry(valor):
    """Converte datas comuns para dd/MM/yyyy, sem quebrar valores já válidos."""
    if valor is None:
        return ""
    try:
        if hasattr(valor, 'strftime'):
            return valor.strftime('%d/%m/%Y')
    except Exception:
        pass
    texto = str(valor).strip()
    if not texto:
        return ""
    try:
        if len(texto) >= 10 and texto[2] == '/' and texto[5] == '/':
            return texto[:10]
    except Exception:
        pass
    try:
        if len(texto) >= 10 and texto[4] == '-' and texto[7] == '-':
            ano, mes, dia = texto[:10].split('-')
            return f"{dia}/{mes}/{ano}"
    except Exception:
        pass
    return texto

def _set_dateentry_br(widget, valor=""):
    """Preenche DateEntry com formato brasileiro sem disparar warning do ttkbootstrap."""
    try:
        texto = _normalizar_data_br_para_dateentry(valor)
        widget.entry.delete(0, tk.END)
        if texto:
            widget.entry.insert(0, texto)
    except Exception:
        try:
            widget.entry.delete(0, 'end')
            if valor:
                widget.entry.insert(0, str(valor))
        except Exception:
            pass

# ===========================================================================
# CORRECAO: UnicodeEncodeError no DatePickerDialog do ttkbootstrap
# ===========================================================================
# No Windows com locale pt_BR (Portuguese_Brazil.1252), o strftime("%B")
# retorna nomes de meses com caracteres surrogate (ex: \udce7 para "c cedilha"
# em "marco"), que o Tcl/Tk nao consegue processar, causando:
#   UnicodeEncodeError: 'utf-8' codec can't encode character '\udce7'
#   in position 17: surrogates not allowed
#
# A correcao aplica um monkey-patch no metodo _set_title do DatePickerDialog
# para usar nomes de meses em portugues puro (sem depender do strftime),
# eliminando completamente o problema de encoding.
# ===========================================================================
try:
    from ttkbootstrap.dialogs.datepicker import DatePickerDialog

    _MESES_PT_BR = {
        1: 'Janeiro', 2: 'Fevereiro', 3: 'Marco', 4: 'Abril',
        5: 'Maio', 6: 'Junho', 7: 'Julho', 8: 'Agosto',
        9: 'Setembro', 10: 'Outubro', 11: 'Novembro', 12: 'Dezembro'
    }

    _original_set_title = DatePickerDialog._set_title

    def _safe_set_title(self):
        """Versao corrigida de _set_title que evita UnicodeEncodeError
        ao usar nomes de meses em portugues no Windows."""
        try:
            _original_set_title(self)
        except (UnicodeEncodeError, UnicodeDecodeError, Exception):
            # Fallback seguro: usa tabela de meses em portugues puro
            try:
                _month = _MESES_PT_BR.get(self.date.month, str(self.date.month))
                _year = str(self.date.year)
                self._title.configure(text=f"{_month} {_year}")
            except Exception:
                # Ultimo recurso: formato numerico
                try:
                    self._title.configure(text=f"{self.date.month:02d}/{self.date.year}")
                except Exception:
                    pass

    DatePickerDialog._set_title = _safe_set_title
    print("[FIX] Monkey-patch aplicado: DatePickerDialog._set_title corrigido para locale pt_BR")
except ImportError:
    pass
except Exception as _e:
    print(f"[AVISO] Nao foi possivel aplicar correcao do DatePicker: {_e}")
# ===========================================================================


def handle_enter_as_tab(event):
    """Faz a tecla Enter se comportar como Tab para navegação entre campos."""
    try:
        widget = event.widget
        # Se event.widget for uma string (nome do widget), converte para objeto widget
        if isinstance(widget, str):
            widget = event.widget.nametowidget(widget) if hasattr(event, 'widget') else None
            if widget is None:
                # Tenta obter o widget através do root
                try:
                    root = event.widget
                    if isinstance(root, str):
                        return "break"
                except:
                    return "break"
        # Verifica se o widget tem o método tk_focusNext
        if widget and hasattr(widget, 'tk_focusNext'):
            next_widget = widget.tk_focusNext()
            if next_widget and hasattr(next_widget, 'focus'):
                next_widget.focus()
    except (AttributeError, TypeError, tk.TclError):
        pass
    return "break"

