class CanvasChart:
    """
    Classe para desenhar gráficos diretamente no Tkinter Canvas.
    Substitui matplotlib para compatibilidade com Python 32-bit.
    """
    
    def __init__(self, parent, width=800, height=400, bg='white', padding=50):
        self.width = width
        self.height = height
        self.padding = padding
        self.canvas = tk.Canvas(parent, width=width, height=height, bg=bg, highlightthickness=0)
        self.colors = ['#007bff', '#28a745', '#dc3545', '#ffc107', '#17a2b8', '#6f42c1', '#fd7e14']
        
    def pack(self, **kwargs):
        self.canvas.pack(**kwargs)
        
    def grid(self, **kwargs):
        self.canvas.grid(**kwargs)
        
    def clear(self):
        self.canvas.delete('all')
        
    def draw_line_chart(self, labels, values, title="", line_color='#007bff', fill_color=None, show_points=True):
        """
        Desenha um gráfico de linha com preenchimento opcional.
        """
        self.clear()
        
        if not values or len(values) == 0:
            self.canvas.create_text(self.width//2, self.height//2, 
                                   text="Sem dados para exibir", 
                                   font=('Segoe UI', 14), fill='gray')
            return
            
        # Área do gráfico
        left = self.padding + 40
        right = self.width - self.padding
        top = self.padding + 30
        bottom = self.height - self.padding - 20
        
        # Título
        if title:
            self.canvas.create_text(self.width//2, 20, text=title, 
                                   font=('Segoe UI', 14, 'bold'), fill='#333')
        
        # Calcular escala
        max_val = max(values) if max(values) > 0 else 1
        min_val = min(values) if min(values) < max_val else 0
        val_range = max_val - min_val if max_val != min_val else 1
        
        # Desenhar grid e eixos
        self.canvas.create_line(left, bottom, right, bottom, fill='#ddd', width=1)  # Eixo X
        self.canvas.create_line(left, top, left, bottom, fill='#ddd', width=1)  # Eixo Y
        
        # Linhas de grade horizontais
        num_grid_lines = 5
        for i in range(num_grid_lines + 1):
            y = bottom - (i / num_grid_lines) * (bottom - top)
            self.canvas.create_line(left, y, right, y, fill='#eee', width=1)
            # Labels do eixo Y
            val = min_val + (i / num_grid_lines) * val_range
            self.canvas.create_text(left - 5, y, text=f'R$ {val:,.0f}', 
                                   anchor='e', font=('Segoe UI', 8), fill='#666')
        
        # Calcular pontos
        n_points = len(values)
        if n_points == 1:
            x_step = 0
        else:
            x_step = (right - left) / (n_points - 1)
        
        points = []
        for i, val in enumerate(values):
            x = left + i * x_step
            y = bottom - ((val - min_val) / val_range) * (bottom - top)
            points.append((x, y))
        
        # Desenhar preenchimento
        if fill_color and len(points) > 1:
            fill_points = [left, bottom]
            for x, y in points:
                fill_points.extend([x, y])
            fill_points.extend([right, bottom])
            self.canvas.create_polygon(fill_points, fill=fill_color, outline='')
        
        # Desenhar linha
        if len(points) > 1:
            for i in range(len(points) - 1):
                x1, y1 = points[i]
                x2, y2 = points[i + 1]
                self.canvas.create_line(x1, y1, x2, y2, fill=line_color, width=3, smooth=True)
        
        # Desenhar pontos e labels
        if show_points:
            for i, (x, y) in enumerate(points):
                # Ponto
                self.canvas.create_oval(x-5, y-5, x+5, y+5, fill=line_color, outline='white', width=2)
                # Label do eixo X
                label = labels[i] if i < len(labels) else str(i)
                self.canvas.create_text(x, bottom + 15, text=label, 
                                       font=('Segoe UI', 8), fill='#666', angle=0)
                # Valor no ponto
                self.canvas.create_text(x, y - 15, text=f'R$ {values[i]:,.2f}', 
                                       font=('Segoe UI', 8, 'bold'), fill='#333')
    
    def draw_bar_chart(self, labels, values, title="", colors=None):
        """
        Desenha um gráfico de barras.
        """
        self.clear()
        
        if not values or len(values) == 0:
            self.canvas.create_text(self.width//2, self.height//2, 
                                   text="Sem dados para exibir", 
                                   font=('Segoe UI', 14), fill='gray')
            return
        
        if colors is None:
            colors = self.colors
            
        # Área do gráfico
        left = self.padding + 40
        right = self.width - self.padding
        top = self.padding + 30
        bottom = self.height - self.padding - 30
        
        # Título
        if title:
            self.canvas.create_text(self.width//2, 20, text=title, 
                                   font=('Segoe UI', 14, 'bold'), fill='#333')
        
        # Calcular escala
        max_val = max(values) if max(values) > 0 else 1
        
        # Desenhar barras
        n_bars = len(values)
        bar_width = (right - left) / n_bars * 0.7
        gap = (right - left) / n_bars * 0.15
        
        for i, val in enumerate(values):
            x1 = left + i * (bar_width + gap * 2) + gap
            x2 = x1 + bar_width
            bar_height = (val / max_val) * (bottom - top)
            y1 = bottom - bar_height
            y2 = bottom
            
            color = colors[i % len(colors)]
            self.canvas.create_rectangle(x1, y1, x2, y2, fill=color, outline='')
            
            # Label
            label = labels[i] if i < len(labels) else str(i)
            self.canvas.create_text((x1 + x2) / 2, bottom + 15, text=label, 
                                   font=('Segoe UI', 9), fill='#666')
            # Valor
            self.canvas.create_text((x1 + x2) / 2, y1 - 10, text=f'R$ {val:,.2f}', 
                                   font=('Segoe UI', 9, 'bold'), fill='#333')
    
    def draw_pie_chart(self, labels, values, title="", colors=None):
        """
        Desenha um gráfico de pizza.
        """
        self.clear()
        
        if not values or len(values) == 0 or sum(values) == 0:
            self.canvas.create_text(self.width//2, self.height//2, 
                                   text="Sem dados para exibir", 
                                   font=('Segoe UI', 14), fill='gray')
            return
        
        if colors is None:
            colors = self.colors
            
        # Título
        if title:
            self.canvas.create_text(self.width//2, 20, text=title, 
                                   font=('Segoe UI', 14, 'bold'), fill='#333')
        
        # Centro e raio
        cx = self.width // 2 - 80
        cy = self.height // 2 + 10
        radius = min(self.width, self.height) // 3
        
        # Calcular ângulos
        total = sum(values)
        start_angle = 90
        
        for i, val in enumerate(values):
            extent = (val / total) * 360
            color = colors[i % len(colors)]
            
            self.canvas.create_arc(cx - radius, cy - radius, cx + radius, cy + radius,
                                  start=start_angle, extent=-extent,
                                  fill=color, outline='white', width=2)
            start_angle -= extent
        
        # Legenda
        legend_x = self.width - 150
        legend_y = 60
        for i, (label, val) in enumerate(zip(labels, values)):
            color = colors[i % len(colors)]
            pct = (val / total) * 100
            
            self.canvas.create_rectangle(legend_x, legend_y + i * 25, 
                                        legend_x + 15, legend_y + i * 25 + 15,
                                        fill=color, outline='')
            self.canvas.create_text(legend_x + 20, legend_y + i * 25 + 7,
                                   text=f'{label}: {pct:.1f}%',
                                   anchor='w', font=('Segoe UI', 9), fill='#333')


