class QuantumIntelligence:
    """Motor de Inteligência Preditiva para sugestão de vendas e análise de estoque."""
    
    def __init__(self, sales_log, products):
        self.sales_log = sales_log
        self.products = products

    def predict_next_sales(self, top_n=5):
        """Prediz os produtos com maior probabilidade de venda baseada no histórico recente."""
        if not self.sales_log: return []
        
        # Analisa os últimos 30 dias
        recent_sales = []
        cutoff = datetime.datetime.now() - datetime.timedelta(days=30)
        for sale in self.sales_log:
            try:
                sale_date = datetime.datetime.fromisoformat(sale.get('timestamp', ''))
                if sale_date > cutoff:
                    for item_id, item_data in sale.get('itens', {}).items():
                        recent_sales.append(item_data.get('nome', ''))
            except: continue
            
        from collections import Counter
        counts = Counter(recent_sales)
        return counts.most_common(top_n)

    def get_stock_health_score(self):
        """Calcula um score de saúde do estoque (0-100)."""
        if not self.products: return 100
        total_items = len(self.products)
        low_stock_items = sum(1 for p in self.products.values() if parse_br_float(p.get('estoque', 0)) <= 5)
        score = max(0, 100 - (low_stock_items / total_items * 100))
        return score

