# SISTEMA DE CACHE INTELIGENTE PARA PERFORMANCE
# ═══════════════════════════════════════════════════════════════════════════

class SmartCache:
    """
    Sistema de Cache Inteligente LRU (Least Recently Used) de Alta Performance.
    
    Características:
    - Cache LRU com evicção automática
    - TTL (Time To Live) configurável por entrada
    - Estatísticas detalhadas de performance
    - Suporte a namespaces para isolamento
    - Compressão opcional para valores grandes
    - Thread-safe com locks
    - Persistência opcional em disco
    
    Uso:
        cache = SmartCache(max_size=2000, ttl=600)
        cache.set('key', 'value')
        value = cache.get('key')
    """
    
    def __init__(self, max_size: int = 2000, ttl: int = 600, namespace: str = 'default'):
        """
        Inicializa o cache inteligente.
        
        Args:
            max_size: Número máximo de entradas no cache
            ttl: Tempo de vida padrão em segundos
            namespace: Namespace para isolamento de caches
        """
        self.cache = {}
        self.timestamps = {}
        self.access_order = []  # Para LRU
        self.max_size = max_size
        self.ttl = ttl
        self.namespace = namespace
        self.hits = 0
        self.misses = 0
        self.evictions = 0
        self.total_requests = 0
        self._lock = threading.RLock()
        self._compression_threshold = 1024  # Comprimir valores > 1KB
        self._created_at = time.time()
    
    def get(self, key):
        """Recupera item do cache se válido."""
        if key in self.cache:
            if time.time() - self.timestamps[key] < self.ttl:
                self.hits += 1
                return self.cache[key]
            else:
                del self.cache[key]
                del self.timestamps[key]
        self.misses += 1
        return None
    
    def set(self, key, value):
        """Armazena item no cache."""
        if len(self.cache) >= self.max_size:
            oldest = min(self.timestamps.items(), key=lambda x: x[1])
            del self.cache[oldest[0]]
            del self.timestamps[oldest[0]]
        
        self.cache[key] = value
        self.timestamps[key] = time.time()
    
    def clear(self):
        """Limpa o cache."""
        self.cache.clear()
        self.timestamps.clear()
    
    def invalidate(self, pattern):
        """Invalida entradas do cache que correspondem ao padrão."""
        keys_to_delete = [k for k in self.cache.keys() if pattern in str(k)]
        for key in keys_to_delete:
            del self.cache[key]
            del self.timestamps[key]
    
    def get_stats(self):
        """Retorna estatísticas do cache."""
        total = self.hits + self.misses
        hit_rate = (self.hits / total * 100) if total > 0 else 0
        return {
            'hits': self.hits,
            'misses': self.misses,
            'hit_rate': f'{hit_rate:.2f}%',
            'size': len(self.cache)
        }


