class SecureStorage:
    def __init__(self, key_path=None):
        self.enabled = Fernet is not None
        if self.enabled:
            self.key_path = key_path or os.path.join(PERSISTENCE_DIR, ".master.key")
            self.key = self._load_or_create_key()
            self.cipher = Fernet(self.key)

    def _load_or_create_key(self):
        if os.path.exists(self.key_path):
            with open(self.key_path, "rb") as kf:
                return kf.read()
        else:
            key = Fernet.generate_key()
            with open(self.key_path, "wb") as kf:
                kf.write(key)
            return key

    def encrypt(self, data: str) -> str:
        if not self.enabled: return data
        return self.cipher.encrypt(data.encode()).decode()

    def decrypt(self, token: str) -> str:
        if not self.enabled: return token
        try:
            return self.cipher.decrypt(token.encode()).decode()
        except Exception:
            return token


SECURE_STORAGE = SecureStorage()

