# SISTEMA DE BACKUP AUTOMÁTICO COM COMPRESSÃO
# ═══════════════════════════════════════════════════════════════════════════

class AutoBackupSystem:
    """Sistema de backup automático com compressão e rotação."""
    
    def __init__(self, backup_dir=None):
        self.backup_dir = backup_dir or os.path.join(PERSISTENCE_DIR, "backups")
        self._ensure_backup_dir()
        self.max_backups = 50
        self.enabled = True
    
    def _ensure_backup_dir(self):
        """Garante que o diretório de backup existe."""
        try:
            if not os.path.exists(self.backup_dir):
                os.makedirs(self.backup_dir)
        except Exception as e:
            print(f"Aviso: Não foi possível criar diretório de backup: {e}")
            self.enabled = False
    
    def create_backup(self, filepath, compress=True):
        """Cria backup de um arquivo com compressão opcional."""
        if not self.enabled:
            return False
        
        try:
            if not os.path.exists(filepath):
                return False
            
            filename = os.path.basename(filepath)
            timestamp = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
            backup_name = f"{filename}.{timestamp}.bak"
            
            if compress:
                backup_name += ".gz"
                backup_path = os.path.join(self.backup_dir, backup_name)
                with open(filepath, 'rb') as f_in:
                    with gzip.open(backup_path, 'wb', compresslevel=6) as f_out:
                        shutil.copyfileobj(f_in, f_out)
            else:
                backup_path = os.path.join(self.backup_dir, backup_name)
                shutil.copy2(filepath, backup_path)
            
            self._cleanup_old_backups(filename)
            return True
        except Exception as e:
            try:
                AUDITORIA.erro(f"Erro no sistema: {e}")
            except Exception:
                pass
            print(f"Erro ao criar backup: {e}")
            return False
    
    def _cleanup_old_backups(self, filename):
        """Remove backups antigos mantendo apenas os mais recentes."""
        try:
            backups = [f for f in os.listdir(self.backup_dir) 
                      if f.startswith(filename)]
            backups.sort(reverse=True)
            
            for old_backup in backups[self.max_backups:]:
                try:
                    os.remove(os.path.join(self.backup_dir, old_backup))
                except Exception:
                    pass
        except Exception as e:
            try:
                AUDITORIA.erro(f"Erro no sistema: {e}")
            except Exception:
                pass
            print(f"Erro ao limpar backups antigos: {e}")
    
    def restore_backup(self, backup_filename, target_path):
        """Restaura um backup específico."""
        try:
            backup_path = os.path.join(self.backup_dir, backup_filename)
            if not os.path.exists(backup_path):
                return False
            
            if backup_filename.endswith('.gz'):
                with gzip.open(backup_path, 'rb') as f_in:
                    with open(target_path, 'wb') as f_out:
                        shutil.copyfileobj(f_in, f_out)
            else:
                shutil.copy2(backup_path, target_path)
            
            return True
        except Exception as e:
            try:
                AUDITORIA.erro(f"Erro no sistema: {e}")
            except Exception:
                pass
            print(f"Erro ao restaurar backup: {e}")
            return False
    
    def list_backups(self, filename=None):
        """Lista backups disponíveis opcionalmente filtrados por nome."""
        try:
            backups = os.listdir(self.backup_dir)
            if filename:
                backups = [b for b in backups if b.startswith(filename)]
            return sorted(backups, reverse=True)
        except Exception:
            return []
    
    def get_backup_size(self):
        """Retorna o tamanho total dos backups em bytes."""
        try:
            total_size = 0
            for backup in os.listdir(self.backup_dir):
                backup_path = os.path.join(self.backup_dir, backup)
                if os.path.isfile(backup_path):
                    total_size += os.path.getsize(backup_path)
            return total_size
        except Exception:
            return 0

# Sistema de backup global
BACKUP_SYSTEM = AutoBackupSystem()

