# SISTEMA DE LOG DE AUDITORIA AVANÇADO
# ═══════════════════════════════════════════════════════════════════════════

class AuditLogger:
    """Sistema de log de auditoria com níveis, rotação e compressão."""
    
    LEVELS = {'DEBUG': 0, 'INFO': 1, 'WARNING': 2, 'ERROR': 3, 'CRITICAL': 4}
    
    def __init__(self, log_file=None, level='INFO'):
        self.log_file = log_file or os.path.join(PERSISTENCE_DIR, "pdv_data", "audit.log")
        self.level = self.LEVELS.get(level, 1)
        self.enabled = True
        self._ensure_log_file()
    
    def _ensure_log_file(self):
        """Garante que o arquivo de log existe."""
        try:
            log_dir = os.path.dirname(self.log_file)
            if not os.path.exists(log_dir):
                os.makedirs(log_dir)
            if not os.path.exists(self.log_file):
                with open(self.log_file, 'w', encoding='utf-8') as f:
                    f.write(f"# Audit Log - Iniciado em {datetime.datetime.now()}\n")
        except Exception as e:
            print(f"Aviso: Não foi possível criar arquivo de log: {e}")
            self.enabled = False
    
    def _write_log(self, level, message, user=None, details=None):
        """Escreve entrada no log com formatação profissional."""
        if not self.enabled or self.LEVELS.get(level, 0) < self.level:
            return
        
        # Também registra no sistema de auditoria global
        try:
            usuario_audit = user if user else "SISTEMA"
            msg_audit = f"[AUDIT_LOGGER] {message}"
            if details:
                msg_audit += f" | {details}"
            AUDITORIA.registrar(usuario_audit, level, msg_audit)
        except Exception:
            pass
        
        try:
            timestamp = datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
            user_info = f"[{user}]" if user else "[SYSTEM]"
            log_entry = f"{timestamp} {level:8} {user_info:15} {message}"
            
            if details:
                log_entry += f" | {details}"
            
            with open(self.log_file, 'a', encoding='utf-8') as f:
                f.write(log_entry + "\n")
            
            # Rotação de log se muito grande (> 10MB)
            if os.path.getsize(self.log_file) > 10 * 1024 * 1024:
                self._rotate_log()
        except Exception as e:
            try:
                AUDITORIA.erro(f"Erro no sistema: {e}")
            except Exception:
                pass
            print(f"Erro ao escrever log: {e}")
    
    def _rotate_log(self):
        """Rotaciona e comprime o arquivo de log."""
        try:
            timestamp = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
            rotated_name = f"{self.log_file}.{timestamp}"
            shutil.move(self.log_file, rotated_name)
            
            # Comprime o log rotacionado
            with open(rotated_name, 'rb') as f_in:
                with gzip.open(f"{rotated_name}.gz", 'wb') as f_out:
                    shutil.copyfileobj(f_in, f_out)
            os.remove(rotated_name)
            
            # Recria o arquivo de log
            self._ensure_log_file()
        except Exception as e:
            try:
                AUDITORIA.erro(f"Erro no sistema: {e}")
            except Exception:
                pass
            print(f"Erro ao rotacionar log: {e}")
    
    def debug(self, message, user=None, details=None):
        self._write_log('DEBUG', message, user, details)
    
    def info(self, message, user=None, details=None):
        self._write_log('INFO', message, user, details)
    
    def warning(self, message, user=None, details=None):
        self._write_log('WARNING', message, user, details)
    
    def error(self, message, user=None, details=None):
        self._write_log('ERROR', message, user, details)
    
    def critical(self, message, user=None, details=None):
        self._write_log('CRITICAL', message, user, details)

# Logger global
AUDIT_LOGGER = AuditLogger(level='INFO')

