def _separate_barcode_number_elements(elementos):
    """Normaliza layouts para manter o número do código de barras separado da imagem."""
    elementos = list(elementos or [])
    normalized = []
    has_explicit_number = any((e or {}).get('tipo') == 'codigo_barras_texto' for e in elementos)
    for elem in elementos:
        e = dict(elem or {})
        if e.get('tipo') == 'codigo_barras' and e.get('mostrar_texto', False):
            e['mostrar_texto'] = False
            normalized.append(e)
            if not has_explicit_number:
                altura = float(e.get('altura', 20) or 20)
                normalized.append({
                    'tipo': 'codigo_barras_texto',
                    'x': float(e.get('x', 50) or 50),
                    'y': min(97.0, float(e.get('y', 50) or 50) + max(8.0, altura * 0.45)),
                    'largura': float(e.get('largura', 80) or 80),
                    'altura': max(6.0, min(12.0, altura * 0.28)),
                    'fonte': 7,
                    'alinhamento': 'centro',
                    'negrito': False,
                })
        else:
            normalized.append(e)
    return normalized


for _layout_key, _layout in LABEL_LAYOUTS.items():
    _layout['elementos'] = _separate_barcode_number_elements(_layout.get('elementos', []))


def generate_product_labels_pdf(product_data, printer_type, bobina_type, quantity, layout_config=None):
    """
    Gera um PDF com etiquetas do produto para impressão direta.
    Sistema avançado com suporte a múltiplas impressoras e layouts personalizáveis.
    
    Args:
        product_data: Dicionário com dados do produto
        printer_type: Nome da impressora do catálogo
        bobina_type: Código do tipo de etiqueta do catálogo
        quantity: Número de etiquetas a imprimir
        layout_config: Configuração de layout personalizado (opcional)
    """
    from reportlab.lib.units import mm
    from reportlab.pdfgen import canvas
    from reportlab.graphics.barcode import code128
    from tkinter import messagebox
    import os
    import datetime
    
    # Obtém configurações da etiqueta
    if bobina_type in LABEL_TEMPLATES_CATALOG:
        template = LABEL_TEMPLATES_CATALOG[bobina_type]
        label_width = template['largura'] * mm
        label_height = template['altura'] * mm
    elif bobina_type == 'PERSONALIZADA' and layout_config:
        label_width = layout_config.get('largura', 60) * mm
        label_height = layout_config.get('altura', 40) * mm
    else:
        # Fallback para configurações legadas
        if bobina_type == "60x40mm":
            label_width = 60 * mm
            label_height = 40 * mm
        elif bobina_type == "65x40x2":
            label_width = 65 * mm
            label_height = 40 * mm
        else:
            # Tenta extrair dimensões do nome
            try:
                dims = bobina_type.replace('mm', '').split('x')
                label_width = float(dims[0]) * mm
                label_height = float(dims[1]) * mm
            except:
                label_width = 60 * mm
                label_height = 40 * mm
    
    # Configurações de layout baseado no tamanho
    if label_height <= 25 * mm:
        name_font_size = 7
        price_font_size = 12
        barcode_height = 8 * mm
    elif label_height <= 35 * mm:
        name_font_size = 8
        price_font_size = 14
        barcode_height = 10 * mm
    elif label_height <= 50 * mm:
        name_font_size = 9
        price_font_size = 16
        barcode_height = 12 * mm
    else:
        name_font_size = 11
        price_font_size = 20
        barcode_height = 15 * mm
    
    # Sobrescreve com configurações personalizadas se fornecidas
    if layout_config:
        name_font_size = layout_config.get('fonte_nome', name_font_size)
        price_font_size = layout_config.get('fonte_preco', price_font_size)
        barcode_height = layout_config.get('altura_codigo', barcode_height / mm) * mm
    
    # Tamanho da página = tamanho da etiqueta (impressão contínua)
    page_size = (label_width, label_height)
    
    # Dados do produto
    product_id = str(product_data.get("id", "sem_id"))
    nome_base = str(product_data.get("nome", "Produto Sem Nome"))
    tamanho_id = product_data.get("tamanho_id")
    
    # Obtém o nome do produto com tamanho concatenado (se houver)
    try:
        tamanhos_dict = _mysql_load_tamanhos()
        product_name = get_nome_produto_com_tamanho(nome_base, tamanho_id, tamanhos_dict)
    except Exception:
        product_name = nome_base
    
    preco = product_data.get("preco", 0.0)
    preco_antigo = product_data.get("preco_antigo", product_data.get("preco_custo", 0.0))
    barcode_value, barcode_kind = _label_effective_barcode_value_and_type(product_data.get("codigo_barras") or product_data.get("codigo") or product_data.get("id") or "", fallback=product_data.get("id") or product_data.get("codigo") or "000000000001", barcode_type="EAN13")
    categoria = str(product_data.get("categoria", ""))
    codigo_interno = str(product_data.get("codigo", product_id))
    tamanho = str(product_data.get("tamanho", ""))
    
    # Nome do arquivo
    safe_name = product_name.replace(' ', '_').replace('/', '_').replace('\\', '_')[:20]
    filename = f"etiquetas_{safe_name}_{printer_type.replace(' ', '_').replace('+', 'plus')}_{bobina_type}.pdf"
    
    # Obtém layout a usar
    layout_name = layout_config.get('layout', 'padrao') if layout_config else 'padrao'
    layout = LABEL_LAYOUTS.get(layout_name, LABEL_LAYOUTS['padrao'])
    elementos = layout_config.get('elementos', layout['elementos']) if layout_config else layout['elementos']
    elementos = _separate_barcode_number_elements(elementos)
    
    try:
        c = canvas.Canvas(filename, pagesize=page_size)
        
        for i in range(quantity):
            # Margens
            margin_x = 2 * mm
            margin_y = 2 * mm
            
            # Renderiza cada elemento do layout
            for elem in elementos:
                tipo = elem.get('tipo', '')
                x_percent = elem.get('x', 50)
                y_percent = elem.get('y', 50)
                w_percent = elem.get('largura', 90)
                h_percent = elem.get('altura', 20)
                fonte = elem.get('fonte', 10)
                alinhamento = elem.get('alinhamento', 'centro')
                negrito = elem.get('negrito', False)
                
                # Converte porcentagens para coordenadas
                x = (x_percent / 100) * label_width
                y = (y_percent / 100) * label_height
                w = (w_percent / 100) * label_width
                h = (h_percent / 100) * label_height
                
                # Define fonte
                font_name = "Helvetica-Bold" if negrito else "Helvetica"
                
                if tipo == 'nome':
                    c.setFont(font_name, fonte)
                    max_chars = int(w / (fonte * 0.5))
                    display_text = product_name[:max_chars-3] + "..." if len(product_name) > max_chars else product_name
                    if alinhamento == 'centro':
                        c.drawCentredString(x, y, display_text)
                    elif alinhamento == 'esquerda':
                        c.drawString(x - w/2, y, display_text)
                    else:
                        c.drawRightString(x + w/2, y, display_text)
                
                elif tipo == 'preco':
                    c.setFont(font_name, fonte)
                    price_str = f"R$ {preco:,.2f}".replace(",", "X").replace(".", ",").replace("X", ".")
                    if alinhamento == 'centro':
                        c.drawCentredString(x, y, price_str)
                    elif alinhamento == 'esquerda':
                        c.drawString(x - w/2, y, price_str)
                    else:
                        c.drawRightString(x + w/2, y, price_str)
                
                elif tipo == 'preco_antigo':
                    c.setFont(font_name, fonte)
                    price_str = f"De: R$ {preco_antigo:,.2f}".replace(",", "X").replace(".", ",").replace("X", ".")
                    if elem.get('riscado', False):
                        text_width = c.stringWidth(price_str, font_name, fonte)
                        text_x = x - text_width/2 if alinhamento == 'centro' else x
                        c.line(text_x, y + fonte/3, text_x + text_width, y + fonte/3)
                    c.drawCentredString(x, y, price_str)
                
                elif tipo == 'codigo_barras':
                    if barcode_value and barcode_value.strip():
                        try:
                            # EAN13 é o padrão de varejo. Se o código tiver letras/formato incompatível,
                            # usa CODE128 automaticamente para manter leitura por scanner comum.
                            bar_height = max(10*mm, (h_percent / 100) * label_height * 0.78)
                            max_bar_width = max(18*mm, w * 0.92)
                            barcode_y = y - bar_height/2
                            if str(barcode_kind).upper() == 'EAN13':
                                from reportlab.graphics.barcode import createBarcodeDrawing
                                from reportlab.graphics import renderPDF
                                d = createBarcodeDrawing('EAN13', value=barcode_value, barHeight=bar_height, humanReadable=False)
                                scale = 1.0
                                if d.width > max_bar_width:
                                    scale = max_bar_width / float(d.width)
                                barcode_x = x - (d.width * scale) / 2
                                c.saveState()
                                c.translate(barcode_x, barcode_y)
                                c.scale(scale, 1.0)
                                renderPDF.draw(d, c, 0, 0)
                                c.restoreState()
                            else:
                                bar_width = 0.42 * mm
                                barcode = code128.Code128(barcode_value, barWidth=bar_width, barHeight=bar_height, humanReadable=False)
                                if barcode.width > max_bar_width and len(barcode_value) > 0:
                                    ratio = max_bar_width / float(barcode.width)
                                    bar_width = max(0.22*mm, bar_width * ratio)
                                    barcode = code128.Code128(barcode_value, barWidth=bar_width, barHeight=bar_height, humanReadable=False)
                                barcode_x = x - barcode.width / 2
                                barcode.humanReadable = False
                                barcode.drawOn(c, barcode_x, barcode_y)

                            if elem.get('mostrar_texto', True):
                                c.setFont("Helvetica-Bold", 7)
                                c.drawCentredString(x, barcode_y - 2.2*mm, barcode_value)
                        except Exception:
                            c.setFont("Helvetica", 7)
                            c.drawCentredString(x, y, barcode_value)
                
                elif tipo == 'codigo_barras_texto':
                    c.setFont(font_name, fonte)
                    texto_codigo = barcode_value or codigo_interno
                    if alinhamento == 'centro':
                        c.drawCentredString(x, y, texto_codigo)
                    elif alinhamento == 'esquerda':
                        c.drawString(x - w/2, y, texto_codigo)
                    else:
                        c.drawRightString(x + w/2, y, texto_codigo)

                elif tipo == 'categoria':
                    c.setFont(font_name, fonte)
                    c.drawCentredString(x, y, categoria)
                
                elif tipo == 'codigo':
                    c.setFont(font_name, fonte)
                    c.drawCentredString(x, y, f"Cód: {codigo_interno}")
                
                elif tipo == 'tamanho':
                    c.setFont(font_name, fonte)
                    c.drawCentredString(x, y, f"Tam: {tamanho}" if tamanho else "")
                
                elif tipo == 'data':
                    c.setFont(font_name, fonte)
                    data_str = datetime.datetime.now().strftime("%d/%m/%Y")
                    c.drawCentredString(x, y, data_str)
                
                elif tipo == 'texto_fixo':
                    c.setFont(font_name, fonte)
                    texto = elem.get('texto', '')
                    c.drawCentredString(x, y, texto)
                
                elif tipo == 'qrcode':
                    try:
                        from reportlab.graphics.barcode import qr
                        from reportlab.graphics.shapes import Drawing
                        from reportlab.graphics import renderPDF
                        
                        qr_size = min(w, h) * 0.9
                        qr_code = qr.QrCodeWidget(barcode_value or codigo_interno)
                        bounds = qr_code.getBounds()
                        qr_width = bounds[2] - bounds[0]
                        qr_height = bounds[3] - bounds[1]
                        d = Drawing(qr_size, qr_size, transform=[qr_size/qr_width, 0, 0, qr_size/qr_height, 0, 0])
                        d.add(qr_code)
                        renderPDF.draw(d, c, x - qr_size/2, y - qr_size/2)
                    except Exception:
                        pass
                elif tipo == 'linha':
                    c.setLineWidth(max(0.5, fonte / 10))
                    c.line(x - w/2, y, x + w/2, y)

                elif tipo == 'retangulo':
                    c.setLineWidth(max(0.5, fonte / 12))
                    c.rect(x - w/2, y - h/2, w, h, stroke=1, fill=0)
            
            # Nova página para próxima etiqueta
            if i < quantity - 1:
                c.showPage()
        
        c.save()
        
        # Retorna informações para impressão
        return {
            'filename': filename,
            'printer': printer_type,
            'bobina': bobina_type,
            'quantity': quantity,
            'label_width_mm': label_width / mm,
            'label_height_mm': label_height / mm
        }
    
    except Exception as e:
        messagebox.showerror("Erro", f"Falha ao gerar o PDF das etiquetas: {e}")
        return None


def print_labels_to_printer(pdf_info):
    """
    Envia o PDF para a impressora de etiquetas.
    Suporta impressão direta via driver do Windows ou comandos de sistema.
    
    Args:
        pdf_info: Dicionário retornado por generate_product_labels_pdf
    """
    import subprocess
    import platform
    from tkinter import messagebox
    import os
    
    if not pdf_info:
        return False
    
    filename = pdf_info['filename']
    printer = pdf_info['printer']
    
    try:
        system = platform.system()
        
        if system == "Windows":
            # Tenta usar win32print para impressão direta
            try:
                import win32print
                import win32api
                
                # Lista impressoras disponíveis
                printers = [p[2] for p in win32print.EnumPrinters(win32print.PRINTER_ENUM_LOCAL | win32print.PRINTER_ENUM_CONNECTIONS)]
                
                # Procura a impressora pelo nome
                target_printer = None
                for p in printers:
                    if printer.lower() in p.lower():
                        target_printer = p
                        break
                
                if target_printer:
                    win32api.ShellExecute(0, "print", filename, f'/d:"{target_printer}"', ".", 0)
                    return True
            except ImportError:
                pass
            
            # Fallback: abre com programa padrão de PDF
            os.startfile(filename, "print")
            return True
            
        elif system == "Linux":
            # No Linux, usa lp ou lpr
            try:
                subprocess.run(["lp", "-d", printer, filename], check=True)
                return True
            except:
                subprocess.run(["lpr", "-P", printer, filename], check=True)
                return True
                
        elif system == "Darwin":  # macOS
            subprocess.run(["lp", "-d", printer, filename], check=True)
            return True
        else:
            # Fallback: abre o arquivo
            os.startfile(filename) if hasattr(os, 'startfile') else subprocess.run(["xdg-open", filename])
            return True
            
    except Exception as e:
        messagebox.showwarning("Aviso", f"Não foi possível enviar diretamente para a impressora.\n\nO arquivo PDF foi gerado: {filename}\n\nAbra o arquivo e imprima manualmente.")
        # Tenta abrir o arquivo para impressão manual
        try:
            if platform.system() == "Windows":
                os.startfile(filename)
            else:
                subprocess.run(["xdg-open", filename])
        except:
            pass
        return False


