# ETIQUETAS: IMPRESSÃO PELA IMPRESSORA CONFIGURADA NO SISTEMA
# ═══════════════════════════════════════════════════════════════════════════════
LABEL_CONFIGURED_PRINTER_OPTION = "Usar impressora das Configurações do Sistema"
LABEL_OWN_PRINTER_OPTION = "Usar impressora própria das Etiquetas"


def _label_get_own_printer_config_path():
    """Retorna o arquivo próprio da impressora das etiquetas, independente da impressora de cupom."""
    try:
        base = globals().get('PERSISTENCE_DIR') or globals().get('DATA_DIR') or os.getcwd()
        return os.path.join(base, 'label_printer_config.json')
    except Exception:
        return os.path.join(os.getcwd(), 'label_printer_config.json')


def _label_load_own_printer_config():
    """Carrega a configuração própria da impressora de etiquetas."""
    caminhos = []
    try:
        caminhos.append(_label_get_own_printer_config_path())
    except Exception:
        pass
    try:
        caminhos.append(os.path.join(os.getcwd(), 'label_printer_config.json'))
    except Exception:
        pass
    try:
        caminhos.append(os.path.join(os.path.dirname(os.path.abspath(__file__)), 'label_printer_config.json'))
    except Exception:
        pass

    vistos = set()
    for caminho in caminhos:
        if not caminho or caminho in vistos:
            continue
        vistos.add(caminho)
        try:
            if os.path.exists(caminho):
                with open(caminho, 'r', encoding='utf-8') as f:
                    cfg = json.load(f)
                if isinstance(cfg, dict):
                    cfg['_config_path'] = caminho
                    return cfg
        except Exception:
            continue
    return {}


def _label_own_printer_display_name(config=None):
    """Nome amigável da impressora própria de etiquetas."""
    cfg = config if isinstance(config, dict) else _label_load_own_printer_config()
    if not cfg:
        return 'Nenhuma impressora própria de etiquetas configurada'
    tipo = str(cfg.get('tipo_conexao') or 'windows_raw')
    endereco = str(cfg.get('impressora_windows') or cfg.get('endereco') or cfg.get('porta_bluetooth') or '').strip()
    nome = str(cfg.get('nome') or 'Impressora de Etiquetas').strip()
    if endereco:
        return f"{nome} - {endereco} ({tipo})"
    return f"{nome} ({tipo})"



