# ETIQUETAS: MOTOR AVANÇADO DE CARACTERES, SÍMBOLOS, CÓDIGO DE BARRAS, QR E IMAGEM
# AJUSTE: Código de barras padrão EAN13 com dígito verificador e fallback CODE128
# ═══════════════════════════════════════════════════════════════════════════════

LABEL_ADVANCED_PRINT_DEFAULTS = {
    'label_charset_mode': 'auto_maximo',          # auto_maximo, utf8, cp850, cp1252, ascii_seguro
    'label_text_sanitize_mode': 'preservar',      # preservar, ascii_seguro
    'label_technology_mode': 'auto',              # auto, escpos, driver_windows_pdf
    'label_barcode_enabled': True,
    'label_barcode_type': 'EAN13',
    'label_barcode_height': 100,
    'label_barcode_width': 3,
    'label_barcode_reader_mode': True,
    'label_barcode_human_readable': True,
    'label_qrcode_enabled': True,
    'label_qrcode_size': 6,
    'label_qrcode_error': 'M',
    'label_image_enabled': False,
    'label_image_path': '',
    'label_image_width': 384,
    'label_print_text': True,
    'label_print_price': True,
    'label_print_product_code': True,
}


def _label_get_adv(cfg, key):
    try:
        if isinstance(cfg, dict) and key in cfg:
            return cfg.get(key)
    except Exception:
        pass
    return LABEL_ADVANCED_PRINT_DEFAULTS.get(key)


def _label_bool_adv(cfg, key):
    val = _label_get_adv(cfg, key)
    if isinstance(val, str):
        return val.strip().lower() in ('1', 'true', 'sim', 'yes', 'on', 's')
    return bool(val)


def _label_int_adv(cfg, key, default=0, min_value=None, max_value=None):
    try:
        value = int(_label_get_adv(cfg, key))
    except Exception:
        value = int(default)
    if min_value is not None:
        value = max(int(min_value), value)
    if max_value is not None:
        value = min(int(max_value), value)
    return value


def _label_normalize_special_text(text, cfg=None):
    """Normaliza texto conforme modo escolhido para etiqueta."""
    import unicodedata
    s = str(text or '')
    s = (s.replace('\\\\r\\\\n', '\n').replace('\\\\n', '\n').replace('\\\\r', '\n')
           .replace('\\r\\n', '\n').replace('\\r', '\n'))
    # Corrige textos que já chegaram quebrados com �
    fixes = {
        'N�O': 'NÃO', 'n�o': 'não', 'Endere�o': 'Endereço', 'ENDERE�O': 'ENDEREÇO',
        'DERIVA�AO': 'DERIVAÇÃO', 'deriva�ao': 'derivação', 'Configura��o': 'Configuração',
        'CUPOM N�O FISCAL': 'CUPOM NÃO FISCAL', 'C�digo': 'Código', 'c�digo': 'código',
        'Pre�o': 'Preço', 'pre�o': 'preço', 'Descri��o': 'Descrição', 'descri��o': 'descrição',
    }
    for bad, good in fixes.items():
        s = s.replace(bad, good)
    mode = str(_label_get_adv(cfg or {}, 'label_text_sanitize_mode') or 'preservar').lower()
    charset = str(_label_get_adv(cfg or {}, 'label_charset_mode') or 'auto_maximo').lower()
    if mode == 'ascii_seguro' or charset == 'ascii_seguro':
        mapa = {
            'ç':'c','Ç':'C','ã':'a','Ã':'A','õ':'o','Õ':'O','á':'a','Á':'A','à':'a','À':'A','â':'a','Â':'A','ä':'a','Ä':'A',
            'é':'e','É':'E','ê':'e','Ê':'E','è':'e','È':'E','ë':'e','Ë':'E','í':'i','Í':'I','ì':'i','Ì':'I','î':'i','Î':'I',
            'ó':'o','Ó':'O','ò':'o','Ò':'O','ô':'o','Ô':'O','ö':'o','Ö':'O','ú':'u','Ú':'U','ù':'u','Ù':'U','ü':'u','Ü':'U',
            'ñ':'n','Ñ':'N','º':'o','ª':'a','°':'o','–':'-','—':'-','“':'"','”':'"','‘':"'",'’':"'",'•':'*','→':'->','←':'<-','✓':'v','✔':'v','✗':'x','×':'x','®':'(R)','©':'(C)','™':'TM','€':'EUR','₢':'Cr$',
        }
        s = ''.join(mapa.get(ch, ch) for ch in s)
        s = unicodedata.normalize('NFKD', s)
        s = ''.join(ch for ch in s if not unicodedata.combining(ch))
        s = s.encode('ascii', errors='ignore').decode('ascii')
    return s


def _label_pick_encoding(cfg):
    mode = str(_label_get_adv(cfg, 'label_charset_mode') or 'auto_maximo').lower()
    if mode in ('utf8', 'utf-8'):
        return 'utf-8'
    if mode == 'cp850':
        return 'cp850'
    if mode == 'cp1252':
        return 'cp1252'
    if mode == 'ascii_seguro':
        return 'ascii'
    # Auto máximo: tenta preservar símbolos/acentos; se a impressora não aceitar, o motor já faz fallback.
    return 'utf-8'



def _label_ean13_check_digit(first12):
    """Calcula o dígito verificador EAN13 para os 12 primeiros dígitos."""
    import re
    digits = re.sub(r'\D+', '', str(first12 or ''))[:12]
    digits = digits.zfill(12)
    soma = 0
    for idx, ch in enumerate(digits):
        n = int(ch)
        soma += n if idx % 2 == 0 else n * 3
    return str((10 - (soma % 10)) % 10)


def _label_is_valid_ean13(code):
    """Confere se um EAN13 possui 13 números e dígito verificador correto."""
    import re
    digits = re.sub(r'\D+', '', str(code or ''))
    return len(digits) == 13 and digits[-1] == _label_ean13_check_digit(digits[:12])


def _label_make_ean13_from_digits(digits, fallback='000000000001'):
    """
    Gera um EAN13 legível por leitor.
    - 13 dígitos válidos: mantém.
    - 13 dígitos inválidos: recalcula o último dígito.
    - 12 dígitos: calcula o 13º.
    - poucos dígitos/código interno: cria um EAN interno iniciado por 200.
    """
    import re
    d = re.sub(r'\D+', '', str(digits or ''))
    if not d:
        d = re.sub(r'\D+', '', str(fallback or ''))
    if len(d) >= 13:
        base = d[:12]
        candidate = d[:13]
        if _label_is_valid_ean13(candidate):
            return candidate
        return base + _label_ean13_check_digit(base)
    if len(d) == 12:
        return d + _label_ean13_check_digit(d)
    # Prefixo 200 é usado como código interno/local. Bom para etiquetas próprias da loja.
    base = '200' + (d or '1').zfill(9)[-9:]
    return base + _label_ean13_check_digit(base)


def _label_sanitize_barcode_data(data, fallback='000000000001', barcode_type='EAN13'):
    """Prepara o valor do código de barras para máxima leitura por leitor comum."""
    import unicodedata, re
    raw = str(data or '').strip()
    if not raw:
        raw = str(fallback or '000000000001').strip()
    raw = unicodedata.normalize('NFKD', raw)
    raw = ''.join(ch for ch in raw if not unicodedata.combining(ch))
    raw = raw.replace('\r', '').replace('\n', '').replace('\t', '')
    btype = str(barcode_type or 'EAN13').upper().replace('-', '').replace(' ', '')
    digits = re.sub(r'\D+', '', raw)
    if btype in ('EAN13', 'EAN13AUTO', 'AUTO'):
        return _label_make_ean13_from_digits(digits, fallback=fallback)
    if btype == 'EAN8':
        return ((digits or '00000000') + '0'*8)[:8]
    if btype in ('UPCA', 'UPCE'):
        size = 12 if btype == 'UPCA' else 8
        return ((digits or ('0'*size)) + '0'*size)[:size]
    safe = re.sub(r'[^A-Za-z0-9\-\.\/_ ]+', '', raw).strip().upper()
    safe = re.sub(r'\s+', '', safe)
    return safe[:64] or (digits[:64] if digits else '000000000001')


def _label_effective_barcode_value_and_type(data, fallback='000000000001', barcode_type='EAN13'):
    """
    Decide o tipo real a imprimir:
    - EAN13 quando o código é numérico, tem 12/13 dígitos ou é código interno numérico.
    - CODE128 quando o valor possui letras ou símbolos incompatíveis com EAN13.
    """
    import unicodedata, re
    raw = str(data or '').strip()
    if not raw:
        raw = str(fallback or '000000000001').strip()
    clean = unicodedata.normalize('NFKD', raw)
    clean = ''.join(ch for ch in clean if not unicodedata.combining(ch))
    clean = clean.replace('\r', '').replace('\n', '').replace('\t', '').strip()
    requested = str(barcode_type or 'EAN13').upper().replace('-', '').replace(' ', '')
    digits = re.sub(r'\D+', '', clean)
    has_letters = bool(re.search(r'[A-Za-z]', clean))

    if requested in ('EAN13', 'EAN13AUTO', 'AUTO'):
        if has_letters:
            return _label_sanitize_barcode_data(clean, fallback=fallback, barcode_type='CODE128'), 'CODE128'
        return _label_make_ean13_from_digits(digits, fallback=fallback), 'EAN13'

    if requested == 'EAN8':
        return _label_sanitize_barcode_data(clean, fallback=fallback, barcode_type='EAN8'), 'EAN8'

    return _label_sanitize_barcode_data(clean, fallback=fallback, barcode_type=requested), requested or 'CODE128'


def _label_barcode_type_name_from_config(cfg):
    return str(_label_get_adv(cfg, 'label_barcode_type') or 'EAN13').upper().replace('-', '').replace(' ', '')

def _label_barcode_type_from_name(name):
    name = str(name or 'EAN13').upper().replace('-', '').replace(' ', '')
    mapping = {
        'CODE128': BarcodeType.CODE128,
        'EAN13': BarcodeType.EAN13,
        'EAN13AUTO': BarcodeType.EAN13,
        'AUTO': BarcodeType.EAN13,
        'EAN8': BarcodeType.EAN8,
        'CODE39': BarcodeType.CODE39,
        'CODE93': BarcodeType.CODE93,
        'ITF': BarcodeType.ITF,
        'CODABAR': BarcodeType.CODABAR,
        'UPCA': BarcodeType.UPC_A,
        'UPCE': BarcodeType.UPC_E,
    }
    return mapping.get(name, BarcodeType.CODE128)

def _label_barcode_type_from_config(cfg):
    return _label_barcode_type_from_name(_label_barcode_type_name_from_config(cfg))


def _label_get_effective_product_barcode(product_data, cfg=None):
    try:
        base = str(product_data.get('codigo_barras') or product_data.get('codigo') or product_data.get('id') or '').strip()
        fallback = str(product_data.get('id') or product_data.get('codigo') or '000000000001')
        return _label_effective_barcode_value_and_type(base, fallback=fallback, barcode_type=_label_barcode_type_name_from_config(cfg or {}))
    except Exception:
        return '2000000000018', 'EAN13'


def _label_get_product_code(product_data):
    try:
        base = str(product_data.get('codigo_barras') or product_data.get('codigo') or product_data.get('id') or '').strip()
        fallback = str(product_data.get('id') or product_data.get('codigo') or '000000000001')
        value, _kind = _label_effective_barcode_value_and_type(base, fallback=fallback, barcode_type='EAN13')
        return value
    except Exception:
        return '2000000000018'

def _label_qr_error_from_config(cfg):
    name = str(_label_get_adv(cfg, 'label_qrcode_error') or 'M').upper()[:1]
    return {'L': QRErrorLevel.L, 'M': QRErrorLevel.M, 'Q': QRErrorLevel.Q, 'H': QRErrorLevel.H}.get(name, QRErrorLevel.M)


def _label_get_product_code(product_data):
    try:
        base = str(product_data.get('codigo_barras') or product_data.get('codigo') or product_data.get('id') or '').strip()
        fallback = str(product_data.get('id') or product_data.get('codigo') or '000000000001')
        return _label_sanitize_barcode_data(base, fallback=fallback, barcode_type='CODE128')
    except Exception:
        return '000000000001'


def _label_get_product_name(product_data):
    try:
        return str(product_data.get('nome') or product_data.get('descricao') or 'Produto').strip()
    except Exception:
        return 'Produto'


def _label_get_price_text(product_data):
    try:
        preco = float(product_data.get('preco') or product_data.get('preco_venda') or 0)
    except Exception:
        preco = 0.0
    return f"R$ {preco:,.2f}".replace(',', 'X').replace('.', ',').replace('X', '.')


def _label_print_thermal_advanced(cfg, product_data=None, quantity=1):
    """Imprime etiqueta térmica com recursos avançados: Unicode, símbolos, barcode, QR Code e imagem."""
    from tkinter import messagebox
    product_data = product_data or {}
    cfg = dict(cfg or {})
    cfg['habilitada'] = True
    # Força encoding do perfil quando for ESC/POS/COM/Bluetooth.
    cfg['encoding_personalizado'] = _label_pick_encoding(cfg)
    manager = ThermalPrinterManagerPDV(cfg)
    if not manager.is_enabled():
        messagebox.showerror('Erro de impressão', 'A impressora de etiquetas não pôde ser inicializada.\n\n' + str(manager.get_last_error() or ''), parent=None)
        return False
    printer = getattr(manager, '_printer', None)
    if printer is None:
        messagebox.showerror('Erro de impressão', 'A impressora de etiquetas não retornou conexão válida.', parent=None)
        return False

    width = 32
    try:
        width = max(24, int(manager.get_line_width()))
    except Exception:
        pass
    nome = _label_normalize_special_text(_label_get_product_name(product_data), cfg)
    codigo, codigo_tipo_efetivo = _label_get_effective_product_barcode(product_data, cfg)
    preco_txt = _label_normalize_special_text(_label_get_price_text(product_data), cfg)
    qtd = max(1, int(quantity or 1))
    image_path = str(_label_get_adv(cfg, 'label_image_path') or '').strip()

    try:
        with printer:
            # Aplica encoding máximo no objeto de impressão quando disponível.
            try:
                printer._encoding = _label_pick_encoding(cfg)
                if hasattr(printer, 'profile') and printer.profile:
                    printer.profile.default_encoding = printer._encoding
            except Exception:
                pass
            for _ in range(qtd):
                printer.init()
                try: printer.align(TextAlign.CENTER)
                except Exception: pass

                if _label_bool_adv(cfg, 'label_image_enabled') and image_path and os.path.exists(image_path):
                    try:
                        printer.image(image_path=image_path, width=_label_int_adv(cfg, 'label_image_width', 384, 80, 576), align=TextAlign.CENTER)
                        printer.feed(1)
                    except Exception:
                        pass

                if _label_bool_adv(cfg, 'label_print_text'):
                    # Quebra produto em linhas, sem destruir caracteres especiais quando o modo permitir.
                    restante = nome
                    while restante:
                        linha = restante[:width]
                        printer.textln(_label_center(linha, width))
                        restante = restante[width:]
                if _label_bool_adv(cfg, 'label_print_price'):
                    try: printer.bold_on(); printer.set_size(2, 2)
                    except Exception: pass
                    printer.textln(_label_center(preco_txt, max(12, width // 2)))
                    try: printer.set_size(1, 1); printer.bold_off()
                    except Exception: pass
                if codigo and _label_bool_adv(cfg, 'label_print_product_code'):
                    printer.textln(_label_center(_label_normalize_special_text(codigo, cfg)[:width], width))

                if codigo and _label_bool_adv(cfg, 'label_barcode_enabled'):
                    try:
                        printer.feed(1)
                        printer.barcode(
                            codigo,
                            barcode_type=_label_barcode_type_from_name(codigo_tipo_efetivo),
                            height=_label_int_adv(cfg, 'label_barcode_height', 100, 50, 255),
                            width=_label_int_adv(cfg, 'label_barcode_width', 3, 2, 6),
                            hri_position='below'
                        )
                    except Exception:
                        # fallback textual se a impressora/simulador não suportar barcode nativo
                        printer.textln(_label_center('[BARCODE] ' + codigo[:max(1, width-10)], width))

                if codigo and _label_bool_adv(cfg, 'label_qrcode_enabled'):
                    try:
                        printer.feed(1)
                        qr_data = str(codigo)
                        printer.qrcode(qr_data, size=_label_int_adv(cfg, 'label_qrcode_size', 6, 1, 16), error_level=_label_qr_error_from_config(cfg))
                    except Exception:
                        printer.textln(_label_center('[QR] ' + codigo[:max(1, width-5)], width))

                printer.feed(2)
                if cfg.get('corte_automatico', True):
                    try: printer.cut()
                    except Exception: pass
        return True
    except Exception as e:
        messagebox.showerror('Erro na impressão avançada de etiquetas', f'Falha ao imprimir etiqueta avançada.\n\nErro: {e}', parent=None)
        return False

def print_labels_using_own_label_printer(pdf_info, product_data=None, quantity=1):
    """Imprime etiquetas usando a configuração própria de impressora de etiquetas."""
    from tkinter import messagebox
    cfg = _label_load_own_printer_config()
    if not cfg:
        messagebox.showerror('Impressora de etiquetas não configurada', 'Nenhuma impressora própria de etiquetas foi configurada. Abra a aba Configuração Própria e clique em Configurar impressora de etiquetas.')
        return False
    if not cfg.get('habilitada', False):
        messagebox.showerror('Impressora de etiquetas desabilitada', 'A impressora própria das etiquetas está salva, mas não está habilitada.')
        return False

    win_printer = _label_extract_windows_printer_name_from_config(cfg)
    if win_printer and pdf_info:
        pdf_cfg = dict(pdf_info)
        pdf_cfg['printer'] = win_printer
        return print_labels_to_printer(pdf_cfg)

    try:
        return _label_print_thermal_advanced(cfg, product_data or {}, quantity)
    except Exception as e:
        messagebox.showerror('Erro na impressora própria de etiquetas', 'Não foi possível imprimir pela impressora própria das etiquetas.\n\n' + f'Configuração: {_label_own_printer_display_name(cfg)}\nErro: {e}')
        return False


def _label_get_system_printer_config_path():
    """Retorna o caminho provável do impressora_config.json usado pelo PDV."""
    try:
        base = globals().get('PERSISTENCE_DIR') or globals().get('DATA_DIR') or os.getcwd()
        return os.path.join(base, 'impressora_config.json')
    except Exception:
        return os.path.join(os.getcwd(), 'impressora_config.json')


def _label_load_system_printer_config():
    """Carrega a impressora salva em Menu Impressora > Configurar Impressora."""
    caminhos = []
    try:
        caminhos.append(_label_get_system_printer_config_path())
    except Exception:
        pass
    try:
        caminhos.append(os.path.join(os.getcwd(), 'impressora_config.json'))
    except Exception:
        pass
    try:
        caminhos.append(os.path.join(os.path.dirname(os.path.abspath(__file__)), 'impressora_config.json'))
    except Exception:
        pass

    vistos = set()
    for caminho in caminhos:
        if not caminho or caminho in vistos:
            continue
        vistos.add(caminho)
        try:
            if os.path.exists(caminho):
                with open(caminho, 'r', encoding='utf-8') as f:
                    cfg = json.load(f)
                if isinstance(cfg, dict):
                    cfg['_config_path'] = caminho
                    return cfg
        except Exception:
            continue
    return {}


def _label_configured_printer_display_name(config=None):
    """Nome amigável da impressora configurada no sistema."""
    cfg = config if isinstance(config, dict) else _label_load_system_printer_config()
    if not cfg:
        return 'Nenhuma impressora configurada'
    tipo = str(cfg.get('tipo_conexao') or 'windows_raw')
    endereco = str(cfg.get('impressora_windows') or cfg.get('endereco') or cfg.get('porta_bluetooth') or '').strip()
    nome = str(cfg.get('nome') or 'Impressora configurada').strip()
    if endereco:
        return f"{nome} - {endereco} ({tipo})"
    return f"{nome} ({tipo})"


def _label_extract_windows_printer_name_from_config(config):
    """Extrai o nome de impressora Windows quando a configuração permitir impressão via spooler/driver."""
    cfg = config or {}
    tipo = str(cfg.get('tipo_conexao') or '').lower()
    runtime = str(cfg.get('bluetooth_runtime_driver') or '').lower()
    endereco = str(cfg.get('impressora_windows') or cfg.get('endereco') or '').strip()
    if not endereco:
        return ''
    if tipo in ('windows_raw', 'windows_driver'):
        return endereco
    if tipo == 'bluetooth' and runtime in ('windows_raw', 'windows_driver'):
        return endereco
    if tipo == 'bluetooth' and not endereco.upper().startswith('COM'):
        return endereco
    return ''


def _label_center(text, width=32):
    text = str(text or '')
    if len(text) >= width:
        return text[:width]
    return text.center(width)


def _label_build_simple_thermal_label(product_data, quantity=1, width=32):
    """Monta etiqueta simples em texto para impressora térmica/COM/Bluetooth ESC/POS."""
    try:
        nome = str(product_data.get('nome') or 'Produto')
        preco = float(product_data.get('preco') or 0)
        codigo = str(product_data.get('codigo_barras') or product_data.get('codigo') or product_data.get('id') or '')
        categoria = str(product_data.get('categoria') or '')
    except Exception:
        nome, preco, codigo, categoria = 'Produto', 0.0, '', ''

    preco_txt = f"R$ {preco:,.2f}".replace(',', 'X').replace('.', ',').replace('X', '.')
    sep = '-' * width
    partes = []
    for _ in range(max(1, int(quantity or 1))):
        linhas = [sep]
        restante = nome.strip()
        while restante:
            linhas.append(_label_center(restante[:width], width))
            restante = restante[width:]
        if categoria:
            linhas.append(_label_center(categoria[:width], width))
        linhas.append(_label_center(preco_txt, width))
        if codigo:
            linhas.append(_label_center(codigo[:width], width))
        linhas.append(sep)
        linhas.append('')
        linhas.append('')
        partes.append('\n'.join(linhas))
    return '\n'.join(partes)


def print_labels_using_configured_printer(pdf_info, product_data=None, quantity=1):
    """Imprime etiquetas usando a impressora salva nas configurações gerais do PDV."""
    from tkinter import messagebox
    cfg = _label_load_system_printer_config()
    if not cfg:
        messagebox.showerror('Impressora não configurada', 'Nenhuma impressora foi encontrada em Menu Impressora > Configurar Impressora.')
        return False
    if not cfg.get('habilitada', False):
        messagebox.showerror('Impressora desabilitada', 'A impressora das configurações está salva, mas não está habilitada.')
        return False

    win_printer = _label_extract_windows_printer_name_from_config(cfg)
    if win_printer and pdf_info:
        pdf_cfg = dict(pdf_info)
        pdf_cfg['printer'] = win_printer
        return print_labels_to_printer(pdf_cfg)

    try:
        return _label_print_thermal_advanced(cfg, product_data or {}, quantity)
    except Exception as e:
        messagebox.showerror('Erro na impressão configurada', 'Não foi possível imprimir pela impressora configurada.\n\n' + f'Configuração: {_label_configured_printer_display_name(cfg)}\nErro: {e}')
        return False


def create_default_admin():
    AUDITORIA.processo("Verificando/criando usuário administrador padrão")
    users = load_users()
    users_modified = False
    
    # Garante que o usuário adm sempre exista e tenha permissão total '*'
    # A senha do adm pode ser modificada pelo usuário
    if "adm" not in users:
        users["adm"] = {
            "password": hash_password("9652"), 
            "nivel_acesso": "admin", 
            "permissoes": ["*"]
        }
        users_modified = True
    elif users["adm"].get("permissoes") != ["*"]:
        # Apenas garante que tenha permissão total, mas mantém a senha existente
        users["adm"]["permissoes"] = ["*"]
        users["adm"]["nivel_acesso"] = "admin"
        users_modified = True
    
    # Garante que o usuário phda sempre exista com senha fixa 4872 e permissão total '*'
    # A senha do phda NÃO pode ser modificada - sempre será resetada para 4872
    phda_password = hash_password("4872")
    if "phda" not in users or users["phda"].get("password") != phda_password or users["phda"].get("permissoes") != ["*"]:
        users["phda"] = {
            "password": phda_password, 
            "nivel_acesso": "admin", 
            "permissoes": ["*"]
        }
        users_modified = True
    
    # Remove o usuário 'admin' antigo se existir (migração para 'adm')
    if "admin" in users:
        del users["admin"]
        users_modified = True
    
    if users_modified:
        save_users(users)

logged_user = None
logged_user_data = None

def check_permission(permission_name):
    """
    Verifica se o usuário logado tem uma permissão específica.
    
    Suporta verificação hierárquica:
    - Permissão exata: 'vendas.aplicar_desconto'
    - Permissão de módulo: 'vendas.*' (concede todas as permissões de vendas)
    - Permissão total: '*' (concede todas as permissões)
    
    Também suporta fallback para permissões genéricas:
    
    Nota: Verificações de permissão são registradas na auditoria quando negadas.
    - Se 'vendas.aplicar_desconto_item' não existe, verifica 'vendas.aplicar_desconto'
    - Se 'produtos.editar_nome' não existe, verifica 'produtos.editar'
    
    Args:
        permission_name: Nome da permissão a verificar (ex: 'vendas.aplicar_desconto')
    
    Returns:
        bool: True se o usuário tem a permissão, False caso contrário
    """
    global logged_user, logged_user_data
    
    # Usuários adm e phda têm TODAS as permissões sem nenhum bloqueio
    if logged_user in ('adm', 'phda'):
        return True
    
    if not logged_user_data or "permissoes" not in logged_user_data:
        return False
    
    # IMPORTANTE: O campo 'nivel_acesso' NÃO concede acesso automático.
    # As permissões são verificadas EXCLUSIVAMENTE pela lista de permissões individuais.
    # Apenas os usuários 'adm' e 'phda' têm acesso total incondicional.
    
    user_perms = logged_user_data["permissoes"]
    
    # Se a lista de permissões está vazia, nega tudo
    if not user_perms:
        return False
    
    # Admin total (para usuários com permissão * na lista de permissões)
    if "*" in user_perms:
        return True
    
    # Verificação direta
    if permission_name in user_perms:
        return True
    
    # Verificação por módulo (ex: vendas.*)
    parts = permission_name.split('.')
    if len(parts) >= 1:
        module = parts[0]
        if f"{module}.*" in user_perms:
            return True
    
    # Verificação de aliases/compatibilidade entre permissões antigas e novas.
    # Ex.: vendas.devolucao <-> devolucoes.acessar; vendas.reimprimir_cupom <-> cupons.reimprimir.
    try:
        aliases = globals().get("PERMISSION_ALIASES", {}).get(permission_name, [])
        for alias_perm in aliases:
            if alias_perm in user_perms:
                return True
            alias_parts = alias_perm.split(".")
            if alias_parts and f"{alias_parts[0]}.*" in user_perms:
                return True
    except Exception:
        pass

    # Verificação hierárquica (fallback para permissões genéricas)
    # Ex: 'vendas.aplicar_desconto_item' -> verifica 'vendas.aplicar_desconto'
    # Ex: 'produtos.editar_nome' -> verifica 'produtos.editar'
    if len(parts) >= 2:
        action = parts[1]
        # Tenta encontrar uma permissão pai
        action_parts = action.split('_')
        for i in range(len(action_parts) - 1, 0, -1):
            parent_action = '_'.join(action_parts[:i])
            parent_perm = f"{parts[0]}.{parent_action}"
            if parent_perm in user_perms:
                return True
    
    # Registra na auditoria que a permissão foi NEGADA
    try:
        AUDITORIA.seguranca(f"Permissão NEGADA: '{permission_name}' para usuário '{logged_user}'")
    except Exception:
        pass
    return False


def check_permission_any(*permission_names):
    """
    Verifica se o usuário tem QUALQUER UMA das permissões listadas.
    
    Args:
        *permission_names: Lista de permissões a verificar
    
    Returns:
        bool: True se o usuário tem pelo menos uma das permissões
    """
    return any(check_permission(perm) for perm in permission_names)


def check_permission_all(*permission_names):
    """
    Verifica se o usuário tem TODAS as permissões listadas.
    
    Args:
        *permission_names: Lista de permissões a verificar
    
    Returns:
        bool: True se o usuário tem todas as permissões
    """
    return all(check_permission(perm) for perm in permission_names)


def get_user_permissions():
    """
    Retorna a lista de permissões do usuário logado.
    
    Returns:
        list: Lista de permissões do usuário
    """
    global logged_user_data
    if not logged_user_data:
        return []
    return logged_user_data.get('permissoes', [])

def authenticate_user():
    """Janela de login com lista de seleção de usuários"""
    users = load_users()
    
    # Criar janela de login como Toplevel do root existente
    login_win = tk.Toplevel()
    login_win._skip_auto_statusbar = True  # Impede StatusBar automática
    login_win.attributes('-alpha', 0)  # Torna completamente transparente
    login_win.withdraw()  # Oculta imediatamente para evitar flash
    login_win.title("Tela de Login - *[- Suporte (85) 98123-7727 -]*")
    login_win.resizable(False, False)  # Impede redimensionamento/maximização
    login_win.configure(bg='#f0f0f0')
    login_win.transient() # Mantém em cima da janela pai
    login_win.grab_set()   # Torna modal
    
    # Dimensões iguais à splash (~42% largura e ~58% altura)
    login_win.update_idletasks()
    screen_w = login_win.winfo_screenwidth()
    screen_h = login_win.winfo_screenheight()
    login_w = max(520, min(800, int(screen_w * 0.42)))
    login_h = max(420, min(680, int(screen_h * 0.58)))
    x = (screen_w - login_w) // 2
    y = (screen_h - login_h) // 2
    login_win.geometry(f"{login_w}x{login_h}+{x}+{y}")
    login_win.maxsize(login_w, login_h)
    
    # Variáveis
    username_var = tk.StringVar()
    password_var = tk.StringVar()
    user_names = sorted([u for u in users.keys()]) if users else []
    result = {"authenticated": False, "username": None}
    
    # Configuração visual da tela de login no mesmo padrão da Splash Screen
    BG_COLOR = '#0a0e27'
    BG_CARD = '#111638'
    BG_CARD_LIGHT = '#181d4a'
    BORDER_COLOR = '#252b52'
    PRIMARY_COLOR = '#4f8cff'
    PRIMARY_LIGHT = '#6ba3ff'
    SUCCESS_COLOR = '#00e676'
    TEXT_COLOR = '#e8ecf4'
    SECONDARY_TEXT = '#8892b0'
    MUTED_TEXT = '#5a6380'
    INPUT_BG = '#080c20'
    INPUT_BORDER = '#2d5fcf'

    login_win.configure(bg=BG_COLOR)

    # Fundo em canvas com efeito metálico/tecnológico semelhante à splash
    bg_canvas = tk.Canvas(login_win, bg=BG_COLOR, highlightthickness=0, bd=0)
    bg_canvas.pack(expand=True, fill='both')

    def _draw_login_background(event=None):
        try:
            bg_canvas.delete('bg_effect')
            w = max(1, bg_canvas.winfo_width())
            h = max(1, bg_canvas.winfo_height())
            # Gradiente vertical escuro
            steps = 80
            for i in range(steps):
                ratio = i / max(1, steps - 1)
                r = int(0x0a + (0x18 - 0x0a) * ratio)
                g = int(0x0e + (0x1d - 0x0e) * ratio)
                b = int(0x27 + (0x4a - 0x27) * ratio)
                color = f'#{r:02x}{g:02x}{b:02x}'
                y1 = int(h * i / steps)
                y2 = int(h * (i + 1) / steps)
                bg_canvas.create_rectangle(0, y1, w, y2, fill=color, outline=color, tags='bg_effect')
            # Linhas de brilho estilo splash
            for xline in range(-w, w * 2, max(90, int(w / 6))):
                bg_canvas.create_line(xline, 0, xline + int(w * 0.35), h, fill='#111c49', width=1, tags='bg_effect')
            bg_canvas.create_oval(-120, -120, 240, 240, outline='#1e40af', width=2, tags='bg_effect')
            bg_canvas.create_oval(w - 220, h - 220, w + 120, h + 120, outline='#123d5c', width=2, tags='bg_effect')
            bg_canvas.tag_lower('bg_effect')
        except Exception:
            pass

    bg_canvas.bind('<Configure>', _draw_login_background)

    # Card principal com borda no estilo da splash
    card_outer = tk.Frame(bg_canvas, bg=BORDER_COLOR, padx=2, pady=2)
    card_window_id = bg_canvas.create_window(login_w // 2, login_h // 2, window=card_outer, anchor='center',
                                             width=min(login_w - 70, 620),
                                             height=min(login_h - 35, 560))

    card_frame = tk.Frame(card_outer, bg=BG_CARD, padx=34, pady=18)
    card_frame.pack(expand=True, fill='both')

    # Cabeçalho com logo igual à splash
    header_frame = tk.Frame(card_frame, bg=BG_CARD)
    header_frame.pack(fill='x', pady=(0, 6))

    tk.Label(header_frame, text="⚛", font=("Segoe UI", 38, "bold"),
             bg=BG_CARD, fg=PRIMARY_COLOR).pack(side='left', padx=(0, 12))

    title_container = tk.Frame(header_frame, bg=BG_CARD)
    title_container.pack(side='left', fill='x', expand=True)

    tk.Label(title_container, text="PDV QUANTUM", font=("Segoe UI", 22, "bold"),
             bg=BG_CARD, fg=TEXT_COLOR, anchor='w').pack(fill='x')
    tk.Label(title_container, text="Supreme Ultra Professional", font=("Segoe UI", 10),
             bg=BG_CARD, fg=SECONDARY_TEXT, anchor='w').pack(fill='x')

    # Separador com brilho azul/verde
    sep_canvas = tk.Canvas(card_frame, height=3, bg=BG_CARD, highlightthickness=0, bd=0)
    sep_canvas.pack(fill='x', pady=(2, 8))
    def _draw_login_sep(event=None):
        try:
            sep_canvas.delete('all')
            w = max(1, sep_canvas.winfo_width())
            seg = 80
            for i in range(seg):
                ratio = i / max(1, seg - 1)
                if ratio < 0.55:
                    a = ratio / 0.55
                    r = int(0x2d + (0x4f - 0x2d) * a)
                    g = int(0x5f + (0x8c - 0x5f) * a)
                    b = 0xff
                else:
                    a = (ratio - 0.55) / 0.45
                    r = int(0x4f + (0x00 - 0x4f) * a)
                    g = int(0x8c + (0xe6 - 0x8c) * a)
                    b = int(0xff + (0x76 - 0xff) * a)
                color = f'#{r:02x}{g:02x}{b:02x}'
                sep_canvas.create_rectangle(int(w*i/seg), 0, int(w*(i+1)/seg), 3, fill=color, outline=color)
        except Exception:
            pass
    sep_canvas.bind('<Configure>', _draw_login_sep)

    # Texto de subtítulo removido conforme solicitado

    # Container para os campos
    fields_frame = tk.Frame(card_frame, bg=BG_CARD)
    fields_frame.pack(fill='x')

    # Estilo customizado para Combobox
    style = ttk.Style()
    style.configure("Login.TCombobox", padding=8)

    # Campo usuário
    tk.Label(fields_frame, text="USUÁRIO", font=("Segoe UI", 8, "bold"), bg=BG_CARD, fg=SECONDARY_TEXT).pack(anchor='w', padx=2)
    username_entry = ttk.Combobox(fields_frame, textvariable=username_var, values=user_names,
                                 font=("Segoe UI", 11), state="readonly", style="Login.TCombobox")
    username_entry.pack(fill='x', pady=(4, 12))
    if user_names: username_entry.current(0)

    # Campo senha
    tk.Label(fields_frame, text="SENHA", font=("Segoe UI", 8, "bold"), bg=BG_CARD, fg=SECONDARY_TEXT).pack(anchor='w', padx=2)
    password_entry = tk.Entry(fields_frame, textvariable=password_var, show="●", font=("Segoe UI", 15, "bold"),
                              relief='flat', bg=INPUT_BG, fg=TEXT_COLOR, insertbackground=PRIMARY_LIGHT,
                              highlightthickness=2, highlightbackground=BORDER_COLOR, highlightcolor=INPUT_BORDER)
    password_entry.pack(fill='x', ipady=7, pady=(4, 4))
    
    # Função de recuperação de senha
    def recuperar_senha():
        """Abre janela para recuperação/reset de senha do usuário"""
        username = username_var.get().strip()
        if not username:
            messagebox.showwarning("Aviso", "Selecione um usuário primeiro.", parent=login_win)
            return
        
        # Criar janela de recuperação
        recovery_win = tk.Toplevel(login_win)
        recovery_win.title("Recuperação de Senha")
        responsive_geometry(recovery_win, 420, 380)
        recovery_win.resizable(True, True)
        recovery_win.configure(bg='#f0f0f0')
        recovery_win.transient(login_win)
        recovery_win.grab_set()
        
        # Centralizar
        recovery_win.update_idletasks()
        rx = (recovery_win.winfo_screenwidth() // 2) - (420 // 2)
        ry = (recovery_win.winfo_screenheight() // 2) - (380 // 2)
        responsive_geometry(recovery_win, 420, 380)
        
        # Frame principal
        rec_frame = tk.Frame(recovery_win, bg='#f0f0f0', padx=30, pady=5)
        rec_frame.pack(expand=True, fill='both')
        
        # Título
        tk.Label(rec_frame, text="🔐 Recuperação de Senha", font=("Arial", 16, "bold"), bg='#f0f0f0', fg='#2c3e50').pack(pady=(0, 5))
        tk.Label(rec_frame, text=f"Usuário: {username}", font=("Arial", 11), bg='#f0f0f0', fg='#7f8c8d').pack(pady=(0, 15))
        
        # Instruções
        tk.Label(rec_frame, text="Para redefinir a senha, informe a senha mestre", font=("Segoe UI", 9), bg='#f0f0f0', fg='#555').pack(anchor='w')
        tk.Label(rec_frame, text="do sistema e defina uma nova senha.", font=("Segoe UI", 9), bg='#f0f0f0', fg='#555').pack(anchor='w', pady=(0, 10))
        
        # Campo senha mestre
        tk.Label(rec_frame, text="SENHA MESTRE DO SISTEMA", font=("Segoe UI", 9, "bold"), bg='#f0f0f0', fg='#7f8c8d').pack(anchor='w')
        master_pass_var = tk.StringVar()
        master_entry = tk.Entry(rec_frame, textvariable=master_pass_var, show="●", font=("Segoe UI", 11), relief='flat', highlightthickness=1)
        master_entry.pack(fill='x', ipady=4, pady=(0, 10))
        
        # Campo nova senha
        tk.Label(rec_frame, text="NOVA SENHA", font=("Segoe UI", 9, "bold"), bg='#f0f0f0', fg='#7f8c8d').pack(anchor='w')
        new_pass_var = tk.StringVar()
        new_pass_entry = tk.Entry(rec_frame, textvariable=new_pass_var, show="●", font=("Segoe UI", 11), relief='flat', highlightthickness=1)
        new_pass_entry.pack(fill='x', ipady=4, pady=(0, 10))
        
        # Campo confirmar nova senha
        tk.Label(rec_frame, text="CONFIRMAR NOVA SENHA", font=("Segoe UI", 9, "bold"), bg='#f0f0f0', fg='#7f8c8d').pack(anchor='w')
        confirm_pass_var = tk.StringVar()
        confirm_pass_entry = tk.Entry(rec_frame, textvariable=confirm_pass_var, show="●", font=("Segoe UI", 11), relief='flat', highlightthickness=1)
        confirm_pass_entry.pack(fill='x', ipady=4, pady=(0, 15))
        
        def executar_reset():
            """Executa o reset da senha após validações"""
            master_pass = master_pass_var.get()
            new_pass = new_pass_var.get()
            confirm_pass = confirm_pass_var.get()
            
            # Validações
            if not master_pass:
                messagebox.showerror("Erro", "Informe a senha mestre do sistema.", parent=recovery_win)
                master_entry.focus()
                return
            
            # Senha mestre padrão do sistema (pode ser alterada conforme necessário)
            # NOTA: Em produção, esta senha deve ser armazenada de forma segura
            SENHA_MESTRE = "2394"  # Mesma senha usada em outras funções administrativas do sistema
            
            if master_pass != SENHA_MESTRE:
                messagebox.showerror("Erro", "Senha mestre incorreta!\n\nContate o administrador do sistema.", parent=recovery_win)
                master_pass_var.set("")
                master_entry.focus()
                return
            
            if not new_pass:
                messagebox.showerror("Erro", "Informe a nova senha.", parent=recovery_win)
                new_pass_entry.focus()
                return
            
            if len(new_pass) < 3:
                messagebox.showerror("Erro", "A nova senha deve ter pelo menos 3 caracteres.", parent=recovery_win)
                new_pass_entry.focus()
                return
            
            if new_pass != confirm_pass:
                messagebox.showerror("Erro", "As senhas não coincidem!\n\nDigite a mesma senha nos dois campos.", parent=recovery_win)
                confirm_pass_var.set("")
                confirm_pass_entry.focus()
                return
            
            # Confirmação final
            if not messagebox.askyesno("Confirmar", f"Deseja realmente redefinir a senha do usuário '{username}'%s", parent=recovery_win):
                return
            
            try:
                # Carrega usuários, atualiza a senha e salva
                users_data = load_users()
                if username in users_data:
                    users_data[username]['password'] = hash_password(new_pass)
                    if save_users(users_data):
                        AUDITORIA.seguranca(f"Senha do usuário '{username}' redefinida via recuperação de senha")
                        messagebox.showinfo("Sucesso", f"Senha do usuário '{username}' redefinida com sucesso!\n\nVocê já pode fazer login com a nova senha.", parent=recovery_win)
                        recovery_win.destroy()
                        password_entry.focus()
                    else:
                        AUDITORIA.erro(f"Falha ao salvar nova senha do usuário '{username}'")
                        messagebox.showerror("Erro", "Falha ao salvar a nova senha.\nTente novamente.", parent=recovery_win)
                else:
                    AUDITORIA.seguranca(f"Tentativa de recuperação de senha para usuário inexistente: '{username}'")
                    messagebox.showerror("Erro", f"Usuário '{username}' não encontrado no sistema.", parent=recovery_win)
            except Exception as e:
                AUDITORIA.erro(f"Erro ao redefinir senha do usuário '{username}': {e}")
                messagebox.showerror("Erro", f"Erro ao redefinir senha:\n{str(e)}", parent=recovery_win)
        
        # Botões
        btn_rec_frame = tk.Frame(rec_frame, bg='#f0f0f0')
        btn_rec_frame.pack(fill='x', pady=(1, 0))
        
        tk.Button(btn_rec_frame, text="Redefinir Senha", command=executar_reset, bg='#27ae60', fg='white', 
                  font=("Arial", 10, "bold"), padx=15, pady=6, cursor='hand2').pack(side='left', padx=5)
        tk.Button(btn_rec_frame, text="Cancelar", command=recovery_win.destroy, bg='#95a5a6', fg='white', 
                  font=("Arial", 10), padx=15, pady=6, cursor='hand2').pack(side='left', padx=5)
        
        # Binds
        master_entry.bind("<Return>", lambda e: new_pass_entry.focus())
        new_pass_entry.bind("<Return>", lambda e: confirm_pass_entry.focus())
        confirm_pass_entry.bind("<Return>", lambda e: executar_reset())
        recovery_win.bind("<Escape>", lambda e: recovery_win.destroy())
        
        master_entry.focus()
    
    # Link "Esqueceu a senha?"
    forgot_link = tk.Label(fields_frame, text="Esqueceu a senha?", font=("Segoe UI", 9),
                           bg=BG_CARD, fg=PRIMARY_LIGHT, cursor='hand2')
    forgot_link.pack(anchor='e', pady=(0, 10))
    forgot_link.bind("<Button-1>", lambda e: recuperar_senha())
    
    def do_login():
        username = username_var.get().strip()
        password = password_var.get()
        if not username or not password:
            messagebox.showerror("Erro", "Preencha a senha.", parent=login_win)
            return
        if username in users and verify_password(password, users[username].get("password")):
            global logged_user, logged_user_data
            logged_user = username
            logged_user_data = users[logged_user]
            result["authenticated"] = True
            result["username"] = username
            # Registra login na auditoria
            AUDITORIA.set_usuario(username)
            AUDITORIA.seguranca(f"Login bem-sucedido do usuário '{username}'")
            login_win.destroy()
        else:
            # Registra tentativa de login falha na auditoria
            AUDITORIA.seguranca(f"Tentativa de login FALHA para usuário '{username}' - Senha incorreta")
            messagebox.showerror("Acesso Negado", "Senha incorreta.", parent=login_win)
            password_var.set("")
            password_entry.focus()
            
    # Função para sair da aplicação de forma segura
    def sair_aplicacao():
        try:
            login_win.grab_release()  # Libera o grab modal
            login_win.destroy()       # Fecha a janela de login
        except:
            pass
        finally:
            os._exit(0)  # Força o encerramento do processo
    
    # Botões
    btn_login = tk.Button(card_frame, text="✅ ENTRAR NO SISTEMA", command=do_login,
                          bg=PRIMARY_COLOR, fg='white', font=("Segoe UI", 11, "bold"),
                          relief='flat', cursor='hand2', activebackground=PRIMARY_LIGHT, activeforeground='white',
                          bd=0)
    btn_login.pack(fill='x', ipady=9, pady=(8, 8))

    btn_sair = tk.Button(card_frame, text="✖ Sair do Sistema", command=sair_aplicacao,
                         bg=BG_CARD_LIGHT, fg=SECONDARY_TEXT, font=("Segoe UI", 9, "bold"),
                         relief='flat', cursor='hand2', activebackground=BORDER_COLOR, activeforeground=TEXT_COLOR,
                         bd=0)
    btn_sair.pack(fill='x', ipady=6)

    tk.Label(card_frame, text=f"v{__version__}  •  Phoenix Eternal Edition",
             font=("Segoe UI", 8), bg=BG_CARD, fg=MUTED_TEXT).pack(fill='x', pady=(8, 0))

    # Ajusta o card sem cortar os botões inferiores.
    def _ajustar_layout_login(event=None):
        try:
            login_win.update_idletasks()
            req_w = card_outer.winfo_reqwidth()
            req_h = card_outer.winfo_reqheight()
            final_w = min(max(req_w, 480), min(login_w - 70, 620))
            # Mantém altura suficiente para exibir Entrar, Sair e rodapé.
            final_h = min(max(req_h + 24, 440), login_h - 35)
            center_x = login_w // 2
            center_y = login_h // 2
            bg_canvas.coords(card_window_id, center_x, center_y)
            bg_canvas.itemconfigure(card_window_id, width=final_w, height=final_h)
        except Exception:
            pass
    
    # Binds
    username_entry.bind("<<ComboboxSelected>>", lambda e: password_entry.focus())
    username_entry.bind("<Return>", lambda e: password_entry.focus())
    password_entry.bind("<Return>", lambda e: do_login())
    login_win.bind("<Escape>", lambda e: sair_aplicacao())
    try:
        bg_canvas.bind('<Configure>', _ajustar_layout_login, add='+')
        login_win.after_idle(_ajustar_layout_login)
    except Exception:
        pass
    
    # Exibe a janela somente após toda configuração estar pronta
    login_win.deiconify()
    login_win.attributes('-alpha', 1)  # Restaura opacidade
    
    # Foca no campo de senha após a janela ser exibida (usando after para garantir)
    login_win.after(100, lambda: password_entry.focus_set())
    
    login_win.wait_window()
    return result["authenticated"]



