# 4) Atualização criteriosa dos níveis.
def _expandir_permissoes_por_wildcard(permissoes):
    resultado = set()
    for perm in permissoes:
        if isinstance(perm, str) and perm.endswith(".*"):
            prefixo = perm[:-2] + "."
            for grupo in PERMISSION_GROUPS.values():
                for chave in grupo.keys():
                    if chave.startswith(prefixo):
                        resultado.add(chave)
            resultado.add(perm)
        else:
            resultado.add(perm)
    return sorted(resultado)

def _aplicar_revisao_permissoes_niveis():
    """Atualiza os níveis para contemplar funções adicionadas depois da criação original."""
    # Gerente: gestão operacional completa, incluindo novas telas de etiquetas,
    # devoluções, cupons, sincronização, integridade e banco.
    ROLES["gerente"]["permissions"] = sorted(set(ROLES["gerente"]["permissions"]) | {
        "devolucoes.*", "cupons.*", "etiquetas.*",
        "sistema.atualizacao_tempo_real", "sistema.sincronizacao_quantica",
        "sistema.otimizacao_abertura", "sistema.logs_auditoria",
        "sistema.diagnostico", "sistema.manter_cache",
        "banco.verificar_estrutura", "banco.criar_indices",
        "banco.configurar_conexao", "mesas.*",
        "permissoes.acessar", "permissoes.revisar_niveis",
        "permissoes.sincronizar_niveis", "permissoes.exportar_matriz",
    })

    # Supervisor: operação avançada de venda, devolução e auditoria operacional,
    # sem acesso destrutivo a estrutura do banco.
    ROLES["supervisor"]["permissions"] = sorted(set(ROLES["supervisor"]["permissions"]) | {
        "devolucoes.acessar", "devolucoes.buscar_venda", "devolucoes.selecionar_item",
        "devolucoes.editar_quantidade", "devolucoes.processar",
        "devolucoes.reembolso", "devolucoes.credito",
        "devolucoes.reabrir_carrinho", "devolucoes.imprimir_comprovante",
        "cupons.reimprimir", "cupons.visualizar", "cupons.exportar_pdf",
        "cupons.imprimir_termica", "cupons.imprimir_comprovante_devolucao",
        "etiquetas.acessar", "etiquetas.imprimir", "etiquetas.visualizar_pdf",
        "etiquetas.exportar_pdf", "etiquetas.selecionar_modelo",
        "sistema.atualizacao_tempo_real", "sistema.sincronizacao_quantica",
        "sistema.diagnostico", "mesas.acessar",
        "permissoes.acessar",
    })

    # Caixa: operação diária segura. Pode reimprimir, visualizar e imprimir cupom;
    # devolução completa continua fora por padrão para exigir supervisor/gerente.
    ROLES["caixa"]["permissions"] = sorted(set(ROLES["caixa"]["permissions"]) | {
        "cupons.reimprimir", "cupons.visualizar", "cupons.imprimir_termica",
        "devolucoes.acessar", "devolucoes.buscar_venda", "devolucoes.selecionar_item",
    })

    # Estoquista: produto, estoque, fornecedor, entrada e etiquetas completas.
    ROLES["estoquista"]["permissions"] = sorted(set(ROLES["estoquista"]["permissions"]) | {
        "produtos.etiquetas", "etiquetas.*",
        "sistema.atualizacao_tempo_real", "sistema.sincronizacao_quantica",
        "banco.verificar_estrutura",
    })

    # Remove permissões inexistentes de todos os níveis, exceto wildcard válido.
    todas = set()
    for grupo in PERMISSION_GROUPS.values():
        todas.update(grupo.keys())
    for role_key, role_data in ROLES.items():
        if role_key == "admin":
            role_data["permissions"] = ["*"]
            continue
        filtradas = []
        for perm in role_data.get("permissions", []):
            if perm == "*" or perm in todas or (isinstance(perm, str) and perm.endswith(".*")):
                filtradas.append(perm)
        role_data["permissions"] = sorted(set(filtradas))

_aplicar_revisao_permissoes_niveis()

def permissoes_efetivas_do_nivel(nivel_acesso):
    """Retorna permissões efetivas do nível, expandindo módulos com .*."""
    nivel = str(nivel_acesso or "caixa").lower()
    role = ROLES.get(nivel)
    if not role:
        role = ROLES.get("caixa", {"permissions": []})
    perms = role.get("permissions", [])
    if "*" in perms:
        return ["*"]
    return _expandir_permissoes_por_wildcard(perms)

def sincronizar_permissoes_usuario_com_nivel(username, user_data):
    """Adiciona permissões novas do nível ao usuário sem remover permissões personalizadas."""
    try:
        nivel = str(user_data.get("nivel_acesso", "caixa")).lower()
        if nivel not in ROLES or nivel == "admin":
            return False
        atuais = set(user_data.get("permissoes", []) or [])
        if "*" in atuais:
            return False
        efetivas = set(permissoes_efetivas_do_nivel(nivel))
        novas = efetivas - atuais
        if novas:
            user_data["permissoes"] = sorted(atuais | efetivas)
            user_data["permissoes_revisadas_em"] = "2026-04-27"
            return True
    except Exception:
        pass
    return False

def sincronizar_todos_usuarios_com_niveis(users_data, salvar=True):
    """Sincroniza usuários existentes para receber permissões de funções novas do respectivo nível."""
    alterou = False
    try:
        for username, user_data in (users_data or {}).items():
            if username in ("adm", "phda"):
                continue
            if sincronizar_permissoes_usuario_com_nivel(username, user_data):
                alterou = True
        if alterou and salvar and "_mysql_save_users" in globals():
            try:
                _mysql_save_users(users_data)
                print("[PERMISSÕES] Usuários existentes sincronizados com os níveis revisados.")
            except Exception as e:
                print(f"[PERMISSÕES] Aviso: não foi possível persistir sincronização automática: {e}")
    except Exception as e:
        print(f"[PERMISSÕES] Erro ao sincronizar usuários com níveis: {e}")
    return users_data



ALL_PERMISSIONS = []
for group in PERMISSION_GROUPS.values():
    ALL_PERMISSIONS.extend(group.keys())

PERMISSION_LABELS = {}
for group in PERMISSION_GROUPS.values():
    PERMISSION_LABELS.update(group)


class NetworkSettingsWindow(tk.Toplevel):
    def __init__(self, master):
        super().__init__(master)
        self.title("Configurações de Rede e Banco de Dados")
        self.state('zoomed')
        self.resizable(True, True)
        self.transient(master)
        self.grab_set()
        
        self.settings = load_network_settings()
        self.path_var = tk.StringVar(value=self.settings.get("data_path", DATA_DIR))
        
        # Carrega configurações atuais do MySQL a partir do config.ini
        _cfg_atual = get_mysql_config()
        self.mysql_host_var = tk.StringVar(value=_cfg_atual.get('host', '127.0.0.1'))
        self.mysql_port_var = tk.StringVar(value=str(_cfg_atual.get('port', 3306)))
        self.mysql_user_var = tk.StringVar(value=_cfg_atual.get('user', 'root'))
        self.mysql_pass_var = tk.StringVar(value=_cfg_atual.get('password', ''))
        self.mysql_db_var = tk.StringVar(value=_cfg_atual.get('database', 'pdv_quantum'))
        
        main_frame = ttk.Frame(self, padding=20)
        main_frame.pack(fill=BOTH, expand=YES)
        
        # ---- Seção: Pasta de Dados em Rede ----
        ttk.Label(main_frame, text="Configuração de Base de Dados em Rede", font=("Segoe UI", 12, "bold")).pack(pady=(0, 10))
        
        ttk.Label(main_frame, text="Caminho da Pasta de Dados:").pack(anchor=W)
        path_frame = ttk.Frame(main_frame)
        path_frame.pack(fill=X, pady=5)
        
        ttk.Entry(path_frame, textvariable=self.path_var).pack(side=LEFT, fill=X, expand=YES, padx=(0, 5))
        ttk.Button(path_frame, text="Procurar", command=self._browse_path).pack(side=RIGHT)
        
        info_text = "Para usar em rede:\n1. Compartilhe a pasta 'pdv_data' do servidor na rede.\n2. Nos clientes, aponte para o caminho de rede (ex: \\\\SERVIDOR\\pdv_data)."
        ttk.Label(main_frame, text=info_text, wraplength=450, foreground="gray").pack(pady=(5, 15))
        
        # ---- Seção: Configuração MySQL (config.ini) ----
        ttk.Separator(main_frame, orient='horizontal').pack(fill=X, pady=10)
        ttk.Label(main_frame, text="Configuração do MySQL (config.ini)", font=("Segoe UI", 12, "bold")).pack(pady=(5, 10))
        
        mysql_frame = ttk.Frame(main_frame)
        mysql_frame.pack(fill=X)
        mysql_frame.columnconfigure(1, weight=1)
        mysql_frame.columnconfigure(3, weight=1)
        
        # Linha 1: Host e Porta
        ttk.Label(mysql_frame, text="Host:").grid(row=0, column=0, sticky=W, padx=5, pady=4)
        ttk.Entry(mysql_frame, textvariable=self.mysql_host_var).grid(row=0, column=1, sticky=EW, padx=5, pady=4)
        ttk.Label(mysql_frame, text="Porta:").grid(row=0, column=2, sticky=W, padx=5, pady=4)
        ttk.Entry(mysql_frame, textvariable=self.mysql_port_var, width=8).grid(row=0, column=3, sticky=W, padx=5, pady=4)
        
        # Linha 2: Usuário e Senha
        ttk.Label(mysql_frame, text="Usuário:").grid(row=1, column=0, sticky=W, padx=5, pady=4)
        ttk.Entry(mysql_frame, textvariable=self.mysql_user_var).grid(row=1, column=1, sticky=EW, padx=5, pady=4)
        ttk.Label(mysql_frame, text="Senha:").grid(row=1, column=2, sticky=W, padx=5, pady=4)
        ttk.Entry(mysql_frame, textvariable=self.mysql_pass_var, show="\u2022").grid(row=1, column=3, sticky=EW, padx=5, pady=4)
        
        # Linha 3: Banco de Dados
        ttk.Label(mysql_frame, text="Banco de Dados:").grid(row=2, column=0, sticky=W, padx=5, pady=4)
        ttk.Entry(mysql_frame, textvariable=self.mysql_db_var).grid(row=2, column=1, columnspan=3, sticky=EW, padx=5, pady=4)
        
        # Botão Testar Conexão MySQL
        ttk.Button(main_frame, text="Testar Conexão MySQL", bootstyle="info", command=self._testar_mysql).pack(pady=(10, 5))
        
        # ---- Botões ----
        btn_frame = ttk.Frame(main_frame)
        btn_frame.pack(side=BOTTOM, fill=X)
        
        ttk.Button(btn_frame, text="Salvar e Reiniciar", bootstyle=SUCCESS, command=self._save).pack(side=RIGHT, padx=5)
        ttk.Button(btn_frame, text="Cancelar", bootstyle=SECONDARY, command=self.destroy).pack(side=RIGHT)

    def _browse_path(self):
        path = filedialog.askdirectory(initialdir=self.path_var.get())
        if path:
            self.path_var.set(path)

    def _testar_mysql(self):
        """Testa a conexão MySQL com os dados informados."""
        host = self.mysql_host_var.get().strip()
        port = self.mysql_port_var.get().strip()
        user = self.mysql_user_var.get().strip()
        password = self.mysql_pass_var.get()
        
        if not host or not port or not user:
            messagebox.showwarning("Aviso", "Preencha pelo menos Host, Porta e Usuário.", parent=self)
            return
        
        sucesso, msg = testar_conexao_mysql(host, port, user, password)
        
        if sucesso:
            messagebox.showinfo("Sucesso", "Conexão com o MySQL estabelecida com sucesso!", parent=self)
        else:
            messagebox.showerror("Erro de Conexão", f"Não foi possível conectar ao MySQL:\n\n{msg}", parent=self)

    def _save(self):
        # Salva configuração de pasta de dados
        new_path = self.path_var.get()
        if not os.path.exists(new_path):
            messagebox.showerror("Erro", "O caminho da pasta de dados não existe.", parent=self)
            return
        
        # Valida porta MySQL
        try:
            int(self.mysql_port_var.get().strip())
        except ValueError:
            messagebox.showerror("Erro", "A porta do MySQL deve ser um número válido.", parent=self)
            return
        
        # Salva configuração de rede
        self.settings["data_path"] = new_path
        save_network_settings(self.settings)
        
        # Salva configuração MySQL no config.ini
        salvar_config(
            self.mysql_host_var.get().strip(),
            self.mysql_port_var.get().strip(),
            self.mysql_user_var.get().strip(),
            self.mysql_pass_var.get(),
            self.mysql_db_var.get().strip()
        )
        
        messagebox.showinfo("Sucesso", "Configurações salvas! O sistema será reiniciado.", parent=self)
        os.execl(sys.executable, sys.executable, *sys.argv)

