def cfg_bool(valor, padrao=False):
    """
    Converte valores vindos do MySQL/JSON/Tkinter para booleano real.
    Corrige o problema clássico do Python onde bool('False') retorna True.
    """
    try:
        if valor is None:
            return bool(padrao)
        if isinstance(valor, bool):
            return valor
        if isinstance(valor, (int, float)):
            return valor != 0
        texto = str(valor).strip().lower()
        if texto in ('true', '1', 'sim', 's', 'yes', 'y', 'on', 'marcado'):
            return True
        if texto in ('false', '0', 'nao', 'não', 'n', 'no', 'off', 'desmarcado', ''):
            return False
        return bool(padrao)
    except Exception:
        return bool(padrao)

# --- Funções Auxiliares de Formatação e Conversão (Vírgula Decimal) ---

@lru_cache(maxsize=1024)
def format_br_currency(value):
    """Formata um valor float para moeda brasileira (R$ 1.234,56)."""
    try:
        # Tenta usar locale se configurado
        return locale.currency(value, symbol=True, grouping=True)
    except (locale.Error, AttributeError, TypeError):
        # Fallback manual
        try:
            return f"R$ {value:,.2f}".replace(".", "TEMP_DOT").replace(",", ".").replace("TEMP_DOT", ",")
        except (ValueError, TypeError):
            return "R$ --,--"

@lru_cache(maxsize=1024)
def format_br_float(value, precision=3):
    """Formata um valor float para string com vírgula decimal."""
    try:
        format_str = f"{{:,.{precision}f}}"
        return format_str.format(value).replace(".", "TEMP_DOT").replace(",", ".").replace("TEMP_DOT", ",")
    except (ValueError, TypeError):
        return "--,--"




# --- Unidade de medida do produto (corrige exibição para metro/litro/caixa/pacote/dúzia) ---
UNIDADES_MEDIDA_PRODUTO = {
    'unidade': {'label': 'unid.', 'label_curto': 'UN', 'suffix_preco': '', 'precisao': 0, 'inteiro': True, 'titulo': 'Quantidade (Unidades)'},
    'peso': {'label': 'kg', 'label_curto': 'KG', 'suffix_preco': '/kg', 'precisao': 3, 'inteiro': False, 'titulo': 'Peso (kg)'},
    'litro': {'label': 'L', 'label_curto': 'LT', 'suffix_preco': '/L', 'precisao': 3, 'inteiro': False, 'titulo': 'Quantidade (Litros)'},
    'caixa': {'label': 'cx', 'label_curto': 'CX', 'suffix_preco': '/cx', 'precisao': 0, 'inteiro': True, 'titulo': 'Quantidade (Caixas)'},
    'pacote': {'label': 'pct', 'label_curto': 'PCT', 'suffix_preco': '/pct', 'precisao': 0, 'inteiro': True, 'titulo': 'Quantidade (Pacotes)'},
    'metro': {'label': 'm', 'label_curto': 'MT', 'suffix_preco': '/m', 'precisao': 3, 'inteiro': False, 'titulo': 'Quantidade (Metros)'},
    'duzia': {'label': 'dz', 'label_curto': 'DZ', 'suffix_preco': '/dz', 'precisao': 0, 'inteiro': True, 'titulo': 'Quantidade (Dúzias)'},
}

def normalizar_tipo_produto(tipo):
    tipo = str(tipo or 'unidade').strip().lower()
    return tipo if tipo in UNIDADES_MEDIDA_PRODUTO else 'unidade'

def dados_unidade_produto(tipo):
    return UNIDADES_MEDIDA_PRODUTO[normalizar_tipo_produto(tipo)]

def sufixo_preco_produto(tipo):
    return dados_unidade_produto(tipo)['suffix_preco']

def formatar_quantidade_produto(valor, tipo, usar_label_curto=False):
    info = dados_unidade_produto(tipo)
    precisao = info['precisao']
    label = info['label_curto'] if usar_label_curto else info['label']
    valor = parse_br_float(valor)
    if valor is None:
        valor = 0.0
    if info['inteiro']:
        try:
            if float(valor).is_integer():
                valor_txt = format_br_float(valor, 0)
            else:
                valor_txt = format_br_float(valor, 3)
        except Exception:
            valor_txt = format_br_float(valor, 0)
    else:
        valor_txt = format_br_float(valor, precisao)
    return f"{valor_txt} {label}"

def formatar_estoque_produto(valor, tipo):
    return formatar_quantidade_produto(valor, tipo, usar_label_curto=False)

def formatar_preco_unitario_produto(valor, tipo, com_moeda=True):
    prefixo = 'R$ ' if com_moeda else ''
    return f"{prefixo}{format_br_float(parse_br_float(valor), 2)}{sufixo_preco_produto(tipo)}"

def get_nome_produto_com_tamanho(nome_produto, tamanho_id, tamanhos_dict=None):
    """
    Retorna o nome do produto concatenado com o tamanho, se houver.
    
    Args:
        nome_produto: Nome original do produto
        tamanho_id: ID do tamanho associado ao produto (pode ser None)
        tamanhos_dict: Dicionário de tamanhos (opcional, se não fornecido tenta carregar)
    
    Returns:
        Nome do produto com tamanho concatenado (ex: "Camiseta - G") ou nome original se não houver tamanho
    """
    if not tamanho_id:
        return nome_produto
    
    try:
        # Converte para string para garantir compatibilidade
        tamanho_id_str = str(tamanho_id)
        
        # Se não foi fornecido o dicionário de tamanhos, tenta carregar
        if tamanhos_dict is None:
            try:
                tamanhos_dict = _mysql_load_tamanhos()
            except Exception:
                return nome_produto
        
        # Busca o tamanho no dicionário
        tamanho_data = tamanhos_dict.get(tamanho_id_str)
        
        if tamanho_data:
            # Usa a sigla se disponível, senão usa o nome do tamanho
            sigla = tamanho_data.get('sigla', '').strip()
            nome_tamanho = tamanho_data.get('nome', '').strip()
            
            # Prioriza a sigla, mas usa o nome se a sigla estiver vazia
            tamanho_display = sigla if sigla else nome_tamanho
            
            if tamanho_display:
                return f"{nome_produto} - {tamanho_display}"
        
        return nome_produto
    except Exception:
        return nome_produto


USER_LOG_FILE = os.path.join(DATA_DIR, "user_log.json")
