def log_exclusion(tipo_registro, dados_excluidos, motivo=""):
    """
    Registra uma exclusao no log de exclusoes para auditoria.
    
    Args:
        tipo_registro: Tipo do registro excluido (ex: 'Transacao Caixa', 'Produto', 'Venda')
        dados_excluidos: Dicionario com os dados do registro que foi excluido
        motivo: Motivo opcional da exclusao
    """
    exclusion_entry = {
        "usuario": logged_user if logged_user else "Sistema",
        "tipo_registro": tipo_registro,
        "dados_excluidos": dados_excluidos,
        "motivo": motivo,
        "datahora": datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    }
    # Registra na auditoria global
    try:
        usuario_excl = logged_user if logged_user else "SISTEMA"
        motivo_str = f" | Motivo: {motivo}" if motivo else ""
        AUDITORIA.registrar(usuario_excl, "EXCLUSAO", f"Exclusão de {tipo_registro}{motivo_str} | Dados: {str(dados_excluidos)[:200]}")
    except Exception:
        pass
    try:
        if not os.path.exists(DATA_DIR):
            os.makedirs(DATA_DIR)
        exclusions = []
        if os.path.exists(EXCLUSIONS_LOG_FILE):
            with open(EXCLUSIONS_LOG_FILE, 'r', encoding='utf-8') as f:
                exclusions = json.load(f)
        exclusions.append(exclusion_entry)
        with open(EXCLUSIONS_LOG_FILE, 'w', encoding='utf-8') as f:
            json.dump(exclusions, f, indent=4, ensure_ascii=False)
    except Exception as e:
        AUDITORIA.erro(f"Erro ao registrar exclusão no log: {e}")
        print(f"Erro ao registrar exclusao: {e}")

