def log_user_action(acao, detalhes=""):
    # Registra na auditoria global SEMPRE (mesmo sem usuário logado)
    try:
        usuario_audit = logged_user if logged_user else "SISTEMA"
        msg_audit = f"{acao}"
        if detalhes:
            msg_audit += f" | {detalhes}"
        AUDITORIA.acao_usuario(acao, detalhes, usuario=usuario_audit)
    except Exception:
        pass
    
    if not logged_user:
        return
    log_entry = {
        "usuario": logged_user,
        "acao": acao,
        "detalhes": detalhes,
        "datahora": datetime.datetime.now().strftime("%Y-%m-%d %H:%M:%S")
    }
    def _async_log():
        try:
            if not os.path.exists(DATA_DIR): os.makedirs(DATA_DIR)
            logs = []
            if os.path.exists(USER_LOG_FILE):
                with open(USER_LOG_FILE, 'r', encoding='utf-8') as f: logs = json.load(f)
            logs.append(log_entry)
            with open(USER_LOG_FILE, 'w', encoding='utf-8') as f: json.dump(logs, f, indent=4, ensure_ascii=False)
        except: pass
    threading.Thread(target=_async_log, daemon=True).start()

@lru_cache(maxsize=2048)
def parse_br_float(value_str):
    """Converte uma string com vírgula decimal para float de forma robusta."""
    if value_str is None: return 0.0
    if isinstance(value_str, (int, float)): return float(value_str)
    
    try:
        # Remove símbolos de moeda e espaços
        s = str(value_str).replace('R$', '').replace(' ', '').strip()
        if not s: return 0.0
        
        # Lógica para detectar se o ponto é milhar ou decimal
        if ',' in s and '.' in s:
            # Se tem ambos, o último é o decimal
            if s.rfind(',') > s.rfind('.'):
                s = s.replace('.', '').replace(',', '.')
            else:
                s = s.replace(',', '')
        elif ',' in s:
            s = s.replace(',', '.')
            
        return float(s)
    except Exception:
        return 0.0

def calcular_preco_efetivo(produto, quantidade=1, config_data=None):
    """
    Calcula o preço efetivo de um produto considerando:
    1. Preço promocional (se estiver dentro do período de promoção)
    2. Preço de atacado (se a quantidade atingir o mínimo)
    3. Preço normal (caso contrário)
    
    Retorna uma tupla: (preco_unitario, tipo_preco, descricao)
    - tipo_preco: 'promocional', 'atacado', 'normal'
    """
    import datetime
    
    preco_normal = parse_br_float(produto.get('preco', 0.0))
    preco_atacado = parse_br_float(produto.get('preco_atacado', 0.0))
    preco_promocional = parse_br_float(produto.get('preco_promocional', 0.0))
    atacado_qtd_minima = parse_br_float(produto.get('atacado_qtd_minima', 10.0))
    # Verifica promocao_ativa aceitando múltiplos formatos (int, bool, string)
    _promo_ativa_raw = produto.get('promocao_ativa', False)
    promocao_ativa = _promo_ativa_raw in (1, True, '1', 'true', 'True') or _promo_ativa_raw is True
    promocao_inicio = produto.get('promocao_inicio', '').strip() if produto.get('promocao_inicio') else ''
    promocao_fim = produto.get('promocao_fim', '').strip() if produto.get('promocao_fim') else ''
    
    # Verifica se está em período de promoção
    # A promoção só é válida se: checkbox marcado E dentro do período de datas
    em_promocao = False
    if promocao_ativa and preco_promocional > 0 and promocao_inicio and promocao_fim:
        try:
            hoje = datetime.datetime.now().date()
            dt_inicio = datetime.datetime.strptime(promocao_inicio, '%d/%m/%Y').date()
            dt_fim = datetime.datetime.strptime(promocao_fim, '%d/%m/%Y').date()
            em_promocao = dt_inicio <= hoje <= dt_fim
        except (ValueError, TypeError):
            em_promocao = False
    
    # Prioridade: Promoção > Atacado > Normal
    # Promoção tem prioridade máxima
    if em_promocao and preco_promocional > 0:
        return (preco_promocional, 'promocional', f'PROMOÇÃO até {promocao_fim}')
    
    # Verifica se atinge quantidade mínima para atacado
    if preco_atacado > 0 and quantidade >= atacado_qtd_minima:
        return (preco_atacado, 'atacado', f'ATACADO ({int(atacado_qtd_minima)}+ itens)')
    
    # Preço normal
    return (preco_normal, 'normal', '')


def generate_unique_ean13(products_dict):
    """Gera um código EAN-13 único para produtos.
    
    O EAN-13 é composto por:
    - 3 dígitos: prefixo do país (789 para Brasil)
    - 4 dígitos: código da empresa (usamos 0001 como padrão)
    - 5 dígitos: código do produto (sequencial)
    - 1 dígito: dígito verificador
    
    Args:
        products_dict: Dicionário de produtos existentes para verificar unicidade
        
    Returns:
        str: Código EAN-13 válido e único
    """
    import random
    
    def calculate_ean13_check_digit(code_12):
        """Calcula o dígito verificador do EAN-13."""
        total = 0
        for i, digit in enumerate(code_12):
            if i % 2 == 0:
                total += int(digit)
            else:
                total += int(digit) * 3
        check_digit = (10 - (total % 10)) % 10
        return str(check_digit)
    
    # Coleta todos os códigos de barras existentes
    existing_codes = set()
    for prod_id, prod_data in products_dict.items():
        codigo = prod_data.get('codigo_barras', '')
        if codigo:
            existing_codes.add(codigo)
    
    # Prefixo Brasil + código empresa padrão
    prefix = "7890001"  # 789 (Brasil) + 0001 (empresa)
    
    # Tenta gerar um código único
    max_attempts = 100000
    for _ in range(max_attempts):
        # Gera 5 dígitos aleatórios para o código do produto
        product_code = str(random.randint(0, 99999)).zfill(5)
        code_12 = prefix + product_code
        
        # Calcula o dígito verificador
        check_digit = calculate_ean13_check_digit(code_12)
        full_ean13 = code_12 + check_digit
        
        # Verifica se é único
        if full_ean13 not in existing_codes:
            return full_ean13
    
    raise ValueError("Não foi possível gerar um código EAN-13 único após várias tentativas.")

