def _internal_save(filepath, data):
    """Lógica interna de salvamento (deve ser chamada dentro de um lock)."""
    try:
        AUDITORIA.banco_dados(f"Salvamento interno: {os.path.basename(filepath) if filepath else 'desconhecido'}")
    except Exception:
        pass
    if not os.path.exists(DATA_DIR): os.makedirs(DATA_DIR)
    
    # 1. Criar backup do arquivo atual
    if os.path.exists(filepath):
        try:
            shutil.copy2(filepath, filepath + ".bak")
        except: pass

    # 2. Gravar em arquivo temporário ÚNICO para esta thread/chamada
    # Usamos o ID da thread para evitar que threads diferentes tentem usar o mesmo .tmp
    temp_filepath = f"{filepath}.{threading.get_ident()}.tmp"
    
    try:
        with open(temp_filepath, 'w', encoding='utf-8') as f:
            json.dump(data, f, indent=4, ensure_ascii=False)
            f.flush()
            os.fsync(f.fileno()) # Garante que os dados foram para o disco

        # 3. Substituição atômica com retentativas
        max_retries = 10
        for attempt in range(max_retries):
            try:
                if os.path.exists(filepath):
                    os.replace(temp_filepath, filepath)
                else:
                    os.rename(temp_filepath, filepath)
                return True
            except (PermissionError, OSError):
                if attempt < max_retries - 1:
                    time.sleep(0.05)
                else: raise
    finally:
        # Limpeza de segurança do arquivo temporário se algo falhou
        if os.path.exists(temp_filepath):
            try: os.remove(temp_filepath)
            except: pass
    return False

