    def _atualizar_status_os(self):
        """Atualiza a barra de status inferior da OS."""
        try:
            cliente = "Consumidor Final"
            if hasattr(self, 'cliente_nome_var'):
                cliente = self.cliente_nome_var.get().strip() or "Consumidor Final"

            qtd_servicos = len(getattr(self, 'servicos_lista', []) or [])
            qtd_pecas = len(getattr(self, 'pecas_lista', []) or [])

            total = 0.0
            try:
                for servico in getattr(self, 'servicos_lista', []) or []:
                    total += float(servico.get('valor', 0) or 0)
                for peca in getattr(self, 'pecas_lista', []) or []:
                    qtd = float(peca.get('qtd', 0) or 0)
                    valor = float(peca.get('valor_unit', 0) or 0)
                    total += qtd * valor
                if hasattr(self, 'desconto_var'):
                    desconto = float(str(self.desconto_var.get()).replace(',', '.'))
                    total -= desconto
            except Exception:
                pass

            if hasattr(self, 'status_label'):
                self.status_label.config(
                    text=f"Cliente: {cliente} | Serviços: {qtd_servicos} | Peças: {qtd_pecas} | Total: R$ {max(total, 0):.2f}"
                )
        except Exception:
            pass

    def _selecionar_cliente(self):
        """Abre janela para selecionar cliente."""
        sel_win = tk.Toplevel(self.window)
        sel_win.title("Selecionar Cliente")
        responsive_geometry(sel_win, 550, 450)
        sel_win.transient(self.window)
        sel_win.grab_set()
        
        frame = ttk.Frame(sel_win, padding=10)
        frame.pack(fill=tk.BOTH, expand=True)
        
        # Busca
        search_frame = ttk.Frame(frame)
        search_frame.pack(fill=tk.X, pady=(0, 10))
        
        ttk.Label(search_frame, text="🔍 Buscar:").pack(side=tk.LEFT)
        search_var = tk.StringVar()
        search_entry = ttk.Entry(search_frame, textvariable=search_var, width=35)
        search_entry.pack(side=tk.LEFT, padx=5)
        
        # Lista
        cols = ('id', 'nome', 'telefone', 'cpf')
        tree = ttk.Treeview(frame, columns=cols, show='headings', height=15)
        tree.heading('id', text='ID')
        tree.heading('nome', text='Nome')
        tree.heading('telefone', text='Telefone')
        tree.heading('cpf', text='CPF/CNPJ')
        tree.column('id', width=50)
        tree.column('nome', width=220)
        tree.column('telefone', width=120)
        tree.column('cpf', width=130)
        
        scroll = ttk.Scrollbar(frame, orient=tk.VERTICAL, command=tree.yview)
        tree.configure(yscrollcommand=scroll.set)
        tree.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        scroll.pack(side=tk.RIGHT, fill=tk.Y)
        
        def carregar(filtro=''):
            tree.delete(*tree.get_children())
            for cid, cdata in self.app.customers.items():
                nome = cdata.get('nome', '')
                tel = cdata.get('telefone', '')
                cpf = cdata.get('cpf', '')
                if filtro.lower() in nome.lower() or filtro in tel or filtro in cpf:
                    tree.insert('', tk.END, values=(cid, nome, tel, cpf))
        
        def filtrar(*args):
            carregar(search_var.get())
        
        search_var.trace_add('write', filtrar)
        
        def confirmar():
            sel = tree.selection()
            if sel:
                item = tree.item(sel[0])
                cid = str(item['values'][0])
                self.cliente_id_var.set(cid)
                self.cliente_nome_var.set(item['values'][1])
                
                # Preencher telefone e endereço
                cliente = self.app.customers.get(cid, {})
                self.cliente_telefone_var.set(cliente.get('telefone', ''))
                self.cliente_endereco_var.set(cliente.get('endereco', ''))
                self.cliente_email_var.set(cliente.get('email', ''))
            sel_win.destroy()
        
        tree.bind('<Double-1>', lambda e: confirmar())
        
        btn_frame = ttk.Frame(frame)
        btn_frame.pack(fill=tk.X, pady=(10, 0))
        ttk.Button(btn_frame, text="✅ Selecionar", command=confirmar,
                   bootstyle="success").pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="❌ Cancelar", command=sel_win.destroy,
                   bootstyle="danger").pack(side=tk.RIGHT, padx=5)
        
        carregar()
        search_entry.focus_set()
    
    def _adicionar_servico(self):
        """Adiciona um serviço à lista."""
        add_win = tk.Toplevel(self.window)
        add_win.title("Adicionar Serviço")
        responsive_geometry(add_win, 450, 200)
        add_win.transient(self.window)
        add_win.grab_set()
        
        frame = ttk.Frame(add_win, padding=20)
        frame.pack(fill=tk.BOTH, expand=True)
        
        ttk.Label(frame, text="Serviço:").pack(anchor='w')
        
        # Combo com serviços cadastrados
        servicos_cadastrados = []
        if hasattr(self.app, 'servicos'):
            servicos_cadastrados = [f"{sid} - {sdata.get('nome', '')}" for sid, sdata in self.app.servicos.items()]
        
        servico_var = tk.StringVar()
        servico_combo = ttk.Combobox(frame, textvariable=servico_var, values=servicos_cadastrados, width=45)
        servico_combo.pack(fill=tk.X, pady=(5, 10))
        
        ttk.Label(frame, text="Valor (R$):").pack(anchor='w')
        valor_var = tk.StringVar(value="0.00")
        valor_entry = ttk.Entry(frame, textvariable=valor_var, width=20)
        valor_entry.pack(anchor='w', pady=(5, 15))
        
        def atualizar_valor(*args):
            sel = servico_var.get()
            if ' - ' in sel:
                sid = sel.split(' - ')[0]
                if hasattr(self.app, 'servicos') and sid in self.app.servicos:
                    preco = self.app.servicos[sid].get('preco', 0)
                    valor_var.set(f"{float(preco):.2f}")
        
        servico_combo.bind('<<ComboboxSelected>>', atualizar_valor)
        
        def confirmar():
            nome = servico_var.get()
            if ' - ' in nome:
                nome = nome.split(' - ', 1)[1]
            
            try:
                valor = float(valor_var.get().replace(',', '.'))
            except:
                valor = 0.0
            
            if nome:
                self.servicos_lista.append({'nome': nome, 'valor': valor})
                self._atualizar_lista_servicos()
                self._atualizar_total()
            add_win.destroy()
        
        btn_frame = ttk.Frame(frame)
        btn_frame.pack(fill=tk.X)
        ttk.Button(btn_frame, text="✅ Adicionar", command=confirmar,
                   bootstyle="success").pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="❌ Cancelar", command=add_win.destroy,
                   bootstyle="danger").pack(side=tk.RIGHT, padx=5)
    
    def _remover_servico(self):
        """Remove serviço selecionado."""
        sel = self.servicos_tree.selection()
        if sel:
            idx = self.servicos_tree.index(sel[0])
            if 0 <= idx < len(self.servicos_lista):
                del self.servicos_lista[idx]
                self._atualizar_lista_servicos()
                self._atualizar_total()
    
    def _atualizar_lista_servicos(self):
        """Atualiza a lista de serviços na treeview."""
        self.servicos_tree.delete(*self.servicos_tree.get_children())
        for s in self.servicos_lista:
            valor = float(s.get('valor', 0))
            self.servicos_tree.insert('', tk.END, values=(
                s.get('nome', ''),
                f"R$ {valor:.2f}"
            ))
    
    def _adicionar_peca(self):
        """Adiciona uma peça/produto à lista."""
        add_win = tk.Toplevel(self.window)
        add_win.title("Adicionar Peça/Produto")
        responsive_geometry(add_win, 500, 250)
        add_win.transient(self.window)
        add_win.grab_set()
        
        frame = ttk.Frame(add_win, padding=20)
        frame.pack(fill=tk.BOTH, expand=True)
        
        ttk.Label(frame, text="Produto:").pack(anchor='w')
        
        # Combo com produtos
        produtos_lista = [f"{pid} - {pdata.get('nome', '')}" for pid, pdata in self.app.products.items()]
        
        produto_var = tk.StringVar()
        produto_combo = ttk.Combobox(frame, textvariable=produto_var, values=produtos_lista, width=50)
        produto_combo.pack(fill=tk.X, pady=(5, 10))
        
        row = ttk.Frame(frame)
        row.pack(fill=tk.X, pady=(0, 10))
        
        ttk.Label(row, text="Quantidade:").pack(side=tk.LEFT)
        qtd_var = tk.StringVar(value="1")
        ttk.Entry(row, textvariable=qtd_var, width=10).pack(side=tk.LEFT, padx=(5, 20))
        
        ttk.Label(row, text="Valor Unit. (R$):").pack(side=tk.LEFT)
        valor_var = tk.StringVar(value="0.00")
        ttk.Entry(row, textvariable=valor_var, width=15).pack(side=tk.LEFT, padx=5)
        
        def atualizar_valor(*args):
            sel = produto_var.get()
            if ' - ' in sel:
                pid = sel.split(' - ')[0]
                if pid in self.app.products:
                    preco = self.app.products[pid].get('preco', 0)
                    valor_var.set(f"{float(preco):.2f}")
        
        produto_combo.bind('<<ComboboxSelected>>', atualizar_valor)
        
        def confirmar():
            nome = produto_var.get()
            if ' - ' in nome:
                nome = nome.split(' - ', 1)[1]
            
            try:
                qtd = int(qtd_var.get())
            except:
                qtd = 1
            
            try:
                valor_unit = float(valor_var.get().replace(',', '.'))
            except:
                valor_unit = 0.0
            
            if nome:
                self.pecas_lista.append({
                    'nome': nome,
                    'qtd': qtd,
                    'valor_unit': valor_unit,
                    'valor_total': qtd * valor_unit
                })
                self._atualizar_lista_pecas()
                self._atualizar_total()
            add_win.destroy()
        
        btn_frame = ttk.Frame(frame)
        btn_frame.pack(fill=tk.X, pady=(10, 0))
        ttk.Button(btn_frame, text="✅ Adicionar", command=confirmar,
                   bootstyle="success").pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="❌ Cancelar", command=add_win.destroy,
                   bootstyle="danger").pack(side=tk.RIGHT, padx=5)
    
    def _remover_peca(self):
        """Remove peça selecionada."""
        sel = self.pecas_tree.selection()
        if sel:
            idx = self.pecas_tree.index(sel[0])
            if 0 <= idx < len(self.pecas_lista):
                del self.pecas_lista[idx]
                self._atualizar_lista_pecas()
                self._atualizar_total()
    
    def _atualizar_lista_pecas(self):
        """Atualiza a lista de peças na treeview."""
        self.pecas_tree.delete(*self.pecas_tree.get_children())
        for p in self.pecas_lista:
            valor_unit = float(p.get('valor_unit', 0))
            valor_total = float(p.get('valor_total', 0))
            self.pecas_tree.insert('', tk.END, values=(
                p.get('nome', ''),
                p.get('qtd', 1),
                f"R$ {valor_unit:.2f}",
                f"R$ {valor_total:.2f}"
            ))
    
    def _atualizar_total(self):
        """Atualiza o valor total."""
        valor_servicos = sum(float(s.get('valor', 0)) for s in self.servicos_lista)
        valor_pecas = sum(float(p.get('valor_total', 0)) for p in self.pecas_lista)
        
        try:
            desconto = float(self.desconto_var.get().replace(',', '.'))
        except:
            desconto = 0.0
        
        total = valor_servicos + valor_pecas - desconto
        total_fmt = f"R$ {total:,.2f}".replace(',', 'X').replace('.', ',').replace('X', '.')
        self.total_label.config(text=f"TOTAL: {total_fmt}")
    
    def _salvar(self):
        """Salva a OS."""
        # Validar campos obrigatórios
        defeito = self.defeito_text.get('1.0', tk.END).strip()
        if not defeito:
            messagebox.showerror("Erro", "Informe o defeito relatado.", parent=self.window)
            return
        
        # Calcular valores
        valor_servicos = sum(float(s.get('valor', 0)) for s in self.servicos_lista)
        valor_pecas = sum(float(p.get('valor_total', 0)) for p in self.pecas_lista)
        
        try:
            desconto = float(self.desconto_var.get().replace(',', '.'))
        except:
            desconto = 0.0
        
        try:
            garantia = int(self.garantia_var.get())
        except:
            garantia = 90
        
        valor_total = valor_servicos + valor_pecas - desconto
        
        # Montar dados
        dados = {
            'cliente_id': self.cliente_id_var.get(),
            'cliente_nome': self.cliente_nome_var.get(),
            'cliente_telefone': self.cliente_telefone_var.get(),
            'cliente_email': self.cliente_email_var.get(),
            'cliente_endereco': self.cliente_endereco_var.get(),
            
            'tipo_equipamento': self.tipo_equip_var.get(),
            'marca': self.marca_var.get(),
            'modelo': self.modelo_var.get(),
            'numero_serie': self.serie_var.get(),
            'cor': self.cor_var.get(),
            'senha_equipamento': self.senha_equip_var.get(),
            'acessorios': self.acessorios_var.get(),
            
            'defeito_relatado': defeito,
            'defeito_constatado': self.defeito_constatado_text.get('1.0', tk.END).strip(),
            
            'status': self.status_var.get(),
            'prioridade': self.prioridade_var.get(),
            'tecnico_nome': self.tecnico_var.get(),
            'data_previsao': self.previsao_var.get(),
            
            'servicos': self.servicos_lista,
            'pecas': self.pecas_lista,
            
            'valor_servicos': valor_servicos,
            'valor_pecas': valor_pecas,
            'desconto': desconto,
            'valor_total': valor_total,
            
            'garantia_dias': garantia,
            
            'observacoes': self.obs_text.get('1.0', tk.END).strip(),
            'observacoes_internas': self.obs_interna_text.get('1.0', tk.END).strip(),
        }
        
        if self.editando:
            # Atualizar OS existente
            os_data = self.ordens[self.numero_os]
            for key, value in dados.items():
                os_data[key] = value
            
            os_data['data_ultima_alteracao'] = datetime.datetime.now().strftime('%Y-%m-%d %H:%M:%S')
            os_data['usuario_ultima_alteracao'] = logged_user
            
            if 'historico' not in os_data:
                os_data['historico'] = []
            os_data['historico'].append({
                'data': datetime.datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
                'usuario': logged_user,
                'acao': 'OS Atualizada',
                'detalhes': 'Dados atualizados'
            })
            
            self.ordens[self.numero_os] = os_data
            save_ordens_servico(self.ordens)
            
            log_user_action("Ordem de Serviço", f"OS #{self.numero_os} atualizada")
            messagebox.showinfo("Sucesso", f"OS #{self.numero_os} atualizada com sucesso!", parent=self.window)
        else:
            # Criar nova OS
            numero = get_proximo_numero_os()
            numero_str = f"{numero:06d}"
            
            os_data = {
                'numero': numero_str,
                'data_abertura': datetime.datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
                'data_conclusao': '',
                'data_entrega': '',
                'usuario_criacao': logged_user,
                'usuario_ultima_alteracao': logged_user,
                'data_ultima_alteracao': datetime.datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
                'valor_pago': 0.0,
                'valor_pendente': valor_total,
                'forma_pagamento': '',
                'data_garantia_fim': '',
                'historico': [{
                    'data': datetime.datetime.now().strftime('%Y-%m-%d %H:%M:%S'),
                    'usuario': logged_user,
                    'acao': 'OS Criada',
                    'detalhes': f'Ordem de Serviço #{numero_str} criada'
                }]
            }
            os_data.update(dados)
            
            self.ordens[numero_str] = os_data
            save_ordens_servico(self.ordens)
            salvar_numero_os(numero)
            
            log_user_action("Ordem de Serviço", f"OS #{numero_str} criada")
            messagebox.showinfo("Sucesso", f"OS #{numero_str} criada com sucesso!", parent=self.window)
            self.numero_os = numero_str
        
        if self.callback:
            self.callback()
        
        self.window.destroy()
    
    def _salvar_e_imprimir(self):
        """Salva e imprime a OS."""
        # Salva a OS e obtém os dados
        os_data = self._salvar_interno()
        
        if os_data:
            # Gera a impressão
            self._gerar_impressao_os(os_data)
        
        # Fecha a janela
        self.window.destroy()
    
