# 👕 Módulo de Cadastro de Tamanhos de Produtos
class CadastroTamanhosWindow(BaseCadastroWindow):
    """
    Janela para cadastro de tamanhos de produtos.
    Permite gerenciar tamanhos como P, M, G, GG, XG, números de calçados, etc.
    """
    def __init__(self, parent, data_dict, filepath, app=None):
        fields = {
            'nome': {'label': 'Nome do Tamanho', 'required': True, 'width': 30},
            'sigla': {'label': 'Sigla/Abreviação', 'width': 10},
            'ordem': {'label': 'Ordem de Exibição', 'type': 'spin_int', 'default': 0, 'from': 0, 'to': 999},
            'tipo': {'label': 'Tipo', 'type': 'combo', 'options': ['Roupa', 'Calçado', 'Acessório', 'Outro'], 'width': 20},
            'descricao': {'label': 'Descrição', 'type': 'text', 'height': 2, 'width': 50},
            'ativo': {'label': 'Ativo', 'type': 'check', 'default': True, 'check_text': 'Tamanho ativo para uso'}
        }
        tree_cols = ('id', 'nome', 'sigla', 'tipo', 'ordem', 'ativo')
        tree_headings = ('ID', 'Tamanho', 'Sigla', 'Tipo', 'Ordem', 'Ativo')
        super().__init__(parent, "👕 Cadastro de Tamanhos", data_dict, filepath, fields, tree_cols, tree_headings, log_action="Gerenciar Tamanhos", app=app)
        
        # Empacota o botão de exclusão (criado na BaseCadastroWindow)
        self.excluir_btn.pack(pady=2, fill=tk.X)
    
    def _get_unique_fields(self):
        """Define campos únicos para Tamanhos: Nome e Sigla devem ser únicos."""
        return [('nome', 'Nome do Tamanho'), ('sigla', 'Sigla')]

    def _get_item_values_for_tree(self, item_data):
        # Retorna os valores na ordem de tree_cols (exceto 'id')
        ativo = item_data.get('ativo', True)
        ativo_str = '✅ Sim' if ativo else '❌ Não'
        return [
            item_data.get('nome', ''),
            item_data.get('sigla', ''),
            item_data.get('tipo', ''),
            item_data.get('ordem', 0),
            ativo_str
        ]
    
    def _check_deletion_constraints(self, tamanho_id):
        """Verifica se o tamanho pode ser excluído."""
        # Verifica se há produtos usando este tamanho
        if hasattr(self, 'parent_app') and hasattr(self.parent_app, 'products'):
            for prod_data in self.parent_app.products.values():
                if str(prod_data.get('tamanho_id')) == str(tamanho_id):
                    tamanho_nome = self.data_dict.get(tamanho_id, {}).get('nome', tamanho_id)
                    messagebox.showerror(
                        "Bloqueado", 
                        f"O tamanho '{tamanho_nome}' está sendo usado pelo produto '{prod_data.get('nome', 'Desconhecido')}'.",
                        parent=self
                    )
                    return False
        return True


