        tree_headings = ('ID', 'Nome', 'Bandeira', 'Tipo', 'Taxa Débito (%)', 'Taxa Crédito (%)', 'Parcelas', 'Operadora')
        super().__init__(parent, "💳 Cadastro de Cartões", data_dict, filepath, fields, tree_cols, tree_headings, log_action="Gerenciar Cartões", app=app)
        
