    def enviar_whatsapp_cp(self):
        selected = self.tree.selection()
        if not selected:
            messagebox.showwarning("WhatsApp", "Selecione uma conta na lista.")
            return
        
        item_id = self.tree.item(selected[0])['values'][0]
        item_data = self.data_dict.get(str(item_id))
        if not item_data: return
        
        fornecedor_id = item_data.get('fornecedor_id', '')
        fornecedor_data = self.suppliers_dict.get(fornecedor_id, {})
        fornecedor_tel = fornecedor_data.get('telefone', '')
        
        if not fornecedor_tel:
            fornecedor_tel = simpledialog.askstring("WhatsApp", "Telefone do fornecedor (com DDD):")
            if not fornecedor_tel: return
            
        valor = format_br_currency(parse_br_float(item_data.get('valor', 0.0)))
        vencimento = item_data.get('data_vencimento', '')
        descricao = item_data.get('descricao', '')
        
        msg = f"*COMPROVANTE DE PAGAMENTO*\n\nOlá,\n\nPagamento referente à: {descricao}\nValor: {valor}\nVencimento: {vencimento}\n\nStatus: {item_data.get('status', 'Pendente')}"
        
        self.parent_app.send_whatsapp_message(fornecedor_tel, msg)

        self.btn_whatsapp = ttk.Button(self.form_buttons_frame, text="WhatsApp", command=self.enviar_whatsapp_cp, bootstyle="success")
        self.btn_whatsapp.pack(side="left", padx=5)
    

    def _get_item_values_for_tree(self, item_data):
        # Retorna os valores na ordem de tree_cols (exceto 'id')
        # tree_cols = ('id', 'descricao', 'valor', 'data_vencimento', 'fornecedor', 'centro_custo', 'status', 'pagamento')
        valor_str = format_br_currency(parse_br_float(item_data.get('valor', 0.0)))
        
        fornecedor_id = item_data.get('fornecedor_id', '')
        fornecedor_nome = self.suppliers_dict.get(fornecedor_id, {}).get('nome', fornecedor_id)
        
        # Obter nome do centro de custos
        centro_custo_id = item_data.get('centro_custo_id', '')
        centro_custo_nome = ''
        if centro_custo_id:
            centros = get_centros_custo_despesas()
            for c in centros:
                if str(c['id']) == str(centro_custo_id):
                    centro_custo_nome = f"{c['codigo']} - {c['nome']}"
                    break
        
        return [
            str(item_data.get('descricao', '')),
            valor_str,
            str(item_data.get('data_vencimento', '')),
            str(fornecedor_nome),
            str(centro_custo_nome),
            str(item_data.get('status', '')),
            str(item_data.get('forma_pagamento', ''))
        ]

    def _load_items_to_tree(self):
        # Sobrescreve para adicionar tags de cor e busca
        for i in self.tree.get_children():
            self.tree.delete(i)
        
        search_term = self.search_var.get().lower() if hasattr(self, 'search_var') else ""
        sorted_ids = sorted(self.data_dict.keys(), key=lambda x: int(x) if x.isdigit() else float('inf'))
        
        today = datetime.date.today()
        
        # Variáveis para calcular os totais
        total_geral = 0.0
        total_pendente = 0.0
        total_atrasado = 0.0
        total_pago = 0.0
        
        for item_id in sorted_ids:
            item_data = self.data_dict[item_id]
            values = [item_id] + self._get_item_values_for_tree(item_data)
            
            # Obtém o valor da conta
            valor_conta = parse_br_float(item_data.get('valor', 0.0)) or 0.0
            
            # Lógica de Busca
            if search_term:
                match_found = False
                for val in values:
                    if search_term in str(val).lower():
                        match_found = True
                        break
                if not match_found:
                    continue
            
            status = item_data.get('status', 'Pendente')
            tags = ()
            
            if status == 'Pago':
                tags = ('pago',)
                total_pago += valor_conta
            elif status == 'Pendente':
                try:
                    vencimento_str = item_data.get('data_vencimento')
                    vencimento_date = datetime.datetime.strptime(vencimento_str, '%d/%m/%Y').date()
                    if vencimento_date < today:
                        tags = ('atrasado',)
                        self.data_dict[item_id]['status'] = 'Atrasado' # Atualiza o status
                        total_atrasado += valor_conta
                    else:
                        tags = ('pendente',)
                        total_pendente += valor_conta
                except ValueError:
                    tags = ('pendente',) # Data inválida, assume pendente
                    total_pendente += valor_conta
            elif status == 'Atrasado':
                tags = ('atrasado',)
                total_atrasado += valor_conta
            
            # Soma ao total geral
            total_geral += valor_conta

            try:
                # Garante que todos os valores sejam strings para o Treeview
                str_values = [str(v) if v is not None else '' for v in values]
                self.tree.insert('', tk.END, values=str_values, iid=item_id, tags=tags)
            except tk.TclError as e:
                print(f"Erro Tcl ao inserir item {item_id}: {e}. Valores: {str_values}")

            # Salva as alterações de status
            save_contas_a_pagar(self.data_dict)
        
        # Atualiza os labels de totais
        self._atualizar_totais(total_geral, total_pendente, total_atrasado, total_pago)
    
    def _atualizar_totais(self, total_geral, total_pendente, total_atrasado, total_pago):
        """Atualiza os labels com os valores totais das contas a pagar."""
        if hasattr(self, 'lbl_total_geral'):
            self.lbl_total_geral.config(text=f"Total Geral: {format_br_currency(total_geral)}")
        if hasattr(self, 'lbl_total_pendente'):
            self.lbl_total_pendente.config(text=f"Pendente: {format_br_currency(total_pendente)}")
        if hasattr(self, 'lbl_total_atrasado'):
            self.lbl_total_atrasado.config(text=f"Atrasado: {format_br_currency(total_atrasado)}")
        if hasattr(self, 'lbl_total_pago'):
            self.lbl_total_pago.config(text=f"Pago: {format_br_currency(total_pago)}")

    def _validate_fields(self, data):
        if not super()._validate_fields(data): return False
        
        # Validação de data de vencimento
        vencimento_str = data.get('data_vencimento')
        try:
            datetime.datetime.strptime(vencimento_str, '%d/%m/%Y')
        except ValueError:
            messagebox.showwarning("Data Inválida", "Formato de Data de Vencimento inválido. Use DD/MM/AAAA.", parent=self)
            return False
            
        # Validação de data de pagamento (se preenchida)
        pagamento_str = data.get('data_pagamento')
        if pagamento_str:
            try:
                datetime.datetime.strptime(pagamento_str, '%d/%m/%Y')
            except ValueError:
                messagebox.showwarning("Data Inválida", "Formato de Data de Pagamento inválido. Use DD/MM/AAAA.", parent=self)
                return False
                
        return True
        

    def _mark_as_paid(self):
        if not is_caixa_aberto():
            messagebox.showwarning("Caixa Fechado", "Não é possível registrar pagamentos com o caixa fechado.", parent=self)
            return
        if not self.selected_item_id:
            messagebox.showwarning("Aviso", "Selecione uma conta para marcar como paga.", parent=self)
            return
            
        item_data = self.data_dict.get(self.selected_item_id)
        if not item_data: return
        
        if item_data['status'] == 'Pago':
            messagebox.showinfo("Informação", "Esta conta já está marcada como paga.", parent=self)
            return
            
        # Pergunta se deseja marcar como pago
        if messagebox.askyesno("Confirmar Pagamento", f"Deseja marcar a conta '{item_data['descricao']}' como PAGA%s", parent=self):
            # Usar MultiPaymentDialog para composição de pagamento
            valor_total = parse_br_float(item_data.get('valor', 0.0))
            dialog = MultiPaymentDialog(self, valor_total, title="Pagamento de Conta")
            self.wait_window(dialog)
            
            if not dialog.result:
                return # Cancelou
            
            forma_pag = dialog.result
            
            item_data['status'] = 'Pago'
            item_data['data_pagamento'] = datetime.datetime.now().strftime('%d/%m/%Y')
            item_data['forma_pagamento'] = forma_pag
            
            if save_contas_a_pagar(self.data_dict):
                # Registrar débito no caixa com forma de pagamento e fornecedor
                valor_pago = parse_br_float(item_data.get('valor', 0.0))
                fornecedor_id = item_data.get('fornecedor_id', '')
                fornecedor_nome = self.suppliers_dict.get(fornecedor_id, {}).get('nome', 'N/A')
                
                caixa_registrado = registrar_transacao_caixa(
                    "DÉBITO", 
                    f"PAGTO CONTA: {item_data['descricao']}", 
                    valor_pago, 
                    forma_pag, 
                    fornecedor_nome
                )
                
                msg = "Conta marcada como paga com sucesso!"
                if caixa_registrado:
                    msg += "\n\n✅ Débito registrado no caixa aberto."
                else:
                    msg += "\n\n⚠️ Nota: Débito NÃO registrado no caixa (caixa fechado)."
                
                messagebox.showinfo("Sucesso", msg, parent=self)
                log_user_action("Gerenciar Contas a Pagar", f"Conta ID {self.selected_item_id} marcada como paga")
                self._load_items_to_tree()
                self._clear_form()
            else:
                messagebox.showerror("Erro", "Falha ao salvar a alteração de status.", parent=self)

