        ttk.Button(prop, text="Aplicar Propriedades", command=self._designer_apply_properties, bootstyle="success").grid(row=row, column=0, columnspan=2, sticky="ew", pady=(10, 3)); row += 1
        ttk.Button(prop, text="Gerar Preview PDF", command=self._preview_pdf, bootstyle="info").grid(row=row, column=0, columnspan=2, sticky="ew", pady=3); row += 1

        self.element_vars = {}
