        super().__init__(master)
        self.title("Entrada de Notas Fiscais (Compras)")
        self.state('zoomed')
        self.transient(master)
        self.grab_set()
        self.parent_app = parent_app
        self.products = parent_app.products
        self.suppliers = parent_app.suppliers
        self.carrinho_nota = {} # {produto_id: {'nome', 'qtd', 'custo', 'total'}}
        self.total_nota = 0.0

        # Variáveis de controle
        self.fornecedor_var = tk.StringVar()
        self.produto_var = tk.StringVar()
        self.qtd_var = tk.StringVar(value="1")
        self.custo_var = tk.StringVar()
        self.total_item_var = tk.StringVar(value="R$ 0,00")
        self.total_nota_var = tk.StringVar(value="R$ 0,00")
        self.nota_fiscal_var = tk.StringVar(value=str(get_next_nota_entrada_number()))
