        ttk.Label(main_frame, text="Entrada de Notas Fiscais", font=("Segoe UI", 16, "bold")).grid(row=0, column=0, columnspan=2, pady=(0, 10), sticky="w")

        # Frame de Dados da Nota (Topo)
        nota_frame = ttk.Labelframe(main_frame, text="Dados da Nota", padding="10")
        nota_frame.grid(row=1, column=0, sticky="new", padx=(0, 10))
        nota_frame.columnconfigure(1, weight=1)
        
        # Fornecedor
