        supplier_options = sorted([f"{supp_id} - {data['nome']}" for supp_id, data in self.suppliers.items() if data.get('nome')])
        self.fornecedor_combo = ttk.Combobox(nota_frame, textvariable=self.fornecedor_var, values=[''] + supplier_options, state="readonly")
        self.fornecedor_combo.grid(row=0, column=1, sticky="ew", pady=5, padx=5)
        
        # Número da Nota Fiscal
        ttk.Label(nota_frame, text="Nº Nota Fiscal:").grid(row=1, column=0, sticky="w", pady=5, padx=5)
        entry_nota_fiscal = ttk.Entry(nota_frame, textvariable=self.nota_fiscal_var)
        entry_nota_fiscal.grid(row=1, column=1, sticky="ew", pady=5, padx=5)
        entry_nota_fiscal.config(state='readonly') # Campo agora é somente leitura
        
        # Data da Nota com Calendário
        ttk.Label(nota_frame, text="Data da Nota:").grid(row=2, column=0, sticky="w", pady=5, padx=5)
        self.entry_data_nota = ttk.DateEntry(nota_frame, bootstyle="primary", width=15, dateformat="%d/%m/%Y")
        self.entry_data_nota.grid(row=2, column=1, sticky="w", pady=5, padx=5)
        
        # Condição de Pagamento
        ttk.Label(nota_frame, text="Condição de Pagamento:").grid(row=3, column=0, sticky="w", pady=5, padx=5)
        cond_options = ["À Vista", "Prazo (30 dias)", "Prazo (30/60 dias)", "Prazo (30/60/90 dias)"]
        ttk.Combobox(nota_frame, textvariable=self.condicao_pagamento_var, values=cond_options, state="readonly").grid(row=3, column=1, sticky="ew", pady=5, padx=5)

        # Frame de Adição de Itens (Meio)
        itens_frame = ttk.Labelframe(main_frame, text="Adicionar Itens", padding="10")
        itens_frame.grid(row=2, column=0, sticky="ew", padx=(0, 10), pady=(10, 0))
