def get_caixas_pdv():
    """Retorna lista de caixas cadastrados."""
    db = get_db()
    rows = db.fetchall("SELECT * FROM caixas_pdv WHERE ativo = 1 ORDER BY nome")
    return [dict(row) for row in rows] if rows else []

def get_turnos():
    """Retorna lista de turnos cadastrados."""
    db = get_db()
    rows = db.fetchall("SELECT * FROM turnos WHERE ativo = 1 ORDER BY hora_inicio")
    return [dict(row) for row in rows] if rows else []

def get_centros_custo():
    """Retorna lista de centros de custo cadastrados."""
    db = get_db()
    rows = db.fetchall("SELECT * FROM centros_custo WHERE ativo = 1 ORDER BY codigo")
    return [dict(row) for row in rows] if rows else []

def get_centros_custo_por_tipo(tipo):
    """Retorna lista de centros de custo filtrados por tipo (receita ou despesa)."""
    db = get_db()
    rows = db.fetchall("SELECT * FROM centros_custo WHERE ativo = 1 AND tipo = %s ORDER BY codigo", (tipo,))
    return [dict(row) for row in rows] if rows else []

def get_centros_custo_receitas():
    """Retorna lista de centros de custo do tipo receita."""
    return get_centros_custo_por_tipo('receita')

def get_centros_custo_despesas():
    """Retorna lista de centros de custo do tipo despesa."""
    return get_centros_custo_por_tipo('despesa')

def criar_caixa_pdv(nome, descricao='', local='', banco='', agencia='', conta=''):
    """Cria um novo caixa PDV."""
    db = get_db()
    try:
        db.execute("INSERT INTO caixas_pdv (nome, descricao, local, banco, agencia, conta) VALUES (%s, %s, %s, %s, %s, %s)", 
                   (nome, descricao, local, banco, agencia, conta))
        return True
    except Exception:
        return False

def atualizar_caixa_pdv(caixa_id, nome, descricao='', local='', banco='', agencia='', conta=''):
    """Atualiza um caixa PDV existente."""
    db = get_db()
    try:
        db.execute("""UPDATE caixas_pdv SET nome = %s, descricao = %s, local = %s, 
                      banco = %s, agencia = %s, conta = %s, updated_at = CURRENT_TIMESTAMP 
                      WHERE id = %s""", 
                   (nome, descricao, local, banco, agencia, conta, caixa_id))
        return True
    except Exception:
        return False

def criar_turno(nome, hora_inicio, hora_fim, descricao=''):
    """Cria um novo turno."""
    db = get_db()
    try:
        db.execute("INSERT INTO turnos (nome, hora_inicio, hora_fim, descricao) VALUES (%s, %s, %s, %s)", 
                  (nome, hora_inicio, hora_fim, descricao))
        return True
    except Exception:
        return False

# ═══════════════════════════════════════════════════════════════════════════════════════
# FUNÇÕES DE VÍNCULOS USUÁRIO-CAIXA-TURNO
# ═══════════════════════════════════════════════════════════════════════════════════════

def get_vinculos_usuario(username):
    """Retorna os vínculos de caixa e turno de um usuário específico.
    
    Retorna lista de dicts com campos: id, username, caixa_id, turno_id.
    caixa_id=0 significa 'Todos os Caixas' (compartilhado).
    turno_id=0 significa 'Todos os Turnos' (compartilhado).
    """
    db = get_db()
    rows = db.fetchall(
        "SELECT * FROM vinculos_usuario_caixa_turno WHERE username = %s AND ativo = 1 ORDER BY id",
        (username,)
    )
    return [dict(row) for row in rows] if rows else []


def get_todos_vinculos():
    """Retorna todos os vínculos ativos de todos os usuários."""
    db = get_db()
    rows = db.fetchall(
        "SELECT * FROM vinculos_usuario_caixa_turno WHERE ativo = 1 ORDER BY username, id"
    )
    return [dict(row) for row in rows] if rows else []


def criar_vinculo_usuario_caixa_turno(username, caixa_id=0, turno_id=0):
    """Cria um vínculo entre usuário, caixa e turno.
    
    Args:
        username: Nome do usuário.
        caixa_id: ID do caixa (0 = todos os caixas / compartilhado).
        turno_id: ID do turno (0 = todos os turnos / compartilhado).
    
    Returns:
        bool: True se criado com sucesso.
    """
    db = get_db()
    try:
        # Verifica se já existe vínculo idêntico
        existente = db.fetchone(
            "SELECT id FROM vinculos_usuario_caixa_turno WHERE username = %s AND caixa_id = %s AND turno_id = %s AND ativo = 1",
            (username, caixa_id, turno_id)
        )
        if existente:
            return False  # Vínculo já existe
        db.execute(
            "INSERT INTO vinculos_usuario_caixa_turno (username, caixa_id, turno_id) VALUES (%s, %s, %s)",
            (username, caixa_id, turno_id)
        )
        try:
            AUDITORIA.acao_usuario("Vínculo Criado", f"Usuário '{username}' vinculado ao Caixa ID={caixa_id}, Turno ID={turno_id}")
        except Exception:
            pass
        return True
    except Exception as e:
        print(f"Erro ao criar vínculo: {e}")
        return False


def remover_vinculo_usuario_caixa_turno(vinculo_id):
    """Remove (desativa) um vínculo pelo ID."""
    db = get_db()
    try:
        db.execute(
            "UPDATE vinculos_usuario_caixa_turno SET ativo = 0, updated_at = CURRENT_TIMESTAMP WHERE id = %s",
            (vinculo_id,)
        )
        try:
            AUDITORIA.acao_usuario("Vínculo Removido", f"Vínculo ID={vinculo_id} desativado")
        except Exception:
            pass
        return True
    except Exception:
        return False


def remover_todos_vinculos_usuario(username):
    """Remove todos os vínculos de um usuário."""
    db = get_db()
    try:
        db.execute(
            "UPDATE vinculos_usuario_caixa_turno SET ativo = 0, updated_at = CURRENT_TIMESTAMP WHERE username = %s AND ativo = 1",
            (username,)
        )
        return True
    except Exception:
        return False


def get_caixas_permitidos_usuario(username):
    """Retorna a lista de caixas que o usuário pode operar.
    
    Se o usuário não tem vínculos, retorna todos os caixas (acesso livre).
    Se algum vínculo tem caixa_id=0, retorna todos os caixas.
    Caso contrário, retorna apenas os caixas vinculados.
    """
    vinculos = get_vinculos_usuario(username)
    if not vinculos:
        # Sem vínculos = acesso a todos (comportamento padrão)
        return get_caixas_pdv()
    
    # Verifica se há vínculo com caixa_id=0 (todos os caixas)
    for v in vinculos:
        if v.get('caixa_id', 0) == 0:
            return get_caixas_pdv()
    
    # Filtra apenas os caixas vinculados
    caixa_ids = list(set(v['caixa_id'] for v in vinculos))
    todos_caixas = get_caixas_pdv()
    return [c for c in todos_caixas if c['id'] in caixa_ids]


def get_turnos_permitidos_usuario(username):
    """Retorna a lista de turnos que o usuário pode operar.
    
    Se o usuário não tem vínculos, retorna todos os turnos (acesso livre).
    Se algum vínculo tem turno_id=0, retorna todos os turnos.
    Caso contrário, retorna apenas os turnos vinculados.
    """
    vinculos = get_vinculos_usuario(username)
    if not vinculos:
        return get_turnos()
    
    for v in vinculos:
        if v.get('turno_id', 0) == 0:
            return get_turnos()
    
    turno_ids = list(set(v['turno_id'] for v in vinculos))
    todos_turnos = get_turnos()
    return [t for t in todos_turnos if t['id'] in turno_ids]


def get_nome_caixa_por_id(caixa_id):
    """Retorna o nome do caixa pelo ID. Se caixa_id=0, retorna 'Todos os Caixas'."""
    if caixa_id == 0:
        return "Todos os Caixas (Compartilhado)"
    caixas = get_caixas_pdv()
    for c in caixas:
        if c['id'] == caixa_id:
            return c['nome']
    return f"Caixa #{caixa_id}"


def get_nome_turno_por_id(turno_id):
    """Retorna o nome do turno pelo ID. Se turno_id=0, retorna 'Todos os Turnos'."""
    if turno_id == 0:
        return "Todos os Turnos (Compartilhado)"
    turnos = get_turnos()
    for t in turnos:
        if t['id'] == turno_id:
            return t['nome']
    return f"Turno #{turno_id}"


def criar_centro_custo(codigo, nome, descricao='', tipo='despesa', orcamento=0.0):
    """Cria um novo centro de custo."""
    db = get_db()
    try:
        db.execute("INSERT INTO centros_custo (codigo, nome, descricao, tipo, orcamento_mensal) VALUES (%s, %s, %s, %s, %s)",
                  (codigo, nome, descricao, tipo, orcamento))
        return True
    except Exception:
        return False

def registrar_lancamento_centro_custo(centro_custo_id, tipo, descricao, valor, data_lancamento=None, documento='', observacao=''):
    """Registra um lançamento no centro de custo."""
    db = get_db()
    if not data_lancamento:
        data_lancamento = datetime.datetime.now().strftime('%d/%m/%Y')
    try:
        db.execute("""
            INSERT INTO lancamentos_centro_custo 
            (centro_custo_id, tipo, descricao, valor, data_lancamento, data_competencia, documento, observacao, usuario)
            VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s)
        """, (centro_custo_id, tipo, descricao, valor, data_lancamento, data_lancamento, documento, observacao, logged_user))
        return True
    except Exception as e:
        try:
            AUDITORIA.erro(f"Erro no sistema: {e}")
        except Exception:
            pass
        print(f"Erro ao registrar lançamento: {e}")
        return False


class GerenciadorCaixasPDV(tk.Toplevel):
    """Janela para gerenciar múltiplos caixas PDV."""
    def __init__(self, master, parent_app):
        super().__init__(master)
        self.title("💻 Gerenciar Caixas PDV")
        self.state('zoomed')
        self.parent_app = parent_app
        self.transient(master)
        self.grab_set()
        self._setup_ui()
        self._load_caixas()
    
        # ⚛️ Quantum Sync - Atualização em tempo real
        self._qs = get_quantum_sync()
        if self._qs:
            self._qs.subscribe("caixa", self._qs_refresh_gerenciadorcaixaspdv)
        self.protocol("WM_DELETE_WINDOW", self._qs_close_gerenciadorcaixaspdv)
    
    def _qs_refresh_gerenciadorcaixaspdv(self):
        """Atualização quântica em tempo real."""
        try:
            if self.winfo_exists() and hasattr(self, '_carregar_dados'):
                self._carregar_dados()
            elif self.winfo_exists() and hasattr(self, '_atualizar'):
                self._atualizar()
        except Exception:
            pass
    
    def _qs_close_gerenciadorcaixaspdv(self):
        """Limpa subscribers ao fechar."""
        try:
            sync = get_quantum_sync()
            if sync:
                sync.unsubscribe_all(self._qs_refresh_gerenciadorcaixaspdv)
        except Exception:
            pass
        try:
            self.destroy()
        except Exception:
            pass

    def _setup_ui(self):
        main_frame = ttk.Frame(self, padding=20)
        main_frame.pack(expand=True, fill=tk.BOTH)
        
        # Cabeçalho
        header = ttk.Frame(main_frame)
        header.pack(fill=tk.X, pady=(0, 15))
        ttk.Label(header, text="💻 CAIXAS PDV CADASTRADOS", font=("Segoe UI", 14, "bold")).pack(side=tk.LEFT)
        ttk.Button(header, text="+ Novo Caixa", bootstyle="success", command=self._novo_caixa).pack(side=tk.RIGHT)
        
        # Treeview com scroll
        tree_frame = ttk.Frame(main_frame)
        tree_frame.pack(expand=True, fill=tk.BOTH)
        
        cols = ("id", "nome", "descricao", "local", "banco", "agencia", "conta", "status")
        self.tree = ttk.Treeview(tree_frame, columns=cols, show="headings", height=15)
        self.tree.heading("id", text="ID")
        self.tree.heading("nome", text="Nome")
        self.tree.heading("descricao", text="Descrição")
        self.tree.heading("local", text="Local")
        self.tree.heading("banco", text="Banco")
        self.tree.heading("agencia", text="Agência")
        self.tree.heading("conta", text="Conta")
        self.tree.heading("status", text="Status")
        self.tree.column("id", width=50, anchor=tk.CENTER)
        self.tree.column("nome", width=120)
        self.tree.column("descricao", width=150)
        self.tree.column("local", width=100)
        self.tree.column("banco", width=100)
        self.tree.column("agencia", width=80, anchor=tk.CENTER)
        self.tree.column("conta", width=100, anchor=tk.CENTER)
        self.tree.column("status", width=70, anchor=tk.CENTER)
        
        # Scrollbar
        scrollbar = ttk.Scrollbar(tree_frame, orient=tk.VERTICAL, command=self.tree.yview)
        self.tree.configure(yscrollcommand=scrollbar.set)
        self.tree.pack(side=tk.LEFT, expand=True, fill=tk.BOTH)
        scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
        
        # Botões de ação
        btn_frame = ttk.Frame(main_frame)
        btn_frame.pack(fill=tk.X, pady=(10, 0))
        ttk.Button(btn_frame, text="Editar", bootstyle="info-outline", command=self._editar_caixa).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="Desativar", bootstyle="warning-outline", command=self._desativar_caixa).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="Fechar", bootstyle="secondary", command=self.destroy).pack(side=tk.RIGHT, padx=5)
    
    def _load_caixas(self):
        for item in self.tree.get_children():
            self.tree.delete(item)
        caixas = get_caixas_pdv()
        for c in caixas:
            self.tree.insert("", tk.END, iid=str(c['id']), values=(
                c['id'], 
                c['nome'], 
                c.get('descricao', ''), 
                c.get('local', ''),
                c.get('banco', ''),
                c.get('agencia', ''),
                c.get('conta', ''),
                'Ativo'
            ))
    
    def _novo_caixa(self):
        dialog = tk.Toplevel(self)
        dialog.title("Novo Caixa PDV")
        responsive_geometry(dialog, 450, 450)
        dialog.transient(self)
        dialog.grab_set()
        
        frame = ttk.Frame(dialog, padding=20)
        frame.pack(expand=True, fill=tk.BOTH)
        
        ttk.Label(frame, text="💻 CADASTRO DE NOVO CAIXA", font=("Segoe UI", 12, "bold")).pack(pady=(0, 15))
        
        # Nome
        ttk.Label(frame, text="Nome do Caixa:*").pack(anchor=tk.W)
        nome_var = tk.StringVar()
        ttk.Entry(frame, textvariable=nome_var, width=45).pack(fill=tk.X, pady=(0, 10))
        
        # Descrição
        ttk.Label(frame, text="Descrição:").pack(anchor=tk.W)
        desc_var = tk.StringVar()
        ttk.Entry(frame, textvariable=desc_var, width=45).pack(fill=tk.X, pady=(0, 10))
        
        # Local
        ttk.Label(frame, text="Local:").pack(anchor=tk.W)
        local_var = tk.StringVar()
        ttk.Entry(frame, textvariable=local_var, width=45).pack(fill=tk.X, pady=(0, 10))
        
        # Separador - Dados Bancários
        ttk.Separator(frame, orient=tk.HORIZONTAL).pack(fill=tk.X, pady=10)
        ttk.Label(frame, text="🏦 DADOS BANCÁRIOS", font=("Segoe UI", 10, "bold")).pack(anchor=tk.W, pady=(0, 5))
        
        # Banco
        ttk.Label(frame, text="Número/Nome do Banco:").pack(anchor=tk.W)
        banco_var = tk.StringVar()
        ttk.Entry(frame, textvariable=banco_var, width=45).pack(fill=tk.X, pady=(0, 10))
        
        # Frame para Agência e Conta lado a lado
        banco_frame = ttk.Frame(frame)
        banco_frame.pack(fill=tk.X, pady=(0, 10))
        
        # Agência
        ag_frame = ttk.Frame(banco_frame)
        ag_frame.pack(side=tk.LEFT, expand=True, fill=tk.X, padx=(0, 5))
        ttk.Label(ag_frame, text="Agência:").pack(anchor=tk.W)
        agencia_var = tk.StringVar()
        ttk.Entry(ag_frame, textvariable=agencia_var, width=20).pack(fill=tk.X)
        
        # Conta
        conta_frame = ttk.Frame(banco_frame)
        conta_frame.pack(side=tk.LEFT, expand=True, fill=tk.X, padx=(5, 0))
        ttk.Label(conta_frame, text="Conta:").pack(anchor=tk.W)
        conta_var = tk.StringVar()
        ttk.Entry(conta_frame, textvariable=conta_var, width=20).pack(fill=tk.X)
        
        def salvar():
            if not nome_var.get().strip():
                messagebox.showerror("Erro", "Nome é obrigatório!", parent=dialog)
                return
            if criar_caixa_pdv(
                nome_var.get().strip(), 
                desc_var.get().strip(), 
                local_var.get().strip(),
                banco_var.get().strip(),
                agencia_var.get().strip(),
                conta_var.get().strip()
            ):
                messagebox.showinfo("Sucesso", "Caixa criado com sucesso!", parent=dialog)
                dialog.destroy()
                self._load_caixas()
            else:
                messagebox.showerror("Erro", "Erro ao criar caixa. Nome pode já existir.", parent=dialog)
        
        btn_frame = ttk.Frame(frame)
        btn_frame.pack(fill=tk.X, pady=(20, 0))
        ttk.Button(btn_frame, text="Salvar", bootstyle="success", command=salvar).pack(side=tk.RIGHT, padx=5)
        ttk.Button(btn_frame, text="Cancelar", bootstyle="secondary", command=dialog.destroy).pack(side=tk.RIGHT)
    
    def _editar_caixa(self):
        sel = self.tree.selection()
        if not sel:
            messagebox.showwarning("Atenção", "Selecione um caixa para editar.", parent=self)
            return
        
        caixa_id = int(sel[0])
        values = self.tree.item(sel[0])['values']
        
        dialog = tk.Toplevel(self)
        dialog.title("Editar Caixa PDV")
        responsive_geometry(dialog, 450, 450)
        dialog.transient(self)
        dialog.grab_set()
        
        frame = ttk.Frame(dialog, padding=20)
        frame.pack(expand=True, fill=tk.BOTH)
        
        ttk.Label(frame, text="✏️ EDITAR CAIXA", font=("Segoe UI", 12, "bold")).pack(pady=(0, 15))
        
        # Nome
        ttk.Label(frame, text="Nome do Caixa:*").pack(anchor=tk.W)
        nome_var = tk.StringVar(value=values[1])
        ttk.Entry(frame, textvariable=nome_var, width=45).pack(fill=tk.X, pady=(0, 10))
        
        # Descrição
        ttk.Label(frame, text="Descrição:").pack(anchor=tk.W)
        desc_var = tk.StringVar(value=values[2])
        ttk.Entry(frame, textvariable=desc_var, width=45).pack(fill=tk.X, pady=(0, 10))
        
        # Local
        ttk.Label(frame, text="Local:").pack(anchor=tk.W)
        local_var = tk.StringVar(value=values[3])
        ttk.Entry(frame, textvariable=local_var, width=45).pack(fill=tk.X, pady=(0, 10))
        
        # Separador - Dados Bancários
        ttk.Separator(frame, orient=tk.HORIZONTAL).pack(fill=tk.X, pady=10)
        ttk.Label(frame, text="🏦 DADOS BANCÁRIOS", font=("Segoe UI", 10, "bold")).pack(anchor=tk.W, pady=(0, 5))
        
        # Banco
        ttk.Label(frame, text="Número/Nome do Banco:").pack(anchor=tk.W)
        banco_var = tk.StringVar(value=values[4] if len(values) > 4 else '')
        ttk.Entry(frame, textvariable=banco_var, width=45).pack(fill=tk.X, pady=(0, 10))
        
        # Frame para Agência e Conta lado a lado
        banco_frame = ttk.Frame(frame)
        banco_frame.pack(fill=tk.X, pady=(0, 10))
        
        # Agência
        ag_frame = ttk.Frame(banco_frame)
        ag_frame.pack(side=tk.LEFT, expand=True, fill=tk.X, padx=(0, 5))
        ttk.Label(ag_frame, text="Agência:").pack(anchor=tk.W)
        agencia_var = tk.StringVar(value=values[5] if len(values) > 5 else '')
        ttk.Entry(ag_frame, textvariable=agencia_var, width=20).pack(fill=tk.X)
        
        # Conta
        conta_frame = ttk.Frame(banco_frame)
        conta_frame.pack(side=tk.LEFT, expand=True, fill=tk.X, padx=(5, 0))
        ttk.Label(conta_frame, text="Conta:").pack(anchor=tk.W)
        conta_var = tk.StringVar(value=values[6] if len(values) > 6 else '')
        ttk.Entry(conta_frame, textvariable=conta_var, width=20).pack(fill=tk.X)
        
        def salvar():
            if not nome_var.get().strip():
                messagebox.showerror("Erro", "Nome é obrigatório!", parent=dialog)
                return
            if atualizar_caixa_pdv(
                caixa_id,
                nome_var.get().strip(), 
                desc_var.get().strip(), 
                local_var.get().strip(),
                banco_var.get().strip(),
                agencia_var.get().strip(),
                conta_var.get().strip()
            ):
                messagebox.showinfo("Sucesso", "Caixa atualizado com sucesso!", parent=dialog)
                dialog.destroy()
                self._load_caixas()
            else:
                messagebox.showerror("Erro", "Erro ao atualizar caixa.", parent=dialog)
        
        btn_frame = ttk.Frame(frame)
        btn_frame.pack(fill=tk.X, pady=(20, 0))
        ttk.Button(btn_frame, text="Salvar", bootstyle="success", command=salvar).pack(side=tk.RIGHT, padx=5)
        ttk.Button(btn_frame, text="Cancelar", bootstyle="secondary", command=dialog.destroy).pack(side=tk.RIGHT)
    
    def _desativar_caixa(self):
        sel = self.tree.selection()
        if not sel:
            messagebox.showwarning("Atenção", "Selecione um caixa para desativar.", parent=self)
            return
        caixa_id = self.tree.item(sel[0])['values'][0]
        if caixa_id == 1:
            messagebox.showerror("Erro", "Não é possível desativar o Caixa Principal.", parent=self)
            return
        if messagebox.askyesno("Confirmar", "Deseja desativar este caixa%s", parent=self):
            db = get_db()
            db.execute("UPDATE caixas_pdv SET ativo = 0 WHERE id = %s", (caixa_id,))
            self._load_caixas()


class GerenciadorTurnos(tk.Toplevel):
    """Janela para gerenciar turnos de trabalho."""
    def __init__(self, master, parent_app):
        super().__init__(master)
        self.title("⏰ Gerenciar Turnos")
        self.state('zoomed')
        self.parent_app = parent_app
        self.transient(master)
        self.grab_set()
        self._setup_ui()
        self._load_turnos()
    
        # ⚛️ Quantum Sync - Atualização em tempo real
        self._qs = get_quantum_sync()
        if self._qs:
            self._qs.subscribe("caixa", self._qs_refresh_gerenciadorturnos)
        self.protocol("WM_DELETE_WINDOW", self._qs_close_gerenciadorturnos)
    
    def _qs_refresh_gerenciadorturnos(self):
        """Atualização quântica em tempo real."""
        try:
            if self.winfo_exists() and hasattr(self, '_carregar_dados'):
                self._carregar_dados()
            elif self.winfo_exists() and hasattr(self, '_atualizar'):
                self._atualizar()
        except Exception:
            pass
    
    def _qs_close_gerenciadorturnos(self):
        """Limpa subscribers ao fechar."""
        try:
            sync = get_quantum_sync()
            if sync:
                sync.unsubscribe_all(self._qs_refresh_gerenciadorturnos)
        except Exception:
            pass
        try:
            self.destroy()
        except Exception:
            pass

    def _setup_ui(self):
        main_frame = ttk.Frame(self, padding=20)
        main_frame.pack(expand=True, fill=tk.BOTH)
        
        header = ttk.Frame(main_frame)
        header.pack(fill=tk.X, pady=(0, 15))
        ttk.Label(header, text="⏰ TURNOS DE TRABALHO", font=("Segoe UI", 14, "bold")).pack(side=tk.LEFT)
        ttk.Button(header, text="+ Novo Turno", bootstyle="success", command=self._novo_turno).pack(side=tk.RIGHT)
        
        cols = ("id", "nome", "inicio", "fim", "descricao")
        self.tree = ttk.Treeview(main_frame, columns=cols, show="headings", height=15)
        self.tree.heading("id", text="ID")
        self.tree.heading("nome", text="Nome")
        self.tree.heading("inicio", text="Início")
        self.tree.heading("fim", text="Fim")
        self.tree.heading("descricao", text="Descrição")
        self.tree.column("id", width=50, anchor=tk.CENTER)
        self.tree.column("nome", width=120)
        self.tree.column("inicio", width=80, anchor=tk.CENTER)
        self.tree.column("fim", width=80, anchor=tk.CENTER)
        self.tree.column("descricao", width=250)
        self.tree.pack(expand=True, fill=tk.BOTH)
        
        btn_frame = ttk.Frame(main_frame)
        btn_frame.pack(fill=tk.X, pady=(10, 0))
        ttk.Button(btn_frame, text="Editar", bootstyle="info-outline", command=self._editar_turno).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="Excluir", bootstyle="danger-outline", command=self._excluir_turno).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="Fechar", bootstyle="secondary", command=self.destroy).pack(side=tk.RIGHT, padx=5)
    
    def _load_turnos(self):
        for item in self.tree.get_children():
            self.tree.delete(item)
        turnos = get_turnos()
        for t in turnos:
            self.tree.insert("", tk.END, values=(t['id'], t['nome'], t.get('hora_inicio', ''), t.get('hora_fim', ''), t.get('descricao', '')))
    
    def _novo_turno(self):
        dialog = tk.Toplevel(self)
        dialog.title("Novo Turno")
        responsive_geometry(dialog, 400, 350)
        dialog.transient(self)
        dialog.grab_set()
        
        frame = ttk.Frame(dialog, padding=20)
        frame.pack(expand=True, fill=tk.BOTH)
        
        ttk.Label(frame, text="Nome do Turno:*").pack(anchor=tk.W)
        nome_var = tk.StringVar()
        ttk.Entry(frame, textvariable=nome_var, width=40).pack(fill=tk.X, pady=(0, 10))
        
        ttk.Label(frame, text="Hora Início (HH:MM):*").pack(anchor=tk.W)
        inicio_var = tk.StringVar(value="08:00")
        ttk.Entry(frame, textvariable=inicio_var, width=10).pack(anchor=tk.W, pady=(0, 10))
        
        ttk.Label(frame, text="Hora Fim (HH:MM):*").pack(anchor=tk.W)
        fim_var = tk.StringVar(value="18:00")
        ttk.Entry(frame, textvariable=fim_var, width=10).pack(anchor=tk.W, pady=(0, 10))
        
        ttk.Label(frame, text="Descrição:").pack(anchor=tk.W)
        desc_var = tk.StringVar()
        ttk.Entry(frame, textvariable=desc_var, width=40).pack(fill=tk.X, pady=(0, 10))
        
        def salvar():
            if not nome_var.get().strip():
                messagebox.showerror("Erro", "Nome é obrigatório!", parent=dialog)
                return
            if criar_turno(nome_var.get().strip(), inicio_var.get().strip(), fim_var.get().strip(), desc_var.get().strip()):
                messagebox.showinfo("Sucesso", "Turno criado com sucesso!", parent=dialog)
                dialog.destroy()
                self._load_turnos()
            else:
                messagebox.showerror("Erro", "Erro ao criar turno.", parent=dialog)
        
        btn_frame = ttk.Frame(frame)
        btn_frame.pack(fill=tk.X, pady=(20, 0))
        ttk.Button(btn_frame, text="Salvar", bootstyle="success", command=salvar).pack(side=tk.RIGHT, padx=5)
        ttk.Button(btn_frame, text="Cancelar", bootstyle="secondary", command=dialog.destroy).pack(side=tk.RIGHT)
    
    def _editar_turno(self):
        messagebox.showinfo("Info", "Função de edição em desenvolvimento.", parent=self)
    
    def _excluir_turno(self):
        sel = self.tree.selection()
        if not sel:
            messagebox.showwarning("Atenção", "Selecione um turno para excluir.", parent=self)
            return
        turno_id = self.tree.item(sel[0])['values'][0]
        if turno_id <= 4:
            messagebox.showerror("Erro", "Não é possível excluir turnos padrão.", parent=self)
            return
        if messagebox.askyesno("Confirmar", "Deseja excluir este turno%s", parent=self):
            db = get_db()
            db.execute("UPDATE turnos SET ativo = 0 WHERE id = %s", (turno_id,))
            self._load_turnos()


class GerenciadorVinculosUsuario(tk.Toplevel):
    """Janela para gerenciar vínculos de usuários a caixas e turnos específicos ou compartilhados."""
    def __init__(self, master, parent_app):
        super().__init__(master)
        self.title("🔗 Vínculos Usuário ↔ Caixa / Turno")
        self.state('zoomed')
        self.parent_app = parent_app
        self.transient(master)
        self.grab_set()
        self._setup_ui()
        self._load_vinculos()

        # ⚛️ Quantum Sync
        self._qs = get_quantum_sync()
        if self._qs:
            self._qs.subscribe("caixa", self._qs_refresh_vinculos)
        self.protocol("WM_DELETE_WINDOW", self._qs_close_vinculos)

    def _qs_refresh_vinculos(self):
        try:
            if self.winfo_exists():
                self._load_vinculos()
        except Exception:
            pass

    def _qs_close_vinculos(self):
        try:
            sync = get_quantum_sync()
            if sync:
                sync.unsubscribe_all(self._qs_refresh_vinculos)
        except Exception:
            pass
        try:
            self.destroy()
        except Exception:
            pass

    def _setup_ui(self):
        main_frame = ttk.Frame(self, padding=20)
        main_frame.pack(expand=True, fill=tk.BOTH)

        # Cabeçalho
        header = ttk.Frame(main_frame)
        header.pack(fill=tk.X, pady=(0, 15))
        ttk.Label(header, text="🔗 VÍNCULOS USUÁRIO ↔ CAIXA / TURNO", font=("Segoe UI", 14, "bold")).pack(side=tk.LEFT)
        ttk.Button(header, text="+ Novo Vínculo", bootstyle="success", command=self._novo_vinculo).pack(side=tk.RIGHT)

        # Informação explicativa
        info_frame = ttk.Frame(main_frame)
        info_frame.pack(fill=tk.X, pady=(0, 10))
        ttk.Label(info_frame, text="Vincule usuários a caixas e turnos específicos. Usuários sem vínculos têm acesso a todos os caixas e turnos.",
                  font=("Segoe UI", 9), foreground="#666").pack(anchor=tk.W)
        ttk.Label(info_frame, text="Selecione 'Todos os Caixas' ou 'Todos os Turnos' para acesso compartilhado.",
                  font=("Segoe UI", 9), foreground="#666").pack(anchor=tk.W)

        # Treeview
        tree_frame = ttk.Frame(main_frame)
        tree_frame.pack(expand=True, fill=tk.BOTH)

        cols = ("id", "usuario", "caixa", "turno", "criado_em")
        self.tree = ttk.Treeview(tree_frame, columns=cols, show="headings", height=18)
        self.tree.heading("id", text="ID")
        self.tree.heading("usuario", text="Usuário")
        self.tree.heading("caixa", text="Caixa")
        self.tree.heading("turno", text="Turno")
        self.tree.heading("criado_em", text="Criado em")
        self.tree.column("id", width=50, anchor=tk.CENTER)
        self.tree.column("usuario", width=150)
        self.tree.column("caixa", width=200)
        self.tree.column("turno", width=200)
        self.tree.column("criado_em", width=150, anchor=tk.CENTER)

        scrollbar = ttk.Scrollbar(tree_frame, orient=tk.VERTICAL, command=self.tree.yview)
        self.tree.configure(yscrollcommand=scrollbar.set)
        self.tree.pack(side=tk.LEFT, expand=True, fill=tk.BOTH)
        scrollbar.pack(side=tk.RIGHT, fill=tk.Y)

        # Botões de ação
        btn_frame = ttk.Frame(main_frame)
        btn_frame.pack(fill=tk.X, pady=(10, 0))
        ttk.Button(btn_frame, text="Remover Vínculo", bootstyle="danger-outline", command=self._remover_vinculo).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="Remover Todos do Usuário", bootstyle="warning-outline", command=self._remover_todos_usuario).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="Fechar", bootstyle="secondary", command=self.destroy).pack(side=tk.RIGHT, padx=5)

    def _load_vinculos(self):
        for item in self.tree.get_children():
            self.tree.delete(item)
        vinculos = get_todos_vinculos()
        for v in vinculos:
            caixa_nome = get_nome_caixa_por_id(v.get('caixa_id', 0))
            turno_nome = get_nome_turno_por_id(v.get('turno_id', 0))
            criado = str(v.get('created_at', ''))[:19] if v.get('created_at') else ''
            self.tree.insert("", tk.END, values=(
                v['id'],
                v['username'],
                caixa_nome,
                turno_nome,
                criado
            ))

    def _novo_vinculo(self):
        dialog = tk.Toplevel(self)
        dialog.title("Novo Vínculo Usuário ↔ Caixa / Turno")
        responsive_geometry(dialog, 500, 400)
        dialog.transient(self)
        dialog.grab_set()

        frame = ttk.Frame(dialog, padding=20)
        frame.pack(expand=True, fill=tk.BOTH)

        ttk.Label(frame, text="🔗 NOVO VÍNCULO", font=("Segoe UI", 13, "bold")).pack(pady=(0, 15))

        # Usuário
        ttk.Label(frame, text="Usuário:*", font=("Segoe UI", 10, "bold")).pack(anchor=tk.W)
        usuario_var = tk.StringVar()
        usuarios = load_users()
        usuario_options = sorted(usuarios.keys()) if usuarios else []
        cmb_usuario = ttk.Combobox(frame, textvariable=usuario_var, values=usuario_options, state='readonly', font=("Segoe UI", 11), width=40)
        cmb_usuario.pack(fill=tk.X, pady=(0, 10))

        # Caixa
        ttk.Label(frame, text="Caixa:", font=("Segoe UI", 10, "bold")).pack(anchor=tk.W)
        caixa_var = tk.StringVar()
        caixas = get_caixas_pdv()
        caixa_options = ["0 - Todos os Caixas (Compartilhado)"] + [f"{c['id']} - {c['nome']}" for c in caixas]
        cmb_caixa = ttk.Combobox(frame, textvariable=caixa_var, values=caixa_options, state='readonly', font=("Segoe UI", 11), width=40)
        cmb_caixa.pack(fill=tk.X, pady=(0, 10))
        cmb_caixa.current(0)

        # Turno
        ttk.Label(frame, text="Turno:", font=("Segoe UI", 10, "bold")).pack(anchor=tk.W)
        turno_var = tk.StringVar()
        turnos = get_turnos()
        turno_options = ["0 - Todos os Turnos (Compartilhado)"] + [f"{t['id']} - {t['nome']} ({t.get('hora_inicio', '')} - {t.get('hora_fim', '')})" for t in turnos]
        cmb_turno = ttk.Combobox(frame, textvariable=turno_var, values=turno_options, state='readonly', font=("Segoe UI", 11), width=40)
        cmb_turno.pack(fill=tk.X, pady=(0, 10))
        cmb_turno.current(0)

        # Nota informativa
        ttk.Separator(frame, orient=tk.HORIZONTAL).pack(fill=tk.X, pady=10)
        ttk.Label(frame, text="Nota: Usuários sem nenhum vínculo têm acesso livre a todos os caixas e turnos.",
                  font=("Segoe UI", 8, "italic"), foreground="#888").pack(anchor=tk.W)

        def salvar():
            username = usuario_var.get().strip()
            if not username:
                messagebox.showerror("Erro", "Selecione um usuário!", parent=dialog)
                return

            caixa_sel = caixa_var.get()
            turno_sel = turno_var.get()

            try:
                caixa_id = int(caixa_sel.split(' - ')[0])
            except (ValueError, IndexError):
                caixa_id = 0

            try:
                turno_id = int(turno_sel.split(' - ')[0])
            except (ValueError, IndexError):
                turno_id = 0

            if criar_vinculo_usuario_caixa_turno(username, caixa_id, turno_id):
                messagebox.showinfo("Sucesso", f"Vínculo criado com sucesso!\n\nUsuário: {username}\nCaixa: {get_nome_caixa_por_id(caixa_id)}\nTurno: {get_nome_turno_por_id(turno_id)}", parent=dialog)
                dialog.destroy()
                self._load_vinculos()
            else:
                messagebox.showerror("Erro", "Erro ao criar vínculo.\nO vínculo pode já existir.", parent=dialog)

        btn_frame = ttk.Frame(frame)
        btn_frame.pack(fill=tk.X, pady=(15, 0))
        ttk.Button(btn_frame, text="Salvar", bootstyle="success", command=salvar).pack(side=tk.RIGHT, padx=5)
        ttk.Button(btn_frame, text="Cancelar", bootstyle="secondary", command=dialog.destroy).pack(side=tk.RIGHT)

    def _remover_vinculo(self):
        sel = self.tree.selection()
        if not sel:
            messagebox.showwarning("Atenção", "Selecione um vínculo para remover.", parent=self)
            return
        vinculo_id = self.tree.item(sel[0])['values'][0]
        username = self.tree.item(sel[0])['values'][1]
        if messagebox.askyesno("Confirmar", f"Deseja remover o vínculo ID {vinculo_id} do usuário '{username}'?", parent=self):
            if remover_vinculo_usuario_caixa_turno(vinculo_id):
                self._load_vinculos()
                messagebox.showinfo("Sucesso", "Vínculo removido com sucesso!", parent=self)
            else:
                messagebox.showerror("Erro", "Erro ao remover vínculo.", parent=self)

    def _remover_todos_usuario(self):
        sel = self.tree.selection()
        if not sel:
            messagebox.showwarning("Atenção", "Selecione um vínculo para identificar o usuário.", parent=self)
            return
        username = self.tree.item(sel[0])['values'][1]
        if messagebox.askyesno("Confirmar", f"Deseja remover TODOS os vínculos do usuário '{username}'?\n\nO usuário voltará a ter acesso livre a todos os caixas e turnos.", parent=self):
            if remover_todos_vinculos_usuario(username):
                self._load_vinculos()
                messagebox.showinfo("Sucesso", f"Todos os vínculos do usuário '{username}' foram removidos.", parent=self)
            else:
                messagebox.showerror("Erro", "Erro ao remover vínculos.", parent=self)


class GerenciadorCentrosCusto(tk.Toplevel):
    """Janela profissional para gerenciar centros de custo."""
    def __init__(self, master, parent_app):
        super().__init__(master)
        self.title("📊 Centro de Custos")
        self.state('zoomed')
        self.parent_app = parent_app
        self.transient(master)
        self.grab_set()
        self._setup_ui()
        self._load_centros()
    
        # ⚛️ Quantum Sync - Atualização em tempo real
        self._qs = get_quantum_sync()
        if self._qs:
            self._qs.subscribe("contas_pagar", self._qs_refresh_centros)
            self._qs.subscribe("contas_receber", self._qs_refresh_centros)
        self.protocol("WM_DELETE_WINDOW", self._qs_close_centros)
    
    def _qs_refresh_centros(self):
        """Atualização quântica em tempo real."""
        try:
            if self.winfo_exists() and hasattr(self, '_carregar_dados'):
                self._carregar_dados()
        except Exception:
            pass
    
    def _qs_close_centros(self):
        """Limpa subscribers ao fechar."""
        try:
            sync = get_quantum_sync()
            if sync:
                sync.unsubscribe_all(self._qs_refresh_centros)
        except Exception:
            pass
        try:
            self.destroy()
        except Exception:
            pass

    def _setup_ui(self):
        main_frame = ttk.Frame(self, padding=20)
        main_frame.pack(expand=True, fill=tk.BOTH)
        
        # Cabeçalho
        header = ttk.Frame(main_frame)
        header.pack(fill=tk.X, pady=(0, 15))
        ttk.Label(header, text="📊 CENTROS DE CUSTO", font=("Segoe UI", 16, "bold")).pack(side=tk.LEFT)
        
        btn_header = ttk.Frame(header)
        btn_header.pack(side=tk.RIGHT)
        ttk.Button(btn_header, text="+ Novo Centro", bootstyle="success", command=self._novo_centro).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_header, text="Relatório", bootstyle="info-outline", command=self._relatorio).pack(side=tk.LEFT, padx=5)
        
        # Treeview
        cols = ("id", "codigo", "nome", "tipo", "orcamento", "realizado", "saldo")
        self.tree = ttk.Treeview(main_frame, columns=cols, show="headings", height=18)
        self.tree.heading("id", text="ID")
        self.tree.heading("codigo", text="Código")
        self.tree.heading("nome", text="Nome")
        self.tree.heading("tipo", text="Tipo")
        self.tree.heading("orcamento", text="Orçamento")
        self.tree.heading("realizado", text="Realizado")
        self.tree.heading("saldo", text="Saldo")
        self.tree.column("id", width=40, anchor=tk.CENTER)
        self.tree.column("codigo", width=70, anchor=tk.CENTER)
        self.tree.column("nome", width=200)
        self.tree.column("tipo", width=80, anchor=tk.CENTER)
        self.tree.column("orcamento", width=120, anchor=tk.E)
        self.tree.column("realizado", width=120, anchor=tk.E)
        self.tree.column("saldo", width=120, anchor=tk.E)
        self.tree.pack(expand=True, fill=tk.BOTH)
        
        # Botões de ação
        btn_frame = ttk.Frame(main_frame)
        btn_frame.pack(fill=tk.X, pady=(10, 0))
        ttk.Button(btn_frame, text="Editar", bootstyle="info-outline", command=self._editar_centro).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="Lançamentos", bootstyle="primary-outline", command=self._ver_lancamentos).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="Novo Lançamento", bootstyle="warning", command=self._novo_lancamento).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="Fechar", bootstyle="secondary", command=self.destroy).pack(side=tk.RIGHT, padx=5)
    
    def _load_centros(self):
        for item in self.tree.get_children():
            self.tree.delete(item)
        centros = get_centros_custo()
        db = get_db()
        for c in centros:
            # Calcular realizado
            result = db.fetchone(
                "SELECT COALESCE(SUM(valor), 0) as total FROM lancamentos_centro_custo WHERE centro_custo_id = %s",
                (c['id'],)
            )
            realizado = result['total'] if result else 0.0
            orcamento = c.get('orcamento_mensal', 0.0)
            saldo = orcamento - realizado
            
            tipo_display = "Receita" if c.get('tipo') == 'receita' else "Despesa"
            self.tree.insert("", tk.END, values=(
                c['id'], c['codigo'], c['nome'], tipo_display,
                format_br_currency(orcamento), format_br_currency(realizado), format_br_currency(saldo)
            ))
    
    def _novo_centro(self):
        dialog = tk.Toplevel(self)
        dialog.title("Novo Centro de Custo")
        responsive_geometry(dialog, 450, 400)
        dialog.transient(self)
        dialog.grab_set()
        
        frame = ttk.Frame(dialog, padding=20)
        frame.pack(expand=True, fill=tk.BOTH)
        
        ttk.Label(frame, text="Código:*").pack(anchor=tk.W)
        codigo_var = tk.StringVar()
        ttk.Entry(frame, textvariable=codigo_var, width=15).pack(anchor=tk.W, pady=(0, 10))
        
        ttk.Label(frame, text="Nome:*").pack(anchor=tk.W)
        nome_var = tk.StringVar()
        ttk.Entry(frame, textvariable=nome_var, width=40).pack(fill=tk.X, pady=(0, 10))
        
        ttk.Label(frame, text="Descrição:").pack(anchor=tk.W)
        desc_var = tk.StringVar()
        ttk.Entry(frame, textvariable=desc_var, width=40).pack(fill=tk.X, pady=(0, 10))
        
        ttk.Label(frame, text="Tipo:").pack(anchor=tk.W)
        tipo_var = tk.StringVar(value="despesa")
        tipo_frame = ttk.Frame(frame)
        tipo_frame.pack(anchor=tk.W, pady=(0, 10))
        ttk.Radiobutton(tipo_frame, text="Despesa", variable=tipo_var, value="despesa").pack(side=tk.LEFT, padx=5)
        ttk.Radiobutton(tipo_frame, text="Receita", variable=tipo_var, value="receita").pack(side=tk.LEFT, padx=5)
        
        ttk.Label(frame, text="Orçamento Mensal (R$):").pack(anchor=tk.W)
        orcamento_var = tk.StringVar(value="0,00")
        ttk.Entry(frame, textvariable=orcamento_var, width=15).pack(anchor=tk.W, pady=(0, 10))
        
        def salvar():
            if not codigo_var.get().strip() or not nome_var.get().strip():
                messagebox.showerror("Erro", "Código e Nome são obrigatórios!", parent=dialog)
                return
            orcamento = parse_br_float(orcamento_var.get()) or 0.0
            if criar_centro_custo(codigo_var.get().strip(), nome_var.get().strip(), desc_var.get().strip(), tipo_var.get(), orcamento):
                messagebox.showinfo("Sucesso", "Centro de custo criado!", parent=dialog)
                dialog.destroy()
                self._load_centros()
            else:
                messagebox.showerror("Erro", "Erro ao criar. Código pode já existir.", parent=dialog)
        
        btn_frame = ttk.Frame(frame)
        btn_frame.pack(fill=tk.X, pady=(20, 0))
        ttk.Button(btn_frame, text="Salvar", bootstyle="success", command=salvar).pack(side=tk.RIGHT, padx=5)
        ttk.Button(btn_frame, text="Cancelar", bootstyle="secondary", command=dialog.destroy).pack(side=tk.RIGHT)
    
    def _editar_centro(self):
        messagebox.showinfo("Info", "Função de edição em desenvolvimento.", parent=self)
    
    def _ver_lancamentos(self):
        sel = self.tree.selection()
        if not sel:
            messagebox.showwarning("Atenção", "Selecione um centro de custo.", parent=self)
            return
        centro_id = self.tree.item(sel[0])['values'][0]
        centro_nome = self.tree.item(sel[0])['values'][2]
        
        lanc_win = tk.Toplevel(self)
        lanc_win.title(f"Lançamentos - {centro_nome}")
        responsive_geometry(lanc_win, 800, 500)
        lanc_win.transient(self)
        
        frame = ttk.Frame(lanc_win, padding=15)
        frame.pack(expand=True, fill=tk.BOTH)
        
        cols = ("data", "tipo", "descricao", "documento", "valor")
        tree = ttk.Treeview(frame, columns=cols, show="headings", height=18)
        tree.heading("data", text="Data")
        tree.heading("tipo", text="Tipo")
        tree.heading("descricao", text="Descrição")
        tree.heading("documento", text="Documento")
        tree.heading("valor", text="Valor")
        tree.column("data", width=100, anchor=tk.CENTER)
        tree.column("tipo", width=80, anchor=tk.CENTER)
        tree.column("descricao", width=300)
        tree.column("documento", width=120)
        tree.column("valor", width=120, anchor=tk.E)
        tree.pack(expand=True, fill=tk.BOTH)
        
        db = get_db()
        rows = db.fetchall("SELECT * FROM lancamentos_centro_custo WHERE centro_custo_id = %s ORDER BY data_lancamento DESC", (centro_id,))
        for r in rows:
            tree.insert("", tk.END, values=(
                r.get('data_lancamento', ''),
                r.get('tipo', '').title(),
                r.get('descricao', ''),
                r.get('documento', ''),
                format_br_currency(r.get('valor', 0))
            ))
    
    def _novo_lancamento(self):
        sel = self.tree.selection()
        if not sel:
            messagebox.showwarning("Atenção", "Selecione um centro de custo.", parent=self)
            return
        centro_id = self.tree.item(sel[0])['values'][0]
        centro_nome = self.tree.item(sel[0])['values'][2]
        
        dialog = tk.Toplevel(self)
        dialog.title(f"Novo Lançamento - {centro_nome}")
        responsive_geometry(dialog, 450, 400)
        dialog.transient(self)
        dialog.grab_set()
        
        frame = ttk.Frame(dialog, padding=20)
        frame.pack(expand=True, fill=tk.BOTH)
        
        ttk.Label(frame, text="Tipo:").pack(anchor=tk.W)
        tipo_var = tk.StringVar(value="despesa")
        tipo_frame = ttk.Frame(frame)
        tipo_frame.pack(anchor=tk.W, pady=(0, 10))
        ttk.Radiobutton(tipo_frame, text="Despesa", variable=tipo_var, value="despesa").pack(side=tk.LEFT, padx=5)
        ttk.Radiobutton(tipo_frame, text="Receita", variable=tipo_var, value="receita").pack(side=tk.LEFT, padx=5)
        
        ttk.Label(frame, text="Descrição:*").pack(anchor=tk.W)
        desc_var = tk.StringVar()
        ttk.Entry(frame, textvariable=desc_var, width=40).pack(fill=tk.X, pady=(0, 10))
        
        ttk.Label(frame, text="Valor (R$):*").pack(anchor=tk.W)
        valor_var = tk.StringVar(value="0,00")
        ttk.Entry(frame, textvariable=valor_var, width=15).pack(anchor=tk.W, pady=(0, 10))
        
        ttk.Label(frame, text="Documento/NF:").pack(anchor=tk.W)
        doc_var = tk.StringVar()
        ttk.Entry(frame, textvariable=doc_var, width=20).pack(anchor=tk.W, pady=(0, 10))
        
        ttk.Label(frame, text="Observação:").pack(anchor=tk.W)
        obs_var = tk.StringVar()
        ttk.Entry(frame, textvariable=obs_var, width=40).pack(fill=tk.X, pady=(0, 10))
        
        def salvar():
            if not desc_var.get().strip():
                messagebox.showerror("Erro", "Descrição é obrigatória!", parent=dialog)
                return
            valor = parse_br_float(valor_var.get())
            if not valor or valor <= 0:
                messagebox.showerror("Erro", "Valor inválido!", parent=dialog)
                return
            if registrar_lancamento_centro_custo(centro_id, tipo_var.get(), desc_var.get().strip(), valor, None, doc_var.get().strip(), obs_var.get().strip()):
                messagebox.showinfo("Sucesso", "Lançamento registrado!", parent=dialog)
                dialog.destroy()
                self._load_centros()
            else:
                messagebox.showerror("Erro", "Erro ao registrar lançamento.", parent=dialog)
        
        btn_frame = ttk.Frame(frame)
        btn_frame.pack(fill=tk.X, pady=(20, 0))
        ttk.Button(btn_frame, text="Salvar", bootstyle="success", command=salvar).pack(side=tk.RIGHT, padx=5)
        ttk.Button(btn_frame, text="Cancelar", bootstyle="secondary", command=dialog.destroy).pack(side=tk.RIGHT)
    
