    def _on_caixa_changed(self, event=None):
        """
        Callback chamado quando o usuario seleciona um caixa diferente no dropdown.
        Atualiza o caixa_selecionado e recarrega os dados do caixa correspondente.
        Se o caixa nao estiver aberto, pergunta se deseja abri-lo.
        """
        try:
            # Extrair o ID do caixa selecionado
            selecionado = self.caixa_var.get()
            if selecionado:
                caixa_id = int(selecionado.split(' - ')[0])
                self.caixa_selecionado = caixa_id
                
                # CARREGAR DADOS DO CAIXA SELECIONADO (cada caixa tem seus proprios dados)
                self.caixa_data = load_caixa_data(self.caixa_selecionado)
                
                # Limpar itens conferidos ao trocar de caixa
                self.itens_conferidos = set()
                
                # Atualizar informacoes do caixa
                self._update_caixa_info()
                
                # Log da mudanca
                log_user_action("Caixa", f"Caixa alterado para: {selecionado}")
                
                # Recarregar exibicao com os dados do novo caixa
                self._update_display()
                
                # Verificar se o caixa esta fechado e perguntar se deseja abrir
                status = self.caixa_data.get("status", "fechado")
                if status == "fechado":
                    caixa_nome = selecionado.split(' - ')[1] if ' - ' in selecionado else selecionado
                    resposta = messagebox.askyesno(
                        "Caixa Fechado",
                        f"O caixa '{caixa_nome}' esta fechado.\n\nDeseja abrir o caixa agora?",
                        parent=self
                    )
                    if resposta:
                        # Chamar a funcao de abrir caixa
                        self._toggle_caixa()
                
        except (ValueError, IndexError) as e:
            print(f"Erro ao mudar caixa: {e}")
    
    def _update_caixa_info(self):
        """
        Atualiza o label de informacoes do caixa selecionado (local/descricao).
        """
        try:
            caixa_atual = next((c for c in self.lista_caixas if c['id'] == self.caixa_selecionado), None)
            if caixa_atual:
                info_parts = []
                if caixa_atual.get('local'):
                    info_parts.append(f"Local: {caixa_atual['local']}")
                if caixa_atual.get('descricao'):
                    info_parts.append(caixa_atual['descricao'])
                
                info_text = " | ".join(info_parts) if info_parts else ""
                self.lbl_caixa_info.config(text=info_text)
            else:
                self.lbl_caixa_info.config(text="")
        except Exception as e:
            try:
                AUDITORIA.erro(f"Erro no sistema: {e}")
            except Exception:
                pass
            print(f"Erro ao atualizar info do caixa: {e}")
            self.lbl_caixa_info.config(text="")
    
    def _refresh_caixas_list(self):
        """
        Atualiza a lista de caixas no dropdown (util apos cadastrar novo caixa).
        """
        try:
            try:
                self.lista_caixas = get_caixas_permitidos_usuario(logged_user) if logged_user else get_caixas_pdv()
            except Exception:
                self.lista_caixas = get_caixas_pdv()
            if not self.lista_caixas:
                self.lista_caixas = [{'id': 1, 'nome': 'Caixa Principal', 'descricao': 'Caixa padrao do sistema', 'local': ''}]
            
            self.caixa_nomes = [f"{c['id']} - {c['nome']}" for c in self.lista_caixas]
            self.cmb_caixa['values'] = self.caixa_nomes
            
            # Manter selecao atual se ainda existir
            caixa_atual = next((c for c in self.lista_caixas if c['id'] == self.caixa_selecionado), None)
            if caixa_atual:
                self.caixa_var.set(f"{caixa_atual['id']} - {caixa_atual['nome']}")
            elif self.lista_caixas:
                self.caixa_selecionado = self.lista_caixas[0]['id']
                self.caixa_var.set(f"{self.lista_caixas[0]['id']} - {self.lista_caixas[0]['nome']}")
            
            self._update_caixa_info()
        except Exception as e:
            try:
                AUDITORIA.erro(f"Erro no sistema: {e}")
            except Exception:
                pass
            print(f"Erro ao atualizar lista de caixas: {e}")

    def _update_display(self):
        """
        Atualiza a exibicao da tela do caixa com todas as transacoes.
        Inclui: Vendas, Contas a Pagar, Contas a Receber, Suprimentos, Sangrias e outras.
        
        REGRA DE DEVOLUÇÃO NA TELA DO CAIXA:
        - Transações de devolução (DÉBITO com 'DEVOLU' na descrição) são ocultadas.
        - Cupons que tiveram devolução TOTAL são completamente ocultados da tela.
        - Cupons que tiveram devolução PARCIAL exibem apenas o valor RESTANTE
          (valor original - valor devolvido), sem mostrar a parte devolvida.
        - O saldo do caixa reflete corretamente apenas os valores não devolvidos.
        """
        try:
            # RECARREGAR dados do arquivo do caixa selecionado
            self.caixa_data = load_caixa_data(self.caixa_selecionado)
            
            # Garantir que transacoes é uma lista válida
            if not isinstance(self.caixa_data.get('transacoes'), list):
                self.caixa_data['transacoes'] = []
            
            status = self.caixa_data.get("status", "fechado")
            if status == "aberto":
                turno_nome = self.caixa_data.get('turno_nome', '')
                usuario_abertura = self.caixa_data.get('usuario_abertura', '')
                status_parts = ["CAIXA ABERTO"]
                if usuario_abertura:
                    status_parts.append(f"Usuário: {usuario_abertura}")
                if turno_nome:
                    status_parts.append(f"Turno: {turno_nome}")
                status_text = " - ".join(status_parts)
                self.lbl_status.config(text=status_text, bg="#28a745")
                self.btn_toggle_caixa.config(text="FECHAR CAIXA", bg="#dc3545")
            else:
                self.lbl_status.config(text="CAIXA FECHADO", bg="#dc3545")
                self.btn_toggle_caixa.config(text="ABRIR CAIXA", bg="#28a745")
                
            saldo_inicial = float(self.caixa_data.get("saldo_inicial", 0.0) or 0.0)
            self.lbl_saldo_inicial.config(text=f"Saldo Inicial: {format_br_currency(saldo_inicial)}")
            
            # ═══════════════════════════════════════════════════════════════════
            # CARREGAR DEVOLUÇÕES DO BANCO PARA FILTRAR CUPONS DEVOLVIDOS
            # ═══════════════════════════════════════════════════════════════════
            devolucoes_por_cupom = _obter_devolucoes_por_cupom_cache()
            
            # Calcular saldo atual com tratamento de erros
            # REGRA: Descontar do valor da venda o que já foi devolvido.
            #        Se devolução total, não soma nada. Se parcial, soma só o restante.
            #        Transações de devolução (DÉBITO) são ignoradas pois o ajuste
            #        já é feito diretamente no valor da venda original.
            saldo_atual = 0.0
            transacoes = self.caixa_data.get('transacoes', [])
            for t in transacoes:
                try:
                    if isinstance(t, dict):
                        # Filtrar transações de devolução - não exibir no caixa principal
                        descricao_t = str(t.get('descricao', '') or '').upper()
                        pagamento_t = str(t.get('pagamento', '') or '').upper()
                        if 'DEVOLU' in descricao_t or 'DEVOLU' in pagamento_t:
                            continue
                        
                        valor = float(t.get('valor', 0.0) or 0.0)
                        tipo = str(t.get('tipo', '')).upper()
                        
                        # Verificar se é uma venda com cupom que teve devolução
                        descricao_str = str(t.get('descricao', '') or '')
                        if 'Venda Cupom' in descricao_str:
                            try:
                                cupom_str = descricao_str.split('Cupom ')[1].split()[0]
                                cupom_num = int(cupom_str)
                                if cupom_num in devolucoes_por_cupom:
                                    valor_devolvido = devolucoes_por_cupom[cupom_num]
                                    valor_restante = valor - valor_devolvido
                                    if valor_restante <= 0.01:  # Devolução total - não soma nada
                                        continue
                                    else:  # Devolução parcial - soma apenas o restante
                                        valor = valor_restante
                            except (ValueError, IndexError):
                                pass
                        
                        if tipo == 'CRÉDITO' or tipo == 'CREDITO':
                            saldo_atual += valor
                        else:
                            saldo_atual -= valor
                except (ValueError, TypeError):
                    continue
            
            self.lbl_saldo_atual.config(text=f"Saldo Atual: {format_br_currency(saldo_atual)}")
            
            # Limpar tabela existente
            for i in self.tree_trans.get_children():
                self.tree_trans.delete(i)
            
            # Configurar cores das tags ANTES de inserir os itens
            self.tree_trans.tag_configure("credito", foreground="#155724", background="#d4edda")
            self.tree_trans.tag_configure("debito", foreground="#721c24", background="#f8d7da")
            self.tree_trans.tag_configure("conferido", foreground="#004085", background="#b8daff")
            # Tag especial para devoluções parciais - destaque visual
            self.tree_trans.tag_configure("credito_parcial", foreground="#856404", background="#fff3cd")
            self.tree_trans.tag_configure("conferido_parcial", foreground="#004085", background="#b8daff")
            
            # Criar índice para cada transação (usado para identificar itens conferidos)
            # Exibir transações em ordem reversa (mais recentes primeiro)
            for idx, t in enumerate(reversed(transacoes)):
                try:
                    # Verificar se t é um dicionário válido
                    if not isinstance(t, dict):
                        continue
                    
                    # Filtrar transações de devolução - não exibir no caixa principal
                    descricao_filtro = str(t.get('descricao', '') or '').upper()
                    pagamento_filtro = str(t.get('pagamento', '') or '').upper()
                    if 'DEVOLU' in descricao_filtro or 'DEVOLU' in pagamento_filtro:
                        continue
                    
                    # Calcular o índice real (na lista original, não invertida)
                    real_idx = len(transacoes) - 1 - idx
                    
                    # Verificar se está conferido
                    conferido = "✔" if real_idx in self.itens_conferidos else ""
                    
                    # Obter tipo da transação com tratamento
                    tipo_trans = str(t.get('tipo', '')).upper()
                    
                    # Extração de dados com tratamento robusto
                    h = str(t.get('hora', '') or '')
                    tp = tipo_trans if tipo_trans else 'N/A'
                    ds = str(t.get('descricao', '') or '')
                    pg = str(t.get('pagamento', '') or '')
                    cl = str(t.get('cliente', '') or '')
                    
                    # Formatar valor com tratamento de erro
                    try:
                        valor_num = float(t.get('valor', 0.0) or 0.0)
                    except (ValueError, TypeError):
                        valor_num = 0.0
                    
                    # ═══════════════════════════════════════════════════════════════
                    # LÓGICA DE DEVOLUÇÃO: Ocultar cupons devolvidos ou ajustar valor
                    # ═══════════════════════════════════════════════════════════════
                    is_devolucao_parcial = False
                    if 'Venda Cupom' in ds:
                        try:
                            cupom_str = ds.split('Cupom ')[1].split()[0]
                            cupom_num = int(cupom_str)
                            if cupom_num in devolucoes_por_cupom:
                                valor_devolvido = devolucoes_por_cupom[cupom_num]
                                valor_restante = valor_num - valor_devolvido
                                if valor_restante <= 0.01:
                                    # DEVOLUÇÃO TOTAL: Ocultar completamente este cupom
                                    continue
                                else:
                                    # DEVOLUÇÃO PARCIAL: Exibir apenas o valor restante
                                    is_devolucao_parcial = True
                                    valor_num = valor_restante
                                    ds = f"{ds} (Restante - Dev. Parcial: {format_br_currency(valor_devolvido)})"
                        except (ValueError, IndexError):
                            pass
                    
                    vl = format_br_currency(valor_num)
                    
                    # Determinar a tag base (crédito ou débito)
                    if real_idx in self.itens_conferidos:
                        tag = "conferido_parcial" if is_devolucao_parcial else "conferido"
                    elif is_devolucao_parcial:
                        tag = "credito_parcial"
                    elif tipo_trans in ('CRÉDITO', 'CREDITO'):
                        tag = "credito"
                    else:
                        tag = "debito"
                    
                    # Tentar recuperar dados do log de vendas se estiverem faltando na transação do caixa
                    if "Venda Cupom" in ds:
                        try:
                            cupom_str = ds.split("Cupom ")[1].split()[0]  # Pega apenas o número
                            cupom_num = int(cupom_str)
                            # Buscar no log de vendas do app principal
                            if hasattr(self.parent_app, 'sales_log') and self.parent_app.sales_log:
                                venda_ref = next((v for v in self.parent_app.sales_log if v.get('coupon_number') == cupom_num), None)
                                if venda_ref:
                                    if not pg or pg == "" or pg == "N/A":
                                        f_pag = venda_ref.get('formas_pagamento', {})
                                        if isinstance(f_pag, dict):
                                            pg = ", ".join([str(k) for k, v in f_pag.items() if v and float(v) > 0])
                                    if not cl or cl == "" or cl == "Consumidor":
                                        cl = venda_ref.get('cliente_nome', 'Consumidor')
                        except Exception:
                            pass
                    
                    # Tentar recuperar dados de contas a pagar
                    if "PAGTO CONTA" in ds.upper():
                        if not pg:
                            pg = "Pagamento"
                    
                    # Tentar recuperar dados de contas a receber
                    if "RECEBTO CONTA" in ds.upper():
                        if not pg:
                            pg = "Recebimento"

                    # Inserir na tabela (Treeview) com o índice real como iid
                    # Usar try/except para evitar erros de iid duplicado
                    try:
                        self.tree_trans.insert('', tk.END, iid=str(real_idx), values=(conferido, h, tp, ds, pg, cl, vl), tags=(tag,))
                    except tk.TclError:
                        # Se o iid já existir, usar um iid único
                        unique_iid = f"{real_idx}_{idx}"
                        self.tree_trans.insert('', tk.END, iid=unique_iid, values=(conferido, h, tp, ds, pg, cl, vl), tags=(tag,))
                
                except Exception as e:
                    # Log do erro mas continua processando outras transações
                    logging.error(f"Erro ao processar transação {idx}: {e}")
                    continue
            
            # Forçar atualização da interface
            self.update_idletasks()
            
        except Exception as e:
            logging.error(f"Erro crítico ao atualizar display do caixa: {e}")
            # Tentar exibir mensagem de erro na interface
            try:
                self.lbl_status.config(text="ERRO AO CARREGAR", bg="#ffc107")
            except:
                pass
        self.update()

    def _toggle_caixa(self):
        status = self.caixa_data.get("status", "fechado")
        if status == "fechado":
            # Janela de Entrada Personalizada para Abertura
            input_win = tk.Toplevel(self)
            input_win.title("Abertura de Caixa")
            responsive_geometry(input_win, 450, 480)
            input_win.resizable(True, True)
            input_win.configure(bg='#f8f9fa')
            input_win.transient(self)
            input_win.grab_set()
            
            # Centralizar
            input_win.update_idletasks()
            x = self.winfo_x() + (self.winfo_width() // 2) - (450 // 2)
            y = self.winfo_y() + (self.winfo_height() // 2) - (480 // 2)
            input_win.geometry(f"+{x}+{y}")

            # Título
            tk.Label(input_win, text="💰 ABERTURA DE CAIXA", font=("Segoe UI", 14, "bold"), bg='#f8f9fa', fg='#333').pack(pady=(15, 10))
            
            # Frame para os campos
            frame_campos = tk.Frame(input_win, bg='#f8f9fa')
            frame_campos.pack(fill=tk.X, padx=20)

            # Seleção de Usuário (OBRIGATÓRIO)
            tk.Label(frame_campos, text="USUÁRIO:", font=("Segoe UI", 10, "bold"), bg='#f8f9fa', fg='#dc3545').pack(anchor=tk.W, pady=(10, 2))
            
            # Carregar usuários disponíveis
            usuarios_disponiveis = load_users()
            usuario_var = tk.StringVar()
            usuario_options = sorted([username for username in usuarios_disponiveis.keys()])
            
            if usuario_options:
                cmb_usuario = ttk.Combobox(frame_campos, textvariable=usuario_var, values=usuario_options, state='readonly', font=("Segoe UI", 11), width=38)
                cmb_usuario.pack(fill=tk.X, pady=2)
                # Pré-selecionar o usuário logado atual
                if logged_user in usuario_options:
                    cmb_usuario.set(logged_user)
                else:
                    cmb_usuario.set('')
            else:
                tk.Label(frame_campos, text="Nenhum usuário cadastrado!", font=("Segoe UI", 10), bg='#f8f9fa', fg='#dc3545').pack(pady=2)
                usuario_var.set('')

            # Senha do Usuário (OBRIGATÓRIO)
            tk.Label(frame_campos, text="SENHA:", font=("Segoe UI", 10, "bold"), bg='#f8f9fa', fg='#dc3545').pack(anchor=tk.W, pady=(10, 2))
            
            entry_senha = tk.Entry(frame_campos, font=("Segoe UI", 12), show="*")
            entry_senha.pack(fill=tk.X, pady=2)

            # Seleção de Turno (OBRIGATÓRIO)
            tk.Label(frame_campos, text="TURNO:", font=("Segoe UI", 10, "bold"), bg='#f8f9fa', fg='#dc3545').pack(anchor=tk.W, pady=(10, 2))
            
            # Carregar turnos disponíveis (filtrados pelo vínculo do usuário)
            turno_var = tk.StringVar()
            turno_frame_container = tk.Frame(frame_campos, bg='#f8f9fa')
            turno_frame_container.pack(fill=tk.X, pady=2)
            
            def _atualizar_turnos_por_usuario(*args):
                """Atualiza a lista de turnos conforme o usuário selecionado."""
                for widget in turno_frame_container.winfo_children():
                    widget.destroy()
                usr = usuario_var.get().strip()
                try:
                    turnos_disponiveis = get_turnos_permitidos_usuario(usr) if usr else get_turnos()
                except Exception:
                    turnos_disponiveis = get_turnos()
                turno_opts = [f"{t['id']} - {t['nome']} ({t.get('hora_inicio', '')} - {t.get('hora_fim', '')})" for t in turnos_disponiveis]
                if turno_opts:
                    cmb_t = ttk.Combobox(turno_frame_container, textvariable=turno_var, values=turno_opts, state='readonly', font=("Segoe UI", 11), width=38)
                    cmb_t.pack(fill=tk.X)
                    turno_var.set('')
                else:
                    tk.Label(turno_frame_container, text="Nenhum turno disponível para este usuário!", font=("Segoe UI", 10), bg='#f8f9fa', fg='#dc3545').pack()
                    turno_var.set('')
            
            usuario_var.trace_add('write', _atualizar_turnos_por_usuario)
            _atualizar_turnos_por_usuario()  # Carrega inicialmente

            # Valor do Fundo de Caixa
            tk.Label(frame_campos, text="VALOR DO FUNDO DE CAIXA (R$):", font=("Segoe UI", 10, "bold"), bg='#f8f9fa').pack(anchor=tk.W, pady=(10, 2))
            
            entry_val = tk.Entry(frame_campos, font=("Segoe UI", 14), justify='center')
            entry_val.pack(fill=tk.X, pady=2)
            entry_val.insert(0, "0,00")
            entry_senha.focus_set()

            def confirmar_abertura(event=None):
                # Validar seleção de usuário (OBRIGATÓRIO)
                usuario_selecionado = usuario_var.get()
                if not usuario_selecionado:
                    messagebox.showerror("Usuário Obrigatório", "É obrigatório selecionar um usuário para abrir o caixa!", parent=input_win)
                    return
                
                # Validar senha (OBRIGATÓRIO)
                senha_digitada = entry_senha.get()
                if not senha_digitada:
                    messagebox.showerror("Senha Obrigatória", "É obrigatório informar a senha do usuário!", parent=input_win)
                    entry_senha.focus_set()
                    return
                
                # Verificar senha do usuário
                user_data = usuarios_disponiveis.get(usuario_selecionado, {})
                senha_hash = user_data.get('password', '')
                
                if not verify_password(senha_digitada, senha_hash):
                    messagebox.showerror("Senha Incorreta", "A senha informada está incorreta!\n\nVerifique e tente novamente.", parent=input_win)
                    entry_senha.delete(0, tk.END)
                    entry_senha.focus_set()
                    return
                
                # Validar seleção de turno (OBRIGATÓRIO)
                turno_selecionado = turno_var.get()
                if not turno_selecionado:
                    messagebox.showerror("Turno Obrigatório", "É obrigatório selecionar um turno para abrir o caixa!", parent=input_win)
                    return
                
                # Extrair ID e nome do turno
                turno_id = turno_selecionado.split(' - ')[0]
                turno_nome = turno_selecionado.split(' - ')[1].split(' (')[0] if ' - ' in turno_selecionado else turno_selecionado
                
                val_str = entry_val.get()
                valor = parse_br_float(val_str)
                if valor is not None:
                    self.caixa_data = {
                        "status": "aberto",
                        "data_abertura": datetime.datetime.now().strftime('%d/%m/%Y %H:%M:%S'),
                        "saldo_inicial": valor,
                        "transacoes": [],
                        "usuario_abertura": usuario_selecionado,
                        "turno_id": turno_id,
                        "turno_nome": turno_nome
                    }
                    # Adiciona a transação inicial de abertura para exibição imediata
                    self.caixa_data["transacoes"].append({
                        "hora": datetime.datetime.now().strftime('%H:%M:%S'),
                        "tipo": "CRÉDITO",
                        "descricao": f"SALDO INICIAL (ABERTURA) - Turno: {turno_nome}",
                        "valor": valor,
                        "pagamento": "Dinheiro",
                        "cliente": usuario_selecionado
                    })
                    save_caixa_data(self.caixa_selecionado, self.caixa_data)
                    log_user_action("Caixa", f"Caixa {self.caixa_selecionado} aberto por {usuario_selecionado} com saldo inicial de {format_br_currency(valor)} - Turno: {turno_nome}")
                    input_win.destroy()
                    self._update_display()
                    messagebox.showinfo("Sucesso", f"Caixa aberto com sucesso!\n\nUsuário: {usuario_selecionado}\nTurno: {turno_nome}\nSaldo Inicial: {format_br_currency(valor)}")
                    self._exibir_tela_impressao_operacao_caixa(
                        titulo_operacao="COMPROVANTE DE ABERTURA DE CAIXA",
                        detalhes=[
                            ("Caixa:", f"{self.caixa_selecionado} - {self._get_caixa_nome_selecionado()}"),
                            ("Usuário da Abertura:", usuario_selecionado),
                            ("Turno:", turno_nome),
                            ("Saldo Inicial:", format_br_currency(valor)),
                            ("Status do Caixa:", "ABERTO")
                        ],
                        titulo_janela="🧾 Abertura de Caixa",
                        titulo_cabecalho="COMPROVANTE DE ABERTURA DE CAIXA",
                        mensagem="A abertura foi registrada com sucesso. Escolha uma opção abaixo para imprimir, salvar ou apenas visualizar.",
                        pdf_titulo="Comprovante de Abertura de Caixa",
                        nome_arquivo_prefixo="Abertura_Caixa"
                    )
                else:
                    messagebox.showerror("Erro", "Valor inválido! Use o formato 0,00", parent=input_win)

            btn_confirmar = tk.Button(input_win, text="CONFIRMAR ABERTURA", font=("Segoe UI", 10, "bold"), bg="#28a745", fg="white", command=confirmar_abertura, pady=10, cursor="hand2")
            btn_confirmar.pack(pady=15, padx=20, fill=tk.X)
            
            btn_cancelar = tk.Button(input_win, text="CANCELAR", font=("Segoe UI", 10), bg="#6c757d", fg="white", command=input_win.destroy, pady=8, cursor="hand2")
            btn_cancelar.pack(pady=(0, 15), padx=20, fill=tk.X)
            
            input_win.bind("<Return>", confirmar_abertura)
            input_win.bind("<Escape>", lambda e: input_win.destroy())
        else:
            # Fechar Caixa
            if messagebox.askyesno("Fechar Caixa", "Deseja realmente fechar o caixa agora%s"):
                # Gera resumo de fechamento
                saldo_inicial = float(self.caixa_data.get("saldo_inicial", 0.0) or 0.0)
                # O saldo inicial já está incluído nas transações de CRÉDITO
                # Calcular totais com tratamento para variações de tipo (CRÉDITO/CREDITO, DÉBITO/DEBITO)
                total_creditos = 0.0
                total_debitos = 0.0
                for t in self.caixa_data.get('transacoes', []):
                    try:
                        if isinstance(t, dict):
                            tipo = str(t.get('tipo', '')).upper()
                            valor = float(t.get('valor', 0.0) or 0.0)
                            if tipo in ('CRÉDITO', 'CREDITO'):
                                total_creditos += valor
                            elif tipo in ('DÉBITO', 'DEBITO'):
                                total_debitos += valor
                    except (ValueError, TypeError):
                        continue
                saldo_final = total_creditos - total_debitos
                
                # Salvar registro de fechamento no histórico
                fechamento_registro = {
                    "id": datetime.datetime.now().strftime('%Y%m%d%H%M%S'),
                    "data_abertura": self.caixa_data.get('data_abertura'),
                    "data_fechamento": datetime.datetime.now().strftime('%d/%m/%Y %H:%M:%S'),
                    "usuario_abertura": self.caixa_data.get('usuario_abertura'),
                    "usuario_fechamento": logged_user,
                    "turno_id": self.caixa_data.get('turno_id', ''),
                    "turno_nome": self.caixa_data.get('turno_nome', ''),
                    "saldo_inicial": saldo_inicial,
                    "total_creditos": total_creditos,
                    "total_debitos": total_debitos,
                    "saldo_final": saldo_final,
                    "transacoes": self.caixa_data.get('transacoes', []).copy()
                }
                
                # Carregar historico de fechamentos do caixa especifico e adicionar novo registro
                fechamentos = load_fechamentos_caixa(self.caixa_selecionado)
                fechamentos.append(fechamento_registro)
                save_fechamentos_caixa(self.caixa_selecionado, fechamentos)
                
                # IMPRIMIR RELATORIO DE FECHAMENTO PROFISSIONAL
                self._imprimir_fechamento_caixa(fechamento_registro)
                
                # Zerar o caixa para proxima abertura
                self.caixa_data = {
                    "status": "fechado",
                    "transacoes": [],
                    "saldo_inicial": 0.0,
                    "caixa_id": self.caixa_selecionado
                }
                save_caixa_data(self.caixa_selecionado, self.caixa_data)
                log_user_action("Caixa", f"Caixa {self.caixa_selecionado} fechado. Saldo final: {format_br_currency(saldo_final)}")
                self._update_display()
    
