class BackupManager:
    """Gerencia a criação, listagem e restauração de backups do sistema."""
    def __init__(self, parent_app):
        self.app = parent_app
        self.root = parent_app.root
        self.backup_dir = os.path.join(PERSISTENCE_DIR, "pdv_backups")
        if not os.path.exists(self.backup_dir):
            os.makedirs(self.backup_dir)

    def create_backup(self, manual=True):
        """Cria um backup compactado de todos os arquivos JSON do sistema."""
        timestamp = datetime.datetime.now().strftime("%Y%m%d_%H%M%S")
        filename = f"backup_pdv_{timestamp}.zip"
        filepath = os.path.join(self.backup_dir, filename)

        try:
            with file_lock:
                with zipfile.ZipFile(filepath, 'w', zipfile.ZIP_DEFLATED) as zipf:
                    for root, dirs, files in os.walk(DATA_DIR):
                        for file in files:
                            if file.endswith('.json'):
                                file_full_path = os.path.join(root, file)
                                arcname = os.path.relpath(file_full_path, DATA_DIR)
                                zipf.write(file_full_path, arcname)
            if manual: messagebox.showinfo("Sucesso", f"Backup criado: {filename}")
            return True
        except Exception as e:
            if manual: messagebox.showerror("Erro", f"Falha ao criar backup: {e}")
            return False

    def show_backup_window(self):
        """Interface para gerenciar backups."""
        win = tk.Toplevel(self.root)
        win.title("📦 Gerenciador de Backup e Restauração")
        win.state('zoomed')
        win.transient(self.root)
        win.grab_set()

        main_frame = ttk.Frame(win, padding=20)
        main_frame.pack(expand=True, fill=tk.BOTH)

        ttk.Label(main_frame, text="📦 Backups do Sistema", font=("Segoe UI", 14, "bold")).pack(pady=(0, 10))

        list_frame = ttk.Frame(main_frame)
        list_frame.pack(expand=True, fill=tk.BOTH)

        columns = ("arquivo", "data", "tamanho")
        self.tree = ttk.Treeview(list_frame, columns=columns, show="headings", height=10)
        self.tree.heading("arquivo", text="Arquivo")
        self.tree.heading("data", text="Data de Criação")
        self.tree.heading("tamanho", text="Tamanho")
        self.tree.column("arquivo", width=250)
        self.tree.column("data", width=150)
        self.tree.column("tamanho", width=100)
        
        scrollbar = ttk.Scrollbar(list_frame, orient=tk.VERTICAL, command=self.tree.yview)
        self.tree.configure(yscroll=scrollbar.set)
        self.tree.pack(side=tk.LEFT, expand=True, fill=tk.BOTH)
        scrollbar.pack(side=tk.RIGHT, fill=tk.Y)

        btn_frame = ttk.Frame(main_frame, padding=(0, 20, 0, 0))
        btn_frame.pack(fill=tk.X)

        ttk.Button(btn_frame, text="Criar Novo Backup", bootstyle="success", 
                  command=lambda: [self.create_backup(), self.refresh_list()]).pack(side=tk.LEFT, padx=5)
        
        ttk.Button(btn_frame, text="Restaurar Selecionado", bootstyle="danger", 
                  command=self.restore_selected).pack(side=tk.LEFT, padx=5)
        
        ttk.Button(btn_frame, text="Excluir", bootstyle="warning", 
                  command=self.delete_selected).pack(side=tk.LEFT, padx=5)

        self.refresh_list()

    def refresh_list(self):
        for item in self.tree.get_children(): self.tree.delete(item)
        if not os.path.exists(self.backup_dir): return
        backups = sorted([f for f in os.listdir(self.backup_dir) if f.endswith('.zip')], reverse=True)
        for b in backups:
            path = os.path.join(self.backup_dir, b)
            stats = os.stat(path)
            size = f"{stats.st_size / 1024:.1f} KB"
            date = datetime.datetime.fromtimestamp(stats.st_mtime).strftime("%d/%m/%Y %H:%M:%S")
            self.tree.insert("", tk.END, values=(b, date, size))

    def restore_selected(self):
        selected = self.tree.selection()
        if not selected: return
        filename = self.tree.item(selected[0])['values'][0]
        filepath = os.path.join(self.backup_dir, filename)
        if not messagebox.askyesno("⚠️ RESTAURAÇÃO CRÍTICA", "ISSO IRÁ SUBSTITUIR TODOS OS DADOS ATUAIS!\nDeseja continuar%s"): return
        try:
            self.create_backup(manual=False)
            with file_lock:
                with zipfile.ZipFile(filepath, 'r') as zipf:
                    zipf.extractall(DATA_DIR)
            messagebox.showinfo("Sucesso", "Restauração concluída! O sistema será fechado.")
            self.root.destroy()
            os._exit(0)
        except Exception as e: messagebox.showerror("Erro", f"Falha na restauração: {e}")

    def delete_selected(self):
        selected = self.tree.selection()
        if not selected: return
        filename = self.tree.item(selected[0])['values'][0]
        if messagebox.askyesno("Confirmar", f"Excluir {filename}%s"):
            try:
                os.remove(os.path.join(self.backup_dir, filename))
                self.refresh_list()
            except Exception as e: messagebox.showerror("Erro", f"Erro ao excluir: {e}")

