        ttk.Button(diag_frame, text="Injetar Vazamento de Memória (1GB)", bootstyle="dark", command=self.run_memory_leak_test).pack(fill=tk.X, pady=5)

        # Aba 5: Logs
        log_frame = ttk.Frame(notebook, padding=15)
