    def __init__(self, root, config_file: str = None):
        self.root = root
        self.config_file = config_file or os.path.join(DATA_DIR, 'theme_config.json')
        self.current_theme = 'light'
        self.auto_mode = False
        self._callbacks = []
        self._load_preferences()
    
    def _load_preferences(self):
        """Carrega preferências salvas."""
        try:
            if os.path.exists(self.config_file):
                with open(self.config_file, 'r', encoding='utf-8') as f:
                    prefs = json.load(f)
                    self.current_theme = prefs.get('theme', 'light')
                    self.auto_mode = prefs.get('auto_mode', False)
        except Exception:
            pass
    
    def _save_preferences(self):
        """Salva preferências."""
        try:
            os.makedirs(os.path.dirname(self.config_file), exist_ok=True)
            with open(self.config_file, 'w', encoding='utf-8') as f:
                json.dump({
                    'theme': self.current_theme,
                    'auto_mode': self.auto_mode
                }, f)
        except Exception:
            pass
    
    def set_theme(self, theme_name: str):
        """Define o tema atual."""
        if theme_name not in self.THEMES:
            return False
        
        self.current_theme = theme_name
        theme = self.THEMES[theme_name]
        
        # Aplica o tema via ttkbootstrap
        try:
            self.root.style.theme_use(theme['bootstyle'])
        except Exception:
            pass
        
        # Notifica callbacks
        for callback in self._callbacks:
            try:
                callback(theme_name, theme)
            except Exception:
                pass
        
        self._save_preferences()
        return True
    
    def get_theme(self) -> dict:
        """Retorna o tema atual."""
        return self.THEMES.get(self.current_theme, self.THEMES['light'])
    
    def get_color(self, color_name: str) -> str:
        """Retorna uma cor específica do tema atual."""
        theme = self.get_theme()
        return theme.get(color_name, '#000000')
    
    def toggle_theme(self):
        """Alterna entre tema claro e escuro."""
        if self.current_theme == 'dark':
            self.set_theme('light')
        else:
            self.set_theme('dark')
    
    def set_auto_mode(self, enabled: bool):
        """Ativa/desativa modo automático dia/noite."""
        self.auto_mode = enabled
        if enabled:
            self._check_auto_theme()
        self._save_preferences()
    
    def _check_auto_theme(self):
        """Verifica e aplica tema baseado na hora."""
        if not self.auto_mode:
            return
        
        hour = datetime.datetime.now().hour
        if 6 <= hour < 18:
            self.set_theme('light')
        else:
            self.set_theme('dark')
    
    def on_theme_change(self, callback):
        """Registra callback para mudança de tema."""
        self._callbacks.append(callback)
    
    def get_available_themes(self) -> list:
        """Retorna lista de temas disponíveis."""
        return [(key, value['name']) for key, value in self.THEMES.items()]


