# SISTEMA DE ATALHOS DE TECLADO AVANÇADO
# ═══════════════════════════════════════════════════════════════════════════════════════

class KeyboardShortcutManager:
    """
    Gerenciador de Atalhos de Teclado Avançado.
    
    Características:
    - Atalhos globais e contextuais
    - Combinações de teclas (Ctrl+, Alt+, Shift+)
    - Personalização de atalhos
    - Conflito de atalhos detectado
    - Ajuda de atalhos integrada
    
    Uso:
        shortcuts = KeyboardShortcutManager(root)
        shortcuts.register('Ctrl+S', save_function, 'Salvar')
        shortcuts.register('F2', edit_function, 'Editar')
        shortcuts.show_help()
    """
    
    # Atalhos padrão do sistema
    DEFAULT_SHORTCUTS = {
        # Navegação
        'F1': ('Ajuda', 'help'),
        'F2': ('Editar Item', 'edit'),
        'F3': ('Buscar', 'search'),
        'F4': ('Nova Venda', 'new_sale'),
        'F5': ('Atualizar', 'refresh'),
        'F6': ('Clientes', 'customers'),
        'F7': ('Produtos', 'products'),
        'F8': ('Relatórios', 'reports'),
        'F9': ('Configurações', 'settings'),
        'F10': ('Menu', 'menu'),
        'F11': ('Tela Cheia', 'fullscreen'),
        'F12': ('Fechar Caixa', 'close_register'),
        
        # Operações com Ctrl
        'Ctrl+N': ('Novo', 'new'),
        'Ctrl+S': ('Salvar', 'save'),
        'Ctrl+P': ('Imprimir', 'print'),
        'Ctrl+F': ('Buscar', 'find'),
        'Ctrl+Z': ('Desfazer', 'undo'),
        'Ctrl+Y': ('Refazer', 'redo'),
        'Ctrl+Q': ('Sair', 'quit'),
        'Ctrl+B': ('Backup', 'backup'),
        'Ctrl+E': ('Exportar', 'export'),
        'Ctrl+I': ('Importar', 'import'),
        
        # Operações com Alt
        'Alt+F4': ('Fechar', 'close'),
        'Alt+Enter': ('Tela Cheia', 'fullscreen'),
        
        # PDV Específicos
        'Enter': ('Confirmar/Adicionar', 'confirm'),
        'Escape': ('Cancelar', 'cancel'),
        'Delete': ('Remover Item', 'delete'),
        '+': ('Aumentar Quantidade', 'qty_up'),
        '-': ('Diminuir Quantidade', 'qty_down'),
        '*': ('Multiplicar', 'multiply'),
        '/': ('Dividir', 'divide'),
    }
    
    def __init__(self, root):
        self.root = root
        self.shortcuts = {}
        self.contexts = {}
        self.current_context = 'global'
        self._help_window = None
    
    def register(self, shortcut: str, callback, description: str = "",
                 context: str = 'global'):
        """
        Registra um atalho de teclado.
        
        Args:
            shortcut: Combinação de teclas (ex: 'Ctrl+S', 'F2')
            callback: Função a ser chamada
            description: Descrição do atalho
            context: Contexto onde o atalho é válido
        """
        key = self._normalize_shortcut(shortcut)
        
        if context not in self.contexts:
            self.contexts[context] = {}
        
        self.contexts[context][key] = {
            'callback': callback,
            'description': description,
            'shortcut': shortcut
        }
        
        # Bind global
        if context == 'global':
            self._bind_shortcut(key, callback)
    
    def unregister(self, shortcut: str, context: str = 'global'):
        """Remove um atalho."""
        key = self._normalize_shortcut(shortcut)
        
        if context in self.contexts and key in self.contexts[context]:
            del self.contexts[context][key]
            
            if context == 'global':
                self._unbind_shortcut(key)
    
    def _normalize_shortcut(self, shortcut: str) -> str:
        """Normaliza o formato do atalho."""
        parts = shortcut.lower().replace(' ', '').split('+')
        modifiers = []
        key = ''
        
        for part in parts:
            if part in ['ctrl', 'control']:
                modifiers.append('Control')
            elif part in ['alt']:
                modifiers.append('Alt')
            elif part in ['shift']:
                modifiers.append('Shift')
            else:
                key = part.capitalize() if len(part) > 1 else part
        
        if modifiers:
            return '-'.join(modifiers) + '-' + key
        return key
    
    def _bind_shortcut(self, key: str, callback):
        """Faz o bind do atalho."""
        try:
            self.root.bind(f'<{key}>', lambda e: callback())
        except tk.TclError:
            pass
    
    def _unbind_shortcut(self, key: str):
        """Remove o bind do atalho."""
        try:
            self.root.unbind(f'<{key}>')
        except tk.TclError:
            pass
    
    def set_context(self, context: str):
        """Define o contexto atual."""
        self.current_context = context
    
    def get_shortcuts(self, context: str = None) -> dict:
        """Retorna atalhos de um contexto."""
        if context is None:
            context = self.current_context
        return self.contexts.get(context, {})
    
    def show_help(self):
        """Mostra janela de ajuda moderna com informações do sistema e atalhos."""
        if self._help_window and self._help_window.winfo_exists():
            self._help_window.lift()
            return
        
        self._help_window = tk.Toplevel(self.root)
        self._help_window.title("Central de Ajuda & Sobre o Sistema")
        responsive_geometry(self._help_window, 1000, 800)
