        canvas.configure(yscrollcommand=scrollbar.set)
        
        canvas.pack(side="left", fill="both", expand=True, padx=10)
        scrollbar.pack(side="right", fill="y")
        
        # --- HEADER ---
        header_frame = tk.Frame(scrollable_frame, bg=BG_DARK, pady=30)
