        about_frame = tk.LabelFrame(scrollable_frame, text=" ℹ️ Sobre o Sistema ", font=("Segoe UI", 12, "bold"),
                                   fg=ACCENT, bg=BG_DARK, padx=20, pady=20, relief='flat', highlightthickness=1, highlightbackground=CARD_BG)
