# SISTEMA DE MÉTRICAS E ANALYTICS EM TEMPO REAL
# ═══════════════════════════════════════════════════════════════════════════════════════

class AnalyticsEngine:
    """
    Motor de Analytics e Métricas em Tempo Real.
    
    Características:
    - Coleta automática de métricas
    - Dashboard de performance
    - Análise de tendências
    - Alertas inteligentes
    - Exportação de dados
    - Previsões baseadas em histórico
    
    Uso:
        analytics = AnalyticsEngine()
        analytics.track_sale(sale_data)
        analytics.get_daily_summary()
        analytics.predict_sales(days=7)
    """
    
    def __init__(self, data_dir: str = None):
        self.data_dir = data_dir or DATA_DIR
        self.metrics_file = os.path.join(self.data_dir, 'analytics.json')
        self._metrics = {
            'sales': [],
            'products': {},
            'customers': {},
            'hourly': {},
            'daily': {},
            'monthly': {},
        }
        self._load_metrics()
    
    def _load_metrics(self):
        """Carrega métricas salvas."""
        try:
            if os.path.exists(self.metrics_file):
                with open(self.metrics_file, 'r', encoding='utf-8') as f:
                    self._metrics = json.load(f)
        except Exception:
            pass
    
    def _save_metrics(self):
        """Salva métricas."""
        try:
            os.makedirs(os.path.dirname(self.metrics_file), exist_ok=True)
            with open(self.metrics_file, 'w', encoding='utf-8') as f:
                json.dump(self._metrics, f, indent=2, default=str)
        except Exception:
            pass
    
    def track_sale(self, sale_data: dict):
        """Registra uma venda para análise."""
        timestamp = datetime.datetime.now()
        
        # Adiciona à lista de vendas
        self._metrics['sales'].append({
            'timestamp': timestamp.isoformat(),
            'total': sale_data.get('total', 0),
            'items': sale_data.get('items', []),
            'payment_method': sale_data.get('payment_method', 'dinheiro'),
            'customer_id': sale_data.get('customer_id'),
        })
        
        # Atualiza métricas horárias
        hour_key = timestamp.strftime('%Y-%m-%d-%H')
        if hour_key not in self._metrics['hourly']:
            self._metrics['hourly'][hour_key] = {'count': 0, 'total': 0}
        self._metrics['hourly'][hour_key]['count'] += 1
        self._metrics['hourly'][hour_key]['total'] += sale_data.get('total', 0)
        
        # Atualiza métricas diárias
        day_key = timestamp.strftime('%Y-%m-%d')
        if day_key not in self._metrics['daily']:
            self._metrics['daily'][day_key] = {'count': 0, 'total': 0}
        self._metrics['daily'][day_key]['count'] += 1
        self._metrics['daily'][day_key]['total'] += sale_data.get('total', 0)
        
        # Atualiza métricas mensais
        month_key = timestamp.strftime('%Y-%m')
        if month_key not in self._metrics['monthly']:
            self._metrics['monthly'][month_key] = {'count': 0, 'total': 0}
        self._metrics['monthly'][month_key]['count'] += 1
        self._metrics['monthly'][month_key]['total'] += sale_data.get('total', 0)
        
        # Atualiza produtos
        for item in sale_data.get('items', []):
            product_id = str(item.get('id', ''))
            if product_id not in self._metrics['products']:
                self._metrics['products'][product_id] = {'count': 0, 'total': 0}
            self._metrics['products'][product_id]['count'] += item.get('qty', 1)
            self._metrics['products'][product_id]['total'] += item.get('subtotal', 0)
        
        self._save_metrics()
    
    def get_daily_summary(self, date: datetime.date = None) -> dict:
        """Retorna resumo do dia."""
        if date is None:
            date = datetime.date.today()
        
        day_key = date.strftime('%Y-%m-%d')
        daily = self._metrics['daily'].get(day_key, {'count': 0, 'total': 0})
        
        return {
            'date': day_key,
            'sales_count': daily['count'],
            'total_revenue': daily['total'],
            'average_ticket': daily['total'] / daily['count'] if daily['count'] > 0 else 0,
        }
    
    def get_monthly_summary(self, year: int = None, month: int = None) -> dict:
        """Retorna resumo do mês."""
        if year is None or month is None:
            now = datetime.date.today()
            year = now.year
            month = now.month
        
        month_key = f'{year}-{month:02d}'
        monthly = self._metrics['monthly'].get(month_key, {'count': 0, 'total': 0})
        
        return {
            'month': month_key,
            'sales_count': monthly['count'],
            'total_revenue': monthly['total'],
            'average_ticket': monthly['total'] / monthly['count'] if monthly['count'] > 0 else 0,
        }
    
    def get_top_products(self, limit: int = 10) -> list:
        """Retorna produtos mais vendidos."""
        products = []
        for product_id, data in self._metrics['products'].items():
            products.append({
                'id': product_id,
                'count': data['count'],
                'total': data['total']
            })
        
        products.sort(key=lambda x: x['count'], reverse=True)
        return products[:limit]
    
    def get_hourly_distribution(self, date: datetime.date = None) -> dict:
        """Retorna distribuição de vendas por hora."""
        if date is None:
            date = datetime.date.today()
        
        day_prefix = date.strftime('%Y-%m-%d')
        distribution = {}
        
        for hour in range(24):
            hour_key = f'{day_prefix}-{hour:02d}'
            data = self._metrics['hourly'].get(hour_key, {'count': 0, 'total': 0})
            distribution[f'{hour:02d}:00'] = data
        
        return distribution
    
    def predict_sales(self, days: int = 7) -> list:
        """Faz previsão de vendas para os próximos dias."""
        # Coleta dados históricos
        daily_data = list(self._metrics['daily'].values())
        
        if len(daily_data) < 7:
            # Sem dados suficientes para previsão
            return []
        
        # Média móvel simples
        recent = daily_data[-7:]
        avg_count = sum(d['count'] for d in recent) / len(recent)
        avg_total = sum(d['total'] for d in recent) / len(recent)
        
        predictions = []
        for i in range(days):
            future_date = datetime.date.today() + datetime.timedelta(days=i+1)
            predictions.append({
                'date': future_date.strftime('%Y-%m-%d'),
                'predicted_count': round(avg_count),
                'predicted_total': round(avg_total, 2),
            })
        
        return predictions
    
    def get_growth_rate(self, period: str = 'daily') -> float:
        """Calcula taxa de crescimento."""
        if period == 'daily':
            data = self._metrics['daily']
        elif period == 'monthly':
            data = self._metrics['monthly']
        else:
            return 0.0
        
        if len(data) < 2:
            return 0.0
        
        keys = sorted(data.keys())
        current = data[keys[-1]]['total']
        previous = data[keys[-2]]['total']
        
        if previous == 0:
            return 100.0 if current > 0 else 0.0
        
        return ((current - previous) / previous) * 100






