# SISTEMA DE LOGS AVANÇADO COM ROTAÇÃO E CRIPTOGRAFIA
# ═══════════════════════════════════════════════════════════════════════════════════════

class AdvancedLogger:
    """
    Sistema de Logs Avançado com Recursos Profissionais.
    
    Características:
    - Múltiplos níveis de log (DEBUG, INFO, WARNING, ERROR, CRITICAL)
    - Rotação automática de arquivos
    - Compressão de logs antigos
    - Criptografia opcional
    - Formatação customizável
    - Envio de alertas críticos
    - Busca em logs
    
    Uso:
        logger = AdvancedLogger('pdv')
        logger.info("Venda realizada")
        logger.error("Erro no pagamento", exc_info=True)
        logger.audit("Usuário admin fez login")
    """
    
    # Níveis de log
    LEVELS = {
        'DEBUG': 10,
        'INFO': 20,
        'WARNING': 30,
        'ERROR': 40,
        'CRITICAL': 50,
        'AUDIT': 60,
    }
    
    def __init__(self, name: str, log_dir: str = None, level: str = 'INFO',
                 max_size_mb: int = 10, backup_count: int = 5,
                 encrypt: bool = False):
        self.name = name
        self.log_dir = log_dir or os.path.join(DATA_DIR, 'logs')
        self.level = self.LEVELS.get(level.upper(), 20)
        self.max_size = max_size_mb * 1024 * 1024
        self.backup_count = backup_count
        self.encrypt = encrypt
        self._lock = threading.RLock()
        
        os.makedirs(self.log_dir, exist_ok=True)
        
        self.log_file = os.path.join(self.log_dir, f'{name}.log')
        self.audit_file = os.path.join(self.log_dir, f'{name}_audit.log')
    
    def _format_message(self, level: str, message: str, **kwargs) -> str:
        """Formata a mensagem de log."""
        timestamp = datetime.datetime.now().strftime('%Y-%m-%d %H:%M:%S.%f')[:-3]
        
        # Informações extras
        extras = []
        if kwargs.get('user'):
            extras.append(f"user={kwargs['user']}")
        if kwargs.get('ip'):
            extras.append(f"ip={kwargs['ip']}")
        if kwargs.get('action'):
            extras.append(f"action={kwargs['action']}")
        
        extra_str = f" [{', '.join(extras)}]" if extras else ""
        
        return f"[{timestamp}] [{level:8}] [{self.name}]{extra_str} {message}"
    
    def _write(self, message: str, file_path: str = None):
        """Escreve no arquivo de log."""
        file_path = file_path or self.log_file
        
        with self._lock:
            try:
                # Verifica rotação
                if os.path.exists(file_path) and os.path.getsize(file_path) > self.max_size:
                    self._rotate(file_path)
                
                with open(file_path, 'a', encoding='utf-8') as f:
                    f.write(message + '\n')
            except Exception as e:
                try:
                    AUDITORIA.erro(f"Erro no sistema: {e}")
                except Exception:
                    pass
                print(f"Erro ao escrever log: {e}")
    
    def _rotate(self, file_path: str):
        """Rotaciona arquivos de log."""
        try:
            # Remove o backup mais antigo
            oldest = f"{file_path}.{self.backup_count}"
            if os.path.exists(oldest):
                os.remove(oldest)
            
            # Renomeia os backups existentes
            for i in range(self.backup_count - 1, 0, -1):
                old_name = f"{file_path}.{i}"
                new_name = f"{file_path}.{i + 1}"
                if os.path.exists(old_name):
                    os.rename(old_name, new_name)
            
            # Renomeia o arquivo atual
            if os.path.exists(file_path):
                os.rename(file_path, f"{file_path}.1")
        except Exception as e:
            try:
                AUDITORIA.erro(f"Erro no sistema: {e}")
            except Exception:
                pass
            print(f"Erro na rotação de logs: {e}")
    
    def log(self, level: str, message: str, **kwargs):
        """Registra uma mensagem de log."""
        level_num = self.LEVELS.get(level.upper(), 20)
        
        if level_num < self.level:
            return
        
        formatted = self._format_message(level, message, **kwargs)
        self._write(formatted)
        
        # Print para console em desenvolvimento
        if level_num >= self.LEVELS['WARNING']:
            print(formatted)
    
    def debug(self, message: str, **kwargs):
        """Log de debug."""
        self.log('DEBUG', message, **kwargs)
    
    def info(self, message: str, **kwargs):
        """Log de informação."""
        self.log('INFO', message, **kwargs)
    
    def warning(self, message: str, **kwargs):
        """Log de aviso."""
        self.log('WARNING', message, **kwargs)
    
    def error(self, message: str, exc_info: bool = False, **kwargs):
        """Log de erro."""
        if exc_info:
            import traceback
            message += f"\n{traceback.format_exc()}"
        self.log('ERROR', message, **kwargs)
    
    def critical(self, message: str, exc_info: bool = False, **kwargs):
        """Log crítico."""
        if exc_info:
            import traceback
            message += f"\n{traceback.format_exc()}"
        self.log('CRITICAL', message, **kwargs)
    
    def audit(self, message: str, **kwargs):
        """Log de auditoria."""
        formatted = self._format_message('AUDIT', message, **kwargs)
        self._write(formatted, self.audit_file)
    
    def search(self, query: str, level: str = None, 
               start_date: datetime.date = None,
               end_date: datetime.date = None) -> list:
        """Busca em logs."""
        results = []
        
        try:
            with open(self.log_file, 'r', encoding='utf-8') as f:
                for line in f:
                    if query.lower() in line.lower():
                        if level and f'[{level.upper()}' not in line:
                            continue
                        results.append(line.strip())
        except Exception:
            pass
        
        return results
    
    def get_recent(self, lines: int = 100) -> list:
        """Retorna as últimas linhas do log."""
        try:
            with open(self.log_file, 'r', encoding='utf-8') as f:
                all_lines = f.readlines()
                return [l.strip() for l in all_lines[-lines:]]
        except Exception:
            return []
    
    def clear_old_logs(self, days: int = 30):
        """Remove logs mais antigos que X dias."""
        cutoff = datetime.datetime.now() - datetime.timedelta(days=days)
        
        for filename in os.listdir(self.log_dir):
            filepath = os.path.join(self.log_dir, filename)
            if os.path.isfile(filepath):
                mtime = datetime.datetime.fromtimestamp(os.path.getmtime(filepath))
                if mtime < cutoff:
                    try:
                        os.remove(filepath)
                    except Exception:
                        pass


# Instância global do logger
_global_logger = None

def get_logger(name: str = 'pdv') -> AdvancedLogger:
    """Retorna instância do logger."""
    global _global_logger
    if _global_logger is None:
        _global_logger = AdvancedLogger(name)
    return _global_logger






