#  SYNC ENGINE - ATUALIZAÇÃO EM TEMPO REAL, SIMULTÂNEA E QUÂNTICA
# ═══════════════════════════════════════════════════════════════════════════════

class QuantumSyncEngine:
    """
    Motor de Sincronização Quântica em Tempo Real.
    
    Monitora alterações em TODOS os arquivos de dados do sistema e notifica
    automaticamente TODAS as telas/janelas abertas para atualização simultânea.
    
    Características:
    - Detecção de mudanças por hash MD5 (ultra-rápido)
    - Notificação simultânea de todas as telas registradas
    - Intervalo de sincronização configurável (padrão: 2 segundos)
    - Auto-recuperação em caso de falhas
    - Zero impacto na performance (thread-safe com after())
    - Suporte a callbacks específicos por tipo de dado
    """
    
    _instance = None
    _initialized = False
    
    def __new__(cls, *args, **kwargs):
        """Singleton - garante apenas uma instância do engine."""
        if cls._instance is None:
            cls._instance = super().__new__(cls)
        return cls._instance
    
    def __init__(self, root=None, sync_interval=2000):
        """
        Inicializa o QuantumSyncEngine.
        
        Args:
            root: Widget raiz do Tkinter (para agendamento via after())
            sync_interval: Intervalo de sincronização em milissegundos (padrão: 2000ms)
        """
        if QuantumSyncEngine._initialized:
            if root is not None:
                self.root = root
            return
        
        self.root = root
        self.sync_interval = sync_interval
        self._running = False
        self._subscribers = {}  # {data_key: [callback1, callback2, ...]}
        self._file_hashes = {}  # {filepath: last_md5_hash}
        self._data_cache = {}   # {filepath: cached_data}
        self._monitored_files = {}  # {data_key: filepath}
        self._error_count = 0
        self._max_errors = 10
        self._sync_count = 0
        self._last_sync_time = None
        
        # Registrar todos os arquivos de dados monitorados
        self._register_default_files()
        
        QuantumSyncEngine._initialized = True
        print("[QuantumSync] ⚛️  Motor de Sincronização Quântica inicializado")
    
    def _register_default_files(self):
        """Registra todos os arquivos de dados do sistema para monitoramento."""
        try:
            # Arquivos principais do sistema
            file_mappings = {
                "products": PRODUCTS_FILE,
                "categories": CATEGORIES_FILE,
                "customers": CUSTOMERS_FILE,
                "sales": SALES_FILE,
                "comandas": COMANDAS_FILE,
                "cartoes": CARTOES_FILE,
                "config": CONFIG_FILE,
                "empresa": EMPRESA_FILE,
                "contas_pagar": CONTAS_A_PAGAR_FILE,
                "contas_receber": CONTAS_A_RECEBER_FILE,
            }
            
            # Arquivos do diretório de login
            login_file_mappings = {
                "users": USERS_FILE,
                "fornecedores": SUPPLIERS_FILE,
                "entregadores": ENTREGADORES_FILE,
                "bairros": BAIRROS_FILE,
                "notas_entrada": NOTAS_ENTRADA_FILE,
                "caixa": CAIXA_FILE,
                "fechamentos_caixa": FECHAMENTOS_CAIXA_FILE,
                "ordens_servico": ORDENS_SERVICO_FILE,
                "servicos": SERVICES_FILE,
                "vendedores": VENDEDORES_FILE,
            }
            
            # Arquivo de tamanhos (caminho relativo)
            tamanhos_path = os.path.join(DATA_DIR, "tamanhos.json")
            if os.path.exists(tamanhos_path):
                login_file_mappings["tamanhos"] = tamanhos_path
            
            # Registrar todos
            for key, filepath in {**file_mappings, **login_file_mappings}.items():
                if filepath and os.path.exists(filepath):
                    self._monitored_files[key] = filepath
                    self._file_hashes[filepath] = self._compute_hash(filepath)
                    self._subscribers[key] = []
        except Exception as e:
            print(f"[QuantumSync] Erro ao registrar arquivos: {e}")
    
    def _compute_hash(self, filepath):
        """Calcula hash MD5 do arquivo para detecção de mudanças."""
        try:
            if not os.path.exists(filepath):
                return None
            # Usa mtime + size para detecção ultra-rápida (sem ler o arquivo)
            stat = os.stat(filepath)
            return f"{stat.st_mtime}:{stat.st_size}"
        except Exception:
            return None
    
    def subscribe(self, data_key, callback):
        """
        Registra um callback para ser notificado quando dados mudarem.
        
        Args:
            data_key: Chave do tipo de dado (ex: 'products', 'customers', 'sales')
            callback: Função a ser chamada quando houver mudança
        """
        if data_key not in self._subscribers:
            self._subscribers[data_key] = []
        
        if callback not in self._subscribers[data_key]:
            self._subscribers[data_key].append(callback)
            # print(f"[QuantumSync] 📡 Subscriber registrado para '{data_key}'")
    
    def unsubscribe(self, data_key, callback):
        """Remove um callback de notificação."""
        if data_key in self._subscribers:
            try:
                self._subscribers[data_key].remove(callback)
            except ValueError:
                pass
    
    def unsubscribe_all(self, callback):
        """Remove um callback de TODAS as chaves de dados."""
        for key in self._subscribers:
            try:
                self._subscribers[key].remove(callback)
            except ValueError:
                pass
    
    def notify_change(self, data_key):
        """
        Notifica manualmente que um tipo de dado foi alterado.
        Útil para quando save_data() é chamado diretamente.
        
        Args:
            data_key: Chave do tipo de dado alterado
        """
        if data_key in self._monitored_files:
            filepath = self._monitored_files[data_key]
            self._file_hashes[filepath] = self._compute_hash(filepath)
        
        self._notify_subscribers(data_key)
    
    def _notify_subscribers(self, data_key):
        """Notifica todos os subscribers de uma chave de dados."""
        if data_key not in self._subscribers:
            return
        
        dead_callbacks = []
        for callback in self._subscribers[data_key]:
            try:
                callback()
            except Exception as e:
                # Se o callback falhar (janela fechada), marca para remoção
                dead_callbacks.append(callback)
                # print(f"[QuantumSync] Callback morto removido para '{data_key}': {e}")
        
        # Remove callbacks mortos
        for dead in dead_callbacks:
            try:
                self._subscribers[data_key].remove(dead)
            except ValueError:
                pass
    
    def start(self):
        """Inicia o loop de sincronização em tempo real."""
        if self._running:
            return
        self._running = True
        self._error_count = 0
        print("[QuantumSync] ⚡ Sincronização em tempo real ATIVADA")
        self._sync_loop()
    
    def stop(self):
        """Para o loop de sincronização."""
        self._running = False
        print("[QuantumSync] ⏹️  Sincronização em tempo real DESATIVADA")
    
    def _sync_loop(self):
        """Loop principal de sincronização - verifica mudanças em todos os arquivos."""
        if not self._running:
            return
        
        try:
            changes_detected = []
            
            for data_key, filepath in self._monitored_files.items():
                try:
                    new_hash = self._compute_hash(filepath)
                    old_hash = self._file_hashes.get(filepath)
                    
                    if new_hash != old_hash and new_hash is not None:
                        self._file_hashes[filepath] = new_hash
                        changes_detected.append(data_key)
                except Exception:
                    pass
            
            # Notifica subscribers de todas as mudanças detectadas
            for data_key in changes_detected:
                try:
                    self._notify_subscribers(data_key)
                except Exception as e:
                    print(f"[QuantumSync] Erro ao notificar '{data_key}': {e}")
            
            if changes_detected:
                self._sync_count += 1
                import datetime
                self._last_sync_time = datetime.datetime.now()
                print(f"[QuantumSync] ⚛️  Sync #{self._sync_count} - Mudanças: {', '.join(changes_detected)}")
            
            self._error_count = 0  # Reset error count on success
            
        except Exception as e:
            self._error_count += 1
            if self._error_count <= 3:
                print(f"[QuantumSync] Erro no sync loop ({self._error_count}): {e}")
        
        # Agenda próxima verificação
        if self._running and self.root:
            try:
                self.root.after(self.sync_interval, self._sync_loop)
            except Exception:
                self._running = False
    
    def get_stats(self):
        """Retorna estatísticas do engine de sincronização."""
        return {
            "running": self._running,
            "sync_count": self._sync_count,
            "last_sync": self._last_sync_time,
            "monitored_files": len(self._monitored_files),
            "total_subscribers": sum(len(v) for v in self._subscribers.values()),
            "sync_interval_ms": self.sync_interval,
            "errors": self._error_count
        }
    
    def register_file(self, data_key, filepath):
        """Registra um novo arquivo para monitoramento."""
        if filepath and os.path.exists(filepath):
            self._monitored_files[data_key] = filepath
            self._file_hashes[filepath] = self._compute_hash(filepath)
            if data_key not in self._subscribers:
                self._subscribers[data_key] = []


# Instância global do QuantumSyncEngine (será inicializada com root no PDVSuperApp)
_quantum_sync_engine = None

def get_quantum_sync():
    """Retorna a instância global do QuantumSyncEngine."""
    global _quantum_sync_engine
    return _quantum_sync_engine

def init_quantum_sync(root, interval=650):
    """Inicializa o QuantumSyncEngine global."""
    global _quantum_sync_engine
    _quantum_sync_engine = QuantumSyncEngine(root=root, sync_interval=interval)
    return _quantum_sync_engine



