# ⚛️ QUANTUM LIVE SCREEN ENGINE v4.0 - ATUALIZAÇÃO GLOBAL EM TEMPO REAL
# ═══════════════════════════════════════════════════════════════════════════════
# Esta camada registra automaticamente TODAS as janelas abertas do sistema e
# propaga mudanças de dados de forma simultânea, sem travar a interface.
# Funciona junto com o QuantumSyncEngine original e reforça:
# - broadcast global após qualquer save_data()
# - atualização em lote via root.after()
# - proteção contra refresh recursivo
# - chamada segura de métodos de atualização existentes em cada tela
# - throttling por janela para manter agilidade
# ═══════════════════════════════════════════════════════════════════════════════

_QUANTUM_LIVE_PATCH_APPLIED = False

def _quantum_apply_live_screen_patch():
    """Aplica patch de atualização global em tempo real para todas as telas."""
    global _QUANTUM_LIVE_PATCH_APPLIED
    if _QUANTUM_LIVE_PATCH_APPLIED:
        return
    _QUANTUM_LIVE_PATCH_APPLIED = True

    import weakref
    import inspect
    import time as _ql_time

    # Métodos conhecidos de atualização existentes no sistema.
    # A ordem privilegia métodos quânticos e depois métodos genéricos de reload.
    _REFRESH_METHODS = (
        '_quantum_refresh_all',
        '_quantum_auto_refresh',
        'refresh_data_views',
        'refresh_list',
        'refresh',
        '_refresh_tree',
        '_load_data_to_tree',
        '_load_items_to_tree',
        '_load_items',
        '_carregar_dados',
        '_carregar_lista',
        '_atualizar_treeview',
        '_atualizar_lista',
        '_atualizar_lista_produtos',
        '_atualizar_lista_produtos_btn',
        '_load_turnos',
        '_load_caixas',
        '_load_vinculos',
        '_load_centros',
        '_quantum_refresh_report',
        '_quantum_refresh_notas',
        '_quantum_refresh_caixa',
        '_quantum_refresh_contas_data',
    )

    def _ensure_live_attrs(engine):
        if not hasattr(engine, '_live_windows'):
            engine._live_windows = weakref.WeakSet()
        if not hasattr(engine, '_live_global_callbacks'):
            engine._live_global_callbacks = []
        if not hasattr(engine, '_live_refreshing'):
            engine._live_refreshing = set()
        if not hasattr(engine, '_live_last_refresh'):
            engine._live_last_refresh = {}
        if not hasattr(engine, '_live_pending_keys'):
            engine._live_pending_keys = set()
        if not hasattr(engine, '_live_batch_scheduled'):
            engine._live_batch_scheduled = False
        if not hasattr(engine, '_live_tick_counter'):
            engine._live_tick_counter = 0
        if not hasattr(engine, '_live_min_window_interval'):
            engine._live_min_window_interval = 0.45
        return engine

    def _callback_accepts_no_required_args(fn):
        try:
            sig = inspect.signature(fn)
            for p in sig.parameters.values():
                if p.default is inspect._empty and p.kind in (p.POSITIONAL_ONLY, p.POSITIONAL_OR_KEYWORD, p.KEYWORD_ONLY):
                    return False
            return True
        except Exception:
            return True

    def _safe_call_refresh(win, data_key=None, force=False):
        """Atualiza uma janela de forma segura, sem recursão e sem travar."""
        try:
            if win is None or not win.winfo_exists():
                return False
        except Exception:
            return False

        engine = get_quantum_sync()
        if engine:
            _ensure_live_attrs(engine)
            wid = id(win)
            now = _ql_time.monotonic()
            if wid in engine._live_refreshing:
                return False
            last = engine._live_last_refresh.get(wid, 0)
            if not force and now - last < engine._live_min_window_interval:
                return False
            engine._live_refreshing.add(wid)

        try:
            # Janelas podem declarar quais chaves aceitam: _quantum_data_key ou _quantum_data_keys
            keys = set()
            if hasattr(win, '_quantum_data_key') and getattr(win, '_quantum_data_key'):
                keys.add(getattr(win, '_quantum_data_key'))
            if hasattr(win, '_quantum_data_keys') and getattr(win, '_quantum_data_keys'):
                try:
                    keys.update(getattr(win, '_quantum_data_keys'))
                except Exception:
                    pass

            # Se a janela declarou escopo e a mudança é de outro módulo, não força refresh pesado.
            scoped = bool(keys)
            if scoped and data_key and data_key not in keys and data_key != 'all':
                return False

            # Callback específico da janela, quando existir.
            custom_cb = getattr(win, '_quantum_live_refresh', None)
            if callable(custom_cb):
                try:
                    custom_cb(data_key)
                    return True
                except TypeError:
                    custom_cb()
                    return True

            # Métodos existentes sem argumentos.
            for name in _REFRESH_METHODS:
                fn = getattr(win, name, None)
                if callable(fn) and _callback_accepts_no_required_args(fn):
                    try:
                        fn()
                        return True
                    except Exception:
                        continue

            return False
        finally:
            if engine:
                try:
                    engine._live_last_refresh[id(win)] = _ql_time.monotonic()
                    engine._live_refreshing.discard(id(win))
                except Exception:
                    pass

    def _register_window(self, win):
        """Registra qualquer Tk/Toplevel para receber atualização quântica global."""
        _ensure_live_attrs(self)
        try:
            if win is not None and win.winfo_exists():
                self._live_windows.add(win)
                # marca padrão para telas sem escopo específico: recebem broadcast leve
                if not hasattr(win, '_quantum_live_registered'):
                    win._quantum_live_registered = True
        except Exception:
            pass

    def _subscribe_all(self, callback):
        _ensure_live_attrs(self)
        if callable(callback) and callback not in self._live_global_callbacks:
            self._live_global_callbacks.append(callback)

    def _schedule_global_refresh(self, data_key='all', force=False):
        """Agenda atualização simultânea em lote no loop visual do Tkinter."""
        _ensure_live_attrs(self)
        self._live_pending_keys.add(data_key or 'all')
        if self._live_batch_scheduled:
            return
        self._live_batch_scheduled = True

        def _run_batch():
            try:
                keys = list(getattr(self, '_live_pending_keys', {'all'}))
                self._live_pending_keys.clear()
                self._live_batch_scheduled = False
                for key in keys:
                    # callbacks globais registrados manualmente
                    for cb in list(getattr(self, '_live_global_callbacks', [])):
                        try:
                            cb(key)
                        except TypeError:
                            try:
                                cb()
                            except Exception:
                                pass
                        except Exception:
                            pass

                    # janelas registradas automaticamente
                    for win in list(getattr(self, '_live_windows', [])):
                        try:
                            _safe_call_refresh(win, key, force=force)
                        except Exception:
                            pass
            except Exception:
                self._live_batch_scheduled = False

        try:
            if getattr(self, 'root', None):
                self.root.after(1, _run_batch)
            else:
                _run_batch()
        except Exception:
            _run_batch()

    def _broadcast_all(self, data_key='all', force=False):
        _schedule_global_refresh(self, data_key=data_key, force=force)

    # Patch dos métodos da classe QuantumSyncEngine.
    if not hasattr(QuantumSyncEngine, 'register_window'):
        QuantumSyncEngine.register_window = _register_window
    if not hasattr(QuantumSyncEngine, 'subscribe_all'):
        QuantumSyncEngine.subscribe_all = _subscribe_all
    if not hasattr(QuantumSyncEngine, 'broadcast_all'):
        QuantumSyncEngine.broadcast_all = _broadcast_all

    # Reforça notify_change para além dos subscribers específicos, também atualizar telas abertas.
    _orig_notify_change = QuantumSyncEngine.notify_change
    def _patched_notify_change(self, data_key):
        _ensure_live_attrs(self)
        try:
            _orig_notify_change(self, data_key)
        finally:
            try:
                self.broadcast_all(data_key, force=True)
            except Exception:
                pass
    QuantumSyncEngine.notify_change = _patched_notify_change

    # Reforça start para registrar root e iniciar heartbeat leve.
    _orig_start = QuantumSyncEngine.start
    def _patched_start(self):
        _ensure_live_attrs(self)
        try:
            if getattr(self, 'root', None):
                self.register_window(self.root)
        except Exception:
            pass
        _orig_start(self)
    QuantumSyncEngine.start = _patched_start

    # Reforça o loop: a cada alguns ciclos faz um pulso leve para telas que dependem de banco/MySQL
    # e que não geram alteração de arquivo local.
    _orig_sync_loop = QuantumSyncEngine._sync_loop
    def _patched_sync_loop(self):
        _ensure_live_attrs(self)
        try:
            self._live_tick_counter += 1
            if self._live_tick_counter % 4 == 0:
                # pulso leve: não força refresh se a janela acabou de atualizar
                self.broadcast_all('all', force=False)
        except Exception:
            pass
        return _orig_sync_loop(self)
    QuantumSyncEngine._sync_loop = _patched_sync_loop

    # Registro automático de novas janelas Toplevel criadas depois do patch.
    try:
        _orig_toplevel_init_live = tk.Toplevel.__init__
        def _patched_toplevel_init_live(self, *args, **kwargs):
            _orig_toplevel_init_live(self, *args, **kwargs)
            try:
                qs = get_quantum_sync()
                if qs:
                    qs.register_window(self)
            except Exception:
                pass
            try:
                self.bind('<Map>', lambda e=None, w=self: (get_quantum_sync() and get_quantum_sync().register_window(w)), add='+')
            except Exception:
                pass
        tk.Toplevel.__init__ = _patched_toplevel_init_live
    except Exception:
        pass

    print("[QuantumLive] ⚛️ Atualização global, simultânea e em tempo real aplicada em todas as telas")


_quantum_apply_live_screen_patch()



# ═══════════════════════════════════════════════════════════════════════════════
# 🔐 LICENCIAMENTO POR HWID / CONTRA-CHAVE / CHAVE DE ATIVAÇÃO
# Compatível com o gerador.py do PDV Quantum Ultra.
# ═══════════════════════════════════════════════════════════════════════════════
_MASTER_SALT = b"PDV_QUANTUM_ULTRA_2025_NEXUS_EDITION"
_LICENSE_VERSION = "4.0"
_SECRET = "NEXUS_PDV_2025"

def normalizar_hwid_licenca(hwid: str) -> str:
    return str(hwid or "").strip().replace("-", "").replace(" ", "").upper()

def normalizar_chave_licenca(chave: str) -> str:
    return str(chave or "").strip().replace("-", "").replace(" ", "").upper()

def formatar_chave_licenca(chave: str, bloco: int = 4) -> str:
    chave = normalizar_chave_licenca(chave)
    return "-".join(chave[i:i+bloco] for i in range(0, len(chave), bloco) if chave[i:i+bloco])

def obter_hwid_licenca() -> str:
    """Gera HWID estável de 64 caracteres para validação da licença."""
    try:
        import uuid as _uuid_lic
        import platform as _platform_lic
        partes = [
            str(_uuid_lic.getnode()),
            str(_platform_lic.node()),
            str(_platform_lic.machine()),
            str(_platform_lic.processor()),
            str(os.environ.get("COMPUTERNAME", "")),
            str(os.environ.get("PROCESSOR_IDENTIFIER", "")),
            str(os.environ.get("SystemDrive", "")),
        ]
        bruto = "|".join(partes)
        return hashlib.sha256(bruto.encode("utf-8", errors="ignore")).hexdigest().upper()
    except Exception:
        return hashlib.sha256(str(os.environ.get("COMPUTERNAME", "QUANTUM")).encode()).hexdigest().upper()

def calcular_contra_chave_licenca(hwid: str, dias: int) -> str:
    hwid_normalizado = normalizar_hwid_licenca(hwid)
    contra_data = f"{hwid_normalizado}|{int(dias)}|{_LICENSE_VERSION}"
    contra_hash = hashlib.sha256(contra_data.encode()).hexdigest()
    contra_key = contra_hash[:12].upper()
    return f"{contra_key[:4]}-{contra_key[4:8]}-{contra_key[8:12]}"

def calcular_chave_ativacao_licenca(hwid: str, dias: int) -> str:
    hwid_normalizado = normalizar_hwid_licenca(hwid)
    expected_data = f"{hwid_normalizado}|{int(dias)}|{_MASTER_SALT.decode()}|{_SECRET}"
    expected_hash = hashlib.sha256(expected_data.encode()).hexdigest()
    return expected_hash[:16].upper()

def validar_chave_ativacao_licenca(hwid: str, dias: int, chave: str) -> bool:
    return normalizar_chave_licenca(chave) == calcular_chave_ativacao_licenca(hwid, int(dias))


class PDVSuperApp:

    def send_whatsapp_message(self, phone, message):
        """Abre o WhatsApp Web ou Desktop com uma mensagem pré-formatada."""
        if not phone:
            messagebox.showwarning("WhatsApp", "Cliente não possui telefone cadastrado.")
            return
        
        # Limpa o número de telefone (mantém apenas dígitos)
        clean_phone = "".join(filter(str.isdigit, str(phone).replace("TEL:", "")))
        if not clean_phone.startswith('55') and len(clean_phone) >= 10:
            clean_phone = '55' + clean_phone
            
        import urllib.parse
        import webbrowser
        encoded_msg = urllib.parse.quote(message)
        url = f"https://wa.me/{clean_phone}?text={encoded_msg}"
        webbrowser.open(url)
        log_user_action("WhatsApp", f"Mensagem enviada para {clean_phone}")
    

    # ═══════════════════════════════════════════════════════════════════════
    # SISTEMA DE ANIVERSÁRIO: WHATSAPP AUTOMÁTICO + VOUCHER
    # ═══════════════════════════════════════════════════════════════════════

    def _load_aniversario_config(self):
        try:
            cfg = load_data(ANIVERSARIO_CONFIG_FILE, DEFAULT_ANIVERSARIO_CONFIG.copy())
            base = DEFAULT_ANIVERSARIO_CONFIG.copy()
            if isinstance(cfg, dict):
                base.update(cfg)
            return base
        except Exception:
            return DEFAULT_ANIVERSARIO_CONFIG.copy()

    def _save_aniversario_config(self, cfg):
        try:
            base = DEFAULT_ANIVERSARIO_CONFIG.copy()
            base.update(cfg or {})
            save_data(ANIVERSARIO_CONFIG_FILE, base)
            return True
        except Exception as e:
            messagebox.showerror("Aniversários", f"Erro ao salvar configuração:\n{e}")
            return False

    def _ensure_aniversario_tables(self):
        try:
            db = get_db()
            sql = """
                CREATE TABLE IF NOT EXISTS aniversarios_envios (
                    id INT AUTO_INCREMENT PRIMARY KEY,
                    cliente_id INTEGER NOT NULL,
                    cliente_nome VARCHAR(500) DEFAULT '',
                    telefone VARCHAR(500) DEFAULT '',
                    ano INTEGER NOT NULL,
                    data_envio TEXT,
                    voucher_codigo VARCHAR(255) DEFAULT '',
                    voucher_valor DOUBLE DEFAULT 0.0,
                    status VARCHAR(500) DEFAULT 'Enviado',
                    observacao VARCHAR(500) DEFAULT '',
                    created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
                    UNIQUE KEY uq_aniv_cliente_ano (cliente_id, ano)
                )
            """
            db.execute(sql)
            return True
        except Exception as e:
            print(f"[ANIVERSÁRIOS] Erro criando tabela: {e}")
            return False

    def _parse_data_aniversario(self, valor):
        try:
            if not valor:
                return None
            texto = str(valor).strip()
            if not texto or texto in ('0000-00-00', 'None', 'null'):
                return None
            import re
            formatos = ('%d/%m/%Y', '%Y-%m-%d', '%d-%m-%Y', '%d/%m/%y', '%Y/%m/%d')
            for fmt in formatos:
                try:
                    return datetime.datetime.strptime(texto[:10], fmt).date()
                except Exception:
                    pass
            nums = re.findall(r'\d+', texto)
            if len(nums) >= 3:
                if len(nums[0]) == 4:
                    return datetime.date(int(nums[0]), int(nums[1]), int(nums[2]))
                return datetime.date(int(nums[2]), int(nums[1]), int(nums[0]))
        except Exception:
            return None
        return None

    def _formatar_telefone_whatsapp(self, telefone):
        clean = ''.join(filter(str.isdigit, str(telefone or '').replace('TEL:', '')))
        if not clean:
            return ''
        if clean.startswith('00'):
            clean = clean[2:]
        if not clean.startswith('55') and len(clean) >= 10:
            clean = '55' + clean
        return clean

    def _aniversario_ja_enviado(self, cliente_id, ano):
        try:
            self._ensure_aniversario_tables()
            row = get_db().fetchone("SELECT id FROM aniversarios_envios WHERE cliente_id = %s AND ano = %s", (int(cliente_id), int(ano)))
            return bool(row)
        except Exception:
            return False

    def _registrar_aniversario_enviado(self, cliente, ano, voucher_codigo='', voucher_valor=0.0, status='Enviado', observacao=''):
        try:
            self._ensure_aniversario_tables()
            agora = datetime.datetime.now().strftime('%d/%m/%Y %H:%M:%S')
            sql = """
                INSERT INTO aniversarios_envios
                    (cliente_id, cliente_nome, telefone, ano, data_envio, voucher_codigo, voucher_valor, status, observacao)
                VALUES (%s, %s, %s, %s, %s, %s, %s, %s, %s)
                ON DUPLICATE KEY UPDATE data_envio=VALUES(data_envio), voucher_codigo=VALUES(voucher_codigo),
                    voucher_valor=VALUES(voucher_valor), status=VALUES(status), observacao=VALUES(observacao)
            """
            get_db().execute(sql, (int(cliente.get('id')), cliente.get('nome', ''), cliente.get('telefone', ''), int(ano), agora, voucher_codigo or '', float(voucher_valor or 0), status, observacao[:500]))
        except Exception as e:
            print(f"[ANIVERSÁRIOS] Erro ao registrar envio: {e}")

    def _gerar_voucher_aniversario(self, cliente, cfg):
        try:
            if not cfg.get('criar_voucher', True):
                return '', 0.0, ''
            valor = float(str(cfg.get('valor_voucher', 0)).replace(',', '.') or 0)
            if valor <= 0:
                return '', 0.0, ''
            validade_dias = int(cfg.get('validade_dias', 30) or 30)
            validade = (datetime.datetime.now() + datetime.timedelta(days=validade_dias)).strftime('%d/%m/%Y')
            codigo = self._gerar_codigo_voucher() if hasattr(self, '_gerar_codigo_voucher') else f"ANIV{datetime.datetime.now().strftime('%Y%m%d%H%M%S')}"
            motivo = cfg.get('nome_promocao', 'Voucher de Aniversário') or 'Voucher de Aniversário'
            usuario = globals().get('logged_user', 'SISTEMA') or 'SISTEMA'
            obs = f"Gerado automaticamente no aniversário. Válido até {validade}."
            sql = """
                INSERT INTO vouchers (codigo, valor_original, valor_restante, cliente_id, cliente_nome, motivo,
                    status, usuario_criacao, data_criacao, observacao)
                VALUES (%s, %s, %s, %s, %s, %s, 'Ativo', %s, %s, %s)
            """
            get_db().execute(sql, (codigo, valor, valor, int(cliente.get('id')), cliente.get('nome', ''), motivo, usuario, datetime.datetime.now().strftime('%d/%m/%Y %H:%M:%S'), obs))
            return codigo, valor, validade
        except Exception as e:
            print(f"[ANIVERSÁRIOS] Erro ao gerar voucher: {e}")
            return '', 0.0, ''

    def _montar_mensagem_aniversario(self, cliente, cfg, voucher_codigo='', voucher_valor=0.0, voucher_validade=''):
        empresa = 'Nossa loja'
        try:
            empresa = (getattr(self, 'empresa_data', {}) or {}).get('nome') or empresa
        except Exception:
            pass
        template = cfg.get('mensagem') or DEFAULT_ANIVERSARIO_CONFIG['mensagem']
        return template.format(
            cliente=cliente.get('nome', ''), empresa=empresa,
            voucher_codigo=voucher_codigo or 'SEM VOUCHER',
            voucher_valor=(f"{float(voucher_valor):.2f}".replace('.', ',') if voucher_valor else '0,00'),
            voucher_validade=voucher_validade or '-', telefone=cliente.get('telefone', ''),
            data=datetime.datetime.now().strftime('%d/%m/%Y')
        )

    def listar_aniversariantes_hoje(self):
        resultado = []
        hoje = datetime.date.today()
        try:
            rows = get_db().fetchall("SELECT id, nome, telefone, email, data_nascimento FROM clientes WHERE ativo = 1 ORDER BY nome")
            for row in rows or []:
                cliente = dict(row)
                nasc = self._parse_data_aniversario(cliente.get('data_nascimento'))
                if nasc and nasc.day == hoje.day and nasc.month == hoje.month:
                    cliente['data_nascimento_formatada'] = nasc.strftime('%d/%m/%Y')
                    cliente['whatsapp_normalizado'] = self._formatar_telefone_whatsapp(cliente.get('telefone'))
                    cliente['ja_enviado_ano'] = self._aniversario_ja_enviado(cliente.get('id'), hoje.year)
                    resultado.append(cliente)
        except Exception as e:
            print(f"[ANIVERSÁRIOS] Erro ao listar aniversariantes: {e}")
        return resultado

    def processar_aniversariantes_whatsapp(self, manual=False, parent=None, reenviar=False):
        cfg = self._load_aniversario_config()
        if not cfg.get('ativo', False) and not manual:
            return {'total': 0, 'enviados': 0, 'ignorados': 0, 'erros': 0, 'mensagem': 'Sistema desativado'}
        hoje = datetime.date.today()
        aniversariantes = self.listar_aniversariantes_hoje()
        enviados = ignorados = erros = 0
        detalhes = []
        import urllib.parse, webbrowser
        for cliente in aniversariantes:
            try:
                if cliente.get('ja_enviado_ano') and not reenviar:
                    ignorados += 1
                    detalhes.append(f"{cliente.get('nome')} - já enviado em {hoje.year}")
                    continue
                telefone = cliente.get('whatsapp_normalizado') or self._formatar_telefone_whatsapp(cliente.get('telefone'))
                if not telefone:
                    ignorados += 1
                    self._registrar_aniversario_enviado(cliente, hoje.year, '', 0.0, 'Ignorado', 'Cliente sem telefone/WhatsApp')
                    detalhes.append(f"{cliente.get('nome')} - sem WhatsApp")
                    continue
                voucher_codigo, voucher_valor, voucher_validade = self._gerar_voucher_aniversario(cliente, cfg)
                mensagem = self._montar_mensagem_aniversario(cliente, cfg, voucher_codigo, voucher_valor, voucher_validade)
                if cfg.get('enviar_whatsapp', True) and (cfg.get('abrir_whatsapp_automaticamente', True) or manual):
                    webbrowser.open(f"https://wa.me/{telefone}?text={urllib.parse.quote(mensagem)}")
                    status = 'Enviado' if cfg.get('marcar_como_enviado_ao_abrir', True) else 'WhatsApp aberto'
                else:
                    status = 'Voucher Gerado'
                self._registrar_aniversario_enviado(cliente, hoje.year, voucher_codigo, voucher_valor, status, 'Processado automaticamente')
                enviados += 1
                detalhes.append(f"{cliente.get('nome')} - {status}" + (f" - Voucher {voucher_codigo}" if voucher_codigo else ''))
            except Exception as e:
                erros += 1
                detalhes.append(f"{cliente.get('nome', 'Cliente')} - ERRO: {e}")
        try:
            AUDITORIA.processo(f"Aniversariantes processados: total={len(aniversariantes)}, enviados={enviados}, ignorados={ignorados}, erros={erros}")
        except Exception:
            pass
        return {'total': len(aniversariantes), 'enviados': enviados, 'ignorados': ignorados, 'erros': erros, 'detalhes': detalhes}

    def iniciar_monitor_aniversariantes(self):
        cfg = self._load_aniversario_config()
        if not cfg.get('ativo', False):
            return
        def verificar():
            try:
                if self._load_aniversario_config().get('ativo', False):
                    self.processar_aniversariantes_whatsapp(manual=False)
            except Exception as e:
                print(f"[ANIVERSÁRIOS] Erro no monitor: {e}")
            finally:
                try:
                    self.root.after(60 * 60 * 1000, verificar)
                except Exception:
                    pass
        try:
            self.root.after(20000, verificar)
        except Exception:
            pass

    def show_aniversarios_whatsapp_window(self, parent=None):
        if not check_permission_any('aniversarios.acessar', 'config.acessar', 'vouchers.acessar'):
            messagebox.showerror('Acesso Negado', 'Você não tem permissão para acessar aniversários.')
            return
        cfg = self._load_aniversario_config()
        win = tk.Toplevel(parent or self.root)
        win.title('🎂 Aniversários - WhatsApp Automático e Voucher')
        responsive_geometry(win, 980, 720)
        main = ttk.Frame(win, padding=15); main.pack(fill=tk.BOTH, expand=True)
        ttk.Label(main, text='🎂 ANIVERSÁRIOS: WHATSAPP AUTOMÁTICO + VOUCHER', font=('Segoe UI', 16, 'bold')).pack(anchor='w', pady=(0, 12))
        ativo = tk.BooleanVar(value=bool(cfg.get('ativo', False)))
        enviar = tk.BooleanVar(value=bool(cfg.get('enviar_whatsapp', True)))
        voucher = tk.BooleanVar(value=bool(cfg.get('criar_voucher', True)))
        abrir = tk.BooleanVar(value=bool(cfg.get('abrir_whatsapp_automaticamente', True)))
        marcar = tk.BooleanVar(value=bool(cfg.get('marcar_como_enviado_ao_abrir', True)))
        valor = tk.StringVar(value=str(cfg.get('valor_voucher', 10.0)).replace('.', ','))
        validade = tk.StringVar(value=str(cfg.get('validade_dias', 30)))
        hora = tk.StringVar(value=str(cfg.get('hora_verificacao', '09:00')))
        promo = tk.StringVar(value=str(cfg.get('nome_promocao', 'Voucher de Aniversário')))
        opts = ttk.LabelFrame(main, text='Configuração', padding=10); opts.pack(fill=tk.X, pady=(0, 10))
        l1 = ttk.Frame(opts); l1.pack(fill=tk.X, pady=3)
        ttk.Checkbutton(l1, text='Ativar sistema automático', variable=ativo).pack(side=tk.LEFT, padx=5)
        ttk.Checkbutton(l1, text='Enviar WhatsApp', variable=enviar).pack(side=tk.LEFT, padx=15)
        ttk.Checkbutton(l1, text='Criar voucher', variable=voucher).pack(side=tk.LEFT, padx=15)
        l2 = ttk.Frame(opts); l2.pack(fill=tk.X, pady=5)
        for label,var,w in [('Valor R$:',valor,10),('Validade dias:',validade,8),('Verificar às:',hora,8),('Promoção:',promo,28)]:
            ttk.Label(l2, text=label).pack(side=tk.LEFT, padx=(12 if label!='Valor R$:' else 0, 3)); ttk.Entry(l2, textvariable=var, width=w).pack(side=tk.LEFT)
        l3 = ttk.Frame(opts); l3.pack(fill=tk.X, pady=3)
        ttk.Checkbutton(l3, text='Abrir WhatsApp automaticamente', variable=abrir).pack(side=tk.LEFT, padx=5)
        ttk.Checkbutton(l3, text='Marcar como enviado ao abrir', variable=marcar).pack(side=tk.LEFT, padx=15)
        msgf = ttk.LabelFrame(main, text='Mensagem - use {cliente}, {empresa}, {voucher_codigo}, {voucher_valor}, {voucher_validade}', padding=10)
        msgf.pack(fill=tk.BOTH, pady=(0,10))
        txt = tk.Text(msgf, height=7, wrap=tk.WORD); txt.pack(fill=tk.BOTH, expand=True); txt.insert('1.0', cfg.get('mensagem') or DEFAULT_ANIVERSARIO_CONFIG['mensagem'])
        lf = ttk.LabelFrame(main, text='Aniversariantes de hoje', padding=10); lf.pack(fill=tk.BOTH, expand=True)
        cols=('id','nome','telefone','nascimento','status'); tree=ttk.Treeview(lf, columns=cols, show='headings', height=9)
        for c,t,w in [('id','ID',60),('nome','Cliente',260),('telefone','WhatsApp',150),('nascimento','Nascimento',120),('status','Status',220)]:
            tree.heading(c,text=t); tree.column(c,width=w,anchor=tk.CENTER if c!='nome' else tk.W)
        scr=ttk.Scrollbar(lf,orient=tk.VERTICAL,command=tree.yview); tree.configure(yscrollcommand=scr.set); tree.pack(side=tk.LEFT,fill=tk.BOTH,expand=True); scr.pack(side=tk.RIGHT,fill=tk.Y)
        info=tk.StringVar(); ttk.Label(main,textvariable=info,foreground='#555').pack(anchor='w',pady=(5,0))
        def carregar():
            tree.delete(*tree.get_children()); dados=self.listar_aniversariantes_hoje()
            for cli in dados:
                st='Já enviado este ano' if cli.get('ja_enviado_ano') else ('Pronto' if cli.get('whatsapp_normalizado') else 'Sem WhatsApp')
                tree.insert('', tk.END, values=(cli.get('id'), cli.get('nome'), cli.get('telefone'), cli.get('data_nascimento_formatada'), st))
            info.set(f'{len(dados)} aniversariante(s) encontrado(s) hoje.')
        def salvar():
            try:
                cfg2={'ativo':ativo.get(),'enviar_whatsapp':enviar.get(),'criar_voucher':voucher.get(),'abrir_whatsapp_automaticamente':abrir.get(),'marcar_como_enviado_ao_abrir':marcar.get(),'valor_voucher':float(valor.get().replace('.', '').replace(',', '.')),'validade_dias':int(validade.get() or 30),'hora_verificacao':hora.get().strip() or '09:00','nome_promocao':promo.get().strip() or 'Voucher de Aniversário','mensagem':txt.get('1.0',tk.END).strip()}
                if self._save_aniversario_config(cfg2):
                    self.iniciar_monitor_aniversariantes(); messagebox.showinfo('Aniversários','Configuração salva com sucesso.',parent=win)
            except Exception as e:
                messagebox.showerror('Erro',f'Configuração inválida:\n{e}',parent=win)
        def processar():
            salvar(); res=self.processar_aniversariantes_whatsapp(manual=True,parent=win,reenviar=False); carregar(); detalhes='\n'.join(res.get('detalhes',[])[:20])
            messagebox.showinfo('Aniversários',f"Processamento concluído.\n\nTotal: {res.get('total')}\nEnviados: {res.get('enviados')}\nIgnorados: {res.get('ignorados')}\nErros: {res.get('erros')}\n\n{detalhes}",parent=win)
        btn=ttk.Frame(main); btn.pack(fill=tk.X,pady=(10,0))
        ttk.Button(btn,text='💾 Salvar configuração',command=salvar,bootstyle='success').pack(side=tk.LEFT,padx=5)
        ttk.Button(btn,text='🎂 Processar hoje',command=processar,bootstyle='primary').pack(side=tk.LEFT,padx=5)
        ttk.Button(btn,text='🔄 Atualizar lista',command=carregar,bootstyle='secondary').pack(side=tk.LEFT,padx=5)
        ttk.Button(btn,text='Fechar',command=win.destroy,bootstyle='danger').pack(side=tk.RIGHT,padx=5)
        carregar()

    def safe_after(self, delay, callback):
        if hasattr(self, 'is_running') and self.is_running:
            try:
                if self.root.winfo_exists():
                    return self.root.after(delay, callback)
            except Exception:
                pass
        return None
    

    def _animate_widget(self, widget, start_alpha=0.0, end_alpha=1.0, duration=600):
        """Efeito de fade-in ultra-suave e dinâmico para widgets."""
        steps = 20
        delay = duration // steps
        def step(current_step=0):
            if current_step <= steps:
                alpha = start_alpha + (end_alpha - start_alpha) * (current_step / steps)
                # Tkinter não suporta alpha real em widgets individuais facilmente sem extensões,
                # então simulamos com transição de cores se for um frame ou label
                try:
                    if isinstance(widget, (tk.Frame, ttk.Frame)):
                        pass # Futura implementação de gradiente
                except: pass
                if self.is_running: self.safe_after(delay, lambda: step(current_step + 1))
        step()

    def _apply_futuristic_style(self):
        """Aplica estilos Quantum Supreme para uma aparência de elite."""
        self.style.configure('Futuristic.TButton', font=('Segoe UI', scale_font_size(10, self.root), 'bold'), padding=scale_value(10, self.root))
        self.style.configure('Quantum.Treeview', rowheight=scale_value(40, self.root), font=('Segoe UI', scale_font_size(10, self.root)))
        self.style.configure('Total.TLabel', font=('Segoe UI', scale_font_size(24, self.root), 'bold'), foreground='#28a745')
        self.style.configure('Header.TLabel', font=('Segoe UI', scale_font_size(18, self.root), 'bold'), foreground='#2c3e50')
        self.style.map('Futuristic.TButton', 
                      background=[('active', '#2980b9'), ('pressed', '#1f6391')],
                      foreground=[('active', 'white')])


