    def show_quantum_dashboard(self):
        """
        if not check_permission("util.dashboard"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para acessar o Dashboard.")
            return
        Exibe dashboard analítico avançado com gráficos nativos.
        Compatível com Python 32-bit - usa Tkinter Canvas ao invés de matplotlib.
        """
        try:
            AUDITORIA.processo("Abrindo Quantum Dashboard")
        except Exception:
            pass
        dash_win = tk.Toplevel(self.root)
        dash_win.title("Quantum Analytics Dashboard")
        dash_win.state('zoomed')
        dash_win.configure(bg='#f8f9fa')
        
        # Frame principal com scroll
        main_frame = ttk.Frame(dash_win, padding=20)
        main_frame.pack(expand=True, fill=tk.BOTH)
        
        # Título
        ttk.Label(main_frame, text="ANALISE DE PERFORMANCE COMERCIAL", 
                 font=("Segoe UI", 22, "bold")).pack(pady=15)
        
        # Frame para cards de resumo
        cards_frame = ttk.Frame(main_frame)
        cards_frame.pack(fill=tk.X, pady=10)
        
        # Calcular estatísticas
        from collections import defaultdict
        vendas_por_dia = defaultdict(float)
        vendas_por_forma = defaultdict(float)
        total_vendas = 0
        total_itens = 0
        
        for venda in self.sales_log:
            data = venda.get('data', '')
            total = venda.get('total', 0.0)
            forma = venda.get('forma_pagamento', 'Outros')
            vendas_por_dia[data] += total
            vendas_por_forma[forma] += total
            total_vendas += total
            total_itens += len(venda.get('itens', []))
        
        # Cards de resumo
        self._create_info_card(cards_frame, "Total Vendas", f"R$ {total_vendas:,.2f}", "primary")
        self._create_info_card(cards_frame, "Nº de Vendas", str(len(self.sales_log)), "success")
        self._create_info_card(cards_frame, "Itens Vendidos", str(total_itens), "info")
        ticket_medio = total_vendas / len(self.sales_log) if self.sales_log else 0
        self._create_info_card(cards_frame, "Ticket Médio", f"R$ {ticket_medio:,.2f}", "warning")
        
        # Frame para gráficos
        charts_frame = ttk.Frame(main_frame)
        charts_frame.pack(expand=True, fill=tk.BOTH, pady=20)
        
        # Preparar dados para gráfico de linha
        datas = sorted(list(vendas_por_dia.keys()))[-7:]
        valores = [vendas_por_dia[d] for d in datas]
        
        if not datas:
            datas, valores = ['Sem Dados'], [0]
        
        # Gráfico de Linha - Tendência de Faturamento
        chart_line = CanvasChart(charts_frame, width=1000, height=350, bg='white', padding=60)
        chart_line.pack(fill=tk.X, pady=10)
        chart_line.draw_line_chart(
            labels=datas,
            values=valores,
            title="Tendencia de Faturamento (Ultimos 7 Dias)",
            line_color='#007bff',
            fill_color='#cce5ff',
            show_points=True
        )
        
        # Frame para gráficos lado a lado
        bottom_charts = ttk.Frame(main_frame)
        bottom_charts.pack(fill=tk.X, pady=10)
        
        # Gráfico de Barras - Formas de Pagamento
        formas = list(vendas_por_forma.keys())[:5]
        valores_forma = [vendas_por_forma[f] for f in formas]
        
        if formas:
            chart_bar = CanvasChart(bottom_charts, width=500, height=300, bg='white', padding=50)
            chart_bar.pack(side=tk.LEFT, padx=10)
            chart_bar.draw_bar_chart(
                labels=formas,
                values=valores_forma,
                title="Vendas por Forma de Pagamento"
            )

    def _create_info_card(self, parent, title, value, style):
        card = ttk.Frame(parent, bootstyle=style, padding=15)
        card.pack(side=tk.LEFT, expand=True, fill=tk.BOTH, padx=10)
        ttk.Label(card, text=title, font=("Segoe UI", 10), bootstyle=f"{style}-inverse").pack()
        ttk.Label(card, text=value, font=("Segoe UI", 18, "bold"), bootstyle=f"{style}-inverse").pack()

    def reimprimir_ultimo_fechamento_caixa(self):
        """
        Reimprimir o último fechamento de caixa do dia.
        Busca o fechamento mais recente do dia atual em todos os caixas e exibe
        o relatório detalhado no mesmo formato da impressão original.
        """
        if not check_permission("relatorios.reimprimir_fechamento"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para reimprimir o fechamento de caixa.")
            return
        
        try:
            hoje_str = datetime.date.today().strftime('%d/%m/%Y')
            hoje_iso = datetime.date.today().isoformat()  # formato YYYY-MM-DD
            
            ultimo_fechamento = None
            ultimo_caixa_id = None
            
            # Busca em todos os caixas cadastrados
            caixas_config = load_data(os.path.join(LOGIN_DATA_DIR, "caixas_config.json"), {"caixas": [{"id": 1, "nome": "Caixa 1"}]})
            lista_caixas = caixas_config.get('caixas', [{"id": 1, "nome": "Caixa 1"}])
            
            for caixa_info in lista_caixas:
                caixa_id = caixa_info.get('id', 1)
                fechamentos = load_fechamentos_caixa(caixa_id)
                
                for f in fechamentos:
                    data_fech = f.get('data_fechamento', '')
                    # Verifica se o fechamento é do dia atual (formato dd/mm/yyyy ou yyyy-mm-dd)
                    eh_hoje = False
                    if data_fech.startswith(hoje_str[:10]):
                        eh_hoje = True
                    elif hoje_iso in data_fech:
                        eh_hoje = True
                    elif len(data_fech) >= 10:
                        # Tenta extrair a data no formato dd/mm/yyyy
                        parte_data = data_fech[:10]
                        if parte_data == hoje_str:
                            eh_hoje = True
                    
                    if eh_hoje:
                        if ultimo_fechamento is None:
                            ultimo_fechamento = f
                            ultimo_caixa_id = caixa_id
                        else:
                            # Compara para pegar o mais recente
                            data_atual = ultimo_fechamento.get('data_fechamento', '')
                            if data_fech > data_atual:
                                ultimo_fechamento = f
                                ultimo_caixa_id = caixa_id
            
            if not ultimo_fechamento:
                messagebox.showinfo("Reimpressão", 
                    f"Nenhum fechamento de caixa encontrado para hoje ({hoje_str}).\n\n"
                    "Realize o fechamento de caixa primeiro.")
                return
            
            # ===== GERAR RELATÓRIO DETALHADO =====
            # Carrega dados da empresa
            empresa = load_data(EMPRESA_FILE, DEFAULT_EMPRESA)
            
            # Prepara dados para impressão
            data_abertura = ultimo_fechamento.get('data_abertura', 'N/A')
            data_fechamento = ultimo_fechamento.get('data_fechamento', 'N/A')
            usuario_abertura = ultimo_fechamento.get('usuario_abertura', 'N/A')
            usuario_fechamento = ultimo_fechamento.get('usuario_fechamento', 'N/A')
            saldo_inicial = float(ultimo_fechamento.get('saldo_inicial', 0.0) or 0.0)
            total_creditos = float(ultimo_fechamento.get('total_creditos', 0.0) or 0.0)
            total_debitos = float(ultimo_fechamento.get('total_debitos', 0.0) or 0.0)
            saldo_final = float(ultimo_fechamento.get('saldo_final', 0.0) or 0.0)
            transacoes = ultimo_fechamento.get('transacoes', [])
            
            # Calcula totais por forma de pagamento
            totais_pagamento = {}
            total_vendas = 0.0
            total_suprimentos = 0.0
            total_sangrias = 0.0
            qtd_vendas = 0
            qtd_suprimentos = 0
            qtd_sangrias = 0
            
            for t in transacoes:
                desc = t.get('descricao', '').upper()
                valor = float(t.get('valor', 0.0) or 0.0)
                pagamento = t.get('pagamento', 'N/A')
                
                if 'VENDA CUPOM' in desc:
                    total_vendas += valor
                    qtd_vendas += 1
                    if pagamento and pagamento != 'N/A':
                        for forma in pagamento.split(','):
                            forma = forma.strip()
                            if forma:
                                totais_pagamento[forma] = totais_pagamento.get(forma, 0.0) + valor
                elif 'SUPRIMENTO' in desc:
                    total_suprimentos += valor
                    qtd_suprimentos += 1
                elif 'SANGRIA' in desc:
                    total_sangrias += valor
                    qtd_sangrias += 1
            
            # Calcula diferença (quebra de caixa)
            saldo_esperado = saldo_inicial + total_vendas + total_suprimentos - total_sangrias
            diferenca = saldo_final - saldo_esperado
            
            # Monta o relatório de texto
            largura = 48
            linha_simples = '-' * largura
            linha_dupla = '=' * largura
            
            # Dados da empresa
            store_name = empresa.get("nome", "EMPRESA")
            store_address = empresa.get("endereco", "")
            store_cidade = empresa.get("cidade", "")
            store_estado = empresa.get("estado", "")
            store_cep = empresa.get("cep", "")
            store_cnpj = empresa.get("cnpj", "")
            store_tel = empresa.get("telefone", "")
            
            city_parts = []
            if store_cidade: city_parts.append(store_cidade)
            if store_estado: city_parts.append(store_estado)
            city_state = ", ".join(city_parts)
            store_city_line = f"{city_state}{' - CEP ' + store_cep if store_cep else ''}" if city_state else ""
            
            relatorio = []
            
            # Cabeçalho da Empresa
            relatorio.append(linha_dupla)
            relatorio.append(store_name.center(largura))
            if store_address:
                relatorio.append(store_address.center(largura))
            if store_city_line:
                relatorio.append(store_city_line.center(largura))
            if store_cnpj:
                relatorio.append(f"CNPJ: {store_cnpj}".center(largura))
            if store_tel:
                relatorio.append(f"TEL: {store_tel}".center(largura))
            relatorio.append(linha_dupla)
            relatorio.append("FECHAMENTO DE CAIXA".center(largura))
            caixa_nome = next((c.get('nome', f'Caixa {ultimo_caixa_id}') for c in lista_caixas if c.get('id') == ultimo_caixa_id), f'Caixa {ultimo_caixa_id}')
            relatorio.append(f"(REIMPRESSAO - {caixa_nome})".center(largura))
            relatorio.append(linha_dupla)
            
            # Informações do Turno
            relatorio.append("")
            relatorio.append("INFORMACOES DO TURNO".center(largura))
            relatorio.append(linha_simples)
            relatorio.append(f"Abertura: {data_abertura}")
            relatorio.append(f"Fechamento: {data_fechamento}")
            relatorio.append(f"Operador Abertura: {usuario_abertura}")
            relatorio.append(f"Operador Fechamento: {usuario_fechamento}")
            relatorio.append("")
            
            # Resumo Financeiro
            relatorio.append(linha_dupla)
            relatorio.append("RESUMO FINANCEIRO".center(largura))
            relatorio.append(linha_dupla)
            
            def linha_valor(label, valor, simbolo='R$'):
                valor_fmt = format_br_currency(valor).replace('R$ ', '')
                espacos = largura - len(label) - len(valor_fmt) - len(simbolo) - 2
                return f"{label}{' ' * max(espacos, 1)}{simbolo} {valor_fmt}"
            
            relatorio.append(linha_valor("Saldo Inicial:", saldo_inicial))
            relatorio.append(linha_simples)
            relatorio.append(linha_valor(f"(+) Vendas ({qtd_vendas}):", total_vendas))
            relatorio.append(linha_valor(f"(+) Suprimentos ({qtd_suprimentos}):", total_suprimentos))
            relatorio.append(linha_valor(f"(-) Sangrias ({qtd_sangrias}):", total_sangrias))
            relatorio.append(linha_simples)
            relatorio.append(linha_valor("Total Creditos:", total_creditos))
            relatorio.append(linha_valor("Total Debitos:", total_debitos))
            relatorio.append(linha_dupla)
            relatorio.append(linha_valor(">>> SALDO FINAL:", saldo_final))
            relatorio.append(linha_dupla)
            
            # Totais por Forma de Pagamento
            if totais_pagamento:
                relatorio.append("")
                relatorio.append("TOTAIS POR FORMA DE PAGAMENTO".center(largura))
                relatorio.append(linha_simples)
                for forma, total in sorted(totais_pagamento.items()):
                    relatorio.append(linha_valor(f"  {forma}:", total))
                relatorio.append(linha_simples)
            
            # Conferência de Caixa
            relatorio.append("")
            relatorio.append("CONFERENCIA DE CAIXA".center(largura))
            relatorio.append(linha_simples)
            relatorio.append(linha_valor("Saldo Esperado:", saldo_esperado))
            relatorio.append(linha_valor("Saldo Informado:", saldo_final))
            if diferenca >= 0:
                relatorio.append(linha_valor("Diferenca (Sobra):", diferenca))
            else:
                relatorio.append(linha_valor("Diferenca (Falta):", abs(diferenca)))
            relatorio.append(linha_simples)
            
            # Movimentações Detalhadas
            relatorio.append("")
            relatorio.append(linha_dupla)
            relatorio.append("MOVIMENTACOES DETALHADAS".center(largura))
            relatorio.append(linha_dupla)
            relatorio.append(f"{'HORA':<8} {'TIPO':<8} {'DESCRICAO':<20} {'VALOR':>10}")
            relatorio.append(linha_simples)
            
            for t in transacoes:
                hora = t.get('hora', '--:--')[:8]
                tipo_raw = str(t.get('tipo', 'N/A')).upper()
                tipo = tipo_raw[:8]
                desc = t.get('descricao', 'N/A')[:20]
                valor = float(t.get('valor', 0.0) or 0.0)
                sinal = '+' if tipo_raw in ('CRÉDITO', 'CREDITO') else '-'
                valor_fmt = f"{sinal}{format_br_currency(valor).replace('R$ ', '')}"
                relatorio.append(f"{hora:<8} {tipo:<8} {desc:<20} {valor_fmt:>10}")
            
            relatorio.append(linha_simples)
            relatorio.append(f"Total de movimentacoes: {len(transacoes)}")
            
            # Rodapé
            relatorio.append("")
            relatorio.append(linha_dupla)
            relatorio.append("ASSINATURAS".center(largura))
            relatorio.append(linha_dupla)
            relatorio.append("")
            relatorio.append("")
            relatorio.append("_" * 35)
            relatorio.append("Operador")
            relatorio.append("")
            relatorio.append("")
            relatorio.append("_" * 35)
            relatorio.append("Supervisor/Gerente")
            relatorio.append("")
            relatorio.append(linha_dupla)
            relatorio.append(f"Reimpresso em: {datetime.datetime.now().strftime('%d/%m/%Y %H:%M:%S')}")
            relatorio.append(linha_dupla)
            relatorio.append(store_name.center(largura))
            relatorio.append("OBRIGADO!".center(largura))
            relatorio.append(linha_dupla)
            
            # Junta todas as linhas
            texto_relatorio = '\n'.join(relatorio)
            
            # ===== EXIBIR JANELA DE VISUALIZAÇÃO =====
            dialog = tk.Toplevel(self.root)
            dialog.title("🧾 Reimpressão de Fechamento de Caixa")
            responsive_geometry(dialog, 650, 700)
            dialog.transient(self.root)
            dialog.grab_set()
            dialog.configure(bg='#f8f9fa')
            
            # Centralizar
            dialog.update_idletasks()
            x = (dialog.winfo_screenwidth() // 2) - 325
            y = (dialog.winfo_screenheight() // 2) - 350
            responsive_geometry(dialog, 650, 700)
            
            # Frame principal
            main_frame = ttk.Frame(dialog, padding=15)
            main_frame.pack(expand=True, fill=tk.BOTH)
            
            # Título
            ttk.Label(main_frame, text="REIMPRESSÃO DE FECHAMENTO DE CAIXA", 
                      font=("Segoe UI", 14, "bold")).pack(pady=(0, 5))
            ttk.Label(main_frame, text=f"📅 {hoje_str} | {caixa_nome}", 
                      font=("Segoe UI", 10), foreground="#555").pack(pady=(0, 10))
            
            # Área de texto com scroll
            text_frame = ttk.Frame(main_frame)
            text_frame.pack(expand=True, fill=tk.BOTH, pady=10)
            
            scrollbar = ttk.Scrollbar(text_frame)
            scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
            
            text_widget = tk.Text(text_frame, wrap=tk.NONE, font=("Courier New", 9),
                                  yscrollcommand=scrollbar.set, bg='white', fg='black')
            text_widget.pack(expand=True, fill=tk.BOTH)
            scrollbar.config(command=text_widget.yview)
            
            text_widget.insert('1.0', texto_relatorio)
            text_widget.config(state='disabled')
            
            # Frame de botões
            btn_frame = ttk.Frame(main_frame)
            btn_frame.pack(fill=tk.X, pady=(10, 0))
            
            def imprimir_windows():
                try:
                    import tempfile
                    import subprocess
                    import sys
                    with tempfile.NamedTemporaryFile(mode='w', suffix='.txt', delete=False, encoding='utf-8') as f:
                        f.write(texto_relatorio)
                        temp_path = f.name
                    if sys.platform == 'win32':
                        os.startfile(temp_path, 'print')
                        messagebox.showinfo("Impressão", "Documento enviado para impressão.", parent=dialog)
                    else:
                        messagebox.showinfo("Info", f"Arquivo salvo em:\n{temp_path}", parent=dialog)
                except Exception as e:
                    messagebox.showerror("Erro", f"Erro ao imprimir:\n{e}", parent=dialog)
            
            def imprimir_termica():
                """CORREÇÃO: Usa print_receipt_text que respeita múltiplas impressoras."""
                try:
                    # CORREÇÃO: Prioriza print_receipt_text que respeita múltiplas impressoras
                    if hasattr(self, 'print_receipt_text'):
                        self.print_receipt_text(texto_relatorio)
                        messagebox.showinfo("Sucesso", "Relatório enviado para impressora!", parent=dialog)
                    elif hasattr(self, 'thermal_printer_manager') and self.thermal_printer_manager:
                        if self.thermal_printer_manager.is_enabled():
                            if self.thermal_printer_manager.print_text(texto_relatorio):
                                messagebox.showinfo("Sucesso", "Relatório enviado para impressora térmica!", parent=dialog)
                            else:
                                messagebox.showerror("Erro", "Falha ao enviar para impressora térmica.", parent=dialog)
                        else:
                            messagebox.showwarning("Aviso", "Impressora térmica não está configurada ou habilitada.", parent=dialog)
                    else:
                        messagebox.showwarning("Aviso", "Impressora térmica não disponível.", parent=dialog)
                except Exception as e:
                    messagebox.showerror("Erro", f"Erro ao imprimir:\n{e}", parent=dialog)
            
            def copiar_texto():
                dialog.clipboard_clear()
                dialog.clipboard_append(texto_relatorio)
                messagebox.showinfo("Copiado", "Relatório copiado para a área de transferência!", parent=dialog)
            
            def salvar_arquivo():
                from tkinter import filedialog
                filepath = filedialog.asksaveasfilename(
                    parent=dialog,
                    defaultextension=".txt",
                    filetypes=[("Arquivo de Texto", "*.txt"), ("Todos os Arquivos", "*.*")],
                    initialfile=f"reimpressao_fechamento_{datetime.datetime.now().strftime('%Y%m%d_%H%M%S')}.txt"
                )
                if filepath:
                    try:
                        with open(filepath, 'w', encoding='utf-8') as f:
                            f.write(texto_relatorio)
                        messagebox.showinfo("Salvo", f"Relatório salvo em:\n{filepath}", parent=dialog)
                    except Exception as e:
                        messagebox.showerror("Erro", f"Erro ao salvar:\n{e}", parent=dialog)
            
            def salvar_pdf_reimpressao():
                timestamp = datetime.datetime.now().strftime('%Y%m%d_%H%M%S')
                gerar_pdf_recibo(
                    texto=texto_relatorio,
                    titulo="Reimpressão de Fechamento de Caixa",
                    nome_arquivo=f"Reimpressao_Fechamento_{timestamp}",
                    parent_window=dialog
                )
            
            ttk.Button(btn_frame, text="🖨️ Imprimir (Windows)", command=imprimir_windows, 
                       bootstyle="primary").pack(side=tk.LEFT, padx=3)
            ttk.Button(btn_frame, text="🧾 Impressora Térmica", command=imprimir_termica,
                       bootstyle="success").pack(side=tk.LEFT, padx=3)
            ttk.Button(btn_frame, text="📄 Salvar PDF", command=salvar_pdf_reimpressao,
                       bootstyle="info").pack(side=tk.LEFT, padx=3)
            ttk.Button(btn_frame, text="📋 Copiar", command=copiar_texto,
                       bootstyle="secondary").pack(side=tk.LEFT, padx=3)
            ttk.Button(btn_frame, text="💾 Salvar TXT", command=salvar_arquivo,
                       bootstyle="warning").pack(side=tk.LEFT, padx=3)
            ttk.Button(btn_frame, text="Fechar", command=dialog.destroy,
                       bootstyle="secondary").pack(side=tk.RIGHT, padx=3)
            
            # Atalhos
            dialog.bind('<Escape>', lambda e: dialog.destroy())
            
            log_user_action("Relatório", f"Reimpressão do último fechamento de caixa do dia ({caixa_nome})")
            
        except Exception as e:
            import traceback
            traceback.print_exc()
            messagebox.showerror("Erro", f"Erro ao reimprimir fechamento de caixa:\n{e}")

    def show_fechamentos_caixa_report(self):
        """
        Gera e exibe o relatório de histórico de fechamentos de caixa com filtro por período.
        """
        if not check_permission("relatorios.fechamentos_caixa"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar o relatório de fechamentos de caixa.")
            return
        
        # Cria janela de seleção de período
        period_win = tk.Toplevel(self.root)
        period_win.title("Relatório de Fechamentos de Caixa")
        period_win.state('zoomed')
        period_win.transient(self.root)
        period_win.grab_set()
        period_win.resizable(True, True)
        period_win.configure(bg='#f8f9fa')

        # Frame principal
        main_frame = ttk.Frame(period_win, padding="20")
        main_frame.pack(expand=True, fill=tk.BOTH)

        # Título
        ttk.Label(main_frame, text="💰 Histórico de Fechamentos de Caixa", 
                 font=("Segoe UI", 14, "bold")).pack(pady=(0, 20))

        # Frame para as datas
        dates_frame = ttk.Frame(main_frame)
        dates_frame.pack(pady=10, fill=tk.X)

        # Data inicial
        ttk.Label(dates_frame, text="Data Inicial:").grid(row=0, column=0, sticky=tk.W, pady=5)
        entry_data_inicial = DateEntry(dates_frame, width=15, bootstyle="primary", dateformat="%d/%m/%Y")
        entry_data_inicial.grid(row=0, column=1, padx=(10, 0), pady=5)

        # Data final
        ttk.Label(dates_frame, text="Data Final:").grid(row=1, column=0, sticky=tk.W, pady=5)
        entry_data_final = DateEntry(dates_frame, width=15, bootstyle="primary", dateformat="%d/%m/%Y")
        entry_data_final.grid(row=1, column=1, padx=(10, 0), pady=5)

        # Filtro por usuário (abertura ou fechamento)
        ttk.Label(dates_frame, text="Usuário:").grid(row=2, column=0, sticky=tk.W, pady=5)
        usuario_filter_var = tk.StringVar(value="Todos")
        # Carrega lista de usuários cadastrados para o dropdown
        try:
            _users_dict = load_users()
            _nomes_usuarios = sorted(_users_dict.keys()) if _users_dict else []
        except Exception:
            _nomes_usuarios = []
        _opcoes_usuario = ["Todos"] + _nomes_usuarios
        cmb_usuario = ttk.Combobox(dates_frame, textvariable=usuario_filter_var,
                                    values=_opcoes_usuario, state="readonly",
                                    width=20, font=("Segoe UI", 10))
        cmb_usuario.grid(row=2, column=1, padx=(10, 0), pady=5, sticky=tk.W)

        # Label de instrução
        ttk.Label(main_frame, text="Formato: DD/MM/AAAA", 
                 font=("Segoe UI", 9), foreground="gray").pack(pady=(5, 15))

        # Função auxiliar para extrair a data (date) de uma string de data/hora
        def _parse_data_fechamento(data_str):
            """Tenta interpretar a data de fechamento em vários formatos possíveis."""
            if not data_str:
                return None
            formatos = [
                '%d/%m/%Y %H:%M:%S',
                '%d/%m/%Y %H:%M',
                '%d/%m/%Y',
                '%Y-%m-%d %H:%M:%S',
                '%Y-%m-%d %H:%M',
                '%Y-%m-%d',
            ]
            for fmt in formatos:
                try:
                    return datetime.datetime.strptime(data_str.strip(), fmt).date()
                except (ValueError, AttributeError):
                    continue
            return None

        # Função para validar e gerar relatório
        def gerar_relatorio():
            try:
                # Converte as datas do formato brasileiro para datetime
                data_inicial_str = entry_data_inicial.entry.get().strip()
                data_final_str = entry_data_final.entry.get().strip()
                
                data_inicial = datetime.datetime.strptime(data_inicial_str, '%d/%m/%Y').date()
                data_final = datetime.datetime.strptime(data_final_str, '%d/%m/%Y').date()
                
                if data_inicial > data_final:
                    messagebox.showerror("Erro", "Data inicial não pode ser maior que data final.", parent=period_win)
                    return
                
                # =============================================================
                # CARREGA FECHAMENTOS DE TODOS OS CAIXAS CADASTRADOS
                # Cada caixa tem seu próprio histórico de fechamentos
                # =============================================================
                todos_fechamentos = []
                
                # 1) Carrega de cada caixa cadastrado (sistema multi-caixa)
                try:
                    lista_caixas = get_caixas_pdv()
                    for caixa in lista_caixas:
                        caixa_id = caixa.get('id', 1)
                        caixa_nome = caixa.get('nome', f'Caixa {caixa_id}')
                        fechamentos_caixa = load_fechamentos_caixa(caixa_id)
                        for f in fechamentos_caixa:
                            f['_caixa_id'] = caixa_id
                            f['_caixa_nome'] = caixa_nome
                            todos_fechamentos.append(f)
                except Exception as e:
                    print(f"[RELATORIO] Erro ao carregar caixas cadastrados: {e}")
                
                # 2) Também carrega do arquivo genérico antigo (compatibilidade)
                try:
                    fechamentos_antigos = load_data(FECHAMENTOS_CAIXA_FILE, [])
                    for f in fechamentos_antigos:
                        # Evita duplicatas: só adiciona se não tiver o mesmo id/data_fechamento
                        f_id = f.get('id', '')
                        f_data = f.get('data_fechamento', '')
                        ja_existe = any(
                            ef.get('id', '') == f_id and ef.get('data_fechamento', '') == f_data 
                            for ef in todos_fechamentos
                        ) if f_id else False
                        if not ja_existe:
                            if '_caixa_nome' not in f:
                                f['_caixa_nome'] = 'Caixa Geral'
                            if '_caixa_id' not in f:
                                f['_caixa_id'] = 0
                            todos_fechamentos.append(f)
                except Exception as e:
                    print(f"[RELATORIO] Erro ao carregar fechamentos antigos: {e}")
                
                if not todos_fechamentos:
                    messagebox.showinfo("Relatório", 
                                      "Nenhum fechamento de caixa registrado.", 
                                      parent=period_win)
                    return
                
                # =============================================================
                # FILTRA FECHAMENTOS FIELMENTE PELO PERÍODO INFORMADO
                # Só inclui se AMBAS as datas (abertura E fechamento) estiverem
                # dentro do período informado (Data Inicial a Data Final).
                # =============================================================
                fechamentos_periodo = []
                for fechamento in todos_fechamentos:
                    data_fechamento_str = fechamento.get('data_fechamento', '')
                    data_abertura_str = fechamento.get('data_abertura', '')
                    data_fech = _parse_data_fechamento(data_fechamento_str)
                    data_abert = _parse_data_fechamento(data_abertura_str)
                    if data_fech is not None and data_abert is not None:
                        if data_inicial <= data_abert <= data_final and data_inicial <= data_fech <= data_final:
                            fechamentos_periodo.append(fechamento)
                    elif data_fech is not None:
                        # Se só tem data de fechamento (sem abertura), usa apenas ela
                        if data_inicial <= data_fech <= data_final:
                            fechamentos_periodo.append(fechamento)
                
                # =============================================================
                # FILTRA POR USUÁRIO (se selecionado)
                # Verifica usuário de abertura OU de fechamento
                # =============================================================
                usuario_filtro = usuario_filter_var.get().strip()
                if usuario_filtro and usuario_filtro != "Todos":
                    fechamentos_filtrados = []
                    for fechamento in fechamentos_periodo:
                        usr_abertura = (fechamento.get('usuario_abertura', '') or fechamento.get('usuario', '') or '').strip().lower()
                        usr_fechamento = (fechamento.get('usuario_fechamento', '') or fechamento.get('usuario', '') or '').strip().lower()
                        filtro_lower = usuario_filtro.lower()
                        if usr_abertura == filtro_lower or usr_fechamento == filtro_lower:
                            fechamentos_filtrados.append(fechamento)
                    fechamentos_periodo = fechamentos_filtrados
                
                # Ordena por data de fechamento (mais antigo primeiro)
                def _sort_key(f):
                    d = _parse_data_fechamento(f.get('data_fechamento', ''))
                    return d if d else datetime.date.min
                fechamentos_periodo.sort(key=_sort_key)
                
                if not fechamentos_periodo:
                    _msg_filtro = f" para o usuário '{usuario_filtro}'" if usuario_filtro and usuario_filtro != 'Todos' else ''
                    messagebox.showinfo("Relatório", 
                                      f"Nenhum fechamento encontrado no período de {data_inicial_str} a {data_final_str}{_msg_filtro}.", 
                                      parent=period_win)
                    return
                
                # =============================================================
                # GERA O RELATÓRIO
                # =============================================================
                _label_usuario = f" | Usuário: {usuario_filtro}" if usuario_filtro and usuario_filtro != 'Todos' else ''
                report = "=" * 48 + "\n"
                report += "RELATORIO DE FECHAMENTOS DE CAIXA\n".center(48)
                report += "=" * 48 + "\n"
                report += f"Periodo: {data_inicial_str} a {data_final_str}\n"
                if usuario_filtro and usuario_filtro != 'Todos':
                    report += f"Usuario: {usuario_filtro}\n"
                report += f"Fechamentos: {len(fechamentos_periodo)}\n"
                report += "=" * 48 + "\n\n"
                
                total_geral_inicial = 0.0
                total_geral_creditos = 0.0
                total_geral_debitos = 0.0
                total_geral_final = 0.0
                
                for idx, fechamento in enumerate(fechamentos_periodo, 1):
                    # Identifica o caixa de origem
                    caixa_nome = fechamento.get('_caixa_nome', 'N/A')
                    
                    report += f"\n{'='*48}\n"
                    report += f"FECHAMENTO #{idx} - {caixa_nome}\n"
                    report += f"{'='*48}\n"
                    report += f"Abert: {fechamento.get('data_abertura', 'N/A')}\n"
                    report += f"Fecha: {fechamento.get('data_fechamento', 'N/A')}\n"
                    report += f"Usr Ab: {fechamento.get('usuario_abertura', fechamento.get('usuario', 'N/A'))}\n"
                    report += f"Usr Fe: {fechamento.get('usuario_fechamento', fechamento.get('usuario', 'N/A'))}\n"
                    report += f"{'-'*48}\n"
                    
                    saldo_inicial = float(fechamento.get('saldo_inicial', 0.0) or 0.0)
                    # Compatibilidade: aceita tanto total_creditos quanto total_entradas
                    total_creditos = float(fechamento.get('total_creditos', fechamento.get('total_entradas', 0.0)) or 0.0)
                    total_debitos = float(fechamento.get('total_debitos', fechamento.get('total_saidas', 0.0)) or 0.0)
                    saldo_final = float(fechamento.get('saldo_final', 0.0) or 0.0)
                    
                    report += f"Saldo Inicial: {format_br_currency(saldo_inicial)}\n"
                    report += f"Total Créditos: {format_br_currency(total_creditos)}\n"
                    report += f"Total Débitos: {format_br_currency(total_debitos)}\n"
                    report += f"Saldo Final: {format_br_currency(saldo_final)}\n"
                    
                    total_geral_inicial += saldo_inicial
                    total_geral_creditos += total_creditos
                    total_geral_debitos += total_debitos
                    total_geral_final += saldo_final
                    
                    # Listar transações
                    transacoes = fechamento.get('transacoes', [])
                    if transacoes:
                        report += f"\n{'-'*48}\n"
                        report += f"TRANSACOES ({len(transacoes)} reg):\n"
                        report += f"{'-'*48}\n"
                        report += f"{'HORA':<8} {'TIPO':<8} {'VALOR':>12}\n"
                        report += f"{'-'*48}\n"
                        
                        for trans in transacoes:
                            hora = trans.get('hora', 'N/A')[:8]
                            tipo = trans.get('tipo', 'N/A')[:8]
                            descricao = trans.get('descricao', 'N/A')
                            valor = trans.get('valor', 0.0)
                            report += f"{hora:<8} {tipo:<8} {format_br_currency(valor):>12}\n"
                            if descricao and descricao != 'N/A':
                                report += f"  {descricao[:44]}\n"
                
                # Totalizador geral
                report += f"\n{'='*48}\n"
                report += f"TOTALIZADOR GERAL\n"
                report += f"{'='*48}\n"
                report += f"Saldo Inicial:{format_br_currency(total_geral_inicial):>33}\n"
                report += f"Creditos:     {format_br_currency(total_geral_creditos):>33}\n"
                report += f"Debitos:      {format_br_currency(total_geral_debitos):>33}\n"
                report += f"Saldo Final:  {format_br_currency(total_geral_final):>33}\n"
                report += f"{'='*48}\n"
                
                # Fecha janela de seleção e exibe relatório
                period_win.destroy()
                _titulo_relatorio = f"💰 Fechamentos de Caixa - {data_inicial_str} a {data_final_str}{_label_usuario}"
                ReportWindow(self.root, _titulo_relatorio, report, self)
                log_user_action("Relatório", f"Visualizou Histórico de Fechamentos de Caixa ({data_inicial_str} a {data_final_str}{_label_usuario})")
                
            except ValueError:
                messagebox.showerror("Erro", "Formato de data inválido. Use DD/MM/AAAA.", parent=period_win)
            except Exception as e:
                messagebox.showerror("Erro", f"Erro ao gerar relatório: {str(e)}", parent=period_win)

        # Botões
        buttons_frame = ttk.Frame(main_frame)
        buttons_frame.pack(pady=20, fill=tk.X)
        
        ttk.Button(buttons_frame, text="Gerar Relatório", 
                  command=gerar_relatorio, style="Accent.TButton").pack(side=tk.LEFT, padx=(0, 10))
        ttk.Button(buttons_frame, text="Cancelar", 
                  command=lambda: period_win.destroy()).pack(side=tk.RIGHT)

        # Foco no primeiro campo
        entry_data_inicial.focus()
        
        # Permite Enter para gerar relatório
        period_win.bind('<Return>', lambda e: gerar_relatorio())
        
        period_win.wait_window()

    def _create_menu(self):
        menubar = tk.Menu(self.root)
        self.root.config(menu=menubar)

        # =====================================================================
        # Função auxiliar: adiciona um item de menu somente se o usuário tiver
        # a permissão correspondente. Retorna True se adicionou.
        # =====================================================================
        def _add_cmd(menu, label, command, permission, **kwargs):
            """Adiciona item ao menu SOMENTE se tiver permissão. Retorna True se adicionou."""
            if check_permission(permission):
                menu.add_command(label=label, command=command, **kwargs)
                return True
            return False

        # =====================================================================
        # 1. MENU ARQUIVO (sempre visível - contém Sair)                Ctrl+Q
        # =====================================================================
        file_menu = tk.Menu(menubar, tearoff=0)
        _add_cmd(file_menu, "1.1  Configurações", self.open_config_window, "config.acessar", accelerator="Ctrl+O")
        file_menu.add_separator()
        file_menu.add_command(label="1.2  Sair", command=self._on_closing, accelerator="Ctrl+Q")
        menubar.add_cascade(label="1. 🗃️ Arquivo", menu=file_menu)

        # =====================================================================
        # 2. MENU CADASTROS - só aparece se tiver ao menos uma permissão
        # =====================================================================
