            "fornecedores.acessar", "entregadores.acessar",
            "tamanhos.acessar", "cartoes.acessar", "bairros.acessar",
            "servicos.acessar", "vendedores.acessar", "garcons.acessar", "mesas.acessar", "mesas.gerenciar",
