    def _perform_auto_heal(self):
        """Verifica e corrige inconsistências nos dados automaticamente com Recuperação de Desastres."""
        healed = False
        try:
            # Auto-cura de produtos
            for pid, pdata in list(self.products.items()):
                if 'estoque' not in pdata: pdata['estoque'] = 0.0; healed = True
                if 'preco' not in pdata: pdata['preco'] = 0.0; healed = True
                if 'fidelidade_pontos' not in pdata: pdata['fidelidade_pontos'] = 0; healed = True
            
            # Verificação de integridade de arquivos críticos
            for file_path in [USERS_FILE, PRODUCTS_FILE, SALES_FILE]:
                if not os.path.exists(file_path) or os.path.getsize(file_path) == 0:
                    # Tenta restaurar do backup mais recente
                    backups = BACKUP_SYSTEM.list_backups(os.path.basename(file_path))
                    if backups:
                        BACKUP_SYSTEM.restore_backup(backups[0], file_path)
                        AUDIT_LOGGER.critical(f"RECUPERAÇÃO DE DESASTRE: Arquivo {file_path} restaurado do backup.")
                        healed = True

            if healed:
                save_data(PRODUCTS_FILE, self.products)
                log_user_action("Auto-Cura", "Inconsistências e integridade de arquivos verificadas")
        except Exception as e:
            AUDIT_LOGGER.error(f"Erro no Auto-Heal: {e}")

    def _inicializar_sessoes_carrinho(self):
        """Inicializa a estrutura de múltiplas abas de carrinho."""
        if hasattr(self, 'cart_sessions') and self.cart_sessions:
            return # Já inicializado
        self.cart_sessions = {}
        self.cart_session_widgets = {}
        self.cart_session_tab_ids = {}
        self.current_cart_session_id = None
        self._cart_session_seq = 0
        self._cart_session_switching = False
        self._registrar_nova_sessao_carrinho(usar_estado_atual=True)

    def _novo_estado_sessao_carrinho(self):
        """Retorna um estado vazio para uma nova venda em paralelo."""
        return {
            'carrinho': {},
            'total_venda': 0.0,
            'selected_customer_id': '1',
            'is_delivery': False,
            'estoque_ja_descontado': False,
            'comanda_origem': None,
            'os_origem': None,
            'desconto_aplicado': 0.0,
            'acrescimo_aplicado': 0.0,
            'selected_entregador_id': None,
            'selected_vendedor_id': None,
            'selected_vendedor_nome': ''
        }

    def _estado_sessao_carrinho_atual(self):
        """Captura o estado da venda atual para persistir na aba selecionada."""
        return {
            'carrinho': self.carrinho,
            'total_venda': self.total_venda,
            'selected_customer_id': self.selected_customer_id,
            'is_delivery': self.is_delivery,
            'estoque_ja_descontado': self.estoque_ja_descontado,
            'comanda_origem': self.comanda_origem,
            'os_origem': self.os_origem,
            'desconto_aplicado': self.desconto_aplicado,
            'acrescimo_aplicado': self.acrescimo_aplicado,
            'selected_entregador_id': self.selected_entregador_id,
            'selected_vendedor_id': self.selected_vendedor_id,
            'selected_vendedor_nome': self.selected_vendedor_nome
        }

    def _registrar_nova_sessao_carrinho(self, usar_estado_atual=False):
        """Registra uma nova sessão de carrinho."""
        self._cart_session_seq += 1
        session_id = f"cart_{self._cart_session_seq}"
        estado = self._estado_sessao_carrinho_atual() if usar_estado_atual else self._novo_estado_sessao_carrinho()
        self.cart_sessions[session_id] = estado
        if self.current_cart_session_id is None:
            self.current_cart_session_id = session_id
        return session_id

    def _salvar_sessao_carrinho(self, session_id=None):
        """Salva o estado da aba de carrinho atualmente ativa."""
        session_id = session_id or self.current_cart_session_id
        if not session_id or session_id not in self.cart_sessions:
            return
        self.cart_sessions[session_id].update(self._estado_sessao_carrinho_atual())

    def _configurar_treeview_carrinho(self, parent):
        """Cria uma treeview de carrinho dentro da aba informada."""
        parent.rowconfigure(0, weight=1)
        parent.columnconfigure(0, weight=1)
        cols_carrinho = ('nome', 'qtd_peso', 'preco_unit', 'subtotal')
        tree_carrinho = ttk.Treeview(parent, columns=cols_carrinho, show='headings', height=12)
        headings_carrinho = ("Produto", "Qtd/Medida", "Preço Unit.", "Subtotal (R$)")
        widths_carrinho = {'nome': scale_value(150, self.root), 'qtd_peso': scale_value(100, self.root), 'preco_unit': scale_value(120, self.root), 'subtotal': scale_value(120, self.root)}
        anchors_carrinho = {'nome': tk.W, 'qtd_peso': tk.CENTER, 'preco_unit': tk.E, 'subtotal': tk.E}
        for col in cols_carrinho:
            tree_carrinho.heading(col, text=headings_carrinho[cols_carrinho.index(col)], anchor=anchors_carrinho[col])
            tree_carrinho.column(col, width=widths_carrinho[col], anchor=anchors_carrinho[col], stretch=tk.YES if col == 'nome' else tk.NO)
        tree_carrinho.grid(row=0, column=0, sticky='nsew')
        scrollbar_carrinho = ttk.Scrollbar(parent, orient=tk.VERTICAL, command=tree_carrinho.yview)
        tree_carrinho.configure(yscroll=scrollbar_carrinho.set)
        scrollbar_carrinho.grid(row=0, column=1, sticky='ns')
        return tree_carrinho

    def _criar_aba_visual_carrinho(self, session_id):
        """Cria a interface visual da aba de carrinho."""
        if not hasattr(self, 'cart_notebook') or session_id in self.cart_session_widgets:
            return
        tab_frame = ttk.Frame(self.cart_notebook)
        tab_frame.rowconfigure(0, weight=1)
        tab_frame.columnconfigure(0, weight=1)
        tree_carrinho = self._configurar_treeview_carrinho(tab_frame)
        self.cart_notebook.add(tab_frame, text='Venda')
        self.cart_session_widgets[session_id] = {'frame': tab_frame, 'tree': tree_carrinho}
        self.cart_session_tab_ids[str(tab_frame)] = session_id

    def _atualizar_titulos_abas_carrinho(self):
        """Mantém os nomes das abas de carrinho em sequência."""
        if not hasattr(self, 'cart_notebook'):
            return
        for index, session_id in enumerate(self.cart_sessions.keys(), start=1):
            widgets = self.cart_session_widgets.get(session_id)
            if not widgets:
                continue
            self.cart_notebook.tab(widgets['frame'], text=f"Venda {index}")

    def _selecionar_sessao_carrinho(self, session_id):
        """Troca a sessão ativa do carrinho sem perder a venda em andamento."""
        if not session_id or session_id not in self.cart_sessions:
            return
        previous_id = self.current_cart_session_id
        if previous_id and previous_id != session_id:
            self._salvar_sessao_carrinho(previous_id)
        self.current_cart_session_id = session_id

        widgets = self.cart_session_widgets.get(session_id, {})
        frame = widgets.get('frame')
        tree = widgets.get('tree')
        if tree is not None:
            self.tree_carrinho = tree

        estado = self.cart_sessions[session_id]
        self.carrinho = estado.get('carrinho', {})
        self.total_venda = estado.get('total_venda', 0.0)
        self.selected_customer_id = estado.get('selected_customer_id', '1')
        self.is_delivery = estado.get('is_delivery', False)
        self.estoque_ja_descontado = estado.get('estoque_ja_descontado', False)
        self.comanda_origem = estado.get('comanda_origem')
        self.os_origem = estado.get('os_origem')
        self.desconto_aplicado = estado.get('desconto_aplicado', 0.0)
        self.acrescimo_aplicado = estado.get('acrescimo_aplicado', 0.0)
        self.selected_entregador_id = estado.get('selected_entregador_id')
        self.selected_vendedor_id = estado.get('selected_vendedor_id')
        self.selected_vendedor_nome = estado.get('selected_vendedor_nome', '')

        if hasattr(self, 'cart_notebook') and frame is not None and self.cart_notebook.select() != str(frame):
            self._cart_session_switching = True
            try:
                self.cart_notebook.select(frame)
            finally:
                self._cart_session_switching = False

        if hasattr(self, 'tree_carrinho'):
            self._atualizar_carrinho_e_total()
        if hasattr(self, 'lbl_customer_display'):
            self._update_customer_display()

    def _on_cart_tab_changed(self, event=None):
        """Sincroniza o estado ao trocar de aba no notebook do carrinho."""
        if self._cart_session_switching or not hasattr(self, 'cart_notebook'):
            return
        selected_tab = self.cart_notebook.select()
        session_id = self.cart_session_tab_ids.get(selected_tab)
        if session_id and session_id != self.current_cart_session_id:
            self._selecionar_sessao_carrinho(session_id)

    def adicionar_aba_carrinho(self):
        """Cria uma nova aba vazia para outra venda simultânea."""
        self._salvar_sessao_carrinho()
        session_id = self._registrar_nova_sessao_carrinho(usar_estado_atual=False)
        self._criar_aba_visual_carrinho(session_id)
        self._atualizar_titulos_abas_carrinho()
        self._selecionar_sessao_carrinho(session_id)

    def remover_aba_carrinho_atual(self):
        """Remove a aba atual de carrinho, preservando as demais vendas."""
        if len(self.cart_sessions) <= 1:
            messagebox.showwarning('Abas de Carrinho', 'Não é possível remover a última aba de carrinho.', parent=self.root)
            return

        session_id = self.current_cart_session_id
        if not session_id or session_id not in self.cart_sessions:
            return

        self._salvar_sessao_carrinho(session_id)
        estado = self.cart_sessions.get(session_id, {})
        if estado.get('carrinho'):
            if not messagebox.askyesno('Remover Aba', 'Esta aba possui itens no carrinho. Deseja removê-la mesmo assim?', parent=self.root):
                return

        remaining_ids = [sid for sid in self.cart_sessions.keys() if sid != session_id]
        next_session_id = remaining_ids[-1] if remaining_ids else None
        widgets = self.cart_session_widgets.pop(session_id, {})
        frame = widgets.get('frame')
        if frame is not None and hasattr(self, 'cart_notebook'):
            self._cart_session_switching = True
            try:
                self.cart_notebook.forget(frame)
            finally:
                self._cart_session_switching = False
            self.cart_session_tab_ids.pop(str(frame), None)

        self.cart_sessions.pop(session_id, None)
        self.current_cart_session_id = None
        self._atualizar_titulos_abas_carrinho()

        if next_session_id:
            self._selecionar_sessao_carrinho(next_session_id)

    def _create_widgets(self):
        modo_supermercado = cfg_bool(self.config_data.get("modo_supermercado", False), False)
        try:
            style = ttk.Style()
            if modo_supermercado:
                style.configure("Supermercado.Total.TLabel", font=("Segoe UI", scale_font_size(30, self.root), "bold"), foreground="#00a651")
                style.configure("Supermercado.TButton", font=("Segoe UI", scale_font_size(13, self.root), "bold"))
                style.configure("Supermercado.Treeview", rowheight=scale_value(30, self.root), font=("Segoe UI", scale_font_size(11, self.root)))
                style.configure("Supermercado.Treeview.Heading", font=("Segoe UI", scale_font_size(11, self.root), "bold"))
        except Exception:
            pass

        if modo_supermercado:
            supermercado_top = ttk.Frame(self.root, padding=(10, 8))
            supermercado_top.pack(fill=tk.X)
            supermercado_top.columnconfigure(1, weight=1)
            ttk.Label(
                supermercado_top,
                text="🛒 Tela de Vendas",
                font=("Segoe UI", scale_font_size(18, self.root), "bold"),
                foreground="#0d6efd"
            ).grid(row=0, column=0, sticky="w", padx=(0, 20))
            ttk.Label(
                supermercado_top,
                text="Leitor de código de barras ativo no campo de busca • F12 finaliza • F6 cliente • DEL remove item",
                font=("Segoe UI", scale_font_size(10, self.root)),
                foreground="#555555"
            ).grid(row=0, column=1, sticky="w")

        # ... (layout principal com PanedWindow igual anterior) ...
        main_pane = ttk.Panedwindow(self.root, orient=tk.HORIZONTAL)
        main_pane.pack(expand=True, fill=tk.BOTH, padx=scale_value(10, self.root), pady=scale_value(10, self.root))

        # --- Frame Esquerdo (Produtos) ---
        left_frame = ttk.Frame(main_pane, padding="5")
        main_pane.add(left_frame, weight=6 if modo_supermercado else 6)
        left_frame.rowconfigure(1, weight=1)
        left_frame.columnconfigure(0, weight=1)
        # Filtros
        filter_frame = ttk.Frame(left_frame)
        filter_frame.grid(row=0, column=0, sticky="ew", pady=(0, 5))
        filter_frame.columnconfigure(1, weight=1)
        ttk.Label(filter_frame, text="CÓDIGO / PRODUTO:" if modo_supermercado else "Buscar:", font=("Segoe UI", scale_font_size(12, self.root), "bold") if modo_supermercado else None).grid(row=0, column=0, padx=(0, 5))
        self.search_var = tk.StringVar()
        self.search_var.trace_add("write", lambda *args: self._filtrar_produtos())
        self.search_entry = ttk.Entry(filter_frame, textvariable=self.search_var, width=32 if modo_supermercado else 24, font=("Segoe UI", scale_font_size(16, self.root), "bold") if modo_supermercado else None)
        self.search_entry.grid(row=0, column=1, sticky="ew", padx=5)
        self.search_entry.bind("<Return>", lambda event: self._handle_search_enter())
        
        # CORREÇÃO: Foca automaticamente no campo de busca quando a janela principal recebe foco
        def _focar_campo_busca(event=None):
            """Foca no campo de busca quando a janela principal recebe foco."""
            try:
                # Verifica se o foco não está em uma janela filha (Toplevel)
                focused_widget = self.root.focus_get()
                if focused_widget is None:
                    self.search_entry.focus_set()
                elif focused_widget.winfo_toplevel() == self.root:
                    # Só foca se o widget atual não for um campo de entrada
                    if not isinstance(focused_widget, (ttk.Entry, tk.Entry, ttk.Combobox, tk.Text)):
                        self.search_entry.focus_set()
            except Exception:
                pass
        
        # Bind para quando a janela principal recebe foco
        self.root.bind("<FocusIn>", _focar_campo_busca)
        # Bind para quando a janela é ativada (clicada ou trazida para frente)
        self.root.bind("<Activate>", _focar_campo_busca)
        # Botões para modo de código de barras
