    def buscar_ordem_servico(self):
        """Abre janela para buscar OS por número."""
        try:
            AUDITORIA.processo("Buscando ordem de serviço")
        except Exception:
            pass
        if not check_permission("os.visualizar"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar ordens de serviço.")
            return
        
        busca_win = tk.Toplevel(self.root)
        busca_win.title("🔍 Buscar Ordem de Serviço")
        responsive_geometry(busca_win, 400, 150)
        busca_win.transient(self.root)
        busca_win.grab_set()
        
        # Centralizar
        busca_win.update_idletasks()
        x = (busca_win.winfo_screenwidth() // 2) - 200
        y = (busca_win.winfo_screenheight() // 2) - 75
        responsive_geometry(busca_win, 400, 150)
        
        frame = ttk.Frame(busca_win, padding=20)
        frame.pack(fill=tk.BOTH, expand=True)
        
        ttk.Label(frame, text="Número da OS:", font=("Segoe UI", 12)).pack(anchor='w')
        numero_var = tk.StringVar()
        numero_entry = ttk.Entry(frame, textvariable=numero_var, width=20, font=("Segoe UI", 14))
        numero_entry.pack(fill=tk.X, pady=(5, 15))
        numero_entry.focus_set()
        
        def buscar():
            numero = numero_var.get().strip().zfill(6)
            ordens = load_ordens_servico()
            if numero in ordens:
                busca_win.destroy()
                VisualizarOSWindow(self.root, self, numero)
            else:
                messagebox.showerror("Erro", f"OS #{numero} não encontrada.", parent=busca_win)
        
        numero_entry.bind('<Return>', lambda e: buscar())
        
        btn_frame = ttk.Frame(frame)
        btn_frame.pack(fill=tk.X)
        ttk.Button(btn_frame, text="🔍 Buscar", command=buscar,
                   bootstyle="success", width=12).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="❌ Cancelar", command=busca_win.destroy,
                   bootstyle="danger", width=12).pack(side=tk.RIGHT, padx=5)
    
    def relatorio_ordens_servico(self):
        """Abre relatório de Ordens de Serviço."""
        try:
            AUDITORIA.processo("Gerando relatório de ordens de serviço")
        except Exception:
            pass
        if not check_permission("os.visualizar"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar relatórios de OS.")
            return
        
        ordens = load_ordens_servico()
        
        rel_win = tk.Toplevel(self.root)
        rel_win.title("📊 Relatório de Ordens de Serviço")
        responsive_geometry(rel_win, 650, 550)
        rel_win.transient(self.root)
        
        frame = ttk.Frame(rel_win, padding=20)
        frame.pack(fill=tk.BOTH, expand=True)
        
        ttk.Label(frame, text="📊 RELATÓRIO DE ORDENS DE SERVIÇO",
                  font=("Segoe UI", 16, "bold")).pack(pady=(0, 20))
        
        # Calcular estatísticas
        total = len(ordens)
        por_status = {}
        por_prioridade = {}
        valor_total = 0.0
        valor_recebido = 0.0
        
        for os_data in ordens.values():
            status = os_data.get('status', 'Aberta')
            prioridade = os_data.get('prioridade', 'Normal')
            
            por_status[status] = por_status.get(status, 0) + 1
            por_prioridade[prioridade] = por_prioridade.get(prioridade, 0) + 1
            
            valor_total += float(os_data.get('valor_total', 0))
            valor_recebido += float(os_data.get('valor_pago', 0))
        
        # Exibir estatísticas
        stats_frame = tk.LabelFrame(frame, text="Resumo Geral", padx=15, pady=15)
        stats_frame.pack(fill=tk.X, pady=(0, 15))
        
        ttk.Label(stats_frame, text=f"Total de OS: {total}", font=("Segoe UI", 12, "bold")).pack(anchor='w')
        
        valor_fmt = f"R$ {valor_total:,.2f}".replace(',', 'X').replace('.', ',').replace('X', '.')
        recebido_fmt = f"R$ {valor_recebido:,.2f}".replace(',', 'X').replace('.', ',').replace('X', '.')
        pendente_fmt = f"R$ {(valor_total - valor_recebido):,.2f}".replace(',', 'X').replace('.', ',').replace('X', '.')
        
        ttk.Label(stats_frame, text=f"Valor Total: {valor_fmt}").pack(anchor='w')
        ttk.Label(stats_frame, text=f"Valor Recebido: {recebido_fmt}").pack(anchor='w')
        ttk.Label(stats_frame, text=f"Valor Pendente: {pendente_fmt}").pack(anchor='w')
        
        # Por status
        status_frame = tk.LabelFrame(frame, text="Por Status", padx=15, pady=15)
        status_frame.pack(fill=tk.X, pady=(0, 15))
        
        for status, count in sorted(por_status.items()):
            ttk.Label(status_frame, text=f"{status}: {count}").pack(anchor='w')
        
        # Por prioridade
        prio_frame = tk.LabelFrame(frame, text="Por Prioridade", padx=15, pady=15)
        prio_frame.pack(fill=tk.X, pady=(0, 15))
        
        for prio, count in sorted(por_prioridade.items()):
            ttk.Label(prio_frame, text=f"{prio}: {count}").pack(anchor='w')
        
        ttk.Button(frame, text="❌ Fechar", command=rel_win.destroy,
                   bootstyle="danger", width=15).pack(pady=(15, 0))
    
