    def _update_customer_display(self):
        # Garante que customers foi carregado
        if not isinstance(self.customers, dict): self.customers = DEFAULT_CUSTOMERS
        customer_data = self.customers.get(self.selected_customer_id)
        if not customer_data or not isinstance(customer_data, dict):
            self.selected_customer_id = "1"
            customer_data = self.customers.get("1", {})
        
        name = customer_data.get('nome', 'Consumidor Final')
        fidelidade = parse_br_float(customer_data.get('saldo_fidelidade', 0.0))
        credito = parse_br_float(customer_data.get('saldo_credito', 0.0))
        text = f"Cliente: {name}"
        # Cashback ocultado da exibição
        # if fidelidade > 0:
        #     text += f" | 💎 Cashback: {format_br_currency(fidelidade)}"
        if credito > 0:
            text += f" | 🎫 Crédito: {format_br_currency(credito)}"
        self.lbl_customer_display.config(text=text)

    def _atualizar_lista_produtos_btn(self):
        """Callback do botão Atualizar - recarrega produtos do banco de dados e atualiza a lista."""
        try:
            # Recarrega os produtos do banco de dados
            self.products = load_data(PRODUCTS_FILE, {})
            # Recarrega as categorias também
            self.categories = load_data(CATEGORIES_FILE, {})
            # Atualiza o combobox de categorias
            self._update_category_filter_options()
            # Atualiza a lista de produtos com os filtros atuais
            self._filtrar_produtos()
            print("[PDV] Lista de produtos atualizada manualmente pelo usuário")
        except Exception as e:
            print(f"[PDV] Erro ao atualizar lista de produtos: {e}")

    def _atualizar_lista_produtos(self, filtro_nome="", filtro_cat_id=None):
        # Otimização Atômica: Batch delete
        self.tree_produtos.delete(*self.tree_produtos.get_children())
        if not isinstance(self.products, dict): return # Segurança
        filtro_nome = filtro_nome.lower()
        sorted_ids = sorted(self.products.keys(), key=lambda x: int(x) if x.isdigit() else float('inf'))

        for prod_id in sorted_ids:
            dados = self.products.get(prod_id)
            if not isinstance(dados, dict): continue # Pula dados inválidos
            
            # Busca por código de barras, nome do produto e categoria
            if filtro_nome:
                codigo_barras = dados.get('codigo_barras', '').lower()
                nome_produto = dados.get('nome', '').lower()
                
                # Obtém o nome da categoria para busca
                prod_cat_id = str(dados.get('category_id', ''))
                cat_name = self.categories.get(prod_cat_id, {}).get('nome', '').lower()
                
                # Verifica se o filtro está presente em qualquer um dos campos
                if (filtro_nome not in codigo_barras and 
                    filtro_nome not in nome_produto and 
                    filtro_nome not in cat_name):
                    continue
                    
            prod_cat_id = str(dados.get('category_id', ''))
            if filtro_cat_id and filtro_cat_id != prod_cat_id: continue

            cat_name = self.categories.get(prod_cat_id, {}).get('nome', 'N/A')
            preco_val = parse_br_float(dados.get('preco', 0.0)) # Usa parse_br_float se preço estiver salvo com vírgula
            if preco_val is None: preco_val = 0.0
            tipo_val = dados.get('tipo', 'unidade')
            
            # ========== VERIFICAÇÃO DE PREÇO PROMOCIONAL PARA EXIBIÇÃO ==========
            preco_exibicao = preco_val
            # Verifica promocao_ativa aceitando múltiplos formatos (int, bool, string)
            _promo_ativa_raw = dados.get('promocao_ativa', False)
            promocao_ativa = _promo_ativa_raw in (1, True, '1', 'true', 'True') or _promo_ativa_raw is True
            preco_promocional = parse_br_float(dados.get('preco_promocional', 0.0))
            promocao_inicio = dados.get('promocao_inicio', '').strip() if dados.get('promocao_inicio') else ''
            promocao_fim = dados.get('promocao_fim', '').strip() if dados.get('promocao_fim') else ''
            
            if promocao_ativa and preco_promocional and preco_promocional > 0 and promocao_inicio and promocao_fim:
                try:
                    from datetime import datetime
                    hoje = datetime.now().date()
                    dt_inicio = datetime.strptime(promocao_inicio, '%d/%m/%Y').date()
                    dt_fim = datetime.strptime(promocao_fim, '%d/%m/%Y').date()
                    if dt_inicio <= hoje <= dt_fim:
                        preco_exibicao = preco_promocional
                except (ValueError, TypeError):
                    pass  # Ignora erros de data e usa preço normal
            # ========== FIM VERIFICAÇÃO DE PREÇO PROMOCIONAL ==========
            
            preco_str = format_br_currency(preco_exibicao) + sufixo_preco_produto(tipo_val)
            estoque_val = parse_br_float(dados.get('estoque', 0.0))
            if estoque_val is None: estoque_val = 0.0
            estoque_str = formatar_estoque_produto(estoque_val, tipo_val)

            # CORREÇÃO: Exibe produto mesmo com estoque zerado ou negativo (sem bloqueio por estoque)
            try:
                # Obtém o nome do produto com tamanho concatenado (se houver)
                nome_base = dados.get("nome", "")
                tamanho_id = dados.get("tamanho_id")
                tamanhos_dict = getattr(self, 'tamanhos', None)
                nome_exibicao = get_nome_produto_com_tamanho(nome_base, tamanho_id, tamanhos_dict)
                
                values = (dados.get("codigo_barras", ""), nome_exibicao, estoque_str, preco_str)
                self.tree_produtos.insert("", tk.END, values=values, iid=prod_id, tags=("low_stock",) if estoque_val < 5 else ())
            except tk.TclError as e: print(f"Erro Tcl ao inserir produto {prod_id}: {e}")

    def _handle_search_enter(self):
        if self.barcode_mode_active:
            # No modo de código de barras, processa o comando apenas no Enter
            filtro_entrada = self.search_var.get().strip()
            if not filtro_entrada:
                return
                
            # Tenta parsear quantidade * código de barras
            qtd = 1.0
            codigo_barras = filtro_entrada
            if '*' in filtro_entrada:
                try:
                    partes = filtro_entrada.split('*', 1)
                    qtd = parse_br_float(partes[0])
                    codigo_barras = partes[1]
                    if qtd is None or qtd <= 0: # Garante que a quantidade é válida
                        raise ValueError("Quantidade inválida")
                except (ValueError, IndexError):
                    messagebox.showwarning("Entrada Inválida", "Formato inválido. Use 'quantidade*codigo' ou apenas 'codigo'.", parent=self.root)
                    self.search_var.set("")
                    self.search_entry.focus()
                    return

            found_product_id = None
            for prod_id, prod_data in self.products.items():
                if prod_data.get('codigo_barras', '').lower() == codigo_barras.lower():
                    found_product_id = prod_id
                    break

            if found_product_id:
                # Adiciona o produto com a quantidade especificada
                self.adicionar_produto_por_id(found_product_id, quantidade_predefinida=qtd)
                self.search_var.set("") # Limpa o campo após adicionar
                # Atualiza a lista de produtos para mostrar todos novamente
                filtro_cat_str = self.category_filter_var.get()
                filtro_cat_id = None
                if filtro_cat_str != "Todas" and ' - ' in filtro_cat_str:
                    filtro_cat_id = filtro_cat_str.split(' - ')[0]
                self._atualizar_lista_produtos("", filtro_cat_id)
            else:
                messagebox.showwarning("Produto Não Encontrado", f"Nenhum produto com código de barras '{codigo_barras}' encontrado.", parent=self.root)
                self.search_var.set("") # Limpa o campo mesmo se não encontrar
                # Atualiza a lista de produtos para mostrar todos novamente
                filtro_cat_str = self.category_filter_var.get()
                filtro_cat_id = None
                if filtro_cat_str != "Todas" and ' - ' in filtro_cat_str:
                    filtro_cat_id = filtro_cat_str.split(' - ')[0]
                self._atualizar_lista_produtos("", filtro_cat_id)
            self.search_entry.focus() # Mantém o foco no campo de busca
        else:
            # No modo normal, apenas filtra os produtos
            self._filtrar_produtos()
            # CORREÇÃO: Se houver produtos na lista filtrada, adiciona o primeiro automaticamente
            # Funciona independente de letras maiúsculas ou minúsculas
            children = self.tree_produtos.get_children()
            if len(children) >= 1:
                first_item_id = children[0]
                self.tree_produtos.selection_set(first_item_id) # Seleciona o item
                self.adicionar_produto() # Adiciona ao carrinho
                self.search_var.set("") # Limpa o campo de busca
                self._filtrar_produtos() # Atualiza a lista para mostrar todos novamente
            self.search_entry.focus() # Mantém o foco no campo de busca

    def _toggle_barcode_mode(self):
        # Este botão no carrinho apenas ativa/desativa o modo de código de barras
        # e transfere o foco para o campo de busca de produtos.
        self.barcode_mode_active = not self.barcode_mode_active
        if self.barcode_mode_active:
            self.btn_barcode_on.grid_remove()
            self.btn_barcode_off.grid()
            self.search_var.set("") # Limpa o campo de busca
            self.search_entry.focus() # Coloca o foco no campo de busca
            messagebox.showinfo("Modo Leitor de Código de Barras", "Modo ativado.\n\nDigite: quantidade*código_de_barras (exemplo: 2*123456789)\nOu apenas: código_de_barras (exemplo: 123456789)\n\nPressione ENTER para adicionar ao carrinho.\n\nA busca em tempo real está desabilitada neste modo.", parent=self.root)
        else:
            self.btn_barcode_off.grid_remove()
            self.btn_barcode_on.grid()
            messagebox.showinfo("Modo Leitor de Código de Barras", "Modo desativado.", parent=self.root)
        self._filtrar_produtos() # Atualiza a lista de produtos

    def _filtrar_produtos(self):
        filtro_entrada = self.search_var.get().strip()
        filtro_cat_str = self.category_filter_var.get()
        filtro_cat_id = None
        if filtro_cat_str != "Todas" and ' - ' in filtro_cat_str:
            filtro_cat_id = filtro_cat_str.split(' - ')[0]

        if self.barcode_mode_active:
            # No modo leitor de código de barras, não filtra em tempo real
            # Apenas mostra todos os produtos ou limpa a lista
            if not filtro_entrada:
                # Se não há entrada, mostra todos os produtos
                self._atualizar_lista_produtos("", filtro_cat_id)
            else:
                # Se há entrada, limpa a lista para não mostrar sugestões
                for i in self.tree_produtos.get_children(): 
                    self.tree_produtos.delete(i)
        else:
            # Comportamento normal de filtragem por nome, código de barras ou categoria
            self._atualizar_lista_produtos(filtro_entrada, filtro_cat_id)

    # --- Funções de Visualização de Imagem do Produto ---
    def _on_product_select(self, event=None):
        """Atualiza o painel de imagem quando um produto é selecionado."""
        selected_iid = self.tree_produtos.focus()
        if not selected_iid:
            selected_items = self.tree_produtos.selection()
            if selected_items:
                selected_iid = selected_items[0]
        
        if not selected_iid:
            self._clear_product_image_panel()
            return
        
        # Obtém dados do produto
        product_data = self.products.get(selected_iid)
        if not product_data:
            self._clear_product_image_panel()
            return
        
        # Atualiza informações do produto
        nome_base = product_data.get('nome', 'N/A')
        tamanho_id = product_data.get('tamanho_id')
        tamanhos_dict = getattr(self, 'tamanhos', None)
        nome = get_nome_produto_com_tamanho(nome_base, tamanho_id, tamanhos_dict)
        
        preco = parse_br_float(product_data.get('preco', 0.0))
        tipo = product_data.get('tipo', 'unidade')
        estoque = parse_br_float(product_data.get('estoque', 0.0))
        cat_id = str(product_data.get('category_id', ''))
        cat_name = self.categories.get(cat_id, {}).get('nome', 'N/A')
        
        # Atualiza labels
        self.product_name_label.config(text=nome)
        preco_str = format_br_currency(preco) + sufixo_preco_produto(tipo)
        self.product_price_label.config(text=preco_str)
        
        estoque_str = f"Estoque: {formatar_estoque_produto(estoque, tipo)}"
        self.product_stock_label.config(text=estoque_str)
        self.product_category_label.config(text=f"Categoria: {cat_name}")
        
        # Carrega imagem do produto
        self._load_product_image_for_sale(selected_iid, product_data)
    
    def _mostrar_zoom_imagem_pdv(self, event=None):
        """Abre o zoom da imagem do produto selecionado no PDV."""
        if not hasattr(self, 'current_product_image_path') or not self.current_product_image_path:
            return
        
        if not os.path.exists(self.current_product_image_path):
            return
            
        # Cria uma janela de zoom (Toplevel)
        zoom_win = tk.Toplevel(self.root)
        zoom_win.title("🔍 Detalhes do Produto")
        zoom_win.transient(self.root)
        zoom_win.grab_set()
        zoom_win.configure(bg='#1a1a2e')
        
        # Tenta centralizar e definir tamanho responsivo
        if hasattr(self, 'root'):
            responsive_geometry(zoom_win, 1100, 900)
        else:
            zoom_win.geometry("1100x900")
            
        # Instrução
        tk.Label(zoom_win, text="Passe o mouse sobre a imagem para usar a lupa | Clique para fechar", 
                 font=("Segoe UI", 10), fg='#888888', bg='#1a1a2e').pack(pady=5)
        
        # Frame para a imagem
        zoom_frame = tk.Frame(zoom_win, bg='#1a1a2e', padx=10, pady=10)
        zoom_frame.pack(fill=tk.BOTH, expand=True)
        
        # Canvas para permitir desenho da lupa
        canvas = tk.Canvas(zoom_frame, bg='#1a1a2e', highlightthickness=0)
        canvas.pack(fill=tk.BOTH, expand=True)
        
        # Referências de imagem
        img_refs = {
            'original': None,
            'display': None,
            'tk_display': None,
            'magnifier_tk': None,
            'zoom_factor': 2.5,
            'lupa_size': 250,
            'coords': (0, 0, 0, 0)
        }
        
        def carregar_e_preparar():
            try:
                from PIL import Image, ImageTk
                img_refs['original'] = Image.open(self.current_product_image_path)
                
                # Calcula tamanho do display
                zoom_win.update_idletasks()
                w, h = canvas.winfo_width(), canvas.winfo_height()
                if w <= 1 or h <= 1: w, h = 1000, 800
                
                # Cria imagem de exibição (display)
                display_img = img_refs['original'].copy()
                display_img.thumbnail((w-20, h-20), Image.Resampling.LANCZOS)
                img_refs['display'] = display_img
                img_refs['tk_display'] = ImageTk.PhotoImage(display_img)
                
                # Centraliza imagem no canvas
                canvas.delete("all")
                x_center, y_center = w//2, h//2
                canvas.create_image(x_center, y_center, image=img_refs['tk_display'], tags="prod_img")
                
                # Armazena as coordenadas da imagem para a lupa
                img_w, img_h = display_img.size
                img_refs['coords'] = (x_center - img_w//2, y_center - img_h//2, x_center + img_w//2, y_center + img_h//2)
                
            except Exception as e:
                print(f"Erro ao carregar lupa: {e}")
                zoom_win.destroy()

        def mover_lupa(event):
            if not img_refs['display']: return
            
            x, y = event.x, event.y
            x1, y1, x2, y2 = img_refs['coords']
            
            # Verifica se o mouse está sobre a imagem
            if x1 <= x <= x2 and y1 <= y <= y2:
                from PIL import Image, ImageTk, ImageDraw
                # Calcula posição relativa na imagem de exibição (0.0 a 1.0)
                rel_x = (x - x1) / (x2 - x1)
                rel_y = (y - y1) / (y2 - y1)
                
                # Calcula posição correspondente na imagem original
                orig_w, orig_h = img_refs['original'].size
                orig_x = int(rel_x * orig_w)
                orig_y = int(rel_y * orig_h)
                
                # Define área de recorte para a lupa
                s = img_refs['lupa_size'] // img_refs['zoom_factor']
                left = max(0, orig_x - s//2)
                top = max(0, orig_y - s//2)
                right = min(orig_w, left + s)
                bottom = min(orig_h, top + s)
                
                # Recorta e amplia
                crop = img_refs['original'].crop((left, top, right, bottom))
                crop = crop.resize((img_refs['lupa_size'], img_refs['lupa_size']), Image.Resampling.LANCZOS)
                
                # Cria máscara circular para a lupa
                mask = Image.new('L', (img_refs['lupa_size'], img_refs['lupa_size']), 0)
                draw = ImageDraw.Draw(mask)
                draw.ellipse((0, 0, img_refs['lupa_size'], img_refs['lupa_size']), fill=255)
                
                # Aplica máscara
                output = Image.new('RGBA', (img_refs['lupa_size'], img_refs['lupa_size']), (0,0,0,0))
                output.paste(crop, (0,0), mask)
                
                img_refs['magnifier_tk'] = ImageTk.PhotoImage(output)
                
                # Desenha no canvas
                canvas.delete("lupa")
                canvas.create_image(x, y, image=img_refs['magnifier_tk'], tags="lupa")
                # Borda da lupa
                canvas.create_oval(x-img_refs['lupa_size']//2, y-img_refs['lupa_size']//2, 
                                 x+img_refs['lupa_size']//2, y+img_refs['lupa_size']//2, 
                                 outline="#00d4ff", width=3, tags="lupa")
            else:
                canvas.delete("lupa")

        def fechar(event=None):
            zoom_win.destroy()

        # Binds
        zoom_win.after(100, carregar_e_preparar)
        canvas.bind('<Motion>', mover_lupa)
        canvas.bind('<Button-1>', fechar)
        zoom_win.bind('<Escape>', fechar)
        
        # Botão fechar
        ttk.Button(zoom_win, text="FECHAR (ESC)", command=zoom_win.destroy, bootstyle="danger").pack(pady=10)

    def _load_product_image_for_sale(self, product_id, product_data):
        """Carrega e exibe a imagem do produto no painel de vendas."""
        if not PIL_AVAILABLE:
            self.product_image_label.config(text="\n📷\nPIL não disponível\n", image='')
            self.current_product_image_path = None
            return
        
        # Verifica se o produto tem imagem
        image_filename = product_data.get('imagem', '')
        image_path = None
        
        if image_filename:
            image_path = os.path.join(PRODUCT_IMAGES_DIR, image_filename)
            if not os.path.exists(image_path):
                image_path = None
        
        # Tenta encontrar por padrão de nome se não encontrou
        if not image_path:
            for ext in ['.png', '.jpg', '.jpeg', '.gif', '.bmp']:
                test_path = os.path.join(PRODUCT_IMAGES_DIR, f"produto_{product_id}{ext}")
                if os.path.exists(test_path):
                    image_path = test_path
                    break
        
        # Armazena o caminho para o zoom
        self.current_product_image_path = image_path
        
        if image_path:
            try:
                # Carrega e redimensiona a imagem
                img = Image.open(image_path)
                img.thumbnail((120, 120), Image.Resampling.LANCZOS)
                self.current_product_image_tk = ImageTk.PhotoImage(img)
                self.product_image_label.config(image=self.current_product_image_tk, text='')
            except Exception as e:
                try:
                    AUDITORIA.erro(f"Erro no sistema: {e}")
                except Exception:
                    pass
                print(f"Erro ao carregar imagem do produto: {e}")
                self.product_image_label.config(text="\n📷\nErro ao carregar\n", image='')
        else:
            self.product_image_label.config(text="\n📷\nSem imagem\n", image='')
    
    def _clear_product_image_panel(self):
        """Limpa o painel de imagem do produto."""
        self.product_image_label.config(text="\n📷\nSelecione um produto\n", image='')
        self.product_name_label.config(text="")
        self.product_price_label.config(text="")
        self.product_stock_label.config(text="")
        self.product_category_label.config(text="")
        self.current_product_image_tk = None
        self.current_product_image_path = None

    # --- Funções do Carrinho e Venda (Revisadas com Vírgula Decimal) ---
    def adicionar_produto(self):
        try:
            AUDITORIA.venda("Adicionando produto ao carrinho")
        except Exception:
            pass
        if not check_permission("vendas.acessar"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para realizar vendas.")
            return
            
        selected_iid = self.tree_produtos.focus()
        if not selected_iid:
            selected_items = self.tree_produtos.selection()
            if not selected_items: messagebox.showwarning("Seleção", "Selecione um produto."); return
            selected_iid = selected_items[0]
        self.adicionar_produto_por_id(selected_iid)

    def adicionar_produto_por_id(self, prod_id, quantidade_predefinida=None):
        try:
            AUDITORIA.venda("Adicionando produto ao carrinho por ID")
        except Exception:
            pass
        dados_produto = self.products.get(prod_id)
        if not dados_produto: messagebox.showerror("Erro", "Produto não encontrado."); return

        tipo_produto = dados_produto.get("tipo", "unidade")
        estoque_disponivel = parse_br_float(dados_produto.get("estoque", 0.0))
        if estoque_disponivel is None: estoque_disponivel = 0.0

        item_no_carrinho = self.carrinho.get(prod_id)
        if item_no_carrinho:
            qtd_carrinho = parse_br_float(item_no_carrinho.get("quantidade_peso", 0.0))
            if qtd_carrinho is not None: estoque_disponivel -= qtd_carrinho

        # CORREÇÃO: Permite venda mesmo com estoque zerado ou negativo (sem bloqueio)

        valor_adicionar = quantidade_predefinida
        if valor_adicionar is None: # Se não foi predefinido (ex: via código de barras)
            prompt_titulo, prompt_texto = "", ""
            # CORREÇÃO: Remove limite máximo pelo estoque para permitir venda com estoque zerado/negativo
            max_valor = None  # Sem limite máximo por estoque
            min_valor = 0.001
            initial = 1.0

            info_unidade = dados_unidade_produto(tipo_produto)
            prompt_titulo = info_unidade['titulo']
            prompt_texto = (
                f"Quantidade de {dados_produto.get('nome', 'N/A')}?\n"
                f"(Estoque: {formatar_estoque_produto(estoque_disponivel, tipo_produto)}"
                f" / Unidade: {info_unidade['label']})"
            )
            initial = 1.0

            # Usa o diálogo customizado que retorna float
            valor_adicionar = ask_br_float(self.root, prompt_titulo, prompt_texto,
                                             initialvalue=initial, minvalue=min_valor, maxvalue=max_valor)

        # Validação para medidas inteiras (unidade/caixa/pacote/dúzia): não permite fracionado
        if dados_unidade_produto(tipo_produto)['inteiro'] and valor_adicionar is not None:
            if valor_adicionar != int(valor_adicionar):
                messagebox.showerror("Erro", f"Produtos do tipo {tipo_produto.upper()} aceitam apenas quantidades inteiras (1, 2, 3...).", parent=self.root)
                return
            valor_adicionar = int(valor_adicionar)

        if valor_adicionar is None or valor_adicionar <= 0: return

        preco_produto = parse_br_float(dados_produto.get("preco", 0.0))
        if preco_produto is None: preco_produto = 0.0
        
        # ========== VERIFICAÇÃO DE PREÇO PROMOCIONAL ==========
        # Verifica se há promoção ativa e válida para aplicar o preço promocional
        preco_promocional = parse_br_float(dados_produto.get("preco_promocional", 0.0))
        # Verifica promocao_ativa aceitando múltiplos formatos (int, bool, string)
        _promo_ativa_raw = dados_produto.get("promocao_ativa", False)
        promocao_ativa = _promo_ativa_raw in (1, True, '1', 'true', 'True') or _promo_ativa_raw is True
        promocao_inicio = dados_produto.get("promocao_inicio", "").strip() if dados_produto.get("promocao_inicio") else ""
        promocao_fim = dados_produto.get("promocao_fim", "").strip() if dados_produto.get("promocao_fim") else ""
        
        # DEBUG: Mostra valores para diagnóstico
        print(f"[DEBUG PROMO] Produto: {dados_produto.get('nome')}")
        print(f"[DEBUG PROMO] promocao_ativa RAW: {_promo_ativa_raw} (tipo: {type(_promo_ativa_raw)})")
        print(f"[DEBUG PROMO] promocao_ativa CONV: {promocao_ativa}")
        print(f"[DEBUG PROMO] preco_promocional: {preco_promocional}")
        print(f"[DEBUG PROMO] promocao_inicio: '{promocao_inicio}' | promocao_fim: '{promocao_fim}'")
        
        usar_preco_promocional = False
        if promocao_ativa and preco_promocional and preco_promocional > 0 and promocao_inicio and promocao_fim:
            try:
                from datetime import datetime
                hoje = datetime.now().date()
                dt_inicio = datetime.strptime(promocao_inicio, '%d/%m/%Y').date()
                dt_fim = datetime.strptime(promocao_fim, '%d/%m/%Y').date()
                print(f"[DEBUG PROMO] hoje: {hoje} | dt_inicio: {dt_inicio} | dt_fim: {dt_fim}")
                print(f"[DEBUG PROMO] Em período? {dt_inicio <= hoje <= dt_fim}")
                if dt_inicio <= hoje <= dt_fim:
                    usar_preco_promocional = True
                    preco_produto = preco_promocional
                    print(f"[DEBUG PROMO] APLICANDO PREÇO PROMOCIONAL: {preco_produto}")
            except (ValueError, TypeError) as e:
                print(f"[DEBUG PROMO] ERRO ao processar datas: {e}")
                pass  # Ignora erros de data e usa preço normal
        else:
            print(f"[DEBUG PROMO] Condições não atendidas - usando preço normal")
        print(f"[DEBUG PROMO] Preço final: {preco_produto} | usar_preco_promocional: {usar_preco_promocional}")
        # ========== FIM VERIFICAÇÃO DE PREÇO PROMOCIONAL ==========
        
        # ========== VERIFICAÇÃO DE PREÇO DE ATACADO ==========
        # Verifica se a quantidade atinge o mínimo para atacado e se há preço de atacado configurado
        preco_atacado = parse_br_float(dados_produto.get("preco_atacado", 0.0))
        atacado_qtd_minima = parse_br_float(dados_produto.get("atacado_qtd_minima", 10.0))
        if preco_atacado is None: preco_atacado = 0.0
        if atacado_qtd_minima is None: atacado_qtd_minima = 10.0
        
        # Calcula a quantidade total (atual no carrinho + nova quantidade)
        qtd_total = valor_adicionar
        if prod_id in self.carrinho:
            qtd_carrinho_atual = parse_br_float(self.carrinho[prod_id].get("quantidade_peso", 0.0))
            if qtd_carrinho_atual: qtd_total += qtd_carrinho_atual
        
        # Se tem preço de atacado configurado e quantidade atinge o mínimo, pergunta ao usuário
        usar_preco_atacado = False
        if preco_atacado > 0 and qtd_total >= atacado_qtd_minima and tipo_produto == "unidade":
            # Exibe diálogo de confirmação de preço de atacado
            resultado_atacado = PrecoAtacadoDialog.ask(
                self.root, 
                quantidade=qtd_total, 
                preco_varejo=preco_produto, 
                preco_atacado=preco_atacado
            )
            
            if resultado_atacado is None:
                # Usuário cancelou a operação
                return
            elif resultado_atacado:
                # Usuário escolheu usar preço de atacado
                usar_preco_atacado = True
                preco_produto = preco_atacado
        # ========== FIM VERIFICAÇÃO DE PREÇO DE ATACADO ==========

        if prod_id in self.carrinho:
            qtd_atual = parse_br_float(self.carrinho[prod_id]["quantidade_peso"])
            if qtd_atual is None: qtd_atual = 0.0
            self.carrinho[prod_id]["quantidade_peso"] = qtd_atual + valor_adicionar
            # Atualiza o preço se optou por atacado
            if usar_preco_atacado:
                self.carrinho[prod_id]["preco"] = preco_produto
                self.carrinho[prod_id]["preco_atacado_aplicado"] = True
        else:
            # Obtém o nome do produto com tamanho concatenado (se houver)
            nome_base = dados_produto.get("nome", "N/A")
            tamanho_id = dados_produto.get("tamanho_id")
            tamanhos_dict = getattr(self, 'tamanhos', None)
            nome_exibicao = get_nome_produto_com_tamanho(nome_base, tamanho_id, tamanhos_dict)
            
            self.carrinho[prod_id] = {
                "nome": nome_exibicao,
                "nome_original": nome_base,  # Armazena o nome original sem tamanho
                "preco": preco_produto,
                "preco_original": parse_br_float(dados_produto.get("preco", 0.0)) or 0.0, # Armazena o preço original de varejo
                "quantidade_peso": valor_adicionar,
                "tipo": tipo_produto,
                "id": prod_id,
                "desconto": 0.0,
                "acrescimo": 0.0,
                "preco_atacado_aplicado": usar_preco_atacado,
                "preco_promocional_aplicado": usar_preco_promocional
            }
        log_user_action("Adicionar Produto ao Carrinho", dados_produto.get("nome")); self._atualizar_carrinho_e_total()
        self.tree_carrinho.focus_set()
        if self.tree_carrinho.exists(prod_id):
             self.tree_carrinho.selection_set(prod_id); self.tree_carrinho.focus(prod_id); self.tree_carrinho.see(prod_id)

    def remover_produto(self):
        try:
            AUDITORIA.venda("Removendo produto do carrinho")
        except Exception:
            pass
        selected_iid = self.tree_carrinho.focus()
        if not selected_iid:
            selected_items = self.tree_carrinho.selection()
            if not selected_items: messagebox.showwarning("Seleção", "Selecione um item do carrinho."); return
            selected_iid = selected_items[0]
        prod_id_remover = selected_iid
        if prod_id_remover in self.carrinho:
            nome_produto = self.carrinho[prod_id_remover]['nome']
            # Confirmação antes de remover
            if not messagebox.askyesno("Confirmar Exclusão", f"Deseja mesmo excluir esse item do carrinho?\n\nProduto: {nome_produto}", parent=self.root):
                return
            log_user_action('Remover Produto do Carrinho', nome_produto)
            del self.carrinho[prod_id_remover]
            self._atualizar_carrinho_e_total()
        else: messagebox.showerror("Erro Interno", f"Item ID {prod_id_remover} não no carrinho.")

    def alterar_item_carrinho(self):
        try:
            AUDITORIA.venda("Alterando item do carrinho")
        except Exception:
            pass
        selected_iid = self.tree_carrinho.focus()
        if not selected_iid:
            selected_items = self.tree_carrinho.selection()
            if not selected_items: messagebox.showwarning("Seleção", "Selecione um item do carrinho."); return
            selected_iid = selected_items[0]

        prod_id_alterar = selected_iid
        if prod_id_alterar not in self.carrinho: messagebox.showerror("Erro Interno", "Item não no carrinho."); return

        dados_carrinho_item = self.carrinho[prod_id_alterar]
        dados_produto_estoque = self.products.get(prod_id_alterar)
        if not dados_produto_estoque: messagebox.showerror("Erro", "Dados do produto não encontrados."); return

        tipo_produto = dados_carrinho_item.get('tipo', 'unidade')
        qtd_peso_atual = parse_br_float(dados_carrinho_item.get('quantidade_peso', 0.0))
        if qtd_peso_atual is None: qtd_peso_atual = 0.0
        estoque_total_produto = parse_br_float(dados_produto_estoque.get('estoque', 0.0))
        if estoque_total_produto is None: estoque_total_produto = 0.0
        nome_produto = dados_carrinho_item.get('nome', 'N/A')

        novo_valor = None
        prompt_titulo, prompt_texto = "", ""
        max_valor = estoque_total_produto
        min_valor = 0.0 # Permite zerar

        if tipo_produto == 'unidade':
            prompt_titulo = "Alterar Quantidade (Unidades)"
            prompt_texto = f"Nova qtd para '{nome_produto}'?\n(Estoque total: {format_br_float(max_valor, 0)} / Use vírgula)"
            novo_valor = ask_br_float(self.root, prompt_titulo, prompt_texto,
                                        initialvalue=qtd_peso_atual, minvalue=min_valor, maxvalue=max_valor)
        elif tipo_produto == 'peso':
            prompt_titulo = "Alterar Peso (em gramas)"
            prompt_texto = f"Novo peso (g) para '{nome_produto}'?\n(Estoque total: {format_br_float(max_valor, 3)}g / Use vírgula)"
            novo_valor = ask_br_float(self.root, prompt_titulo, prompt_texto,
                                        initialvalue=qtd_peso_atual, minvalue=min_valor, maxvalue=max_valor)

        if novo_valor is not None:
            if novo_valor > 0.0001:
                self.carrinho[prod_id_alterar]["quantidade_peso"] = novo_valor
                log_user_action("Alterar Quantidade/Peso", f"{nome_produto}: {format_br_float(qtd_peso_atual, 3)} -> {format_br_float(novo_valor, 3)}")
            else:
                log_user_action("Remover Produto do Carrinho (Alterar Qtd/Peso)", nome_produto)
                del self.carrinho[prod_id_alterar]
            self._atualizar_carrinho_e_total()

    def limpar_carrinho(self, confirmar=True):
        try:
            AUDITORIA.venda("Limpando carrinho")
        except Exception:
            pass
        if not self.carrinho: return
        
        # ===================================================================
        # CONFIRMAÇÃO ANTES DE LIMPAR O CARRINHO
        # Só exibe a confirmação quando chamado pelo botão (confirmar=True).
        # No encerramento de venda, é chamado com confirmar=False (automático).
        # ===================================================================
        if confirmar:
            if not messagebox.askyesno("Limpar Carrinho", "Deseja realmente limpar o carrinho?", parent=self.root):
                return
        
        # ===================================================================
        # RESTAURAÇÃO AUTOMÁTICA DE COMANDA AO CANCELAR VENDA
        # Se a venda era proveniente de uma comanda, restaura automaticamente
        # ===================================================================
        if hasattr(self, 'comanda_origem') and self.comanda_origem is not None:
            try:
                comanda_data = self.comanda_origem
                num_comanda = comanda_data['numero']
                
                # Restaura automaticamente sem perguntar
                # Inicializa o comanda_manager se necessário
                if not hasattr(self, 'comanda_manager'):
                    self.comanda_manager = ComandaManager(self)
                
                # Restaura a comanda com os dados originais
                self.comanda_manager.comandas[num_comanda] = {
                    'abertura': comanda_data.get('abertura', datetime.datetime.now().strftime('%d/%m/%Y %H:%M:%S')),
                    'itens': comanda_data.get('itens_backup', []),
                    'cliente': comanda_data.get('cliente', 'Consumidor Final'),
                    'cliente_id': comanda_data.get('cliente_id', '1'),
                    'observacao': comanda_data.get('observacao', '')
                }
                
                # Salva as comandas e notifica
                self.comanda_manager._save_comandas(notify_action='created', notify_numero=num_comanda)
                
                # Devolve o estoque dos itens (já que a venda foi cancelada)
                for item in comanda_data.get('itens_backup', []):
                    try:
                        item_id = str(item.get('id', ''))
                        qtd = item.get('qtd', item.get('quantidade', 0))
                        
                        # Tenta encontrar o produto
                        for pid_format in [item_id, str(item_id)]:
                            if pid_format in self.products:
                                estoque_atual = parse_br_float(self.products[pid_format].get('estoque', 0.0)) or 0.0
                                novo_estoque = estoque_atual + float(qtd)
                                self.products[pid_format]['estoque'] = novo_estoque
                                print(f"[COMANDA RESTAURADA] Estoque devolvido: Produto {pid_format} - Qtd: {qtd} - Novo estoque: {novo_estoque}")
                                break
                        
                        # Tenta com int
                        try:
                            pid_int = int(item_id)
                            if pid_int in self.products:
                                estoque_atual = parse_br_float(self.products[pid_int].get('estoque', 0.0)) or 0.0
                                novo_estoque = estoque_atual + float(qtd)
                                self.products[pid_int]['estoque'] = novo_estoque
                                print(f"[COMANDA RESTAURADA] Estoque devolvido: Produto {pid_int} - Qtd: {qtd} - Novo estoque: {novo_estoque}")
                        except (ValueError, TypeError):
                            pass
                    except Exception as e:
                        print(f"[COMANDA RESTAURADA] Erro ao devolver estoque: {e}")
                
                # Salva os produtos com estoque atualizado
                save_data(PRODUCTS_FILE, self.products)
                
                # Atualiza a treeview de produtos para refletir o estoque devolvido na tela principal
                try:
                    self._popular_treeview_produtos()
                except Exception:
                    pass
                
                log_user_action(f"Comanda #{num_comanda} restaurada automaticamente após cancelamento de venda")
                messagebox.showinfo("Comanda Restaurada", 
                    f"A Comanda #{num_comanda} foi restaurada ao mural automaticamente!\n\n"
                    f"O estoque dos itens foi devolvido.")
                print(f"[COMANDA] Comanda #{num_comanda} restaurada automaticamente!")
                    
            except Exception as e:
                print(f"[COMANDA] Erro ao restaurar comanda: {e}")
                import traceback
                traceback.print_exc()
            finally:
                # Limpa os dados da comanda de origem
                self.comanda_origem = None
        
        self.carrinho = {}
        self.selected_customer_id = "1"
        self.is_delivery = False
        self.estoque_ja_descontado = False  # Reseta a flag de estoque
        self.desconto_aplicado = 0.0  # CORREÇÃO: Reseta desconto ao limpar carrinho para não persistir no próximo cupom
        self.acrescimo_aplicado = 0.0  # CORREÇÃO: Reseta acréscimo ao limpar carrinho para não persistir no próximo cupom
        self.selected_entregador_id = None  # CORREÇÃO: Reseta entregador ao limpar carrinho para não persistir no próximo cupom
        self.selected_vendedor_id = None  # Reseta vendedor ao limpar carrinho
        self.selected_vendedor_nome = ''  # Reseta nome do vendedor ao limpar carrinho
        self.os_origem = None  # Reseta a OS de origem
        log_user_action("Limpar Carrinho")
        self._atualizar_carrinho_e_total()
        self._update_customer_display()  # CORREÇÃO: Reseta o label do cliente na tela principal para 'Consumidor Final'

    def converter_venda_para_comanda(self):
        """
        if not check_permission("comandas.acessar"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para criar comandas.")
            return
        Converte a venda atual (carrinho) em uma nova comanda AUTOMATICAMENTE.
        Ao clicar no botão, a comanda é criada instantaneamente com o próximo número disponível.
        """
        try:
            AUDITORIA.venda("Convertendo venda para comanda")
        except Exception:
            pass
        # Verifica se há itens no carrinho
        if not self.carrinho:
            messagebox.showwarning("Carrinho Vazio", 
                "Não há itens no carrinho para converter em comanda.\n\n"
                "Adicione produtos ao carrinho antes de criar uma comanda.")
            return
        
        # Inicializa o comanda_manager se necessário
        if not hasattr(self, 'comanda_manager'):
            self.comanda_manager = ComandaManager(self)
        
        # Gera número automático único que NUNCA se repete usando contador persistente
        try:
            config_data = load_data(CONFIG_FILE, DEFAULT_CONFIG)
            ultimo_numero = int(config_data.get('last_comanda_number', 0))
            proximo_num = ultimo_numero + 1
            config_data['last_comanda_number'] = proximo_num
            save_data(CONFIG_FILE, config_data)
            self.config_data['last_comanda_number'] = proximo_num
            print(f"[COMANDA] Número sequencial gerado para conversão: #{proximo_num}")
        except Exception as e:
            print(f"[COMANDA] Erro ao gerar número: {e}")
            import time
            proximo_num = int(time.time()) % 100000
        
        num_comanda = str(proximo_num).zfill(3)
        
        # Obtém o cliente atual
        cliente_atual = self.customers.get(self.selected_customer_id, {}).get('nome', 'Consumidor Final')
        
        # Calcula totais para a mensagem de confirmação
        total_itens = 0
        total_valor = 0.0
        
        # Cria a nova comanda
        self.comanda_manager.comandas[num_comanda] = {
            'abertura': datetime.datetime.now().strftime('%d/%m/%Y %H:%M:%S'),
            'itens': [],
            'cliente': cliente_atual,
            'cliente_id': self.selected_customer_id,
            'observacao': ''
        }
        
        # Adiciona os itens do carrinho à comanda
        for prod_id, item_data in self.carrinho.items():
            nome = item_data.get('nome', 'Produto')
            qtd = item_data.get('quantidade_peso', 1)
            preco = parse_br_float(item_data.get('preco', 0))
            tipo = item_data.get('tipo', 'unidade')
            
            subtotal_base = preco * qtd
            desconto_item = parse_br_float(item_data.get('desconto', 0.0)) or 0.0
            acrescimo_item = parse_br_float(item_data.get('acrescimo', 0.0)) or 0.0
            subtotal = max(0.0, subtotal_base - desconto_item + acrescimo_item)
            
            self.comanda_manager.comandas[num_comanda]['itens'].append({
                'id': prod_id,
                'nome': nome,
                'qtd': qtd,
                'preco': preco,
                'subtotal': subtotal,
                'tipo': tipo
            })
            
            total_itens += 1
            total_valor += subtotal
        
        # ═══════════════════════════════════════════════════════════════════════
        # CORREÇÃO: Garantir que comanda nova fica visível e editável
        # ═══════════════════════════════════════════════════════════════════════
        if self.comanda_manager.comandas[num_comanda].get('sinalizada_para_fechar', False):
            self.comanda_manager.comandas[num_comanda]['sinalizada_para_fechar'] = False
            self.comanda_manager.comandas[num_comanda]['sinalizada_por'] = ''
            self.comanda_manager.comandas[num_comanda]['oculto_cozinha'] = False
        
        # Salva as comandas e notifica o servidor web
        self.comanda_manager._save_comandas(notify_action='created', notify_numero=num_comanda)
        
        # Limpa o carrinho
        self.carrinho = {}
        self.selected_customer_id = "1"
        self.is_delivery = False
        self.desconto_aplicado = 0.0  # CORREÇÃO: Reseta desconto ao converter para comanda
        self.acrescimo_aplicado = 0.0  # CORREÇÃO: Reseta acréscimo ao converter para comanda
        self.selected_entregador_id = None  # CORREÇÃO: Reseta entregador ao converter para comanda
        self.selected_vendedor_id = None  # Reseta vendedor ao converter para comanda
        self.selected_vendedor_nome = ''  # Reseta nome do vendedor ao converter para comanda
        self._atualizar_carrinho_e_total()
        
        # Registra a ação
        log_user_action(f"Converteu venda em Comanda #{num_comanda}")
        AUDIT_LOGGER.info(f"Venda convertida em Comanda #{num_comanda} com {total_itens} itens", user=logged_user)
        
        # Mensagem de sucesso
        messagebox.showinfo("✅ Comanda Criada",
            f"Venda convertida com sucesso!\n\n"
            f"📋 Comanda: #{num_comanda}\n"
            f"📎 Itens: {total_itens}\n"
            f"💰 Total: {format_br_currency(total_valor)}\n\n"
            f"A comanda está disponível no Mural de Comandas.")
        
        # Pergunta se deseja abrir o mural de comandas
        if messagebox.askyesno("Abrir Mural", "Deseja abrir o Mural de Comandas agora%s"):
            self.comanda_manager.show_comandas_window()

    def aplicar_desconto_acrescimo_item(self):
        try:
            AUDITORIA.venda("Aplicando desconto/acréscimo em item")
        except Exception:
            pass
        if not check_permission("vendas.aplicar_desconto"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para aplicar desconto/acréscimo.")
            return
        selected_iids = self.tree_carrinho.selection()
        if not selected_iids:
            messagebox.showwarning("Seleção", "Selecione um ou mais itens do carrinho para aplicar desconto/acréscimo.", parent=self.root)
            return

        # Janela de diálogo para escolher tipo e valor
        dialog = tk.Toplevel(self.root)
        dialog.title("Desconto/Acréscimo no Item")
        responsive_geometry(dialog, 350, 200)
        dialog.transient(self.root)
        dialog.grab_set()

        ttk.Label(dialog, text="Aplicar em {} item(s) selecionado(s)".format(len(selected_iids))).pack(pady=5)

        frame = ttk.Frame(dialog, padding=10)
        frame.pack(expand=True, fill=tk.BOTH)

        # Tipo: Desconto ou Acréscimo
        tipo_var = tk.StringVar(value="desconto")
        ttk.Radiobutton(frame, text="Desconto", variable=tipo_var, value="desconto").grid(row=0, column=0, padx=5, sticky='w')
        ttk.Radiobutton(frame, text="Acréscimo", variable=tipo_var, value="acrescimo").grid(row=0, column=1, padx=5, sticky='w')

        # Modo: Porcentagem ou Valor Fixo
        modo_var = tk.StringVar(value="porcentagem")
        ttk.Radiobutton(frame, text="Porcentagem (%)", variable=modo_var, value="porcentagem").grid(row=1, column=0, padx=5, sticky='w')
        ttk.Radiobutton(frame, text="Valor Fixo (R$)", variable=modo_var, value="valor").grid(row=1, column=1, padx=5, sticky='w')

        # Campo de Valor
        ttk.Label(frame, text="Valor:").grid(row=2, column=0, pady=5, sticky='w')
        valor_var = tk.StringVar()
        valor_entry = ttk.Entry(frame, textvariable=valor_var, width=15)
        valor_entry.grid(row=2, column=1, pady=5, sticky='w')
        valor_entry.focus()

        def on_confirm():
            valor_str = valor_var.get()
            valor = parse_br_float(valor_str)
            if valor is None or valor < 0:
                messagebox.showerror("Valor Inválido", "Por favor, insira um valor numérico positivo.", parent=dialog)
                return

            tipo = tipo_var.get()
            modo = modo_var.get()

            for item_id in selected_iids:
                if item_id in self.carrinho:
                    item = self.carrinho[item_id]
                    subtotal_original = (item.get('preco_original') or item['preco']) * item['quantidade_peso']

                    if modo == "porcentagem":
                        modificador = subtotal_original * (valor / 100.0)
                    else: # modo == "valor"
                        # Divide o valor fixo pelo número de itens selecionados
                        modificador = valor / len(selected_iids)

                    if tipo == "desconto":
                        item['desconto'] = item.get('desconto', 0) + modificador
                        item['acrescimo'] = 0 # Zera o oposto
                    else: # tipo == "acrescimo"
                        item['acrescimo'] = item.get('acrescimo', 0) + modificador
                        item['desconto'] = 0 # Zera o oposto

            self._atualizar_carrinho_e_total()
            dialog.destroy()

        btn_frame = ttk.Frame(dialog)
        btn_frame.pack(pady=10)
        ttk.Button(btn_frame, text="Confirmar", underline=1, command=on_confirm, bootstyle="success").pack(side=tk.LEFT, padx=10)
        ttk.Button(btn_frame, text="Cancelar", underline=0, command=lambda: dialog.destroy(), bootstyle="secondary").pack(side=tk.LEFT)

        dialog.wait_window()

    def _atualizar_carrinho_e_total(self):
        if not hasattr(self, 'tree_carrinho') or self.tree_carrinho is None: return
        for i in self.tree_carrinho.get_children(): self.tree_carrinho.delete(i)
        self.total_venda = 0.0
        sorted_cart_ids = sorted(self.carrinho.keys(), key=lambda pid: self.carrinho[pid]['nome'])

        for prod_id in sorted_cart_ids:
            dados = self.carrinho[prod_id]
            subtotal = 0.0
            display_qtd_peso = ""
            
            # CORREÇÃO: Verifica se o preço de atacado ou promocional foi aplicado
            # Se sim, usa o preço especial (armazenado em 'preco'), senão usa o preço original
            preco_atacado_aplicado = dados.get("preco_atacado_aplicado", False)
            preco_promocional_aplicado = dados.get("preco_promocional_aplicado", False)
            if preco_atacado_aplicado or preco_promocional_aplicado:
                # Usa o preço especial (atacado ou promocional) que foi armazenado em 'preco'
                preco_base = parse_br_float(dados.get("preco", 0.0))
            else:
                # Usa o preço original de varejo
                preco_base = parse_br_float(dados.get("preco_original", dados.get("preco", 0.0)))
            
            if preco_base is None: preco_base = 0.0
            qtd_peso = parse_br_float(dados.get("quantidade_peso", 0.0))
            if qtd_peso is None: qtd_peso = 0.0

            # Calcula o subtotal base
            subtotal_base = preco_base * qtd_peso

            # Aplica desconto/acréscimo
            desconto_item = parse_br_float(dados.get("desconto", 0.0)) or 0.0
            acrescimo_item = parse_br_float(dados.get("acrescimo", 0.0)) or 0.0

            subtotal = subtotal_base - desconto_item + acrescimo_item

            # Garante que o subtotal não seja negativo
            if subtotal < 0: subtotal = 0.0

            # Formata preço base sem símbolo de moeda para coluna unitário
            display_preco_unit = format_br_float(preco_base, 2)

            tipo_item = dados.get("tipo", "unidade")
            display_qtd_peso = formatar_quantidade_produto(qtd_peso, tipo_item)
            display_preco_unit = f"R$ {display_preco_unit}{sufixo_preco_produto(tipo_item)}"

            subtotal_str = format_br_currency(subtotal) # Usa função com R$
            try:
                values = (dados.get("nome", "N/A"), display_qtd_peso, display_preco_unit, subtotal_str)
                self.tree_carrinho.insert("", tk.END, values=values, iid=prod_id)
            except tk.TclError as e: print(f"Erro Tcl ao inserir item {prod_id} no carrinho: {e}")
            self.total_venda += subtotal

        total_str = format_br_currency(self.total_venda)
        if hasattr(self, "lbl_total_valor") and self.lbl_total_valor is not None:
            self.lbl_total_valor.config(text=total_str)

    def _select_customer(self):
        win = tk.Toplevel(self.root)
        win.title("Selecionar Cliente")
        win.state('zoomed')
        win.transient(self.root)
        win.grab_set()
        win.columnconfigure(0, weight=1)
        win.rowconfigure(2, weight=1)

        # Frame de Busca
        search_frame = ttk.Frame(win, padding=10)
        search_frame.grid(row=0, column=0, sticky="ew")
        search_frame.columnconfigure(1, weight=1)

        ttk.Label(search_frame, text="Buscar Cliente:").grid(row=0, column=0, padx=(0, 5))
        search_var = tk.StringVar()
        search_entry = ttk.Entry(search_frame, textvariable=search_var)
        search_entry.grid(row=0, column=1, sticky="ew")
        search_entry.focus_set()

        ttk.Label(win, text="Selecione um cliente na lista abaixo:").grid(row=1, column=0, pady=(0, 5), padx=10, sticky='w')
        
        listbox = tk.Listbox(win, height=12, width=60, font=("Segoe UI", 10))
        listbox.grid(row=2, column=0, pady=5, padx=(10, 0), sticky='nsew')
        
        scrollbar = ttk.Scrollbar(win, orient=tk.VERTICAL, command=listbox.yview)
        listbox.configure(yscrollcommand=scrollbar.set)
        scrollbar.grid(row=2, column=1, sticky='ns', pady=5, padx=(0, 10))

        customer_list_map = {} # Mapeia índice do listbox para ID do cliente

        def atualizar_lista(*args):
            listbox.delete(0, tk.END)
            customer_list_map.clear()
            termo = search_var.get().lower()
            
            idx = 0
            # Garante que customers é dict
            customers_dict = self.customers if isinstance(self.customers, dict) else DEFAULT_CUSTOMERS
            
            for cust_id, cust_data in sorted(customers_dict.items(), key=lambda item: item[1].get('nome', '').lower()):
                if not isinstance(cust_data, dict): continue
                
                nome = cust_data.get('nome', '').lower()
                cpf = cust_data.get('cpf', '').lower()
                
                if termo in nome or termo in cpf or termo in str(cust_id):
                    display = f"{cust_id} - {cust_data.get('nome', 'N/A')}"
                    if cust_data.get('cpf'):
                        display += f" (CPF: {cust_data.get('cpf')})"
                    
                    listbox.insert(tk.END, display)
                    customer_list_map[idx] = cust_id
                    idx += 1
            
            # Seleciona o primeiro se houver busca ativa
            if termo and listbox.size() > 0:
                listbox.selection_set(0)

        search_var.trace_add("write", atualizar_lista)
        atualizar_lista() # Carga inicial

        def on_select(event=None):
            selected_indices = listbox.curselection()
            if not selected_indices: return
            selected_lb_idx = selected_indices[0]
            if selected_lb_idx in customer_list_map:
                cust_id = customer_list_map[selected_lb_idx]
                self.selected_customer_id = cust_id
                
                # Se não for o consumidor final, pergunta se é para entrega
                if cust_id != "1":
                    self.is_delivery = messagebox.askyesno("Entrega", "Este pedido é para ENTREGA%s", parent=win)
                    
                    # Se for entrega, abre janela para selecionar entregador e adiciona taxa
                    if self.is_delivery:
                        win.destroy()  # Fecha a janela de seleção de cliente primeiro
                        self._selecionar_entregador_e_adicionar_taxa(cust_id)
                        self._update_customer_display()
                        return
                else:
                    self.is_delivery = False
                
                self._update_customer_display()
                win.destroy()

        # Botões
        btn_frame = ttk.Frame(win, padding=10)
        btn_frame.grid(row=3, column=0, columnspan=2)
        
        ttk.Button(btn_frame, text="Selecionar (Enter)", underline=0, command=on_select, bootstyle="success").pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="Cancelar (Esc)", underline=0, command=win.destroy, bootstyle="secondary").pack(side=tk.LEFT, padx=5)

        # Atalhos
        win.bind("<Return>", on_select)
        win.bind("<Escape>", lambda e: fechar_janela_vencimento())
        listbox.bind("<Double-1>", on_select)
        
        win.wait_window()

    def show_daily_summary(self):
        if not check_permission("relatorios.resumo_dia"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar o resumo do dia.")
            return
        total_vendas = sum(parse_br_float(venda.get('total', 0)) for venda in self.sales_log)
        total_itens = sum(len(venda.get('itens', [])) for venda in self.sales_log)
        resumo = f"Resumo do Dia:\nTotal de Vendas: R$ {total_vendas:.2f}\nItens Vendidos: {total_itens}"
        messagebox.showinfo("Resumo do Dia", resumo)

    
    def show_wholesale_sales_report(self):
        """
        Gera e exibe o relatório de vendas realizadas com preço de atacado.
        Permite filtrar por período e exibe detalhamento completo das vendas.
        """
        if not check_permission("relatorios.vendas_atacado"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar relatório de vendas no atacado.")
            return
        
        # Cria janela de seleção de período
        period_win = tk.Toplevel(self.root)
        period_win.title("📦 Relatório de Vendas no Atacado")
        responsive_geometry(period_win, 500, 450)
        period_win.transient(self.root)
        period_win.grab_set()
        period_win.resizable(True, True)
        period_win.configure(bg='#f8f9fa')
        
        # Centralizar a janela na tela
        period_win.update_idletasks()
        width = period_win.winfo_width()
        height = period_win.winfo_height()
        x = (period_win.winfo_screenwidth() // 2) - (width // 2)
        y = (period_win.winfo_screenheight() // 2) - (height // 2)
        period_win.geometry(f'+{x}+{y}')

        # Frame principal
        main_frame = ttk.Frame(period_win, padding="20")
        main_frame.pack(expand=True, fill=tk.BOTH)

        # Título
        ttk.Label(main_frame, text="📦 Relatório de Vendas no Atacado", 
                 font=("Segoe UI", 14, "bold")).pack(pady=(0, 20))
        
        ttk.Label(main_frame, text="Selecione o período para gerar o relatório:", 
                 font=("Segoe UI", 10)).pack(pady=(0, 15))

        # Frame para as datas
        dates_frame = ttk.Frame(main_frame)
        dates_frame.pack(pady=10)

        # Data inicial
        ttk.Label(dates_frame, text="Data Inicial:").grid(row=0, column=0, sticky=tk.W, pady=5)
        entry_data_inicial = DateEntry(dates_frame, width=15, bootstyle="primary", dateformat="%d/%m/%Y")
        entry_data_inicial.grid(row=0, column=1, padx=(10, 0), pady=5)

        # Data final
        ttk.Label(dates_frame, text="Data Final:").grid(row=1, column=0, sticky=tk.W, pady=5)
        entry_data_final = DateEntry(dates_frame, width=15, bootstyle="primary", dateformat="%d/%m/%Y")
        entry_data_final.grid(row=1, column=1, padx=(10, 0), pady=5)

        # Label de instrução
        ttk.Label(main_frame, text="Formato: DD/MM/AAAA", 
                 font=("Segoe UI", 9), foreground="gray").pack(pady=(5, 15))
        
        # Opções de filtro
        options_frame = tk.LabelFrame(main_frame, text="Opções de Filtro", padx=10, pady=10, bg='#f8f9fa')
        options_frame.pack(pady=(0, 15))
        
        filtro_var = tk.StringVar(value="todos")
        ttk.Radiobutton(options_frame, text="Todas as vendas com itens no atacado", 
                       variable=filtro_var, value="todos").pack(anchor=tk.W)
        ttk.Radiobutton(options_frame, text="Apenas vendas 100% no atacado", 
                       variable=filtro_var, value="somente_atacado").pack(anchor=tk.W)

        # Função para validar e gerar relatório
        def gerar_relatorio_atacado(imprimir=False):
            try:
                # Converte as datas do formato brasileiro para datetime
                data_inicial_str = entry_data_inicial.entry.get().strip()
                data_final_str = entry_data_final.entry.get().strip()
                
                data_inicial = datetime.datetime.strptime(data_inicial_str, '%d/%m/%Y').date()
                data_final = datetime.datetime.strptime(data_final_str, '%d/%m/%Y').date()
                
                if data_inicial > data_final:
                    messagebox.showerror("Erro", "Data inicial não pode ser maior que data final.", parent=period_win)
                    return
                
                if not self.sales_log:
                    messagebox.showinfo("Relatório", "Nenhuma venda registrada.", parent=period_win)
                    return
                
                # Filtra vendas do período que possuem itens com preço de atacado
                vendas_atacado = []
                filtro_tipo = filtro_var.get()
                
                for sale in self.sales_log:
                    if not isinstance(sale, dict):
                        continue
                    
                    # Verifica a data da venda
                    timestamp = sale.get('timestamp', '')
                    if timestamp:
                        try:
                            sale_date = datetime.datetime.fromisoformat(timestamp).date()
                            if not (data_inicial <= sale_date <= data_final):
                                continue
                        except Exception:
                            continue
                    else:
                        continue
                    
                    # Verifica se há itens com preço de atacado
                    itens = sale.get('itens', {})
                    if not isinstance(itens, dict):
                        continue
                    
                    itens_atacado = []
                    itens_varejo = []
                    total_atacado = 0.0
                    total_varejo = 0.0
                    
                    for item_id, item_data in itens.items():
                        flag_atacado = item_data.get('preco_atacado_aplicado', item_data.get('usar_atacado', False))
                        if isinstance(flag_atacado, str):
                            usar_atacado = flag_atacado.strip().lower() in ['1', 'true', 'sim', 'yes']
                        else:
                            usar_atacado = bool(flag_atacado)
                        qtd = parse_br_float(item_data.get('quantidade_peso', 1)) or 1
                        preco = parse_br_float(item_data.get('preco', 0)) or 0
                        subtotal = qtd * preco
                        
                        # Aplica desconto/acréscimo se houver
                        desconto = parse_br_float(item_data.get('desconto', 0)) or 0
                        acrescimo = parse_br_float(item_data.get('acrescimo', 0)) or 0
                        subtotal = subtotal - desconto + acrescimo
                        if subtotal < 0:
                            subtotal = 0
                        
                        if usar_atacado:
                            itens_atacado.append({
                                'nome': item_data.get('nome', 'N/A'),
                                'qtd': qtd,
                                'preco': preco,
                                'subtotal': subtotal
                            })
                            total_atacado += subtotal
                        else:
                            itens_varejo.append({
                                'nome': item_data.get('nome', 'N/A'),
                                'qtd': qtd,
                                'preco': preco,
                                'subtotal': subtotal
                            })
                            total_varejo += subtotal
                    
                    # Aplica filtro
                    if filtro_tipo == "somente_atacado":
                        if itens_atacado and not itens_varejo:
                            vendas_atacado.append({
                                'cupom': sale.get('coupon_number', 'N/A'),
                                'data': sale.get('data', 'N/A'),
                                'cliente': sale.get('cliente_nome', 'Consumidor Final'),
                                'cliente_id': sale.get('cliente_id', '1'),
                                'total_venda': sale.get('total', 0.0),
                                'itens_atacado': itens_atacado,
                                'itens_varejo': itens_varejo,
                                'total_atacado': total_atacado,
                                'total_varejo': total_varejo,
                                'usuario': sale.get('usuario', 'N/A')
                            })
                    else:
                        if itens_atacado:
                            vendas_atacado.append({
                                'cupom': sale.get('coupon_number', 'N/A'),
                                'data': sale.get('data', 'N/A'),
                                'cliente': sale.get('cliente_nome', 'Consumidor Final'),
                                'cliente_id': sale.get('cliente_id', '1'),
                                'total_venda': sale.get('total', 0.0),
                                'itens_atacado': itens_atacado,
                                'itens_varejo': itens_varejo,
                                'total_atacado': total_atacado,
                                'total_varejo': total_varejo,
                                'usuario': sale.get('usuario', 'N/A')
                            })
                
                if not vendas_atacado:
                    messagebox.showinfo("Relatório", 
                                      f"Nenhuma venda no atacado encontrada no período de {data_inicial_str} a {data_final_str}.", 
                                      parent=period_win)
                    return
                
                # Gera o relatório
                report = "=" * 48 + "\n"
                report += "VENDAS NO ATACADO".center(48) + "\n"
                report += "=" * 48 + "\n"
                report += f"Periodo: {data_inicial_str} a {data_final_str}\n"
                report += f"Emitido: {datetime.datetime.now().strftime('%d/%m/%Y %H:%M')}\n"
                
                if filtro_tipo == "somente_atacado":
                    report += "FILTRO: Somente atacado\n"
                else:
                    report += "FILTRO: Todas c/ atacado\n"
                report += "=" * 48 + "\n\n"
                
                # Totalizadores gerais
                total_geral_vendas = 0.0
                total_geral_atacado = 0.0
                total_geral_varejo = 0.0
                total_itens_atacado = 0
                produtos_atacado = {}
                clientes_atacado = {}
                
                for venda in vendas_atacado:
                    total_geral_vendas += venda['total_venda']
                    total_geral_atacado += venda['total_atacado']
                    total_geral_varejo += venda['total_varejo']
                    
                    for item in venda['itens_atacado']:
                        total_itens_atacado += 1
                        nome_prod = item['nome']
                        if nome_prod not in produtos_atacado:
                            produtos_atacado[nome_prod] = {'qtd': 0, 'valor': 0.0}
                        produtos_atacado[nome_prod]['qtd'] += item['qtd']
                        produtos_atacado[nome_prod]['valor'] += item['subtotal']
                    
                    cliente_nome = venda['cliente']
                    if cliente_nome not in clientes_atacado:
                        clientes_atacado[cliente_nome] = {'vendas': 0, 'valor': 0.0}
                    clientes_atacado[cliente_nome]['vendas'] += 1
                    clientes_atacado[cliente_nome]['valor'] += venda['total_atacado']
                
                # Resumo geral
                report += "RESUMO GERAL\n"
                report += "-" * 48 + "\n"
                report += f"Vendas Atacado:{len(vendas_atacado):>32}\n"
                report += f"Itens Atacado:{total_itens_atacado:>33}\n"
                report += f"Total Vendas:{format_br_currency(total_geral_vendas):>34}\n"
                report += f"Total Atacado:{format_br_currency(total_geral_atacado):>33}\n"
                
                if total_geral_vendas > 0:
                    percentual_atacado = (total_geral_atacado / total_geral_vendas) * 100
                    report += f"% Atacado:{percentual_atacado:>36.1f}%\n"
                
                report += "=" * 48 + "\n\n"
                
                # Ranking de Produtos
                report += "TOP 10 PRODUTOS ATACADO\n"
                report += "-" * 48 + "\n"
                report += f"{'PRODUTO':<22}{'QTD':>8}{'VALOR':>16}\n"
                report += "-" * 48 + "\n"
                
                produtos_ordenados = sorted(produtos_atacado.items(), key=lambda x: x[1]['valor'], reverse=True)[:10]
                for nome, dados in produtos_ordenados:
                    nome_truncado = nome[:22]
                    report += f"{nome_truncado:<22}{dados['qtd']:>8.0f}{format_br_currency(dados['valor']):>16}\n"
                
                report += "=" * 48 + "\n\n"
                
                # Ranking de Clientes
                report += "TOP 10 CLIENTES ATACADO\n"
                report += "-" * 48 + "\n"
                report += f"{'CLIENTE':<22}{'VENDAS':>6}{'VALOR':>18}\n"
                report += "-" * 48 + "\n"
                
                clientes_ordenados = sorted(clientes_atacado.items(), key=lambda x: x[1]['valor'], reverse=True)[:10]
                for nome, dados in clientes_ordenados:
                    nome_truncado = nome[:38] if len(nome) > 38 else nome
                    report += f"{nome_truncado[:20]:<22}{dados['vendas']:>6} {format_br_currency(dados['valor']):>18}\n"
                
                report += "=" * 48 + "\n\n"
                
                # Detalhamento das vendas
                report += "DETALHAMENTO DAS VENDAS\n"
                report += "=" * 48 + "\n"
                
                for idx, venda in enumerate(vendas_atacado, 1):
                    report += f"\n{'='*48}\n"
                    report += f"VENDA #{idx} - Cupom: {venda['cupom']}\n"
                    report += f"{'='*48}\n"
                    report += f"Data: {venda['data']}\n"
                    report += f"Cliente: {venda['cliente'][:40]}\n"
                    report += f"Usuario: {venda['usuario']}\n"
                    report += f"{'-'*48}\n"
                    
                    report += "\nITENS ATACADO:\n"
                    report += f"{'PRODUTO':<22}{'QTD':>6}{'SUBTOTAL':>18}\n"
                    report += "-" * 48 + "\n"
                    
                    for item in venda['itens_atacado']:
                        nome_item = item['nome']
                        _qtd_str = f"{item['qtd']:>6.2f}"
                        _sub_str = f"{format_br_currency(item['subtotal']):>18}"
                        if len(nome_item) <= 22:
                            report += f"{nome_item:<22}{_qtd_str}{_sub_str}\n"
                        else:
                            # Word wrap do nome completo
                            _palavras = nome_item.split()
                            _linha_atual = ""
                            for _p in _palavras:
                                if _linha_atual and len(_linha_atual) + 1 + len(_p) > 48:
                                    report += f"{_linha_atual}\n"
                                    _linha_atual = _p
                                elif not _linha_atual:
                                    _linha_atual = _p
                                else:
                                    _linha_atual += " " + _p
                            if _linha_atual:
                                report += f"{_linha_atual}\n"
                            report += f"{'':<22}{_qtd_str}{_sub_str}\n"
                    
                    report += "-" * 48 + "\n"
                    report += f"SUBTOTAL ATACADO:{format_br_currency(venda['total_atacado']):>30}\n"
                    
                    if venda['itens_varejo']:
                        report += "\nITENS VAREJO:\n"
                        report += f"{'PRODUTO':<22}{'QTD':>6}{'SUBTOTAL':>18}\n"
                        report += "-" * 48 + "\n"
                        
                        for item in venda['itens_varejo']:
                            nome_item = item['nome']
                            _qtd_str = f"{item['qtd']:>6.2f}"
                            _sub_str = f"{format_br_currency(item['subtotal']):>18}"
                            if len(nome_item) <= 22:
                                report += f"{nome_item:<22}{_qtd_str}{_sub_str}\n"
                            else:
                                _palavras = nome_item.split()
                                _linha_atual = ""
                                for _p in _palavras:
                                    if _linha_atual and len(_linha_atual) + 1 + len(_p) > 48:
                                        report += f"{_linha_atual}\n"
                                        _linha_atual = _p
                                    elif not _linha_atual:
                                        _linha_atual = _p
                                    else:
                                        _linha_atual += " " + _p
                                if _linha_atual:
                                    report += f"{_linha_atual}\n"
                                report += f"{'':<22}{_qtd_str}{_sub_str}\n"
                        
                        report += "-" * 48 + "\n"
                        report += f"SUBTOTAL VAREJO:{format_br_currency(venda['total_varejo']):>31}\n"
                    
                    report += f"\nTOTAL DA VENDA:{format_br_currency(venda['total_venda']):>32}\n"
                
                report += "\n" + "=" * 48 + "\n"
                report += "FIM DO RELATORIO\n"
                report += "=" * 48 + "\n"
                
                # Fecha janela de seleção e exibe relatório
                period_win.destroy()
                
                if imprimir:
                    try:
                        if hasattr(self, 'thermal_printer') and self.thermal_printer:
                            self.thermal_printer.text(report)
                            self.thermal_printer.cut()
                            messagebox.showinfo("Impressão", "Relatório enviado para a impressora.", parent=self.root)
                        else:
                            messagebox.showwarning("Aviso", "Impressora térmica não configurada.\nO relatório será exibido na tela.", parent=self.root)
                            ReportWindow(self.root, f"📦 Vendas no Atacado - {data_inicial_str} a {data_final_str}", report, self)
                    except Exception as print_error:
                        logger.error(f"Erro ao imprimir relatório: {print_error}")
                        messagebox.showwarning("Aviso", f"Erro ao imprimir: {print_error}\nO relatório será exibido na tela.", parent=self.root)
                        ReportWindow(self.root, f"📦 Vendas no Atacado - {data_inicial_str} a {data_final_str}", report, self)
                else:
                    ReportWindow(self.root, f"📦 Vendas no Atacado - {data_inicial_str} a {data_final_str}", report, self)
                
                log_user_action("Relatório", f"{'Imprimiu' if imprimir else 'Visualizou'} Relatório de Vendas no Atacado ({data_inicial_str} a {data_final_str})")
                
            except ValueError as e:
                messagebox.showerror("Erro", f"Data inválida. Use o formato DD/MM/AAAA.\n{e}", parent=period_win)
            except Exception as e:
                logger.error(f"Erro ao gerar relatório de vendas no atacado: {e}")
                messagebox.showerror("Erro", f"Erro ao gerar relatório:\n{e}", parent=period_win)

        # Botões
        btn_frame = ttk.Frame(main_frame)
        btn_frame.pack(pady=(20, 10))
        
        ttk.Button(btn_frame, text="✅ Entrar (Enter)", command=lambda: gerar_relatorio_atacado(imprimir=False), 
                  bootstyle="success", width=20).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="📊 Gerar Relatório (F5)", command=lambda: gerar_relatorio_atacado(imprimir=False), 
                  bootstyle="primary", width=22).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="🖨️ Imprimir", command=lambda: gerar_relatorio_atacado(imprimir=True), 
                  bootstyle="info", width=15).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="❌ Cancelar (Esc)", command=period_win.destroy, 
                  bootstyle="danger", width=18).pack(side=tk.LEFT, padx=5)
        
        # Teclas de atalho
        period_win.bind('<Return>', lambda e: gerar_relatorio_atacado(imprimir=False))
        period_win.bind('<F5>', lambda e: gerar_relatorio_atacado(imprimir=False))
        period_win.bind('<Escape>', lambda e: period_win.destroy())


    def _adicionar_taxa_entrega_automatica(self, cliente_id):
        """
        Adiciona automaticamente a taxa de entrega baseada no bairro do cliente.
        A taxa é buscada primeiro no cadastro de bairros, depois no cadastro de entregadores.
        """
        try:
            # Obtém os dados do cliente
            cliente_data = self.customers.get(cliente_id, {})
            bairro_cliente = cliente_data.get('bairro', '').strip().lower()
            
            if not bairro_cliente:
                # Cliente sem bairro cadastrado - pergunta se deseja adicionar taxa manual
                resposta = messagebox.askyesno(
                    "Taxa de Entrega",
                    "Cliente sem bairro cadastrado.\n\nDeseja adicionar uma taxa de entrega manualmente%s",
                    parent=self.root
                )
                if resposta:
                    self._adicionar_taxa_entrega_manual()
                return
            
            # Busca o valor da taxa no cadastro de bairros
            taxa_entrega = 0.0
            bairro_encontrado = None
            
            for bairro_id, bairro_data in self.bairros.items():
                nome_bairro = bairro_data.get('nome', '').strip().lower()
                if nome_bairro == bairro_cliente:
                    taxa_entrega = parse_br_float(bairro_data.get('valor_entrega', 0.0)) or 0.0
                    bairro_encontrado = bairro_data.get('nome', '')
                    break
            
            # Se não encontrou no cadastro de bairros, usa taxa padrão dos entregadores
            if taxa_entrega == 0.0 and not bairro_encontrado:
                entregadores_ativos = [e for e in self.entregadores.values() if e.get('status', 'Ativo') == 'Ativo']
                if entregadores_ativos:
                    taxas = [parse_br_float(e.get('valor_entrega', 5.0)) or 5.0 for e in entregadores_ativos]
                    taxa_entrega = sum(taxas) / len(taxas)
            
            if taxa_entrega > 0:
                # Remove taxa de entrega anterior se existir
                self._remover_taxa_entrega_existente()
                
                # Adiciona a taxa de entrega como um item especial no carrinho
                taxa_id = "TAXA_ENTREGA"
                self.carrinho[taxa_id] = {
                    "nome": f"🚚 Tx Entrega ({bairro_encontrado or bairro_cliente.title()})",
                    "preco": taxa_entrega,
                    "preco_original": taxa_entrega,
                    "quantidade_peso": 1,
                    "tipo": "servico",
                    "id": taxa_id,
                    "desconto": 0.0,
                    "acrescimo": 0.0,
                    "is_taxa_entrega": True
                }
                
                self._atualizar_carrinho_e_total()
                
                log_user_action("Taxa de Entrega", f"Adicionada automaticamente: {format_br_currency(taxa_entrega)} - Bairro: {bairro_encontrado or bairro_cliente.title()}")
                
                messagebox.showinfo(
                    "Taxa de Entrega",
                    f"Taxa de entrega adicionada automaticamente!\n\n"
                    f"Bairro: {bairro_encontrado or bairro_cliente.title()}\n"
                    f"Valor: {format_br_currency(taxa_entrega)}",
                    parent=self.root
                )
            else:
                resposta = messagebox.askyesno(
                    "Taxa de Entrega",
                    f"Bairro '{bairro_cliente.title()}' não possui taxa de entrega configurada.\n\n"
                    f"Deseja adicionar uma taxa de entrega manualmente%s",
                    parent=self.root
                )
                if resposta:
                    self._adicionar_taxa_entrega_manual()
                    
        except Exception as e:
            try:
                AUDITORIA.erro(f"Erro no sistema: {e}")
            except Exception:
                pass
            print(f"[ERRO] Ao adicionar taxa de entrega automática: {e}")
            import traceback
            traceback.print_exc()
    
    def _remover_taxa_entrega_existente(self):
        """Remove taxa de entrega existente do carrinho."""
        taxa_id = "TAXA_ENTREGA"
        if taxa_id in self.carrinho:
            del self.carrinho[taxa_id]
    
    def _adicionar_taxa_entrega_ao_selecionar_cliente(self, cliente_id):
        """
        Adiciona automaticamente a taxa de entrega ao carrinho quando um cliente é selecionado.
        A taxa é baseada no bairro do cliente cadastrado.
        Não exibe mensagens de confirmação, apenas adiciona silenciosamente.
        """
        try:
            # Obtém os dados do cliente
            cliente_data = self.customers.get(cliente_id, {})
            bairro_cliente = cliente_data.get('bairro', '').strip().lower()
            
            if not bairro_cliente:
                # Cliente sem bairro cadastrado - não adiciona taxa automaticamente
                return
            
            # Busca o valor da taxa no cadastro de bairros
            taxa_entrega = 0.0
            bairro_encontrado = None
            
            # Carrega bairros se não estiverem carregados
            if not hasattr(self, 'bairros') or not self.bairros:
                self.bairros = load_data(BAIRROS_FILE, {})
            
            for bairro_id, bairro_data in self.bairros.items():
                nome_bairro = bairro_data.get('nome', '').strip().lower()
                if nome_bairro == bairro_cliente:
                    taxa_entrega = parse_br_float(bairro_data.get('valor_entrega', 0.0)) or 0.0
                    bairro_encontrado = bairro_data.get('nome', '')
                    break
            
            # Se não encontrou no cadastro de bairros, usa taxa padrão dos entregadores
            if taxa_entrega == 0.0 and not bairro_encontrado:
                if hasattr(self, 'entregadores') and self.entregadores:
                    entregadores_ativos = [e for e in self.entregadores.values() if e.get('status', 'Ativo') == 'Ativo']
                    if entregadores_ativos:
                        taxas = [parse_br_float(e.get('valor_entrega', 5.0)) or 5.0 for e in entregadores_ativos]
                        taxa_entrega = sum(taxas) / len(taxas)
            
            if taxa_entrega > 0:
                # Remove taxa de entrega anterior se existir
                self._remover_taxa_entrega_existente()
                
                # Adiciona a taxa de entrega como um item no carrinho
                taxa_id = "TAXA_ENTREGA"
                self.carrinho[taxa_id] = {
                    "nome": f"Tx. Entrega",
                    "preco": taxa_entrega,
                    "preco_original": taxa_entrega,
                    "quantidade_peso": 1,
                    "tipo": "servico",
                    "id": taxa_id,
                    "desconto": 0.0,
                    "acrescimo": 0.0,
                    "is_taxa_entrega": True,
                    "bairro": bairro_encontrado or bairro_cliente.title()
                }
                
                self._atualizar_carrinho_e_total()
                
                log_user_action("Taxa de Entrega", f"Adicionada automaticamente: {format_br_currency(taxa_entrega)} - Bairro: {bairro_encontrado or bairro_cliente.title()}")
                    
        except Exception as e:
            try:
                AUDITORIA.erro(f"Erro no sistema: {e}")
            except Exception:
                pass
            print(f"[ERRO] Ao adicionar taxa de entrega ao selecionar cliente: {e}")
            import traceback
            traceback.print_exc()
            self._atualizar_carrinho_e_total()
    
    def _selecionar_entregador_e_adicionar_taxa(self, cliente_id):
        """
        Abre uma janela para selecionar o entregador via dropdown e adiciona a taxa de entrega.
        """
        try:
            # Carrega entregadores se não estiverem carregados
            if not hasattr(self, 'entregadores') or not self.entregadores:
                self.entregadores = load_data(ENTREGADORES_FILE, {})
            
            # Filtra apenas entregadores ativos
            entregadores_ativos = {eid: edata for eid, edata in self.entregadores.items() 
                                   if edata.get('status', 'Ativo') == 'Ativo'}
            
            if not entregadores_ativos:
                messagebox.showwarning("Aviso", 
                    "Nenhum entregador ativo cadastrado.\n\n"
                    "Cadastre entregadores em:\nCadastros → Entregadores",
                    parent=self.root)
                # Adiciona taxa de entrega sem entregador
                self._adicionar_taxa_entrega_ao_selecionar_cliente(cliente_id)
                return
            
            # Cria janela de seleção de entregador
            ent_win = tk.Toplevel(self.root)
            ent_win.title("🚚 Selecionar Entregador")
            responsive_geometry(ent_win, 450, 250)
            ent_win.resizable(True, True)
            ent_win.transient(self.root)
            ent_win.grab_set()
            
            # Centraliza
            ent_win.update_idletasks()
            x = self.root.winfo_x() + (self.root.winfo_width() // 2) - 225
            y = self.root.winfo_y() + (self.root.winfo_height() // 2) - 125
            ent_win.geometry(f"+{x}+{y}")
            
            # Frame principal
            main_frame = ttk.Frame(ent_win, padding=20)
            main_frame.pack(fill=tk.BOTH, expand=True)
            
            ttk.Label(main_frame, text="🚚 SELECIONAR ENTREGADOR", font=("Segoe UI", 16, "bold")).pack(pady=(0, 20))
            
            # Monta lista de entregadores para o combobox
            entregadores_list = []
            entregadores_map = {}  # Mapeia índice para ID do entregador
            
            for eid, edata in entregadores_ativos.items():
                nome = edata.get('nome', 'Sem nome')
                veiculo = edata.get('veiculo', '')
                telefone = edata.get('telefone', '')
                
                display = f"{nome}"
                if veiculo:
                    display += f" - {veiculo}"
                if telefone:
                    display += f" ({telefone})"
                
                entregadores_list.append(display)
                entregadores_map[len(entregadores_list) - 1] = eid
            
            # Label e Combobox
            ttk.Label(main_frame, text="Selecione o entregador:", font=("Segoe UI", 11)).pack(anchor='w', pady=(0, 5))
            
            entregador_var = tk.StringVar()
            entregador_combo = ttk.Combobox(main_frame, textvariable=entregador_var, 
                                            values=entregadores_list, 
                                            state='readonly', width=50, font=("Segoe UI", 11))
            entregador_combo.pack(fill=tk.X, pady=(0, 20))
            
            # Seleciona o primeiro por padrão
            if entregadores_list:
                entregador_combo.current(0)
            
            # Variável para armazenar o entregador selecionado
            self.selected_entregador_id = None
            
            def confirmar():
                if not entregador_var.get():
                    messagebox.showwarning("Aviso", "Selecione um entregador.", parent=ent_win)
                    return
                
                # Obtém o índice selecionado
                idx = entregador_combo.current()
                if idx >= 0 and idx in entregadores_map:
                    self.selected_entregador_id = entregadores_map[idx]
                    entregador_data = self.entregadores.get(self.selected_entregador_id, {})
                    entregador_nome = entregador_data.get('nome', 'Entregador')
                    
                    log_user_action("Entrega", f"Entregador selecionado: {entregador_nome} (ID: {self.selected_entregador_id})")
                
                ent_win.destroy()
                
                # Adiciona a taxa de entrega após selecionar o entregador
                self._adicionar_taxa_entrega_ao_selecionar_cliente(cliente_id)
            
            def cancelar():
                self.is_delivery = False
                self.selected_entregador_id = None
                ent_win.destroy()
            
            # Botões
            btn_frame = ttk.Frame(main_frame)
            btn_frame.pack(fill=tk.X, pady=(10, 0))
            
            ttk.Button(btn_frame, text="✅ Confirmar", command=confirmar, 
                      bootstyle="success", width=15).pack(side=tk.LEFT, padx=5)
            ttk.Button(btn_frame, text="❌ Cancelar", command=cancelar, 
                      bootstyle="danger", width=15).pack(side=tk.RIGHT, padx=5)
            
            # Atalhos
            ent_win.bind('<Return>', lambda e: confirmar())
            ent_win.bind('<Escape>', lambda e: cancelar())
            
            # Foco no combobox
            entregador_combo.focus_set()
            
            # Aguarda a janela fechar
            ent_win.wait_window()
            
        except Exception as e:
            try:
                AUDITORIA.erro(f"Erro no sistema: {e}")
            except Exception:
                pass
            print(f"[ERRO] Ao selecionar entregador: {e}")
            import traceback
            traceback.print_exc()
            # Em caso de erro, adiciona taxa sem entregador
            self._adicionar_taxa_entrega_ao_selecionar_cliente(cliente_id)
    
    def _adicionar_taxa_entrega_manual(self):
        """
        Permite ao usuário adicionar uma taxa de entrega manualmente.
        Exibe uma janela para selecionar o bairro ou digitar o valor.
        """
        try:
            # Cria janela para seleção de taxa
            taxa_win = tk.Toplevel(self.root)
            taxa_win.title("🚚 Taxa de Entrega Manual")
            responsive_geometry(taxa_win, 450, 400)
            taxa_win.resizable(True, True)
            taxa_win.transient(self.root)
            taxa_win.grab_set()
            
            # Centraliza
            taxa_win.update_idletasks()
            x = self.root.winfo_x() + (self.root.winfo_width() // 2) - 225
            y = self.root.winfo_y() + (self.root.winfo_height() // 2) - 200
            taxa_win.geometry(f"+{x}+{y}")
            
            # Frame principal
            main_frame = ttk.Frame(taxa_win, padding=20)
            main_frame.pack(fill=tk.BOTH, expand=True)
            
            ttk.Label(main_frame, text="🚚 TAXA DE ENTREGA", font=("Segoe UI", 16, "bold")).pack(pady=(0, 15))
            
            # Opção 1: Selecionar bairro cadastrado
            ttk.Label(main_frame, text="Selecione um bairro cadastrado:", font=("Segoe UI", 10)).pack(anchor='w', pady=(10, 5))
            
            # Lista de bairros
            bairros_list = [(bid, f"{bdata.get('nome', '')} - {format_br_currency(parse_br_float(bdata.get('valor_entrega', 0)) or 0)}") 
                           for bid, bdata in self.bairros.items() if parse_br_float(bdata.get('valor_entrega', 0)) or 0 > 0]
            
            bairro_var = tk.StringVar()
            bairro_combo = ttk.Combobox(main_frame, textvariable=bairro_var, 
                                        values=[b[1] for b in bairros_list], 
                                        state='readonly', width=40)
            bairro_combo.pack(fill=tk.X, pady=(0, 15))
            
            # Separador
            ttk.Separator(main_frame, orient='horizontal').pack(fill=tk.X, pady=10)
            
            # Opção 2: Digitar valor manual
            ttk.Label(main_frame, text="Ou digite o valor manualmente:", font=("Segoe UI", 10)).pack(anchor='w', pady=(10, 5))
            
            valor_frame = ttk.Frame(main_frame)
            valor_frame.pack(fill=tk.X, pady=(0, 15))
            
            ttk.Label(valor_frame, text="R$", font=("Segoe UI", 12, "bold")).pack(side=tk.LEFT, padx=(0, 5))
            valor_var = tk.StringVar(value="0,00")
            valor_entry = ttk.Entry(valor_frame, textvariable=valor_var, width=15, font=("Segoe UI", 12))
            valor_entry.pack(side=tk.LEFT)
            
            # Descrição opcional
            ttk.Label(main_frame, text="Descrição (opcional):", font=("Segoe UI", 10)).pack(anchor='w', pady=(10, 5))
            desc_var = tk.StringVar(value="Entrega")
            desc_entry = ttk.Entry(main_frame, textvariable=desc_var, width=40)
            desc_entry.pack(fill=tk.X, pady=(0, 20))
            
            def confirmar():
                try:
                    taxa_valor = 0.0
                    descricao = desc_var.get().strip() or "Entrega"
                    
                    # Verifica se selecionou um bairro
                    if bairro_var.get():
                        idx = [b[1] for b in bairros_list].index(bairro_var.get())
                        bairro_id = bairros_list[idx][0]
                        bairro_data = self.bairros.get(bairro_id, {})
                        taxa_valor = parse_br_float(bairro_data.get('valor_entrega', 0)) or 0.0
                        descricao = bairro_data.get('nome', 'Entrega')
                    else:
                        # Usa o valor digitado
                        taxa_valor = parse_br_float(valor_var.get()) or 0.0
                    
                    if taxa_valor <= 0:
                        messagebox.showwarning("Aviso", "Informe um valor válido para a taxa de entrega.", parent=taxa_win)
                        return
                    
                    # Remove taxa anterior se existir
                    self._remover_taxa_entrega_existente()
                    
                    # Adiciona a taxa
                    taxa_id = "TAXA_ENTREGA"
                    self.carrinho[taxa_id] = {
                        "nome": f"🚚 Taxa de Entrega ({descricao})",
                        "preco": taxa_valor,
                        "preco_original": taxa_valor,
                        "quantidade_peso": 1,
                        "tipo": "servico",
                        "id": taxa_id,
                        "desconto": 0.0,
                        "acrescimo": 0.0,
                        "is_taxa_entrega": True
                    }
                    
                    self._atualizar_carrinho_e_total()
                    log_user_action("Taxa de Entrega", f"Adicionada manualmente: {format_br_currency(taxa_valor)} - {descricao}")
                    
                    taxa_win.destroy()
                    messagebox.showinfo("Sucesso", f"Taxa de entrega de {format_br_currency(taxa_valor)} adicionada!", parent=self.root)
                    
                except Exception as e:
                    messagebox.showerror("Erro", f"Erro ao adicionar taxa: {e}", parent=taxa_win)
            
            # Botões
            btn_frame = ttk.Frame(main_frame)
            btn_frame.pack(fill=tk.X, pady=(10, 0))
            
            ttk.Button(btn_frame, text="✅ Confirmar", command=confirmar, bootstyle="success", width=15).pack(side=tk.LEFT, padx=5)
            ttk.Button(btn_frame, text="❌ Cancelar", command=taxa_win.destroy, bootstyle="danger", width=15).pack(side=tk.RIGHT, padx=5)
            
            # Atalhos
            taxa_win.bind('<Return>', lambda e: confirmar())
            taxa_win.bind('<Escape>', lambda e: taxa_win.destroy())
            
            # Atualiza valor quando seleciona bairro
            def on_bairro_select(event):
                if bairro_var.get():
                    idx = [b[1] for b in bairros_list].index(bairro_var.get())
                    bairro_id = bairros_list[idx][0]
                    bairro_data = self.bairros.get(bairro_id, {})
                    taxa = parse_br_float(bairro_data.get('valor_entrega', 0)) or 0.0
                    valor_var.set(format_br_float(taxa, 2))
                    desc_var.set(bairro_data.get('nome', 'Entrega'))
            
            bairro_combo.bind('<<ComboboxSelected>>', on_bairro_select)
            
        except Exception as e:
            try:
                AUDITORIA.erro(f"Erro no sistema: {e}")
            except Exception:
                pass
            print(f"[ERRO] Ao abrir janela de taxa manual: {e}")
            messagebox.showerror("Erro", f"Erro ao abrir janela: {e}", parent=self.root)


    def show_user_action_log(self):
        if not check_permission("relatorios.auditoria"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar o log de ações.")
            return
        logs = []
        if os.path.exists(USER_LOG_FILE):
            with open(USER_LOG_FILE, 'r', encoding='utf-8') as f:
                try:
                    logs = json.load(f)
                except json.JSONDecodeError:
                    logs = []
        content = "=" * 48 + "\n"
        content += "RELATORIO DE ACOES DOS USUARIOS\n".center(48)
        content += "=" * 48 + "\n"
        content += f"Emitido: {datetime.datetime.now().strftime('%d/%m/%Y %H:%M')}\n"
        content += "-" * 48 + "\n"
        for log in logs:
            content += f"{log['datahora']}\n"
            content += f"Usr: {log['usuario']}\n"
            content += f"Acao: {log['acao']}\n"
            if log.get('detalhes'):
                det = log['detalhes'][:46]
                content += f"Det: {det}\n"
            content += "-" * 48 + "\n"
        content += "=" * 48 + "\n"
        ReportWindow(self.root, "Relatorio de Acoes dos Usuarios", content, self)

    def show_exclusions_report(self):
        """
        Exibe relatório de registros excluídos com filtro de período usando calendário.
        Mostra usuário responsável, data/hora e detalhes do registro excluído.
        """
        if not check_permission("relatorios.exclusoes"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar o relatório de exclusões.", parent=self.root)
            return
        
        # Cria janela de seleção de período
        period_win = tk.Toplevel(self.root)
        period_win.title("Relatorio de Registros Excluidos")
        period_win.state('zoomed')
        period_win.transient(self.root)
        period_win.grab_set()
        period_win.resizable(True, True)
        
        # Centralizar
        period_win.update_idletasks()
        x = self.root.winfo_x() + (self.root.winfo_width() // 2) - (240)
        y = self.root.winfo_y() + (self.root.winfo_height() // 2) - (210)
        responsive_geometry(period_win, 480, 420)

        # Frame principal
        main_frame = tk.Frame(period_win, bg='#f8f9fa', padx=15, pady=10)
        main_frame.pack(expand=True, fill=tk.BOTH)

        # Título
        tk.Label(main_frame, text="RELATORIO DE EXCLUSOES", 
                 font=("Segoe UI", 14, "bold"), fg="#dc3545", bg='#f8f9fa').pack(pady=(0, 3))
        
        tk.Label(main_frame, text="Visualize todos os registros excluidos do sistema", 
                 font=("Segoe UI", 9), fg="gray", bg='#f8f9fa').pack(pady=(0, 10))

        # Frame para as datas
        dates_frame = tk.LabelFrame(main_frame, text=" Filtrar por Periodo ", font=("Segoe UI", 9, "bold"),
                                    bg='#f8f9fa', padx=10, pady=10)
        dates_frame.pack(pady=5, fill=tk.X)

        # Data inicial
        row1 = tk.Frame(dates_frame, bg='#f8f9fa')
        row1.pack(fill=tk.X, pady=3)
        tk.Label(row1, text="Data Inicial:", font=("Segoe UI", 10), bg='#f8f9fa', width=12, anchor='w').pack(side=tk.LEFT)
        entry_data_inicial = DateEntry(row1, width=15, bootstyle="primary", dateformat="%d/%m/%Y")
        entry_data_inicial.pack(side=tk.LEFT, padx=(10, 0))
        
        # Define data inicial como primeiro dia do mês
        try:
            primeiro_dia_mes = datetime.date.today().replace(day=1)
            entry_data_inicial.entry.delete(0, tk.END)
            entry_data_inicial.entry.insert(0, primeiro_dia_mes.strftime("%d/%m/%Y"))
        except:
            pass

        # Data final
        row2 = tk.Frame(dates_frame, bg='#f8f9fa')
        row2.pack(fill=tk.X, pady=3)
        tk.Label(row2, text="Data Final:", font=("Segoe UI", 10), bg='#f8f9fa', width=12, anchor='w').pack(side=tk.LEFT)
        entry_data_final = DateEntry(row2, width=15, bootstyle="primary", dateformat="%d/%m/%Y")
        entry_data_final.pack(side=tk.LEFT, padx=(10, 0))

        # Frame para filtro de tipo
        tipo_frame = tk.LabelFrame(main_frame, text=" Filtrar por Tipo ", font=("Segoe UI", 9, "bold"),
                                   bg='#f8f9fa', padx=10, pady=10)
        tipo_frame.pack(pady=5, fill=tk.X)
        
        tipo_row = tk.Frame(tipo_frame, bg='#f8f9fa')
        tipo_row.pack(fill=tk.X)
        tipo_var = tk.StringVar(value="Todos")
        tipos_exclusao = ["Todos", "Transacao Caixa", "Produto", "Venda", "Cliente", "Fornecedor", "Categoria", "Entregador", "Bairro", "Tamanho", "Cartão", "Vendedor", "Serviço"]
        tk.Label(tipo_row, text="Tipo de Registro:", font=("Segoe UI", 10), bg='#f8f9fa').pack(side=tk.LEFT, padx=(0, 10))
        cmb_tipo = ttk.Combobox(tipo_row, textvariable=tipo_var, values=tipos_exclusao, state="readonly", width=20)
        cmb_tipo.pack(side=tk.LEFT)

        # Função para gerar relatório
        def gerar_relatorio():
            try:
                # Converte as datas do formato brasileiro para datetime
                data_inicial_str = entry_data_inicial.entry.get().strip()
                data_final_str = entry_data_final.entry.get().strip()
                
                data_inicial = datetime.datetime.strptime(data_inicial_str, '%d/%m/%Y').date()
                data_final = datetime.datetime.strptime(data_final_str, '%d/%m/%Y').date()
                
                if data_inicial > data_final:
                    messagebox.showerror("Erro", "Data inicial nao pode ser maior que data final.", parent=period_win)
                    return
                
                # Carrega log de exclusões
                exclusions = load_exclusions_log()
                
                if not exclusions:
                    messagebox.showinfo("Relatorio", "Nenhum registro de exclusao encontrado.\n\nAs exclusoes serao registradas a partir de agora.", parent=period_win)
                    return
                
                # Filtra exclusões do período e tipo
                tipo_filtro = tipo_var.get()
                exclusions_filtered = []
                
                for exc in exclusions:
                    datahora_str = exc.get('datahora', '')
                    if datahora_str:
                        try:
                            exc_date = datetime.datetime.strptime(datahora_str, '%Y-%m-%d %H:%M:%S').date()
                            if data_inicial <= exc_date <= data_final:
                                if tipo_filtro == "Todos" or exc.get('tipo_registro') == tipo_filtro:
                                    exclusions_filtered.append(exc)
                        except Exception:
                            continue
                
                if not exclusions_filtered:
                    messagebox.showinfo("Relatorio", 
                                      f"Nenhuma exclusao encontrada no periodo de {data_inicial_str} a {data_final_str}.", 
                                      parent=period_win)
                    return
                
                # Gera o relatório
                report = "=" * 48 + "\n"
                report += "RELATORIO DE EXCLUSOES".center(48) + "\n"
                report += "=" * 48 + "\n"
                report += f"Periodo: {data_inicial_str} a {data_final_str}\n"
                if tipo_filtro != "Todos":
                    report += f"Tipo: {tipo_filtro}\n"
                report += f"Emitido: {datetime.datetime.now().strftime('%d/%m/%Y %H:%M')}\n"
                report += "=" * 48 + "\n\n"
                
                # Agrupa por usuário
                exclusions_by_user = defaultdict(list)
                for exc in exclusions_filtered:
                    usuario = exc.get('usuario', 'Desconhecido')
                    exclusions_by_user[usuario].append(exc)
                
                # Resumo
                report += "RESUMO POR USUARIO:\n"
                report += "-" * 48 + "\n"
                for usuario, excs in sorted(exclusions_by_user.items()):
                    report += f"  {usuario}: {len(excs)} exclusao(oes)\n"
                report += "-" * 48 + "\n"
                report += f"  TOTAL: {len(exclusions_filtered)} exclusao(oes)\n\n"
                
                # Detalhamento
                report += "=" * 48 + "\n"
                report += "DETALHAMENTO DAS EXCLUSOES:\n"
                report += "=" * 48 + "\n\n"
                
                for exc in sorted(exclusions_filtered, key=lambda x: x.get('datahora', ''), reverse=True):
                    datahora = exc.get('datahora', 'N/A')
                    usuario = exc.get('usuario', 'Desconhecido')
                    tipo_reg = exc.get('tipo_registro', 'N/A')
                    dados = exc.get('dados_excluidos', {})
                    motivo = exc.get('motivo', '')
                    
                    # Obtém o nome do caixa dos dados excluídos (se disponível)
                    caixa_nome = dados.get('caixa', '') if isinstance(dados, dict) else ''
                    
                    # Formata data/hora para exibição
                    try:
                        dt = datetime.datetime.strptime(datahora, '%Y-%m-%d %H:%M:%S')
                        datahora_fmt = dt.strftime('%d/%m/%Y %H:%M:%S')
                    except:
                        datahora_fmt = datahora
                    
                    report += "=" * 48 + "\n"
                    report += f"DATA: {datahora_fmt}\n"
                    report += f"USUARIO: {usuario}\n"
                    if caixa_nome:
                        report += f"TIPO: {tipo_reg} | CX: {caixa_nome}\n"
                    else:
                        report += f"TIPO: {tipo_reg}\n"
                    report += "-" * 48 + "\n"
                    
                    # Exibe dados do registro excluído
                    if isinstance(dados, dict):
                        for key, value in dados.items():
                            key_fmt = key.replace('_', ' ').title()
                            if key == 'valor' and isinstance(value, (int, float)):
                                value_fmt = format_br_currency(value)
                            else:
                                value_fmt = str(value)[:40]
                            report += f"  {key_fmt}: {value_fmt}\n"
                    else:
                        report += f"  Dados: {str(dados)[:44]}\n"
                    
                    if motivo:
                        report += f"  Motivo: {motivo}\n"
                    
                    report += "\n"
                
                report += "=" * 48 + "\n"
                report += "FIM DO RELATORIO\n"
                report += "=" * 48 + "\n"
                
                # Fecha janela de seleção e exibe relatório
                period_win.destroy()
                ReportWindow(self.root, f"Exclusoes - {data_inicial_str} a {data_final_str}", report, self)
                log_user_action("Relatorio", f"Visualizou Relatorio de Exclusoes ({data_inicial_str} a {data_final_str})")
                
            except ValueError:
                messagebox.showerror("Erro", "Formato de data invalido. Use DD/MM/AAAA.", parent=period_win)
            except Exception as e:
                messagebox.showerror("Erro", f"Erro ao gerar relatorio: {str(e)}", parent=period_win)

        # Botões
        buttons_frame = tk.Frame(main_frame, bg='#f8f9fa')
        buttons_frame.pack(pady=(10, 5), fill=tk.X)
        
        btn_gerar = tk.Button(buttons_frame, text="GERAR RELATORIO", 
                              command=gerar_relatorio, bg="#dc3545", fg="white",
                              font=("Segoe UI", 11, "bold"), padx=25, pady=10, cursor="hand2")
        btn_gerar.pack(side=tk.LEFT, padx=(0, 10))
        
        btn_cancelar = tk.Button(buttons_frame, text="Cancelar", 
                                 command=period_win.destroy, bg="#6c757d", fg="white",
                                 font=("Segoe UI", 10), padx=20, pady=10, cursor="hand2")
        btn_cancelar.pack(side=tk.RIGHT)

        # Atalhos
        period_win.bind("<Return>", lambda e: gerar_relatorio())
        period_win.bind("<Escape>", lambda e: period_win.destroy())
        
        # Forçar atualização da janela
        period_win.update()

    def show_users_report(self):
        if not check_permission("relatorios.usuarios"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar este relatório.")
            return
        users = load_users()
        if not users:
            messagebox.showinfo("Relatório", "Nenhum usuário cadastrado.", parent=self.root)
            return
        
        report = "=" * 48 + "\n"
        report += "RELATORIO DE USUARIOS".center(48) + "\n"
        report += "=" * 48 + "\n"
        report += f"{'USUARIO':<15} {'NIVEL':<10}\n"
        report += "-" * 48 + "\n"
        
        # Ordena usuários por nome
        for username in sorted(users.keys()):
            user_data = users[username]
            level = user_data.get('nivel_acesso', user_data.get('level', 'N/A'))
            permissions = user_data.get('permissoes', user_data.get('permissions', []))
            
            # Formata as permissões para exibição
            if level == 'admin':
                perm_str = "TODAS (Administrador)"
            else:
                # Mapeia as chaves de permissão para nomes amigáveis
                perm_map = {
                    "produtos.editar": "Produtos",
                    "clientes.editar": "Clientes",
                    "fornecedores.editar": "Fornecedores",
                    "cartoes.editar": "Cartões",
                    "estoque.entrada_nota": "Entrada NF",
                    "financeiro.pagar_conta": "Contas Pagar",
                    "financeiro.receber_conta": "Contas Receber",
                    "relatorios.acessar": "Relatórios",
                    "config.usuarios": "Usuários",
                    "config.acessar": "Configurações"
                }
                active_perms = [perm_map.get(p, p) for p in permissions]
                perm_str = ", ".join(active_perms) if active_perms else "Nenhuma"
            
            report += f"{username:<15} {level:<10}\n"
            if perm_str and perm_str != "Nenhuma":
                perm_line = f"  {perm_str}"
                while len(perm_line) > 46:
                    report += f"{perm_line[:46]}\n"
                    perm_line = f"  {perm_line[46:]}"
                report += f"{perm_line}\n"
            report += "-" * 48 + "\n"

        report += "=" * 48 + "\n"
        report += f"TOTAL: {len(users)} usuario(s)\n"
        report += "=" * 48 + "\n"
        
        ReportWindow(self.root, "Usuarios do Sistema", report, self)

    def show_vendedores_report(self):
        """Gera e exibe o relatório completo de vendedores com desempenho de vendas."""
        if not check_permission("relatorios.vendedores"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar este relatório.")
            return
        
        # Carrega vendedores
        if not hasattr(self, 'vendedores') or not self.vendedores:
            self.vendedores = load_data(VENDEDORES_FILE, {})
        
        vendedores = self.vendedores
        if not vendedores:
            messagebox.showinfo("Relatório", "Nenhum vendedor cadastrado.", parent=self.root)
            return
        
        # Calcula totais de vendas por vendedor a partir do sales_log
        vendas_por_vendedor = {}  # {vendedor_id: {'num_vendas': int, 'total_vendas': float}}
        for venda in self.sales_log:
            vid = str(venda.get('vendedor_id', '') or '')
            if vid:
                if vid not in vendas_por_vendedor:
                    vendas_por_vendedor[vid] = {'num_vendas': 0, 'total_vendas': 0.0}
                vendas_por_vendedor[vid]['num_vendas'] += 1
                vendas_por_vendedor[vid]['total_vendas'] += float(venda.get('total', 0.0) or 0.0)
        
        store_name = self.empresa_data.get('nome_fantasia', self.empresa_data.get('razao_social', 'LOJA'))
        
        report = "=" * 48 + "\n"
        report += "RELATORIO DE VENDEDORES".center(48) + "\n"
        report += f"{store_name.center(48)}\n"
        report += f"{datetime.datetime.now().strftime('%d/%m/%Y %H:%M').center(48)}\n"
        report += "=" * 48 + "\n\n"
        
        # Cabeçalho da tabela resumo
        report += f"{'VENDEDOR':<20}{'STATUS':<10}{'VENDAS':>8}{'TOTAL':>10}\n"
        report += "-" * 48 + "\n"
        
        total_geral_vendas = 0.0
        total_geral_num = 0
        vendedores_ativos = 0
        vendedores_inativos = 0
        
        # Ordena vendedores por nome
        for vid in sorted(vendedores.keys(), key=lambda x: vendedores[x].get('nome', '').lower()):
            vdata = vendedores[vid]
            if not isinstance(vdata, dict):
                continue
            
            nome = vdata.get('nome', 'N/A')[:19]
            status = vdata.get('status', 'Ativo')[:9]
            
            if status == 'Ativo':
                vendedores_ativos += 1
            else:
                vendedores_inativos += 1
            
            dados_vendas = vendas_por_vendedor.get(vid, {'num_vendas': 0, 'total_vendas': 0.0})
            num_vendas = dados_vendas['num_vendas']
            total_vendas = dados_vendas['total_vendas']
            total_geral_vendas += total_vendas
            total_geral_num += num_vendas
            
            total_str = format_br_currency(total_vendas).replace('R$ ', '')
            report += f"{nome:<20}{status:<10}{num_vendas:>8}{total_str:>10}\n"
        
        report += "-" * 48 + "\n"
        total_geral_str = format_br_currency(total_geral_vendas).replace('R$ ', '')
        report += f"{'TOTAL':<20}{'':<10}{total_geral_num:>8}{total_geral_str:>10}\n"
        report += "=" * 48 + "\n\n"
        
        # Detalhamento individual de cada vendedor
        report += "DETALHAMENTO POR VENDEDOR\n"
        report += "=" * 48 + "\n"
        
        for vid in sorted(vendedores.keys(), key=lambda x: vendedores[x].get('nome', '').lower()):
            vdata = vendedores[vid]
            if not isinstance(vdata, dict):
                continue
            
            nome = vdata.get('nome', 'N/A')
            telefone = vdata.get('telefone', '')
            email = vdata.get('email', '')
            comissao = float(vdata.get('comissao', 0.0) or 0.0)
            meta_mensal = float(vdata.get('meta_mensal', 0.0) or 0.0)
            salario_base = float(vdata.get('salario_base', 0.0) or 0.0)
            status = vdata.get('status', 'Ativo')
            data_admissao = vdata.get('data_admissao', '')
            pix = vdata.get('pix', '')
            observacao = vdata.get('observacao', '')
            
            dados_vendas = vendas_por_vendedor.get(vid, {'num_vendas': 0, 'total_vendas': 0.0})
            num_vendas = dados_vendas['num_vendas']
            total_vendas = dados_vendas['total_vendas']
            valor_comissao = total_vendas * (comissao / 100.0) if comissao > 0 else 0.0
            
            report += f"\n{nome}\n"
            report += "-" * 48 + "\n"
            report += f"  Status: {status}\n"
            if telefone:
                report += f"  Telefone: {telefone}\n"
            if email:
                report += f"  Email: {email}\n"
            if data_admissao:
                report += f"  Admissao: {data_admissao}\n"
            if pix:
                report += f"  PIX: {pix}\n"
            if salario_base > 0:
                report += f"  Salario Base: {format_br_currency(salario_base)}\n"
            report += f"  Comissao: {format_br_float(comissao, 2)}%\n"
            
            report += f"  Vendas Realizadas: {num_vendas}\n"
            report += f"  Total Vendido: {format_br_currency(total_vendas)}\n"
            
            if comissao > 0 and total_vendas > 0:
                report += f"  Comissao Devida: {format_br_currency(valor_comissao)}\n"
            
            if meta_mensal > 0:
                report += f"  Meta Mensal: {format_br_currency(meta_mensal)}\n"
                # Calcula vendas do mês atual
                mes_atual = datetime.datetime.now().month
                ano_atual = datetime.datetime.now().year
                total_mes = 0.0
                for venda in self.sales_log:
                    if str(venda.get('vendedor_id', '') or '') == vid:
                        try:
                            data_venda = venda.get('data', '')
                            if '/' in data_venda:
                                partes = data_venda.split('/')
                                if len(partes) >= 3:
                                    m = int(partes[1])
                                    a = int(partes[2]) if len(partes[2]) == 4 else int('20' + partes[2])
                                    if m == mes_atual and a == ano_atual:
                                        total_mes += float(venda.get('total', 0.0) or 0.0)
                        except (ValueError, IndexError):
                            pass
                
                percentual_meta = (total_mes / meta_mensal) * 100 if meta_mensal > 0 else 0.0
                report += f"  Vendas no Mes: {format_br_currency(total_mes)}\n"
                report += f"  Atingimento Meta: {format_br_float(percentual_meta, 1)}%\n"
                
                if percentual_meta >= 100:
                    report += f"  >>> META ATINGIDA! <<<\n"
                elif percentual_meta >= 80:
                    falta = meta_mensal - total_mes
                    report += f"  Falta: {format_br_currency(falta)}\n"
            
            if observacao:
                obs_truncada = observacao[:44]
                report += f"  Obs: {obs_truncada}\n"
            
            report += "-" * 48 + "\n"
        
        # Resumo final
        report += "\n" + "=" * 48 + "\n"
        report += "RESUMO GERAL\n"
        report += "=" * 48 + "\n"
        report += f"Vendedores Ativos:{vendedores_ativos:>29}\n"
        report += f"Vendedores Inativos:{vendedores_inativos:>27}\n"
        report += f"Total Vendedores:{len(vendedores):>30}\n"
        report += f"Total Vendas:{total_geral_num:>34}\n"
        report += f"Valor Total:{format_br_currency(total_geral_vendas):>35}\n"
        
        if total_geral_num > 0:
            ticket_medio = total_geral_vendas / total_geral_num
            report += f"Ticket Medio:{format_br_currency(ticket_medio):>34}\n"
        
        # Calcula total de comissões devidas
        total_comissoes = 0.0
        for vid in vendedores.keys():
            vdata = vendedores[vid]
            if not isinstance(vdata, dict):
                continue
            comissao = float(vdata.get('comissao', 0.0) or 0.0)
            dados_v = vendas_por_vendedor.get(vid, {'total_vendas': 0.0})
            total_comissoes += dados_v['total_vendas'] * (comissao / 100.0)
        
        if total_comissoes > 0:
            report += f"Total Comissoes:{format_br_currency(total_comissoes):>31}\n"
        
        report += "=" * 48 + "\n"
        
        log_user_action("Relatório", "Visualizou Relatório de Vendedores")
        ReportWindow(self.root, "Relatorio de Vendedores", report, self)

    def show_resumo_vendas_por_vendedor_report(self):
        """
        Gera e exibe o relatório de RESUMO DE VENDAS POR VENDEDOR com filtro por período.
        Mostra para cada vendedor: quantidade de vendas, valor total, comissão devida,
        detalhamento por forma de pagamento, ticket médio e ranking de vendedores.
        """
        try:
            AUDITORIA.processo("Relatório de vendas por vendedor")
        except Exception:
            pass
        if not check_permission("relatorios.resumo_vendas_vendedor"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar este relatório.", parent=self.root)
            return
        
        # Carrega vendedores
        if not hasattr(self, 'vendedores') or not self.vendedores:
            self.vendedores = load_data(VENDEDORES_FILE, {})
        
        vendedores = self.vendedores
        if not vendedores:
            messagebox.showinfo("Relatório", "Nenhum vendedor cadastrado.", parent=self.root)
            return
        
        if not self.sales_log:
            messagebox.showinfo("Relatório", "Nenhuma venda registrada.", parent=self.root)
            return
        
        # Cria janela de seleção de período
        period_win = tk.Toplevel(self.root)
        period_win.title("💰 Resumo de Vendas por Vendedor")
        responsive_geometry(period_win, 500, 400)
        period_win.transient(self.root)
        period_win.grab_set()
        period_win.resizable(True, True)
        period_win.configure(bg='#f8f9fa')
        
        # Centralizar a janela na tela
        period_win.update_idletasks()
        width = period_win.winfo_width()
        height = period_win.winfo_height()
        x = (period_win.winfo_screenwidth() // 2) - (width // 2)
        y = (period_win.winfo_screenheight() // 2) - (height // 2)
        period_win.geometry(f'+{x}+{y}')

        # Frame principal
        main_frame = ttk.Frame(period_win, padding="20")
        main_frame.pack(expand=True, fill=tk.BOTH)

        # Título
        ttk.Label(main_frame, text="💰 Resumo de Vendas por Vendedor", 
                 font=("Segoe UI", 14, "bold")).pack(pady=(0, 20))
        
        ttk.Label(main_frame, text="Selecione o período para gerar o relatório:", 
                 font=("Segoe UI", 10)).pack(pady=(0, 15))

        # Frame para as datas
        dates_frame = ttk.Frame(main_frame)
        dates_frame.pack(pady=10)

        # Data inicial
        ttk.Label(dates_frame, text="Data Inicial:").grid(row=0, column=0, sticky=tk.W, pady=5)
        entry_data_inicial = DateEntry(dates_frame, width=15, bootstyle="primary", dateformat="%d/%m/%Y")
        entry_data_inicial.grid(row=0, column=1, padx=(10, 0), pady=5)

        # Data final
        ttk.Label(dates_frame, text="Data Final:").grid(row=1, column=0, sticky=tk.W, pady=5)
        entry_data_final = DateEntry(dates_frame, width=15, bootstyle="primary", dateformat="%d/%m/%Y")
        entry_data_final.grid(row=1, column=1, padx=(10, 0), pady=5)

        # Label de instrução
        ttk.Label(main_frame, text="Formato: DD/MM/AAAA", 
                 font=("Segoe UI", 9), foreground="gray").pack(pady=(5, 15))

        # Função para validar e gerar relatório
        def gerar_relatorio_vendas_vendedor():
            try:
                # Converte as datas do formato brasileiro para datetime
                data_inicial_str = entry_data_inicial.entry.get().strip()
                data_final_str = entry_data_final.entry.get().strip()
                
                data_inicial = datetime.datetime.strptime(data_inicial_str, '%d/%m/%Y').date()
                data_final = datetime.datetime.strptime(data_final_str, '%d/%m/%Y').date()
                
                if data_inicial > data_final:
                    messagebox.showerror("Erro", "Data inicial não pode ser maior que data final.", parent=period_win)
                    return
                
                # Filtra vendas do período
                sales_period = []
                for sale in self.sales_log:
                    if not isinstance(sale, dict):
                        continue
                    timestamp = sale.get('timestamp', '')
                    if timestamp:
                        try:
                            sale_date = datetime.datetime.fromisoformat(timestamp).date()
                            if data_inicial <= sale_date <= data_final:
                                sales_period.append(sale)
                        except Exception:
                            continue
                
                if not sales_period:
                    messagebox.showinfo("Relatório", 
                                      f"Nenhuma venda encontrada no período de {data_inicial_str} a {data_final_str}.", 
                                      parent=period_win)
                    return
                
                # Chaves que NÃO são formas de pagamento
                chaves_ignorar = ['Desconto', 'Observacao', 'ContasAReceber_parcelas', 'Parcelamento',
                                  'CartaoDebito_Bandeira', 'CartaoDebito_Taxa', 'CartaoDebito_ID', 'CartaoDebito_Parcelas', 'CartaoDebito_Taxa_Acrescimo_Ativo', 'CartaoDebito_Valor_Original', 'CartaoDebito_Valor_Taxa',
                                  'CartaoCredito_Bandeira', 'CartaoCredito_Taxa', 'CartaoCredito_ID', 'CartaoCredito_Parcelas', 'CartaoCredito_Taxa_Acrescimo_Ativo', 'CartaoCredito_Valor_Original', 'CartaoCredito_Valor_Taxa', 'Acrescimo']
                
                # Mapeamento de nomes de formas de pagamento
                nomes_formas = {
                    'Dinheiro': 'Dinheiro',
                    'CartaoDebito': 'Cartão Débito',
                    'CartaoCredito': 'Cartão Crédito',
                    'PIX': 'PIX',
                    'ContasAReceber': 'Fiado',
                    'CreditoCliente': 'Crédito Cliente',
                    'Cashback': 'Cashback',
                    'LinkPagamento': 'Link Pagamento',
                    'PAGO': 'Pago',
                    'ENVIOS': 'Envios'
                }
                
                # Agrupa vendas por vendedor
                # Estrutura: {vendedor_id: {'nome': str, 'num_vendas': int, 'total_vendas': float,
                #              'formas_pagamento': {forma: valor}, 'comissao_pct': float, 'itens_vendidos': int}}
                resumo_vendedores = {}
                vendas_sem_vendedor = {'num_vendas': 0, 'total_vendas': 0.0, 'formas_pagamento': {}, 'itens_vendidos': 0}
                
                for sale in sales_period:
                    vid = str(sale.get('vendedor_id', '') or '')
                    total_venda = float(sale.get('total', 0.0) or 0.0)
                    
                    # Conta itens da venda
                    itens = sale.get('itens', {})
                    num_itens = 0
                    if isinstance(itens, dict):
                        for item_id, item_data in itens.items():
                            try:
                                qtd = float(item_data.get('quantidade_peso', 1) or 1)
                                num_itens += qtd
                            except (ValueError, TypeError):
                                num_itens += 1
                    
                    # Processa formas de pagamento da venda
                    formas = sale.get('formas_pagamento', {})
                    formas_venda = {}
                    if isinstance(formas, dict):
                        for metodo, valor in formas.items():
                            if metodo in chaves_ignorar:
                                continue
                            try:
                                valor_f = float(valor)
                                if valor_f > 0:
                                    nome_forma = nomes_formas.get(metodo, metodo)
                                    formas_venda[nome_forma] = formas_venda.get(nome_forma, 0.0) + valor_f
                            except (ValueError, TypeError):
                                continue
                    
                    if vid and vid in vendedores:
                        if vid not in resumo_vendedores:
                            vdata = vendedores[vid]
                            resumo_vendedores[vid] = {
                                'nome': vdata.get('nome', 'N/A') if isinstance(vdata, dict) else 'N/A',
                                'num_vendas': 0,
                                'total_vendas': 0.0,
                                'formas_pagamento': {},
                                'comissao_pct': float(vdata.get('comissao', 0.0) or 0.0) if isinstance(vdata, dict) else 0.0,
                                'itens_vendidos': 0
                            }
                        resumo_vendedores[vid]['num_vendas'] += 1
                        resumo_vendedores[vid]['total_vendas'] += total_venda
                        resumo_vendedores[vid]['itens_vendidos'] += num_itens
                        for forma, val in formas_venda.items():
                            resumo_vendedores[vid]['formas_pagamento'][forma] = \
                                resumo_vendedores[vid]['formas_pagamento'].get(forma, 0.0) + val
                    else:
                        # Vendas sem vendedor associado
                        vendas_sem_vendedor['num_vendas'] += 1
                        vendas_sem_vendedor['total_vendas'] += total_venda
                        vendas_sem_vendedor['itens_vendidos'] += num_itens
                        for forma, val in formas_venda.items():
                            vendas_sem_vendedor['formas_pagamento'][forma] = \
                                vendas_sem_vendedor['formas_pagamento'].get(forma, 0.0) + val
                
                # Dados da empresa
                empresa = self.empresa_data
                store_name = empresa.get('nome_fantasia', empresa.get('razao_social', empresa.get('nome', 'EMPRESA')))
                store_cnpj = empresa.get('cnpj', '')
                
                # ========== MONTA O RELATÓRIO ==========
                report = "=" * 48 + "\n"
                report += f"{store_name.center(48)}\n"
                if store_cnpj:
                    report += f"{'CNPJ: ' + store_cnpj:^48}\n"
                report += "=" * 48 + "\n"
                report += "RESUMO DE VENDAS POR VENDEDOR".center(48) + "\n"
                report += "=" * 48 + "\n"
                report += f"Periodo: {data_inicial_str} a {data_final_str}\n"
                report += f"Data/Hora: {datetime.datetime.now().strftime('%d/%m/%Y %H:%M')}\n"
                report += "=" * 48 + "\n\n"
                
                # ===== TABELA RESUMO GERAL =====
                report += "RESUMO GERAL POR VENDEDOR\n"
                report += "-" * 48 + "\n"
                report += f"{'VENDEDOR':<20}{'QTD':>6}{'TOTAL':>21}\n"
                report += "-" * 48 + "\n"
                
                total_geral = 0.0
                total_geral_vendas = 0
                total_geral_comissao = 0.0
                total_geral_itens = 0
                
                # Ordena por total de vendas (maior para menor)
                vendedores_ordenados = sorted(
                    resumo_vendedores.items(),
                    key=lambda x: x[1]['total_vendas'],
                    reverse=True
                )
                
                for vid, dados in vendedores_ordenados:
                    nome = dados['nome'][:19]
                    num_v = dados['num_vendas']
                    total_v = dados['total_vendas']
                    total_geral += total_v
                    total_geral_vendas += num_v
                    total_geral_itens += dados['itens_vendidos']
                    
                    comissao_valor = total_v * (dados['comissao_pct'] / 100.0) if dados['comissao_pct'] > 0 else 0.0
                    total_geral_comissao += comissao_valor
                    
                    total_str = format_br_currency(total_v)
                    report += f"{nome:<20}{num_v:>6}{total_str:>21}\n"
                
                # Vendas sem vendedor
                if vendas_sem_vendedor['num_vendas'] > 0:
                    nome_sv = "(Sem Vendedor)"[:19]
                    num_sv = vendas_sem_vendedor['num_vendas']
                    total_sv = vendas_sem_vendedor['total_vendas']
                    total_geral += total_sv
                    total_geral_vendas += num_sv
                    total_geral_itens += vendas_sem_vendedor['itens_vendidos']
                    total_str_sv = format_br_currency(total_sv)
                    report += f"{nome_sv:<20}{num_sv:>6}{total_str_sv:>21}\n"
                
                report += "-" * 48 + "\n"
                report += f"{'TOTAL GERAL':<20}{total_geral_vendas:>6}{format_br_currency(total_geral):>21}\n"
                report += "=" * 48 + "\n\n"
                
                # ===== DETALHAMENTO POR VENDEDOR =====
                report += "DETALHAMENTO POR VENDEDOR\n"
                report += "=" * 48 + "\n"
                
                ranking = 0
                for vid, dados in vendedores_ordenados:
                    ranking += 1
                    nome = dados['nome']
                    num_v = dados['num_vendas']
                    total_v = dados['total_vendas']
                    comissao_pct = dados['comissao_pct']
                    comissao_valor = total_v * (comissao_pct / 100.0) if comissao_pct > 0 else 0.0
                    itens_v = dados['itens_vendidos']
                    ticket_medio = total_v / num_v if num_v > 0 else 0.0
                    
                    report += f"\n#{ranking} - {nome}\n"
                    report += "-" * 48 + "\n"
                    report += f"  Vendas Realizadas: {num_v:>26}\n"
                    report += f"  Itens Vendidos: {itens_v:>29.0f}\n"
                    report += f"  Total Vendido: {format_br_currency(total_v):>30}\n"
                    report += f"  Ticket Medio: {format_br_currency(ticket_medio):>31}\n"
                    
                    if comissao_pct > 0:
                        report += f"  Comissao ({format_br_float(comissao_pct, 2)}%): {format_br_currency(comissao_valor):>25}\n"
                    
                    # Percentual de participação
                    if total_geral > 0:
                        participacao = (total_v / total_geral) * 100
                        report += f"  Participacao: {format_br_float(participacao, 1)}%\n"
                    
                    # Formas de pagamento do vendedor
                    if dados['formas_pagamento']:
                        report += f"  \n"
                        report += f"  Formas de Pagamento:\n"
                        for forma, valor_forma in sorted(dados['formas_pagamento'].items(), key=lambda x: x[1], reverse=True):
                            forma_fmt = forma[:22]
                            report += f"    {forma_fmt:<22}{format_br_currency(valor_forma):>22}\n"
                    
                    report += "-" * 48 + "\n"
                
                # Vendas sem vendedor (detalhamento)
                if vendas_sem_vendedor['num_vendas'] > 0:
                    report += f"\n(SEM VENDEDOR ASSOCIADO)\n"
                    report += "-" * 48 + "\n"
                    report += f"  Vendas Realizadas: {vendas_sem_vendedor['num_vendas']:>26}\n"
                    report += f"  Itens Vendidos: {vendas_sem_vendedor['itens_vendidos']:>29.0f}\n"
                    report += f"  Total Vendido: {format_br_currency(vendas_sem_vendedor['total_vendas']):>30}\n"
                    if vendas_sem_vendedor['num_vendas'] > 0:
                        tm_sv = vendas_sem_vendedor['total_vendas'] / vendas_sem_vendedor['num_vendas']
                        report += f"  Ticket Medio: {format_br_currency(tm_sv):>31}\n"
                    if vendas_sem_vendedor['formas_pagamento']:
                        report += f"  \n"
                        report += f"  Formas de Pagamento:\n"
                        for forma, valor_forma in sorted(vendas_sem_vendedor['formas_pagamento'].items(), key=lambda x: x[1], reverse=True):
                            forma_fmt = forma[:22]
                            report += f"    {forma_fmt:<22}{format_br_currency(valor_forma):>22}\n"
                    report += "-" * 48 + "\n"
                
                # ===== RESUMO FINAL =====
                report += "\n" + "=" * 48 + "\n"
                report += "TOTAIS GERAIS DO PERIODO\n"
                report += "=" * 48 + "\n"
                report += f"Total de Vendedores:{len(resumo_vendedores):>27}\n"
                report += f"Total de Vendas:{total_geral_vendas:>31}\n"
                report += f"Total de Itens:{total_geral_itens:>32.0f}\n"
                report += f"Valor Total:{format_br_currency(total_geral):>35}\n"
                
                if total_geral_vendas > 0:
                    ticket_medio_geral = total_geral / total_geral_vendas
                    report += f"Ticket Medio Geral:{format_br_currency(ticket_medio_geral):>28}\n"
                
                if total_geral_comissao > 0:
                    report += f"Total Comissoes:{format_br_currency(total_geral_comissao):>31}\n"
                
                # Formas de pagamento consolidadas
                report += "\n" + "-" * 48 + "\n"
                report += "FORMAS DE PAGAMENTO (CONSOLIDADO)\n"
                report += "-" * 48 + "\n"
                
                formas_consolidadas = {}
                for vid, dados in resumo_vendedores.items():
                    for forma, val in dados['formas_pagamento'].items():
                        formas_consolidadas[forma] = formas_consolidadas.get(forma, 0.0) + val
                # Inclui vendas sem vendedor
                for forma, val in vendas_sem_vendedor['formas_pagamento'].items():
                    formas_consolidadas[forma] = formas_consolidadas.get(forma, 0.0) + val
                
                for forma, valor_total in sorted(formas_consolidadas.items(), key=lambda x: x[1], reverse=True):
                    forma_fmt = forma[:24]
                    report += f"  {forma_fmt:<24}{format_br_currency(valor_total):>22}\n"
                
                report += "-" * 48 + "\n"
                report += f"{'TOTAL:':>26}{format_br_currency(sum(formas_consolidadas.values())):>22}\n"
                
                report += "=" * 48 + "\n"
                report += f"{store_name.center(48)}\n"
                report += "=" * 48 + "\n"
                
                # Fecha janela de seleção e exibe relatório
                period_win.destroy()
                log_user_action("Relatório", f"Visualizou Resumo de Vendas por Vendedor ({data_inicial_str} a {data_final_str})")
                ReportWindow(self.root, f"Resumo de Vendas por Vendedor - {data_inicial_str} a {data_final_str}", report, self)
                
            except ValueError:
                messagebox.showerror("Erro", "Formato de data inválido. Use DD/MM/AAAA.", parent=period_win)
            except Exception as e:
                messagebox.showerror("Erro", f"Erro ao gerar relatório: {str(e)}", parent=period_win)
                import traceback
                traceback.print_exc()

        # Botões
        buttons_frame = ttk.Frame(main_frame)
        buttons_frame.pack(pady=20, fill=tk.X)
        
        ttk.Button(buttons_frame, text="📊 Gerar Relatório", 
                  command=gerar_relatorio_vendas_vendedor, bootstyle="success").pack(side=tk.LEFT, padx=(0, 10))
        ttk.Button(buttons_frame, text="Cancelar", 
                  command=lambda: period_win.destroy(), bootstyle="secondary").pack(side=tk.RIGHT)

        # Foco no primeiro campo
        entry_data_inicial.focus()
        
        # Permite Enter para gerar relatório
        period_win.bind('<Return>', lambda e: gerar_relatorio_vendas_vendedor())
        
        period_win.wait_window()

    def show_discounts_report(self):
        if not check_permission("relatorios.descontos"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar este relatório.")
            return
        if not self.sales_log:
            messagebox.showinfo("Relatório", "Nenhuma venda registrada.", parent=self.root)
            return
        
        report = "=" * 48 + "\n"
        report += "RELATORIO DE DESCONTOS".center(48) + "\n"
        report += "=" * 48 + "\n"
        report += f"{'CUPOM':<8}{'DATA':<11}{'TOTAL':>14}{'DESC':>14}\n"
        report += "-" * 48 + "\n"
        
        total_descontos = 0.0
        vendas_com_desconto = 0
        
        for venda in self.sales_log:
            desconto_venda = 0.0
            itens = venda.get('itens', {})
            
            # Calcula o desconto total da venda somando o desconto de cada item
            if isinstance(itens, dict):
                for item_id, item_data in itens.items():
                    desconto_item = parse_br_float(item_data.get('desconto', 0.0)) or 0.0
                    desconto_venda += desconto_item
            
            if desconto_venda > 0.001:
                vendas_com_desconto += 1
                total_descontos += desconto_venda
                
                cupom = str(venda.get('coupon_number', 'N/A'))
                data = venda.get('data', 'N/A')
                usuario = venda.get('usuario', 'N/A')
                total_venda = venda.get('total', 0.0)
                
                report += f"{cupom:<8}{data:<11}{format_br_float(total_venda, 2):>14}{format_br_float(desconto_venda, 2):>14}\n"
                report += f"  Usr: {usuario}\n"
                
                # Detalha quais itens tiveram desconto
                for item_id, item_data in itens.items():
                    desc_item = parse_br_float(item_data.get('desconto', 0.0)) or 0.0
                    if desc_item > 0.001:
                        _nome_desc = item_data.get('nome', 'N/A')
                        if len(_nome_desc) <= 30:
                            report += f"  {_nome_desc:<32} {format_br_float(desc_item, 2):>14}\n"
                        else:
                            report += f"  {_nome_desc}\n"
                            report += f"{'':<34} {format_br_float(desc_item, 2):>14}\n"
                report += "-" * 48 + "\n"

        if vendas_com_desconto == 0:
            messagebox.showinfo("Relatório", "Nenhuma venda com desconto encontrada.", parent=self.root)
            return

        report += "=" * 48 + "\n"
        report += f"Vendas c/ desconto: {vendas_com_desconto}\n"
        report += f"Total descontos:{format_br_currency(total_descontos):>31}\n"
        report += "=" * 48 + "\n"
        
        ReportWindow(self.root, "Relatorio de Descontos", report, self)

    def show_notas_entrada_report(self):
        if not check_permission("relatorios.notas_entrada"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar este relatório.")
            return
        notas = load_data(NOTAS_ENTRADA_FILE, {})
        if not notas:
            messagebox.showinfo("Relatório", "Nenhuma nota de entrada registrada.", parent=self.root)
            return
        
        report = "=" * 48 + "\n"
        report += "RELATORIO NOTAS DE ENTRADA".center(48) + "\n"
        report += "=" * 48 + "\n"
        report += f"{'ID':<4}{'DATA':<11}{'FORNECEDOR':<18}{'TOTAL':>14}\n"
        report += "-" * 48 + "\n"
        
        total_geral = 0.0
        # Ordena por ID numérico
        sorted_ids = sorted(notas.keys(), key=lambda x: int(x) if x.isdigit() else 0)
        
        for nota_id in sorted_ids:
            nota = notas[nota_id]
            fornecedor_id = nota.get('fornecedor_id', '')
            fornecedor_nome = self.suppliers.get(fornecedor_id, {}).get('nome', 'N/A')
            if len(fornecedor_nome) > 20: fornecedor_nome = fornecedor_nome[:17] + "..."
            
            total_nota = parse_br_float(nota.get('total_nota', '0,00'))
            total_geral += total_nota
            
            report += f"{nota_id:<4}{nota.get('data_nota', 'N/A'):<11}{fornecedor_nome[:16]:<18}{format_br_float(total_nota, 2):>14}\n"
            report += f"  NF: {nota.get('nota_fiscal', 'N/A')}\n"
            
            # Opcional: Listar itens da nota
            itens = nota.get('itens', {})
            if itens:
                for item_id, item_data in itens.items():
                    _nome_nota = item_data.get('nome', 'N/A')
                    _qtd_nota = item_data.get('qtd', 0)
                    _custo_nota = item_data.get('custo', '0,00')
                    if len(_nome_nota) <= 24:
                        report += f"  {_nome_nota:<26}x{_qtd_nota:<5}{_custo_nota:>14}\n"
                    else:
                        report += f"  {_nome_nota}\n"
                        report += f"{'':<28}x{_qtd_nota:<5}{_custo_nota:>14}\n"
                report += "-" * 48 + "\n"

        report += "=" * 48 + "\n"
        report += f"TOTAL COMPRAS:{format_br_currency(total_geral):>33}\n"
        report += "=" * 48 + "\n"
        
        ReportWindow(self.root, "Notas de Entrada", report, self)

    def show_taxa_entrega_report(self):
        """
        Gera e exibe o relatório de taxas de entrega por período.
        Mostra: Nome do entregador, Nº cupom, Valor da taxa de entrega.
        Ao final: Total da taxa de entrega e quantidade de entregas.
        """
        if not check_permission("relatorios.taxa_entrega"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar relatório de taxas de entrega.")
            return
        # Cria janela de seleção de período
        period_win = tk.Toplevel(self.root)
        period_win.title("🚚 Relatório de Taxa de Entrega")
        responsive_geometry(period_win, 500, 420)
        period_win.transient(self.root)
        period_win.grab_set()
        period_win.resizable(True, True)
        
        # Centralizar
        period_win.update_idletasks()
        x = (period_win.winfo_screenwidth() // 2) - (500 // 2)
        y = (period_win.winfo_screenheight() // 2) - (420 // 2)
        responsive_geometry(period_win, 500, 420)

        # Frame principal
        main_frame = ttk.Frame(period_win, padding="20")
        main_frame.pack(expand=True, fill=tk.BOTH)

        # Título
        ttk.Label(main_frame, text="🚚 Relatório de Taxa de Entrega", 
                 font=("Segoe UI", 14, "bold")).pack(pady=(0, 20))

        # Frame para as datas
        dates_frame = ttk.Frame(main_frame)
        dates_frame.pack(pady=10, fill=tk.X)

        # Data inicial
        ttk.Label(dates_frame, text="Data Inicial:").grid(row=0, column=0, sticky=tk.W, pady=5)
        entry_data_inicial = DateEntry(dates_frame, width=15, bootstyle="primary", dateformat="%d/%m/%Y")
        entry_data_inicial.grid(row=0, column=1, padx=(10, 0), pady=5)

        # Data final
        ttk.Label(dates_frame, text="Data Final:").grid(row=1, column=0, sticky=tk.W, pady=5)
        entry_data_final = DateEntry(dates_frame, width=15, bootstyle="primary", dateformat="%d/%m/%Y")
        entry_data_final.grid(row=1, column=1, padx=(10, 0), pady=5)

        # Label de instrução
        ttk.Label(main_frame, text="Formato: DD/MM/AAAA", 
                 font=("Segoe UI", 9), foreground="gray").pack(pady=(5, 15))

        # Função para gerar relatório
        def gerar_relatorio():
            try:
                # Converte as datas do formato brasileiro para datetime
                data_inicial_str = entry_data_inicial.entry.get().strip()
                data_final_str = entry_data_final.entry.get().strip()
                
                data_inicial = datetime.datetime.strptime(data_inicial_str, '%d/%m/%Y').date()
                data_final = datetime.datetime.strptime(data_final_str, '%d/%m/%Y').date()
                
                if data_inicial > data_final:
                    messagebox.showerror("Erro", "Data inicial não pode ser maior que data final.", parent=period_win)
                    return
                
                # Lista para armazenar as entregas encontradas
                entregas = []
                
                for venda in self.sales_log:
                    if not isinstance(venda, dict):
                        continue
                    
                    timestamp = venda.get('timestamp', '')
                    if not timestamp:
                        continue
                    
                    try:
                        sale_date = datetime.datetime.fromisoformat(timestamp).date()
                        if not (data_inicial <= sale_date <= data_final):
                            continue
                    except Exception:
                        continue
                    
                    # Verifica se é uma entrega
                    is_delivery = venda.get('is_delivery', False)
                    entregador_nome = venda.get('entregador_nome', '')
                    cupom = venda.get('coupon_number', 'N/A')
                    data_venda = venda.get('data', 'N/A')
                    
                    # Busca a taxa de entrega nos itens
                    itens = venda.get('itens', {})
                    taxa_valor = 0.0
                    
                    if isinstance(itens, dict):
                        for item_id, item_data in itens.items():
                            if isinstance(item_data, dict):
                                # Verifica se é taxa de entrega
                                if item_data.get('is_taxa_entrega', False) or item_id == 'TAXA_ENTREGA' or 'taxa' in item_data.get('nome', '').lower() and 'entrega' in item_data.get('nome', '').lower():
                                    preco = parse_br_float(item_data.get('preco', 0.0)) or 0.0
                                    qtd = parse_br_float(item_data.get('quantidade_peso', 1)) or 1
                                    taxa_valor += preco * qtd
                    
                    # Se encontrou taxa de entrega, adiciona à lista
                    if taxa_valor > 0:
                        entregas.append({
                            'entregador': entregador_nome if entregador_nome else 'Não informado',
                            'cupom': cupom,
                            'data': data_venda,
                            'taxa': taxa_valor
                        })
                
                if not entregas:
                    messagebox.showinfo("Relatório", 
                                      f"Nenhuma taxa de entrega encontrada no período de {data_inicial_str} a {data_final_str}.", 
                                      parent=period_win)
                    return
                
                # Gera o relatório
                report = "=" * 48 + "\n"
                report += "RELATORIO TAXA DE ENTREGA".center(48) + "\n"
                report += "=" * 48 + "\n"
                report += f"Periodo: {data_inicial_str} a {data_final_str}\n"
                report += f"Emitido: {datetime.datetime.now().strftime('%d/%m/%Y %H:%M')}\n"
                report += "=" * 48 + "\n\n"
                
                report += f"{'ENTREGADOR':<20}{'CUP':>6}{'VALOR':>20}\n"
                report += "-" * 48 + "\n"
                
                total_taxa = 0.0
                qtd_entregas = len(entregas)
                
                # Ordena por data e cupom
                entregas_ordenadas = sorted(entregas, key=lambda x: (x['data'], x['cupom']))
                
                for entrega in entregas_ordenadas:
                    entregador = entrega['entregador'][:20]
                    cupom_str = str(entrega['cupom'])[:6]
                    taxa_str = format_br_currency(entrega['taxa'])
                    
                    report += f"{entregador:<20}{cupom_str:>6}{taxa_str:>20}\n"
                    total_taxa += entrega['taxa']
                
                report += "-" * 48 + "\n"
                report += "\n"
                report += "=" * 48 + "\n"
                report += f"Entregas: {qtd_entregas}\n"
                report += f"Total Taxas:{format_br_currency(total_taxa):>35}\n"
                report += "=" * 48 + "\n"
                
                # Agrupa por entregador para resumo
                resumo_entregador = {}
                for entrega in entregas:
                    nome = entrega['entregador']
                    if nome not in resumo_entregador:
                        resumo_entregador[nome] = {'qtd': 0, 'total': 0.0}
                    resumo_entregador[nome]['qtd'] += 1
                    resumo_entregador[nome]['total'] += entrega['taxa']
                
                if len(resumo_entregador) > 1:
                    report += "\n\nRESUMO POR ENTREGADOR:\n"
                    report += "-" * 48 + "\n"
                    report += f"{'ENTREGADOR':<22}{'QTD':>6}{'TOTAL':>18}\n"
                    report += "-" * 48 + "\n"
                    
                    for nome, dados in sorted(resumo_entregador.items(), key=lambda x: x[1]['total'], reverse=True):
                        nome_exib = nome[:22]
                        report += f"{nome_exib:<22}{dados['qtd']:>6}{format_br_currency(dados['total']):>18}\n"
                    
                    report += "-" * 48 + "\n"
                
                # Fecha janela de seleção e exibe relatório
                period_win.destroy()
                ReportWindow(self.root, f"🚚 Taxa de Entrega - {data_inicial_str} a {data_final_str}", report, self)
                log_user_action("Relatório", f"Visualizou Relatório de Taxa de Entrega ({data_inicial_str} a {data_final_str})")
                
            except ValueError:
                messagebox.showerror("Erro", "Formato de data inválido. Use DD/MM/AAAA.", parent=period_win)
            except Exception as e:
                messagebox.showerror("Erro", f"Erro ao gerar relatório: {str(e)}", parent=period_win)

        # Botões
        buttons_frame = ttk.Frame(main_frame)
        buttons_frame.pack(pady=20, fill=tk.X)
        
        ttk.Button(buttons_frame, text="📊 Gerar Relatório", 
                  command=gerar_relatorio, bootstyle="success", width=20).pack(side=tk.LEFT, padx=(0, 10))
        ttk.Button(buttons_frame, text="Cancelar", 
                  command=lambda: period_win.destroy(), bootstyle="secondary").pack(side=tk.RIGHT)

        # Foco no primeiro campo
        entry_data_inicial.focus()
        
        # Permite Enter para gerar relatório
        period_win.bind('<Return>', lambda e: gerar_relatorio())
        period_win.bind('<Escape>', lambda e: period_win.destroy())

    def export_sales_csv(self):
        try:
            AUDITORIA.processo("Exportando vendas em CSV")
        except Exception:
            pass
        if not check_permission("relatorios.exportar_csv"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para exportar dados.")
            return
        import csv
        from tkinter import filedialog
        file_path = filedialog.asksaveasfilename(defaultextension=".csv",
                                                 filetypes=[("CSV files", "*.csv")],
                                                 title="Salvar Relatório de Vendas")
        if not file_path:
            return
        with open(file_path, 'w', newline='', encoding='utf-8') as csvfile:
            fieldnames = ['data', 'hora', 'cliente', 'total']
            writer = csv.DictWriter(csvfile, fieldnames=fieldnames)
            writer.writeheader()
            for venda in self.sales_log:
                writer.writerow({
                    'data': venda.get('data', ''),
                    'hora': venda.get('hora', ''),
                    'cliente': venda.get('cliente_nome', ''),
                    'total': venda.get('total', '')
                })
        messagebox.showinfo("Exportar CSV", f"Relatório exportado para:\n{file_path}")

    def show_reprint_window(self):
        """Janela para reimpressão de cupons de venda."""
        if not check_permission("vendas.reimprimir_cupom"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para reimprimir cupons.")
            return
        if not self.sales_log:
            messagebox.showinfo("Reimpressão", "Nenhuma venda registrada.")
            return

        reprint_win = tk.Toplevel(self.root)
        reprint_win._skip_auto_statusbar = True  # Mantém a tela no tamanho normal; não adiciona barra automática
        reprint_win.title("Reimpressão de Cupom")
        responsive_geometry(reprint_win, 800, 600)  # Tamanho normal ao invés de maximizado
        reprint_win.resizable(True, True)
        
        frame = ttk.Frame(reprint_win, padding=10)
        frame.pack(fill=tk.BOTH, expand=True)
        
        ttk.Label(frame, text="Selecione a venda para reimpressão:").pack(pady=5)
        
        cols = ('cupom', 'data', 'cliente', 'total', 'pagamento')
        tree = ttk.Treeview(frame, columns=cols, show='headings')
        tree.heading('cupom', text='Cupom')
        tree.heading('data', text='Data')
        tree.heading('cliente', text='Cliente')
        tree.heading('total', text='Total')
        tree.heading('pagamento', text='Pagamento')
        
        tree.column('cupom', width=80)
        tree.column('data', width=120)
        tree.column('cliente', width=200)
        tree.column('total', width=100)
        tree.column('pagamento', width=150)
        
        for venda in reversed(self.sales_log):
            # Extrair formas de pagamento para exibição
            formas = venda.get('formas_pagamento', {})
            pag_str = ", ".join([f"{k}" for k, v in formas.items() if v > 0]) if isinstance(formas, dict) else "N/A"
            
            tree.insert('', tk.END, values=(
                venda.get('coupon_number', 'N/A'),
                venda.get('data', 'N/A'),
                venda.get('cliente_nome', 'N/A'),
                format_br_currency(venda.get('total', 0.0)),
                pag_str
            ), iid=venda.get('coupon_number'))
            
        tree.pack(fill=tk.BOTH, expand=True)
        
        def process_reprint():
            selected = tree.selection()
            if not selected:
                messagebox.showwarning("Aviso", "Selecione uma venda.")
                return
            
            cupom_num = int(selected[0])
            venda_data = next((v for v in self.sales_log if v.get('coupon_number') == cupom_num), None)
            
            if venda_data:
                recibo = self.gerar_recibo(venda_data)
                
                view_win = tk.Toplevel(reprint_win)
                view_win._skip_auto_statusbar = True  # Mantém o preview do cupom no tamanho normal
                view_win.title(f"Visualizar Cupom {cupom_num}")
                responsive_geometry(view_win, 500, 700)  # Tamanho normal ao invés de maximizado
                view_win.resizable(True, True)
                
                txt = scrolledtext.ScrolledText(view_win, wrap=tk.WORD, font=("Consolas", 9))
                txt.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)
                txt.insert(tk.END, recibo)
                txt.config(state=tk.DISABLED)
                
                btn_frame = ttk.Frame(view_win)
                btn_frame.pack(pady=10)
                
                def _reimprimir_com_canhoto():
                    # CONDIÇÃO ENVIOS: Se a forma de pagamento for ENVIOS, NÃO imprime o cupom do cliente
                    # Imprime SOMENTE o canhoto da loja
                    _formas_pag = venda_data.get('formas_pagamento', {})
                    _eh_envios = float(_formas_pag.get('ENVIOS', 0)) > 0
                    
                    if not _eh_envios:
                        self.print_receipt_text(recibo)
                    # Imprime canhoto da loja automaticamente após o cupom (se habilitado nas configurações)
                    _imprimir_canhoto_cfg = self.config_data.get("imprimir_canhoto_loja", True)
                    if _imprimir_canhoto_cfg:
                        try:
                            canhoto_texto = self.gerar_canhoto_loja(venda_data)
                            self.print_receipt_text(canhoto_texto)
                        except Exception as e_canhoto:
                            logging.error(f"Erro ao imprimir canhoto da loja: {e_canhoto}")
                    # Imprime canhoto do entregador SOMENTE em vendas do tipo ENTREGA (não imprime se for ENVIOS)
                    if venda_data.get('is_delivery', False) and not _eh_envios:
                        try:
                            canhoto_entregador_texto = self.gerar_canhoto_entregador(venda_data)
                            self.print_receipt_text(canhoto_entregador_texto)
                        except Exception as e_canhoto_ent:
                            logging.error(f"Erro ao imprimir canhoto do entregador: {e_canhoto_ent}")
                
                btn_imprimir = ttk.Button(btn_frame, text="Imprimir (INSERT)", command=_reimprimir_com_canhoto, bootstyle="primary")
                btn_imprimir.pack(side=tk.LEFT, padx=5)
                view_win.bind("<Insert>", lambda e: _reimprimir_com_canhoto())
                view_win.bind("<Return>", lambda e: _reimprimir_com_canhoto())
                
                def enviar_whatsapp_reimpressao():
                    cliente_id = venda_data.get('cliente_id', '1')
                    cliente_data = self.customers.get(cliente_id, {})
                    cliente_tel = cliente_data.get('telefone', '')
                    
                    if not cliente_tel:
                        cliente_tel = simpledialog.askstring("WhatsApp", "Telefone do cliente (com DDD):")
                        if not cliente_tel: return
                    
                    self.send_whatsapp_message(cliente_tel, recibo)

                def salvar_pdf_reimpressao():
                    """Salva o cupom como PDF."""
                    gerar_pdf_recibo(
                        texto=recibo,
                        titulo=f"Cupom de Venda #{cupom_num:06d}",
                        nome_arquivo=f"Cupom_{cupom_num:06d}",
                        parent_window=view_win
                    )
                
                ttk.Button(btn_frame, text="Salvar PDF (F2)", command=salvar_pdf_reimpressao, bootstyle="info").pack(side=tk.LEFT, padx=5)
                ttk.Button(btn_frame, text="Enviar WhatsApp (HOME)", command=enviar_whatsapp_reimpressao, bootstyle="success").pack(side=tk.LEFT, padx=5)
                ttk.Button(btn_frame, text="Fechar", command=view_win.destroy, bootstyle="secondary").pack(side=tk.LEFT, padx=5)
                view_win.bind("<F2>", lambda e: salvar_pdf_reimpressao())
                view_win.bind("<Home>", lambda e: enviar_whatsapp_reimpressao())
                view_win.after(100, lambda: btn_imprimir.focus_set())

        ttk.Button(frame, text="Visualizar / Reimprimir", command=process_reprint, bootstyle="primary").pack(pady=10)

    def reabrir_venda(self, venda_data):
        """Carrega os itens de uma venda fechada de volta para o carrinho ativo."""
        if not venda_data or 'itens' not in venda_data:
            messagebox.showerror("Erro", "Dados da venda inválidos ou incompletos.")
            return

        # Verifica se o carrinho atual está vazio ou pede confirmação
        if self.carrinho:
            if not messagebox.askyesno("Confirmar", 
                "O carrinho atual não está vazio. Deseja limpá-lo e carregar os itens desta venda?",
                parent=self.root):
                return

        # Limpa o carrinho atual
        self.carrinho = {}
        
        # Carrega os itens
        itens_venda = venda_data.get('itens', {})
        for prod_id, dados in itens_venda.items():
            # Cria uma cópia profunda manual para evitar referências ao log
            self.carrinho[prod_id] = {
                'nome': dados.get('nome', 'Produto'),
                'preco': float(dados.get('preco', 0.0)),
                'quantidade_peso': float(dados.get('quantidade_peso', 1.0)),
                'subtotal': float(dados.get('subtotal', 0.0)),
                'unidade': dados.get('unidade', 'un'),
                'preco_atacado_aplicado': dados.get('preco_atacado_aplicado', False)
            }
        
        # Carrega o cliente
        self.selected_customer_id = str(venda_data.get('cliente_id', '1'))
        
        # Atualiza a interface
        self._atualizar_carrinho_e_total()
        self._update_customer_display()
        
        messagebox.showinfo("Sucesso", f"Venda nº {venda_data.get('coupon_number')} carregada no carrinho.")

    def show_devolucao_window(self):
        """Janela para devolução de vendas com opções de reembolso ou crédito.
        if not check_permission("vendas.devolucao"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para realizar devoluções.")
            return
        
        MÓDULO DE DEVOLUÇÃO DE VENDA - FUNCIONALIDADES:
        
        1. REEMBOLSO: Devolve o valor ao cliente em dinheiro
           - Produto volta para o estoque
           - Registra saída no caixa (débito)
           - Gera log de auditoria
        
        2. CRÉDITO: Gera crédito para o cliente usar em compras futuras
           - Produto volta para o estoque
           - Crédito fica disponível no cadastro do cliente
           - Cliente pode usar o crédito como forma de pagamento "Crédito Cliente"
           - Não registra saída no caixa (valor fica como crédito)
        """
        if not self.sales_log:
            messagebox.showinfo("Devolução", "Nenhuma venda registrada.")
            return

        devolucao_win = tk.Toplevel(self.root)
        devolucao_win.title("🔄 Devolução de Venda")
        devolucao_win.transient(self.root)
        devolucao_win.grab_set()
        
        # Maximizar a janela e mantê-la maximizada
        devolucao_win.state('zoomed')  # Maximiza no Windows
        
        # Função para manter a janela maximizada
        def manter_maximizado(event=None):
            if devolucao_win.state() != 'zoomed':
                devolucao_win.state('zoomed')
        
        # Bind para detectar tentativa de restaurar a janela
        devolucao_win.bind('<Configure>', manter_maximizado)
        
        # ===== CONTAINER COM SCROLL =====
        # Frame container principal
        container = ttk.Frame(devolucao_win)
        container.pack(fill=tk.BOTH, expand=True)
        
        # Canvas para permitir rolagem
        canvas = tk.Canvas(container, highlightthickness=0)
        canvas.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        
        # Scrollbar vertical
        scrollbar = ttk.Scrollbar(container, orient=tk.VERTICAL, command=canvas.yview)
        scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
        
        # Configurar canvas para usar scrollbar
        canvas.configure(yscrollcommand=scrollbar.set)
        
        # Frame interno que conterá todo o conteúdo
        main_frame = ttk.Frame(canvas, padding=10)
        
        # Criar janela no canvas para o frame
        canvas_window = canvas.create_window((0, 0), window=main_frame, anchor='nw')
        
        # Função para atualizar a região de scroll quando o conteúdo mudar
        def configurar_scroll(event=None):
            canvas.configure(scrollregion=canvas.bbox('all'))
            # Ajustar largura do frame interno para preencher o canvas
            canvas.itemconfig(canvas_window, width=canvas.winfo_width())
        
