        # FUNÇÃO DE EDITAR CRÉDITO
        # ═══════════════════════════════════════════════════════════════════
        def editar_credito():
            """Edita o valor de um crédito selecionado no histórico de movimentações."""
            # Verificar qual aba está ativa
            aba_atual = notebook.index(notebook.select())
            
            if aba_atual == 0:
                # Aba Saldo por Cliente - editar saldo direto do cliente
                selected = tree_saldo.selection()
                if not selected:
                    messagebox.showwarning("Aviso", "Selecione um cliente na aba 'Saldo por Cliente' para editar!", parent=cred_win)
                    return
                
                item = tree_saldo.item(selected[0])
                values = item['values']
                cliente_id = str(values[0])
                cliente_nome = values[1]
                saldo_atual_str = values[3]
                saldo_atual = parse_br_float(saldo_atual_str) or 0.0
                
                # Janela de edição
                edit_win = tk.Toplevel(cred_win)
                edit_win.title("✏️ Editar Saldo de Crédito")
                edit_win.transient(cred_win)
                edit_win.grab_set()
                responsive_geometry(edit_win, 480, 350)
                edit_win.resizable(True, True)
                
                edit_win.update_idletasks()
                x = (edit_win.winfo_screenwidth() // 2) - 240
                y = (edit_win.winfo_screenheight() // 2) - 175
                responsive_geometry(edit_win, 480, 350)
                
                frame_edit = ttk.Frame(edit_win, padding=20)
                frame_edit.pack(fill=tk.BOTH, expand=True)
                
                ttk.Label(frame_edit, text="✏️ EDITAR SALDO DE CRÉDITO",
                         font=("Segoe UI", 14, "bold")).pack(pady=(0, 10))
                
                # Info do cliente
                info_frame = tk.LabelFrame(frame_edit, text="Dados do Cliente", padx=10, pady=5)
                info_frame.pack(fill=tk.X, pady=(0, 10))
                
                ttk.Label(info_frame, text=f"ID: {cliente_id} | Nome: {cliente_nome}",
                         font=("Segoe UI", 9)).pack(anchor='w')
                ttk.Label(info_frame, text=f"Saldo Atual: {format_br_currency(saldo_atual)}",
                         font=("Segoe UI", 9, "bold")).pack(anchor='w')
                
                # Novo valor
                ttk.Label(frame_edit, text="Novo valor do saldo de crédito:",
                         font=("Segoe UI", 10)).pack(anchor='w', pady=(5, 2))
                novo_valor_var = tk.StringVar(value=f"{saldo_atual:.2f}".replace('.', ','))
