    def _gerar_codigo_voucher(self):
        """Gera um código alfanumérico único de 6 caracteres (letras maiúsculas + números)."""
        import random
        import string
        db = get_db()
        caracteres = string.ascii_uppercase + string.digits
        
        for _ in range(100):  # Máximo 100 tentativas
            codigo = ''.join(random.choices(caracteres, k=6))
            # Verificar se já existe
            existente = db.fetchone("SELECT id FROM vouchers WHERE codigo = %s", (codigo,))
            if not existente:
                return codigo
        
        # Fallback com timestamp
        import time
        return f"V{int(time.time()) % 100000:05d}"

