    def show_politica_troca_window(self, parent=None):
        """Exibe a janela de consulta da Política de Troca da empresa.
        if not check_permission("politica_troca.acessar"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para acessar a política de troca.")
            return
        
        Permite visualizar, editar (se tiver permissão) e imprimir a política
        de troca configurada nos dados da empresa.
        """
        politica_win = tk.Toplevel(parent or self.root)
        politica_win.title("\U0001f4dc Política de Troca")
        politica_win.transient(parent or self.root)
        politica_win.grab_set()
        politica_win.state('zoomed')
        
        # Container principal
        main_frame = ttk.Frame(politica_win, padding=20)
        main_frame.pack(fill=tk.BOTH, expand=True)
        
        # Cabeçalho
        header_frame = ttk.Frame(main_frame)
        header_frame.pack(fill=tk.X, pady=(0, 15))
        
        store_name = self.empresa_data.get('nome', 'Sua Empresa Aqui')
        ttk.Label(header_frame, text=f"\U0001f4dc POL\u00cdTICA DE TROCA", 
                  font=("Segoe UI", 18, "bold")).pack(side=tk.LEFT)
        ttk.Label(header_frame, text=f"  |  {store_name}", 
                  font=("Segoe UI", 14), foreground="gray").pack(side=tk.LEFT, padx=(10, 0))
        
        # Separador
        ttk.Separator(main_frame, orient=tk.HORIZONTAL).pack(fill=tk.X, pady=(0, 15))
        
        # Informações da empresa
        info_frame = tk.LabelFrame(main_frame, text="Dados da Empresa", padx=15, pady=10)
        info_frame.pack(fill=tk.X, pady=(0, 15))
        
        cnpj = self.empresa_data.get('cnpj', '')
        endereco = self.empresa_data.get('endereco', '')
        telefone = self.empresa_data.get('telefone', '')
        email = self.empresa_data.get('email', '')
        
        info_text = f"Empresa: {store_name}"
        if cnpj:
            info_text += f"   |   CNPJ: {cnpj}"
        if telefone:
            info_text += f"   |   Tel: {telefone}"
        if endereco:
            info_text += f"\nEndere\u00e7o: {endereco}"
        cidade = self.empresa_data.get('cidade', '')
        estado = self.empresa_data.get('estado', '')
        if cidade or estado:
            info_text += f" - {cidade}"
            if estado:
                info_text += f"/{estado}"
        
        ttk.Label(info_frame, text=info_text, font=("Segoe UI", 10), wraplength=800, justify=tk.LEFT).pack(anchor=tk.W)
        
        # Conteúdo da política
        politica_frame = tk.LabelFrame(main_frame, text="Pol\u00edtica de Troca e Devolu\u00e7\u00e3o", padx=15, pady=15)
        politica_frame.pack(fill=tk.BOTH, expand=True, pady=(0, 15))
        
        politica_texto = self.empresa_data.get('politica_troca', '')
        
        if not politica_texto:
            politica_texto = ("Nenhuma pol\u00edtica de troca configurada.\n\n"
                             "Para configurar, acesse:\n"
                             "Menu Sistema > Dados da Empresa > Pol\u00edtica de Troca\n\n"
                             "Ou clique no bot\u00e3o 'Editar Pol\u00edtica' abaixo.")
        
        # Campo de texto somente leitura para exibir a política
        politica_display = tk.Text(politica_frame, wrap=tk.WORD, font=("Segoe UI", 12), 
                                   padx=15, pady=15, relief=tk.FLAT, bg="#f8f9fa",
                                   height=12)
        politica_display.pack(fill=tk.BOTH, expand=True)
        politica_display.insert('1.0', politica_texto)
        politica_display.config(state=tk.DISABLED)
        
        # Data de atualização
        ttk.Label(politica_frame, 
                  text=f"\u00daltima atualiza\u00e7\u00e3o: {datetime.datetime.now().strftime('%d/%m/%Y')}",
                  font=("Segoe UI", 9), foreground="gray").pack(anchor=tk.E, pady=(5, 0))
        
        # Botões de ação
        btn_frame = ttk.Frame(main_frame)
        btn_frame.pack(fill=tk.X, pady=(0, 5))
        
        # Botão Imprimir
        def imprimir_politica():
            """Gera e imprime a política de troca."""
            politica = self.empresa_data.get('politica_troca', '')
            if not politica:
                messagebox.showwarning("Aviso", "Nenhuma pol\u00edtica de troca configurada para imprimir.", parent=politica_win)
                return
            
            # Gera o texto formatado para impressão
            texto_impressao = "=" * 48 + "\n"
            texto_impressao += store_name.center(48) + "\n"
            if cnpj:
                texto_impressao += f"CNPJ: {cnpj}".center(48) + "\n"
            texto_impressao += "=" * 48 + "\n"
            texto_impressao += "POLITICA DE TROCA E DEVOLUCAO".center(48) + "\n"
            texto_impressao += "-" * 48 + "\n"
            
            # Word wrap em 48 colunas
            palavras = politica.split()
            linha = ""
            for palavra in palavras:
                if linha and len(linha) + 1 + len(palavra) > 48:
                    texto_impressao += linha + "\n"
                    linha = palavra
                elif not linha:
                    linha = palavra
                else:
                    linha += " " + palavra
            if linha:
                texto_impressao += linha + "\n"
            
            texto_impressao += "-" * 48 + "\n"
            texto_impressao += f"Data: {datetime.datetime.now().strftime('%d/%m/%Y %H:%M')}\n"
            texto_impressao += "=" * 48 + "\n"
            
            # Tenta imprimir na térmica
            try:
                self.print_receipt_text(texto_impressao)
                messagebox.showinfo("Impress\u00e3o", "Pol\u00edtica de troca enviada para a impressora.", parent=politica_win)
            except Exception as e:
                # Fallback: exibe em janela para impressão manual
                ReportWindow(politica_win, "Pol\u00edtica de Troca", texto_impressao, self)
            
            log_user_action("Pol\u00edtica de Troca", "Pol\u00edtica de troca impressa")
        
        # Botão Editar
        def editar_politica():
            """Abre janela para editar a política de troca."""
            if not check_permission("politica_troca.editar"):
                messagebox.showerror("Acesso Negado", "Voc\u00ea n\u00e3o tem permiss\u00e3o para editar a pol\u00edtica de troca.", parent=politica_win)
                return
            
            edit_win = tk.Toplevel(politica_win)
            edit_win.title("\u270f\ufe0f Editar Pol\u00edtica de Troca")
            edit_win.transient(politica_win)
            edit_win.grab_set()
            responsive_geometry(edit_win, 700, 500)
            
            edit_frame = ttk.Frame(edit_win, padding=15)
            edit_frame.pack(fill=tk.BOTH, expand=True)
            
            ttk.Label(edit_frame, text="\u270f\ufe0f Editar Pol\u00edtica de Troca", 
                      font=("Segoe UI", 14, "bold")).pack(pady=(0, 10))
            
            ttk.Label(edit_frame, text="Digite abaixo a pol\u00edtica de troca da sua empresa:",
                      font=("Segoe UI", 10)).pack(anchor=tk.W, pady=(0, 5))
            
            # Campo de edição
            text_frame = ttk.Frame(edit_frame)
            text_frame.pack(fill=tk.BOTH, expand=True, pady=(0, 10))
            
            edit_text = tk.Text(text_frame, wrap=tk.WORD, font=("Segoe UI", 11), 
                               padx=10, pady=10)
            edit_text.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
            
            edit_scroll = ttk.Scrollbar(text_frame, orient=tk.VERTICAL, command=edit_text.yview)
            edit_scroll.pack(side=tk.RIGHT, fill=tk.Y)
            edit_text.configure(yscrollcommand=edit_scroll.set)
            
            # Carrega texto atual
            politica_atual = self.empresa_data.get('politica_troca', '')
            if politica_atual:
                edit_text.insert('1.0', politica_atual)
            
            # Sugestões de texto
            sugestoes_frame = ttk.Frame(edit_frame)
            sugestoes_frame.pack(fill=tk.X, pady=(0, 10))
            
            ttk.Label(sugestoes_frame, text="Modelos r\u00e1pidos:", font=("Segoe UI", 9, "bold")).pack(side=tk.LEFT, padx=(0, 10))
            
            modelos = {
                "7 dias": "Trocas em at\u00e9 7 dias corridos ap\u00f3s a compra, mediante apresenta\u00e7\u00e3o do cupom não fiscal. O produto deve estar sem uso, com etiqueta e embalagem original. Produtos em promo\u00e7\u00e3o ou liquida\u00e7\u00e3o n\u00e3o s\u00e3o pass\u00edveis de troca. A troca est\u00e1 sujeita \u00e0 an\u00e1lise da equipe.",
                "15 dias": "Trocas em at\u00e9 15 dias corridos ap\u00f3s a compra, mediante apresenta\u00e7\u00e3o do cupom não fiscal. O produto deve estar sem uso, com etiqueta e embalagem original. Produtos em promo\u00e7\u00e3o possuem prazo reduzido de 7 dias para troca. A troca est\u00e1 sujeita \u00e0 an\u00e1lise.",
                "30 dias": "Trocas em at\u00e9 30 dias corridos ap\u00f3s a compra, mediante apresenta\u00e7\u00e3o do cupom não fiscal. O produto deve estar em perfeitas condi\u00e7\u00f5es, sem uso, com etiqueta e embalagem original. Produtos de uso pessoal, \u00edntimos ou aliment\u00edcios n\u00e3o s\u00e3o pass\u00edveis de troca. A troca est\u00e1 sujeita \u00e0 an\u00e1lise da equipe.",
                "Sem troca": "Esta empresa N\u00c3O realiza trocas ou devolu\u00e7\u00f5es. Todos os produtos s\u00e3o vendidos no estado em que se encontram. Verifique o produto antes de finalizar a compra."
            }
            
            def aplicar_modelo(texto_modelo):
                edit_text.delete('1.0', tk.END)
                edit_text.insert('1.0', texto_modelo)
            
            for nome_modelo, texto_modelo in modelos.items():
                ttk.Button(sugestoes_frame, text=nome_modelo, 
                          command=lambda t=texto_modelo: aplicar_modelo(t),
                          bootstyle="info-outline", width=10).pack(side=tk.LEFT, padx=2)
            
            # Botões
            edit_btn_frame = ttk.Frame(edit_frame)
            edit_btn_frame.pack(fill=tk.X)
            
            def salvar_politica():
                nova_politica = edit_text.get('1.0', tk.END).strip()
                self.empresa_data['politica_troca'] = nova_politica
                if save_data(EMPRESA_FILE, self.empresa_data):
                    # Atualiza o display na janela principal
                    politica_display.config(state=tk.NORMAL)
                    politica_display.delete('1.0', tk.END)
                    if nova_politica:
                        politica_display.insert('1.0', nova_politica)
                    else:
                        politica_display.insert('1.0', "Nenhuma pol\u00edtica de troca configurada.")
                    politica_display.config(state=tk.DISABLED)
                    
                    log_user_action("Pol\u00edtica de Troca", f"Pol\u00edtica de troca atualizada: {nova_politica[:100]}...")
                    messagebox.showinfo("Sucesso", "Pol\u00edtica de troca salva com sucesso!", parent=edit_win)
                    edit_win.destroy()
                else:
                    messagebox.showerror("Erro", "Falha ao salvar a pol\u00edtica de troca.", parent=edit_win)
            
            ttk.Button(edit_btn_frame, text="\u2705 Salvar Pol\u00edtica", command=salvar_politica,
                      bootstyle="success", width=20).pack(side=tk.LEFT, padx=5)
            ttk.Button(edit_btn_frame, text="\u274c Cancelar", command=edit_win.destroy,
                      bootstyle="secondary", width=15).pack(side=tk.RIGHT, padx=5)
            
            edit_text.focus_set()
        
        # Botões da janela principal
        if check_permission("politica_troca.imprimir"):
            ttk.Button(btn_frame, text="\U0001f5a8\ufe0f Imprimir Pol\u00edtica", command=imprimir_politica,
                      bootstyle="info", width=20).pack(side=tk.LEFT, padx=5)
        
        if check_permission("politica_troca.editar"):
            ttk.Button(btn_frame, text="\u270f\ufe0f Editar Pol\u00edtica", command=editar_politica,
                      bootstyle="warning", width=20).pack(side=tk.LEFT, padx=5)
        
        ttk.Button(btn_frame, text="\u274c Fechar", command=politica_win.destroy,
                  bootstyle="secondary", width=15).pack(side=tk.RIGHT, padx=5)

    def print_receipt_text(self, text, impressora_key: str = None):
        """
        Imprime texto usando impressora termica se disponivel,
        caso contrario usa metodo de fallback via driver do sistema.
        
        CORREÇÃO: Agora respeita o sistema de múltiplas impressoras.
        Quando o sistema de múltiplas impressoras está habilitado:
        - Se impressora_key for especificada, usa essa impressora específica
        - Se impressora_key for None, usa a impressora padrão do multi_printer_manager
          (que faz fallback para thermal_printer_manager)
        
        Args:
            text: Texto a ser impresso
            impressora_key: Chave da impressora específica (impressora_1, impressora_2, etc.)
                           Se None, usa a impressora padrão
        """
        try:
            # CORREÇÃO: Verifica primeiro se o sistema de múltiplas impressoras está habilitado
            if hasattr(self, 'multi_printer_manager') and self.multi_printer_manager and self.multi_printer_manager.is_enabled():
                # Se especificou uma impressora específica, usa ela
                if impressora_key:
                    printer = self.multi_printer_manager.get_printer_by_key(impressora_key)
                    if printer and printer.is_enabled():
                        if printer.print_text(text):
                            return
                else:
                    # Sem impressora específica: usa o método print_text do multi_printer_manager
                    # que faz fallback para a impressora padrão (default_printer_manager)
                    if self.multi_printer_manager.print_text(text):
                        return
            
            # Tenta usar impressora termica configurada (padrão) - fallback quando
            # o sistema de múltiplas impressoras não está habilitado ou falhou
            if hasattr(self, 'thermal_printer_manager') and self.thermal_printer_manager:
                if self.thermal_printer_manager.is_enabled():
                    if self.thermal_printer_manager.print_text(text):
                        return
            
            # Fallback: impressao via sistema
            import tempfile, os, platform
            with tempfile.NamedTemporaryFile('w', delete=False, suffix=".txt", encoding='utf-8') as f:
                f.write(text)
                caminho_temp = f.name
            if platform.system() == "Windows":
                os.startfile(caminho_temp, "print")
            else:
                import subprocess
                subprocess.run(["lp", caminho_temp], check=False)
        except Exception as e:
            messagebox.showerror("Erro ao imprimir", f"Erro: {e}")
    
    def print_items_by_category(self, items: list, header_text: str = "", footer_text: str = "") -> dict:
        """
        Imprime itens separados por categoria/impressora usando o sistema de múltiplas impressoras.
        
        Args:
            items: Lista de itens para imprimir
            header_text: Texto do cabeçalho
            footer_text: Texto do rodapé
            
        Returns:
            Dicionário com resultado por impressora
        """
        if hasattr(self, 'multi_printer_manager') and self.multi_printer_manager and self.multi_printer_manager.is_enabled():
            return self.multi_printer_manager.print_items_by_category(
                items=items,
                products_dict=self.products,
                header_text=header_text,
                footer_text=footer_text
            )
        else:
            # Fallback: imprime tudo na impressora padrão
            linhas = []
            if header_text:
                linhas.append(header_text)
                linhas.append("-" * 48)
            
            for item in items:
                qtd = item.get('quantidade', item.get('qtd', 1))
                nome = item.get('nome', 'Item')
                linhas.append(f"{qtd:<6} {nome}")
                obs = item.get('observacao', '')
                if obs:
                    linhas.append(f"       -> OBS: {obs}")
            
            linhas.append("-" * 48)
            if footer_text:
                linhas.append(footer_text)
            linhas.append("\n\n\n\n")
            
            texto = "\n".join(linhas)
            self.print_receipt_text(texto)
            return {'padrao': True}

    def show_finance_reprint_window(self):
        """Janela para reimpressão de recibos financeiros."""
        if not check_permission("relatorios.reimprimir_recibo_financeiro"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para reimprimir recibos financeiros.")
            return
        reprint_win = tk.Toplevel(self.root)
        reprint_win.title("Reimpressão de Recibo Financeiro")
        responsive_geometry(reprint_win, 800, 600)  # Tamanho normal ao invés de maximizado
        reprint_win.resizable(True, True)
        
        tab_control = ttk.Notebook(reprint_win)
        
        # Aba Contas a Receber
        tab_cr = ttk.Frame(tab_control)
        tab_control.add(tab_cr, text="Contas a Receber")
        
        cols = ('id', 'data', 'cliente', 'valor', 'descricao')
        tree_cr = ttk.Treeview(tab_cr, columns=cols, show='headings')
        for col in cols: tree_cr.heading(col, text=col.upper())
        
        contas_cr = load_contas_a_receber()
        for cid, cdata in contas_cr.items():
            if cdata.get('status') == 'Recebido':
                tree_cr.insert('', tk.END, values=(cid, cdata.get('data_recebimento'), self.customers.get(cdata.get('cliente_id'), {}).get('nome', 'N/A'), cdata.get('valor'), cdata.get('descricao')))
        tree_cr.pack(fill=tk.BOTH, expand=True)
        
        # Aba Contas a Pagar
        tab_cp = ttk.Frame(tab_control)
        tab_control.add(tab_cp, text="Contas a Pagar")
        
        tree_cp = ttk.Treeview(tab_cp, columns=cols, show='headings')
        for col in cols: tree_cp.heading(col, text=col.upper())
        
        contas_cp = load_contas_a_pagar()
        for cid, cdata in contas_cp.items():
            if cdata.get('status') == 'Pago':
                tree_cp.insert('', tk.END, values=(cid, cdata.get('data_pagamento'), self.suppliers.get(cdata.get('fornecedor_id'), {}).get('nome', 'N/A'), cdata.get('valor'), cdata.get('descricao')))
        tree_cp.pack(fill=tk.BOTH, expand=True)
        
        tab_control.pack(expand=1, fill="both")
        
        def process_finance_reprint():
            current_tab = tab_control.index(tab_control.select())
            tree = tree_cr if current_tab == 0 else tree_cp
            selected = tree.selection()
            if not selected:
                messagebox.showwarning("Aviso", "Selecione um registro.")
                return
            
            item_id = selected[0]
            item_values = tree.item(item_id, 'values')
            
            recibo = f"*RECIBO FINANCEIRO*\n\nID: {item_values[0]}\nData: {item_values[1]}\nNome: {item_values[2]}\nValor: {item_values[3]}\nDescrição: {item_values[4]}\n\nGerado em: {datetime.datetime.now().strftime('%d/%m/%Y %H:%M')}"
            
            view_win = tk.Toplevel(reprint_win)
            view_win.title("Visualizar Recibo")
            responsive_geometry(view_win, 500, 600)  # Tamanho normal ao invés de maximizado
            view_win.resizable(True, True)
            
            txt = scrolledtext.ScrolledText(view_win, wrap=tk.WORD, font=("Consolas", 10))
            txt.pack(fill=tk.BOTH, expand=True, padx=10, pady=10)
            txt.insert(tk.END, recibo)
            txt.config(state=tk.DISABLED)
            
            btn_frame = ttk.Frame(view_win)
            btn_frame.pack(pady=10)
            
            btn_imprimir = ttk.Button(btn_frame, text="Imprimir (INSERT)", command=lambda: self.print_receipt_text(recibo), bootstyle="primary")
            btn_imprimir.pack(side=tk.LEFT, padx=5)
            view_win.bind("<Insert>", lambda e: self.print_receipt_text(recibo))
            view_win.bind("<Return>", lambda e: self.print_receipt_text(recibo))
        
            
            def enviar_whatsapp_financeiro():
                tel = simpledialog.askstring("WhatsApp", "Telefone do contato (com DDD):")
                if not tel: return
                self.send_whatsapp_message(tel, recibo)

            def salvar_pdf_financeiro():
                """Salva o recibo financeiro como PDF."""
                gerar_pdf_recibo(
                    texto=recibo,
                    titulo="Recibo Financeiro",
                    nome_arquivo=f"Recibo_Financeiro_{item_values[0]}",
                    parent_window=view_win
                )
            
            ttk.Button(btn_frame, text="Salvar PDF (F2)", command=salvar_pdf_financeiro, bootstyle="info").pack(side=tk.LEFT, padx=5)
            ttk.Button(btn_frame, text="Enviar WhatsApp (HOME)", command=enviar_whatsapp_financeiro, bootstyle="success").pack(side=tk.LEFT, padx=5)
            ttk.Button(btn_frame, text="Fechar", command=view_win.destroy, bootstyle="secondary").pack(side=tk.LEFT, padx=5)
            view_win.bind("<F2>", lambda e: salvar_pdf_financeiro())
            view_win.bind("<Home>", lambda e: enviar_whatsapp_financeiro())
            view_win.after(100, lambda: btn_imprimir.focus_set())

        ttk.Button(reprint_win, text="Visualizar / Reimprimir Selecionado", command=process_finance_reprint, bootstyle="primary").pack(pady=10)
    def iniciar_pagamento(self):
        """Tela de pagamento simples com Tkinter puro"""
        try:
            AUDITORIA.venda("Iniciando pagamento")
        except Exception:
            pass
        if not is_caixa_aberto():
            messagebox.showwarning("Caixa Fechado", "Abra o caixa primeiro!")
            return
            
        if not check_permission("vendas.acessar"):
            messagebox.showerror("Acesso Negado", "Sem permissão!")
            return
            
        if not self.carrinho:
            messagebox.showwarning("Carrinho Vazio", "Adicione itens!")
            return

        # ===== JANELA PRINCIPAL =====
        pagamento_win = tk.Toplevel(self.root)
        pagamento_win.title("Finalizar Pagamento")
        
        # Remove os botões minimizar, maximizar e fechar da barra de título
        pagamento_win.overrideredirect(True)
        
        # Posiciona a janela na area util da tela (acima da barra de tarefas)
        try:
            _wa_x, _wa_y, _wa_w, _wa_h = get_responsive_work_area(pagamento_win)
            pagamento_win.geometry(f"{_wa_w}x{_wa_h}+{_wa_x}+{_wa_y}")
        except Exception:
            pagamento_win.state("zoomed")  # Fallback
        pagamento_win.resizable(True, True)
        pagamento_win.configure(bg='white')
        
        # ===== PROTEÇÃO CONTRA SEGUNDO PLANO =====
        # Mantém a janela sempre no topo de todas as outras
        pagamento_win.attributes('-topmost', True)
        pagamento_win._skip_auto_statusbar = True  # Ja tem layout proprio
        
        # ===== BARRA DE STATUS DA TELA DE PAGAMENTO =====
        try:
            _pag_status_frame = tk.Frame(pagamento_win, bg='#e0e0e0', height=30)
            _pag_status_frame.pack(side=tk.BOTTOM, fill=tk.X)
            _pag_status_frame.pack_propagate(False)
            _pag_user = logged_user if logged_user else 'Usuario'
            tk.Label(_pag_status_frame, text=f"  Usuario: {_pag_user}", bg='#e0e0e0', fg='#333',
                     font=('Segoe UI', 9), anchor=tk.W).pack(side=tk.LEFT, padx=5)
            ttk.Separator(_pag_status_frame, orient=tk.VERTICAL).pack(side=tk.LEFT, fill=tk.Y, padx=5)
            import datetime as _dt_pag
            _pag_dt_label = tk.Label(_pag_status_frame, text="", bg='#e0e0e0', fg='#333',
                                      font=('Segoe UI', 9))
            _pag_dt_label.pack(side=tk.LEFT, padx=5)
            def _atualizar_dt_pag():
                try:
                    if pagamento_win.winfo_exists():
                        _pag_dt_label.config(text=_dt_pag.datetime.now().strftime("%d/%m/%Y %H:%M:%S"))
                        pagamento_win.after(1000, _atualizar_dt_pag)
                except Exception:
                    pass
            _atualizar_dt_pag()
            tk.Label(_pag_status_frame, text="v12.0", bg='#e0e0e0', fg='#999',
                     font=('Segoe UI', 8)).pack(side=tk.RIGHT, padx=10)
        except Exception:
            pass
        
        # Lista para rastrear janelas filhas abertas (exceções)
        janelas_filhas_ativas = []
        
        # Função para registrar janela filha (permite que fique à frente)
        def registrar_janela_filha(janela_filha):
            """Registra uma janela filha como exceção à proteção de segundo plano."""
            janelas_filhas_ativas.append(janela_filha)
            # Configura a janela filha para ficar no topo também
            janela_filha.attributes('-topmost', True)
            janela_filha.transient(pagamento_win)
            janela_filha.grab_set()
            
            # Quando a janela filha fechar, remove da lista e restaura o grab
            def ao_fechar_filha():
                try:
                    if janela_filha in janelas_filhas_ativas:
                        janelas_filhas_ativas.remove(janela_filha)
                    janela_filha.grab_release()
                    janela_filha.destroy()
                    # Restaura o grab para a janela de pagamento
                    if pagamento_win.winfo_exists() and not janelas_filhas_ativas:
                        pagamento_win.grab_set()
                        pagamento_win.focus_force()
                except:
                    pass
            
            janela_filha.protocol("WM_DELETE_WINDOW", ao_fechar_filha)
            return ao_fechar_filha
        
        # Função para verificar se há janela filha ativa
        def tem_janela_filha_ativa():
            """Verifica se existe alguma janela filha ativa."""
            # Remove janelas que já foram fechadas
            janelas_filhas_ativas[:] = [j for j in janelas_filhas_ativas if j.winfo_exists()]
            return len(janelas_filhas_ativas) > 0
        
        # Função para garantir que a janela mantenha o foco (com exceção para janelas filhas)
        def manter_foco(event=None):
            """Garante que a janela de pagamento mantenha o foco, exceto quando há janela filha."""
            try:
                # Só força o foco se não houver janela filha ativa
                if not tem_janela_filha_ativa():
                    pagamento_win.focus_force()
                    pagamento_win.lift()
            except:
                pass
        
        # Vincula eventos para manter o foco
        pagamento_win.bind('<FocusOut>', manter_foco)
        pagamento_win.bind('<Visibility>', manter_foco)
        
        # Verifica periodicamente se a janela ainda está no topo (com exceção para janelas filhas)
        def verificar_topo():
            """Verifica periodicamente se a janela está no topo e restaura se necessário."""
            try:
                if pagamento_win.winfo_exists():
                    # Só força o topo se não houver janela filha ativa
                    if not tem_janela_filha_ativa():
                        pagamento_win.attributes('-topmost', True)
                        pagamento_win.lift()
                    pagamento_win.after(500, verificar_topo)  # Verifica a cada 500ms
            except:
                pass
        
        # Inicia a verificação periódica
        pagamento_win.after(500, verificar_topo)
        
        # Captura todos os eventos de entrada (mouse e teclado) para esta janela
        pagamento_win.grab_set()
        
        # Maximizar janela
        pagamento_win.update_idletasks()
        
        # Força o foco inicial na janela
        pagamento_win.focus_force()
        
        # ===== FRAME PRINCIPAL COM SCROLL VERTICAL =====
        _scroll_outer = tk.Frame(pagamento_win, bg='white')
        _scroll_outer.pack(fill=tk.BOTH, expand=True)
        
        _main_canvas = tk.Canvas(_scroll_outer, bg='white', highlightthickness=0)
        _main_scrollbar = tk.Scrollbar(_scroll_outer, orient=tk.VERTICAL, command=_main_canvas.yview)
        _main_canvas.configure(yscrollcommand=_main_scrollbar.set)
        
        _main_scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
        _main_canvas.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        
        main_frame = tk.Frame(_main_canvas, bg='white')
        _main_canvas_window = _main_canvas.create_window((0, 0), window=main_frame, anchor='nw', tags='main_frame_win')
        
        # Atualiza scrollregion quando o conteudo muda
        def _on_main_frame_configure(event):
            _main_canvas.configure(scrollregion=_main_canvas.bbox('all'))
        main_frame.bind('<Configure>', _on_main_frame_configure)
        
        # Faz o frame interno acompanhar a largura do canvas
        def _on_main_canvas_configure(event):
            _main_canvas.itemconfig('main_frame_win', width=event.width)
        _main_canvas.bind('<Configure>', _on_main_canvas_configure)
        
        # Scroll com roda do mouse em toda a tela
        def _on_main_mousewheel(event):
            try:
                _main_canvas.yview_scroll(int(-1 * (event.delta / 120)), 'units')
            except Exception:
                pass
        
        def _bind_main_mousewheel(event):
            _main_canvas.bind_all('<MouseWheel>', _on_main_mousewheel)
        
        def _unbind_main_mousewheel(event):
            _main_canvas.unbind_all('<MouseWheel>')
        
        _main_canvas.bind('<Enter>', _bind_main_mousewheel)
        _main_canvas.bind('<Leave>', _unbind_main_mousewheel)
        
        # Bind mousewheel tambem no main_frame para Linux (Button-4/5)
        def _on_main_mousewheel_linux(event):
            try:
                if event.num == 4:
                    _main_canvas.yview_scroll(-3, 'units')
                elif event.num == 5:
                    _main_canvas.yview_scroll(3, 'units')
            except Exception:
                pass
        _main_canvas.bind_all('<Button-4>', _on_main_mousewheel_linux)
        _main_canvas.bind_all('<Button-5>', _on_main_mousewheel_linux)
        
        # ===== VISIBILIDADE CONFIGURÁVEL DO TOPO DO PAGAMENTO =====
        mostrar_total_pagamento = cfg_bool(self.config_data.get("pagamento_mostrar_total_venda", True), True)
        mostrar_cliente_pagamento = cfg_bool(self.config_data.get("pagamento_mostrar_cliente", True), True)
        mostrar_entrega_pagamento = cfg_bool(self.config_data.get("pagamento_mostrar_entrega", True), True)
        mostrar_vendedor_pagamento = cfg_bool(self.config_data.get("pagamento_mostrar_vendedor", True), True)
        mostrar_garcom_taxa_pagamento = cfg_bool(self.config_data.get("pagamento_mostrar_garcom_taxa", True), True)

        # ===== CABEÇALHO =====
        header = tk.Frame(main_frame, bg='#0066cc')
        if mostrar_total_pagamento or mostrar_cliente_pagamento or mostrar_entrega_pagamento:
            header.pack(fill=tk.X, padx=0, pady=0)
        
        lbl_total_titulo = tk.Label(header, text="TOTAL DA VENDA", bg='#0066cc', fg='white', font=("Arial", 14, "bold"))
        if mostrar_total_pagamento:
            lbl_total_titulo.pack(pady=(8, 0))
        
        total_label = tk.Label(header, text=format_br_currency(self.total_venda), bg='#0066cc', fg='white', font=("Arial", 36, "bold"))
        if mostrar_total_pagamento:
            total_label.pack(pady=5)
        
        cliente_nome = self.customers.get(self.selected_customer_id, {}).get('nome', 'Consumidor Final')
        
        # Frame para cliente com botão de alterar
        cliente_header_frame = tk.Frame(header, bg='#0066cc')
        if mostrar_cliente_pagamento:
            cliente_header_frame.pack(pady=(0, 5))
        
        lbl_cliente = tk.Label(cliente_header_frame, text=f"Cliente: {cliente_nome}", bg='#0066cc', fg='white', font=("Arial", 11))
        lbl_cliente.pack(side=tk.LEFT, padx=5)
        
        def mudar_cliente():
            """Abre janela para selecionar outro cliente."""
            select_win = tk.Toplevel(pagamento_win)
            select_win.title("Selecionar Cliente")
            responsive_geometry(select_win, 500, 400)
            select_win.configure(bg='white')
            
            # Registra como janela filha (permite ficar à frente da tela de pagamento)
            fechar_janela_filha = registrar_janela_filha(select_win)
            
            # Centralizar janela
            select_win.update_idletasks()
            x = (select_win.winfo_screenwidth() // 2) - (500 // 2)
            y = (select_win.winfo_screenheight() // 2) - (400 // 2)
            responsive_geometry(select_win, 500, 400)
            
            tk.Label(select_win, text="Selecionar Cliente", font=("Arial", 14, "bold"), bg='white').pack(pady=10)
            
            # Campo de busca
            search_frame = tk.Frame(select_win, bg='white')
            search_frame.pack(fill=tk.X, padx=20, pady=5)
            
            tk.Label(search_frame, text="Buscar:", bg='white', font=("Arial", 10)).pack(side=tk.LEFT)
            search_var = tk.StringVar()
            search_entry = tk.Entry(search_frame, textvariable=search_var, font=("Arial", 11), width=30)
            search_entry.pack(side=tk.LEFT, padx=10, fill=tk.X, expand=True)
            
            # Lista de clientes
            list_frame = tk.Frame(select_win, bg='white')
            list_frame.pack(fill=tk.BOTH, expand=True, padx=20, pady=10)
            
            scrollbar = tk.Scrollbar(list_frame)
            scrollbar.pack(side=tk.RIGHT, fill=tk.Y)
            
            listbox = tk.Listbox(list_frame, font=("Arial", 11), yscrollcommand=scrollbar.set, height=12)
            listbox.pack(fill=tk.BOTH, expand=True)
            scrollbar.config(command=listbox.yview)
            
            # Dicionário para mapear índice -> id do cliente
            cliente_ids = []
            
            def atualizar_lista(*args):
                listbox.delete(0, tk.END)
                cliente_ids.clear()
                filtro = search_var.get().lower()
                
                # Adiciona Consumidor Final primeiro
                if 'consumidor' in 'consumidor final' or not filtro or filtro in 'consumidor final':
                    listbox.insert(tk.END, "Consumidor Final")
                    cliente_ids.append('1')
                
                for cid, cdata in self.customers.items():
                    if cid == '1':
                        continue
                    nome = cdata.get('nome', '')
                    cpf = cdata.get('cpf', '')
                    telefone = cdata.get('telefone', '')
                    
                    if filtro and filtro not in nome.lower() and filtro not in cpf and filtro not in telefone:
                        continue
                    
                    display = f"{nome}"
                    if cpf:
                        display += f" - CPF: {cpf}"
                    if telefone:
                        display += f" - Tel: {telefone}"
                    
                    listbox.insert(tk.END, display)
                    cliente_ids.append(cid)
            
            search_var.trace_add('write', atualizar_lista)
            atualizar_lista()
            
            def selecionar_cliente():
                sel = listbox.curselection()
                if not sel:
                    messagebox.showwarning("Aviso", "Selecione um cliente!", parent=select_win)
                    return
                
                idx = sel[0]
                novo_cliente_id = cliente_ids[idx]
                self.selected_customer_id = novo_cliente_id
                
                novo_nome = self.customers.get(novo_cliente_id, {}).get('nome', 'Consumidor Final')
                lbl_cliente.config(text=f"Cliente: {novo_nome}")
                
                # Atualiza saldo de crédito e cashback do novo cliente
                nonlocal saldo_credito_cliente, saldo_cashback_cliente
                cliente_selecionado = self.customers.get(novo_cliente_id, {})
                saldo_credito_cliente = parse_br_float(cliente_selecionado.get('saldo_credito', 0.0)) or 0.0
                saldo_cashback_cliente = parse_br_float(cliente_selecionado.get('saldo_fidelidade', 0.0)) or 0.0
                
                fechar_janela_filha()
                messagebox.showinfo("Cliente Alterado", f"Cliente alterado para: {novo_nome}", parent=pagamento_win)
            
            def on_double_click(event):
                selecionar_cliente()
            
            listbox.bind('<Double-Button-1>', on_double_click)
            
            btn_frame = tk.Frame(select_win, bg='white')
            btn_frame.pack(fill=tk.X, padx=20, pady=10)
            
            tk.Button(btn_frame, text="Selecionar", command=selecionar_cliente, bg='#0066cc', fg='white', font=("Arial", 11, "bold"), width=15).pack(side=tk.LEFT, padx=5)
            tk.Button(btn_frame, text="Cancelar", command=fechar_janela_filha, bg='#cc0000', fg='white', font=("Arial", 11), width=15).pack(side=tk.RIGHT, padx=5)
            
            search_entry.focus_set()
        
        btn_mudar_cliente = tk.Button(cliente_header_frame, text="👤 Alterar Cliente (F11)", command=mudar_cliente, 
                                       bg='#004499', fg='white', font=("Arial", 9, "bold"), relief=tk.RAISED, bd=1)
        btn_mudar_cliente.pack(side=tk.LEFT, padx=10)
        
        # Opção de Entrega
        entrega_frame = tk.Frame(header, bg='#0066cc')
        if mostrar_entrega_pagamento:
            entrega_frame.pack(pady=(0, 8))
        
        var_entrega = tk.BooleanVar(value=self.is_delivery if hasattr(self, 'is_delivery') else False)
        
        # Label para mostrar o entregador selecionado
        lbl_entregador_selecionado = tk.Label(entrega_frame, text="", bg='#0066cc', fg='#00ff00', font=("Arial", 10, "bold"))
        
        def _atualizar_label_entregador():
            """Atualiza o label do entregador selecionado na tela de pagamento."""
            if hasattr(self, 'selected_entregador_id') and self.selected_entregador_id:
                entregador_data = self.entregadores.get(self.selected_entregador_id, {})
                nome = entregador_data.get('nome', 'Entregador')
                lbl_entregador_selecionado.config(text=f"📋 Entregador: {nome}")
            else:
                lbl_entregador_selecionado.config(text="")
        
        def _abrir_selecao_entregador():
            """Abre janela para selecionar o entregador dentro da tela de pagamento."""
            try:
                # Carrega entregadores se não estiverem carregados
                if not hasattr(self, 'entregadores') or not self.entregadores:
                    self.entregadores = load_data(ENTREGADORES_FILE, {})
                
                # Filtra apenas entregadores ativos
                entregadores_ativos = {eid: edata for eid, edata in self.entregadores.items() 
                                       if edata.get('status', 'Ativo') == 'Ativo'}
                
                if not entregadores_ativos:
                    messagebox.showwarning("Aviso", 
                        "Nenhum entregador ativo cadastrado.\n\n"
                        "Cadastre entregadores em:\nCadastros → Entregadores",
                        parent=pagamento_win)
                    # Desmarca a entrega pois não há entregador
                    var_entrega.set(False)
                    self.is_delivery = False
                    lbl_entrega_status.config(text="", fg='white')
                    lbl_entregador_selecionado.config(text="")
                    return
                
                # Cria janela de seleção de entregador como filha da tela de pagamento
                ent_win = tk.Toplevel(pagamento_win)
                ent_win.title("🚚 Selecionar Entregador")
                responsive_geometry(ent_win, 450, 280)
                ent_win.resizable(True, True)
                ent_win.configure(bg='white')
                
                # Registra como janela filha para funcionar com a proteção de foco
                fechar_janela_filha = registrar_janela_filha(ent_win)
                
                # Centralizar janela
                ent_win.update_idletasks()
                x = (ent_win.winfo_screenwidth() // 2) - 225
                y = (ent_win.winfo_screenheight() // 2) - 140
                responsive_geometry(ent_win, 450, 280)
                
                # Frame principal
                main_ent_frame = tk.Frame(ent_win, bg='white', padx=20, pady=20)
                main_ent_frame.pack(fill=tk.BOTH, expand=True)
                
                tk.Label(main_ent_frame, text="🚚 SELECIONAR ENTREGADOR", font=("Segoe UI", 16, "bold"), bg='white').pack(pady=(0, 15))
                
                # Monta lista de entregadores para o combobox
                entregadores_list = []
                entregadores_map = {}  # Mapeia índice para ID do entregador
                
                for eid, edata in entregadores_ativos.items():
                    nome = edata.get('nome', 'Sem nome')
                    veiculo = edata.get('veiculo', '')
                    telefone = edata.get('telefone', '')
                    
                    display = f"{nome}"
                    if veiculo:
                        display += f" - {veiculo}"
                    if telefone:
                        display += f" ({telefone})"
                    
                    entregadores_list.append(display)
                    entregadores_map[len(entregadores_list) - 1] = eid
                
                # Label e Combobox
                tk.Label(main_ent_frame, text="Selecione o entregador:", font=("Segoe UI", 11), bg='white').pack(anchor='w', pady=(0, 5))
                
                entregador_sel_var = tk.StringVar()
                entregador_combo = ttk.Combobox(main_ent_frame, textvariable=entregador_sel_var, 
                                                values=entregadores_list, 
                                                state='readonly', width=50, font=("Segoe UI", 11))
                entregador_combo.pack(fill=tk.X, pady=(0, 20))
                
                # Seleciona o primeiro por padrão, ou o entregador já selecionado
                idx_selecionado = 0
                if hasattr(self, 'selected_entregador_id') and self.selected_entregador_id:
                    for idx, eid in entregadores_map.items():
                        if eid == self.selected_entregador_id:
                            idx_selecionado = idx
                            break
                if entregadores_list:
                    entregador_combo.current(idx_selecionado)
                
                def confirmar_entregador():
                    if not entregador_sel_var.get():
                        messagebox.showwarning("Aviso", "Selecione um entregador.", parent=ent_win)
                        return
                    
                    # Obtém o índice selecionado
                    idx = entregador_combo.current()
                    if idx >= 0 and idx in entregadores_map:
                        self.selected_entregador_id = entregadores_map[idx]
                        entregador_data = self.entregadores.get(self.selected_entregador_id, {})
                        entregador_nome = entregador_data.get('nome', 'Entregador')
                        
                        log_user_action("Entrega", f"Entregador selecionado na tela de pagamento: {entregador_nome} (ID: {self.selected_entregador_id})")
                    
                    fechar_janela_filha()
                    _atualizar_label_entregador()
                
                def cancelar_entregador():
                    # Se cancelou a seleção de entregador, desmarca a entrega
                    var_entrega.set(False)
                    self.is_delivery = False
                    self.selected_entregador_id = None
                    lbl_entrega_status.config(text="", fg='white')
                    lbl_entregador_selecionado.config(text="")
                    fechar_janela_filha()
                
                # Botões
                btn_ent_frame = tk.Frame(main_ent_frame, bg='white')
                btn_ent_frame.pack(fill=tk.X, pady=(10, 0))
                
                tk.Button(btn_ent_frame, text="✅ Confirmar", command=confirmar_entregador, 
                          bg='#28a745', fg='white', font=("Segoe UI", 11, "bold"), width=15, cursor="hand2").pack(side=tk.LEFT, padx=5)
                tk.Button(btn_ent_frame, text="❌ Cancelar", command=cancelar_entregador, 
                          bg='#dc3545', fg='white', font=("Segoe UI", 11, "bold"), width=15, cursor="hand2").pack(side=tk.RIGHT, padx=5)
                
                # Atalhos
                ent_win.bind('<Return>', lambda e: confirmar_entregador())
                ent_win.bind('<Escape>', lambda e: cancelar_entregador())
                
                # Foco no combobox
                entregador_combo.focus_set()
                
            except Exception as e:
                try:
                    AUDITORIA.erro(f"Erro no sistema: {e}")
                except Exception:
                    pass
                print(f"[ERRO] Ao selecionar entregador na tela de pagamento: {e}")
                import traceback
                traceback.print_exc()
        
        def toggle_entrega():
            self.is_delivery = var_entrega.get()
            if self.is_delivery:
                lbl_entrega_status.config(text="🚚 ENTREGA ATIVADA", fg='#ffff00')
                # Abre a janela de seleção de entregador
                _abrir_selecao_entregador()
            else:
                lbl_entrega_status.config(text="", fg='white')
                self.selected_entregador_id = None
                lbl_entregador_selecionado.config(text="")
        
        chk_entrega = tk.Checkbutton(entrega_frame, text="🚚 Solicitar para Entrega (F12)", variable=var_entrega, 
                                      bg='#0066cc', fg='white', font=("Arial", 10, "bold"), 
                                      selectcolor='#004499', activebackground='#0066cc', activeforeground='white',
                                      command=toggle_entrega)
        chk_entrega.pack(side=tk.LEFT, padx=5)
        
        lbl_entrega_status = tk.Label(entrega_frame, text="🚚 ENTREGA ATIVADA" if var_entrega.get() else "", 
                                       bg='#0066cc', fg='#ffff00', font=("Arial", 10, "bold"))
        lbl_entrega_status.pack(side=tk.LEFT, padx=10)
        
        lbl_entregador_selecionado.pack(side=tk.LEFT, padx=10)
        
        # Se já havia um entregador selecionado (entrega já ativada antes de abrir a tela), mostra o nome
        _atualizar_label_entregador()
        
        # ===== SELEÇÃO OBRIGATÓRIA DE VENDEDOR =====
        vendedor_frame = tk.Frame(main_frame, bg='#004d00')
        if mostrar_vendedor_pagamento:
            vendedor_frame.pack(fill=tk.X, padx=0, pady=0)
        
        # Carrega vendedores ativos
        if not hasattr(self, 'vendedores') or not self.vendedores:
            self.vendedores = load_data(VENDEDORES_FILE, {})
        
        vendedores_ativos = {vid: vdata for vid, vdata in self.vendedores.items() 
                             if isinstance(vdata, dict) and vdata.get('status', 'Ativo') == 'Ativo'}
        
        # Monta lista de vendedores para o combobox
        vendedores_list = []
        vendedores_map = {}  # Mapeia índice para ID do vendedor
        
        for vid, vdata in vendedores_ativos.items():
            nome = vdata.get('nome', 'Sem nome')
            vendedores_list.append(nome)
            vendedores_map[len(vendedores_list) - 1] = vid
        
        _vendedor_obrigatorio_cfg = self.config_data.get("vendedor_obrigatorio", True)
        _lbl_vendedor_texto = "\U0001f464 VENDEDOR (OBRIGAT\u00d3RIO) (Alt+V):" if _vendedor_obrigatorio_cfg else "\U0001f464 VENDEDOR (OPCIONAL) (Alt+V):"
        tk.Label(vendedor_frame, text=_lbl_vendedor_texto, bg='#004d00', fg='white', 
                 font=("Arial", 11, "bold")).pack(side=tk.LEFT, padx=(15, 5), pady=8)
        
        vendedor_sel_var = tk.StringVar(value='')
        
        # Se já havia um vendedor selecionado, pré-seleciona
        if hasattr(self, 'selected_vendedor_id') and self.selected_vendedor_id:
            for idx, vid in vendedores_map.items():
                if vid == self.selected_vendedor_id:
                    vendedor_sel_var.set(vendedores_list[idx])
                    break
        
        # Entry somente-leitura para exibir o vendedor selecionado
        vendedor_entry = tk.Entry(vendedor_frame, textvariable=vendedor_sel_var, 
                                   state='readonly', width=30, font=("Arial", 11),
                                   readonlybackground='white', relief=tk.SUNKEN, bd=2)
        vendedor_entry.pack(side=tk.LEFT, padx=(5, 0), pady=8)
        
        # Função para abrir popup de seleção de vendedor
        def abrir_selecao_vendedor(event=None):
            if not vendedores_list:
                messagebox.showwarning("Sem Vendedores", 
                    "Nenhum vendedor cadastrado!\nCadastre em: Cadastros \u2192 Vendedores", 
                    parent=pagamento_win)
                return 'break'
            
            sel_win = tk.Toplevel(pagamento_win)
            sel_win.title("Selecionar Vendedor")
            responsive_geometry(sel_win, 400, 350)
            sel_win.configure(bg='white')
            sel_win.attributes('-topmost', True)
            sel_win.transient(pagamento_win)
            
            # Centralizar
            sel_win.update_idletasks()
            x = (sel_win.winfo_screenwidth() // 2) - 200
            y = (sel_win.winfo_screenheight() // 2) - 175
            responsive_geometry(sel_win, 400, 350)
            
            # Registra como janela filha
            fechar_sel = registrar_janela_filha(sel_win)
            
            tk.Label(sel_win, text="\U0001f464 Selecione o Vendedor", bg='white', 
                     font=("Arial", 13, "bold")).pack(pady=(10, 5))
            
            # Busca
            search_frame_v = tk.Frame(sel_win, bg='white')
            search_frame_v.pack(fill=tk.X, padx=15, pady=5)
            tk.Label(search_frame_v, text="\U0001f50d Buscar:", bg='white', font=("Arial", 10)).pack(side=tk.LEFT)
            search_var_v = tk.StringVar()
            search_entry_v = tk.Entry(search_frame_v, textvariable=search_var_v, font=("Arial", 11), width=30)
            search_entry_v.pack(side=tk.LEFT, padx=5, fill=tk.X, expand=True)
            
            # Listbox
            list_frame_v = tk.Frame(sel_win, bg='white')
            list_frame_v.pack(fill=tk.BOTH, expand=True, padx=15, pady=5)
            
            scrollbar_v = tk.Scrollbar(list_frame_v)
            scrollbar_v.pack(side=tk.RIGHT, fill=tk.Y)
            
            listbox_v = tk.Listbox(list_frame_v, font=("Arial", 12), yscrollcommand=scrollbar_v.set,
                                    selectmode=tk.SINGLE, activestyle='dotbox')
            listbox_v.pack(fill=tk.BOTH, expand=True)
            scrollbar_v.config(command=listbox_v.yview)
            
            # Mapeia posição na listbox para índice no vendedores_map
            listbox_idx_map = []
            
            def filtrar_vendedores(*args):
                listbox_v.delete(0, tk.END)
                listbox_idx_map.clear()
                termo = search_var_v.get().lower()
                for idx, nome in enumerate(vendedores_list):
                    if not termo or termo in nome.lower():
                        listbox_v.insert(tk.END, f"  {nome}")
                        listbox_idx_map.append(idx)
                if listbox_idx_map:
                    listbox_v.selection_set(0)
            
            search_var_v.trace_add('write', filtrar_vendedores)
            filtrar_vendedores()  # Popula inicialmente
            
            def selecionar_vendedor_popup():
                sel = listbox_v.curselection()
                if not sel:
                    messagebox.showwarning("Atenção", "Selecione um vendedor da lista!", parent=sel_win)
                    return
                idx_original = listbox_idx_map[sel[0]]
                vid = vendedores_map.get(idx_original)
                if vid:
                    self.selected_vendedor_id = vid
                    vendedor_data = vendedores_ativos.get(vid, {})
                    self.selected_vendedor_nome = vendedor_data.get('nome', '')
                    vendedor_sel_var.set(self.selected_vendedor_nome)
                    lbl_vendedor_status.config(text=f"\u2705 {self.selected_vendedor_nome}", fg='#00ff00')
                fechar_sel()
            
            def on_double_click_v(event):
                selecionar_vendedor_popup()
            
            listbox_v.bind('<Double-Button-1>', on_double_click_v)
            listbox_v.bind('<Return>', lambda e: selecionar_vendedor_popup())
            
            btn_frame_v = tk.Frame(sel_win, bg='white')
            btn_frame_v.pack(fill=tk.X, padx=15, pady=10)
            
            tk.Button(btn_frame_v, text="\u2705 Selecionar", command=selecionar_vendedor_popup, 
                      bg='#006600', fg='white', font=("Arial", 11, "bold"), width=15).pack(side=tk.LEFT, padx=5)
            tk.Button(btn_frame_v, text="\u274c Cancelar", command=fechar_sel, 
                      bg='#cc0000', fg='white', font=("Arial", 11), width=15).pack(side=tk.RIGHT, padx=5)
            
            search_entry_v.focus_set()
            return 'break'
        
        # Botão para abrir seleção de vendedor (seta dropdown)
        btn_vendedor = tk.Button(vendedor_frame, text="\u25bc", command=abrir_selecao_vendedor,
                                  bg='#006600', fg='white', font=("Arial", 10, "bold"),
                                  width=3, relief=tk.RAISED, bd=2, cursor='hand2')
        btn_vendedor.pack(side=tk.LEFT, padx=(0, 5), pady=8)
        
        # Clicar no entry também abre a seleção
        vendedor_entry.bind('<Button-1>', abrir_selecao_vendedor)
        
        # Referência para compatibilidade com o código existente (atalhos e validação)
        vendedor_combo = vendedor_entry
        
        _lbl_vendedor_status_texto = "\u26a0 Selecione um vendedor!" if _vendedor_obrigatorio_cfg else "\u26a0 Vendedor n\u00e3o selecionado (opcional)"
        _lbl_vendedor_status_cor = '#ff4444' if _vendedor_obrigatorio_cfg else '#ffaa00'
        lbl_vendedor_status = tk.Label(vendedor_frame, text=_lbl_vendedor_status_texto, 
                                        bg='#004d00', fg=_lbl_vendedor_status_cor, font=("Arial", 10, "bold"))
        
        # Se já tinha vendedor selecionado, atualiza o status
        if hasattr(self, 'selected_vendedor_id') and self.selected_vendedor_id:
            lbl_vendedor_status.config(text=f"\u2705 {self.selected_vendedor_nome}", fg='#00ff00')
        
        lbl_vendedor_status.pack(side=tk.LEFT, padx=10, pady=8)
        
        # Mensagem caso não haja vendedores cadastrados
        if not vendedores_list:
            lbl_vendedor_status.config(text="\u26a0 Nenhum vendedor cadastrado! Cadastre em: Cadastros \u2192 Vendedores", fg='#ff4444')
        
        # ===== GARÇOM / TAXA DE SERVIÇO =====
        self.selected_garcom_id = None
        self.selected_garcom_nome = ''
        taxa_garcom_ativa = cfg_bool(self.config_data.get("taxa_garcom_ativa", False), False) and mostrar_garcom_taxa_pagamento
        garcom_obrigatorio_pagamento = cfg_bool(self.config_data.get("garcom_obrigatorio_pagamento", False), False) and mostrar_garcom_taxa_pagamento
        taxa_garcom_valor = tk.DoubleVar(value=0.0)
        garcom_sel_var = tk.StringVar(value='')
        garcons_ativos = {}
        garcons_list = []
        garcons_map = {}
        try:
            if not hasattr(self, 'garcons') or self.garcons is None:
                self.garcons = load_data(GARCONS_FILE, {})
            garcons_ativos = {gid: g for gid, g in self.garcons.items() if str(g.get('status', 'Ativo')).lower() == 'ativo'}
            for gid, gdata in garcons_ativos.items():
                nome = gdata.get('nome', 'Sem nome')
                pct = parse_br_float(gdata.get('percentual_taxa', 0.0)) or 0.0
                rotulo = f"{nome} ({format_br_float(pct, 2)}%)"
                garcons_list.append(rotulo)
                garcons_map[len(garcons_list) - 1] = gid
        except Exception:
            garcons_ativos = {}

        garcom_frame = tk.Frame(main_frame, bg='#3b2f00' if taxa_garcom_ativa else '#eeeeee', relief=tk.RIDGE, bd=2)
        if mostrar_garcom_taxa_pagamento:
            garcom_frame.pack(fill=tk.X, padx=15, pady=(0, 8))
        tk.Label(garcom_frame, text="🍽️ GARÇOM / TAXA DE SERVIÇO:", bg=garcom_frame.cget('bg'),
                 fg='white' if taxa_garcom_ativa else '#333', font=("Arial", 11, "bold")).pack(side=tk.LEFT, padx=(15, 5), pady=8)
        garcom_entry = tk.Entry(garcom_frame, textvariable=garcom_sel_var, state='readonly', width=34,
                                font=("Arial", 11), readonlybackground='white', relief=tk.SUNKEN, bd=2)
        garcom_entry.pack(side=tk.LEFT, padx=(5, 0), pady=8)
        lbl_garcom_taxa = tk.Label(garcom_frame, text="Taxa desativada nas configurações" if not taxa_garcom_ativa else "Selecione um garçom para aplicar a taxa",
                                   bg=garcom_frame.cget('bg'), fg='#ffffff' if taxa_garcom_ativa else '#666', font=("Arial", 10, "bold"))
        lbl_garcom_taxa.pack(side=tk.LEFT, padx=10, pady=8)

        def _aplicar_taxa_garcom(gid):
            try:
                anterior = float(taxa_garcom_valor.get() or 0.0)
                if anterior > 0:
                    self.total_venda -= anterior
                taxa_garcom_valor.set(0.0)
                if not taxa_garcom_ativa or not gid:
                    total_label.config(text=format_br_currency(self.total_venda))
                    try:
                        atualizar_saldo()
                    except Exception:
                        pass
                    return
                gd = garcons_ativos.get(gid, {})
                pct = parse_br_float(gd.get('percentual_taxa', 0.0)) or 0.0
                base = max(0.0, float(self.total_venda or 0.0))
                valor_taxa = base * (pct / 100.0)
                if valor_taxa > 0:
                    self.total_venda += valor_taxa
                    taxa_garcom_valor.set(valor_taxa)
                total_label.config(text=format_br_currency(self.total_venda))
                lbl_garcom_taxa.config(text=f"+ {format_br_currency(valor_taxa)} ({format_br_float(pct, 2)}%)", fg='#00ff99' if taxa_garcom_ativa else '#666')
                try:
                    atualizar_saldo()
                except Exception:
                    pass
            except Exception as e:
                try:
                    AUDITORIA.erro("Erro ao aplicar taxa do garçom", exception=e)
                except Exception:
                    pass

        def abrir_selecao_garcom(event=None):
            if not taxa_garcom_ativa:
                messagebox.showinfo("Taxa do Garçom", "A taxa do garçom está desativada em Configurações Gerais.", parent=pagamento_win)
                return 'break'
            if not garcons_list:
                messagebox.showwarning("Sem Garçons", "Nenhum garçom ativo cadastrado!\nCadastre em: Cadastros → Garçons", parent=pagamento_win)
                return 'break'
            sel_win = tk.Toplevel(pagamento_win)
            sel_win.title("Selecionar Garçom")
            responsive_geometry(sel_win, 430, 380)
            sel_win.configure(bg='white')
            sel_win.attributes('-topmost', True)
            sel_win.transient(pagamento_win)
            fechar_sel_g = registrar_janela_filha(sel_win)
            tk.Label(sel_win, text="🍽️ Selecione o Garçom", bg='white', font=("Arial", 13, "bold")).pack(pady=(10, 5))
            search_frame_g = tk.Frame(sel_win, bg='white')
            search_frame_g.pack(fill=tk.X, padx=15, pady=5)
            tk.Label(search_frame_g, text="🔍 Buscar:", bg='white', font=("Arial", 10)).pack(side=tk.LEFT)
            search_var_g = tk.StringVar()
            search_entry_g = tk.Entry(search_frame_g, textvariable=search_var_g, font=("Arial", 11), width=30)
            search_entry_g.pack(side=tk.LEFT, padx=5, fill=tk.X, expand=True)
            list_frame_g = tk.Frame(sel_win, bg='white')
            list_frame_g.pack(fill=tk.BOTH, expand=True, padx=15, pady=5)
            scrollbar_g = tk.Scrollbar(list_frame_g)
            scrollbar_g.pack(side=tk.RIGHT, fill=tk.Y)
            listbox_g = tk.Listbox(list_frame_g, font=("Arial", 12), yscrollcommand=scrollbar_g.set, selectmode=tk.SINGLE, activestyle='dotbox')
            listbox_g.pack(fill=tk.BOTH, expand=True)
            scrollbar_g.config(command=listbox_g.yview)
            idx_map_g = []
            def filtrar_garcons(*args):
                listbox_g.delete(0, tk.END)
                idx_map_g.clear()
                termo = search_var_g.get().lower()
                for idx, nome in enumerate(garcons_list):
                    if not termo or termo in nome.lower():
                        listbox_g.insert(tk.END, f"  {nome}")
                        idx_map_g.append(idx)
                if idx_map_g:
                    listbox_g.selection_set(0)
            search_var_g.trace_add('write', filtrar_garcons)
            filtrar_garcons()
            def selecionar_garcom_popup():
                sel = listbox_g.curselection()
                if not sel:
                    messagebox.showwarning("Atenção", "Selecione um garçom da lista!", parent=sel_win)
                    return
                idx_original = idx_map_g[sel[0]]
                gid = garcons_map.get(idx_original)
                if gid:
                    gd = garcons_ativos.get(gid, {})
                    self.selected_garcom_id = gid
                    self.selected_garcom_nome = gd.get('nome', '')
                    garcom_sel_var.set(garcons_list[idx_original])
                    _aplicar_taxa_garcom(gid)
                fechar_sel_g()
            listbox_g.bind('<Double-Button-1>', lambda e: selecionar_garcom_popup())
            listbox_g.bind('<Return>', lambda e: selecionar_garcom_popup())
            btn_frame_g = tk.Frame(sel_win, bg='white')
            btn_frame_g.pack(fill=tk.X, padx=15, pady=10)
            tk.Button(btn_frame_g, text="✅ Selecionar", command=selecionar_garcom_popup, bg='#006600', fg='white', font=("Arial", 11, "bold"), width=15).pack(side=tk.LEFT, padx=5)
