        desc_valor_entry = tk.Entry(desc_inner, textvariable=desconto_valor_var, width=10, font=("Arial", 12), justify='center')
        desc_valor_entry.pack(side=tk.LEFT, padx=3)
        
        lbl_desc_valor = tk.Label(desc_inner, text="", bg='#f0f0f0', font=("Arial", 10), fg='green')
