        def aplicar_desconto():
            # Verifica se os campos estão bloqueados (forma de pagamento selecionada)
            if str(desc_entry.cget('state')) == 'disabled' and not desconto_ja_aplicado[0]:
                messagebox.showwarning("Bloqueado", 
                    "Desconto bloqueado!\n\n"
                    "Uma forma de pagamento já foi selecionada.\n"
                    "Para aplicar desconto, cancele o pagamento (Esc)\n"
                    "e volte para a tela de vendas.",
                    parent=pagamento_win)
                return
            # Verifica se o desconto já foi aplicado
            if desconto_ja_aplicado[0]:
                messagebox.showwarning("Aviso", "O desconto já foi aplicado nesta venda!", parent=pagamento_win)
                return
            
            try:
                pct = parse_br_float(desconto_var.get()) or 0
                valor_direto = parse_br_float(desconto_valor_var.get()) or 0
                
                # Prioriza valor direto se informado, senão usa percentual
                if valor_direto > 0:
                    desc_valor = valor_direto
                    if desc_valor > self.total_venda:
                        messagebox.showwarning("Aviso", "O desconto não pode ser maior que o total da venda!", parent=pagamento_win)
                        return
                elif pct > 0:
                    if pct > 100:
                        messagebox.showwarning("Aviso", "O percentual não pode ser maior que 100%!", parent=pagamento_win)
                        return
                    desc_valor = self.total_venda * pct / 100
                else:
                    messagebox.showwarning("Aviso", "Informe um percentual ou valor de desconto!", parent=pagamento_win)
                    return
                
                self.desconto_aplicado = desc_valor
                self.total_venda -= desc_valor
                total_label.config(text=format_br_currency(self.total_venda))
                lbl_desc_valor.config(text=f"(-{format_br_currency(desc_valor)})")
                atualizar_saldo()
                
                # Marca que o desconto foi aplicado e desabilita os controles
                desconto_ja_aplicado[0] = True
                desc_entry.config(state='disabled', bg='#d0d0d0')
                desc_valor_entry.config(state='disabled', bg='#d0d0d0')
                btn_desconto.config(state='disabled', bg='#888888', text="✓ Aplicado")
                
                if valor_direto > 0:
                    messagebox.showinfo("Desconto", f"Desconto de {format_br_currency(desc_valor)} aplicado!", parent=pagamento_win)
                else:
                    messagebox.showinfo("Desconto", f"Desconto de {pct:.2f}% aplicado!\nValor: {format_br_currency(desc_valor)}", parent=pagamento_win)
            except Exception:
                messagebox.showerror("Erro", "Valor inválido!", parent=pagamento_win)
        
