                # Configuração: acrescentar ou não a taxa percentual cadastrada do cartão no ato da escolha da bandeira
        acrescentar_taxa_cartao_pagamento = cfg_bool(self.config_data.get("acrescentar_taxa_cartao_pagamento", True), True)

        def _texto_modo_taxa_cartao(taxa):
            try:
                taxa_txt = format_br_float(float(taxa or 0.0), 2)
            except Exception:
                taxa_txt = "0,00"
            if acrescentar_taxa_cartao_pagamento:
                return f"Taxa: {taxa_txt}% - acréscimo ATIVO"
            return f"Taxa: {taxa_txt}% - acréscimo DESATIVADO"

        def _calcular_valor_com_taxa_cartao(valor_original, taxa):
            try:
                valor_original = float(valor_original or 0.0)
                taxa = float(taxa or 0.0)
            except Exception:
                return 0.0, 0.0
            if acrescentar_taxa_cartao_pagamento and valor_original > 0 and taxa > 0:
                valor_taxa = valor_original * (taxa / 100)
                return valor_original + valor_taxa, valor_taxa
            return valor_original, 0.0

        # ===== CHECKBOXES DE PARCELAMENTO (Oculto inicialmente) =====
        frame_parcelamento = tk.Frame(left_col, bg='#fff3cd', relief=tk.RIDGE, bd=1)
        # Inicialmente oculto - sera exibido quando selecionar debito ou credito
        
        # Frame unico para titulo e checkboxes em linha compacta
        parcelamento_inner = tk.Frame(frame_parcelamento, bg='#fff3cd')
        parcelamento_inner.pack(fill=tk.X, padx=5, pady=5)
        
        tk.Label(parcelamento_inner, text="Parcelas:", bg='#fff3cd', font=("Arial", 9, "bold")).pack(side=tk.LEFT, padx=(0, 5))
        
        # Variavel para armazenar a opcao selecionada
        parcelamento_var = tk.StringVar(value="")
        
        # Lista de opcoes de parcelamento - texto curto para caber em uma linha
        opcoes_parcelamento = [
            ("1x", "Cartao 1 Vez"),
            ("2x", "Cartao 2 Vezes"),
            ("3x", "Cartao 3 Vezes"),
            ("4x", "Cartao 4 Vezes"),
            ("5x", "Cartao 5 Vezes"),
            ("6x", "Cartao 6 Vezes"),
            ("7x", "Cartao 7 Vezes"),
            ("8x", "Cartao 8 Vezes"),
            ("9x", "Cartao 9 Vezes"),
            ("10x", "Cartao 10 Vezes"),
            ("11x", "Cartao 11 Vezes"),
            ("12x", "Cartao 12 Vezes")
        ]
        
        # Criar checkboxes com comportamento de selecao unica (como radiobuttons)
        parcelamento_checks = {}
        parcelamento_widgets = {}
        
        def selecionar_parcelamento(valor):
            """Funcao para selecionar apenas um checkbox por vez."""
            # Desmarca todos os outros
            for key, var in parcelamento_checks.items():
                if key != valor:
                    var.set(False)
            # Atualiza a variavel de parcelamento
            parcelamento_var.set(valor)
        
        # Todos os checkboxes em uma unica linha
        for texto, valor in opcoes_parcelamento:
            var_check = tk.BooleanVar(value=False)
            parcelamento_checks[valor] = var_check
            cb = tk.Checkbutton(parcelamento_inner, text=texto, variable=var_check, 
                               bg='#fff3cd', font=("Arial", 8),
                               command=lambda v=valor, vc=var_check: selecionar_parcelamento(v) if vc.get() else None)
            cb.pack(side=tk.LEFT, padx=1)
            parcelamento_widgets[valor] = cb
        
        def _max_parcelas_cartao_selecionado():
            """Retorna o limite de parcelas permitido para o cartão.
            Como o campo de bandeira/cartão foi ocultado, quando não houver cartão
            selecionado o sistema libera as parcelas padrão de 1x até 12x.
            """
            try:
                if var_credito.get():
                    band = ""
                    try:
                        band = credito_bandeira_var.get()
                    except Exception:
                        band = ""
                    nome = band.split(" (")[0] if band and " (" in band else band
                    if nome and nome in cartoes_credito_dict:
                        return max(1, min(24, int(cartoes_credito_dict[nome].get('max_parcelas', 12) or 12)))
                    # Sem bandeira/cartão escolhido: libera as 12 parcelas visíveis.
                    return 12
                if var_debito.get():
                    # Débito continua sendo pagamento em 1x.
                    return 1
            except Exception:
                return 12 if var_credito.get() else 1
            return 12 if var_credito.get() else 1

        def atualizar_opcoes_parcelamento_por_cartao(*args):
            """Habilita as parcelas disponíveis.
            Crédito sem bandeira/cartão selecionado libera 1x até 12x.
            Débito permanece 1x.
            """
            limite = _max_parcelas_cartao_selecionado()
            for idx, (texto, valor) in enumerate(opcoes_parcelamento, start=1):
                widget = parcelamento_widgets.get(valor)
                if widget:
                    if idx <= limite:
                        widget.config(state='normal')
                    else:
                        widget.config(state='disabled')
                        parcelamento_checks[valor].set(False)
            atual = parcelamento_var.get()
            if not atual:
                parcelamento_checks['Cartao 1 Vez'].set(True)
                parcelamento_var.set('Cartao 1 Vez')
            else:
                try:
                    atual_num = int(atual.replace('Cartao ', '').replace(' Vezes', '').replace(' Vez', '').strip())
                    if atual_num > limite:
                        for key, var in parcelamento_checks.items():
                            var.set(False)
                        parcelamento_checks['Cartao 1 Vez'].set(True)
                        parcelamento_var.set('Cartao 1 Vez')
                except Exception:
                    parcelamento_var.set('Cartao 1 Vez')
            try:
                # Os campos de bandeira/cartão estão ocultos, então não exibe aviso visual neles.
                lbl_taxa_credito.config(text="")
                lbl_taxa_debito.config(text="")
            except Exception:
                pass

        def atualizar_visibilidade_parcelamento(*args):
            """Mostra ou oculta o frame de parcelamento baseado na selecao de debito/credito."""
            if var_debito.get() or var_credito.get():
                frame_parcelamento.pack(fill=tk.X, pady=(0, 3), after=check_frame2)
                atualizar_opcoes_parcelamento_por_cartao()
            else:
                frame_parcelamento.pack_forget()
                # Reset - desmarca todos os checkboxes
                for key, var in parcelamento_checks.items():
                    var.set(False)
                parcelamento_var.set("")
        
        # Vincular a atualizacao de visibilidade as variaveis de debito e credito
