        right_col = tk.Frame(right_canvas, bg='white')
        
        right_col.bind('<Configure>', lambda e: right_canvas.configure(scrollregion=right_canvas.bbox('all')))
        right_canvas.create_window((0, 0), window=right_col, anchor='nw', tags='right_col_win')
