    def show_closing_report(self):
        if not check_permission("relatorios.fechamento_caixa"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar este relatório.")
            return
        today_str = datetime.date.today().isoformat()
        sales_today = [sale for sale in self.sales_log if isinstance(sale, dict) and sale.get('timestamp', '').startswith(today_str)]
        if not sales_today: messagebox.showinfo("Relatório", "Nenhuma venda hoje.", parent=self.root); return
        total_sales_value = sum(s.get('total', 0.0) for s in sales_today)
        num_sales = len(sales_today)
        sales_by_payment = defaultdict(float); num_sales_by_payment = defaultdict(int)
        for sale in sales_today:
            method = sale.get('forma_pagamento', 'N/A'); total = sale.get('total', 0.0)
            sales_by_payment[method] += total; num_sales_by_payment[method] += 1
        report = "=" * 48 + "\n"
        report += "FECHAMENTO DO DIA".center(48) + "\n"
        report += f"{datetime.date.today().strftime('%d/%m/%Y')}".center(48) + "\n"
        report += "=" * 48 + "\n"
        report += f"Total de Vendas: {num_sales}\n"
        report += f"Valor Total:{format_br_currency(total_sales_value):>35}\n"
        report += "-" * 48 + "\n"
        report += "VENDAS POR FORMA DE PAGAMENTO:\n"
        report += "-" * 48 + "\n"
        for method, total in sorted(sales_by_payment.items()):
            count = num_sales_by_payment[method]
            met = method[:20]
            report += f"{met:<20}{count:>4} {format_br_currency(total):>22}\n"
        report += "=" * 48 + "\n"
        ReportWindow(self.root, "Fechamento - Hoje", report, self)

    def show_products_sold_report(self):
        if not check_permission("relatorios.produtos_vendidos"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar este relatório.")
            return
        today_str = datetime.date.today().isoformat()
        sales_today = [sale for sale in self.sales_log if isinstance(sale, dict) and sale.get('timestamp', '').startswith(today_str)]
        if not sales_today: messagebox.showinfo("Relatório", "Nenhuma venda hoje.", parent=self.root); return
        products_sold = defaultdict(lambda: {'quantidade': 0.0, 'valor': 0.0, 'tipo': 'unidade'})
        for sale in sales_today:
            itens = sale.get('itens', {})
            if isinstance(itens, dict):
                for prod_id, item_data in itens.items():
                    if not isinstance(item_data, dict): continue
                    current_prod_data = products_sold[prod_id]
                    qtd = parse_br_float(item_data.get('quantidade_peso', 0.0))
                    preco_base = parse_br_float(item_data.get('preco', 0.0))
                    tipo = item_data.get('tipo', 'unidade')
                    if qtd is None: qtd = 0.0
                    if preco_base is None: preco_base = 0.0
                    current_prod_data['tipo'] = tipo
                    current_prod_data['quantidade'] += qtd
                    subtotal_base = qtd * preco_base
                    desconto_item = parse_br_float(item_data.get('desconto', 0.0)) or 0.0
                    acrescimo_item = parse_br_float(item_data.get('acrescimo', 0.0)) or 0.0
                    subtotal = max(0.0, subtotal_base - desconto_item + acrescimo_item)
                    current_prod_data['valor'] += subtotal
        report = "=" * 48 + "\n"
        report += "PRODUTOS VENDIDOS HOJE".center(48) + "\n"
        report += f"{datetime.date.today().strftime('%d/%m/%Y')}".center(48) + "\n"
        report += "=" * 48 + "\n"
        report += f"{'PRODUTO':<22}{'QTD':>10}{'VALOR':>14}\n"
        report += "-" * 48 + "\n"
        sorted_prod_ids = sorted(products_sold.keys(), key=lambda x: int(x) if x.isdigit() else float('inf'))
        for prod_id in sorted_prod_ids:
            data = products_sold[prod_id]
            prod_name = self.products.get(prod_id, {}).get('nome', f'ID {prod_id}')[:22]
            qtd_total = data['quantidade']; valor_total = data['valor']; tipo = data['tipo']
            if tipo == 'unidade': qtd_str = f"{format_br_float(qtd_total, 1)}un"
            elif tipo == 'peso': qtd_str = f"{format_br_float(qtd_total, 3)}g"
            else: qtd_str = f"{format_br_float(qtd_total, 3)}"
            valor_str = format_br_float(valor_total, 2)
            report += f"{prod_name:<22}{qtd_str:>10}{valor_str:>14}\n"
        report += "=" * 48 + "\n"
        ReportWindow(self.root, "Produtos Vendidos - Hoje", report, self)

    def show_product_stock_report(self):
        """Gera e exibe o relatório de estoque de produtos."""
        if not check_permission("relatorios.estoque_produtos"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar este relatório.")
            return
        if not isinstance(self.products, dict) or not self.products:
            messagebox.showinfo("Relatório de Estoque", "Nenhum produto cadastrado.", parent=self.root)
            return

        report = "=" * 48 + "\n"
        report += "RELATORIO DE ESTOQUE".center(48) + "\n"
        report += "=" * 48 + "\n"
        report += f"Emitido: {datetime.datetime.now().strftime('%d/%m/%Y %H:%M')}\n"
        report += "=" * 48 + "\n"
        report += f"{'PRODUTO':<22}{'PRECO':>12}{'ESTOQUE':>12}\n"
        report += "-" * 48 + "\n"

        produtos_ordenados = sorted(self.products.items(), key=lambda x: x[1].get('nome', '').lower())

        for prod_id, dados in produtos_ordenados:
            nome = dados.get('nome', 'N/A')[:24]
            cat_id = dados.get('categoria_id', '')
            cat_name = self.categories.get(cat_id, {}).get('nome', 'N/A')[:18]
            tipo = dados.get('tipo', 'unidade').capitalize()
            preco_val = parse_br_float(dados.get('preco', 0.0))
            if preco_val is None: preco_val = 0.0
            preco_str = format_br_currency(preco_val) + sufixo_preco_produto(dados.get('tipo', 'unidade'))
            estoque_val = parse_br_float(dados.get('estoque', 0.0))
            if estoque_val is None: estoque_val = 0.0
            estoque_str = formatar_estoque_produto(estoque_val, dados.get('tipo', 'unidade'))

            report += f"{nome:<22}{preco_str:>12}{estoque_str:>12}\n"

        report += "=" * 48 + "\n"
        report += f"Total: {len(self.products)} produtos\n"
        report += f"Valor Estoque:{format_br_currency(calcular_total_estoque(self.products)):>33}\n"
        report += "=" * 48 + "\n"

        log_user_action("Relatório", "Visualizou Relatório de Estoque de Produtos")
        ReportWindow(self.root, "Estoque de Produtos", report, self)

    def show_stock_with_entry_dates_report(self):
        if not check_permission("relatorios.estoque_datas"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar o relatório de estoque com datas.")
            return
        """
        Gera e exibe o relatório de estoque de produtos com as datas de entrada de mercadorias.
        Mostra informações de cada produto e as últimas entradas registradas nas notas fiscais.
        """
        if not isinstance(self.products, dict) or not self.products:
            messagebox.showinfo("Relatório de Estoque", "Nenhum produto cadastrado.", parent=self.root)
            return
        
        # Carrega as notas de entrada
        notas_entrada = load_data(NOTAS_ENTRADA_FILE, {})
        
        # Cria um dicionário para mapear produto_id -> lista de entradas
        entradas_por_produto = defaultdict(list)
        
        for nota_id, nota_data in notas_entrada.items():
            data_nota = nota_data.get('data_nota', 'N/A')
            data_registro = nota_data.get('data_registro', 'N/A')
            nota_fiscal = nota_data.get('nota_fiscal', 'N/A')
            fornecedor_id = nota_data.get('fornecedor_id', '')
            
            # Busca nome do fornecedor
            fornecedor_nome = "N/A"
            if fornecedor_id and hasattr(self, 'suppliers') and fornecedor_id in self.suppliers:
                fornecedor_nome = self.suppliers[fornecedor_id].get('nome', 'N/A')
            
            itens = nota_data.get('itens', {})
            
            for produto_id, item_data in itens.items():
                qtd = item_data.get('qtd', 0.0)
                custo = item_data.get('custo', 0.0)
                
                entrada_info = {
                    'data_nota': data_nota,
                    'data_registro': data_registro,
                    'nota_fiscal': nota_fiscal,
                    'fornecedor': fornecedor_nome,
                    'quantidade': qtd,
                    'custo_unitario': custo
                }
                entradas_por_produto[produto_id].append(entrada_info)
        
        # Ordena as entradas por data (mais recente primeiro)
        for produto_id in entradas_por_produto:
            entradas_por_produto[produto_id].sort(
                key=lambda x: datetime.datetime.strptime(x['data_nota'], '%d/%m/%Y') 
                if x['data_nota'] != 'N/A' else datetime.datetime.min,
                reverse=True
            )
        
        # Monta o relatório
        report = "=" * 48 + "\n"
        report += "ESTOQUE C/ DATAS ENTRADA".center(48) + "\n"
        report += "=" * 48 + "\n"
        report += f"Emitido: {datetime.datetime.now().strftime('%d/%m/%Y %H:%M')}\n"
        report += "=" * 48 + "\n\n"
        
        # Cabeçalho da tabela principal
        report += f"{'PRODUTO':<22}{'ESTOQUE':>12}{'PRECO':>12}\n"
        report += "-" * 48 + "\n"
        
        produtos_ordenados = sorted(self.products.items(), key=lambda x: x[1].get('nome', '').lower())
        
        for prod_id, dados in produtos_ordenados:
            nome = dados.get('nome', 'N/A')[:30]
            
            # Categoria
            cat_id = dados.get('categoria_id', '')
            cat_name = "N/A"
            if cat_id and hasattr(self, 'categories') and cat_id in self.categories:
                cat_name = self.categories[cat_id].get('nome', 'N/A')[:18]
            
            # Preço
            preco_val = parse_br_float(dados.get('preco', 0.0))
            if preco_val is None:
                preco_val = 0.0
            tipo_val = dados.get('tipo', 'unidade')
            preco_str = format_br_currency(preco_val) + sufixo_preco_produto(tipo_val)
            
            # Estoque
            estoque_val = parse_br_float(dados.get('estoque', 0.0))
            if estoque_val is None:
                estoque_val = 0.0
            estoque_str = formatar_estoque_produto(estoque_val, tipo_val)
            
            # Linha principal do produto
            report += f"{nome:<22}{estoque_str:>12}{preco_str:>12}\n"
            
            # Adiciona informações de entrada (últimas 3 entradas)
            if prod_id in entradas_por_produto:
                entradas = entradas_por_produto[prod_id][:3]
                
                report += f"  Entradas:\n"
                report += f"  {'DATA':<11}{'FORN':<16}{'QTD':>8}{'CUSTO':>11}\n"
                report += f"  {'-' * 46}\n"
                
                for entrada in entradas:
                    data_nota = entrada['data_nota'][:10]
                    fornecedor = entrada['fornecedor'][:16]
                    qtd_entrada = format_br_float(entrada['quantidade'], 3)
                    custo_entrada = format_br_currency(entrada['custo_unitario'])
                    
                    report += f"  {data_nota:<11}{fornecedor:<16}{qtd_entrada:>8}{custo_entrada:>11}\n"
                
                if len(entradas_por_produto[prod_id]) > 3:
                    report += f"  +{len(entradas_por_produto[prod_id]) - 3} entrada(s)\n"
                
                report += "\n"
            else:
                report += f"  Sem entradas registradas\n\n"
        
        report += "=" * 48 + "\n"
        report += f"Total: {len(self.products)} produtos\n"
        report += f"Com entradas: {len(entradas_por_produto)}\n"
        report += "=" * 48 + "\n"
        
        # Exibe o relatório em uma janela
        ReportWindow(self.root, "Relatório de Estoque com Datas de Entrada", report, self)

    # --- Funções de Saída ---


    def export_all_data(self):
        """Exporta todos os dados do sistema para backup manual."""
        try:
            AUDITORIA.processo("Exportando todos os dados")
        except Exception:
            pass
        if not check_permission("config.exportar_dados"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para exportar dados.")
            return
        try:
            from tkinter import filedialog
            import zipfile
            
            # Pergunta onde salvar
            export_path = filedialog.asksaveasfilename(
                parent=self.root,
                title="Exportar Dados do Sistema",
                defaultextension=".zip",
                filetypes=[("Arquivo ZIP", "*.zip"), ("Todos os arquivos", "*.*")],
                initialfile=f"pdv_backup_{datetime.datetime.now().strftime('%Y%m%d_%H%M%S')}.zip"
            )
            
            if not export_path:
                return
            
            # Cria arquivo ZIP com todos os dados
            with zipfile.ZipFile(export_path, 'w', zipfile.ZIP_DEFLATED) as zipf:
                # Adiciona todos os arquivos JSON
                for root_dir, dirs, files in os.walk(DATA_DIR):
                    for file in files:
                        if file.endswith('.json'):
                            file_path = os.path.join(root_dir, file)
                            arcname = os.path.relpath(file_path, PERSISTENCE_DIR)
                            zipf.write(file_path, arcname)
            
            messagebox.showinfo(
                "Sucesso",
                f"Dados exportados com sucesso!\n\nArquivo: {export_path}",
                parent=self.root
            )
            log_user_action("Exportar Dados", f"Dados exportados para: {export_path}")
            AUDIT_LOGGER.info("Exportação de dados realizada", user=logged_user, details=export_path)
        except Exception as e:
            messagebox.showerror("Erro", f"Erro ao exportar dados: {e}", parent=self.root)
            AUDIT_LOGGER.error("Erro na exportação de dados", user=logged_user, details=str(e))

