    # MÉTODOS DE INTEGRAÇÃO COM BALANÇA
    # ═══════════════════════════════════════════════════════════════════════════
    
    def _inicializar_balanca(self):
        """Inicializa o sistema de balança"""
        self.balanca_config_file = os.path.join(PERSISTENCE_DIR, "balanca_config.json")
        self.balanca_config_manager = ConfiguracaoBalancaManager(self.balanca_config_file)
        self.balanca_gerenciador = None
        self.balanca_conectada = False
        self.balanca_ultima_leitura = None
        
        # Tenta carregar configuração existente
        config = self.balanca_config_manager.obter_balanca_padrao()
        if config:
            self.balanca_gerenciador = GerenciadorBalanca(config)
            logger.info(f"Configuração de balança carregada: {config.nome}")
    
    def abrir_configuracao_balanca(self):
        """Abre janela de configuração de balança"""
        try:
            AUDITORIA.configuracao("Abrindo configuração de balança")
        except Exception:
            pass
        if not check_permission("balanca.configurar"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para configurar a balança.")
            return
        def callback_salvar(config):
            self.balanca_gerenciador = GerenciadorBalanca(config)
            log_user_action("Balança", f"Configuração salva: {config.nome}")
        
        ConfiguracaoBalancaWindow(self.root, self.balanca_config_manager, callback_salvar)
    
    def conectar_balanca(self) -> bool:
        """Conecta à balança configurada"""
        if not check_permission("balanca.configurar"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para configurar a balança.")
            return False
        if not self.balanca_gerenciador:
            messagebox.showwarning("Balança", "Nenhuma balança configurada.\n\n"
                                  "Configure a balança em: Menu Balança > Configurar Balança")
            return False
        
        try:
            if self.balanca_gerenciador.conectar():
                self.balanca_conectada = True
                messagebox.showinfo("Balança", "✅ Balança conectada com sucesso!")
                log_user_action("Balança", "Conectada")
                return True
            else:
                messagebox.showerror("Balança", "Não foi possível conectar à balança.\n\n"
                                   "Verifique se está ligada e conectada corretamente.")
                return False
        except Exception as e:
            messagebox.showerror("Erro", f"Erro ao conectar à balança:\n{e}")
            return False
    
    def desconectar_balanca(self):
        """Desconecta da balança"""
        if not check_permission("balanca.configurar"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para configurar a balança.")
            return
        if self.balanca_gerenciador:
            self.balanca_gerenciador.desconectar()
        self.balanca_conectada = False
        messagebox.showinfo("Balança", "Balança desconectada.")
        log_user_action("Balança", "Desconectada")
    
    def pesar_produto_balanca(self):
        """Pesa o produto selecionado usando a balança"""
        try:
            AUDITORIA.processo("Pesando produto na balança")
        except Exception:
            pass
        if not check_permission("balanca.pesar"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para pesar produtos.")
            return
        # Verifica se há produto selecionado
        prod_id = None
        
        # Tenta pegar do carrinho primeiro
        selected = self.tree_carrinho.selection()
        if selected:
            prod_id = selected[0]
        
        # Se não, tenta da lista de produtos
        if not prod_id:
            selected = self.tree_produtos.selection()
            if selected:
                prod_id = selected[0]
        
        if not prod_id:
            # Abre pesagem genérica
            peso = self._realizar_pesagem()
            if peso is not None:
                messagebox.showinfo("Peso Lido", 
                                   f"Peso: {peso:,.3f}g\n\n"
                                   f"Selecione um produto para aplicar o peso.")
            return
        
        # Verifica se é produto do tipo peso
        produto = self.products.get(prod_id, {})
        tipo = produto.get('tipo', 'unidade')
        
        if tipo != 'peso':
            messagebox.showwarning("Tipo de Produto", 
                                  "Este produto não é vendido por peso.\n\n"
                                  "A pesagem só funciona para produtos do tipo 'peso'.")
            return
        
        # Realiza a pesagem
        peso = self._realizar_pesagem(produto.get('nome', 'Produto'))
        
        if peso is None:
            return
        
        # Aplica o peso no carrinho
        self._aplicar_peso_carrinho(prod_id, peso)
    
    def _realizar_pesagem(self, nome_produto: str = "Produto") -> Optional[float]:
        """Realiza uma pesagem e retorna o peso em gramas"""
        # Se não tem gerenciador, usa balança virtual
        if not self.balanca_gerenciador:
            config = ConfiguracaoBalanca(
                nome="Balança Virtual",
                tipo_conexao=TipoConexao.VIRTUAL,
                config_serial=ConfiguracaoSerial(),
                config_protocolo=ConfiguracaoProtocolo()
            )
            self.balanca_gerenciador = GerenciadorBalanca(config)
        
        # Conecta se necessário
        if not self.balanca_gerenciador.esta_conectado():
            self.balanca_gerenciador.conectar()
        
        # Abre diálogo de pesagem
        dialogo = DialogoPesagemPDV(self.root, self.balanca_gerenciador, f"Pesagem: {nome_produto}")
        self.root.wait_window(dialogo)
        
        if dialogo.resultado is not None:
            log_user_action("Balança", f"Pesagem realizada: {dialogo.resultado:.3f}g")
        
        return dialogo.resultado
    
    def _aplicar_peso_carrinho(self, prod_id: str, peso_gramas: float):
        """Aplica o peso lido no carrinho"""
        # Se o produto já está no carrinho, atualiza
        if prod_id in self.carrinho:
            self.carrinho[prod_id]['quantidade_peso'] = peso_gramas
            log_user_action("Balança", f"Peso atualizado no carrinho: {peso_gramas:.3f}g")
        else:
            # Adiciona ao carrinho com o peso
            self.adicionar_produto_por_id(prod_id, quantidade_predefinida=peso_gramas)
            log_user_action("Balança", f"Produto adicionado com peso: {peso_gramas:.3f}g")
        
        # Atualiza a visualização
        self._atualizar_carrinho_e_total()
    
    def abrir_monitor_peso(self):
        """Abre janela de monitoramento de peso em tempo real"""
        if not self.balanca_gerenciador:
            messagebox.showwarning("Balança", "Configure uma balança primeiro.")
            return
        
        if not self.balanca_gerenciador.esta_conectado():
            if not self.conectar_balanca():
                return
        
        MonitorPesoWindowPDV(self.root, self)
    
    def testar_balanca_virtual(self):
        """Testa o sistema com uma balança virtual"""
        if not check_permission("balanca.configurar"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para testar a balança virtual.")
            return
        # Cria configuração de balança virtual
        config = ConfiguracaoBalanca(
            nome="Balança Virtual (Teste)",
            tipo_conexao=TipoConexao.VIRTUAL,
            config_serial=ConfiguracaoSerial(),
            config_protocolo=ConfiguracaoProtocolo()
        )
        
        # Cria gerenciador temporário
        gerenciador_teste = GerenciadorBalanca(config)
        gerenciador_teste.conectar()
        
        # Realiza leitura de teste
        leitura = gerenciador_teste.ler_peso()
        
        if leitura.valido:
            peso_str = f"{leitura.peso_liquido:,.3f}".replace(',', 'X').replace('.', ',').replace('X', '.')
            messagebox.showinfo("Teste de Balança Virtual", 
                               f"✅ Balança virtual funcionando!\n\n"
                               f"Peso simulado: {peso_str} {leitura.unidade.value}\n"
                               f"Estado: {'Estável' if leitura.estavel else 'Instável'}\n\n"
                               f"A balança virtual gera pesos aleatórios para teste.")
        else:
            messagebox.showerror("Erro", f"Erro no teste: {leitura.mensagem_erro}")
        
        gerenciador_teste.desconectar()


