    def _inicializar_impressora_termica(self):
        """Inicializa o sistema de impressora térmica"""
        self.impressora_config_file = os.path.join(PERSISTENCE_DIR, "impressora_config.json")
        self.multi_impressora_config_file = os.path.join(PERSISTENCE_DIR, "multi_impressora_config.json")
        self.thermal_printer_manager = None
        self.multi_printer_manager = None
        self.impressora_conectada = False
    
        # Tenta carregar configuração existente da impressora padrão
        try:
            if os.path.exists(self.impressora_config_file):
                with open(self.impressora_config_file, 'r', encoding='utf-8') as f:
                    config = json.load(f)
            
                if config.get('habilitada', False):
                    self.thermal_printer_manager = ThermalPrinterManagerPDV(config)
                    logger.info(f"Configuração de impressora carregada: {config.get('nome', 'Impressora')}")
        except Exception as e:
            logger.warning(f"Erro ao carregar configuração de impressora: {e}")
        
        # Inicializa o gerenciador de múltiplas impressoras
        try:
            self.multi_printer_manager = MultiPrinterManager(
                self.multi_impressora_config_file,
                self.categories,
                self.thermal_printer_manager
            )
            if self.multi_printer_manager.is_enabled():
                logger.info("Sistema de múltiplas impressoras habilitado")
        except Exception as e:
            logger.warning(f"Erro ao inicializar múltiplas impressoras: {e}")

    def abrir_configuracao_impressora(self):
        """Abre janela de configuração de impressora térmica"""
        try:
            AUDITORIA.configuracao("Abrindo configuração de impressora")
        except Exception:
            pass
        if not check_permission("impressora.configurar"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para configurar a impressora.")
            return
        def callback_salvar(config):
            # Salva configuração
            with open(self.impressora_config_file, 'w', encoding='utf-8') as f:
                json.dump(config, f, ensure_ascii=False, indent=2)
            
            # Recarrega o gerenciador
            if config.get('habilitada', False):
                self.thermal_printer_manager = ThermalPrinterManagerPDV(config)
            else:
                self.thermal_printer_manager = None
            
            log_user_action("Impressora", f"Configuração salva: {config.get('nome', 'Impressora')}")
        
        ConfiguracaoImpressoraWindow(self.root, self.impressora_config_file, callback_salvar)

    def abrir_configuracao_impressora_etiquetas(self):
        """Abre a configuração própria da impressora de etiquetas pelo menu Impressora."""
        try:
            AUDITORIA.configuracao("Abrindo configuração de impressora de etiquetas")
        except Exception:
            pass
        if not check_permission("impressora.configurar"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para configurar a impressora de etiquetas.")
            return

        label_printer_config_file = _label_get_own_printer_config_path()

        def _ativar_impressora_propria_nas_etiquetas():
            """Faz a tela de etiquetas usar automaticamente a impressora própria configurada aqui."""
            try:
                label_cfg_file = 'label_config.json'
                cfg = {}
                if os.path.exists(label_cfg_file):
                    with open(label_cfg_file, 'r', encoding='utf-8') as f:
                        loaded = json.load(f)
                    if isinstance(loaded, dict):
                        cfg = loaded
                cfg['impressora'] = LABEL_OWN_PRINTER_OPTION
                cfg['usar_impressora_propria_etiquetas'] = True
                cfg['usar_impressora_configurada'] = False
                cfg.setdefault('etiqueta', '60x40mm')
                cfg.setdefault('layout', 'padrao')
                cfg.setdefault('largura_custom', 60)
                cfg.setdefault('altura_custom', 40)
                with open(label_cfg_file, 'w', encoding='utf-8') as f:
                    json.dump(cfg, f, ensure_ascii=False, indent=2)
            except Exception as e:
                try:
                    logger.warning(f"Não foi possível ativar a impressora própria das etiquetas: {e}")
                except Exception:
                    pass

        def callback_salvar(config):
            # Garante que a configuração própria das etiquetas fique salva em arquivo separado.
            try:
                with open(label_printer_config_file, 'w', encoding='utf-8') as f:
                    json.dump(config, f, ensure_ascii=False, indent=2)
            except Exception as e:
                messagebox.showerror("Erro", f"Não foi possível salvar a impressora de etiquetas:\n{e}")
                return

            _ativar_impressora_propria_nas_etiquetas()
            try:
                log_user_action("Impressora", f"Configuração da impressora de etiquetas salva: {config.get('nome', 'Impressora de Etiquetas')}")
            except Exception:
                pass
            messagebox.showinfo(
                "Impressora de Etiquetas",
                "Configuração salva.\n\nAs impressões de etiquetas agora usarão esta impressora escolhida no menu Impressora > Configurar Impressora de Etiquetas.",
                parent=self.root
            )

        ConfiguracaoImpressoraWindow(self.root, label_printer_config_file, callback_salvar)

