    def imprimir_cupom_termico(self, dados_venda: dict):
        """
        Imprime cupom de venda na impressora térmica.
    
        Args:
            dados_venda: Dicionário com dados da venda
        """
        try:
            AUDITORIA.impressao("Imprimindo cupom térmico")
        except Exception:
            pass
        if not self.thermal_printer_manager or not self.thermal_printer_manager.is_enabled():
            return False
    
        try:
            # Prepara dados do cupom
            empresa = self.empresa_data
        
            receipt_data = {
                'company_name': empresa.get('nome', 'EMPRESA'),
                'company_info': [
                    empresa.get('endereco', ''),
                    f"CNPJ: {empresa.get('cnpj', '')}",
                    f"Tel: {empresa.get('telefone', '')}"
                ],
                'items': [],
                'subtotal': dados_venda.get('subtotal', 0),
                'discount': dados_venda.get('desconto', 0),
                'total': dados_venda.get('total', 0),
                'payment_method': dados_venda.get('forma_pagamento', ''),
                'payment_value': dados_venda.get('valor_pago', 0),
                'change': dados_venda.get('troco', 0),
                'receipt_number': dados_venda.get('numero_cupom', ''),
                'operator': logged_user,
                'vendedor': dados_venda.get('vendedor_nome', ''),
                'entregador': dados_venda.get('entregador_nome', ''),
                'is_delivery': dados_venda.get('is_delivery', False),
                'footer_lines': [
                    empresa.get('mensagem_cupom', 'Obrigado pela preferência!')
                ] + (['--- POLITICA DE TROCA ---'] + [empresa.get('politica_troca', '')[:200]] if empresa.get('politica_troca', '') else []),
                'customer_data': {
                    'nome': dados_venda.get('cliente_nome', ''),
                    'cpf': dados_venda.get('cliente_cpf', ''),
                    'telefone': dados_venda.get('cliente_telefone', ''),
                    'endereco': dados_venda.get('cliente_endereco', '')
                }
            }
        
            # Adiciona itens
            for item in dados_venda.get('itens', []):
                receipt_data['items'].append({
                    'description': item.get('nome', ''),
                    'quantity': item.get('quantidade', 1),
                    'unit_price': item.get('preco_unitario', 0),
                    'total': item.get('total', 0)
                })
        
            return self.thermal_printer_manager.print_receipt(receipt_data)
        except Exception as e:
            logger.error(f"Erro ao imprimir cupom térmico: {e}")
            return False


    def _on_closing(self):
        # Pergunta de confirmação geral
        if not messagebox.askyesno("Confirmar Saída", "Deseja realmente fechar o sistema?"):
            AUDITORIA.info("Usuário cancelou o fechamento do sistema")
            return

        AUDITORIA.processo("Usuário confirmou fechamento do sistema - Iniciando encerramento")
        self.is_running = False
        try:
            if self.carrinho:
                if not messagebox.askokcancel("Sair", "Há itens no carrinho. Sair e perder a venda atual?"):
                    AUDITORIA.info("Usuário cancelou fechamento - Carrinho com itens")
                    self.is_running = True
                    return
                else:
                    AUDITORIA.info(f"Usuário confirmou saída com {len(self.carrinho)} itens no carrinho (venda perdida)")
            
            # Backups e Logs
            try:
                BACKUP_SYSTEM.create_backup(PRODUCTS_FILE)
                BACKUP_SYSTEM.create_backup(SALES_FILE)
                AUDIT_LOGGER.info("Sistema encerrado com sucesso.", user=logged_user)
                save_data(CONFIG_FILE, self.config_data)
                AUDITORIA.backup("Backup automático de encerramento realizado")
            except Exception as e:
                AUDITORIA.erro(f"Erro no backup de encerramento: {e}")
            
            AUDITORIA.processo("Sistema sendo encerrado pelo usuário")
            self.root.destroy()
        except Exception as e:
            AUDITORIA.erro(f"Erro durante encerramento: {e}")
        finally:
            import sys
            sys.exit(0)
    
    def show_sales_by_customer_report(self):
        """Gera e exibe o relatório de vendas por cliente (hoje)."""
        if not check_permission("relatorios.vendas_cliente"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar este relatório.")
            return
        today_str = datetime.date.today().isoformat()
        sales_today = [
            sale for sale in self.sales_log
            if isinstance(sale, dict) and sale.get('timestamp', '').startswith(today_str)
        ]
        if not sales_today:
            messagebox.showinfo("Relatório", "Nenhuma venda hoje.", parent=self.root)
            return

        sales_by_cust = defaultdict(lambda: {"nome": "", "num_vendas": 0, "total": 0.0})
        for sale in sales_today:
            cust_id = sale.get('cliente_id', 'N/A')
            cust_nome = sale.get('cliente_nome', 'N/A')
            total = sale.get('total', 0.0)
            sales_by_cust[cust_id]["nome"] = cust_nome
            sales_by_cust[cust_id]["num_vendas"] += 1
            sales_by_cust[cust_id]["total"] += total

        report = "=" * 48 + "\n"
        report += "VENDAS POR CLIENTE".center(48) + "\n"
        report += f"{datetime.date.today().strftime('%d/%m/%Y')}".center(48) + "\n"
        report += "=" * 48 + "\n"
        report += f"{'CLIENTE':<22}{'QTD':>6}{'TOTAL':>18}\n"
        report += "-" * 48 + "\n"
        for cust_id, data in sorted(sales_by_cust.items(), key=lambda x: int(x[0]) if x[0].isdigit() else x[0]):
            nome = data["nome"][:24]
            num = data["num_vendas"]
            total = data["total"]
            total_str = format_br_currency(total)
            report += f"{nome[:22]:<22}{num:>6}{total_str:>18}\n"
        report += "=" * 48 + "\n"

        ReportWindow(self.root, "Vendas por Cliente", report, self)

    def show_monthly_sales_report(self):
        """Gera e exibe o relatório de vendas do mês atual agrupado por dia."""
        if not check_permission("relatorios.vendas_mensal"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar este relatório.")
            return
        hoje = datetime.date.today()
        ano_atual = hoje.year
        mes_atual = hoje.month

        sales_this_month = [
            sale for sale in self.sales_log
            if isinstance(sale, dict)
            and sale.get('timestamp', '').startswith(f"{ano_atual:04d}-{mes_atual:02d}")
        ]
        if not sales_this_month:
            messagebox.showinfo("Relatório", f"Nenhuma venda em {mes_atual:02d}/{ano_atual}.", parent=self.root)
            return

        sales_by_day = defaultdict(lambda: {"num_vendas": 0, "total": 0.0})
        for sale in sales_this_month:
            data_iso = sale.get('timestamp', '')[:10]
            try:
                data_date = datetime.datetime.fromisoformat(sale['timestamp']).date()
            except Exception:
                continue
            total = sale.get('total', 0.0)
            sales_by_day[data_date]["num_vendas"] += 1
            sales_by_day[data_date]["total"] += total

        mes_str = hoje.strftime("%m/%Y")
        report = "=" * 48 + "\n"
        report += f"VENDAS DO MES {mes_str}".center(48) + "\n"
        report += "=" * 48 + "\n"
        report += f"{'DATA':<12}{'QTD':>8}{'TOTAL':>26}\n"
        report += "-" * 48 + "\n"
        for dia in sorted(sales_by_day.keys()):
            num = sales_by_day[dia]["num_vendas"]
            total = sales_by_day[dia]["total"]
            total_str = format_br_currency(total)
            report += f"{dia.strftime('%d/%m/%Y'):<12}{num:>8}{total_str:>26}\n"
        report += "-" * 48 + "\n"
        total_mes = sum(d["total"] for d in sales_by_day.values())
        report += f"TOTAL MES:{format_br_currency(total_mes):>37}\n"
        report += "=" * 48 + "\n"

        ReportWindow(self.root, f"Relatório de Vendas Mês {mes_str}", report, self)

    def show_sales_by_category_report(self):
        """Gera e exibe o relatório de vendas por categoria (hoje)."""
        try:
            AUDITORIA.processo("Relatório de vendas por categoria")
        except Exception:
            pass
        if not check_permission("relatorios.vendas_categoria"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar este relatório.")
            return
        today_str = datetime.date.today().isoformat()
        sales_today = [
            sale for sale in self.sales_log
            if isinstance(sale, dict) and sale.get('timestamp', '').startswith(today_str)
        ]
        if not sales_today:
            messagebox.showinfo("Relatório", "Nenhuma venda hoje.", parent=self.root)
            return

        sales_by_cat = defaultdict(lambda: {"nome": "", "valor": 0.0})
        for sale in sales_today:
            itens = sale.get('itens', {})
            if not isinstance(itens, dict): continue
            for prod_id, item_data in itens.items():
                preco_base = parse_br_float(item_data.get('preco', 0.0)) or 0.0
                qtd = parse_br_float(item_data.get('quantidade_peso', 0.0)) or 0.0
                subtotal_base = preco_base * qtd
                desconto_item = parse_br_float(item_data.get('desconto', 0.0)) or 0.0
                acrescimo_item = parse_br_float(item_data.get('acrescimo', 0.0)) or 0.0
                subtotal = max(0.0, subtotal_base - desconto_item + acrescimo_item)

                prod_data = self.products.get(prod_id, {})
                cat_id = str(prod_data.get('category_id', ''))
                cat_nome = self.categories.get(cat_id, {}).get('nome', 'Sem Categoria')
                sales_by_cat[cat_id]["nome"] = cat_nome
                sales_by_cat[cat_id]["valor"] += subtotal

        report = "=" * 48 + "\n"
        report += "VENDAS POR CATEGORIA".center(48) + "\n"
        report += f"{datetime.date.today().strftime('%d/%m/%Y')}".center(48) + "\n"
        report += "=" * 48 + "\n"
        report += f"{'CATEGORIA':<28}{'TOTAL':>18}\n"
        report += "-" * 48 + "\n"
        for cat_id, data in sorted(
            sales_by_cat.items(),
            key=lambda x: (0, int(str(x[0]).strip())) if str(x[0]).strip().isdigit() else (1, str(x[0]).strip().lower())
        ):
            nome = data["nome"][:24]
            total = data["valor"]
            total_str = format_br_currency(total)
            report += f"{nome[:28]:<28}{total_str:>18}\n"
        report += "=" * 48 + "\n"

        ReportWindow(self.root, "Vendas por Categoria", report, self)

    def show_customers_report(self):
        """Gera e exibe o relatório de clientes cadastrados."""
        if not check_permission("relatorios.clientes"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar este relatório.")
            return
        if not isinstance(self.customers, dict) or not self.customers:
            messagebox.showinfo("Relatório", "Nenhum cliente cadastrado.", parent=self.root)
            return

        report = "=" * 48 + "\n"
        report += "CLIENTES CADASTRADOS".center(48) + "\n"
        report += f"{datetime.datetime.now().strftime('%d/%m/%Y %H:%M')}".center(48) + "\n"
        report += "=" * 48 + "\n"
        report += f"{'NOME':<22}{'TELEFONE':>14}\n"
        report += "-" * 48 + "\n"
        for cust_id in sorted(self.customers.keys(), key=lambda x: int(x) if x.isdigit() else x):
            data = self.customers[cust_id]
            nome = data.get('nome', '')[:24]
            telefone = data.get('telefone', '')
            bairro = data.get('bairro', '')
            report += f"{nome[:22]:<22}{telefone:>14}\n"
            if bairro:
                report += f"  Bairro: {bairro[:38]}\n"
        report += "=" * 48 + "\n"

        ReportWindow(self.root, "Clientes Cadastrados", report, self)

    def show_cashback_report(self):
        """Gera e exibe o relatório de Cashback (Fidelidade) dos clientes com detalhes das vendas e filtro."""
        if not check_permission("relatorios.cashback"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para visualizar o relatório de cashback.")
            return
        
        if not isinstance(self.customers, dict) or not self.customers:
            messagebox.showinfo("Relatório", "Nenhum cliente cadastrado.", parent=self.root)
            return
        
        # Janela de filtro
        filter_win = tk.Toplevel(self.root)
        filter_win.title("💰 Relatório de Cashback - Filtros")
        filter_win.state('zoomed')
        filter_win.transient(self.root)
        filter_win.grab_set()
        
        # Frame principal
        main_frame = ttk.Frame(filter_win, padding=15)
        main_frame.pack(fill=tk.BOTH, expand=True)
        
        ttk.Label(main_frame, text="💰 RELATÓRIO DE CASHBACK (FIDELIDADE)", 
                 font=("Segoe UI", 14, "bold")).pack(pady=(0, 15))
        
        # Frame de pesquisa
        search_frame = tk.LabelFrame(main_frame, text="Filtrar Cliente", padx=10, pady=10)
        search_frame.pack(fill=tk.X, pady=(0, 10))
        
        ttk.Label(search_frame, text="🔍 Pesquisar:").pack(side=tk.LEFT, padx=(0, 5))
        search_var = tk.StringVar()
        search_entry = ttk.Entry(search_frame, textvariable=search_var, width=30)
        search_entry.pack(side=tk.LEFT, padx=(0, 10))
        ttk.Label(search_frame, text="(Nome, ID ou Telefone)", foreground="gray").pack(side=tk.LEFT)
        
        # Frame da lista de clientes
        list_frame = tk.LabelFrame(main_frame, text="Selecione os Clientes", padx=10, pady=10)
        list_frame.pack(fill=tk.BOTH, expand=True, pady=(0, 10))
        
        # Treeview com checkboxes
        cols = ('selecionado', 'id', 'nome', 'telefone', 'saldo')
        tree = ttk.Treeview(list_frame, columns=cols, show='headings', height=12)
        
        tree.heading('selecionado', text='✔')
        tree.heading('id', text='ID')
        tree.heading('nome', text='Nome')
        tree.heading('telefone', text='Telefone')
        tree.heading('saldo', text='Saldo Cashback')
        
        tree.column('selecionado', width=40, anchor=tk.CENTER)
        tree.column('id', width=50, anchor=tk.CENTER)
        tree.column('nome', width=200)
        tree.column('telefone', width=120)
        tree.column('saldo', width=120, anchor=tk.E)
        
        scroll = ttk.Scrollbar(list_frame, orient=tk.VERTICAL, command=tree.yview)
        tree.configure(yscrollcommand=scroll.set)
        
        tree.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
        scroll.pack(side=tk.RIGHT, fill=tk.Y)
        
        # Dicionário para controlar seleção
        clientes_selecionados = {}
        
        # Carregar clientes na lista
        def carregar_clientes(filtro=""):
            tree.delete(*tree.get_children())
            filtro = filtro.lower().strip()
            
            for cust_id, cust_data in sorted(self.customers.items(), key=lambda x: x[0]):
                if cust_id == '1':  # Pular Consumidor Final
                    continue
                
                nome = cust_data.get('nome', 'N/A')
                telefone = cust_data.get('telefone', '')
                saldo = parse_br_float(cust_data.get('saldo_fidelidade', 0.0)) or 0.0
                
                # Aplicar filtro
                if filtro:
                    if not (filtro in cust_id.lower() or 
                            filtro in nome.lower() or 
                            filtro in telefone.lower().replace('-', '').replace(' ', '')):
                        continue
                
                # Verificar se está selecionado
                check = '✔' if clientes_selecionados.get(cust_id, False) else ''
                
                tree.insert('', tk.END, iid=cust_id, values=(
                    check,
                    cust_id,
                    nome[:30],
                    telefone,
                    format_br_currency(saldo)
                ))
        
        # Toggle seleção ao clicar
        def toggle_selecao(event):
            item = tree.identify_row(event.y)
            if item:
                clientes_selecionados[item] = not clientes_selecionados.get(item, False)
                carregar_clientes(search_var.get())
        
        tree.bind('<ButtonRelease-1>', toggle_selecao)
        
        # Atualizar lista ao digitar
        def on_search(*args):
            carregar_clientes(search_var.get())
        
        search_var.trace_add('write', on_search)
        
        # Botões de seleção rápida
        btn_sel_frame = ttk.Frame(main_frame)
        btn_sel_frame.pack(fill=tk.X, pady=(0, 10))
        
        def selecionar_todos():
            for item in tree.get_children():
                clientes_selecionados[item] = True
            carregar_clientes(search_var.get())
        
        def desmarcar_todos():
            clientes_selecionados.clear()
            carregar_clientes(search_var.get())
        
        def selecionar_com_saldo():
            for cust_id, cust_data in self.customers.items():
                if cust_id == '1':
                    continue
                saldo = parse_br_float(cust_data.get('saldo_fidelidade', 0.0)) or 0.0
                if saldo > 0:
                    clientes_selecionados[cust_id] = True
            carregar_clientes(search_var.get())
        
        ttk.Button(btn_sel_frame, text="✔ Selecionar Todos", command=selecionar_todos, 
                  bootstyle="info-outline", width=18).pack(side=tk.LEFT, padx=2)
        ttk.Button(btn_sel_frame, text="✖ Desmarcar Todos", command=desmarcar_todos, 
                  bootstyle="secondary-outline", width=18).pack(side=tk.LEFT, padx=2)
        ttk.Button(btn_sel_frame, text="💰 Com Saldo > 0", command=selecionar_com_saldo, 
                  bootstyle="success-outline", width=18).pack(side=tk.LEFT, padx=2)
        
        # Botões de ação
        btn_frame = ttk.Frame(main_frame)
        btn_frame.pack(fill=tk.X, pady=(10, 0))
        
        def gerar_relatorio():
            # Verificar se há clientes selecionados
            selecionados = [k for k, v in clientes_selecionados.items() if v]
            
            # Coletar vendas por cliente para calcular cashback gerado
            vendas_por_cliente = {}
            for venda in self.sales_log:
                if not isinstance(venda, dict):
                    continue
                cliente_id = str(venda.get('cliente_id', '1'))
                if cliente_id == '1':  # Pular Consumidor Final
                    continue
                
                total_venda = venda.get('total', 0.0)
                cashback_gerado = total_venda * 0.01  # 1% de cashback
                
                if cliente_id not in vendas_por_cliente:
                    vendas_por_cliente[cliente_id] = []
                
                vendas_por_cliente[cliente_id].append({
                    'cupom': venda.get('coupon_number', 'N/A'),
                    'data': venda.get('data', venda.get('timestamp', '')[:10] if venda.get('timestamp') else 'N/A'),
                    'total_venda': total_venda,
                    'cashback': cashback_gerado
                })
            
            # Coletar dados de cashback dos clientes
            clientes_com_cashback = []
            total_cashback_disponivel = 0.0
            total_cashback_gerado = 0.0
            
            for cust_id, cust_data in self.customers.items():
                if cust_id == '1':  # Pular Consumidor Final
                    continue
                
                # Se há filtro de clientes, aplicar
                if selecionados and cust_id not in selecionados:
                    continue
                
                saldo_fidelidade = parse_br_float(cust_data.get('saldo_fidelidade', 0.0)) or 0.0
                vendas_cliente = vendas_por_cliente.get(cust_id, [])
                
                # Calcular total de cashback gerado nas vendas
                cashback_total_gerado = sum(v['cashback'] for v in vendas_cliente)
                total_cashback_gerado += cashback_total_gerado
                
                if saldo_fidelidade > 0 or vendas_cliente:
                    clientes_com_cashback.append({
                        'id': cust_id,
                        'nome': cust_data.get('nome', 'N/A'),
                        'telefone': cust_data.get('telefone', ''),
                        'saldo': saldo_fidelidade,
                        'vendas': vendas_cliente,
                        'cashback_gerado': cashback_total_gerado
                    })
                    total_cashback_disponivel += saldo_fidelidade
            
            # Ordenar por saldo (maior para menor)
            clientes_com_cashback.sort(key=lambda x: x['saldo'], reverse=True)
            
            # Gerar relatório
            report = "=" * 48 + "\n"
            report += "RELATORIO DE CASHBACK".center(48) + "\n"
            report += f"{datetime.datetime.now().strftime('%d/%m/%Y %H:%M')}".center(48) + "\n"
            report += "=" * 48 + "\n"
            
            if selecionados:
                report += f"FILTRO: {len(selecionados)} cliente(s)\n"
                report += "=" * 48 + "\n"
            
            if clientes_com_cashback:
                for cliente in clientes_com_cashback:
                    nome = cliente['nome'][:35]
                    telefone = cliente['telefone'][:14] if cliente['telefone'] else '-'
                    saldo_str = format_br_currency(cliente['saldo'])
                    
                    report += f"\nCLIENTE: {nome[:38]}\n"
                    report += f"ID: {cliente['id']} Tel: {telefone}\n"
                    report += f"SALDO: {saldo_str}\n"
                    report += "-" * 48 + "\n"
                    
                    if cliente['vendas']:
                        report += f"{'CUPOM':<8}{'DATA':<11}{'VENDA':>14}{'CASHBACK':>13}\n"
                        report += "-" * 48 + "\n"
                        
                        for venda in cliente['vendas']:
                            cupom_str = str(venda['cupom'])[:8]
                            data_str = str(venda['data'])[:11]
                            total_str = format_br_currency(venda['total_venda'])
                            cashback_str = format_br_currency(venda['cashback'])
                            report += f"{cupom_str:<8}{data_str:<11}{total_str:>14}{cashback_str:>13}\n"
                        
                        report += "-" * 48 + "\n"
                        report += f"TOTAL CASHBACK:{format_br_currency(cliente['cashback_gerado']):>32}\n"
                    else:
                        report += "Nenhuma venda registrada.\n"
                    
                    report += "=" * 48 + "\n"
            else:
                report += "Nenhum cliente com cashback.\n"
                report += "=" * 48 + "\n"
            
            # Resumo geral
            report += "\n"
            report += "RESUMO GERAL\n"
            report += "=" * 48 + "\n"
            report += f"Clientes:{len(clientes_com_cashback):>38}\n"
            report += f"CB Gerado:{format_br_currency(total_cashback_gerado):>37}\n"
            report += f"CB Disponivel:{format_br_currency(total_cashback_disponivel):>33}\n"
            
            cashback_utilizado = total_cashback_gerado - total_cashback_disponivel
            if cashback_utilizado > 0:
                report += f"CB Utilizado:{format_br_currency(cashback_utilizado):>34}\n"
            
            report += "=" * 48 + "\n"
            report += "\n"
            report += "INFORMACOES:\n"
            report += "-" * 48 + "\n"
            report += "Cashback: 1% do valor da compra\n"
            report += "Saldo usado como pagamento\n"
            report += "=" * 48 + "\n"
            
            filter_win.destroy()
            ReportWindow(self.root, "Relatório de Cashback (Fidelidade)", report, self)
        
        ttk.Button(btn_frame, text="📄 Gerar Relatório", command=gerar_relatorio, 
                  bootstyle="success", width=20).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="❌ Cancelar", command=filter_win.destroy, 
                  bootstyle="danger", width=15).pack(side=tk.RIGHT, padx=5)
        
        # Carregar clientes inicialmente
        carregar_clientes()
        
        # Foco no campo de pesquisa
        search_entry.focus_set()

    # ========== MÉTODOS DE ORÇAMENTO ==========
    
    def _get_proximo_numero_orcamento(self):
        """Retorna o próximo número de orçamento disponível."""
        try:
            db = get_db()
            result = db.fetchone("SELECT MAX(numero) as max_num FROM orcamentos")
            if result and result['max_num']:
                return result['max_num'] + 1
            return 1
        except Exception:
            return 1
    
    def novo_orcamento(self):
        """Abre janela para criar novo orçamento."""
        try:
            AUDITORIA.venda("Criando novo orçamento")
        except Exception:
            pass
        if not check_permission("orcamentos.criar"):
            messagebox.showerror("Acesso Negado", "Você não tem permissão para criar orçamentos.")
            return
