        orc_win.state('zoomed')  # Maximizada
        orc_win.transient(self.root)
        orc_win.grab_set()
        
        # Variáveis
        numero_orc = self._get_proximo_numero_orcamento()
        cliente_var = tk.StringVar(value="1")
        cliente_nome_var = tk.StringVar(value="Consumidor Final")
        obs_var = tk.StringVar()
        desconto_var = tk.StringVar(value="0,00")
        itens_orcamento = []
        
        # Frame principal
        main_frame = ttk.Frame(orc_win, padding=10)
        main_frame.pack(fill=tk.BOTH, expand=True)
        
        # Cabeçalho
        header_frame = ttk.Frame(main_frame)
        header_frame.pack(fill=tk.X, pady=(0, 10))
        
        ttk.Label(header_frame, text=f"📝 ORÇAMENTO Nº {numero_orc:06d}", 
                  font=("Segoe UI", 16, "bold")).pack(side=tk.LEFT)
        
        data_atual = datetime.datetime.now().strftime('%d/%m/%Y')
        ttk.Label(header_frame, text=f"Data: {data_atual}", 
                  font=("Segoe UI", 12)).pack(side=tk.RIGHT)
        
        # Barra lateral de ações
        btn_frame = tk.LabelFrame(main_frame, text="Ações do Orçamento", padx=10, pady=10)  # FIX: ttkbootstrap não tem LabelFrame
        btn_frame.pack(side=tk.RIGHT, fill=tk.Y, padx=(15, 0), pady=(0, 10), anchor='n')
        
        # Frame cliente
        cliente_frame = tk.LabelFrame(main_frame, text="Cliente", padx=10, pady=10)
        cliente_frame.pack(fill=tk.X, pady=(0, 10))
        
        ttk.Label(cliente_frame, text="Cliente:").pack(side=tk.LEFT, padx=(0, 5))
        cliente_entry = ttk.Entry(cliente_frame, textvariable=cliente_nome_var, width=40, state='readonly')
        cliente_entry.pack(side=tk.LEFT, padx=(0, 10))
        
        def selecionar_cliente():
            """Abre janela para selecionar cliente."""
            sel_win = tk.Toplevel(orc_win)
            sel_win.title("Selecionar Cliente")
            responsive_geometry(sel_win, 500, 400)
            sel_win.transient(orc_win)
            sel_win.grab_set()
            
            # Pesquisa
            search_frame = ttk.Frame(sel_win, padding=10)
            search_frame.pack(fill=tk.X)
            
            ttk.Label(search_frame, text="🔍 Buscar:").pack(side=tk.LEFT)
            search_var = tk.StringVar()
            search_entry = ttk.Entry(search_frame, textvariable=search_var, width=30)
            search_entry.pack(side=tk.LEFT, padx=5)
            
            # Lista de clientes
            tree_frame = ttk.Frame(sel_win, padding=10)
            tree_frame.pack(fill=tk.BOTH, expand=True)
            
            cols = ('id', 'nome', 'cpf', 'telefone')
            tree = ttk.Treeview(tree_frame, columns=cols, show='headings', height=12)
            tree.heading('id', text='ID')
            tree.heading('nome', text='Nome')
            tree.heading('cpf', text='CPF')
            tree.heading('telefone', text='Telefone')
            tree.column('id', width=50)
            tree.column('nome', width=200)
            tree.column('cpf', width=120)
            tree.column('telefone', width=100)
            
            scroll = ttk.Scrollbar(tree_frame, orient=tk.VERTICAL, command=tree.yview)
            tree.configure(yscrollcommand=scroll.set)
            tree.pack(side=tk.LEFT, fill=tk.BOTH, expand=True)
            scroll.pack(side=tk.RIGHT, fill=tk.Y)
            
            def carregar_clientes(filtro=''):
                tree.delete(*tree.get_children())
                for cid, cdata in self.customers.items():
                    nome = cdata.get('nome', '')
                    cpf = cdata.get('cpf', '')
                    tel = cdata.get('telefone', '')
                    if filtro.lower() in nome.lower() or filtro in cpf or filtro in tel:
                        tree.insert('', tk.END, values=(cid, nome, cpf, tel))
            
            def filtrar(*args):
                carregar_clientes(search_var.get())
            
            search_var.trace_add('write', filtrar)
            
            def confirmar():
                sel = tree.selection()
                if sel:
                    item = tree.item(sel[0])
                    cliente_var.set(item['values'][0])
                    cliente_nome_var.set(item['values'][1])
                sel_win.destroy()
            
            tree.bind('<Double-1>', lambda e: confirmar())
            
            btn_frame = ttk.Frame(sel_win, padding=10)
            btn_frame.pack(fill=tk.X)
            ttk.Button(btn_frame, text="✅ Selecionar", command=confirmar, bootstyle="success").pack(side=tk.LEFT, padx=5)
            ttk.Button(btn_frame, text="❌ Cancelar", command=sel_win.destroy, bootstyle="danger").pack(side=tk.RIGHT, padx=5)
            
            carregar_clientes()
            search_entry.focus_set()
        
        ttk.Button(cliente_frame, text="🔍 Buscar", command=selecionar_cliente, 
                   bootstyle="info", width=12).pack(side=tk.LEFT)
        
        # Frame de produtos
        prod_frame = tk.LabelFrame(main_frame, text="Adicionar Produtos", padx=10, pady=10)
        prod_frame.pack(fill=tk.X, pady=(0, 10))
        
        ttk.Label(prod_frame, text="Produto:").grid(row=0, column=0, padx=5, pady=5, sticky='w')
        prod_search_var = tk.StringVar()
        prod_combo = ttk.Combobox(prod_frame, textvariable=prod_search_var, width=40)
        prod_combo.grid(row=0, column=1, padx=5, pady=5)
        
        # Preencher combo com produtos
        produtos_lista = [(pid, pdata.get('nome', '')) for pid, pdata in self.products.items()]
        todos_produtos = [f"{p[0]} - {p[1]}" for p in produtos_lista]
        prod_combo['values'] = todos_produtos
        
        # Função de autocomplete - filtra produtos à medida que o usuário digita
        def filtrar_produtos(*args):
            """Filtra os produtos no dropdown conforme o usuário digita."""
            texto_digitado = prod_search_var.get().lower()
            if texto_digitado == '':
                prod_combo['values'] = todos_produtos
            else:
                produtos_filtrados = [p for p in todos_produtos if texto_digitado in p.lower()]
                prod_combo['values'] = produtos_filtrados
                if produtos_filtrados and not prod_combo.winfo_ismapped():
                    pass
                # Abre o dropdown automaticamente se houver resultados
                if produtos_filtrados:
                    prod_combo.event_generate('<Down>')
        
        # Bind para detectar digitação
        def on_keyrelease(event):
            """Evento disparado ao soltar uma tecla."""
            # Ignora teclas especiais
            if event.keysym in ('Return', 'Tab', 'Escape', 'Up', 'Down', 'Left', 'Right', 'Shift_L', 'Shift_R', 'Control_L', 'Control_R', 'Alt_L', 'Alt_R'):
                return
            texto_digitado = prod_search_var.get().lower()
            if texto_digitado == '':
                prod_combo['values'] = todos_produtos
            else:
                produtos_filtrados = [p for p in todos_produtos if texto_digitado in p.lower()]
                prod_combo['values'] = produtos_filtrados
        
        prod_combo.bind('<KeyRelease>', on_keyrelease)
        
        qtd_var = tk.StringVar(value="1")
        qtd_entry = ttk.Entry(prod_frame, textvariable=qtd_var, width=8)
        
        preco_var = tk.StringVar(value="0,00")
        preco_entry = ttk.Entry(prod_frame, textvariable=preco_var, width=12)
        
        def atualizar_preco(*args):
            """Atualiza o preço quando um produto é selecionado."""
            try:
                sel = prod_search_var.get()
                if ' - ' in sel:
                    pid = sel.split(' - ')[0].strip()
                    if pid in self.products:
                        preco = self.products[pid].get('preco', 0)
                        preco_var.set(format_br_currency(preco).replace('R$ ', ''))
            except Exception:
                pass
        
        prod_combo.bind('<<ComboboxSelected>>', atualizar_preco)
        
        # Função para abrir janela de busca de produtos
        def selecionar_produto():
            """Abre janela para selecionar produto."""
            sel_win = tk.Toplevel(orc_win)
            sel_win.title("🔍 Selecionar Produto")
            responsive_geometry(sel_win, 700, 500)
            sel_win.transient(orc_win)
            sel_win.grab_set()
            
            # Centralizar janela
            sel_win.update_idletasks()
            x = (sel_win.winfo_screenwidth() // 2) - (700 // 2)
            y = (sel_win.winfo_screenheight() // 2) - (500 // 2)
            responsive_geometry(sel_win, 700, 500)
            
            # Pesquisa
            search_frame = ttk.Frame(sel_win, padding=10)
