class DialogoPesagemPDV(tk.Toplevel):
    """Diálogo para pesagem rápida no PDV"""
    
    def __init__(self, parent, gerenciador: GerenciadorBalanca, titulo: str = "Pesagem"):
        super().__init__(parent)
        self.status_bar = StatusBar(self, user_name=getattr(self, 'current_user', 'Usuário'))
        self.gerenciador = gerenciador
        self.resultado = None
        
        self.title(f"⚖️ {titulo}")
        responsive_geometry(self, 400, 350)
        self.resizable(True, True)
        self.transient(parent)
        self.grab_set()
        
        self._criar_interface()
        
        # Centraliza
        self.update_idletasks()
        x = (self.winfo_screenwidth() - self.winfo_width()) // 2
        y = (self.winfo_screenheight() - self.winfo_height()) // 2
        self.geometry(f"+{x}+{y}")
        
        # Conecta e lê automaticamente
        self.after(100, self._conectar_e_ler)
    
    def _criar_interface(self):
        """Cria interface do diálogo"""
        main_frame = ttk.Frame(self, padding=20)
        main_frame.pack(fill=tk.BOTH, expand=True)
        
        # Título
        ttk.Label(main_frame, text="Coloque o produto na balança", 
                 font=("Segoe UI", 11)).pack(pady=10)
        
        # Display de peso
        self.lbl_peso = ttk.Label(main_frame, text="Aguardando...", 
                                  font=("Segoe UI", 36, "bold"), foreground="#6c757d")
        self.lbl_peso.pack(pady=20)
        
        # Status
        self.lbl_status = ttk.Label(main_frame, text="", foreground="gray")
        self.lbl_status.pack()
        
        # Botões
        btn_frame = ttk.Frame(main_frame)
        btn_frame.pack(fill=tk.X, pady=20)
        
        ttk.Button(btn_frame, text="🔄 Ler Novamente", command=self._ler_peso,
                   bootstyle="info", width=15).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="✓ Confirmar", command=self._confirmar,
                   bootstyle="success", width=15).pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="✗ Cancelar", command=self._cancelar,
                   bootstyle="secondary", width=15).pack(side=tk.RIGHT, padx=5)
    
    def _conectar_e_ler(self):
        """Conecta e faz primeira leitura"""
        if not self.gerenciador.esta_conectado():
            self.lbl_status.config(text="Conectando...")
            if not self.gerenciador.conectar():
                self.lbl_peso.config(text="Erro", foreground="#dc3545")
                self.lbl_status.config(text="Falha na conexão")
                return
        
        self._ler_peso()
    
    def _ler_peso(self):
        """Lê o peso da balança"""
        self.lbl_status.config(text="Lendo...")
        self.update()
        
        leitura = self.gerenciador.ler_peso()
        
        if leitura.valido:
            self.resultado = leitura.peso_em_gramas()
            peso_str = f"{self.resultado:,.3f}g".replace(',', 'X').replace('.', ',').replace('X', '.')
            self.lbl_peso.config(text=peso_str, foreground="#28a745")
            self.lbl_status.config(text="✓ Peso estável" if leitura.estavel else "⚡ Peso instável")
        else:
            self.resultado = None
            self.lbl_peso.config(text="---", foreground="#dc3545")
            self.lbl_status.config(text=leitura.mensagem_erro)
    
    def _confirmar(self):
        """Confirma o peso"""
        if self.resultado is not None:
            self.destroy()
        else:
            messagebox.showwarning("Aviso", "Nenhum peso válido para confirmar", parent=self)
    
    def _cancelar(self):
        """Cancela a pesagem"""
        self.resultado = None
        self.destroy()


class MonitorPesoWindowPDV(tk.Toplevel):
    """Janela para monitoramento de peso em tempo real no PDV"""
    
    def __init__(self, parent, app):
        super().__init__(parent)
        self.status_bar = StatusBar(self, user_name=getattr(self, 'current_user', 'Usuário'))
        self.app = app
        self.leitura_ativa = False
        
        self.title("⚖️ Monitor de Peso em Tempo Real")
        responsive_geometry(self, 450, 400)
        self.resizable(True, True)
        self.transient(parent)
        
        self._criar_interface()
        self._iniciar_leitura()
        
        # Centraliza
        self.update_idletasks()
        x = (self.winfo_screenwidth() - self.winfo_width()) // 2
        y = (self.winfo_screenheight() - self.winfo_height()) // 2
        self.geometry(f"+{x}+{y}")
        
        self.protocol("WM_DELETE_WINDOW", self._on_close)
    
    def _criar_interface(self):
        """Cria interface da janela"""
        main_frame = ttk.Frame(self, padding=20)
        main_frame.pack(fill=tk.BOTH, expand=True)
        
        # Título
        ttk.Label(main_frame, text="Peso em Tempo Real", 
                 font=("Segoe UI", 14, "bold")).pack(pady=10)
        
        # Display de peso grande
        self.lbl_peso = ttk.Label(main_frame, text="---", 
                                  font=("Segoe UI", 48, "bold"), foreground="#28a745")
        self.lbl_peso.pack(pady=20)
        
        # Status
        self.lbl_status = ttk.Label(main_frame, text="", foreground="gray")
        self.lbl_status.pack()
        
        # Informações adicionais
        info_frame = ttk.Frame(main_frame)
        info_frame.pack(fill=tk.X, pady=10)
        
        ttk.Label(info_frame, text="Peso Bruto:").grid(row=0, column=0, sticky="w")
        self.lbl_bruto = ttk.Label(info_frame, text="---")
        self.lbl_bruto.grid(row=0, column=1, sticky="e", padx=10)
        
        ttk.Label(info_frame, text="Tara:").grid(row=1, column=0, sticky="w")
        self.lbl_tara = ttk.Label(info_frame, text="---")
        self.lbl_tara.grid(row=1, column=1, sticky="e", padx=10)
        
        ttk.Label(info_frame, text="Unidade:").grid(row=2, column=0, sticky="w")
        self.lbl_unidade = ttk.Label(info_frame, text="---")
        self.lbl_unidade.grid(row=2, column=1, sticky="e", padx=10)
        
        info_frame.columnconfigure(1, weight=1)
        
        # Botões
        btn_frame = ttk.Frame(main_frame)
        btn_frame.pack(fill=tk.X, pady=10)
        
        self.btn_pausar = ttk.Button(btn_frame, text="⏸️ Pausar", command=self._toggle_leitura,
                   bootstyle="warning")
        self.btn_pausar.pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="✓ Usar Este Peso", command=self._usar_peso,
                   bootstyle="success").pack(side=tk.LEFT, padx=5)
        ttk.Button(btn_frame, text="✗ Fechar", command=self._on_close,
                   bootstyle="secondary").pack(side=tk.RIGHT, padx=5)
    
    def _iniciar_leitura(self):
        """Inicia leitura contínua"""
        self.leitura_ativa = True
        self._ler_peso_loop()
    
    def _ler_peso_loop(self):
        """Loop de leitura de peso"""
        if not self.leitura_ativa or not self.winfo_exists():
            return
        
        try:
            if self.app.balanca_gerenciador and self.app.balanca_gerenciador.esta_conectado():
                leitura = self.app.balanca_gerenciador.ler_peso()
                self._atualizar_display(leitura)
                self.app.balanca_ultima_leitura = leitura
        except Exception as e:
            self.lbl_status.config(text=f"Erro: {e}", foreground="red")
        
        # Agenda próxima leitura
        if self.leitura_ativa:
            self.after(200, self._ler_peso_loop)
    
    def _atualizar_display(self, leitura):
        """Atualiza o display com a leitura"""
        if leitura.valido:
            peso_gramas = leitura.peso_em_gramas()
            peso_str = f"{peso_gramas:,.3f}g".replace(',', 'X').replace('.', ',').replace('X', '.')
            
            cor = "#28a745" if leitura.estavel else "#ffc107"
            self.lbl_peso.config(text=peso_str, foreground=cor)
            
            status = "✓ Estável" if leitura.estavel else "⚡ Instável"
            self.lbl_status.config(text=status, foreground=cor)
            
            # Informações adicionais
            self.lbl_bruto.config(text=f"{leitura.peso_bruto:,.3f}g".replace(',', 'X').replace('.', ',').replace('X', '.'))
            self.lbl_tara.config(text=f"{leitura.tara:,.3f}g".replace(',', 'X').replace('.', ',').replace('X', '.'))
            self.lbl_unidade.config(text=leitura.unidade.value)
        else:
            self.lbl_peso.config(text="---", foreground="#dc3545")
            self.lbl_status.config(text=leitura.mensagem_erro, foreground="#dc3545")
    
    def _toggle_leitura(self):
        """Liga/desliga leitura"""
        self.leitura_ativa = not self.leitura_ativa
        if self.leitura_ativa:
            self.btn_pausar.config(text="⏸️ Pausar")
            self._ler_peso_loop()
        else:
            self.btn_pausar.config(text="▶️ Continuar")
    
    def _usar_peso(self):
        """Usa o peso atual no produto selecionado"""
        if self.app.balanca_ultima_leitura and self.app.balanca_ultima_leitura.valido:
            # Verifica se há produto selecionado
            selected = self.app.tree_carrinho.selection()
            if not selected:
                selected = self.app.tree_produtos.selection()
            
            if selected:
                prod_id = selected[0]
                produto = self.app.products.get(prod_id, {})
                
                if produto.get('tipo') == 'peso':
                    peso = self.app.balanca_ultima_leitura.peso_em_gramas()
                    self.app._aplicar_peso_carrinho(prod_id, peso)
                    messagebox.showinfo("Peso Aplicado", 
                                       f"Peso de {peso:,.3f}g aplicado ao produto!".replace(',', 'X').replace('.', ',').replace('X', '.'),
                                       parent=self)
                    self._on_close()
                else:
                    messagebox.showwarning("Aviso", "Selecione um produto do tipo 'peso'.", parent=self)
            else:
                messagebox.showwarning("Aviso", "Selecione um produto primeiro.", parent=self)
        else:
            messagebox.showwarning("Aviso", "Nenhum peso válido disponível.", parent=self)
    
    def _on_close(self):
        """Fecha a janela"""
        self.leitura_ativa = False
        self.destroy()

    


# ═══════════════════════════════════════════════════════════════════════════════════════
# SISTEMA DE ANIMAÇÕES FLUIDAS E TRANSIÇÕES
# ═══════════════════════════════════════════════════════════════════════════════════════





class AnimationEngine:
    """
    Motor de Animações Fluidas para Interface Gráfica.
    
    Suporta:
    - Fade In/Out
    - Slide (esquerda, direita, cima, baixo)
    - Scale (zoom in/out)
    - Bounce
    - Elastic
    - Easing functions (ease-in, ease-out, ease-in-out)
    """
    
    # Funções de easing para animações suaves
    EASING = {
        'linear': lambda t: t,
        'ease_in': lambda t: t * t,
        'ease_out': lambda t: 1 - (1 - t) * (1 - t),
        'ease_in_out': lambda t: 2 * t * t if t < 0.5 else 1 - pow(-2 * t + 2, 2) / 2,
        'ease_in_cubic': lambda t: t * t * t,
        'ease_out_cubic': lambda t: 1 - pow(1 - t, 3),
        'ease_in_out_cubic': lambda t: 4 * t * t * t if t < 0.5 else 1 - pow(-2 * t + 2, 3) / 2,
        'ease_in_quart': lambda t: t * t * t * t,
        'ease_out_quart': lambda t: 1 - pow(1 - t, 4),
        'ease_in_out_quart': lambda t: 8 * t * t * t * t if t < 0.5 else 1 - pow(-2 * t + 2, 4) / 2,
        'bounce': lambda t: 1 - abs(math.sin(t * math.pi * 2.5) * (1 - t)),
        'elastic': lambda t: pow(2, -10 * t) * math.sin((t - 0.075) * (2 * math.pi) / 0.3) + 1 if t > 0 else 0,
    }
    
    def __init__(self, widget, duration: int = 300, fps: int = 60):
        """
        Inicializa o motor de animação.
        
        Args:
            widget: Widget Tkinter a ser animado
            duration: Duração da animação em milissegundos
            fps: Frames por segundo
        """
        self.widget = widget
        self.duration = duration
        self.fps = fps
        self.frame_time = 1000 // fps
        self._animation_id = None
        self._is_animating = False
    
    def fade_in(self, callback=None, easing='ease_out'):
        """Animação de fade in (aparecer gradualmente)."""
        self._animate_property('alpha', 0.0, 1.0, easing, callback)
    
    def fade_out(self, callback=None, easing='ease_in'):
        """Animação de fade out (desaparecer gradualmente)."""
        self._animate_property('alpha', 1.0, 0.0, easing, callback)
    
    def slide_in_left(self, distance: int = 100, callback=None, easing='ease_out'):
        """Animação de slide da esquerda."""
        self._animate_position(-distance, 0, 0, 0, easing, callback)
    
    def slide_in_right(self, distance: int = 100, callback=None, easing='ease_out'):
        """Animação de slide da direita."""
        self._animate_position(distance, 0, 0, 0, easing, callback)
    
    def slide_in_top(self, distance: int = 100, callback=None, easing='ease_out'):
        """Animação de slide de cima."""
        self._animate_position(0, -distance, 0, 0, easing, callback)
    
    def slide_in_bottom(self, distance: int = 100, callback=None, easing='ease_out'):
        """Animação de slide de baixo."""
        self._animate_position(0, distance, 0, 0, easing, callback)
    
    def pulse(self, scale: float = 1.1, callback=None):
        """Animação de pulso (escala aumenta e volta)."""
        # Implementação simplificada para Tkinter
        pass
    
    def shake(self, intensity: int = 10, callback=None):
        """Animação de shake (tremor)."""
        original_x = self.widget.winfo_x()
        original_y = self.widget.winfo_y()
        
        def do_shake(step=0):
            if step >= 10:
                self.widget.place(x=original_x, y=original_y)
                if callback:
                    callback()
                return
            
            offset = intensity * (1 - step / 10) * (1 if step % 2 == 0 else -1)
            try:
                self.widget.place(x=original_x + offset, y=original_y)
                self.widget.after(50, lambda: do_shake(step + 1))
            except tk.TclError:
                pass
        
        do_shake()
    
    def _animate_property(self, prop: str, start: float, end: float, easing: str, callback=None):
        """Anima uma propriedade do widget."""
        easing_func = self.EASING.get(easing, self.EASING['linear'])
        steps = self.duration // self.frame_time
        current_step = [0]
        
        def animate():
            if current_step[0] >= steps:
                self._is_animating = False
                if callback:
                    callback()
                return
            
            t = current_step[0] / steps
            value = start + (end - start) * easing_func(t)
            
            try:
                if prop == 'alpha':
                    # Tkinter não suporta alpha diretamente, simulamos com cores
                    pass
                current_step[0] += 1
                self._animation_id = self.widget.after(self.frame_time, animate)
            except tk.TclError:
                self._is_animating = False
        
        self._is_animating = True
        animate()
    
    def _animate_position(self, start_x: int, start_y: int, end_x: int, end_y: int, 
                         easing: str, callback=None):
        """Anima a posição do widget."""
        easing_func = self.EASING.get(easing, self.EASING['linear'])
        steps = self.duration // self.frame_time
        current_step = [0]
        
        # Posição original
        try:
            orig_x = self.widget.winfo_x()
            orig_y = self.widget.winfo_y()
        except tk.TclError:
            return
        
        def animate():
            if current_step[0] >= steps:
                self._is_animating = False
                if callback:
                    callback()
                return
            
            t = current_step[0] / steps
            ease_t = easing_func(t)
            
            x = orig_x + start_x + (end_x - start_x) * ease_t
            y = orig_y + start_y + (end_y - start_y) * ease_t
            
            try:
                self.widget.place(x=int(x), y=int(y))
                current_step[0] += 1
                self._animation_id = self.widget.after(self.frame_time, animate)
            except tk.TclError:
                self._is_animating = False
        
        self._is_animating = True
        animate()
    
    def stop(self):
        """Para a animação atual."""
        if self._animation_id:
            try:
                self.widget.after_cancel(self._animation_id)
            except tk.TclError:
                pass
        self._is_animating = False


class ModernCard(ttk.Frame):
    """
    Componente de Card Moderno com sombra e hover effects.
    
    Uso:
        card = ModernCard(parent, title="Vendas", value="R$ 1.500,00", icon="💰")
        card.pack(padx=10, pady=10)
    """
    
    def __init__(self, parent, title: str = "", value: str = "", icon: str = "",
                 color: str = "#2563eb", hover_color: str = "#1d4ed8",
                 width: int = 200, height: int = 120, **kwargs):
        super().__init__(parent, **kwargs)
        
        self.title = title
        self.value = value
        self.icon = icon
        self.color = color
        self.hover_color = hover_color
        self.card_width = width
        self.card_height = height
        
        self._create_card()
        self._bind_events()
    
    def _create_card(self):
        """Cria a estrutura visual do card."""
        # Frame principal com borda arredondada simulada
        self.configure(padding=15)
        
        # Container interno
        self.inner_frame = ttk.Frame(self)
        self.inner_frame.pack(fill=tk.BOTH, expand=True)
        
        # Ícone
        if self.icon:
            self.icon_label = ttk.Label(
                self.inner_frame,
                text=self.icon,
                font=('Segoe UI', 24)
            )
            self.icon_label.pack(anchor='w')
        
        # Título
        self.title_label = ttk.Label(
            self.inner_frame,
            text=self.title,
            font=('Segoe UI', 10),
            foreground='#64748b'
        )
        self.title_label.pack(anchor='w', pady=(5, 0))
        
        # Valor
        self.value_label = ttk.Label(
            self.inner_frame,
            text=self.value,
            font=('Segoe UI', 18, 'bold'),
            foreground=self.color
        )
        self.value_label.pack(anchor='w', pady=(5, 0))
    
    def _bind_events(self):
        """Configura eventos de hover."""
        self.bind('<Enter>', self._on_enter)
        self.bind('<Leave>', self._on_leave)
    
    def _on_enter(self, event):
        """Efeito ao passar o mouse."""
        self.value_label.configure(foreground=self.hover_color)
    
    def _on_leave(self, event):
        """Efeito ao tirar o mouse."""
        self.value_label.configure(foreground=self.color)
    
    def update_value(self, new_value: str):
        """Atualiza o valor exibido no card."""
        self.value = new_value
        self.value_label.configure(text=new_value)
    
    def update_title(self, new_title: str):
        """Atualiza o título do card."""
        self.title = new_title
        self.title_label.configure(text=new_title)


class ModernProgressBar(ttk.Frame):
    """
    Barra de Progresso Moderna com animação suave.
    
    Uso:
        progress = ModernProgressBar(parent, maximum=100)
        progress.set_value(50)
        progress.animate_to(100)
    """
    
    def __init__(self, parent, maximum: int = 100, height: int = 8,
                 color: str = "#2563eb", bg_color: str = "#e2e8f0",
                 show_percentage: bool = True, **kwargs):
        super().__init__(parent, **kwargs)
        
        self.maximum = maximum
        self.bar_height = height
        self.color = color
        self.bg_color = bg_color
        self.show_percentage = show_percentage
        self._value = 0
        self._animation_id = None
        
        self._create_bar()
    
    def _create_bar(self):
        """Cria a estrutura visual da barra."""
        # Canvas para desenhar a barra
        self.canvas = tk.Canvas(
            self,
            height=self.bar_height,
            bg=self.bg_color,
            highlightthickness=0
        )
        self.canvas.pack(fill=tk.X, expand=True)
        
        # Barra de progresso
        self.bar = self.canvas.create_rectangle(
            0, 0, 0, self.bar_height,
            fill=self.color,
            outline=''
        )
        
        # Label de porcentagem
        if self.show_percentage:
            self.percentage_label = ttk.Label(
                self,
                text="0%",
                font=('Segoe UI', 9)
            )
            self.percentage_label.pack(pady=(5, 0))
        
        # Bind para redimensionamento
        self.canvas.bind('<Configure>', self._on_resize)
    
    def _on_resize(self, event):
        """Atualiza a barra quando o widget é redimensionado."""
        self._update_bar()
    
    def _update_bar(self):
        """Atualiza a visualização da barra."""
        width = self.canvas.winfo_width()
        bar_width = (self._value / self.maximum) * width if self.maximum > 0 else 0
        self.canvas.coords(self.bar, 0, 0, bar_width, self.bar_height)
        
        if self.show_percentage:
            percentage = (self._value / self.maximum * 100) if self.maximum > 0 else 0
            self.percentage_label.configure(text=f"{percentage:.1f}%")
    
    def set_value(self, value: int):
        """Define o valor da barra."""
        self._value = max(0, min(value, self.maximum))
        self._update_bar()
    
    def get_value(self) -> int:
        """Retorna o valor atual."""
        return self._value
    
    def animate_to(self, target: int, duration: int = 500):
        """Anima a barra até o valor alvo."""
        if self._animation_id:
            self.after_cancel(self._animation_id)
        
        start_value = self._value
        target = max(0, min(target, self.maximum))
        steps = duration // 16  # ~60 FPS
        step_value = (target - start_value) / steps if steps > 0 else 0
        current_step = [0]
        
        def animate():
            if current_step[0] >= steps:
                self._value = target
                self._update_bar()
                return
            
            self._value = start_value + step_value * current_step[0]
            self._update_bar()
            current_step[0] += 1
            self._animation_id = self.after(16, animate)
        
        animate()


class ModernSearchBox(ttk.Frame):
    """
    Caixa de Busca Moderna com ícone e sugestões.
    
    Uso:
        search = ModernSearchBox(parent, placeholder="Buscar produtos...")
        search.on_search = lambda text: print(f"Buscando: {text}")
    """
    
    def __init__(self, parent, placeholder: str = "Buscar...",
                 width: int = 300, debounce: int = 300, **kwargs):
        super().__init__(parent, **kwargs)
        
        self.placeholder = placeholder
        self.box_width = width
        self.debounce = debounce
        self._debounce_id = None
        self._has_focus = False
        
        # Callbacks
        self.on_search = None
        self.on_clear = None
        self.on_focus = None
        self.on_blur = None
        
        self._create_search_box()
    
    def _create_search_box(self):
        """Cria a estrutura visual da caixa de busca."""
        # Frame container
        self.container = ttk.Frame(self)
        self.container.pack(fill=tk.X, expand=True)
        
        # Ícone de busca
        self.search_icon = ttk.Label(
            self.container,
            text="🔍",
            font=('Segoe UI', 12)
        )
        self.search_icon.pack(side=tk.LEFT, padx=(10, 5))
        
        # Entry
        self.entry_var = tk.StringVar()
        self.entry = ttk.Entry(
            self.container,
            textvariable=self.entry_var,
            width=self.box_width // 10,
            font=('Segoe UI', 11)
        )
        self.entry.pack(side=tk.LEFT, fill=tk.X, expand=True, padx=5)
        
        # Placeholder
        self._show_placeholder()
        
        # Botão limpar
        self.clear_btn = ttk.Button(
            self.container,
            text="✖",
            width=3,
            command=self.clear,
            bootstyle="secondary-link"
        )
        
        # Bindings
        self.entry.bind('<FocusIn>', self._on_focus_in)
        self.entry.bind('<FocusOut>', self._on_focus_out)
        self.entry.bind('<KeyRelease>', self._on_key_release)
        self.entry.bind('<Return>', self._on_enter)
        self.entry.bind('<Escape>', lambda e: self.clear())
    
    def _show_placeholder(self):
        """Mostra o placeholder."""
        if not self._has_focus and not self.entry_var.get():
            self.entry.configure(foreground='gray')
            self.entry_var.set(self.placeholder)
    
    def _hide_placeholder(self):
        """Esconde o placeholder."""
        if self.entry_var.get() == self.placeholder:
            self.entry_var.set('')
            self.entry.configure(foreground='black')
    
    def _on_focus_in(self, event):
        """Evento de foco."""
        self._has_focus = True
        self._hide_placeholder()
        if self.on_focus:
            self.on_focus()
    
    def _on_focus_out(self, event):
        """Evento de perda de foco."""
        self._has_focus = False
        self._show_placeholder()
        if self.on_blur:
            self.on_blur()
    
    def _on_key_release(self, event):
        """Evento de tecla liberada."""
        text = self.get_text()
        
        # Mostra/esconde botão limpar
        if text:
            self.clear_btn.pack(side=tk.RIGHT, padx=(0, 5))
        else:
            self.clear_btn.pack_forget()
        
        # Debounce para busca
        if self._debounce_id:
            self.after_cancel(self._debounce_id)
        
        if self.on_search and text:
            self._debounce_id = self.after(self.debounce, lambda: self.on_search(text))
    
    def _on_enter(self, event):
        """Evento de Enter."""
        if self.on_search:
            self.on_search(self.get_text())
    
    def get_text(self) -> str:
        """Retorna o texto atual (sem placeholder)."""
        text = self.entry_var.get()
        return '' if text == self.placeholder else text
    
    def set_text(self, text: str):
        """Define o texto da busca."""
        self._hide_placeholder()
        self.entry_var.set(text)
    
    def clear(self):
        """Limpa a busca."""
        self.entry_var.set('')
        self.clear_btn.pack_forget()
        self._show_placeholder()
        if self.on_clear:
            self.on_clear()
    
    def focus(self):
        """Coloca foco na caixa de busca."""
        self.entry.focus_set()


class ModernStatusBar(ttk.Frame):
    """
    Barra de Status Moderna com múltiplas seções.
    
    Uso:
        status = ModernStatusBar(parent)
        status.set_text("Pronto")
        status.set_user("Admin")
        status.set_datetime()
    """
    
    def __init__(self, parent, **kwargs):
        super().__init__(parent, **kwargs)
        
        self._sections = {}
        self._datetime_update_id = None
        
        self._create_status_bar()
        self._start_datetime_update()
    
    def _create_status_bar(self):
        """Cria a estrutura visual da barra de status."""
        # Separador superior
        ttk.Separator(self, orient='horizontal').pack(fill=tk.X)
        
        # Container principal
        self.container = ttk.Frame(self)
        self.container.pack(fill=tk.X, padx=10, pady=5)
        
        # Seção de status principal (esquerda)
        self.status_frame = ttk.Frame(self.container)
        self.status_frame.pack(side=tk.LEFT, fill=tk.X, expand=True)
        
        self.status_icon = ttk.Label(self.status_frame, text="✓", foreground='green')
        self.status_icon.pack(side=tk.LEFT, padx=(0, 5))
        
        self.status_label = ttk.Label(self.status_frame, text="Pronto", font=('Segoe UI', 9))
        self.status_label.pack(side=tk.LEFT)
        
        # Seção de informações (direita)
        self.info_frame = ttk.Frame(self.container)
        self.info_frame.pack(side=tk.RIGHT)
        
        # Usuário
        self.user_label = ttk.Label(
            self.info_frame,
            text="👤 Usuário",
            font=('Segoe UI', 9)
        )
        self.user_label.pack(side=tk.LEFT, padx=(0, 15))
        
        # Separador
        ttk.Separator(self.info_frame, orient='vertical').pack(side=tk.LEFT, fill=tk.Y, padx=5)
        
        # Data/Hora
        self.datetime_label = ttk.Label(
            self.info_frame,
            text="",
            font=('Segoe UI', 9)
        )
        self.datetime_label.pack(side=tk.LEFT, padx=(15, 0))
    
    def _start_datetime_update(self):
        """Inicia a atualização automática de data/hora."""
        self._update_datetime()
    
    def _update_datetime(self):
        """Atualiza a data/hora."""
        try:
            now = datetime.datetime.now()
            self.datetime_label.configure(
                text=f"📅 {now.strftime('%d/%m/%Y')}  🕐 {now.strftime('%H:%M:%S')}"
            )
            self._datetime_update_id = self.after(1000, self._update_datetime)
        except tk.TclError:
            pass
    
    def set_text(self, text: str, icon: str = "✓", color: str = "green"):
        """Define o texto de status."""
        self.status_icon.configure(text=icon, foreground=color)
        self.status_label.configure(text=text)
    
    def set_success(self, text: str):
        """Define status de sucesso."""
        self.set_text(text, "✓", "green")
    
    def set_error(self, text: str):
        """Define status de erro."""
        self.set_text(text, "✗", "red")
    
    def set_warning(self, text: str):
        """Define status de aviso."""
        self.set_text(text, "⚠", "orange")
    
    def set_info(self, text: str):
        """Define status de informação."""
        self.set_text(text, "ℹ", "blue")
    
    def set_loading(self, text: str = "Carregando..."):
        """Define status de carregamento."""
        self.set_text(text, "⏳", "gray")
    
    def set_user(self, username: str):
        """Define o usuário exibido."""
        self.user_label.configure(text=f"👤 {username}")
    
    def destroy(self):
        """Limpa recursos ao destruir."""
        if self._datetime_update_id:
            try:
                self.after_cancel(self._datetime_update_id)
            except tk.TclError:
                pass
        super().destroy()


class ModernDataTable(ttk.Frame):
    """
    Tabela de Dados Moderna com ordenação, filtros e paginação.
    
    Uso:
        table = ModernDataTable(parent, columns=['ID', 'Nome', 'Preço'])
        table.set_data([{'ID': 1, 'Nome': 'Produto', 'Preço': 10.00}])
    """
    
    def __init__(self, parent, columns: list, page_size: int = 50,
                 show_row_numbers: bool = True, striped: bool = True,
                 selectable: bool = True, **kwargs):
        super().__init__(parent, **kwargs)
        
        self.columns = columns
        self.page_size = page_size
        self.show_row_numbers = show_row_numbers
        self.striped = striped
        self.selectable = selectable
        
        self._data = []
        self._filtered_data = []
        self._current_page = 0
        self._sort_column = None
        self._sort_reverse = False
        self._selected_items = set()
        
        # Callbacks
        self.on_select = None
        self.on_double_click = None
        self.on_right_click = None
        
        self._create_table()
    
    def _create_table(self):
        """Cria a estrutura visual da tabela."""
        # Toolbar
        self.toolbar = ttk.Frame(self)
        self.toolbar.pack(fill=tk.X, pady=(0, 5))
        
        # Busca
        self.search_var = tk.StringVar()
        self.search_entry = ttk.Entry(
            self.toolbar,
            textvariable=self.search_var,
            width=30
        )
        self.search_entry.pack(side=tk.LEFT, padx=(0, 10))
        self.search_entry.bind('<KeyRelease>', self._on_search)
        
        # Info de registros
        self.info_label = ttk.Label(self.toolbar, text="0 registros")
        self.info_label.pack(side=tk.RIGHT)
        
        # Frame da tabela
        self.table_frame = ttk.Frame(self)
        self.table_frame.pack(fill=tk.BOTH, expand=True)
        
        # Treeview
        display_columns = ['#'] + self.columns if self.show_row_numbers else self.columns
        self.tree = ttk.Treeview(
            self.table_frame,
            columns=display_columns,
            show='headings',
            selectmode='extended' if self.selectable else 'none'
        )
        
        # Scrollbars
        self.vsb = ttk.Scrollbar(self.table_frame, orient='vertical', command=self.tree.yview)
        self.hsb = ttk.Scrollbar(self.table_frame, orient='horizontal', command=self.tree.xview)
        self.tree.configure(yscrollcommand=self.vsb.set, xscrollcommand=self.hsb.set)
        
        # Grid
        self.tree.grid(row=0, column=0, sticky='nsew')
        self.vsb.grid(row=0, column=1, sticky='ns')
        self.hsb.grid(row=1, column=0, sticky='ew')
        
        self.table_frame.grid_rowconfigure(0, weight=1)
        self.table_frame.grid_columnconfigure(0, weight=1)
        
        # Configura colunas
        for col in display_columns:
            self.tree.heading(col, text=col, command=lambda c=col: self._sort_by_column(c))
            self.tree.column(col, width=100, minwidth=50)
        
        # Bindings
        self.tree.bind('<<TreeviewSelect>>', self._on_select)
        self.tree.bind('<Double-1>', self._on_double_click)
        self.tree.bind('<Button-3>', self._on_right_click)
        
        # Paginação
        self.pagination_frame = ttk.Frame(self)
        self.pagination_frame.pack(fill=tk.X, pady=(5, 0))
        
        self.prev_btn = ttk.Button(
            self.pagination_frame,
            text="◀ Anterior",
            command=self._prev_page,
            bootstyle="secondary"
        )
        self.prev_btn.pack(side=tk.LEFT)
        
        self.page_label = ttk.Label(self.pagination_frame, text="Página 1 de 1")
        self.page_label.pack(side=tk.LEFT, padx=20)
        
        self.next_btn = ttk.Button(
            self.pagination_frame,
            text="Próximo ▶",
            command=self._next_page,
            bootstyle="secondary"
        )
        self.next_btn.pack(side=tk.LEFT)
    
    def set_data(self, data: list):
        """Define os dados da tabela."""
        self._data = data
        self._filtered_data = data.copy()
        self._current_page = 0
        self._refresh_table()
    
    def _refresh_table(self):
        """Atualiza a exibição da tabela."""
        # Limpa tabela
        for item in self.tree.get_children():
            self.tree.delete(item)
        
        # Calcula paginação
        start = self._current_page * self.page_size
        end = start + self.page_size
        page_data = self._filtered_data[start:end]
        
        # Insere dados
        for i, row in enumerate(page_data):
            values = []
            if self.show_row_numbers:
                values.append(start + i + 1)
            
            for col in self.columns:
                values.append(row.get(col, ''))
            
            tags = ('odd',) if self.striped and i % 2 else ('even',)
            self.tree.insert('', 'end', values=values, tags=tags)
        
        # Aplica estilo striped
        if self.striped:
            self.tree.tag_configure('odd', background='#f8f9fa')
            self.tree.tag_configure('even', background='white')
        
        # Atualiza info
        total = len(self._filtered_data)
        total_pages = max(1, (total + self.page_size - 1) // self.page_size)
        self.info_label.configure(text=f"{total} registros")
        self.page_label.configure(text=f"Página {self._current_page + 1} de {total_pages}")
        
        # Habilita/desabilita botões
        self.prev_btn.configure(state='normal' if self._current_page > 0 else 'disabled')
        self.next_btn.configure(state='normal' if self._current_page < total_pages - 1 else 'disabled')
    
    def _on_search(self, event):
        """Filtra dados pela busca."""
        search_text = self.search_var.get().lower()
        
        if not search_text:
            self._filtered_data = self._data.copy()
        else:
            self._filtered_data = [
                row for row in self._data
                if any(search_text in str(v).lower() for v in row.values())
            ]
        
        self._current_page = 0
        self._refresh_table()
    
    def _sort_by_column(self, column):
        """Ordena por coluna."""
        if self._sort_column == column:
            self._sort_reverse = not self._sort_reverse
        else:
            self._sort_column = column
            self._sort_reverse = False
        
        if column != '#':
            self._filtered_data.sort(
                key=lambda x: x.get(column, ''),
                reverse=self._sort_reverse
            )
        
        self._refresh_table()
    
    def _prev_page(self):
        """Vai para página anterior."""
        if self._current_page > 0:
            self._current_page -= 1
            self._refresh_table()
    
    def _next_page(self):
        """Vai para próxima página."""
        total_pages = (len(self._filtered_data) + self.page_size - 1) // self.page_size
        if self._current_page < total_pages - 1:
            self._current_page += 1
            self._refresh_table()
    
    def _on_select(self, event):
        """Evento de seleção."""
        if self.on_select:
            selected = self.tree.selection()
            self.on_select(selected)
    
    def _on_double_click(self, event):
        """Evento de duplo clique."""
        if self.on_double_click:
            item = self.tree.identify_row(event.y)
            if item:
                self.on_double_click(item)
    
    def _on_right_click(self, event):
        """Evento de clique direito."""
        if self.on_right_click:
            item = self.tree.identify_row(event.y)
            self.on_right_click(event, item)
    
    def get_selected_data(self) -> list:
        """Retorna os dados das linhas selecionadas."""
        selected = []
        for item in self.tree.selection():
            values = self.tree.item(item, 'values')
            if values:
                idx = int(values[0]) - 1 if self.show_row_numbers else 0
                if 0 <= idx < len(self._filtered_data):
                    selected.append(self._filtered_data[idx])
        return selected




class ModernTooltip:
    """Sistema de tooltips modernos e elegantes."""
    def __init__(self, widget, text, delay=500):
        self.widget = widget
        self.text = text
        self.delay = delay
        self.tooltip_window = None
        self.schedule_id = None
        self.widget.bind('<Enter>', self.on_enter)
        self.widget.bind('<Leave>', self.on_leave)
    
    def on_enter(self, event=None):
        self.schedule_id = self.widget.after(self.delay, self.show_tooltip)
    
    def on_leave(self, event=None):
        if self.schedule_id:
            self.widget.after_cancel(self.schedule_id)
        self.hide_tooltip()
    
    def show_tooltip(self):
        if self.tooltip_window:
            return
        x = self.widget.winfo_rootx() + 20
        y = self.widget.winfo_rooty() + self.widget.winfo_height() + 5
        self.tooltip_window = tk.Toplevel(self.widget)
        self.tooltip_window.wm_overrideredirect(True)
        self.tooltip_window.wm_geometry(f"+{x}+{y}")
        label = tk.Label(self.tooltip_window, text=self.text, background="#2c3e50",
                        foreground="white", relief=tk.SOLID, borderwidth=1,
                        font=('Segoe UI', 9), padding=5)
        label.pack()
    
    def hide_tooltip(self):
        if self.tooltip_window:
            self.tooltip_window.destroy()
            self.tooltip_window = None

def add_tooltip(widget, text):
    """Adiciona tooltip a um widget."""
    return ModernTooltip(widget, text)




