FLASK_IMPORT_ERROR = None
SOCKETIO_AVAILABLE = False
SOCKETIO_IMPORT_ERROR = None
SocketIO = None
emit = None
_QUANTUM_ENABLE_WEB_SERVER = str(os.environ.get("QUANTUM_ENABLE_WEB_SERVER", "0")).strip().lower() in ("1", "true", "sim", "yes", "on")
