    def _setup_routes(self):
        """Configura todas as rotas da API e páginas."""
        
        # ═══════════════════════════════════════════════════════════════════════
        # SISTEMA DE AUTENTICAÇÃO WEB - QUANTUM ULTRA
        # Usa o cadastro de usuários do PDV para autenticação
        # ═══════════════════════════════════════════════════════════════════════
        
        def _get_web_users(self_ref):
            """Obtém usuários do sistema para autenticação web."""
            try:
                conn = self_ref._get_db_connection()
                cursor = conn.cursor(dictionary=True)
                cursor.execute("SELECT username, password_hash, nivel_acesso FROM usuarios WHERE ativo = 1")
                rows = cursor.fetchall()
                conn.close()
                users = {}
                for row in rows:
                    row_dict = dict(row)
                    users[row_dict['username']] = {
                        'password': row_dict['password_hash'],
                        'nivel_acesso': row_dict['nivel_acesso'] or 'caixa'
                    }
                return users
            except Exception as e:
                print(f"[Servidor] Erro ao carregar usuários: {e}")
                return {}
        
        def login_required(f):
            """Decorator para proteger rotas que requerem autenticação."""
            @wraps(f)
            def decorated_function(*args, **kwargs):
                if not session.get('web_authenticated'):
                    # Se for requisição API, retorna JSON
                    if request.path.startswith('/api/'):
                        return jsonify({'success': False, 'error': 'Não autenticado', 'redirect': '/login'}), 401
                    # Se for página, redireciona para login
                    return redirect(url_for('login_page'))
                return f(*args, **kwargs)
            return decorated_function
        
        @self.flask_app.route('/login', methods=['GET', 'POST'])
        def login_page():
            """Página de login da comanda web usando usuários do PDV."""
            error_message = ''
            users = _get_web_users(self)
            user_list = sorted(users.keys()) if users else []
            
            if request.method == 'POST':
                username = request.form.get('username', '').strip()
                password = request.form.get('password', '')
                
                if not username:
                    error_message = 'Selecione um usuário!'
                elif not password:
                    error_message = 'Digite a senha!'
                elif username in users:
                    # Verifica a senha usando a mesma função do PDV
                    stored_hash = users[username].get('password', '')
                    if verify_password(password, stored_hash):
                        session['web_authenticated'] = True
                        session['web_username'] = username
                        session['web_nivel_acesso'] = users[username].get('nivel_acesso', 'caixa')
                        session['web_login_time'] = datetime.datetime.now().isoformat()
                        return redirect(url_for('index'))
                    else:
                        error_message = 'Senha incorreta!'
                else:
                    error_message = 'Usuário não encontrado!'
            
            return self._get_login_template(error_message, user_list)
        
        @self.flask_app.route('/logout')
        def logout():
            """Encerra a sessão do usuário."""
            session.pop('web_authenticated', None)
            session.pop('web_username', None)
            session.pop('web_nivel_acesso', None)
            session.pop('web_login_time', None)
            return redirect(url_for('login_page'))
        
