        @self.flask_app.route('/api/cozinha/pedidos', methods=['GET'])
        @login_required
        def api_cozinha_pedidos():
            """Retorna todos os pedidos para a cozinha com status de itens."""
            try:
                conn = self._get_db_connection()
                cursor = conn.cursor(dictionary=True)
                cursor.execute("SELECT * FROM comandas WHERE status = 'aberta' ORDER BY created_at ASC")
                rows = cursor.fetchall()
                
                pedidos = []
                for row in rows:
                    row_dict = dict(row)
                    itens_raw = json.loads(row_dict['itens']) if row_dict['itens'] else []
                    
                    itens_formatados = []
                    for idx, item in enumerate(itens_raw):
                        if item.get('excluido', False):
                            continue
                        
                        item_formatado = {
                            'index': idx,
                            'id': item.get('id', ''),
                            'nome': item.get('nome', 'Produto'),
                            'quantidade': item.get('qtd', item.get('quantidade', 1)),
                            'observacao': item.get('observacao', ''),
                            'usuario': item.get('usuario', ''),
                            'preco': item.get('preco', item.get('preco_unit', 0)),
                            'subtotal': item.get('subtotal', 0),
                            'feito': item.get('feito_cozinha', False),
                            'feito_por': item.get('feito_por', ''),
                            'feito_em': item.get('feito_em', ''),
                            'obs_cozinha': item.get('obs_cozinha', ''),
                            'impresso_individual': item.get('impresso_individual', False)
                        }
                        itens_formatados.append(item_formatado)
                    
                    todos_feitos = all(item.get('feito', False) for item in itens_formatados) if itens_formatados else False
                    oculto_cozinha = row_dict.get('oculto_cozinha', 0) == 1
                    
                    pedido = {
                        'numero': row_dict['numero'],
                        'cliente': row_dict['cliente'] or 'Consumidor Final',
                        'observacao': row_dict['observacao'] or '',
                        'itens': itens_formatados,
                        'status': row_dict['status'],
                        'abertura': row_dict.get('created_at', ''),
                        'updated_at': row_dict.get('updated_at', ''),
                        'sinalizada_para_fechar': bool(row_dict.get('sinalizada_para_fechar', 0)),
                        'sinalizada_por': row_dict.get('sinalizada_por', ''),
                        'todos_feitos': todos_feitos,
                        'oculto_cozinha': oculto_cozinha,
                        'obs_cozinha_geral': row_dict.get('obs_cozinha_geral', '')
                    }
                    pedidos.append(pedido)
                
                conn.close()
                return jsonify({
                    'success': True,
                    'pedidos': pedidos,
                    'timestamp': datetime.datetime.now().isoformat(),
                    'total_pedidos': len(pedidos)
                })
            except Exception as e:
                print(f"[API Cozinha] Erro ao carregar pedidos: {e}")
                import traceback
                traceback.print_exc()
                return jsonify({'success': False, 'error': str(e)}), 500
        
        @self.flask_app.route('/api/cozinha/item/<numero>/<int:item_index>/feito', methods=['POST'])
        @login_required
        def api_cozinha_marcar_feito(numero, item_index):
            """Marca um item como feito na cozinha."""
            try:
                data = request.get_json() or {}
                feito = data.get('feito', True)
                usuario = session.get('web_username', 'Cozinha')
                
                conn = self._get_db_connection()
                cursor = conn.cursor(dictionary=True)
                cursor.execute("SELECT itens FROM comandas WHERE numero = %s", (numero,))
                row = cursor.fetchone()
                
                if not row:
                    conn.close()
                    return jsonify({'success': False, 'error': 'Comanda nao encontrada'}), 404
                
                row_dict = dict(row)
                itens = json.loads(row_dict['itens']) if row_dict['itens'] else []
                
                if item_index < 0 or item_index >= len(itens):
                    conn.close()
                    return jsonify({'success': False, 'error': 'Item nao encontrado'}), 404
                
                itens[item_index]['feito_cozinha'] = feito
                if feito:
                    itens[item_index]['feito_por'] = usuario
                    itens[item_index]['feito_em'] = datetime.datetime.now().strftime('%d/%m/%Y %H:%M:%S')
                else:
                    itens[item_index]['feito_por'] = ''
                    itens[item_index]['feito_em'] = ''
                
                cursor.execute("UPDATE comandas SET itens = %s, updated_at = CURRENT_TIMESTAMP WHERE numero = %s",
                           (json.dumps(itens), numero))
                
                # Muda status para ABERTA
                cursor.execute("UPDATE comandas SET status = 'aberta', updated_at = CURRENT_TIMESTAMP WHERE numero = %s", (numero,))
                conn.commit()
                conn.close()
                
                if SOCKETIO_AVAILABLE and self.socketio:
                    self.socketio.emit('cozinha_update', {
                        'action': 'item_feito',
                        'numero': numero,
                        'item_index': item_index,
                        'feito': feito,
                        'usuario': usuario,
                        'timestamp': datetime.datetime.now().isoformat()
                    })
                
                return jsonify({
                    'success': True,
                    'message': 'Item marcado como feito' if feito else 'Item desmarcado'
                })
            except Exception as e:
                print(f"[API Cozinha] Erro ao marcar item: {e}")
                return jsonify({'success': False, 'error': str(e)}), 500
        
        @self.flask_app.route('/api/cozinha/pedido/<numero>/ocultar', methods=['POST'])
        @login_required
        def api_cozinha_ocultar_pedido(numero):
            """Oculta um pedido da tela da cozinha."""
            try:
                data = request.get_json() or {}
                ocultar = data.get('ocultar', True)
                usuario = session.get('web_username', 'Cozinha')
                
                conn = self._get_db_connection()
                cursor = conn.cursor(dictionary=True)
                
                cursor.execute("SELECT itens FROM comandas WHERE numero = %s", (numero,))
                row = cursor.fetchone()
                
                if not row:
                    conn.close()
                    return jsonify({'success': False, 'error': 'Comanda nao encontrada'}), 404
                
                row_dict = dict(row)
                itens = json.loads(row_dict['itens']) if row_dict['itens'] else []
                
                itens_ativos = [item for item in itens if not item.get('excluido', False)]
                todos_feitos = all(item.get('feito_cozinha', False) for item in itens_ativos) if itens_ativos else False
                
                if ocultar and not todos_feitos:
                    conn.close()
                    return jsonify({
                        'success': False, 
                        'error': 'Todos os itens devem estar marcados como feitos antes de ocultar o pedido'
                    }), 400
                
                cursor.execute(
                    "UPDATE comandas SET oculto_cozinha = %s, oculto_cozinha_por = %s, oculto_cozinha_em = %s, updated_at = CURRENT_TIMESTAMP WHERE numero = %s",
                    (1 if ocultar else 0, usuario if ocultar else '', 
                     datetime.datetime.now().strftime('%d/%m/%Y %H:%M:%S') if ocultar else '', numero))
                conn.commit()
                conn.close()
                
                if SOCKETIO_AVAILABLE and self.socketio:
                    self.socketio.emit('cozinha_update', {
                        'action': 'pedido_oculto',
                        'numero': numero,
                        'oculto': ocultar,
                        'usuario': usuario,
                        'timestamp': datetime.datetime.now().isoformat()
                    })
                
                return jsonify({
                    'success': True,
                    'message': 'Pedido ocultado' if ocultar else 'Pedido restaurado'
                })
            except Exception as e:
                print(f"[API Cozinha] Erro ao ocultar pedido: {e}")
                return jsonify({'success': False, 'error': str(e)}), 500
        
        @self.flask_app.route('/api/cozinha/item/<numero>/<int:item_index>/obs', methods=['POST'])
        @login_required
        def api_cozinha_obs_item(numero, item_index):
            """Adiciona observacao da cozinha a um item, concatenando com a observacao existente."""
            try:
                data = request.get_json() or {}
                obs = data.get('observacao', '').strip()
                usuario = session.get('web_username', 'Cozinha')
                
                conn = self._get_db_connection()
                cursor = conn.cursor(dictionary=True)
                cursor.execute("SELECT itens FROM comandas WHERE numero = %s", (numero,))
                row = cursor.fetchone()
                
                if not row:
                    conn.close()
                    return jsonify({'success': False, 'error': 'Comanda nao encontrada'}), 404
                
                row_dict = dict(row)
                itens = json.loads(row_dict['itens']) if row_dict['itens'] else []
                
                if item_index < 0 or item_index >= len(itens):
                    conn.close()
                    return jsonify({'success': False, 'error': 'Item nao encontrado'}), 404
                
                # Busca a observacao existente do item
                obs_existente = itens[item_index].get('observacao', '') or ''
                
                # Formata a nova observacao da cozinha com timestamp e usuario
                timestamp_obs = datetime.datetime.now().strftime('%d/%m %H:%M')
                nova_obs_cozinha = f"[....... {timestamp_obs} - {usuario}]: {obs}"
                
                # Concatena com a observacao existente do item
                if obs_existente:
                    obs_final = f"{obs_existente} | {nova_obs_cozinha}"
                else:
                    obs_final = nova_obs_cozinha
                
                # Atualiza a observacao do item (concatenada) e a obs_cozinha separada
                itens[item_index]['observacao'] = obs_final
                itens[item_index]['obs_cozinha'] = obs
                itens[item_index]['obs_cozinha_por'] = usuario
                itens[item_index]['obs_cozinha_em'] = datetime.datetime.now().strftime('%d/%m/%Y %H:%M:%S')
                
                cursor.execute("UPDATE comandas SET itens = %s, updated_at = CURRENT_TIMESTAMP WHERE numero = %s",
                           (json.dumps(itens), numero))
                
                # Muda status para ABERTA
                cursor.execute("UPDATE comandas SET status = 'aberta', updated_at = CURRENT_TIMESTAMP WHERE numero = %s", (numero,))
                conn.commit()
                conn.close()
                
                if SOCKETIO_AVAILABLE and self.socketio:
                    self.socketio.emit('cozinha_update', {
                        'action': 'obs_item',
                        'numero': numero,
                        'item_index': item_index,
                        'observacao': obs,
                        'observacao_completa': obs_final,
                        'usuario': usuario,
                        'timestamp': datetime.datetime.now().isoformat()
                    })
                
                return jsonify({
                    'success': True,
                    'message': 'Observacao adicionada',
                    'observacao_final': obs_final
                })
            except Exception as e:
                print(f"[API Cozinha] Erro ao adicionar obs: {e}")
                return jsonify({'success': False, 'error': str(e)}), 500
        
