        @self.flask_app.route('/api/cozinha/hash', methods=['GET'])
        @login_required
        def api_cozinha_hash():
            """Retorna um hash dos pedidos para verificacao de mudancas."""
            try:
                conn = self._get_db_connection()
                cursor = conn.cursor(dictionary=True)
                cursor.execute("SELECT numero, updated_at, itens FROM comandas WHERE status = 'aberta' AND (oculto_cozinha IS NULL OR oculto_cozinha = 0)")
                rows = cursor.fetchall()
                conn.close()
                
                hash_data = ""
                for row in rows:
                    row_dict = dict(row)
                    hash_data += f"{row_dict['numero']}|{row_dict['updated_at']}|{row_dict['itens']}|"
                
                import hashlib
                hash_value = hashlib.md5(hash_data.encode()).hexdigest()
                
                return jsonify({
                    'hash': hash_value,
                    'count': len(rows),
                    'timestamp': datetime.datetime.now().isoformat()
                })
            except Exception as e:
                return jsonify({'hash': '', 'error': str(e)}), 500
        

        
