        @self.flask_app.route('/api/comandas', methods=['GET', 'POST'])
        @login_required
        def api_comandas():
            if request.method == 'GET':
                return jsonify(self._get_comandas())
            elif request.method == 'POST':
                try:
                    data = request.get_json()
                    cliente = data.get('cliente', 'Consumidor Final').strip()
                    observacao = data.get('observacao', '').strip()
                    
                    # Gera número automático único que NUNCA se repete
                    try:
                        config_data = load_data(CONFIG_FILE, DEFAULT_CONFIG)
                        ultimo_numero = int(config_data.get('last_comanda_number', 0))
                        proximo_num = ultimo_numero + 1
                        config_data['last_comanda_number'] = proximo_num
                        save_data(CONFIG_FILE, config_data)
                        numero = str(proximo_num).zfill(3)
                        print(f"[Servidor WEB] Número sequencial gerado: #{numero}")
                    except Exception as num_error:
                        print(f"[Servidor WEB] Erro ao gerar número: {num_error}")
                        import time
                        numero = str(int(time.time()) % 100000).zfill(5)
                    
                    comandas = self._get_comandas()
                    # Verificação de segurança (não deveria acontecer)
                    if numero in comandas:
                        # Gera outro número se já existir
                        config_data = load_data(CONFIG_FILE, DEFAULT_CONFIG)
                        ultimo_numero = int(config_data.get('last_comanda_number', 0))
                        proximo_num = ultimo_numero + 1
                        config_data['last_comanda_number'] = proximo_num
                        save_data(CONFIG_FILE, config_data)
                        numero = str(proximo_num).zfill(3)
                    
                    # Cria no banco de dados usando conexão independente
                    try:
                        conn = self._get_db_connection()
                        cursor = conn.cursor(dictionary=True)
                        # Verifica se já existe uma comanda com esse número (mesmo fechada)
                        cursor.execute("SELECT id FROM comandas WHERE numero = %s", (numero,))
                        existing = cursor.fetchone()
                        if existing:
                            # Atualiza para reabrir
                            cursor.execute('''
                                UPDATE comandas SET cliente = %s, observacao = %s, itens = '[]', 
                                status = 'aberta', updated_at = CURRENT_TIMESTAMP
                                WHERE numero = %s
                            ''', (cliente, observacao, numero))
                        else:
                            # Cria nova
                            cursor.execute('''
                                INSERT INTO comandas (numero, cliente, observacao, itens, status)
                                VALUES (%s, %s, %s, '[]', 'aberta')
                            ''', (numero, cliente, observacao))
                        conn.commit()
                        conn.close()
                        print(f"[Servidor] Comanda {numero} criada com sucesso!")
                    except Exception as db_error:
                        print(f"[Servidor] Erro ao criar comanda no banco: {db_error}")
                        import traceback
                        traceback.print_exc()
                        return jsonify({'success': False, 'error': f'Erro no banco de dados: {str(db_error)}'})
                    
                    if SOCKETIO_AVAILABLE and self.socketio:
                        self.socketio.emit('comanda_update', {
                            'action': 'created',
                            'numero': numero,
                            'cliente': cliente
                        })
                    
                    return jsonify({'success': True, 'numero': numero})
                except Exception as e:
                    print(f"[Servidor] Erro geral ao criar comanda: {e}")
                    import traceback
                    traceback.print_exc()
                    return jsonify({'success': False, 'error': str(e)})
        
        @self.flask_app.route('/api/comandas/fechadas', methods=['GET'])
        @login_required
        def api_comandas_fechadas():
            """
            Retorna todas as comandas fechadas para exibição na interface.
            
            Returns:
                JSON com lista de comandas fechadas contendo:
                - numero: Número da comanda
                - cliente: Nome do cliente
                - status: Status da comanda (fechada, paga, finalizada)
                - data_fechamento: Data/hora do fechamento
                - total: Valor total da comanda
            """
            try:
                conn = self._get_db_connection()
                cursor = conn.cursor(dictionary=True)
                
                # Tenta buscar com colunas de reabertura (se existirem)
                try:
                    cursor.execute("""
                        SELECT numero, cliente, status, updated_at, itens,
                               reaberta_por, vezes_reaberta, motivo_reabertura, reaberta_em
                        FROM comandas 
                        WHERE status IN ('fechada', 'paga', 'finalizada') 
                        ORDER BY updated_at DESC
                    """)
                except Exception:
                    # Fallback para bancos sem as colunas de reabertura
                    cursor.execute("""
                        SELECT numero, cliente, status, updated_at, itens 
                        FROM comandas 
                        WHERE status IN ('fechada', 'paga', 'finalizada') 
                        ORDER BY updated_at DESC
                    """)
                    
                rows = cursor.fetchall()
                
                comandas_fechadas = []
                for row in rows:
                    row_dict = dict(row)
                    itens = json.loads(row_dict['itens']) if row_dict['itens'] else []
                    total = sum(item.get('subtotal', 0) for item in itens if not item.get('excluido', False))
                    
                    comanda_data = {
                        'numero': row_dict['numero'],
                        'cliente': row_dict.get('cliente', 'Consumidor Final'),
                        'status': row_dict.get('status', 'fechada'),
                        'data_fechamento': row_dict.get('updated_at', ''),
                        'total': total,
                        # Campos de reabertura (se existirem)
                        'reaberta_por': row_dict.get('reaberta_por', ''),
                        'vezes_reaberta': row_dict.get('vezes_reaberta', 0),
                        'motivo_reabertura': row_dict.get('motivo_reabertura', ''),
                        'reaberta_em': row_dict.get('reaberta_em', '')
                    }
                    comandas_fechadas.append(comanda_data)
                    
                conn.close()
                return jsonify(comandas_fechadas)
            except Exception as e:
                print(f"[API] Erro ao buscar comandas fechadas: {e}")
                import traceback
                traceback.print_exc()
                return jsonify([])
        
