        @self.flask_app.route('/api/comandas/<numero>/reabrir', methods=['POST'])
        @login_required
        def api_reabrir_comanda(numero):
            """
            Reabre manualmente uma comanda fechada.
            
            Esta rota permite que um garçom reabra uma comanda que foi fechada
            para adicionar novos itens ou fazer correções.
            REQUER AUTENTICACAO: Usuario e senha devem ser verificados.
            
            Args:
                numero: Número da comanda a ser reaberta
                
            Returns:
                JSON com status da operação
            """
            try:
                # Obtem dados da requisicao
                data = request.get_json() or {}
                usuario_autenticacao = data.get('usuario_autenticacao', '').strip()
                senha_autenticacao = data.get('senha_autenticacao', '')
                motivo_reabertura = data.get('motivo_reabertura', '').strip()
                
                # Verifica se foram fornecidos usuario e senha
                if not usuario_autenticacao:
                    return jsonify({'success': False, 'error': 'Usuario nao informado. Informe seu usuario para reabrir a comanda.'})
                
                if not senha_autenticacao:
                    return jsonify({'success': False, 'error': 'Senha nao informada. Informe sua senha para reabrir a comanda.'})
                
                # Carrega usuarios do sistema para verificar credenciais
                users = _get_web_users(self)
                
                # Verifica se o usuario existe
                if usuario_autenticacao not in users:
                    return jsonify({'success': False, 'error': f'Usuario "{usuario_autenticacao}" nao encontrado no sistema.'})
                
                # Verifica a senha do usuario
                user_data = users[usuario_autenticacao]
                senha_hash = user_data.get('password', '')
                
                if not verify_password(senha_autenticacao, senha_hash):
                    return jsonify({'success': False, 'error': 'Senha incorreta. Verifique sua senha e tente novamente.'})
                
                # Autenticacao bem-sucedida - usa o usuario autenticado
                usuario = usuario_autenticacao
                
                conn = self._get_db_connection()
                cursor = conn.cursor(dictionary=True)
                
                # Verifica se a comanda existe e está fechada
                cursor.execute("SELECT status, cliente FROM comandas WHERE numero = %s", (numero,))
                row = cursor.fetchone()
                
                if not row:
                    conn.close()
                    return jsonify({'success': False, 'error': f'Comanda #{numero} não encontrada'})
                
                row_dict = dict(row)
                status_atual = row_dict.get('status', '')
                
                if status_atual == 'aberta':
                    conn.close()
                    return jsonify({'success': False, 'error': f'Comanda #{numero} já está aberta'})
                
                # Reabre a comanda - compatível com bancos existentes
                # Primeiro tenta adicionar as colunas se não existirem
                try:
                    cursor.execute("ALTER TABLE comandas ADD COLUMN reaberta_em TIMESTAMP DEFAULT NULL")
                except Exception:
                    pass  # Coluna já existe
                try:
                    cursor.execute("ALTER TABLE comandas ADD COLUMN reaberta_por VARCHAR(500) DEFAULT NULL")
                except Exception:
                    pass  # Coluna já existe
                try:
                    cursor.execute("ALTER TABLE comandas ADD COLUMN vezes_reaberta INTEGER DEFAULT 0")
                except Exception:
                    pass  # Coluna já existe
                try:
                    cursor.execute("ALTER TABLE comandas ADD COLUMN motivo_reabertura VARCHAR(500) DEFAULT NULL")
                except Exception:
                    pass  # Coluna já existe
                
                # Agora atualiza a comanda - INCLUI RESET DO oculto_cozinha para reaparecer na cozinha
                # Tambem registra o usuario que reabriu e o motivo
                # INCLUI RESET DO sinalizada_para_fechar para reabilitar o botão de sinalizar
                try:
                    cursor.execute("""
                        UPDATE comandas 
                        SET status = 'aberta', 
                            updated_at = CURRENT_TIMESTAMP,
                            reaberta_em = CURRENT_TIMESTAMP,
                            reaberta_por = %s,
                            motivo_reabertura = %s,
                            vezes_reaberta = COALESCE(vezes_reaberta, 0) + 1,
                            oculto_cozinha = 0,
                            oculto_cozinha_por = '',
                            oculto_cozinha_em = '',
                            sinalizada_para_fechar = 0,
                            sinalizada_por = ''
                        WHERE numero = %s
                    """, (usuario, motivo_reabertura if motivo_reabertura else 'Nao informado', numero))
                except Exception:
                    # Fallback para bancos sem as colunas novas - tenta com oculto_cozinha e sinalizada
                    try:
                        cursor.execute("""
                            UPDATE comandas 
                            SET status = 'aberta', 
                                updated_at = CURRENT_TIMESTAMP,
                                oculto_cozinha = 0,
                                oculto_cozinha_por = '',
                                oculto_cozinha_em = '',
                                sinalizada_para_fechar = 0,
                                sinalizada_por = ''
                            WHERE numero = %s
                        """, (numero,))
                    except Exception:
                        # Fallback minimo
                        cursor.execute("""
                            UPDATE comandas 
                            SET status = 'aberta', 
                                updated_at = CURRENT_TIMESTAMP,
                                sinalizada_para_fechar = 0,
                                sinalizada_por = ''
                            WHERE numero = %s
                        """, (numero,))
                
                conn.commit()
                conn.close()
                
                # Log detalhado da reabertura
                motivo_log = motivo_reabertura if motivo_reabertura else 'Nao informado'
                print(f"[API] [SYNC] Comanda #{numero} REABERTA manualmente por {usuario}")
                print(f"[API]   -> Motivo: {motivo_log}")
                print(f"[API]   -> Visivel novamente na cozinha")
                
                # Notifica via WebSocket - GARCOM
                if SOCKETIO_AVAILABLE and self.socketio:
                    self.socketio.emit('comanda_update', {
                        'action': 'reopened',
                        'numero': numero,
                        'source': 'web',
                        'reaberta_por': usuario,
                        'motivo_reabertura': motivo_log,
                        'message': f'Comanda #{numero} reaberta por {usuario}',
                        'timestamp': datetime.datetime.now().isoformat()
                    })
                    
                    # NOVO: Notifica a COZINHA especificamente para reexibir a comanda
                    self.socketio.emit('cozinha_update', {
                        'action': 'comanda_reaberta',
                        'numero': numero,
                        'reaberta_por': usuario,
                        'motivo_reabertura': motivo_log,
                        'message': f'Comanda #{numero} reaberta pelo garcom {usuario}',
                        'timestamp': datetime.datetime.now().isoformat()
                    })
                
                return jsonify({
                    'success': True, 
                    'message': f'Comanda #{numero} reaberta com sucesso',
                    'reaberta_por': usuario,
                    'motivo_reabertura': motivo_log
                })
                
            except Exception as e:
                print(f"[API] Erro ao reabrir comanda: {e}")
                import traceback
                traceback.print_exc()
                return jsonify({'success': False, 'error': str(e)})
        
