        @self.flask_app.route('/api/comandas/<numero>/itens', methods=['POST'])
        @login_required
        def api_add_item(numero):
            try:
                data = request.get_json()
                produto_id = str(data.get('produto_id', ''))  # Converte para string
                quantidade = int(data.get('quantidade', 1))
                observacao = data.get('observacao', '')
                
                produtos = self._get_produtos()
                print(f"[Servidor] Adicionando produto {produto_id} à comanda {numero}")
                print(f"[Servidor] Produtos disponíveis: {list(produtos.keys())[:5]}...")  # Mostra primeiros 5
                
                if produto_id not in produtos:
                    print(f"[Servidor] Produto {produto_id} não encontrado!")
                    return jsonify({'success': False, 'error': f'Produto {produto_id} não encontrado'})
                
                produto = produtos[produto_id]
                preco = parse_br_float(produto.get('preco', 0))
                subtotal = preco * quantidade
                
                # ═══════════════════════════════════════════════════════════════════════
                # VERIFICAÇÃO DE ESTOQUE ANTES DE ADICIONAR À COMANDA (WEB)
                # ═══════════════════════════════════════════════════════════════════════
                estoque_disponivel = parse_br_float(produto.get('estoque', 0.0))
                if estoque_disponivel is None:
                    estoque_disponivel = 0.0
                
                if quantidade > estoque_disponivel:
                    return jsonify({
                        'success': False, 
                        'error': f'Estoque insuficiente. Disponível: {estoque_disponivel}',
                        'estoque_atual': estoque_disponivel,
                        'quantidade_solicitada': quantidade
                    })
                
                # Alerta de estoque baixo (menos de 10 unidades após a venda)
                estoque_apos_venda = estoque_disponivel - quantidade
                if estoque_apos_venda < 10 and estoque_apos_venda >= 0:
                    print(f"[ALERTA] [ALERTA] Estoque baixo para produto {produto_id}: {estoque_apos_venda} unidades restantes")
                    # Notifica via WebSocket sobre estoque baixo
                    if SOCKETIO_AVAILABLE and self.socketio:
                        self.socketio.emit('stock_alert', {
                            'type': 'low_stock',
                            'produto_id': produto_id,
                            'produto_nome': produto.get('nome', 'Produto'),
                            'estoque_atual': estoque_apos_venda,
                            'timestamp': datetime.datetime.now().isoformat()
                        })
                
                # Atualiza no banco usando conexão independente
                try:
                    conn = self._get_db_connection()
                    cursor = conn.cursor(dictionary=True)
                    cursor.execute("SELECT itens FROM comandas WHERE numero = %s", (numero,))
                    row = cursor.fetchone()
                    
                    # ═══════════════════════════════════════════════════════════════════════
                    # REABERTURA AUTOMÁTICA DE COMANDA FECHADA
                    # Se a comanda não for encontrada como aberta, verifica se existe fechada
                    # e reabre automaticamente para permitir adicionar novos itens
                    # ═══════════════════════════════════════════════════════════════════════
                    if not row:
                        # Verifica se existe comanda fechada com esse número
                        cursor.execute("SELECT itens, status FROM comandas WHERE numero = %s", (numero,))
                        closed_row = cursor.fetchone()
                        if closed_row:
                            closed_dict = dict(closed_row)
                            if closed_dict.get('status') in ['fechada', 'paga', 'finalizada']:
                                # REABRE A COMANDA AUTOMATICAMENTE - compatível com bancos existentes
                                try:
                                    # Tenta adicionar colunas se não existirem
                                    try:
                                        cursor.execute("ALTER TABLE comandas ADD COLUMN reaberta_em TIMESTAMP DEFAULT NULL")
                                    except Exception:
                                        pass
                                    try:
                                        cursor.execute("ALTER TABLE comandas ADD COLUMN reaberta_por VARCHAR(500) DEFAULT NULL")
                                    except Exception:
                                        pass
                                    
                                    cursor.execute("""
                                        UPDATE comandas 
                                        SET status = 'aberta', 
                                            updated_at = CURRENT_TIMESTAMP,
                                            reaberta_em = CURRENT_TIMESTAMP,
                                            reaberta_por = %s,
                                            oculto_cozinha = 0,
                                            oculto_cozinha_por = '',
                                            oculto_cozinha_em = '',
                                            sinalizada_para_fechar = 0,
                                            sinalizada_por = ''
                                        WHERE numero = %s
                                    """, (session.get('web_username', 'Sistema'), numero))
                                except Exception:
                                    # Fallback para bancos sem as colunas novas - tenta com oculto_cozinha e sinalizada
                                    try:
                                        cursor.execute("""
                                            UPDATE comandas 
                                            SET status = 'aberta', 
                                                updated_at = CURRENT_TIMESTAMP,
                                                oculto_cozinha = 0,
                                                oculto_cozinha_por = '',
                                                oculto_cozinha_em = '',
                                                sinalizada_para_fechar = 0,
                                                sinalizada_por = ''
                                            WHERE numero = %s
                                        """, (numero,))
                                    except Exception:
                                        # Fallback minimo
                                        cursor.execute("""
                                            UPDATE comandas 
                                            SET status = 'aberta', 
                                                updated_at = CURRENT_TIMESTAMP,
                                                sinalizada_para_fechar = 0,
                                                sinalizada_por = ''
                                            WHERE numero = %s
                                        """, (numero,))
                                conn.commit()
                                print(f"[Servidor] [SYNC] COMANDA #{numero} REABERTA AUTOMATICAMENTE!")
                                
                                # Backup automático ao reabrir comanda (segurança)
                                try:
                                    if hasattr(self, 'app') and hasattr(self.app, 'backup_system'):
                                        self.app.backup_system.create_backup('comandas.json', reason=f'Reabertura comanda #{numero}')
                                except Exception as backup_error:
                                    print(f"[Servidor] Aviso: Backup não realizado: {backup_error}")
                                
                                # Notifica via WebSocket sobre a reabertura - GARCOM
                                usuario_reabertura = session.get('web_username', 'Sistema')
                                if SOCKETIO_AVAILABLE and self.socketio:
                                    self.socketio.emit('comanda_update', {
                                        'action': 'reopened',
                                        'numero': numero,
                                        'source': 'web',
                                        'message': f'Comanda #{numero} reaberta automaticamente para adicionar itens',
                                        'timestamp': datetime.datetime.now().isoformat()
                                    })
                                    
                                    # NOVO: Notifica a COZINHA especificamente para reexibir a comanda
                                    self.socketio.emit('cozinha_update', {
                                        'action': 'comanda_reaberta',
                                        'numero': numero,
                                        'reaberta_por': usuario_reabertura,
                                        'message': f'Comanda #{numero} reaberta automaticamente pelo garcom {usuario_reabertura}',
                                        'timestamp': datetime.datetime.now().isoformat()
                                    })
                                
                                # Busca novamente a comanda agora reaberta
                                cursor.execute("SELECT itens FROM comandas WHERE numero = %s AND status = 'aberta'", (numero,))
                                row = cursor.fetchone()
                    
                    if row:
                        row_dict = dict(row)
                        itens = json.loads(row_dict['itens']) if row_dict['itens'] else []
                        itens.append({
                            'id': produto_id,
                            'nome': produto.get('nome', 'Produto'),
                            'qtd': quantidade,
                            'preco': preco,
                            'subtotal': subtotal,
                            'observacao': observacao,
                            'usuario': session.get('web_username', 'N/A'),  # Usuário que adicionou o item
                            'adicionado_em': datetime.datetime.now().isoformat(),
                            'categoria': produto.get('categoria', 'Geral'),
                            'categoria_id': produto.get('categoria_id', produto.get('category_id', '1')),  # ID da categoria para impressão múltipla
                            'codigo': produto.get('codigo', ''),
                            'feito_cozinha': False,
                            'prioridade': data.get('prioridade', 'normal')  # normal, urgente, vip
                        })
                        cursor.execute("UPDATE comandas SET itens = %s, updated_at = CURRENT_TIMESTAMP WHERE numero = %s",
                                   (json.dumps(itens), numero))

                        # Muda status para ABERTA
                        cursor.execute("UPDATE comandas SET status = 'aberta', updated_at = CURRENT_TIMESTAMP WHERE numero = %s", (numero,))
                        
                        # ═══════════════════════════════════════════════════════════════════════
                        # REABERTURA NA COZINHA: Se a comanda estava oculta pela cozinha,
                        # reseta o flag para que ela reapareça na tela da cozinha
                        # ═══════════════════════════════════════════════════════════════════════
                        comanda_reaberta_cozinha = False
                        try:
                            cursor.execute("SELECT oculto_cozinha FROM comandas WHERE numero = %s", (numero,))
                            oculto_row = cursor.fetchone()
                            if oculto_row and dict(oculto_row).get('oculto_cozinha', 0) == 1:
                                # Comanda estava oculta pela cozinha - reabrir!
                                # Tambem reseta a sinalização para permitir sinalizar novamente
                                cursor.execute("""
                                    UPDATE comandas 
                                    SET oculto_cozinha = 0, 
                                        oculto_cozinha_por = '', 
                                        oculto_cozinha_em = '',
                                        sinalizada_para_fechar = 0,
                                        sinalizada_por = '',
                                        updated_at = CURRENT_TIMESTAMP
                                    WHERE numero = %s
                                """, (numero,))
                                comanda_reaberta_cozinha = True
                                print(f"[Servidor] COMANDA #{numero} REABERTA NA COZINHA - novo item adicionado")
                        except Exception as oculto_error:
                            print(f"[Servidor] Aviso: Erro ao verificar/resetar oculto_cozinha: {oculto_error}")
                        
                        # ═══════════════════════════════════════════════════════════════════════
                        # BAIXA IMEDIATA NO ESTOQUE AO ADICIONAR ITEM À COMANDA (WEB)
                        # ═══════════════════════════════════════════════════════════════════════
                        novo_estoque = max(0.0, estoque_disponivel - quantidade)
                        cursor.execute("UPDATE produtos SET estoque = %s, updated_at = CURRENT_TIMESTAMP WHERE id = %s",
                                   (novo_estoque, int(produto_id)))
                        print(f"[Servidor WEB] Baixa estoque: Produto {produto_id} - Qtd: {quantidade} - Estoque anterior: {estoque_disponivel} - Novo estoque: {novo_estoque}")
                        
                        conn.commit()
                        
                        # ═══════════════════════════════════════════════════════════════════════
                        # SINCRONIZAÇÃO COM app.products DO PDV DESKTOP
                        # Atualiza o dicionário em memória para manter consistência
                        # ═══════════════════════════════════════════════════════════════════════
                        try:
                            if hasattr(self, 'app') and hasattr(self.app, 'products'):
                                # Tenta atualizar com diferentes formatos de ID
                                for pid_format in [produto_id, str(produto_id)]:
                                    try:
                                        if pid_format in self.app.products:
                                            self.app.products[pid_format]['estoque'] = novo_estoque
                                            print(f"[Servidor WEB] Sincronizado app.products[{pid_format}] com novo estoque: {novo_estoque}")
                                            break
                                    except (ValueError, TypeError):
                                        continue
                                # Tenta também com int
                                try:
                                    pid_int = int(produto_id)
                                    if pid_int in self.app.products:
                                        self.app.products[pid_int]['estoque'] = novo_estoque
                                        print(f"[Servidor WEB] Sincronizado app.products[{pid_int}] com novo estoque: {novo_estoque}")
                                except (ValueError, TypeError):
                                    pass
                        except Exception as sync_error:
                            print(f"[Servidor WEB] Aviso: Não foi possível sincronizar app.products: {sync_error}")
                        
                        print(f"[Servidor] [OK] Item adicionado com sucesso:")
                        print(f"    [PACOTE] Produto: {produto.get('nome')} (ID: {produto_id})")
                        print(f"    [STATS] Quantidade: {quantidade}")
                        print(f"    [DINHEIRO] Preço unitário: R$ {preco:.2f}")
                        print(f"    [CASH] Subtotal: R$ {subtotal:.2f}")
                        print(f"    [USUARIO] Usuário: {session.get('web_username', 'N/A')}")
                        print(f"    [LISTA] Comanda: #{numero}")
                        print(f"    [PACOTE] Estoque restante: {novo_estoque}")
                    else:
                        print(f"[Servidor] Comanda {numero} não encontrada ou fechada")
                        conn.close()
                        return jsonify({'success': False, 'error': 'Comanda não encontrada ou fechada'})
                    conn.close()
                except Exception as e:
                    print(f"[Servidor] Erro ao adicionar item: {e}")
                    import traceback
                    traceback.print_exc()
                    return jsonify({'success': False, 'error': str(e)})
                
                if SOCKETIO_AVAILABLE and self.socketio:
                    self.socketio.emit('comanda_update', {
                        'action': 'item_added',
                        'numero': numero,
                        'produto': produto.get('nome')
                    })
                    
                    # Se a comanda foi reaberta na cozinha, notifica a cozinha
                    if comanda_reaberta_cozinha:
                        usuario_garcom = session.get('web_username', 'Garcom')
                        self.socketio.emit('cozinha_update', {
                            'action': 'comanda_reaberta',
                            'numero': numero,
                            'reaberta_por': usuario_garcom,
                            'message': f'Comanda #{numero} reaberta - novo item adicionado por {usuario_garcom}',
                            'timestamp': datetime.datetime.now().isoformat()
                        })
                        print(f"[Servidor] Notificacao enviada para cozinha: comanda #{numero} reaberta")
                
                return jsonify({'success': True})
            except Exception as e:
                print(f"[Servidor] Erro geral ao adicionar item: {e}")
                import traceback
                traceback.print_exc()
                return jsonify({'success': False, 'error': str(e)})
        
        @self.flask_app.route('/api/comandas/<numero>/itens/<int:item_index>', methods=['DELETE'])
        @login_required
        def api_remove_item(numero, item_index):
            try:
                conn = self._get_db_connection()
                cursor = conn.cursor(dictionary=True)
                cursor.execute("SELECT itens FROM comandas WHERE numero = %s", (numero,))
                row = cursor.fetchone()
                if row:
                    row_dict = dict(row)
                    itens = json.loads(row_dict['itens']) if row_dict['itens'] else []
                    if 0 <= item_index < len(itens):
                        # Pega os dados do item antes de marcar como excluído
                        item_excluido = itens[item_index]
                        produto_id = str(item_excluido.get('id', ''))
                        quantidade_removida = item_excluido.get('qtd', 0)
                        
                        # MARCA O ITEM COMO EXCLUÍDO (mantém registro para impressão)
                        itens[item_index]['excluido'] = True
                        itens[item_index]['excluido_por'] = session.get('web_username', 'N/A')
                        itens[item_index]['excluido_em'] = datetime.datetime.now().strftime('%d/%m/%Y %H:%M:%S')
                        
                        cursor.execute("UPDATE comandas SET itens = %s, updated_at = CURRENT_TIMESTAMP WHERE numero = %s",
                                   (json.dumps(itens), numero))

                        # Muda status para ABERTA
                        cursor.execute("UPDATE comandas SET status = 'aberta', updated_at = CURRENT_TIMESTAMP WHERE numero = %s", (numero,))
                        
                        # ===================================================================
                        # DEVOLVER ESTOQUE AO REMOVER ITEM DA COMANDA (WEB)
                        # ===================================================================
                        if produto_id and quantidade_removida > 0:
                            try:
                                # Busca estoque atual do produto
                                cursor.execute("SELECT estoque FROM produtos WHERE id = %s", (int(produto_id),))
                                prod_row = cursor.fetchone()
                                if prod_row:
                                    estoque_atual = float(prod_row[0]) if prod_row[0] else 0.0
                                    novo_estoque = estoque_atual + float(quantidade_removida)
                                    cursor.execute("UPDATE produtos SET estoque = %s, updated_at = CURRENT_TIMESTAMP WHERE id = %s",
                                               (novo_estoque, int(produto_id)))
                                    print(f"[Servidor WEB] Estoque devolvido: Produto {produto_id} - Qtd: {quantidade_removida} - Estoque anterior: {estoque_atual} - Novo estoque: {novo_estoque}")
                                    
                                    # Sincroniza com app.products do PDV
                                    if hasattr(self, 'app') and hasattr(self.app, 'products'):
                                        for pid_format in [produto_id, str(produto_id)]:
                                            if pid_format in self.app.products:
                                                self.app.products[pid_format]['estoque'] = novo_estoque
                                                print(f"[Servidor WEB] Sincronizado app.products[{pid_format}] com estoque devolvido: {novo_estoque}")
                                                break
                                        try:
                                            pid_int = int(produto_id)
                                            if pid_int in self.app.products:
                                                self.app.products[pid_int]['estoque'] = novo_estoque
                                        except (ValueError, TypeError):
                                            pass
                            except Exception as estoque_error:
                                print(f"[Servidor WEB] Erro ao devolver estoque: {estoque_error}")
                        
                        conn.commit()
                        conn.close()
                        if SOCKETIO_AVAILABLE and self.socketio:
                            self.socketio.emit('comanda_update', {'action': 'item_removed', 'numero': numero})
                        return jsonify({'success': True})
                conn.close()
                return jsonify({'success': False, 'error': 'Item não encontrado'})
            except Exception as e:
                return jsonify({'success': False, 'error': str(e)})
        
        @self.flask_app.route('/api/comandas/<numero>/itens/<int:item_index>/observacao', methods=['PUT'])
        @login_required
        def api_update_item_observacao(numero, item_index):
            """Atualiza a observação de um item específico da comanda."""
            try:
                data = request.get_json() or {}
                nova_observacao = data.get('observacao', '').strip()
                usuario = session.get('web_username', 'N/A')
                
                conn = self._get_db_connection()
                cursor = conn.cursor(dictionary=True)
                cursor.execute("SELECT itens FROM comandas WHERE numero = %s", (numero,))
                row = cursor.fetchone()
                
                if not row:
                    conn.close()
                    return jsonify({'success': False, 'error': 'Comanda não encontrada ou fechada'}), 404
                
                row_dict = dict(row)
                itens = json.loads(row_dict['itens']) if row_dict['itens'] else []
                
                if item_index < 0 or item_index >= len(itens):
                    conn.close()
                    return jsonify({'success': False, 'error': 'Item não encontrado'}), 404
                
                # Verifica se o item foi excluído
                if itens[item_index].get('excluido', False):
                    conn.close()
                    return jsonify({'success': False, 'error': 'Não é possível editar item excluído'}), 400
                
                # Atualiza a observação do item
                itens[item_index]['observacao'] = nova_observacao
                itens[item_index]['obs_editada_por'] = usuario
                itens[item_index]['obs_editada_em'] = datetime.datetime.now().strftime('%d/%m/%Y %H:%M:%S')
                
                cursor.execute("UPDATE comandas SET itens = %s, updated_at = CURRENT_TIMESTAMP WHERE numero = %s",
                           (json.dumps(itens), numero))
                
                # Muda status para ABERTA
                cursor.execute("UPDATE comandas SET status = 'aberta', updated_at = CURRENT_TIMESTAMP WHERE numero = %s", (numero,))
                conn.commit()
                conn.close()
                
                print(f"[Servidor WEB] Observação do item {item_index} da comanda {numero} atualizada por {usuario}")
                
                # Notifica via WebSocket
                if SOCKETIO_AVAILABLE and self.socketio:
                    self.socketio.emit('comanda_update', {
                        'action': 'item_obs_updated',
                        'numero': numero,
                        'item_index': item_index
                    })
                
                return jsonify({'success': True, 'message': 'Observação atualizada com sucesso'})
                
            except Exception as e:
                print(f"[Servidor WEB] Erro ao atualizar observação: {e}")
                import traceback
                traceback.print_exc()
                return jsonify({'success': False, 'error': str(e)})
        
        @self.flask_app.route('/api/comandas/estatisticas')
        @login_required
        def api_comandas_estatisticas():
            """
            Retorna estatísticas das comandas.
            
            Métricas:
            - Total de comandas abertas
            - Total de comandas fechadas hoje
            - Valor total em comandas abertas
            - Tempo médio de atendimento
            - Comandas reaberturas
            """
            try:
                conn = self._get_db_connection()
                cursor = conn.cursor(dictionary=True)
                
                # Comandas abertas
                cursor.execute("SELECT COUNT(*) as total FROM comandas WHERE status = 'aberta'")
                abertas = cursor.fetchone()['total']
                
                # Comandas fechadas hoje
                cursor.execute("""
                    SELECT COUNT(*) as total FROM comandas 
                    WHERE status IN ('fechada', 'paga') 
                    AND DATE(updated_at) = DATE('now')
                """)
                fechadas_hoje = cursor.fetchone()['total']
                
                # Valor total em comandas abertas
                cursor.execute("SELECT itens FROM comandas WHERE status = 'aberta'")
                valor_total = 0
                for row in cursor.fetchall():
                    itens = json.loads(row['itens']) if row['itens'] else []
                    for item in itens:
                        valor_total += item.get('subtotal', 0)
                
                # Comandas reaberturas - compatível com bancos existentes
                reaberturas = 0
                try:
                    cursor.execute("""
                        SELECT COUNT(*) as total FROM comandas 
                        WHERE reaberta_em IS NOT NULL
                    """)
                    reaberturas = cursor.fetchone()['total']
                except Exception:
                    # Coluna não existe no banco antigo
                    reaberturas = 0
                
                conn.close()
                
                return jsonify({
                    'success': True,
                    'estatisticas': {
                        'comandas_abertas': abertas,
                        'comandas_fechadas_hoje': fechadas_hoje,
                        'valor_total_abertas': round(valor_total, 2),
                        'total_reaberturas': reaberturas
                    }
                })
            except Exception as e:
                return jsonify({'success': False, 'error': str(e)})
        
