                        conn_cli = self._get_db_connection()
                        cursor_cli = conn_cli.cursor()
                        cursor_cli.execute("SELECT * FROM clientes WHERE nome = %s", (cliente_nome_busca,))
                        cliente_row = cursor_cli.fetchone()
                        conn_cli.close()
                        
                        if cliente_row:
                            cliente_data = dict(cliente_row)
                            comanda['cpf_cliente'] = cliente_data.get('cpf', '')
                            comanda['telefone_cliente'] = cliente_data.get('telefone', '')
                            comanda['endereco_cliente'] = cliente_data.get('endereco', '')
                            comanda['bairro_cliente'] = cliente_data.get('bairro', '')
                            comanda['obs_cliente'] = cliente_data.get('observacao', '')
