# ═══════════════════════════════════════════════════════════════════════════
# FUNÇÕES AUXILIARES ADICIONAIS
# ═══════════════════════════════════════════════════════════════════════════



# ═══════════════════════════════════════════════════════════════════════════════════════
# FUNÇÕES UTILITÁRIAS AVANÇADAS
# ═══════════════════════════════════════════════════════════════════════════════════════

def debounce(wait_ms: int):
    """Decorator para debounce de funções."""
    def decorator(func):
        timer = [None]
        def debounced(*args, **kwargs):
            def call_func():
                timer[0] = None
                func(*args, **kwargs)
            if timer[0]:
                timer[0].cancel()
            timer[0] = threading.Timer(wait_ms / 1000, call_func)
            timer[0].start()
        return debounced
    return decorator


def throttle(wait_ms: int):
    """Decorator para throttle de funções."""
    def decorator(func):
        last_call = [0]
        def throttled(*args, **kwargs):
            now = time.time() * 1000
            if now - last_call[0] >= wait_ms:
                last_call[0] = now
                return func(*args, **kwargs)
        return throttled
    return decorator


def retry(max_attempts: int = 3, delay_ms: int = 1000, exceptions=(Exception,)):
    """Decorator para retry automático em caso de falha."""
    def decorator(func):
        def wrapper(*args, **kwargs):
            last_exception = None
            for attempt in range(max_attempts):
                try:
                    return func(*args, **kwargs)
                except exceptions as e:
                    last_exception = e
                    if attempt < max_attempts - 1:
                        time.sleep(delay_ms / 1000)
            raise last_exception
        return wrapper
    return decorator


def memoize(ttl_seconds: int = 300):
    """Decorator para memoização com TTL."""
    def decorator(func):
        cache = {}
        timestamps = {}
        def wrapper(*args, **kwargs):
            key = str(args) + str(kwargs)
            now = time.time()
            if key in cache and now - timestamps[key] < ttl_seconds:
                return cache[key]
            result = func(*args, **kwargs)
            cache[key] = result
            timestamps[key] = now
            return result
        wrapper.clear_cache = lambda: (cache.clear(), timestamps.clear())
        return wrapper
    return decorator


def format_file_size(size_bytes: int) -> str:
    """Formata tamanho de arquivo para exibição."""
    for unit in ['B', 'KB', 'MB', 'GB', 'TB']:
        if size_bytes < 1024:
            return f"{size_bytes:.1f} {unit}"
        size_bytes /= 1024
    return f"{size_bytes:.1f} PB"


def format_duration(seconds: float) -> str:
    """Formata duração em segundos para exibição."""
    if seconds < 60:
        return f"{seconds:.0f}s"
    elif seconds < 3600:
        minutes = seconds // 60
        secs = seconds % 60
        return f"{minutes:.0f}min {secs:.0f}s"
    else:
        hours = seconds // 3600
        minutes = (seconds % 3600) // 60
        return f"{hours:.0f}h {minutes:.0f}min"


def format_number_br(number: float, decimals: int = 2) -> str:
    """Formata número no padrão brasileiro."""
    try:
        formatted = f"{float(number):,.{decimals}f}"
        return formatted.replace(',', '_').replace('.', ',').replace('_', '.')
    except (ValueError, TypeError):
        return "0,00"


def parse_number_br(text: str) -> float:
    """Converte número no formato brasileiro para float."""
    try:
        clean = str(text).replace('.', '').replace(',', '.')
        return float(clean)
    except (ValueError, TypeError):
        return 0.0


def generate_unique_id(prefix: str = "", length: int = 8) -> str:
    """Gera um ID único."""
    import random
    import string
    chars = string.ascii_uppercase + string.digits
    random_part = ''.join(random.choices(chars, k=length))
    if prefix:
        return f"{prefix}-{random_part}"
    return random_part


def safe_divide(numerator: float, denominator: float, default: float = 0.0) -> float:
    """Divisão segura que evita divisão por zero."""
    try:
        if denominator == 0:
            return default
        return numerator / denominator
    except (TypeError, ValueError):
        return default


def clamp(value: float, min_val: float, max_val: float) -> float:
    """Limita um valor entre mínimo e máximo."""
    return max(min_val, min(value, max_val))


def deep_merge(dict1: dict, dict2: dict) -> dict:
    """Merge profundo de dois dicionários."""
    result = dict1.copy()
    for key, value in dict2.items():
        if key in result and isinstance(result[key], dict) and isinstance(value, dict):
            result[key] = deep_merge(result[key], value)
        else:
            result[key] = value
    return result


def get_system_info() -> dict:
    """Obtém informações do sistema."""
    import platform
    return {
        'os': platform.system(),
        'os_version': platform.version(),
        'os_release': platform.release(),
        'machine': platform.machine(),
        'processor': platform.processor(),
        'python_version': platform.python_version(),
        'python_implementation': platform.python_implementation(),
        'hostname': platform.node(),
    }


def is_valid_barcode(barcode: str) -> bool:
    """Valida código de barras EAN-13."""
    barcode = re.sub(r'[^0-9]', '', str(barcode))
    if len(barcode) != 13:
        return False
    total = 0
    for i, digit in enumerate(barcode[:12]):
        if i % 2 == 0:
            total += int(digit)
        else:
            total += int(digit) * 3
    check_digit = (10 - (total % 10)) % 10
    return int(barcode[12]) == check_digit


def generate_ean13(base_code: str) -> str:
    """Gera código EAN-13 com dígito verificador."""
    base_code = re.sub(r'[^0-9]', '', str(base_code))[:12].zfill(12)
    total = 0
    for i, digit in enumerate(base_code):
        if i % 2 == 0:
            total += int(digit)
        else:
            total += int(digit) * 3
    check_digit = (10 - (total % 10)) % 10
    return base_code + str(check_digit)




def format_currency_br(value):
    """Formata valor como moeda brasileira."""
    try:
        return f"R$ {float(value):,.2f}".replace(',', '_').replace('.', ',').replace('_', '.')
    except Exception:
        return "R$ 0,00"

def format_percentage(value):
    """Formata valor como percentual."""
    try:
        return f"{float(value):.2f}%"
    except Exception:
        return "0.00%"

def truncate_text(text, max_length=50):
    """Trunca texto longo."""
    if len(text) <= max_length:
        return text
    return text[:max_length-3] + "..."

def validate_positive_float(value):
    """Valida número positivo."""
    try:
        num = float(str(value).replace(',', '.'))
        return num >= 0, num
    except Exception:
        return False, 0.0

def sanitize_filename(filename):
    """Remove caracteres inválidos de nome de arquivo."""
    import re
    return re.sub(r'[<>:"/\|?*]', '_', filename)


