    def silent_exception_handler(self, exc, val, tb):
        error_msg = str(val)
        ignorable_errors = [
            "application has been destroyed",
            "_on_closing",
            "can't invoke",
            "invalid command name"
        ]
        if any(err in error_msg for err in ignorable_errors):
            return
        try:
            tb_str = ''.join(traceback.format_exception(exc, val, tb))
            AUDITORIA.erro(f"Exceção de callback: {exc.__name__}: {val} | {tb_str.replace(chr(10), ' | ')[:500]}")
        except Exception:
            pass
        traceback.print_exception(exc, val, tb)

    tk.Tk.report_callback_exception = silent_exception_handler

